  ------------------------------------------------------------------------------
  -- Funcao para Obter Regra Especifica de Medicamentos --
  --------------------------------------------------------
  FUNCTION F_REGRA_MEDICAMENTOS(pi_vCodFilial IN VARCHAR2,
                                pi_vNome      IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetRegraMedicamentos VARCHAR2(250);
  BEGIN
    -- Verifica se usa regra
    BEGIN
      EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ' || '''' || pi_vNome || '''' || ' AND CODFILIAL = ' || '''' || pi_vCodFilial || ''''
                   INTO vvRetRegraMedicamentos;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetRegraMedicamentos := NULL;
      WHEN OTHERS THEN
        vvRetRegraMedicamentos := NULL;
    END;
    -- Retorno
    RETURN vvRetRegraMedicamentos;
  END F_REGRA_MEDICAMENTOS;

 /*******************************************************************************
  Nome         : F_FORMATAR_NUMERO_PARA_TEXTO
  Descricão    : Função para Formatar um Número para Texto
  ********************************************************************************/   
  FUNCTION F_FORMATAR_NUMERO_PARA_TEXTO(pi_nNumero            IN NUMBER,
                                        pi_iQtdeCasasDecimais IN INTEGER) RETURN VARCHAR2 IS                                           
    vvTextoRetorno  VARCHAR2(200);
    vvMascara       VARCHAR2(200);
  BEGIN
  
    vvMascara :=  NULL;
    
    -- Monta a parte da Mascara com Casas Decimais
    IF (pi_iQtdeCasasDecimais > 0) THEN
      FOR viIdx IN 1..pi_iQtdeCasasDecimais LOOP
        IF (vvMascara IS NULL) THEN
          vvMascara := '0';
        ELSE
          vvMascara := vvMascara || '0';
        END IF;
      END LOOP;
      vvMascara := '0.' || vvMascara;
    -- Monta a parte da Mascara sem Casas Decimais
    ELSE
      vvMascara := '0';
    END IF;
    
    -- Finaliza a Mascara da Parte Inteira
    vvMascara := '999,999,999,999,999,999,999,999,999,999,999,99' || vvMascara;

    -- Prepara Texto Retorno
    vvTextoRetorno := TO_CHAR(pi_nNumero,vvMascara);
    
    -- Troca Ponto por um caracter auxiliar
    vvTextoRetorno := REPLACE(vvTextoRetorno,'.','@');
    
    -- Troca Virgulas por ponto
    vvTextoRetorno := REPLACE(vvTextoRetorno,',','.');

    -- Troca caracter auxiliar por virgula
    vvTextoRetorno := REPLACE(vvTextoRetorno,'@',',');
    
    -- Elimina espaços em branco
    vvTextoRetorno := TRIM(vvTextoRetorno);
    
    -- Retorno
    RETURN vvTextoRetorno;
 
  END F_FORMATAR_NUMERO_PARA_TEXTO;   
  
 /***************************************************************************
  FUNÇÃO     : F_USA_REGRA_PERMISSAO
  DESCRIÇÃO  : Função para Verificar se Usa Regra de Permissão da Rotina 2345
  ***************************************************************************/
  FUNCTION F_USA_REGRA_PERMISSAO RETURN VARCHAR2 IS
    vvRetUsaRegraPermissao VARCHAR2(1);
  BEGIN
  
    -- Verifica se utiliza Regra de Permissão da Rotina 2345
    BEGIN
      SELECT 'S'
        INTO vvRetUsaRegraPermissao
        FROM PCPERMISSAOLIBPEDIDOMED
       WHERE (ROWNUM = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetUsaRegraPermissao := 'N';
    END;
    
    -- Retorno
    RETURN vvRetUsaRegraPermissao;
    
  END F_USA_REGRA_PERMISSAO;

 /**************************************************************************************************
  FUNÇÃO     : F_IGNORA_AUTORIZACAO_LIB_BLOQ
  DESCRIÇÃO  : Função para Verificar se Ignora Autorização do Bloqueio da Rotina 320 - DDMEDICA-3918
  **************************************************************************************************/
  FUNCTION F_IGNORA_AUTORIZACAO_LIB_BLOQ RETURN VARCHAR2 IS
    vvIgnoraAutoriLibBloq VARCHAR2(1);
  BEGIN
  
    -- Verifica se Ignora Autorização do Bloqueio da Rotina 320
    vvIgnoraAutoriLibBloq := F_REGRA_MEDICAMENTOS('99','IGNORAAUTORIZACAOBLOQUEIO320');
    
    -- Retorno
    RETURN vvIgnoraAutoriLibBloq;
    
  END F_IGNORA_AUTORIZACAO_LIB_BLOQ;
 
 /************************************************************************
  FUNÇÃO   : F_IGNORARACESSOCONTROLE2336
  DESCRIÇÃO: Verificar Controle de Acesso da Rotina 2336
  ************************************************************************/
  FUNCTION F_IGNORARACESSOCONTROLE2336(pi_nCodRotina IN NUMBER)
  RETURN BOOLEAN IS
    vbRetIgnorarControleAcesso BOOLEAN;
  BEGIN 
    IF (NVL(pi_nCodRotina,0) = 2336) THEN
      IF (NVL(F_USA_REGRA_PERMISSAO,'N') = 'S') THEN
        vbRetIgnorarControleAcesso := (F_REGRA_MEDICAMENTOS('99',
                                                            'IGNORARPERMISSOESACESSO2336') = 'S');
      ELSE
        vbRetIgnorarControleAcesso := FALSE;
      END IF;
    ELSE
      vbRetIgnorarControleAcesso := FALSE;
    END IF;
    RETURN vbRetIgnorarControleAcesso;     
  END F_IGNORARACESSOCONTROLE2336;
 
 /************************************************************************
  FUNÇÃO   : F_VERIFICARACESSOCONTROLE
  DESCRIÇÃO: Verificar Controle de Acesso
  ************************************************************************/
  FUNCTION F_VERIFICARACESSOCONTROLE(pi_nCodRotina   IN NUMBER,
                                     pi_nCodControle IN NUMBER,
                                     pi_nCodUsuario  IN NUMBER)
  RETURN BOOLEAN IS
    vbRetControleAcesso BOOLEAN;
    vvAcesso            PCCONTROI.ACESSO%TYPE; 
  BEGIN 
    BEGIN
      SELECT NVL(PCCONTROI.ACESSO,'N') ACESSO
        INTO vvAcesso
        FROM PCCONTROI
       WHERE (PCCONTROI.CODROTINA   = pi_nCodRotina)
         AND (PCCONTROI.CODCONTROLE = pi_nCodControle)
         AND (PCCONTROI.CODUSUARIO  = pi_nCodUsuario);        
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvAcesso := 'N';
    END;
    vbRetControleAcesso := (vvAcesso = 'S');
    RETURN vbRetControleAcesso;     
  END;

  ------------------------------------------------------------------------------
  -- Procedimento para Obter o Parâmetro da Filial STRING
  ------------------------------------------------------------------------------
  PROCEDURE POBTEM_PARAMFILIAL_STRING(pi_vCodFilial   IN VARCHAR2,
                                      pi_vNomeCampo   IN VARCHAR2,
                                      pi_vValorPadrao IN VARCHAR2,
                                      po_vValor     OUT VARCHAR2) IS
  BEGIN

    -- Inicializa Retorno
    po_vValor := NULL;

    -- Pesquisa Parametro
    BEGIN
      SELECT PCPARAMFILIAL.VALOR
        INTO po_vValor
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = pi_vNomeCampo);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_vValor := NULL;
    END;
    
    -- Valor Padrão se NULO
    po_vValor := NVL(po_vValor,pi_vValorPadrao);

  END POBTEM_PARAMFILIAL_STRING;

  ------------------------------------------------------------------------------
  -- Procedimento para Obter o Parâmetro da Filial NUMBER
  ------------------------------------------------------------------------------
  PROCEDURE POBTEM_PARAMFILIAL_NUMBER(pi_vCodFilial IN  VARCHAR2,
                                      pi_vNomeCampo IN  VARCHAR2,
                                      po_nValor     OUT NUMBER) IS

    vvValorString PCPARAMFILIAL.VALOR%TYPE;

  BEGIN
  
    -- Inicializa Retorno
    po_nValor   := 0;

    -- Pesquisa Parametro
    BEGIN
      SELECT PCPARAMFILIAL.VALOR
        INTO vvValorString
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = pi_vNomeCampo);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvValorString := NULL;
    END;


    -- Tira Espaços em Branco do Valor
    vvValorString := TRIM(vvValorString);
    IF (vvValorString IS NULL) THEN
      vvValorString := '0';
    END IF;

    -- Converte String para Number
    BEGIN
      po_nValor := TO_NUMBER(vvValorString);
    EXCEPTION
      WHEN OTHERS THEN
        po_nValor := 0;
    END;

  END POBTEM_PARAMFILIAL_NUMBER;
 
 /*******************************************************************************
  Nome         : P_OBTER_PARAMETROS
  Descricão    : Procedimento para Carregar Parâmetros
  ********************************************************************************/    
  PROCEDURE P_OBTER_PARAMETROS(pi_vCodFilial                  IN VARCHAR2,
                               pSOMACREDITOCLIPRINCIPAL      OUT VARCHAR2,
                               pUSABNFLIMITECREDITO          OUT VARCHAR2,
                               pPEREXCEDELIMCRED             OUT NUMBER,
                               pVERIFICALIMCREDCODCOBD       OUT VARCHAR2,
                               pACEITAVENDAAVISTACLIBLOQ     OUT VARCHAR2,
                               pBLOQPEDLIMCRED               OUT VARCHAR2,
                               pNUMCASASDECVENDA             OUT NUMBER,
                               pVALIDALVARAPORTIPOCTLVEN     OUT VARCHAR2,
                               pVERIFICABLOQUEIOSEFAZ        OUT VARCHAR2,
                               pPERMITIRTROCACLIENTEPFCONSIG OUT VARCHAR2) IS
  BEGIN 
    --
    SELECT PEREXCEDELIMCRED
         , NUMCASASDECVENDA
      INTO pPEREXCEDELIMCRED
         , pNUMCASASDECVENDA
      FROM PCCONSUM;
    --   
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO pSOMACREDITOCLIPRINCIPAL
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99') -- DDMEDICA-4732
         AND (NOME      = 'SOMACREDITOCLIPRINCIPAL');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pSOMACREDITOCLIPRINCIPAL := 'N';
    END;                
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO pUSABNFLIMITECREDITO
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99') -- DDMEDICA-4732
         AND (NOME      = 'USABNFLIMITECREDITO');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pUSABNFLIMITECREDITO := 'N';
    END;            
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO pVERIFICALIMCREDCODCOBD
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_VERIFICALIMCREDCODCOBD');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pVERIFICALIMCREDCODCOBD := 'N';
    END;            
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO pACEITAVENDAAVISTACLIBLOQ
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'ACEITAVENDAAVISTACLIBLOQ');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pACEITAVENDAAVISTACLIBLOQ := 'N';
    END;            
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO pBLOQPEDLIMCRED
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'BLOQPEDLIMCRED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pBLOQPEDLIMCRED := 'N';
    END;            
    --
     BEGIN
      SELECT VALOR
        INTO pVALIDALVARAPORTIPOCTLVEN
        FROM PCPARAMFILIAL 
       WHERE (NOME      = 'VALIDALVARAPORTIPOCTLVEN')
         AND (CODFILIAL = '99');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pVALIDALVARAPORTIPOCTLVEN := 'N';
    END;
    --
     BEGIN
      SELECT VALOR
        INTO pVERIFICABLOQUEIOSEFAZ
        FROM PCPARAMFILIAL 
       WHERE (NOME      = 'VERIFICABLOQUEIOSEFAZ')
         AND (CODFILIAL = '99');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pVERIFICABLOQUEIOSEFAZ := 'N';
    END;   
    -- DDMEDICA-6874
    BEGIN
      SELECT VALOR
        INTO pPERMITIRTROCACLIENTEPFCONSIG
        FROM PCPARAMFILIAL 
       WHERE (NOME      = 'PERMITIRTROCACLIENTEPFCONSIG')
         AND (CODFILIAL = '99');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pPERMITIRTROCACLIENTEPFCONSIG := 'N';
    END;       
    --
  END P_OBTER_PARAMETROS;
  
  ------------------------------------------------------------------------------
  -- Função para retornar o Parâmetro da Integradora
  -- MED-861
  -------------------------------------------------------------------
  FUNCTION FOBTEM_PARAM_INTEGRADORA(pi_nIntegradora  IN NUMBER,
                                    pi_vNome         IN VARCHAR2,
                                    pi_vValorDefault IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetParamIntegradora PCPARAMINTEGRADORAMED.VALOR%TYPE;
  BEGIN
  
    -- Pesquisa Parâmetro
    BEGIN
      SELECT NVL(PCPARAMINTEGRADORAMED.VALOR,pi_vValorDefault)
        INTO vvRetParamIntegradora
        FROM PCPARAMINTEGRADORAMED
       WHERE (PCPARAMINTEGRADORAMED.NOME        = pi_vNome)
         AND (PCPARAMINTEGRADORAMED.INTEGRADORA = pi_nIntegradora);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetParamIntegradora := pi_vValorDefault;
    END;
  
    -- Retorno
    RETURN vvRetParamIntegradora;
  
  END FOBTEM_PARAM_INTEGRADORA;   
  
 /*********************************************************************************
  FUNÇÃO     : F_MANTEM_CRITICAS_PESSOAFISICA
  DESCRIÇÃO  : Função para retornar se continua criticando troca de cliente pessoa fisica
               ou se parâmetro ativado e permissão, deixa trocar o cliente de pessoa fisica para juridica
  *********************************************************************************/
  FUNCTION F_MANTEM_CRITICAS_PESSOAFISICA(pi_nMatricula                  IN NUMBER,
                                          pi_vPERMITIRTROCACLIENTEPFCONS IN VARCHAR2)
  RETURN BOOLEAN IS
    vbRetMantemCriticas     BOOLEAN;
    vnCondVenda             PCPEDC.CONDVENDA%TYPE;
    vnNumTransEntOrigConsig PCPEDC.CONDVENDA%TYPE;
  BEGIN
  
    -- Inicia Mantendo as Críticas
    vbRetMantemCriticas := TRUE;
    
    IF (pi_vPERMITIRTROCACLIENTEPFCONS = 'S') THEN
      IF (F_VERIFICARACESSOCONTROLE(2316,
                                    98,
                                    pi_nMatricula)) THEN
        -- Não terá a Crítica de Pessoa Física
        vbRetMantemCriticas := FALSE;
      END IF;
    END IF;
    
    RETURN vbRetMantemCriticas;
    
  END F_MANTEM_CRITICAS_PESSOAFISICA;
                                            
 /*********************************************************************************
  FUNÇÃO     : F_OBTER_ACAO_CONFORME_ACESSO
  DESCRIÇÃO  : Função para Obter a ação conforme acesso da matricula ao motivo bloqueio
               Se a Matricula puder liberar o motivo, a ação será abortar, porque por
               exemplo se a matricula puder liberar cliente bloqueado, primeiro precisa
               liberar o cliente, enquanto isso precisa abortar até que o cliente seja liberado.
               Se a matricula não puder liberar o motivo, a ação será perguntar, porque
               a metricula precisa liberar os demais motivos que ele tem acesso.
  *********************************************************************************/
  FUNCTION F_OBTER_ACAO_CONFORME_ACESSO(pi_nCodMotivo IN NUMBER,
                                        pi_nMatricula IN NUMBER) RETURN VARCHAR2 IS
    vvRetAcao VARCHAR2(1);
  BEGIN
    BEGIN
      SELECT 'A'
        INTO vvRetAcao
        FROM PCPERMISSAOLIBPEDIDOMED
       WHERE (MATRICULA = pi_nMatricula)
         AND (CODMOTIVO = pi_nCodMotivo);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetAcao := 'I';
    END;
    RETURN vvRetAcao;
  END F_OBTER_ACAO_CONFORME_ACESSO;  

 /*********************************************************************************
  FUNÇÃO     : F_REGRA_PERMISSAO_MATRICULA
  DESCRIÇÃO  : Função para Verificar se a Matricula tem acesso a Liberar o Bloqueio
  *********************************************************************************/
  FUNCTION F_REGRA_PERMISSAO_MATRICULA(pi_vUsaRegraPermissao   IN VARCHAR2,
                                       pi_nMatricula           IN NUMBER,
                                       pi_nCodMotivo           IN NUMBER,
                                       pi_vIgnoraAutoriLibBloq IN VARCHAR2,
                                       pi_nCodMotivoBloqueio   IN NUMBER) RETURN VARCHAR2 IS
    vvRetRegraPermissao VARCHAR2(1);
    vnCodMotivo         NUMBER;
  BEGIN
  
    -- Verifica se Matricula tem acesso a Liberar o Bloqueio
    IF (NVL(pi_vUsaRegraPermissao,'N') = 'S') THEN
      -- Se por algum motivo bloquear sem o código do motivo, assumirá -1, porque senão não conseguirá liberar porque não existirá o motivo "0" liberado para a Matrícula
      vnCodMotivo := pi_nCodMotivo;
      IF (NVL(vnCodMotivo,0) = 0) THEN
        vnCodMotivo := -1;
      END IF;
      --
      BEGIN
        SELECT 'S'
          INTO vvRetRegraPermissao
          FROM PCPERMISSAOLIBPEDIDOMED
         WHERE (MATRICULA = pi_nMatricula)
           AND (CODMOTIVO = vnCodMotivo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvRetRegraPermissao := 'N';
      END;
    ELSE
      vvRetRegraPermissao := 'S';
    END IF;  
    
    -- Verificar se a Matricula tem acesso a Liberar o Bloqueio Comercial conforme cadastro da rotina 320 - DDMEDICA-3918
    IF (vvRetRegraPermissao = 'S') AND
       (pi_nCodMotivoBloqueio > 0) THEN
      IF (NVL(pi_vIgnoraAutoriLibBloq,'N') <> 'S') THEN
        BEGIN
          SELECT 'S'
            INTO vvRetRegraPermissao
            FROM PCCONTROBLOQUEIO
           WHERE (CODFUNCLIBBLOQ = pi_nMatricula)
             AND (CODMOTBLOQUEIO = pi_nCodMotivoBloqueio);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            -- DDMEDICA-6772 - Se não encontrou o Controle de Bloqueio para a Matrícula,
            -- Verifica se o Bloqueio Comercial ainda está Cadastrado, 
            -- se não estiver cadastrado (foi removido), fica liberado para todas as matrículas
            BEGIN
              SELECT 'N'
                INTO vvRetRegraPermissao
                FROM PCBLOQUEIO
               WHERE (CODMOTBLOQUEIO = pi_nCodMotivoBloqueio);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vvRetRegraPermissao := 'S'; -->> Liberado para todos os Clientes
            END;
        END;
      ELSE
        vvRetRegraPermissao := 'S';
      END IF;  
    END IF;
      
    -- Retorno
    RETURN vvRetRegraPermissao;
         
  END F_REGRA_PERMISSAO_MATRICULA;            
  
 /*********************************************************************
  FUNÇÃO   : F_INCLUIR_BLOQUEIO_PEDIDO
  DESCRIÇÃO: Função para verificar se o motivo de bloqueio passado no 
             parâmetro existe na tabela temporária
  *********************************************************************/
  FUNCTION F_INCLUIR_BLOQUEIO_PEDIDO(pi_nNumPed            IN NUMBER,
                                     pi_nMotivo            IN NUMBER,
                                     pi_nCodMotivoBloqueio IN NUMBER) RETURN VARCHAR2 IS
    vvRetIncluirBloqueio VARCHAR2(1);
  BEGIN
  
    BEGIN
      SELECT 'N' 
        INTO vvRetIncluirBloqueio
        FROM PCMED_VALIDACAO_ESTOQUE_RESERV
       WHERE (NUMPED                = pi_nNumPed)
         AND (CODMOTIVO             = NVL(pi_nMotivo,0))
         AND (NVL(CODMOTBLOQUEIO,0) = NVL(pi_nMotivo,0))
         AND (NVL(SITUACAO,'P')     = 'P')
         AND (ROWNUM                = 1); 
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetIncluirBloqueio := 'S';
    END;
    
    RETURN vvRetIncluirBloqueio;
    
  END F_INCLUIR_BLOQUEIO_PEDIDO;      
  
 /*********************************************************************
  PROCEDIMENTO : P_ATU_DTWMS
  DESCRIÇÃO    : Procedimento para atualizar o DTWMS do Pedido
                 quando Transferências entre Filiais que usam o mesmo
                 Estoque do WMS
  *********************************************************************/
  PROCEDURE P_ATU_DTWMS(pi_nNumPed          IN  NUMBER,
                        pi_vCodFilialOrigem IN  VARCHAR2,
                        pi_nCodCliDestino   IN  NUMBER,
                        po_vMensagem        OUT VARCHAR2) IS
    vFIL_USAWMS_ORIGEM     PCPARAMFILIAL.VALOR%TYPE;
    vFIL_USAWMS_DESTINO    PCPARAMFILIAL.VALOR%TYPE;
    vvCodFilialDestino     PCFILIAL.CODIGO%TYPE;
    vvEstoqueCompartilhado VARCHAR2(1);
  BEGIN
    
    po_vMensagem := NULL;
    
    -- Verifica se a Filial de Origem Usa WMS
    POBTEM_PARAMFILIAL_STRING(pi_vCodFilialOrigem,
                              'FIL_USAWMS',
                              'N',
                              vFIL_USAWMS_ORIGEM);
                              
    -- Se a Filial de Origem usa WMS
    IF (vFIL_USAWMS_ORIGEM = 'S') THEN
    
      -- Pesquisa a Filial de Destino
      BEGIN
        SELECT CODIGO 
          INTO vvCodFilialDestino
          FROM PCFILIAL
         WHERE (CODCLI = pi_nCodCliDestino);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvCodFilialDestino := NULL;
          po_vMensagem       := 'Filial de Destino não encontrada na PCFILIAL';
        WHEN TOO_MANY_ROWS THEN
          vvCodFilialDestino := NULL;
          po_vMensagem       := 'Mais de uma Filial de Destino não encontrada na PCFILIAL';
      END;
      
      -- Se achou a Filial de Destino
      IF (vvCodFilialDestino IS NOT NULL) THEN
      
        -- Verifica se a Filial de Destino Usa WMS
        POBTEM_PARAMFILIAL_STRING(vvCodFilialDestino,
                                  'FIL_USAWMS',
                                  'N',
                                  vFIL_USAWMS_DESTINO);

        IF (NVL(vFIL_USAWMS_DESTINO,'N') = 'S') THEN
        
          BEGIN
            SELECT
              CASE WHEN ((SELECT VALOR FROM PCPARAMETROWMS WHERE NOME = 'FILIALESTOQUE' AND CODFILIAL = pi_vCodFilialOrigem) =
                         (SELECT VALOR FROM PCPARAMETROWMS WHERE NOME = 'FILIALESTOQUE' AND CODFILIAL = vvCodFilialDestino))
                   THEN 'S'
                   ELSE 'N'
                   END
              INTO vvEstoqueCompartilhado
              FROM DUAL;        
          EXCEPTION
            WHEN OTHERS THEN
              vvEstoqueCompartilhado := NULL;
              po_vMensagem           := 'Problemas ao verificar se as duas filiais utilizam o mesmo estoque';
          END;
          
          -- Se estoque compartilhado
          IF (NVL(vvEstoqueCompartilhado,'N') = 'S') THEN
          
            UPDATE PCPEDC
               SET DTWMS = TRUNC(SYSDATE)
             WHERE (NUMPED = pi_nNumPed)
               AND (DTWMS  IS NULL); -->> Se ainda não atualizou
          
          ELSE          
          
            po_vMensagem := 'Estoque não é compartilhado no WMS';
          
          END IF;
        
        ELSE
        
          po_vMensagem := 'Filial de Destino não usa WMS';
          
        END IF;
      
      END IF; -- Fim: Se achou a Filial de Destino
    
    END IF;
    
   END P_ATU_DTWMS;                        

 /*********************************************************************
  PROCEDIMENTO : P_ATU_VALIDACAO_ESTOQUE_RESERV
  DESCRIÇÃO    : Procedimento para atualizar a Tabela Temporária
                 PCMED_VALIDACAO_ESTOQUE_RESERV
  *********************************************************************/
  PROCEDURE P_ATU_VALIDACAO_ESTOQUE_RESERV(pi_vChamadaProcesso IN VARCHAR2,
                                           pNUMPED             IN PCMED_VALIDACAO_ESTOQUE_RESERV.NUMPED%TYPE,
                                           pCODPLPAG           IN PCMED_VALIDACAO_ESTOQUE_RESERV.CODPLPAG%TYPE,
                                           pCODREJEICAO        IN PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO%TYPE,
                                           pACAO               IN PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO%TYPE,
                                           pDESCRICAOREJEICAO  IN PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO%TYPE,
                                           pCODROTINA          IN PCMED_VALIDACAO_ESTOQUE_RESERV.CODROTINA%TYPE,
                                           pVALORVALIDACAO     IN PCMED_VALIDACAO_ESTOQUE_RESERV.VALORVALIDACAO%TYPE,
                                           pVALORATINGIDO      IN PCMED_VALIDACAO_ESTOQUE_RESERV.VALORATINGIDO%TYPE,
                                           pVENDAPERMITIDA     IN PCMED_VALIDACAO_ESTOQUE_RESERV.VENDAPERMITIDA%TYPE,
                                           pNUMEROPARAMETRO    IN PCMED_VALIDACAO_ESTOQUE_RESERV.NUMEROPARAMETRO%TYPE,
                                           pCODMOTIVO          IN PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO%TYPE,
                                           pCODMOTBLOQUEIO     IN PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO%TYPE,
                                           pMOTIVOPOSICAO      IN PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO%TYPE,
                                           pPERMISSAO          IN PCMED_VALIDACAO_ESTOQUE_RESERV.PERMISSAO%TYPE,
                                           pSOLUCAOP4          IN PCMED_VALIDACAO_ESTOQUE_RESERV.SOLUCAOP4%TYPE,
                                           pSITUACAO           IN PCMED_VALIDACAO_ESTOQUE_RESERV.SITUACAO%TYPE DEFAULT 'P',
                                           pCODFUNCLIBERA      IN PCMED_VALIDACAO_ESTOQUE_RESERV.CODFUNCAPROVADOR%TYPE DEFAULT NULL,
                                           pNOMEFUNCAPROVADOR  IN PCMED_VALIDACAO_ESTOQUE_RESERV.NOMEFUNCAPROVADOR%TYPE DEFAULT NULL,
                                           pOBSERVACAO         IN PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO%TYPE DEFAULT NULL,
                                           pDTAPROVACAO        IN PCMED_VALIDACAO_ESTOQUE_RESERV.DTAPROVACAO%TYPE DEFAULT NULL,
                                           pDTINCLUSAO         IN PCMED_VALIDACAO_ESTOQUE_RESERV.DTINCLUSAO%TYPE DEFAULT NULL,
                                           pREGRAPERMISSAO     IN PCMED_VALIDACAO_ESTOQUE_RESERV.REGRAPERMISSAO%TYPE DEFAULT NULL) IS
    BEGIN  

      UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
         SET VALORATINGIDO  = NVL(VALORATINGIDO,0) + NVL(pVALORATINGIDO,0)
           , REGRAPERMISSAO = DECODE(NVL(REGRAPERMISSAO,'X'),'A',REGRAPERMISSAO,pREGRAPERMISSAO) -->> Priorizar o Flag para indicar que não tem permissão da 530 e assim a chave ficar amarela na 2336
       WHERE (NUMPED            = pNUMPED)
         AND (CODPLPAG          = NVL(pCODPLPAG,0))     
         AND (CODREJEICAO       = NVL(pCODREJEICAO,0))
         AND (NVL(SITUACAO,'P') = pSITUACAO); 

      IF ((NVL(SQL%ROWCOUNT,0) = 0) OR 
          ((pi_vChamadaProcesso = 'LB') AND
           (pCODREJEICAO = 8888)))      THEN -->> Ao carregar oo Histórico dos Bloqueios Manuais exibe Tudo - DDMEDICA-3918
      
        INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                  ( NUMPED
                  , CODPLPAG
                  , CODREJEICAO
                  , ACAO
                  , DESCRICAOREJEICAO
                  , CODROTINA
                  , VALORVALIDACAO
                  , VALORATINGIDO
                  , VENDAPERMITIDA
                  , NUMEROPARAMETRO
                  , CODMOTIVO
                  , CODMOTBLOQUEIO
                  , MOTIVOPOSICAO
                  , PERMISSAO
                  , SOLUCAOP4
                  , SITUACAO
                  , CODFUNCAPROVADOR
                  , NOMEFUNCAPROVADOR
                  , OBSERVACAO
                  , DTAPROVACAO
                  , DTINCLUSAO
                  , REGRAPERMISSAO )
           VALUES ( pNUMPED
                  , NVL(pCODPLPAG,0)
                  , NVL(pCODREJEICAO,0)
                  , pACAO
                  , pDESCRICAOREJEICAO
                  , pCODROTINA
                  , pVALORVALIDACAO
                  , pVALORATINGIDO
                  , pVENDAPERMITIDA
                  , pNUMEROPARAMETRO
                  , pCODMOTIVO
                  , pCODMOTBLOQUEIO
                  , pMOTIVOPOSICAO
                  , pPERMISSAO
                  , pSOLUCAOP4
                  , NVL(pSITUACAO,'P')
                  , pCODFUNCLIBERA
                  , SUBSTR(pNOMEFUNCAPROVADOR,1,40)
                  , pOBSERVACAO
                  , pDTAPROVACAO
                  , pDTINCLUSAO
                  , pREGRAPERMISSAO );

      END IF;
                  
  END P_ATU_VALIDACAO_ESTOQUE_RESERV;  

 /*********************************************************************
  PROCEDIMENTO : P_OBTEM_SITUACAO_PEDIDO_CA_PBM
  DESCRIÇÃO    : Função para Consultar o Status do Pedido gerado
                 para o Canal Autorizador CA PBM
  *********************************************************************/
  PROCEDURE P_OBTEM_SITUACAO_PEDIDO_CA_PBM(pi_nNumPed                 IN NUMBER,
                                           po_nNumPedOperLog         OUT NUMBER,
                                           po_vSituacao              OUT VARCHAR2,
                                           po_vDescricaoSituacao     OUT VARCHAR2,
                                           po_nNumTransVendaOriginal OUT NUMBER) IS
    vEnviaPrePedidoApi  PCPEDCOMPRAOPERLOGCAB.ENVIAPREPEDIDOAPI%TYPE;                                           
    vvStatusOrd         PCPEDRETORNO.STATUSORD%TYPE; 
    -- DDVENDAS-38983
    vvGerouRet          PCPEDRETORNO.GEROURET%TYPE;    
    vnNumPedRca         PCPEDRETORNO.NUMPEDRCA%TYPE;    
    vdDtAberturaPedPalm PCPEDRETORNO.DTABERTURAPEDPALM%TYPE;    
  BEGIN
  
    -- Verifica se o Pedido já foi gravado
    BEGIN
      SELECT NUMPED
           , NUMTRANSVENDAORIGINAL
           , ENVIAPREPEDIDOAPI -- DDVENDAS-38983
        INTO po_nNumPedOperLog
           , po_nNumTransVendaOriginal
           , vEnviaPrePedidoApi -- DDVENDAS-38983
        FROM PCPEDCOMPRAOPERLOGCAB
       WHERE (NUMPEDORIGINAL = pi_nNumPed)
         AND (MODALIDADE     = 'V') -- DDVENDAS-41449 
         AND (ROWNUM         = '1');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_nNumPedOperLog         := NULL;
        po_nNumTransVendaOriginal := NULL;
        vEnviaPrePedidoApi        := NULL; -- DDVENDAS-38983
    END;
    
    -- Se Processo de Envio de Pré-Pedido -- DDVENDAS-38983
    IF (NVL(vEnviaPrePedidoApi,'N') = 'S') THEN
      
      BEGIN
        SELECT STATUSORD
             , GEROURET
             , NUMPEDRCA
             , DTABERTURAPEDPALM
          INTO vvStatusOrd
             , vvGerouRet
             , vnNumPedRca
             , vdDtAberturaPedPalm
          FROM PCPEDRETORNO
         WHERE (NUMPED = pi_nNumPed)
           AND (ROWNUM = 1);
        -- Se AR - Aguardando Resposta que é considerado Autorizado e Pode Liberar o Pedido
        IF    (NVL(vvStatusOrd,'NP') = 'AR') THEN
          po_vSituacao          := 'A'; -- Autorizado
          po_vDescricaoSituacao := 'Autorizado, aguardando Retorno do Pedido';
        -- Se AN - Aguardando Nota já foi liberada a continuidade do Canal Autorizador  
        ELSIF (NVL(vvStatusOrd,'NP') = 'AN') THEN
          po_vSituacao          := 'L'; -- Liberado
          po_vDescricaoSituacao := 'Aguardando Nota Fiscal';
        -- Se NR - Nota Recebida, já foi liberada a continuidade do Canal Autorizador  
        ELSIF (NVL(vvStatusOrd,'NP') = 'NR') THEN
          po_vSituacao          := 'L'; -- Liberado
          po_vDescricaoSituacao := 'Nota Fiscal foi recebida';
        -- Se AP - Aguardando Processameno
        ELSIF (NVL(vvStatusOrd,'NP') = 'AP') THEN
          -- Se já gerou o Retorno já autorizou
          IF (NVL(vvGerouRet,'N') = 'S') THEN
            po_vSituacao          := 'T'; -- Em Transmissão
            po_vDescricaoSituacao := 'Pedido Autorizado em processamento na Indústria';
          -- Se não gerou o Retorno ainda não autorizou
          ELSE
            po_vSituacao          := 'T'; -- Em Transmissão
            po_vDescricaoSituacao := 'Pedido em processamento aguardando autorização da Indústria';
          END IF;
        -- Se EP - Erro no Processameno
        ELSIF (NVL(vvStatusOrd,'NP') = 'EP') THEN
          -- Se já gerou o Retorno já autorizou
          IF (NVL(vvGerouRet,'N') = 'S') THEN
            po_vSituacao          := 'E'; -- Erro
            po_vDescricaoSituacao := 'Informações enviadas após a Autorização não foram aceitos pela Indústria';
          -- Se não gerou o Retorno ainda não autorizou
          ELSE
            po_vSituacao          := 'E'; -- Erro
            po_vDescricaoSituacao := 'O Pedido Rejeitado - Não foi Autorizado pela Indústria';
          END IF;
        -- Demais casos - Exportado
        ELSE
          po_vSituacao          := 'T'; -- Em Transmissão
          po_vDescricaoSituacao := 'Pedido em processamento no Canal Autorizador.';
        END IF;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN -- Se ainda não gerou o Arquivo ORDER
          po_vSituacao          := 'P';
          po_vDescricaoSituacao := 'Pedido Pendente de Transmissão para o Canal Autorizador.';
      END;  
      
      -- Se a API respondeu, replicar alguns valores da PCPEDRETORNO para a PCPEDC para se conseguir gerar os retornos
      IF (NVL(vvStatusOrd,'NP') IN ('AR','EP'))  THEN
        
        UPDATE PCPEDC
           SET NUMPEDRCA         = vnNumPedRca
             , DTABERTURAPEDPALM = vdDtAberturaPedPalm
         WHERE (NUMPED = pi_nNumPed);
        
      END IF;
    
    -- Se Processo de Nota Extra
    ELSIF (NVL(po_nNumTransVendaOriginal,0) > 0) THEN    
      BEGIN
        SELECT STATUSORD
             , GEROURET
          INTO vvStatusOrd
             , vvGerouRet
          FROM PCPEDRETORNO
         WHERE (NUMTRANSVENDA = po_nNumTransVendaOriginal)
           AND (ROWNUM        = 1);
        -- Se AR - Aguardando Resposta que é considerado Autorizado e Pode Liberar o Pedido
        IF    (NVL(vvStatusOrd,'NP') = 'AR') THEN
          po_vSituacao          := 'A'; -- Autorizado
          po_vDescricaoSituacao := 'Autorizado, aguardando Retorno do Pedido';
        -- Se AN - Aguardando Nota já foi liberada a continuidade do Canal Autorizador  
        ELSIF (NVL(vvStatusOrd,'NP') = 'AN') THEN
          po_vSituacao          := 'L'; -- Liberado
          po_vDescricaoSituacao := 'Aguardando Nota Fiscal';
        -- Se NR - Nota Recebida, já foi liberada a continuidade do Canal Autorizador  
        ELSIF (NVL(vvStatusOrd,'NP') = 'NR') THEN
          po_vSituacao          := 'L'; -- Liberado
          po_vDescricaoSituacao := 'Nota Fiscal foi recebida';
        -- Se AP - Aguardando Processameno
        ELSIF (NVL(vvStatusOrd,'NP') = 'AP') THEN
          -- Se já gerou o Retorno já autorizou
          IF (NVL(vvGerouRet,'N') = 'S') THEN
            po_vSituacao          := 'T'; -- Em Transmissão
            po_vDescricaoSituacao := 'Pedido Autorizado em processamento na Indústria';
          -- Se não gerou o Retorno ainda não autorizou
          ELSE
            po_vSituacao          := 'T'; -- Em Transmissão
            po_vDescricaoSituacao := 'Pedido em processamento aguardando autorização da Indústria';
          END IF;
        -- Se EP - Erro no Processameno
        ELSIF (NVL(vvStatusOrd,'NP') = 'EP') THEN
          -- Se já gerou o Retorno já autorizou
          IF (NVL(vvGerouRet,'N') = 'S') THEN
            po_vSituacao          := 'E'; -- Erro
            po_vDescricaoSituacao := 'Informações enviadas após a Autorização não foram aceitos pela Indústria';
          -- Se não gerou o Retorno ainda não autorizou
          ELSE
            po_vSituacao          := 'E'; -- Erro
            po_vDescricaoSituacao := 'O Pedido Rejeitado - Não foi Autorizado pela Indústria';
          END IF;
        -- Demais casos - Exportado
        ELSE
          po_vSituacao          := 'T'; -- Em Transmissão
          po_vDescricaoSituacao := 'Pedido em processamento no Canal Autorizador.';
        END IF;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN -- Se ainda não gerou o Arquivo ORDER
          po_vSituacao          := 'P';
          po_vDescricaoSituacao := 'Pedido Pendente de Transmissão para o Canal Autorizador.';
      END;      
      
    END IF;
    
  END P_OBTEM_SITUACAO_PEDIDO_CA_PBM;                                  

 /*********************************************************************
  PROCEDIMENTO : P_LIMPAR_ITENS_PEDIDO_CA_PBM
  DESCRIÇÃO    : Procedimento para Limpar os Itens do Pedido que será enviado
                 para o Canal Autorizador CA PBM
  *********************************************************************/
  PROCEDURE P_LIMPAR_ITENS_PEDIDO_CA_PBM(pi_nNumPed IN NUMBER) IS


    vnNumPedOperLog         PCPEDCOMPRAOPERLOGCAB.NUMPED%TYPE;
    vvSituacao              PCPEDCOMPRAOPERLOGCAB.SITUACAO%TYPE;
    vvDescricaoSituacao     VARCHAR2(255);
    vnNumTransVendaOriginal PCPEDCOMPRAOPERLOGCAB.NUMTRANSVENDAORIGINAL%TYPE;
    
  BEGIN  
  
    -- Verifica se o Pedido de Operador Logístico já foi gravado e sua Situação
    P_OBTEM_SITUACAO_PEDIDO_CA_PBM(pi_nNumPed,
                                   vnNumPedOperLog,
                                   vvSituacao,
                                   vvDescricaoSituacao,
                                   vnNumTransVendaOriginal);
    
    -- Somente se está Pendente de Exportação que pode refazer o Pedido de Operador Logístico
    IF (NVL(vnNumPedOperLog,0) > 0)     AND
       (NVL(vvSituacao,'P') = 'P') THEN
      
      DELETE FROM PCPEDCOMPRAOPERLOGITE
            WHERE (NUMPED = vnNumPedOperLog);
    
    END IF;
                          
  END P_LIMPAR_ITENS_PEDIDO_CA_PBM;  

 /*********************************************************************
  PROCEDIMENTO : P_GRAVAR_PEDIDO_CA_PBM
  DESCRIÇÃO    : Procedimento para Gravação de Pedido que será enviado
                 para o Canal Autorizador CA PBM
  *********************************************************************/
  PROCEDURE P_GRAVAR_PEDIDO_CA_PBM(pi_nNumPed        IN NUMBER,
                                   pi_nCodCli        IN NUMBER, -- DDVENDAS-38983
                                   pi_nCodProd       IN NUMBER,
                                   pi_nNumSeq        IN NUMBER,
                                   pi_nIntegradora   IN NUMBER,
                                   pi_vCodFilial     IN VARCHAR2,
                                   pi_nCodMatricula  IN NUMBER,
                                   pi_nQtdePedida    IN NUMBER,
                                   po_nNumPedOperLog OUT NUMBER) IS

    vvSituacao              PCPEDCOMPRAOPERLOGCAB.SITUACAO%TYPE;
    vvDescricaoSituacao     VARCHAR2(255);
    vnCodFornec             PCPRODUT.CODFORNEC%TYPE;
    vnNumTransVendaOriginal PCPEDCOMPRAOPERLOGCAB.NUMTRANSVENDAORIGINAL%TYPE;
    -- DDVENDAS-38983
    vvEnviaPrePedidoApi     PCPEDCOMPRAOPERLOGCAB.ENVIAPREPEDIDOAPI%TYPE;
    vvArquivoPed            PCPEDCOMPRAOPERLOGCAB.ARQUIVOPED%TYPE;
    
  BEGIN  
  
    -- Verifica se o Pedido de Operador Logístico já foi gravado e sua Situação
    P_OBTEM_SITUACAO_PEDIDO_CA_PBM(pi_nNumPed,
                                   po_nNumPedOperLog,
                                   vvSituacao,
                                   vvDescricaoSituacao,
                                   vnNumTransVendaOriginal);
    
    -- Se o Pedido não existe, Insere
    IF (NVL(po_nNumPedOperLog,0) = 0) THEN
      
      -- Gera o Número de Pedido de Operador Logístico
      SELECT NVL(PCPEDCOMPRAOPERLOGCAB_DFSEQ.NEXTVAL,0) PROXNUMPEDOPERLOG
        INTO po_nNumPedOperLog
        FROM DUAL;
        
      -- Pesquisa o Fornecedor do Produto
      BEGIN
        SELECT CODFORNEC
          INTO vnCodFornec
          FROM PCPRODUT
         WHERE (CODPROD = pi_nCodProd);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCodFornec := NULL;
      END;  

      -- Verifica se Envia Pré-Pedido para a API - DDVENDAS-38983
      BEGIN
        SELECT PCLAYOUTINTEGRAVERSOPERLOG.ENVIAPREPEDIDOAPI
          INTO vvEnviaPrePedidoApi
          FROM PCINTEGRADORA
             , PCLAYOUTINTEGRAVERSOPERLOG
         WHERE (PCINTEGRADORA.LAYOUT      = PCLAYOUTINTEGRAVERSOPERLOG.LAYOUT)
           AND (PCINTEGRADORA.SEQVERSAO   = PCLAYOUTINTEGRAVERSOPERLOG.SEQVERSAO)
           AND (PCINTEGRADORA.INTEGRADORA = pi_nIntegradora);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvEnviaPrePedidoApi := 'N';
      END;
      
      -- Gera o NUMTRANSVENDA que será temporário somente para utilizar o processo da Nota Extra Padrão
      vnNumTransVendaOriginal := NULL;
      IF (NVL(vvEnviaPrePedidoApi,'N') <> 'S') THEN
        BEGIN
          EXECUTE IMMEDIATE 'SELECT FERRAMENTAS.F_PROX_NUMTRANSVENDA AS NUMTRANSVENDA FROM DUAL'
                       INTO vnNumTransVendaOriginal;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnNumTransVendaOriginal := NULL;
          WHEN OTHERS THEN
            vnNumTransVendaOriginal := NULL;
        END;
      END IF;
      
      -- Gera o ARQUIVOPED quando envia o Pré-Pedido para a API - DDVENDAS-38983
      vvArquivoPed := NULL;
      IF (NVL(vvEnviaPrePedidoApi,'N') = 'S') THEN
        BEGIN        
          SELECT 'PRE-PED_' || NVL(pi_nIntegradora,0) || '_' || REGEXP_REPLACE(PCCLIENT.CGCENT, '[^[:digit:]]') || '_' || NVL(pi_nNumPed,0) ARQUIVOPED
            INTO vvArquivoPed
            FROM PCCLIENT
           WHERE (CODCLI = pi_nCodCli);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvArquivoPed :=  'PRE-PED_' || NVL(pi_nIntegradora,0) || '_' || NVL(pi_nNumPed,0);
        END;
      END IF;
            
      -- Insere na PCPEDCOMPRAOPERLOGCAB
      INSERT INTO PCPEDCOMPRAOPERLOGCAB
                ( NUMPED
                , DTPED
                , CODFORNEC
                , CODFILIAL
                , CODUSUARIO
                , INTEGRADORA
                , SITUACAO
                , NUMPEDORIGINAL
                , NUMTRANSVENDAORIGINAL
                , ENVIAPREPEDIDOAPI -- DDVENDAS-38983
                , ARQUIVOPED
                , MODALIDADE -- DDVENDAS-41449                 
                )
          VALUES( po_nNumPedOperLog
                , TRUNC(SYSDATE)
                , vnCodFornec
                , pi_vCodFilial
                , pi_nCodMatricula
                , pi_nIntegradora
                , 'P' -- Situação Pendente
                , pi_nNumPed
                , vnNumTransVendaOriginal
                , vvEnviaPrePedidoApi -- DDVENDAS-38983
                , vvArquivoPed
                , 'V' -- DDVENDAS-41449 
                );
    
    -- Se o Pedido já existe
    ELSE
    
      -- Somente se está Pendente de Exportação que pode refazer o Pedido de Operador Logístico
      IF (NVL(vvSituacao,'P') = 'P') THEN
        
        -- Mudar a Integradora, podem ter sido trocados os produtos e com isso o contrato
        UPDATE PCPEDCOMPRAOPERLOGCAB
           SET INTEGRADORA = pi_nIntegradora
             , CODUSUARIO  = pi_nCodMatricula
         WHERE (NUMPED = po_nNumPedOperLog);
         
      END IF;
    
    END IF;
    
    -- Insere o Item
    BEGIN
      INSERT INTO PCPEDCOMPRAOPERLOGITE
                ( NUMPED
                , CODPROD
                , NUMSEQ
                , QTPED
                , INTEGRADORAPROD )
         VALUES ( po_nNumPedOperLog
                , pi_nCodProd
                , pi_nNumSeq
                , pi_nQtdePedida
                , pi_nIntegradora );
    EXCEPTION
      WHEN DUP_VAL_ON_INDEX THEN
        UPDATE PCPEDCOMPRAOPERLOGITE
           SET QTPED = pi_nQtdePedida
         WHERE (NUMPED  = po_nNumPedOperLog)
           AND (CODPROD = pi_nCodProd)
           AND (NUMSEQ  = pi_nNumSeq);
    END;
                      
  END P_GRAVAR_PEDIDO_CA_PBM;  

 /*********************************************************************
  FUNÇÃO    : F_CRITICA_PEDIDO_CA_PBM
  DESCRIÇÃO : Função para verificar críticas de Pedido que será enviado
              para o Canal Autorizador CA PBM
  *********************************************************************/
  FUNCTION F_CRITICA_PEDIDO_CA_PBM(pi_nNumPed IN NUMBER,
                                   pi_nCodCli IN NUMBER) -- DDVENDAS-38983
  RETURN VARCHAR2 IS

    vnNumPedOperLog            NUMBER;
    vvSituacaoPedOperLog       VARCHAR2(255);
    vvDescricaoSituacaoOperLog VARCHAR2(255);
    viItensPedido              INTEGER;
    viItensPbm                 INTEGER;
    viQtdePedido               INTEGER;
    viQtdePbm                  INTEGER;
    viQtdeContratosPbm         INTEGER;    
    vvRetMsgCriticas           VARCHAR2(255);
    vnNumTransVendaOriginal    PCPEDCOMPRAOPERLOGCAB.NUMTRANSVENDAORIGINAL%TYPE;
    vvEnviaPrePedidoApi        PCPEDCOMPRAOPERLOGCAB.ENVIAPREPEDIDOAPI%TYPE; -- DDVENDAS-38983   
    
  BEGIN  
  
    -- Inicializa Retorno 
    vvRetMsgCriticas := NULL;

    -- Obtém dados do Pedido PBM
    P_OBTEM_SITUACAO_PEDIDO_CA_PBM(pi_nNumPed,
                                   vnNumPedOperLog,
                                   vvSituacaoPedOperLog,
                                   vvDescricaoSituacaoOperLog,
                                   vnNumTransVendaOriginal);
  
    -- Verifica quantos itens tem no Pedido
    SELECT COUNT(DISTINCT CODPROD) 
         , SUM(QT)
      INTO viItensPedido
         , viQtdePedido
      FROM PCPEDI
     WHERE (NUMPED = pi_nNumPed);

    -- Verifica quantos itens tem no Pedido do Canal Autorizador - DDVENDAS-38983
    BEGIN
      SELECT PCPEDCOMPRAOPERLOGCAB.ENVIAPREPEDIDOAPI
           , COUNT(DISTINCT PCPEDCOMPRAOPERLOGITE.CODPROD) 
           , SUM(PCPEDCOMPRAOPERLOGITE.QTPED)
           , COUNT(DISTINCT PCPEDCOMPRAOPERLOGITE.INTEGRADORAPROD)
        INTO vvEnviaPrePedidoApi
           , viItensPbm
           , viQtdePbm
           , viQtdeContratosPbm
        FROM PCPEDCOMPRAOPERLOGITE
           , PCPEDCOMPRAOPERLOGCAB
       WHERE (PCPEDCOMPRAOPERLOGITE.NUMPED         = PCPEDCOMPRAOPERLOGCAB.NUMPED)
         AND (PCPEDCOMPRAOPERLOGCAB.NUMPEDORIGINAL = pi_nNumPed)
         AND (PCPEDCOMPRAOPERLOGCAB.MODALIDADE     = 'V') -- DDVENDAS-41449 
       GROUP BY PCPEDCOMPRAOPERLOGCAB.ENVIAPREPEDIDOAPI;  
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvEnviaPrePedidoApi := NULL;  
        viItensPbm          := 0;
        viQtdePbm           := 0; 
        viQtdeContratosPbm  := 0;
      WHEN TOO_MANY_ROWS THEN
        vvEnviaPrePedidoApi := NULL;  
        viItensPbm          := 0;
        viQtdePbm           := 0; 
        viQtdeContratosPbm  := 0;
        vvRetMsgCriticas    := 'Encontrado mais de um registro de reposição de PBM';
    END;
  
    -- Se existem Produtos do Canal Autorizador
    IF (NVL(viItensPbm,0) > 0) THEN
    
      -- Se problemas com o NUMTRANSVENDAORIGINAL (rejeição exclusiva Canal Autorizador)
      IF (NVL(vvEnviaPrePedidoApi,'N') <> 'S') AND -- DDVENDAS-38983
         (NVL(vnNumTransVendaOriginal,0) = 0)  THEN

        vvRetMsgCriticas := 'Pedido sem Sequencial de Transação';
      
      ELSE

        -- Se erro no Processamento no Canal Autorizador
        IF (NVL(vvSituacaoPedOperLog,'P') = 'E') THEN    
        
          vvRetMsgCriticas := 'Pedido com críticas no Canal Autorizador e não pode ser alterado.';

        -- Se existem mais produtos no Pedido que os do Canal Autorizador
        ELSIF (NVL(viItensPedido,0) > NVL(viItensPbm,0)) THEN
          
          vvRetMsgCriticas := 'Pedido com produtos do Canal Autorizador. Somente são permitidos produtos que fazem parte do contrato do Canal Autorizador.';
          
        -- Se houve alteração em SKUs do Pedido com itens do Canal Autorizador PBM
        ELSIF (NVL(viItensPedido,0) <> NVL(viItensPbm,0)) AND
              (NVL(vvSituacaoPedOperLog,'P') <> 'P')      THEN
        
          vvRetMsgCriticas := 'Existem alterações em SKUs no Pedido que não são permitidas após a solicitação de autorização com a Indústria';
        
        -- Se houve alteração em Qtde. do Pedido com itens do Canal Autorizador PBM
        ELSIF (NVL(viQtdePedido,0) <> NVL(viQtdePbm,0)) AND
              (NVL(vvSituacaoPedOperLog,'P') <> 'P')    THEN
        
          vvRetMsgCriticas := 'Existem alterações em unidades no Pedido que não são permitidas após a solicitação de autorização com a Indústria';
        
        -- Se existem produtos de Indústrias com contratos diferentes
        ELSIF (NVL(viQtdeContratosPbm,0) > 1) THEN
        
          vvRetMsgCriticas := 'Não são permitidos produtos de Indústrias de contratos diferentes do Canal Autorizador';
        
        END IF;
        
        -- Mensagem adicional com situação no Canal Autorizador
        -- (Diferente de: Pendente, Autorizado e Liberado)
        IF (NVL(vvSituacaoPedOperLog,'P') NOT IN ('P','A','L')) THEN
          vvRetMsgCriticas := vvRetMsgCriticas || ' (' || vvDescricaoSituacaoOperLog || ')'; 
        END IF;

      END IF;
    
    END IF;
    
    -- Retorno da Função
    RETURN vvRetMsgCriticas;
                      
  END F_CRITICA_PEDIDO_CA_PBM;  

 /***********************************************************************************************
  PROCEDIMENTO: P_HISTORICO_MOTIVO_BLOQ
  DESCRIÇÃO   : Histórico de Bloqueios
  ***********************************************************************************************/
  PROCEDURE P_HISTORICO_MOTIVO_BLOQ(pi_vChamadaProcesso IN VARCHAR2,
                                    pi_nNumPed          IN NUMBER,
                                    pi_nMatricula       IN NUMBER) IS
    vvNomeFuncLibera      PCEMPR.NOME%TYPE;
    nCODROTINA            PCMED_VALIDACAO_ESTOQUE_RESE_H.CODROTINA%TYPE;
    vNUMEROPARAMETRO      PCMED_VALIDACAO_ESTOQUE_RESE_H.NUMEROPARAMETRO%TYPE;
    vPERMISSAO            PCMED_VALIDACAO_ESTOQUE_RESE_H.PERMISSAO%TYPE;
    vREGRAPERMISSAO       PCMED_VALIDACAO_ESTOQUE_RESE_H.PERMISSAO%TYPE;
    -- Regra de Permissão
    vvUsaRegraPermissao   VARCHAR2(1);
    vvRegraPermissao      VARCHAR2(1);
    -- Liberação de Bloqueio da Rotina 320 - DDMEDICA-3918
    vvIgnoraAutoriLibBloq VARCHAR2(1);
  BEGIN

    -- Verifica se utiliza Regra de Permissão da Rotina 2345
    vvUsaRegraPermissao   := F_USA_REGRA_PERMISSAO;
    -- Verifica se Ignora Autorização do Bloqueio da Rotina 320 - DDMEDICA-3918
    vvIgnoraAutoriLibBloq := F_IGNORA_AUTORIZACAO_LIB_BLOQ;

    FOR vc_Historico IN (SELECT PCBLOQUEIOSPEDIDOMED.CODMOTIVO
                              , PCBLOQUEIOSPEDIDOMED.CODMOTBLOQUEIO
                              , PCBLOQUEIOSPEDIDOMED.MOTIVO
                              , PCBLOQUEIOSPEDIDOMED.CODFUNCLIBERA
                              , PCBLOQUEIOSPEDIDOMED.STATUS
                              , PCBLOQUEIOSPEDIDOMED.CODEVENTO
                              , PCBLOQUEIOSPEDIDOMED.CODREJEICAO
                              , PCBLOQUEIOSPEDIDOMED.DESCRICAOREJEICAO
                              , PCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO
                              , PCBLOQUEIOSPEDIDOMED.DTLIBERA
                              , PCBLOQUEIOSPEDIDOMED.DTINCLUSAO
                           FROM PCBLOQUEIOSPEDIDOMED
                          WHERE (PCBLOQUEIOSPEDIDOMED.NUMPED = pi_nNumPed)) LOOP

      -- Regra de Permissão da Matrícula ao Motivo de Bloqueio
      vvRegraPermissao := F_REGRA_PERMISSAO_MATRICULA(vvUsaRegraPermissao,
                                                      pi_nMatricula,
                                                      vc_Historico.CODMOTIVO,
                                                      vvIgnoraAutoriLibBloq,
                                                      vc_Historico.CODMOTBLOQUEIO);      

      -- Nome do Funcionário
      BEGIN
        SELECT NOME
          INTO vvNomeFuncLibera
          FROM PCEMPR
         WHERE (MATRICULA = vc_Historico.CODFUNCLIBERA);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvNomeFuncLibera := NULL;
      END;
      
      -- Pesquisa Dados do Tipo de Bloqueio
      BEGIN
        SELECT CODROTINA
             , NUMEROPARAMETRO
             , PERMISSAO
             , REGRAPERMISSAO
          INTO nCODROTINA
             , vNUMEROPARAMETRO
             , vPERMISSAO
             , vREGRAPERMISSAO
          FROM PCMED_VALIDACAO_ESTOQUE_RESE_H
         WHERE (NUMPED             = pi_nNumPed)
           AND (NVL(CODPLPAG,0)    = NVL(vc_Historico.CODEVENTO,0))
           AND (NVL(CODREJEICAO,0) = NVL(vc_Historico.CODREJEICAO,0))
           AND (ROWNUM             = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          nCODROTINA       := NULL;
          vNUMEROPARAMETRO := NULL;
          vPERMISSAO       := NULL;
          vREGRAPERMISSAO  := NULL;
      END;
 
      -->> Priorizar o Flag para indicar que não tem permissão da 530 e assim a chave ficar amarela na 2336     
      IF (NVL(vREGRAPERMISSAO,'X') = 'A') THEN
        vvRegraPermissao := vREGRAPERMISSAO;
      END IF;
      
      -- Insere Histórico
      P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                    , pi_nNumPed
                                    , vc_Historico.CODEVENTO
                                    , vc_Historico.CODREJEICAO
                                    , NULL -- pACAO
                                    , SUBSTR(vc_Historico.DESCRICAOREJEICAO,1,100)
                                    , nCODROTINA
                                    , NULL -- pVALORVALIDACAO
                                    , NULL -- pVALORATINGIDO
                                    , 'X'
                                    , vNUMEROPARAMETRO
                                    , vc_Historico.CODMOTIVO
                                    , vc_Historico.CODMOTBLOQUEIO
                                    , SUBSTR(vc_Historico.MOTIVO,1,60)
                                    , vPERMISSAO
                                    , NULL -- pSOLUCAOP4
                                    , 'L'  -->> Coloca L para sair na Página de Histórico
                                    , vc_Historico.CODFUNCLIBERA
                                    , vvNomeFuncLibera
                                    , vc_Historico.OBSERVACAOREJEICAO
                                    , vc_Historico.DTLIBERA
                                    , vc_Historico.DTINCLUSAO
                                    , vvRegraPermissao );
        
    END LOOP;

  END P_HISTORICO_MOTIVO_BLOQ;  

 /***********************************************************************************************
  PROCEDIMENTO: P_INSERIR_MOTIVO_BLOQ
  DESCRIÇÃO   : Inserir o Motivo de Bloqueio
  ***********************************************************************************************/
  PROCEDURE P_INSERIR_MOTIVO_BLOQ(pi_nNumPed             IN NUMBER,
                                  pi_nCodMotivo          IN NUMBER,
                                  pi_vMotivo             VARCHAR2,
                                  pi_nCodMotBloqueio     IN NUMBER,
                                  pi_nCodPlPag           IN NUMBER,
                                  pi_nCodRejeicao        IN NUMBER,
                                  pi_vDescricaoRejeicao  IN VARCHAR2,
                                  pi_vObservacaoRejeicao IN VARCHAR2) IS
    vvAchou                VARCHAR2(1);
    vnCodigo               PCBLOQUEIOSPEDIDOMED.CODIGO%TYPE;
    vvTipo                 PCMOTBLOQUEIO.TIPO%TYPE;
    vrPCBLOQUEIOSPEDIDOMED PCBLOQUEIOSPEDIDOMED%ROWTYPE;
  BEGIN

    -- Verifica se já inseriu o bloqueio (Não Liberado)
    BEGIN
      SELECT 'S'
        INTO vvAchou
        FROM PCBLOQUEIOSPEDIDOMED
       WHERE (PCBLOQUEIOSPEDIDOMED.NUMPED             = pi_nNumPed)
         AND (NVL(PCBLOQUEIOSPEDIDOMED.CODEVENTO,0)   = NVL(pi_nCodPlPag,0))
         AND (NVL(PCBLOQUEIOSPEDIDOMED.CODREJEICAO,0) = NVL(pi_nCodRejeicao,0))
         AND (PCBLOQUEIOSPEDIDOMED.DTLIBERA           IS NULL)
         AND (ROWNUM                                  = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvAchou := 'N';
    END;
    
    -- Se ainda não inseriu o motivo de bloqueio
    IF (vvAchou = 'N') THEN
    
      SELECT DFSEQ_PCBLOQUEIOSPEDIDOMED.NEXTVAL 
        INTO vnCodigo FROM DUAL;
        
      BEGIN
        SELECT PCMOTBLOQUEIO.TIPO
          INTO vvTipo
          FROM PCMOTBLOQUEIO
         WHERE (PCMOTBLOQUEIO.CODMOTIVO = pi_nCodMotivo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTipo := NULL;
      END;
  
      vrPCBLOQUEIOSPEDIDOMED.CODIGO             := vnCodigo;
      vrPCBLOQUEIOSPEDIDOMED.NUMPED             := pi_nNumPed;
      vrPCBLOQUEIOSPEDIDOMED.CODMOTIVO          := pi_nCodMotivo;
      vrPCBLOQUEIOSPEDIDOMED.CODMOTBLOQUEIO     := pi_nCodMotBloqueio;
      vrPCBLOQUEIOSPEDIDOMED.MOTIVO             := SUBSTR(pi_vMotivo, 1, 200);
      vrPCBLOQUEIOSPEDIDOMED.STATUS             := 'B';
      vrPCBLOQUEIOSPEDIDOMED.TIPO               := vvTipo;
      vrPCBLOQUEIOSPEDIDOMED.DTINCLUSAO         := SYSDATE;
      vrPCBLOQUEIOSPEDIDOMED.CODEVENTO          := pi_nCodPlPag;
      vrPCBLOQUEIOSPEDIDOMED.CODREJEICAO        := pi_nCodRejeicao;
      vrPCBLOQUEIOSPEDIDOMED.DESCRICAOREJEICAO  := pi_vDescricaoRejeicao;
      vrPCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO := pi_vObservacaoRejeicao;
  
      INSERT INTO PCBLOQUEIOSPEDIDOMED VALUES vrPCBLOQUEIOSPEDIDOMED;
            
    END IF;

  END P_INSERIR_MOTIVO_BLOQ;

 /***********************************************************************************************
  PROCEDIMENTO: P_INSERIR_MOTIVO_BLOQ_MANUAL
  DESCRIÇÃO   : Inserir o Motivo de Bloqueio Manual na 2336 - DDMEDICA-3918
  ***********************************************************************************************/
  PROCEDURE P_INSERIR_MOTIVO_BLOQ_MANUAL(pi_nNumPed    IN NUMBER,
                                         pi_nCodMotivo IN NUMBER,
                                         pi_nMatricula IN NUMBER) IS
    vvAchou                VARCHAR2(1);
    vnCodigo               PCBLOQUEIOSPEDIDOMED.CODIGO%TYPE;
    vvTipo                 PCMOTBLOQUEIO.TIPO%TYPE;
    vvDescricaoMotivo      PCMOTBLOQUEIO.DESCRICAO%TYPE;
    vrPCBLOQUEIOSPEDIDOMED PCBLOQUEIOSPEDIDOMED%ROWTYPE;    
  BEGIN

    -- Verifica se já inseriu o bloqueio (Não Liberado)
    BEGIN
      SELECT 'S'
        INTO vvAchou
        FROM PCBLOQUEIOSPEDIDOMED
       WHERE (PCBLOQUEIOSPEDIDOMED.NUMPED             = pi_nNumPed)
         AND (NVL(PCBLOQUEIOSPEDIDOMED.CODEVENTO,0)   = NVL(pi_nCodMotivo,0))
         AND (NVL(PCBLOQUEIOSPEDIDOMED.CODREJEICAO,0) = 8888)
         AND (PCBLOQUEIOSPEDIDOMED.DTLIBERA           IS NULL)
         AND (ROWNUM                                  = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvAchou := 'N';
    END;
    
    -- Se ainda não inseriu o motivo de bloqueio
    IF (vvAchou = 'N') THEN
    
      SELECT DFSEQ_PCBLOQUEIOSPEDIDOMED.NEXTVAL 
        INTO vnCodigo FROM DUAL;
        
      BEGIN
        SELECT PCMOTBLOQUEIO.TIPO
             , PCMOTBLOQUEIO.DESCRICAO
          INTO vvTipo
             , vvDescricaoMotivo
          FROM PCMOTBLOQUEIO
         WHERE (PCMOTBLOQUEIO.CODMOTIVO = pi_nCodMotivo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTipo            := NULL;
          vvDescricaoMotivo := NULL;
      END;
  
      vrPCBLOQUEIOSPEDIDOMED.CODIGO             := vnCodigo;
      vrPCBLOQUEIOSPEDIDOMED.NUMPED             := pi_nNumPed;
      vrPCBLOQUEIOSPEDIDOMED.CODMOTIVO          := pi_nCodMotivo;
      vrPCBLOQUEIOSPEDIDOMED.CODMOTBLOQUEIO     := NULL;
      vrPCBLOQUEIOSPEDIDOMED.MOTIVO             := SUBSTR(vvDescricaoMotivo, 1, 200);
      vrPCBLOQUEIOSPEDIDOMED.STATUS             := 'B';
      vrPCBLOQUEIOSPEDIDOMED.TIPO               := vvTipo;
      vrPCBLOQUEIOSPEDIDOMED.DTINCLUSAO         := SYSDATE;
      vrPCBLOQUEIOSPEDIDOMED.CODEVENTO          := pi_nCodMotivo;
      vrPCBLOQUEIOSPEDIDOMED.CODREJEICAO        := 8888;
      vrPCBLOQUEIOSPEDIDOMED.DESCRICAOREJEICAO  := 'Bloqueios Manuais';
      vrPCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO := 'Motivo ' || pi_nCodMotivo || ': ' || vvDescricaoMotivo || ' - gerado manualmente a partir da Rotina 2336';
  
      INSERT INTO PCBLOQUEIOSPEDIDOMED VALUES vrPCBLOQUEIOSPEDIDOMED;
            
    END IF;

  END P_INSERIR_MOTIVO_BLOQ_MANUAL;
  
 /***********************************************************************************************
  PROCEDIMENTO: P_LIBERAR_MOTIVO_BLOQ
  DESCRIÇÃO   : Liberar o Motivo de Bloqueio
  ***********************************************************************************************/
  PROCEDURE P_LIBERAR_MOTIVO_BLOQ(pi_nNumPed                      IN NUMBER,
                                  pi_nMatricula                   IN NUMBER,
                                  po_vBloqueioPendente           OUT VARCHAR2,
                                  po_nCodMotivoBloqueioPendente  OUT NUMBER,
                                  po_vMotivoBloqueioPendente     OUT VARCHAR2,
                                  po_vObservacaoBloqueioPendente OUT VARCHAR2) IS
    vOBSERVACAOREJEICAO  PCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO%TYPE;
    -- Regra de Permissão
    vvUsaRegraPermissao  VARCHAR2(1);
    vvRegraPermissao     VARCHAR2(1);
    -- Liberação de Bloqueio da Rotina 320 - DDMEDICA-3918
    vvIgnoraAutoriLibBloq VARCHAR2(1);
    
  BEGIN
  
    -- Inicializa Retorno
    po_vBloqueioPendente := 'N';
  
    -- Verifica se utiliza Regra de Permissão da Rotina 2345
    vvUsaRegraPermissao   := F_USA_REGRA_PERMISSAO;
    -- Verifica se Ignora Autorização do Bloqueio da Rotina 320 - DDMEDICA-3918
    vvIgnoraAutoriLibBloq := F_IGNORA_AUTORIZACAO_LIB_BLOQ;
  
    -- Cursor de Bloqueios não Liberados
    FOR vc_Bloqueio IN (SELECT PCBLOQUEIOSPEDIDOMED.CODMOTIVO
                             , PCBLOQUEIOSPEDIDOMED.CODMOTBLOQUEIO
                             , PCBLOQUEIOSPEDIDOMED.CODEVENTO
                             , PCBLOQUEIOSPEDIDOMED.CODREJEICAO
                          FROM PCBLOQUEIOSPEDIDOMED
                         WHERE (PCBLOQUEIOSPEDIDOMED.NUMPED = pi_nNumPed)
                           AND (PCBLOQUEIOSPEDIDOMED.DTLIBERA IS NULL)) LOOP
      
      -- Regra de Permissão da Matrícula ao Motivo de Bloqueio
      vvRegraPermissao := F_REGRA_PERMISSAO_MATRICULA(vvUsaRegraPermissao,
                                                      pi_nMatricula,
                                                      vc_Bloqueio.CODMOTIVO,
                                                      vvIgnoraAutoriLibBloq,
                                                      vc_Bloqueio.CODMOTBLOQUEIO);      
      
      -- Se a Matrícula tem Permissão para Liberar o Bloqueio
      IF (vvRegraPermissao = 'S') THEN
      
        -- Busca a nova Observação
        BEGIN
          SELECT PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO
            INTO vOBSERVACAOREJEICAO
            FROM PCMED_VALIDACAO_ESTOQUE_RESERV
           WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.NUMPED             = pi_nNumPed)
             AND (NVL(PCMED_VALIDACAO_ESTOQUE_RESERV.CODPLPAG,0)    = NVL(vc_Bloqueio.CODEVENTO,0))
             AND (NVL(PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO,0) = NVL(vc_Bloqueio.CODREJEICAO,0));
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vOBSERVACAOREJEICAO := NULL;
          WHEN TOO_MANY_ROWS THEN
            -- Se achar mais de uma linha mantém a observação original
            vOBSERVACAOREJEICAO := NULL;
        END;
       
        UPDATE PCBLOQUEIOSPEDIDOMED
           SET PCBLOQUEIOSPEDIDOMED.CODFUNCLIBERA      = pi_nMatricula
             , PCBLOQUEIOSPEDIDOMED.DTLIBERA           = SYSDATE
             , PCBLOQUEIOSPEDIDOMED.STATUS             = 'L' -->> Liberado
             , PCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO = NVL(vOBSERVACAOREJEICAO,PCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO)
         WHERE (PCBLOQUEIOSPEDIDOMED.NUMPED             = pi_nNumPed)
           AND (NVL(PCBLOQUEIOSPEDIDOMED.CODEVENTO,0)   = NVL(vc_Bloqueio.CODEVENTO,0))
           AND (NVL(PCBLOQUEIOSPEDIDOMED.CODREJEICAO,0) = NVL(vc_Bloqueio.CODREJEICAO,0))
           AND (PCBLOQUEIOSPEDIDOMED.DTLIBERA           IS NULL) ;

      END IF; -- Fim Condição: Permissão para Liberar o Bloqueio
             
    END LOOP;                         

    -- Verifica se algum Bloqueio ainda está pendente de Aprovação
    po_vBloqueioPendente           := 'N';
    po_nCodMotivoBloqueioPendente  := NULL;
    po_vMotivoBloqueioPendente     := NULL;
    po_vObservacaoBloqueioPendente := NULL;    
    FOR vc_BloqueiosPendentes IN (SELECT PCBLOQUEIOSPEDIDOMED.CODMOTIVO
                                       , PCBLOQUEIOSPEDIDOMED.MOTIVO
                                       , PCBLOQUEIOSPEDIDOMED.OBSERVACAOREJEICAO
                                    FROM PCBLOQUEIOSPEDIDOMED
                                   WHERE (PCBLOQUEIOSPEDIDOMED.NUMPED = pi_nNumPed)
                                     AND (NVL(PCBLOQUEIOSPEDIDOMED.STATUS,'P') <> 'L')
                                     AND (ROWNUM = 1)) LOOP
      po_vBloqueioPendente           := 'S';
      po_nCodMotivoBloqueioPendente  := vc_BloqueiosPendentes.CODMOTIVO;
      po_vMotivoBloqueioPendente     := vc_BloqueiosPendentes.MOTIVO;
      po_vObservacaoBloqueioPendente := vc_BloqueiosPendentes.OBSERVACAOREJEICAO;    
    END LOOP;        
    
  END P_LIBERAR_MOTIVO_BLOQ;  
  
 /***********************************************************************************************
  PROCEDIMENTO: P_APLICAR_REDUCAO_COMISSAO
  DESCRIÇÃO   : Obter a Região do Cliente
  ***********************************************************************************************/
  PROCEDURE P_APLICAR_REDUCAO_COMISSAO(pi_vCodFilial    IN NUMBER,
                                       pi_nNumRegiao    IN NUMBER,
                                       pi_nCodUsur      IN NUMBER,
                                       pi_nCodEmitente  IN NUMBER,
                                       pio_nPerCom      IN OUT NUMBER,
                                       po_nPerRedComiss OUT NUMBER) IS
    -- 
    vnCodUsurEmitente PCUSUARI.CODUSUR%TYPE;
    --
  BEGIN
  
    -- Inicializa Retorno
    po_nPerRedComiss := NULL;
  
    -- Pesquisa o Código do RCA do Emitente
    BEGIN
      SELECT CODUSUR
        INTO vnCodUsurEmitente
        FROM PCEMPR
       WHERE (MATRICULA = pi_nCodEmitente);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnCodUsurEmitente := NULL;
    END;
    
    -- Só executa a redução de comissão se o RCA da Venda for Diferente do RCA logado no winthor
    IF (NVL(vnCodUsurEmitente,0) <> NVL(pi_nCodUsur,0)) THEN
    
      -- Pesquisa o Redutor de Comissão
      BEGIN
        SELECT NVL(PCCOMISSMEDREDUCAO.PERREDCOMISS,0) PERREDCOMISS
         INTO po_nPerRedComiss
         FROM PCCOMISSMEDREDUCAO
        WHERE (CODFILIAL = pi_vCodFilial)
          AND (NUMREGIAO = pi_nNumRegiao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_nPerRedComiss := NULL;
      END;
      
      -- Se tem Redutor de Comissão
      IF (NVL(po_nPerRedComiss,0) > 0) THEN
        pio_nPerCom := pio_nPerCom * (1 - (NVL(po_nPerRedComiss,0) / 100));
      END IF;
      
    END IF;
  
  END P_APLICAR_REDUCAO_COMISSAO;
  
 /***********************************************************************************************
  PROCEDIMENTO: P_OBTER_REGIAO_CLIENTE
  DESCRIÇÃO   : Obter a Região do Cliente
  ***********************************************************************************************/
  PROCEDURE P_OBTER_REGIAO_CLIENTE(pi_nCodCli     IN NUMBER,
                                   pi_vCodFilial  IN VARCHAR2,
                                   po_nNumRegiao OUT NUMBER) IS
    vnCodPraca PCCLIENT.CODPRACA%TYPE;
  BEGIN
  
    -- Inicializa Retorno
    po_nNumRegiao := NULL;
      
    -- Pesquisa Região do Cliente por Filial
    BEGIN
      SELECT NUMREGIAO
        INTO po_nNumRegiao
        FROM PCTABPRCLI
       WHERE (CODCLI      = pi_nCodCli)
         AND (CODFILIALNF = pi_vCodFilial);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_nNumRegiao := NULL;
    END;
  
    -- Se não achou Regiao do Cliente por Filial
    IF (po_nNumRegiao IS NULL) THEN
  
      -- Pesquisa a Praça do Cliente
      BEGIN
        SELECT CODPRACA
          INTO vnCodPraca
          FROM PCCLIENT
         WHERE (CODCLI = pi_nCodCli);
      EXCEPTION
       WHEN NO_DATA_FOUND THEN
         vnCodPraca := NULL;
      END;
  
      -- Pesquisa Região da Praça
      BEGIN
        SELECT NUMREGIAO
          INTO po_nNumRegiao
          FROM PCPRACA
         WHERE (CODPRACA = vnCodPraca);
      EXCEPTION
       WHEN NO_DATA_FOUND THEN
          po_nNumRegiao := NULL;
      END;
    END IF;    
 
  END P_OBTER_REGIAO_CLIENTE; 
  
 /***********************************************************************************************
  PROCEDIMENTO: P_OBTER_TRIBUTACAO
  DESCRIÇÃO   : Obter a Tributação do Produto
  ***********************************************************************************************/
  PROCEDURE P_OBTER_TRIBUTACAO(pi_nCodProd         IN NUMBER,
                               pi_nCodCli          IN NUMBER,
                               pi_vCodFilial       IN VARCHAR2,
                               pi_nNumRegiao       IN NUMBER,
                               po_nCodSt          OUT NUMBER,
                               po_vMensagem       OUT VARCHAR2,
                               po_nRotinaMensagem OUT NUMBER) IS
    vvEstEnt             PCCLIENT.ESTENT%TYPE;
    vvUsaTributacaoPorUf PCCONSUM.USATRIBUTACAOPORUF%TYPE;
    e_tratado            EXCEPTION;
  BEGIN
  
    -- Inicializa Retornos
    po_nCodSt    := NULL;
    po_vMensagem := NULL;
    
    ----------------------
    -- Pesquisa Parâmetros
    ----------------------
    BEGIN
      SELECT NVL(USATRIBUTACAOPORUF,'N') USATRIBUTACAOPORUF
        INTO vvUsaTributacaoPorUf
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_vMensagem := 'Não foram encontrados dados na PCCONSUM';
        RAISE e_tratado;
    END;
    
    ----------------------------
    -- Pesquisa Dados do Cliente
    ----------------------------
    BEGIN
      SELECT PCCLIENT.ESTENT
        INTO vvEstEnt
        FROM PCCLIENT
       WHERE (PCCLIENT.CODCLI = pi_nCodCli);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_vMensagem := 'Não foram encontrados dados do Cliente ' || NVL(pi_nCodCli,0);
        RAISE e_tratado;
    END;
  
    ---------------------------
    -- Se usa Tributação por UF
    ---------------------------
    IF (NVL(vvUsaTributacaoPorUf,'N') = 'S') THEN
    
     po_nRotinaMensagem := 574; 
    
      -- Pesquisa Tributação por UF
      BEGIN
        SELECT CODST
          INTO po_nCodSt
          FROM PCTABTRIB
         WHERE (CODPROD     = pi_nCodProd)
           AND (UFDESTINO   = vvEstEnt)
           AND (CODFILIALNF = pi_vCodFilial);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_nCodSt := NULL;
      END;
      IF (NVL(po_nCodSt,0) = 0) THEN
        po_vMensagem := 'Não foi encontrada Tributação para o Produto ' || NVL(pi_nCodProd,0) || ', UF Destino [' || NVL(vvEstEnt,' ') || '] e Filial [' || NVL(pi_vCodFilial,' ' ||']');
        RAISE e_tratado;
      END IF;
    
    -------------------------------
    -- Se Não usa Tributação por UF
    -------------------------------
    ELSE
    
     po_nRotinaMensagem := 271; 

      -- Pesquisa Tributação por Região
      BEGIN
        SELECT CODST
          INTO po_nCodSt
          FROM PCTABPR
         WHERE (CODPROD   = pi_nCodProd)
           AND (NUMREGIAO = pi_nNumRegiao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_nCodSt := NULL;
      END;
      IF (NVL(po_nCodSt,0) = 0) THEN
        po_vMensagem := 'Não foi encontrada Tributação para o Produto ' || NVL(pi_nCodProd,0) || ' e Região ' || NVL(pi_nNumRegiao,0);
        RAISE e_tratado;
      END IF;
        
    END IF; -- Fim Condição v_usatributacaoporuf
    
    -- Se Achou a Tributação
    IF (NVL(po_nCodSt,0) > 0) THEN
      -- Pesquisa Tributação por Região
      BEGIN
        SELECT CODST
          INTO po_nCodSt
          FROM PCTRIBUT
         WHERE (CODST = po_nCodSt);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vMensagem := 'Não foi encontrado o código ' || NVL(po_nCodSt,0) || ' no cadastro da tributação';
          RAISE e_tratado;
      END;    
    END IF;
    
  EXCEPTION
    WHEN e_tratado THEN
      po_nCodSt := NULL;
    WHEN OTHERS THEN  
      po_nCodSt := NULL;
      po_vMensagem    := 'Erro ao obter a Tributação: ' || SUBSTR('Erro: ' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,240);    
  END P_OBTER_TRIBUTACAO;
  
 /***********************************************************************************************
  PROCEDIMENTO: P_BLOQUEIO_LIMCRED
  DESCRIÇÃO   : Validar Limite de Crédito do Cliente - MED-1499
  ***********************************************************************************************/
  PROCEDURE P_BLOQUEIO_LIMCRED(pi_nMatricula                IN NUMBER,
                               pi_nCodRotina                IN NUMBER,
                               pi_nNumPed                   IN NUMBER,
                               pi_nCodCli                   IN NUMBER,
                               pi_nCodUsur                  IN NUMBER,
                               pi_nValorPedido              IN NUMBER,
                               pi_vSomaCreditoCliPrincipal  IN VARCHAR2,
                               pi_vUsaBnfLimiteCredito      IN VARCHAR2,
                               pi_nPerExcedeLimCred         IN NUMBER,
                               pi_vBloqPedLimCred           IN VARCHAR2,
                               pi_nNumCasasDecVenda         IN NUMBER,
                               pi_vChamadaProcesso          IN VARCHAR2,
                               pi_vPosicaoFinalPedido       IN VARCHAR2,
                               po_vRejeitado               OUT VARCHAR2,
                               po_vGravarComoBloqueado     OUT VARCHAR2,
                               po_vDescricaoRejeicao       OUT VARCHAR2,
                               po_vMotivoPosicao           OUT VARCHAR2,
                               po_vObservacao              OUT VARCHAR2,
                               po_vLogRetorno              OUT VARCHAR2) IS
                             
    -- Variáveis para Validação do Cliente                          
    vnCODCLIPRINC               PCCLIENT.CODCLIPRINC%TYPE;
    
    -- Record de Retorno das Validações
    TYPE TRecRetValidacao       IS RECORD(
         vvRejeitado            VARCHAR2(1),
         vvMotivoRejeitado      VARCHAR2(255),
         vvObservacao           VARCHAR2(32000),
         vvRetJson              VARCHAR2(32000),
         vvGravarComoBloqueado  VARCHAR2(1),
         vnValorRetSaldoDisp    NUMBER,
         vnLimiteCredito        NUMBER,
         vnLimiteCreditoTotal   NUMBER,
         vvLogRetorno           VARCHAR2(32000));
    vrRetValidacao              TRecRetValidacao;
    
    --DDMEDICA-1706
    vAtualizarAutorizacao       VARCHAR2(1);
    vnVLAUTORMENSAL             NUMBER;
    vnVlMaxAutorizacao          NUMBER;
    vnProxNumAutorizacao        NUMBER;

    --DDMEDICA-1706 - Função para retornar o valor total autorizado mensal
    FUNCTION func_RetonarVlAutorMensal(pi_nCodCli    IN NUMBER,
                                       pi_nMatricula IN NUMBER) RETURN NUMBER IS
      vnRetVlAutorMensal NUMBER;                                   
    BEGIN

      vnRetVlAutorMensal := 0;
      
      SELECT SUM(NVL(PCAUTORC.VLLIBERADO, 0)) SOMA_VLLIBERADO
        INTO vnRetVlAutorMensal
        FROM PCAUTORC
       WHERE CODCLI = pi_nCodCli
         AND CODFUNC = pi_nMatricula
         AND PCAUTORC.DATA BETWEEN TO_DATE('01/' || TO_CHAR(SYSDATE, 'MM/YYYY'), 'DD/MM/YYYY') AND TRUNC(SYSDATE);

      RETURN vnRetVlAutorMensal;     
      
    END func_RetonarVlAutorMensal;
    
    --DDMEDICA-1706 - Função para retornar o limite adicional do funcionário
    FUNCTION func_RetornarPercExcLimCred(pi_nMatricula IN NUMBER) RETURN NUMBER IS
      vnRetPercExcLimCred NUMBER;
    BEGIN
    
      vnRetPercExcLimCred := 0;
      
      BEGIN
        SELECT PERCEXCLIMCRED
          INTO vnRetPercExcLimCred
          FROM PCEMPR
         WHERE MATRICULA = pi_nMatricula;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnRetPercExcLimCred := 0;
      END;
      
      RETURN vnRetPercExcLimCred;

    END func_RetornarPercExcLimCred;    
    
    --DDMEDICA-1706 - Função para retornar o valor de Pedidos Pendentes
    FUNCTION func_BuscarVlPedidosPendentes(pi_nCodCli IN NUMBER) RETURN NUMBER IS
      vnRetVlPedidosPendentes NUMBER;
    BEGIN
    
      vnRetVlPedidosPendentes := 0;
    
      SELECT SUM (NVL (VLATEND, 0)) VLATEND
        INTO vnRetVlPedidosPendentes
        FROM PCPEDC
       WHERE CODCLI = pi_nCodCli
         AND DTCANCEL IS NULL
         AND POSICAO IN ('P', 'B');
    
      RETURN vnRetVlPedidosPendentes;

    END func_BuscarVlPedidosPendentes;
    
    --DDMEDICA-1706 - Compartilhado Procedimento Auxiliar
    procedure proc_atualizarpcautorc(pi_nNumPedAux      IN NUMBER,
                                     pi_nCodUsurAux     IN NUMBER,
                                     pi_nCodCliAux      IN NUMBER,
                                     pi_nVlPendenteAux  IN NUMBER,
                                     pi_nLimCredAux     IN NUMBER,
                                     pi_nMatricula      IN NUMBER, --DDMEDICA-1706
                                     pi_nNumAutorizacao IN NUMBER) --DDMEDICA-1706
    is  
    begin
      
      IF (NVL(pi_nNumAutorizacao,0) > 0) THEN
        for reg in (select *
                    from pcautorc
                    where numpedido = pi_nNumAutorizacao
                      and codfuncutilizacao is null
                      and dtutilizacao is null
                      for update) loop
    
          exit;
        end loop;
    
        update pcautorc
        set  limcred = pi_nLimCredAux
             ,vlpendente = pi_nVlPendenteAux
             ,dtutilizacao = trunc(sysdate)
             ,codfuncutilizacao = pi_nMatricula --DDMEDICA-1706 - Permitir uso tanto pela Integradora como pela 2336
             ,numpedutilizacao = pi_nNumPedAux
        where numpedido = pi_nNumAutorizacao
        and codfuncutilizacao is null
        and dtutilizacao is null;
      END IF;
  
    end proc_atualizarpcautorc;
    
    -- Procedure Auxiliar para Validação do Limite do Cliente -----------------
    PROCEDURE proc_validacreditocliente(pi_nMatricula               IN  NUMBER,
                                        pi_nCodRoina                IN  NUMBER,
                                        pi_nNumPed                  IN  NUMBER,
                                        pi_nCodCli                  IN  NUMBER,
                                        pi_nCodCliPrincipal         IN  NUMBER,
                                        pi_nCodUsur                 IN  NUMBER,
                                        pi_nVlTotPed                IN  NUMBER,
                                        pi_vSomaCreditoCliPrincipal IN  VARCHAR2,
                                        pi_vUsaBnfLimiteCredito     IN  VARCHAR2,
                                        pi_nPerExcedeLimCred        IN  NUMBER,
                                        pi_nNumCasasDecVenda        IN  NUMBER,
                                        pi_vAtualizarAutorizacao    IN  VARCHAR2,
                                        pi_vBloqPedLimCred          IN  VARCHAR2,
                                        po_vRejeitado               OUT VARCHAR2,
                                        po_vMotivoRejeitado         OUT VARCHAR2,
                                        po_vObservacao              OUT VARCHAR2,
                                        po_vJsonRejeitado           OUT VARCHAR2,
                                        po_vGravarComoBloqueado     OUT VARCHAR2,
                                        po_nValorRetorno            OUT VARCHAR2,
                                        po_nLimiteCredito           OUT NUMBER,
                                        po_nLimiteCreditoTotal      OUT NUMBER,
                                        po_vLogDetalheLimiteRetorno OUT VARCHAR2) IS
      -- Variáveis
      vvOrientacaoCondicaoNaoCad VARCHAR2(32000);
      vvOrientacaoDetalheLimCred VARCHAR2(32000);
      vncontasareceberemaberto   number;
      vnvalorpedidospendentes    number;
      vnsaldodisponivel          number;
      vbpodecomprar              boolean;
      vnvalorautorizacao         number;
      vnNumAutorizacao           number; -- DDMEDICA-5501
      --DDMEDICA-1245
      vdatavalidadecredito       date;
      -- Valor da Autorização de Crédito já aplicado no Pedido - DDMEDICA-5501
      vnVlAutoriAplicadoNoPedido number;
      -- Valor de Autorização de Crédito Prioritária para o Número do Pedido - DDMEDICA-5501
      vnValorAutoriC_Prioritaria number;
      -- Parâmetro Específico
      vUSALIMCREDSANZONALPEDIDO  PCREGRASEXCECAOMED.VALOR%TYPE;
      -- Valor Total em Cheques - DDVENDAS-38538
      vnvalortotalcheques        number;
      -- Limite Crédito Extra - DDVENDAS-38538
      vnLimiteCreditoExtra       number;
      -- Limite Crédito Sazonal - DDVENDAS-38538
      vnLimiteCreditoSanzonal    number;
      -- Saldo Disponivel Total
      vnsaldodisponiveltotal     number;
      
      -- Função Auxiliar
      function func_validaautorizacaopcautorc(pi_nCodRotina                  IN NUMBER, -- DDMEDICA-5501 
                                              pi_nNumPed                     IN NUMBER, -- DDMEDICA-5501 
                                              pi_nCodCliAux                  IN NUMBER,
                                              pi_nCodCliPrincipalAux         IN NUMBER,
                                              pi_nCodUsur                    IN NUMBER,
                                              pi_vSomaCreditoCliPrincipalAux IN VARCHAR2,
                                              pi_nVlDispAux                  IN NUMBER,
                                              pi_nVlAtendAux                 IN NUMBER,
                                              po_nNumAutorizacao             OUT NUMBER, -- DDMEDICA-5501 
                                              po_nValorAutorizPrioritaria    OUT NUMBER) -- DDMEDICA-5501 
      return number is
  
        vnvlliberado    number;
        vnNumPedLiberar number; -- DDMEDICA-5501
  
      begin
        
        -- Inicializa Retornos - DDMEDICA-5501
        vnvlliberado                := 0;
        po_nNumAutorizacao          := NULL;
        po_nValorAutorizPrioritaria := NULL;
  
        begin            
          select pcautorc.vlliberado
               , pcautorc.numpedido     -- DDMEDICA-5501
               , pcautorc.numpedliberar -- DDMEDICA-5501
            into vnvlliberado
               , po_nNumAutorizacao -- DDMEDICA-5501
               , vnNumPedLiberar    -- DDMEDICA-5501
            from pcautorc, pcempr
            where ((pcautorc.codcli = pi_nCodCli) OR
                (pi_vSomaCreditoCliPrincipalAux = 'S' and ( pcautorc.codcli in (select pcclient.codcli from pcclient where codcliprinc = pi_nCodCliPrincipalAux))))
             and pcautorc.codusur = pi_nCodUsur
             and pcautorc.codfunc = pcempr.matricula
             and pcautorc.liberalimcred = 'S'
             and pcautorc.dtutilizacao is null
             and pcautorc.codfuncutilizacao is null
             and (nvl(pi_nVlDispAux,0) + nvl(pcautorc.vlliberado,0)) >= pi_nVlAtendAux
             and rownum = 1;
       exception 
         -- DDMEDICA-5501
         when no_data_found then
           -- Verifica se tem alguma autorização criada exclusivamente para o Pedido que está sendo liberado e atende o valor do pedido
           BEGIN
             select pcautorc.vlliberado
                  , pcautorc.numpedido       
                  , pcautorc.numpedliberar
               into vnvlliberado
                  , po_nNumAutorizacao
                  , vnNumPedLiberar
               from pcautorc
               where pcautorc.liberalimcred = 'S'
                 and pcautorc.dtutilizacao is null
                 and pcautorc.codfuncutilizacao is null
                 and pcautorc.numpedliberar = pi_nNumPed          -->> AUTORIZAÇÃO EXCLUSIVA PARA O PEDIDO
                 and nvl(pcautorc.vlliberado,0) >= pi_nVlAtendAux -->> VALOR SUFICIENTE PARA O PEDIDO
                 and rownum = 1;
           EXCEPTION
             WHEN NO_DATA_FOUND THEN
               vnvlliberado       := 0;
               po_nNumAutorizacao := NULL;
               vnNumPedLiberar    := NULL;
           END;
         when others then
           vnvlliberado       := 0;
           po_nNumAutorizacao := NULL; -- DDMEDICA-5501
           vnNumPedLiberar    := NULL; -- DDMEDICA-5501
       end;
       
       -- Retornará também o valor de autorização prioritária para o pedido que será liberado -- DDMEDICA-5501
       IF (pi_nCodRotina = 2336) AND
          (NVL(pi_nNumPed,0) = NVL(vnNumPedLiberar,0)) THEN
         po_nValorAutorizPrioritaria := NVL(vnvlliberado,0); 
       END IF; 
  
       return vnvlliberado;
  
      end func_validaautorizacaopcautorc;
        
      -- Calcular o Valor da Autorização de Crédito que já foi aplicado no Pedido - DDMEDICA-5501
      function func_AutoriC_AplicadaNoPedido(pi_nNumPed     IN NUMBER,
                                             pi_nVlAtendAux IN NUMBER)
      return number is
  
        vnvlliberado number;
  
      begin
        
        -- Pega o maior valor autorizado que ainda atenda o valor do pedido
        select max(pcautorc.vlliberado)
          into vnvlliberado
          from pcautorc
         where pcautorc.numpedutilizacao = pi_nNumPed
           and pcautorc.dtutilizacao is not null
           and pcautorc.codfuncutilizacao is not null
           and nvl(pcautorc.vlliberado,0) >= pi_nVlAtendAux;
                        
       return vnvlliberado;
  
      end func_AutoriC_AplicadaNoPedido;
        
      procedure proc_adicionar_limite_sanzonal(pi_nCodCli                 IN NUMBER,
                                               pi_nCodUsur                IN NUMBER,
                                               pi_nLimiteCredito          IN NUMBER,
                                               pio_nSaldoDisponivel       IN OUT NUMBER,
                                               pio_nLimiteCreditoTotal    IN OUT NUMBER,  
                                               po_vMensagemLimiteSanzonal OUT VARCHAR2) is
        vnPercLimiteSanzonal  NUMBER;                                         
        vnValorLimiteSanzonal NUMBER;                                         
      begin
      
        po_vMensagemLimiteSanzonal := NULL;
      
        vnPercLimiteSanzonal := 0;
        FOR vc_Limite IN (SELECT percaumento
                            FROM pclimcred
                           WHERE pclimcred.coddcli = pi_nCodCli
                             AND TRUNC( SYSDATE ) BETWEEN pclimcred.dtinicio AND pclimcred.dtfim
                             AND (    ( pclimcred.codusur IS NULL )
                                  OR ( pclimcred.codusur = pi_nCodUsur ) )) LOOP
          vnPercLimiteSanzonal := vc_Limite.percaumento;
          EXIT;
        END LOOP;                          
        IF (NVL(vnPercLimiteSanzonal,0) <> 0) THEN
          vnValorLimiteSanzonal      := ROUND(NVL(pi_nLimiteCredito,0) * (NVL(vnPercLimiteSanzonal,0) / 100),2);
          po_vMensagemLimiteSanzonal := '% Limite de crédito sanzonal = ' || vnPercLimiteSanzonal;
          po_vMensagemLimiteSanzonal := po_vMensagemLimiteSanzonal || CHR(13) ||
                                        '(+) Valor do acréscimo de limite de crédito sanzonal = ' || vnValorLimiteSanzonal;
          pio_nSaldoDisponivel       := NVL(pio_nSaldoDisponivel,0) + NVL(vnValorLimiteSanzonal,0);
          pio_nLimiteCreditoTotal    := NVL(pio_nLimiteCreditoTotal,0) + NVL(vnValorLimiteSanzonal,0);
        END IF;

      end proc_adicionar_limite_sanzonal;
  
    -- INICIO PROCEDIMENTO
    BEGIN
  
      -- Inicializa Retornos
      po_vRejeitado            := 'N';
      po_vMotivoRejeitado      := NULL;
      po_vObservacao           := NULL;
      po_vJsonRejeitado        := NULL;
      po_vGravarComoBloqueado  := NULL;
      po_nValorRetorno         := 0;
      po_nLimiteCredito        := 0;
      po_nLimiteCreditoTotal   := 0;
  
      vnsaldodisponivel        := 0;
      vnsaldodisponiveltotal   := 0;
      vbpodecomprar            := FALSE;
      
      -- Parâmetro Específico
      vUSALIMCREDSANZONALPEDIDO := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','USALIMCREDSANZONALPEDIDO');  
      
      -- Pendencias no contas a receber do cliente
      vncontasareceberemaberto := PKG_LIMITECREDITO.RETORNA_CONTAS_RECEBER_ABERTO(pi_nCodCli);
      vnvalorpedidospendentes  := PKG_LIMITECREDITO.RETORNA_PEDIDOS_FATURAR(pi_nCodCli, pi_nNumPed);
      
      -- Total em Cheques
      vnvalortotalcheques      := PKG_LIMITECREDITO.RETORNA_TOTAL_CHEQUE(pi_nCodCli);
      
      -- Guarda Limite de Crédito para Retorno
      po_nLimiteCredito        := PKG_LIMITECREDITO.RETORNA_LIMITE_CREDITO_CLIENTE(pi_nCodCli);
      
      -- Limite de Crédito Sazonal 
      vnLimiteCreditoSanzonal  := PKG_LIMITECREDITO.RETORNA_LIMITE_CREDITO_SAZONAL(pi_nCodCli,
                                                                                   pi_nCodUsur);
      
      -- Saldo Disponivel
      vnsaldodisponivel        := PKG_LIMITECREDITO.RETORNA_LIMITE_CRED_DISPONIVEL(pi_nCodCli,
                                                                                   TRUE,  -- UTILIZALIMITEEXTRA
                                                                                   FALSE, -- UTILIZALIMITEPARCEIROS
                                                                                   pi_nNumPed);
      
      -- Limite de crédito extra
      vnLimiteCreditoExtra     := PKG_LIMITECREDITO.RETORNA_LIMITE_CREDITO_EXTRA(pi_nCodCli);

      -- Saldo Disponível Total (com Sanzonal)
      vnsaldodisponiveltotal   := NVL(vnsaldodisponivel,0) + NVL(vnLimiteCreditoSanzonal,0);

      -- Limite Crédito Total com Extra para Retorno
      po_nLimiteCreditoTotal   := (nvl(po_nLimiteCredito,0) + NVL(vnLimiteCreditoExtra,0));

      -- Se NÃO Considera o Limite Disponível do Cliente Principal
      IF (NVL(pi_vSomaCreditoCliPrincipal,'N') = 'N') THEN

        --DDMEDICA-1245
        begin
          select NVL(trunc(pcclient.dtvenclimcred),trunc(sysdate))
            into vdatavalidadecredito
            from pcclient
           where (pcclient.codcli =  pi_nCodCli);
        exception
          when others then
            vdatavalidadecredito := trunc(sysdate);
        end;
      
      ELSE
      
        --DDMEDICA-1245
        begin
          select NVL(trunc(pcclient.dtvenclimcred),trunc(sysdate))
            into vdatavalidadecredito
            from pcclient
           where (pcclient.codcliprinc =  pi_nCodCliPrincipal OR pcclient.codcli = pi_nCodCli);
        exception
          when others then
            vdatavalidadecredito := trunc(sysdate);
        end;

      END IF;

      -- Permissão na 2316 - Desmarcado permite digitar pedidos com data liite vencido
      IF (pi_nCodRotina = 2316) AND (NOT F_VERIFICARACESSOCONTROLE(pi_nCodRotina, 50, pi_nMatricula)) THEN
         vdatavalidadecredito := trunc(sysdate);
      END IF;

      IF vdatavalidadecredito >= trunc(sysdate) THEN
                                                              
        -- DDMEDICA-5501
        -- Retorna o valor da autorização de crédito que já foi aplicado anteriormente no pedido
        -- e que ainda atende o valor total do pedido
        vnVlAutoriAplicadoNoPedido := func_AutoriC_AplicadaNoPedido(pi_nNumPed,
                                                                    nvl(pi_nVlTotPed,0));


        -- DDMEDICA-5501
        -- Se já foi aplicadada anteriormente uma autorização de crédito
        -- neste Pedido e ainda é válida (ainda atende o valor total do pedido)
        -- não precisará validar o Limite de Crédito
        if    (nvl(vnVlAutoriAplicadoNoPedido,0) > 0) then
        
          vbpodecomprar := true;

        -- Calcula o valor disponivel de credito para o cliente
        elsif (nvl(pi_nVlTotPed,0) > nvl(vnsaldodisponiveltotal,0)) then
      
          vnvalorautorizacao := func_validaautorizacaopcautorc(pi_nCodRoina, -- DDMEDICA-5501
                                                               pi_nNumPed,   -- DDMEDICA-5501
                                                               pi_nCodCli,
                                                               pi_nCodCliPrincipal,
                                                               pi_nCodUsur,
                                                               pi_vSomaCreditoCliPrincipal,
                                                               nvl(vnsaldodisponiveltotal,0),
                                                               nvl(pi_nVlTotPed,0),
                                                               vnNumAutorizacao,            -- DDMEDICA-5501
                                                               vnValorAutoriC_Prioritaria); -- DDMEDICA-5501 
          
          -- Se com a autorização ficou com crédito suficiente (Regra Atual)
          -- OU
          -- Se Autorização de Crédito Prioritária para o Pedido não precisa validar o Limite de Crédito - DDMEDICA-5501           
          if ((nvl(vnsaldodisponiveltotal,0) + nvl(vnvalorautorizacao,0)) >= nvl(pi_nVlTotPed,0)) or
             (nvl(vnValorAutoriC_Prioritaria,0) > 0) then 
  
            -- Se chamado para atualizar a autorização
            IF (pi_vAtualizarAutorizacao = 'S') THEN
              proc_atualizarpcautorc(pi_nNumPed,
                                     pi_nCodUsur,
                                     pi_nCodCli,
                                     (NVL(vncontasareceberemaberto, 0) +  NVL(vnvalorpedidospendentes, 0)), --DDMEDICA-1706 - Obs: Na 2316 passa somente o saldo de pedidos
                                     nvl(po_nLimiteCredito,0),
                                     pi_nMatricula, --DDMEDICA-1706
                                     vnNumAutorizacao); --DDMEDICA-5501
            END IF;
  
            vbpodecomprar := true;
  
          else
         
            vbpodecomprar := false;
            
          end if;
      
        else
      
          vbpodecomprar := true;
        
        end if;
                  
      ELSE
      
        vbpodecomprar := false;
        
      END IF;
      
      --INICIO: LOG DETALHAMENTO DO LIMITE DE CRÉDITO - DDMEDICA-3551
      vvOrientacaoDetalheLimCred := '*** Observações do Limite de Crédito do Cliente ***' || CHR(13);
      IF (NVL(pi_vSomaCreditoCliPrincipal,'N') = 'S') THEN
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '* Empresa considera o limite de crédito disponível do cliente principal (Parâmetro 2553).' || CHR(13) ||
                                      'Código do Cliente Principal = "' || pi_nCodCliPrincipal || '"';
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '>> Valor do limite de crédito do cliente principal = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(po_nLimiteCredito,0),2);
      ELSE
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '* Empresa não considera o limite de crédito disponível do cliente principal (Parâmetro 2553).';
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '>> Valor do limite de crédito do cliente = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(po_nLimiteCredito,0),2);
      END IF;
  
      IF (nvl(vnLimiteCreditoExtra,0) <> 0) THEN
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(+) Valor do acréscimo permitido para exceder o limite de crédito = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnLimiteCreditoExtra,0),2);
      END IF;
  
      IF (NVL(pi_vUsaBnfLimiteCredito,'N') = 'S') THEN
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '* Empresa usa bonificações em aberto para diminuir o limite de crédito do cliente (Parâmetro 2583).';
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(-) Valor do contas a receber em aberto com bonificações = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vncontasareceberemaberto,0),2);
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(-) Valor do saldo de pedidos não faturados com bonificações = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnvalorpedidospendentes,0),2);
      ELSE
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '* Empresa não usa bonificações em aberto para diminuir o limite de crédito do cliente (Parâmetro 2583)).';
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(-) Valor do contas a receber em aberto sem bonificações = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vncontasareceberemaberto,0),2);
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(-) Valor do saldo de pedidos não faturados sem bonificações = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnvalorpedidospendentes,0),2);
      END IF;

      -- DDVENDAS-38538
      vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                    '(-) Total em Cheques = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnvalortotalcheques,0),2);
      
      IF (NVL(vnvalorautorizacao,0) <> 0) THEN
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(+) Valor adicional de limite autorizado = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnvalorautorizacao,0),2);
      END IF;
      vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                    '(=) SALDO DISPONIVEL = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnsaldodisponivel,0) + nvl(vnvalorautorizacao,0),2);

      -- DDVENDAS-38538
      IF (NVL(vnLimiteCreditoSanzonal,0) > 0) THEN
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(+) Sazonalidade de Limite de Crédito (Rotina 3321) = ' || ROUND(nvl(vnLimiteCreditoSanzonal,0),2);
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '(=) SALDO DISPONIVEL + Limite Sazonal  = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnsaldodisponiveltotal,0),2);
      END IF;                                

      vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) || CHR(13) ||
                                    '>> VALOR TOTAL DO PEDIDO = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(pi_nVlTotPed,0),2);
      -- Autorização de Crédito já aplicado no Pedido - DDMEDICA-5501
      IF (NVL(vnVlAutoriAplicadoNoPedido,0) > 0) THEN
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '** Valor de autorização de crédito aplicado anteriormente para o pedido = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnVlAutoriAplicadoNoPedido,0),2);
      END IF;       
      -- Valor de Autorização de Crédito Prioritária para o Número do Pedido - DDMEDICA-5501
      IF (NVL(vnValorAutoriC_Prioritaria,0) > 0) THEN               
        vvOrientacaoDetalheLimCred := vvOrientacaoDetalheLimCred || CHR(13) ||
                                      '** Valor de autorização de crédito prioritária para o pedido = ' || F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnValorAutoriC_Prioritaria,0),2);
      END IF;        
      --FIM: LOG DETALHAMENTO DO LIMITE DE CRÉDITO - DDMEDICA-3551
      
      -- SE NÃO PODE COMPRAR
      IF (NOT vbpodecomprar) THEN
  
        po_vRejeitado       := 'S';
  
        --DDMEDICA-1245
        IF vdatavalidadecredito >= trunc(sysdate) THEN
          po_vMotivoRejeitado := 'Cliente sem Limite de Crédito Disponível';
          po_vObservacao      := 'O Valor Total do Pedido: ' ||  F_FORMATAR_NUMERO_PARA_TEXTO(nvl(pi_nVlTotPed,0),2) || CHR(13) ||
                                 'superior ao Limite de Crédito Disponível: ' ||  F_FORMATAR_NUMERO_PARA_TEXTO(nvl(vnsaldodisponivel,0),2);
  
          -- Se está deixando gravar como Bloqueado
          IF (NVL(pi_vBloqPedLimCred,'N') = 'S') THEN
            po_vGravarComoBloqueado    := 'S'; -->> Gravar o Pedido como Bloqueado
            vvOrientacaoCondicaoNaoCad := 'Para gravar o Pedido na posição Liberado (não bloquear o Pedido), verifique com o departamento financeiro a possibilidade de aumentar o Limite de Crédito do Cliente.';
          -- Se está rejeitando
          ELSE
            vvOrientacaoCondicaoNaoCad := 'Alternativas para não rejeitar o Pedido: ' || CHR(13) ||
                                          '- Alterar o Parâmetro da Presidência "2697" para gravar o Pedido como Bloqueado.' || CHR(13) ||
                                          '- Verificar com o departamento financeiro a possibilidade de aumento do Limite de Crédito do Cliente.';
            vvOrientacaoCondicaoNaoCad := vvOrientacaoCondicaoNaoCad || CHR(13) ||
                                          'Após revisão do Limite de Crédito do Cliente, o Pedido poderá ser reprocessado na Consulta de Pedidos da Rotina 2302, na aba "Pedidos", podendo ser feita a multi-seleção de Pedidos para reprocessamento.';
          END IF;
  
        ELSE
          po_vMotivoRejeitado := 'Cliente com a data de vencimento do Limite de Crédito utrapassado';
          po_vObservacao      := 'A data de vencimento do limite de crédito do cliente : ' ||  vdatavalidadecredito  || CHR(13) ||
                                 'superior a data atual: ' ||  trunc(sysdate);
  
          -- Se está deixando gravar como Bloqueado
          IF (NVL(pi_vBloqPedLimCred,'N') = 'S') THEN
            po_vGravarComoBloqueado    := 'S'; -->> Gravar o Pedido como Bloqueado
            vvOrientacaoCondicaoNaoCad := 'Para gravar o Pedido na posição Liberado (não bloquear o Pedido), verifique com o departamento financeiro a possibilidade de alterar a data de vencimento do Limite de Crédito do Cliente.';
          -- Se está rejeitando
          ELSE
            vvOrientacaoCondicaoNaoCad := 'Alternativas para não rejeitar o Pedido: ' || CHR(13) ||
                                          '- Alterar o Parâmetro da Presidência "2697" para gravar o Pedido como Bloqueado.' || CHR(13) ||
                                          '- Verificar com o departamento financeiro a possibilidade de alterar a data de vencimento do Limite de Crédito Cliente.';
            vvOrientacaoCondicaoNaoCad := vvOrientacaoCondicaoNaoCad || CHR(13) ||
                                          'Após revisão da data de vencimento do Limite de Crédito do Cliente, o Pedido poderá ser reprocessado na Consulta de Pedidos da Rotina 2302, na aba "Pedidos", podendo ser feita a multi-seleção de Pedidos para reprocessamento.';
          END IF;
        END IF;
  
        vvOrientacaoCondicaoNaoCad := vvOrientacaoCondicaoNaoCad || CHR(13) || CHR(13) ||
                                      vvOrientacaoDetalheLimCred; -- DDMEDICA-3551
  
      END IF;
  
      -- Retornará o Saldo Disponível calculado
      po_nValorRetorno := nvl(vnsaldodisponivel,0);

      -- Retornará também o Log de Detalhamento do Limite de Crédito - DDMEDICA-3551
      po_vLogDetalheLimiteRetorno := vvOrientacaoDetalheLimCred;
  
    END proc_validacreditocliente;
    
  -- INICIO DA FUNÇÃO
  BEGIN
  
    -- Inicializa Retornos
    po_vRejeitado           := 'N';
    po_vGravarComoBloqueado := NULL;
    po_vDescricaoRejeicao   := 'Cliente sem limite de credito / data vencto. limite credito.';
    po_vMotivoPosicao       := 'Cliente sem limite de credito / data vencto. limite credito.';
    po_vObservacao          := NULL;

    -- Inicio da Validação
    BEGIN
    
      -- Pesquisa Dados do Cliente
      BEGIN
        SELECT PCCLIENT.CODCLIPRINC
          INTO vnCODCLIPRINC
          FROM PCCLIENT
         WHERE (CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCODCLIPRINC := NULL;
      END;
      
      -- DDMEDICA-1706 - Define se realiza Autorização de Crédito Adicional
      IF (pi_vChamadaProcesso IN ('MP','GP')) THEN
        vAtualizarAutorizacao := 'S';
      ELSE
        vAtualizarAutorizacao := 'N';
      END IF;
    
      -- Validação
      proc_validacreditocliente(pi_nMatricula,
                                pi_nCodRotina,
                                pi_nNumPed,
                                pi_nCodCli,
                                vnCODCLIPRINC,
                                pi_nCodUsur,
                                pi_nValorPedido,
                                pi_vSomaCreditoCliPrincipal,
                                pi_vUsaBnfLimiteCredito,
                                pi_nPerExcedeLimCred,
                                pi_nNumCasasDecVenda,
                                vAtualizarAutorizacao, -->> Atualizar Autorização de Crédito adicional se houver
                                pi_vBloqPedLimCred,
                                vrRetValidacao.vvRejeitado,
                                vrRetValidacao.vvMotivoRejeitado,
                                vrRetValidacao.vvObservacao,
                                vrRetValidacao.vvRetJson,
                                vrRetValidacao.vvGravarComoBloqueado,
                                vrRetValidacao.vnValorRetSaldoDisp,
                                vrRetValidacao.vnLimiteCredito,
                                vrRetValidacao.vnLimiteCreditoTotal,
                                vrRetValidacao.vvLogRetorno);
    
    EXCEPTION
      WHEN OTHERS THEN
        po_vDescricaoRejeicao := 'Erro na validação: ' || SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000);
    END;

    ----------------------------------------------------------------
    -- DDMEDICA-1706 - Limites Adicionais da 2336 ao Mudar a Posição
    ----------------------------------------------------------------
    IF (pi_nCodRotina = 2336)               AND
       (pi_vChamadaProcesso IN ('VM','MP')) AND
       (vrRetValidacao.vvRejeitado = 'S')   THEN
      
      IF (NOT F_VERIFICARACESSOCONTROLE(pi_nCodRotina, 46, pi_nMatricula)) AND
         (NOT F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
      

        vrRetValidacao.vvObservacao := '* Usuário sem permissão para liberar pedido com limite de crédito excedido *' || CHR(13) || vrRetValidacao.vvObservacao;
      
      ELSE
         
        vnVLAUTORMENSAL := func_RetonarVlAutorMensal(pi_nCodCli, 
                                                     pi_nMatricula);
                     
        -- O Limite de Crédito da Autorização para o Funcionário é o Limite do Cliente + Extra + Sanzonal
        vnVlMaxAutorizacao := NVL(vrRetValidacao.vnLimiteCreditoTotal,0) * (NVL(func_RetornarPercExcLimCred(pi_nMatricula),0) / 100);
  
        IF (NVL(vnVlMaxAutorizacao,0) = 0) THEN
          vrRetValidacao.vvObservacao := '* Usuário não pode conceder autorização de crédito *' || CHR(13) || vrRetValidacao.vvObservacao;
        ELSE
          IF (NVL(vnVLAUTORMENSAL,0) >= (NVL(vnVlMaxAutorizacao,0) + NVL(pi_nValorPedido,0))) THEN
            vrRetValidacao.vvObservacao := '* Usuário não pode conceder mais autorização de crédito *'                                                  || CHR(13) ||
                                           'Somatória de limite de crédito autorizado no valor de ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnVLAUTORMENSAL,2)  || CHR(13) ||
                                           ' superou o limite do usuário no valor de ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnVlMaxAutorizacao,2)            || CHR(13) ||
                                           '(Ajuste o limite de crédito do cliente ou ajuste o % Excesso limite de crédito do usuario na rotina 528)'   || CHR(13) || 
                                           vrRetValidacao.vvObservacao;
          ELSE
            -- Saldo Dispoível  menor que Valor do Pedido
            IF (NVL(vrRetValidacao.vnValorRetSaldoDisp,0) < NVL(pi_nValorPedido,0)) THEN
            
              -- DDMEDICA-6631 - Zera o Saldo de Limite de Crédito se estiver negativo para não afetar as operações matemáticas com subtração de negativo
              IF (NVL(vrRetValidacao.vnValorRetSaldoDisp,0) < 0) THEN
                vrRetValidacao.vnValorRetSaldoDisp := 0;
              END IF;
            
              -- Somente ao mudar a posição do pedido para Liberado que cria a autorização de limite de crédito
              IF (pi_vChamadaProcesso    = 'MP') AND
                 (pi_vPosicaoFinalPedido = 'L') THEN
            
                SELECT DFSEQ_PCAUTORC.NEXTVAL SEQ
                  INTO vnProxNumAutorizacao
                  FROM DUAL;
                  
                INSERT INTO pcautorc
                          ( numpedido
                          , DATA
                          , codfunc
                          , liberalimcred
                          , codcli
                          , codusur
                          , codplpag
                          , vlliberado
                          , liberarporpedido
                          , numpedliberar
                          , obs )
                     VALUES
                          ( vnProxNumAutorizacao
                          , TRUNC(SYSDATE)
                          , pi_nMatricula
                          , 'S'
                          , pi_nCodCli
                          , pi_nCodUsur
                          , 0
                          , (NVL(pi_nValorPedido,0) - NVL(vrRetValidacao.vnValorRetSaldoDisp,0))
                          , 'LP'
                          , pi_nNumPed
                          , 'Autorização automáticamente gerada pela rotina 2336' );
                          
                proc_atualizarpcautorc(pi_nNumPed,
                                       pi_nCodUsur,
                                       pi_nCodCli,
                                       func_BuscarVlPedidosPendentes(pi_nCodCli),
                                       nvl(vrRetValidacao.vnLimiteCredito,0), -- Grava na Autorização somente o Limite do Cliente
                                       pi_nMatricula, --DDMEDICA-1706                       
                                       vnProxNumAutorizacao); --DDMEDICA-5501
                
                -- Não é mais Rejeitado
                vrRetValidacao.vvRejeitado           := 'N';
                vrRetValidacao.vvObservacao          := 'Autorização de Crédito Nº ' || vrRetValidacao.vvGravarComoBloqueado ||
                                                        ' no valor de ' || F_FORMATAR_NUMERO_PARA_TEXTO((NVL(pi_nValorPedido,0) - NVL(vrRetValidacao.vnValorRetSaldoDisp,0)),2) ||
                                                        '.' || CHR(13) || vrRetValidacao.vvObservacao;
                vrRetValidacao.vvGravarComoBloqueado := 'N';
                
              -- Prévia do que irá acontecer ao Mudar a Posição na Validação do Mínimo
              ELSIF (pi_vChamadaProcesso    = 'VM') AND
                    (pi_vPosicaoFinalPedido = 'L') THEN

                -- Não é mais Rejeitado
                vrRetValidacao.vvRejeitado           := 'N';
                vrRetValidacao.vvObservacao          := 'Será gerada uma autorização de crédito no valor de ' || F_FORMATAR_NUMERO_PARA_TEXTO((NVL(pi_nValorPedido,0) - NVL(vrRetValidacao.vnValorRetSaldoDisp,0)),2) ||
                                                        ' ao mudar a posição do pedido.' || CHR(13) || vrRetValidacao.vvObservacao;
                vrRetValidacao.vvGravarComoBloqueado := 'N';
                    
              END IF; -- Fim Condição: Somente ao mudar a posição do pedido para Liberado que cria a autorização de limite de crédito
             
            END IF;        
          END IF;                                 
        END IF; 
        
      END IF; -- Fim: Permissão para Liberar Pedido sem Limite de Crédito
      
    END IF; -- Fim: Limites Adicionais da 2336
      
    -- Atualiza Retornos
    po_vRejeitado           := vrRetValidacao.vvRejeitado;
    po_vGravarComoBloqueado := vrRetValidacao.vvGravarComoBloqueado;
    po_vDescricaoRejeicao   := SUBSTR(vrRetValidacao.vvObservacao,1,250);
    po_vMotivoPosicao       := SUBSTR(vrRetValidacao.vvMotivoRejeitado,250);    
    po_vObservacao          := vrRetValidacao.vvObservacao;
    po_vLogRetorno          := vrRetValidacao.vvLogRetorno; -- DDMEDICA-3551
      
  END P_BLOQUEIO_LIMCRED; 
                
 /*********************************************************************
  FUNÇÃO   : F_BLOQUEIO_RCA
  DESCRIÇÃO: Validação de RCA Bloqueado
  *********************************************************************/
  FUNCTION F_BLOQUEIO_RCA(pi_nCodUsur            IN NUMBER,
                          po_vDescricaoRejeicao OUT VARCHAR2,
                          po_vMotivoPosicao     OUT VARCHAR2) RETURN BOOLEAN IS
    vsRCABLOQUEADO VARCHAR2(1);
  BEGIN
  
    -- Inicializa OK
    vsRCABLOQUEADO        := 'N';
  
    -- Inicializa Retornos
    po_vDescricaoRejeicao := 'RCA Bloqueado';
    po_vMotivoPosicao     := 'RCA Bloqueado';
    
    -- Inicializa Validação
    BEGIN
    
      BEGIN
        SELECT PCUSUARI.BLOQUEIO
          INTO vsRCABLOQUEADO
          FROM PCUSUARI
         WHERE (PCUSUARI.Codusur = pi_nCodUsur);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vsRCABLOQUEADO := 'N';
      END;
      
    EXCEPTION
      WHEN OTHERS THEN
        vsRCABLOQUEADO        := 'S';
        po_vDescricaoRejeicao := 'Erro na validação: ' || SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000);
    END;
    
    -- Atualiza Retorno
    RETURN (vsRCABLOQUEADO = 'S');
    
  END F_BLOQUEIO_RCA;
                
 /*********************************************************************
  FUNÇÃO   : F_BLOQUEIO_CLIENTE
  DESCRIÇÃO: Validação de Cliente Bloqueado
  *********************************************************************/
  FUNCTION F_BLOQUEIO_CLIENTE(pi_nCodCli                    IN NUMBER,
                              pi_vCodCob                    IN VARCHAR2,
                              pi_vVerificarLimCredCodCobD   IN VARCHAR2,
                              pi_vAceitaVendaAVistaCliBloq  IN VARCHAR2,
                              po_vDescricaoRejeicao        OUT VARCHAR2,
                              po_vMotivoPosicao            OUT VARCHAR2) RETURN BOOLEAN IS
    vsCLIBLOQUEADO    VARCHAR2(1);
    vsCLIENTESREDBLOQ VARCHAR2(2000);
    viCONTACLIREDBLOQ INTEGER;
  BEGIN

    -- Inicializa OK
    vsCLIBLOQUEADO        := 'N';
      
    -- Inicializa Retornos
    po_vDescricaoRejeicao := 'Cliente Bloqueado';
    po_vMotivoPosicao     := 'Cliente Bloqueado';
    
    -- Inicializa Validação
    BEGIN
    
      BEGIN
        SELECT NVL(PCCLIENT.BLOQUEIO,'N')
          INTO vsCLIBLOQUEADO
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vsCLIBLOQUEADO := 'N';
      END;
      
      IF (NVL(vsCLIBLOQUEADO,'N') <> 'S') THEN
  
        IF FERRAMENTAS.F_BUSCARPARAMETRO_ALFA('CON_VERIFICARCLIENTESREDE', '99', 'N') = 'S' THEN
    
          vsCLIENTESREDBLOQ := NULL;
          viCONTACLIREDBLOQ := 0;
    
          FOR DADOS IN (SELECT CODCLI
                          FROM PCCLIENT
                         WHERE (CODCLIPRINC = NVL((SELECT NVL(CODCLIPRINC,CODCLI)
                                                     FROM PCCLIENT
                                                    WHERE CODCLI = pi_nCodCli), -1))
                           AND (NVL(BLOQUEIO, 'N') = 'S')) LOOP
                           
            IF (NVL(LENGTH(vsCLIENTESREDBLOQ),0) <= 1800) THEN
              IF (vsCLIENTESREDBLOQ IS NOT NULL) THEN
                vsCLIENTESREDBLOQ := vsCLIENTESREDBLOQ || ' ,';
              END IF;
              vsCLIENTESREDBLOQ := vsCLIENTESREDBLOQ || DADOS.CODCLI;
            END IF;
            
            viCONTACLIREDBLOQ := NVL(viCONTACLIREDBLOQ,0) + 1;
            
          END LOOP;
          
          IF (NVL(viCONTACLIREDBLOQ,0) > 0) THEN
            vsCLIBLOQUEADO        := 'S';
            IF (NVL(viCONTACLIREDBLOQ,0) = 1) THEN
              po_vDescricaoRejeicao := 'Cliente da rede bloqueado: ' || vsCLIENTESREDBLOQ;
            ELSE
              po_vDescricaoRejeicao := 'Clientes da rede bloqueados: ' || vsCLIENTESREDBLOQ;
            END IF;
          END IF;
      
        END IF; -- (CON_VERIFICARCLIENTESREDE)
        
      END IF; -- (NVL(vsCLIBLOQUEADO,'N') <> 'S')
       
      -- Validação Venda à Vista
      IF (NVL(vsCLIBLOQUEADO,'N') = 'S') AND (pi_vCodCob IN ('D', 'DH', 'CAR')) AND
         (NVL(pi_vVerificarLimCredCodCobD,'N') = 'N')                           AND
         (NVL(pi_vAceitaVendaAVistaCliBloq,'N') = 'S')                          THEN
        vsCLIBLOQUEADO := 'N';
      END IF;
      
    EXCEPTION
      WHEN OTHERS THEN
        vsCLIBLOQUEADO        := 'S';
        po_vDescricaoRejeicao := 'Erro na validação: ' || SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000);
    END;
    
    -- Atualiza Retorno
    RETURN (vsCLIBLOQUEADO = 'S');
    
  END F_BLOQUEIO_CLIENTE;
    
 /*********************************************************************
  FUNÇÃO   : F_BLOQUEIO_SEFAZ
  DESCRIÇÃO: Validação de Bloqueio do Cliente no SEFAZ
  *********************************************************************/
  FUNCTION F_BLOQUEIO_SEFAZ(pi_nCodCli             IN NUMBER,
                            po_vDescricaoRejeicao OUT VARCHAR2,
                            po_vMotivoPosicao     OUT VARCHAR2) RETURN BOOLEAN IS
    vsBLOQUEIOSEFAZPED VARCHAR2(1);
    vsCLIENTESREDBLOQ  VARCHAR2(2000);
    viCONTACLIREDBLOQ  INTEGER;
  BEGIN

    -- Inicializa OK
    vsBLOQUEIOSEFAZPED := 'N';
      
    -- Inicializa Retornos
    po_vDescricaoRejeicao := 'Bloqueio SEFAZ';
    po_vMotivoPosicao     := 'Bloqueio SEFAZ';
    
    -- Inicializa Validação
    BEGIN
    
      BEGIN
        SELECT NVL(PCCLIENT.BLOQUEIOSEFAZPED,'N')
          INTO vsBLOQUEIOSEFAZPED
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vsBLOQUEIOSEFAZPED := 'N';
      END;
      
      IF (NVL(vsBLOQUEIOSEFAZPED,'N') = 'S') THEN
        po_vDescricaoRejeicao := 'Cliente com Bloqueio no SEFAZ';
      END IF;
      
    EXCEPTION
      WHEN OTHERS THEN
        vsBLOQUEIOSEFAZPED    := 'S';
        po_vDescricaoRejeicao := 'Erro na validação: ' || SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000);
    END;
    
    -- Atualiza Retorno
    RETURN (vsBLOQUEIOSEFAZPED = 'S');
    
  END F_BLOQUEIO_SEFAZ;

 /*******************************************************************************
  Nome         : F_REGIAO_INATIVA
  Descricão    : Função para Validar a Inadimplência de Clientes
  ********************************************************************************/    
  FUNCTION F_REGIAO_INATIVA(pi_nNumRegiao IN NUMBER,
                            po_vMensagem OUT VARCHAR2) RETURN BOOLEAN IS
    vvStatus PCREGIAO.STATUS%TYPE;
  BEGIN
  
    -- Inicializa Retorno
    po_vMensagem := NULL;
  
    BEGIN
      SELECT PCREGIAO.STATUS
        INTO vvStatus
        FROM PCREGIAO
       WHERE (NUMREGIAO = pi_nNumRegiao);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvStatus := 'I';
    END;
    
    IF (vvStatus = 'I') THEN
      po_vMensagem := 'Região ' || pi_nNumRegiao || ' inativada.';
    END IF;
    
    -- Retorno
    RETURN  (vvStatus = 'I');
    
  END F_REGIAO_INATIVA;
                  
  /*******************************************************************************
   Nome         : PRC_MED_VALIDA_CONTROLE_VENDA
   Descricão    : Procedimento para validar o Controle de Venda do Produto para
                  os Clientes
   Parâmetros   : ENTRADA:
                  pi_vTipoChamada          = Tipo de Chamada
                                             'I' - Inclusão do Item no Pedido
                                             'G' - Gravação do Pedido
                                             'P' - Inicio da Digitação do Pedido
                  pi_nCodCli               = Código do Cliente
                  pi_vTipoFJ               = Tipo de Pessoa Fisica ou Juridica
                                             [F-Fisica;J-Juridica]
                  pi_nCodProd              = Código do Produto
                  pi_nQtdeVenda            = Qtde. Vendida
                  pi_nNumPed               = Número Pedido
                  pi_nNumSeq               = Número da Sequência do Item
                  SAIDA:
                  po_vPodeComprarProduto   = Se o Cliente pode Comprar o Produto
                                             [S-Sim;N-Não]
                  po_vMotivoNaoPodeComprar = Descrição do Motivo de não poder comprar
                  po_nQtdeLimite           = Quantidade Limite que pode comprar
   Alteracão    : Anderson Silva - 09/09/2013 - Criação da Procedure [Tarefa: 210309]
   Alteracão    : Anderson Silva - 02/04/2014 - Novos Tipos de Controle HIS.01334.2014
                                              - Novo campo isenção distribuidores
   Alteracão    : Anderson Silva - 01/05/2014 - Ajuste Calculo Isenção
   Alteracão    : Anderson Silva - 06/06/2014 - HIS.01779.2014 Cortar somente a 
                                                quantidade excedida Alvará
   Alteração    : Anderson Silva - 22/05/2014 - HIS.00517.2015 - Devoluções                                              
   Alteração    : Anderson Silva - 07/12/2017 - HIS.01687.2017 - Controle de Gramatura                                              
  ********************************************************************************/                                       
  PROCEDURE P_VALIDA_CONTROLE_VENDA(pi_vTipoChamada          IN  VARCHAR2,
                                    pi_nCodCli               IN  NUMBER,
                                    pi_vTipoFJ               IN  VARCHAR2,
                                    pi_nCodProd              IN  NUMBER,
                                    pi_nQtdeVenda            IN  NUMBER,   
                                    pi_nNumPed               IN  NUMBER,                                     
                                    pi_nNumSeq               IN  NUMBER,
                                    po_vPodeComprarProduto   OUT VARCHAR2,
                                    po_vMotivoNaoPodeComprar OUT VARCHAR2,
                                    po_nQtdeLimite           OUT VARCHAR,
                                    pi_nCodRotina            IN  NUMBER DEFAULT NULL)
  IS
  
    -- Array para receber os dados dos Tipos de Controle de Venda do Cliente
    TYPE TRecDadosControleVenCli IS RECORD(
         vNUMDOC                 PCCLICONTROLEVENDA.NUMDOC%TYPE,
         dDTVALIDADE             PCCLICONTROLEVENDA.DTVALIDADE%TYPE);
    TYPE TTvDadosControleVenCli  IS TABLE OF TRecDadosControleVenCli INDEX BY BINARY_INTEGER;
    vtDadosControleVenCli        TTvDadosControleVenCli;   
    
    -- Variáveis para identificar se o Cliente pode Comprar o Produto
    vbCliPodeComprarProduto      BOOLEAN;  
    vvMotivoNaoPodeComprarProd   VARCHAR2(240);
    
    -- Variável para receber o total de venda no mês
    vnTotalVendaMes              NUMBER;
    
    -- Segmento do Cliente
    vTIPOCLIMED                  PCCLIENT.TIPOCLIMED%TYPE;
    
    -- Peso Limite - HIS.01687.2017
    vnPesoVendaItemPedido        NUMBER;
    vnPesoTotalExcedido          NUMBER;
    vnQtEquivalentePesoExcedido  NUMBER;
    
    -- Parâmetro de Controle de Venda
    vVALIDALVARAPORTIPOCTLVEN    PCPARAMFILIAL.VALOR%TYPE;
    vDIGITARPEDIDOCLIENTEALVARA  PCPARAMFILIAL.VALOR%TYPE;

    -- Parâmetro Alvará - DDMEDICA-6213
    vVALIDALVARAFUNCLIBERADOS      VARCHAR2(255);  
    -- Parâmetro para Ignorar Alvará SUS - DDMEDICA-6491
    vIGNORARVALIDACAOALVARASUS     VARCHAR2(255);  
    -- Parâmetro para Ignorar Alvará CRF - DDMEDICA-6491
    vIGNORARVALIDACAOALVARACRF     VARCHAR2(255);  
    -- Parâmetro para Aceitar Pedido de Cliente com Alvará Vencido recebidos pela Integradora - DDMEDICA-6545
    vACEITARPEDALVARAVENCINTEGRAD  VARCHAR2(255);  

    ------------------------------------------------------------------------------
    -- Função para obter o Total de Venda no Mês
    ------------------------------------------------------------------------------
    FUNCTION F_OBTEMVENDAMES(pi_vDeduzDevolucoes IN VARCHAR2) RETURN NUMBER IS
      -- Data Inicial de Final do mês atual
      vnDataInicialMesAtu DATE;  
      vnDataFinalMesAtu   DATE;  
      -- Totais de Venda do Mês
      vnTotalPedido       NUMBER;
      vnTotalFaturado     NUMBER;
      vnTotalDevol        NUMBER;
    BEGIN
      -- Define Data Inicial de Final do mês atual
      vnDataInicialMesAtu := TO_DATE('01/'||TO_CHAR(SYSDATE,'MM/YYYY'),'DD/MM/YYYY');  
      vnDataFinalMesAtu   := ADD_MONTHS(vnDataInicialMesAtu,1)-1;
      -- Calcula o Total em Pedidos no Mês
      SELECT SUM(PCPEDI.QT)
        INTO vnTotalPedido
        FROM PCPEDI
       WHERE (PCPEDI.DATA  >= vnDataInicialMesAtu) 
         AND (PCPEDI.DATA   < vnDataFinalMesAtu+1) 
         AND (PCPEDI.CODCLI  = pi_nCodCli)
         AND (PCPEDI.POSICAO <> 'F')
         AND (PCPEDI.CODPROD = pi_nCodProd)
         AND (NOT ((PCPEDI.NUMPED  = NVL(pi_nNumPed,0)) AND (PCPEDI.NUMSEQ = NVL(pi_nNumSeq,0)))); -->> Ignora o Item passado no Parâmetro na Conta
      -- Calcula o total faturado no mês
      SELECT SUM(PCMOV.QT)
        INTO vnTotalFaturado
        FROM PCMOV
       WHERE (DTMOV  >= vnDataInicialMesAtu) 
         AND (DTMOV   < vnDataFinalMesAtu+1) 
         AND (CODPROD = pi_nCodProd)
         AND (CODCLI  = pi_nCodCli)
         AND (DTCANCEL IS NULL) 
         AND (SUBSTR(CODOPER,1,1) = 'S');
      -- Se deduz Devoluções
      IF (NVL(pi_vDeduzDevolucoes,'N') = 'S') THEN
        -- Calcula o total devolvido no mês
        SELECT SUM(PCMOV.QT)
          INTO vnTotalDevol
          FROM PCMOV
             , PCNFENT
         WHERE (PCNFENT.NUMTRANSENT     = PCMOV.NUMTRANSENT)
           AND (PCNFENT.CODFORNEC       = pi_nCodCli)
           AND (PCNFENT.DTENT          >= vnDataInicialMesAtu) 
           AND (PCNFENT.DTENT           < vnDataFinalMesAtu+1) 
           AND (PCMOV.CODPROD           = pi_nCodProd)
           AND PCNFENT.TIPODESCARGA     IN ('6', '7')
           AND NVL(PCNFENT.CODFISCAL,0) IN (131, 132, 231, 232, 199, 299)
           AND PCMOV.DTCANCEL            IS NULL
           AND PCMOV.CODOPER             = 'ED'
           AND NVL(PCNFENT.OBS, 'X')    <> 'NF CANCELADA';
        -- Abate do Total Faturado as Devoluções (Deixar Negativo para fazer a compensação na quantidade pedida)   
        vnTotalFaturado := NVL(vnTotalFaturado,0) - NVL(vnTotalDevol,0);    
      END IF;       
      -- Retorno da Função
      RETURN (NVL(vnTotalPedido,0) + NVL(vnTotalFaturado,0));
    END F_OBTEMVENDAMES;
      
  
    ------------------------------------------------------------------------------
    -- Função para obter o Total de Venda no Mês por Gramatura - HIS.01687.2017
    ------------------------------------------------------------------------------
    FUNCTION F_OBTEMVENDAMES_GRAMATURA(pi_vDeduzDevolucoes      IN VARCHAR2,
                                       pi_nCodTipoControleVenda IN NUMBER) RETURN NUMBER IS
      -- Data Inicial de Final do mês atual
      vnDataInicialMesAtu DATE;  
      vnDataFinalMesAtu   DATE;  
      -- Totais de Venda do Mês
      vnTotalPedido       NUMBER;
      vnTotalFaturado     NUMBER;
      vnTotalDevol        NUMBER;
    BEGIN
      -- Define Data Inicial de Final do mês atual
      vnDataInicialMesAtu := TO_DATE('01/'||TO_CHAR(SYSDATE,'MM/YYYY'),'DD/MM/YYYY');  
      vnDataFinalMesAtu   := ADD_MONTHS(vnDataInicialMesAtu,1)-1;
      -- Calcula o Total em Pedidos no Mês
      SELECT SUM(NVL(PCPEDI.QT,0) * NVL(PCPRODCONTROLEVENDA.QTLIMPESOMES,0))
        INTO vnTotalPedido
        FROM PCPEDI
           , PCPRODCONTROLEVENDA
       WHERE (PCPRODCONTROLEVENDA.CODPROD = PCPEDI.CODPROD)
         AND (PCPRODCONTROLEVENDA.CODTIPOCONTROLEVENDA = pi_nCodTipoControleVenda)
         AND (PCPEDI.DATA  >= vnDataInicialMesAtu) 
         AND (PCPEDI.DATA   < vnDataFinalMesAtu+1) 
         AND (PCPEDI.CODCLI  = pi_nCodCli)
         AND (PCPEDI.POSICAO <> 'F')
         AND (NOT ((PCPEDI.NUMPED  = NVL(pi_nNumPed,0)) AND (PCPEDI.NUMSEQ = NVL(pi_nNumSeq,0)))); -->> Ignora o Item passado no Parâmetro na Conta
      -- Calcula o total faturado no mês
      SELECT SUM(NVL(PCMOV.QT,0) * NVL(PCPRODCONTROLEVENDA.QTLIMPESOMES,0))
        INTO vnTotalFaturado
        FROM PCMOV
           , PCPRODCONTROLEVENDA
       WHERE (PCPRODCONTROLEVENDA.CODPROD = PCMOV.CODPROD)
         AND (PCPRODCONTROLEVENDA.CODTIPOCONTROLEVENDA = pi_nCodTipoControleVenda)
         AND (DTMOV  >= vnDataInicialMesAtu) 
         AND (DTMOV   < vnDataFinalMesAtu+1) 
         AND (CODCLI  = pi_nCodCli)
         AND (DTCANCEL IS NULL) 
         AND (SUBSTR(CODOPER,1,1) = 'S');
      -- Se deduz Devoluções
      IF (NVL(pi_vDeduzDevolucoes,'N') = 'S') THEN
        -- Calcula o total devolvido no mês
        SELECT SUM(NVL(PCMOV.QT,0) * NVL(PCPRODCONTROLEVENDA.QTLIMPESOMES,0))
          INTO vnTotalDevol
          FROM PCMOV
             , PCNFENT
             , PCPRODCONTROLEVENDA
         WHERE (PCPRODCONTROLEVENDA.CODPROD              = PCMOV.CODPROD)
           AND (PCPRODCONTROLEVENDA.CODTIPOCONTROLEVENDA = pi_nCodTipoControleVenda)
           AND (PCNFENT.NUMTRANSENT                      = PCMOV.NUMTRANSENT)
           AND (PCNFENT.CODFORNEC                        = pi_nCodCli)
           AND (PCNFENT.DTENT                           >= vnDataInicialMesAtu) 
           AND (PCNFENT.DTENT                            < vnDataFinalMesAtu+1) 
           AND PCNFENT.TIPODESCARGA                     IN ('6', '7')
           AND NVL(PCNFENT.CODFISCAL,0)                 IN (131, 132, 231, 232, 199, 299)
           AND PCMOV.DTCANCEL                           IS NULL
           AND PCMOV.CODOPER                             = 'ED'
           AND NVL(PCNFENT.OBS, 'X')                    <> 'NF CANCELADA';
        -- Abate do Total Faturado as Devoluções (Deixar Negativo para fazer a compensação na quantidade pedida)   
        vnTotalFaturado := NVL(vnTotalFaturado,0) - NVL(vnTotalDevol,0);    
      END IF;              
      -- Retorno da Função
      RETURN (NVL(vnTotalPedido,0) + NVL(vnTotalFaturado,0));
    END F_OBTEMVENDAMES_GRAMATURA;
    
    --------------------------------------
    -- PROCEDIMENTO PARA VALIDAR O CLIENTE
    --------------------------------------
    PROCEDURE P_VALIDACLIENTE(pi_nCODTIPOCONTROLEVENDA IN NUMBER,
                              pi_vCRITICANUMDOC        IN VARCHAR2,
                              pi_vCRITICADTVALIDADE    IN VARCHAR2,
                              pi_vDESCRICAO            IN VARCHAR2,
                              pio_bPodeComprar         IN OUT BOOLEAN,
                              pio_vMsgNaoPodeComprar   IN OUT VARCHAR2) IS 
    BEGIN                             
                              
      -- Se o Cliente possui Controle de Venda para o Tipo passado no parâmetro
      IF (vtDadosControleVenCli.EXISTS(pi_nCODTIPOCONTROLEVENDA)) THEN
        
        -- Se Critica Documento
        IF ((pi_vCRITICANUMDOC = 'S') AND
            (vtDadosControleVenCli(pi_nCODTIPOCONTROLEVENDA).vNUMDOC IS NULL)) THEN
          -- Cliente não pode comprar Produto    
          pio_bPodeComprar       := FALSE;
          pio_vMsgNaoPodeComprar := 'Número Requerido: ' || pi_vDESCRICAO;
        END IF;
  
        -- Se Critica Data de Validade
        IF (pi_vCRITICADTVALIDADE = 'S') THEN
          -- Se não preencheu a Validade
          IF    (vtDadosControleVenCli(pi_nCODTIPOCONTROLEVENDA).dDTVALIDADE IS NULL) THEN
            -- Cliente não pode comprar Produto    
            pio_bPodeComprar       := FALSE;
            pio_vMsgNaoPodeComprar := 'Dt. Validade Requerida: ' || pi_vDESCRICAO;
          -- Se Validade Expirada
          ELSIF (TRUNC(vtDadosControleVenCli(pi_nCODTIPOCONTROLEVENDA).dDTVALIDADE) < TRUNC(SYSDATE)) THEN
            -- Cliente não pode comprar Produto    
            pio_bPodeComprar       := FALSE;
            pio_vMsgNaoPodeComprar := 'Dt. Validade Expirada: ' || pi_vDESCRICAO;
          END IF;
        END IF;
          
      -- Se o Cliente NÃO possui Controle de Venda para o Tipo passado no parâmetro
      ELSE
  
        -- Cliente não pode comprar Produto    
        pio_bPodeComprar       := FALSE;
        pio_vMsgNaoPodeComprar := 'Sem Autorização: ' || pi_vDESCRICAO;
          
      END IF;
                                
    END P_VALIDACLIENTE;
  
    -------------------------------------------------------------
    -- FUNCAO PARA DEFINIR SE O CONTROLE DE VENDA EXIGE VALIDAÇÃO 
    -- COM BASE NO SEGMENTO DO CLIENTE
    -------------------------------------------------------------
    FUNCTION F_EXIGEVALIDACAOSEGMENTOCLI(pi_nCODTIPOCONTROLEVENDA     IN NUMBER,
                                         pi_vTIPOCLIMED               IN VARCHAR2,
                                         pi_vVALIDALVARAPORTIPOCTLVEN IN VARCHAR2) -- DDMEDICA-1586
    RETURN VARCHAR2 IS 
      -- Controle de Restrição
      vvPossuiRestricao VARCHAR2(1);
      vvValidarCliente  VARCHAR2(1);
    BEGIN         
    
      -- DDMEDICA-1586 - Processo antigo não tem Exceção por Segmento
      IF (NVL(pi_vVALIDALVARAPORTIPOCTLVEN,'N') = 'N') THEN
      
        vvValidarCliente := 'S';
      
      ELSE
                     
        -- Verifica se o Tipo de Controle de Venda possui Restrições por Segmento
        BEGIN
          SELECT 'S'
            INTO vvPossuiRestricao
            FROM PCTIPOCONTROLEVENDATIPOCLIMED
           WHERE (CODTIPOCONTROLEVENDA = pi_nCODTIPOCONTROLEVENDA)
             AND (ROWNUM               = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvPossuiRestricao := 'N';
        END;
        
        -- Se possui Restrições, verifica se o Segmento do Cliente está Restrito
        IF (NVL(vvPossuiRestricao,'N') = 'S') THEN
          -- Verifica se o Segmento do Cliente está nas Restrições obrigando o Cliente a ser Validado se encontrar nas Restrições
          BEGIN
            SELECT 'S'
              INTO vvValidarCliente
              FROM PCTIPOCONTROLEVENDATIPOCLIMED
             WHERE (CODTIPOCONTROLEVENDA = pi_nCODTIPOCONTROLEVENDA)
               AND (TIPOCLIMED           = pi_vTIPOCLIMED);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvValidarCliente := 'N';
          END;
        -- Se NÃO possui Restrições
        ELSE
          -- Vai validar o Cliente 
          vvValidarCliente := 'S';
        END IF;
        
      END IF; -- DDMEDICA-1586
      
      -- RETORNO Se validará ou não o cliente com base no segmento do cliente
      RETURN vvValidarCliente;    
                                                            
    END F_EXIGEVALIDACAOSEGMENTOCLI;
  
    -------------------------------------------------------------
    -- PROCEDIMENTO PARA ATUALIZAR A QUANTIDADE LIMITE DE COMPRA
    -------------------------------------------------------------
    PROCEDURE PATUALIZA_QTDE_LIMITE_COMPRA(pi_nQtdeVenda       IN NUMBER,
                                           pi_nQtdeExcedida    IN NUMBER,
                                           pio_nCalcQtdeLimite IN OUT NUMBER) IS                                        
      -- Variável Auxiliar para cálculo do Limite de Compra
      vnAuxQtLimite PCPEDI.QT%TYPE;
    BEGIN
      -- Limite que pode comprar (Quantidade no Pedido - Excedido)
      vnAuxQtLimite := NVL(pi_nQtdeVenda,0) - NVL(pi_nQtdeExcedida,0);
      IF (NVL(vnAuxQtLimite,0) < 0) THEN
        vnAuxQtLimite := 0;
      END IF;
      -- Se ainda não preencheu o retorno de quantidade limite, assume a quantidade calculada
      IF    (pio_nCalcQtdeLimite IS NULL) THEN
        pio_nCalcQtdeLimite := NVL(vnAuxQtLimite,0);
      -- Se já preencheu o retorno de quantidade limite, somente atualiza o retorno se a nova quantidade calculada for menor que a anterior
      ELSIF (NVL(vnAuxQtLimite,0) < NVL(pio_nCalcQtdeLimite,0)) THEN
        pio_nCalcQtdeLimite := NVL(vnAuxQtLimite,0);
      END IF;                                              
      -- Retorno
    END PATUALIZA_QTDE_LIMITE_COMPRA;
  
    --------------------------------------------------------------------------
    -- PROCEDIMENTO PARA ATUALIZAR A QUANTIDADE LIMITE DE COMPRA COM GRAMATURA
    --------------------------------------------------------------------------
    PROCEDURE PATU_QTDE_LIMITE_COMPRA_GRAM(pi_nPesoProduto          IN NUMBER,
                                           pi_nPesoVenda            IN NUMBER,
                                           pi_nPesoExcedido         IN NUMBER,
                                           pio_nCalcQtdeEquivalente IN OUT NUMBER) IS                                        
      -- Variável Auxiliar para cálculo do Limite de Compra
      vnAuxPesoLimite                NUMBER;
      vnAuxQtdeEquivalentePesoLimite NUMBER;
    BEGIN
      -- Limite que pode comprar (Peso Quantidade no Pedido - Peso Excedido)
      vnAuxPesoLimite := NVL(pi_nPesoVenda,0) - NVL(pi_nPesoExcedido,0);
      IF (NVL(vnAuxPesoLimite,0) < 0) THEN
        vnAuxPesoLimite := 0;
      END IF;
      
      -- Calcula a Qtde. Equivalente para o Peso Limite
      IF (NVL(pi_nPesoProduto,0) <> 0) THEN
        vnAuxQtdeEquivalentePesoLimite := TRUNC(NVL(vnAuxPesoLimite,0) / NVL(pi_nPesoProduto,0));
      ELSE
        vnAuxQtdeEquivalentePesoLimite := 0;
      END IF;
      
      
      -- Se ainda não preencheu o retorno de quantidade equivalente limite, assume a quantidade calculada
      IF    (pio_nCalcQtdeEquivalente IS NULL) THEN
        pio_nCalcQtdeEquivalente := NVL(vnAuxQtdeEquivalentePesoLimite,0);
      -- Se já preencheu o retorno de quantidade limite, somente atualiza o retorno se a nova quantidade calculada for menor que a anterior
      ELSIF (NVL(vnAuxQtdeEquivalentePesoLimite,0) < NVL(pio_nCalcQtdeEquivalente,0)) THEN
        pio_nCalcQtdeEquivalente := NVL(vnAuxQtdeEquivalentePesoLimite,0);
      END IF;                                              
      -- Retorno
    END PATU_QTDE_LIMITE_COMPRA_GRAM;
    
  /*******************************************************************************
                     INICIO DO PROCESSAMENTO PRINCIPAL
   *******************************************************************************/  
  BEGIN
  
    -- Inicializa Retornos
    po_vPodeComprarProduto   := 'S';
    po_vMotivoNaoPodeComprar := '';
    po_nQtdeLimite           := NULL; -->> Começar com NULL para a Lógica funcionar
    
    -- Pesquisa Parâmetros
    BEGIN
      SELECT VALOR
        INTO vVALIDALVARAPORTIPOCTLVEN
        FROM PCPARAMFILIAL 
       WHERE (NOME      = 'VALIDALVARAPORTIPOCTLVEN')
         AND (CODFILIAL = '99');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vVALIDALVARAPORTIPOCTLVEN := 'N';
    END;
    --
    BEGIN
      SELECT VALOR
        INTO vDIGITARPEDIDOCLIENTEALVARA
        FROM PCPARAMFILIAL 
       WHERE (NOME      = 'DIGITARPEDIDOCLIENTEALVARAVENCIDO')
         AND (CODFILIAL = '99');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vDIGITARPEDIDOCLIENTEALVARA := 'N';
    END;
    -- DDMEDICA-6213
    vVALIDALVARAFUNCLIBERADOS     := F_REGRA_MEDICAMENTOS('99','VALIDALVARAFUNCLIBERADOS');
    -- DDMEDICA-6491
    vIGNORARVALIDACAOALVARASUS    := F_REGRA_MEDICAMENTOS('99','IGNORARVALIDACAOALVARASUS');
    -- DDMEDICA-6491
    vIGNORARVALIDACAOALVARACRF    := F_REGRA_MEDICAMENTOS('99','IGNORARVALIDACAOALVARACRF');
    -- DDMEDICA-6491 - Parâmetro para Aceitar Pedido de Cliente com Alvará Vencido recebidos pela Integradora
    vACEITARPEDALVARAVENCINTEGRAD := F_REGRA_MEDICAMENTOS('99','ACEITARPEDALVARAVENCINTEGRADORA');

    -- Exceção para recebidos pela Integradora Aceitar Receber Pedidos com Alvará Vencido - DDMEDICA-6545
    IF (pi_nCodRotina = 2513) AND
       (vACEITARPEDALVARAVENCINTEGRAD = 'S') THEN
      vDIGITARPEDIDOCLIENTEALVARA := 'S';  
    END IF;

    -- Segmento do Cliente
    BEGIN
      SELECT TIPOCLIMED
        INTO vTIPOCLIMED
        FROM PCCLIENT
       WHERE (CODCLI = pi_nCodCli);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vTIPOCLIMED := NULL;
    END;     
      
    ------------------------------------------------------------------------------
    -- Pesquisa os Tipos de Controle de Venda do Cliente
    ----------------------------------------------------
    FOR vc_TipoControleVenCli IN (SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                       , VIEW_MED_ALVARA_CLIENTE.NUMALVARAANVISA    NUMDOC
                                       , VIEW_MED_ALVARA_CLIENTE.DTVENCALVARAANVISA DTVALIDADE
                                    FROM VIEW_MED_ALVARA_CLIENTE -- DDMEDICA-1586
                                   WHERE (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)) LOOP
                                                                        
      -- Preenche Array indexado pelos Tipos de Controle de Venda do Cliente  
      vtDadosControleVenCli(vc_TipoControleVenCli.CODTIPOCONTROLEVENDA).vNUMDOC     := vc_TipoControleVenCli.NUMDOC;
      vtDadosControleVenCli(vc_TipoControleVenCli.CODTIPOCONTROLEVENDA).dDTVALIDADE := vc_TipoControleVenCli.DTVALIDADE;
      
    END LOOP; -- Fim do Cursor dos Tipos de Controles de Venda associados ao Cliente    
  
   /******************************
    SE CHAMADO AO INICIAR O PEDIDO
   /******************************/
    IF    (pi_vTipoChamada IN ('P')) THEN
    
      ------------------------------------------------------------------------------
      -- Pesquisa os Tipos de Controles de Venda que não deixa
      -- iniciar o Pedido se o Cliente não tiver com a Licença
      -- Usam Validação 3
      --------------------------------------------------------
      FOR vc_ControleVen IN (SELECT PCTIPOCONTROLEVENDA.CODTIPOCONTROLEVENDA
                                  , PCTIPOCONTROLEVENDA.DESCRICAO
                                  , PCTIPOCONTROLEVENDA.CRITICANUMDOC
                                  , PCTIPOCONTROLEVENDA.CRITICADTVALIDADE
                                  , PCTIPOCONTROLEVENDA.TIPOVALIDACAO
                                  , PCTIPOCONTROLEVENDA.DEDUZDEVOLUCOES
                               FROM PCTIPOCONTROLEVENDA
                              WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') -- DDMEDICA-1586
                                AND (PCTIPOCONTROLEVENDA.TIPOVALIDACAO IN ('3'))
                              UNION -- DDMEDICA-1586
                             SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                  , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                  , 'S' CRITICANUMDOC
                                  , 'S' CRITICADTVALIDADE
                                  , '3' TIPOVALIDACAO
                                  , 'N' DEDUZDEVOLUCOES
                               FROM VIEW_MED_ALVARA_CLIENTE
                              WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N')   = 'N') -- DDMEDICA-1586
                                AND (NVL(vDIGITARPEDIDOCLIENTEALVARA,'N') = 'N') -- DDMEDICA-1586 (Somente critica Alvará ao abrir pedido mediante parâmetro Permite incluir pedido de venda para cliente que possui alvará vencido)
                                AND (NVL(VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA,0) NOT IN (3,4,5,6)) -- DDMEDICA-6213 - SUS/CRF não Impedem o Pedido de Iniciar
                                AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)) LOOP
                              
        -- SE CONTROLE DE VENDA EXIGIR VALIDAÇÃO PARA O SEGMENTO DO CLIENTE
        IF (F_EXIGEVALIDACAOSEGMENTOCLI(vc_ControleVen.CODTIPOCONTROLEVENDA,
                                        vTIPOCLIMED,
                                        vVALIDALVARAPORTIPOCTLVEN) = 'S') THEN -- DDMEDICA-1586
  
          -- Inicializa Variável para identificar se o Cliente pode Comprar o Produto
          vbCliPodeComprarProduto := TRUE;
        
          -- Validação do Cliente
          P_VALIDACLIENTE(vc_ControleVen.CODTIPOCONTROLEVENDA,
                          vc_ControleVen.CRITICANUMDOC,
                          vc_ControleVen.CRITICADTVALIDADE,
                          vc_ControleVen.DESCRICAO,
                          vbCliPodeComprarProduto,
                          vvMotivoNaoPodeComprarProd);
  
          -- Se o Cliente não pode Comprar
          IF (NOT vbCliPodeComprarProduto) THEN
                            
            -- Altera Retorno confirmando que o cliente não pode comprar
            po_vPodeComprarProduto := 'N';      
            -- Motivo
            po_vMotivoNaoPodeComprar := vvMotivoNaoPodeComprarProd; 
           
          END IF; -- Fim Condição Se o Cliente não pode Comprar Produto
          
        END IF; -- FIM CONDIÇÃO SE CONTROLE DE VENDA EXIGIR VALIDAÇÃO PARA O SEGMENTO DO CLIENTE
                                
      END LOOP; -- Fim do Cursor dos Tipos de Controles de Venda
  
   /*******************************************************
    SE CHAMADO DA INCLUSAO DO ITEM OU DA GRAVAÇÃO DO PEDIDO
   /*******************************************************/
    ELSIF (pi_vTipoChamada IN ('I','G')) THEN
    
      ------------------------------------------------------------------------------
      -- Pesquisa os Tipos de Controles de Venda associados ao Produto
      -- que usam Validação 1, 2 e 3
      ----------------------------------------------------------------
      FOR vc_ControleVenProd IN (SELECT PCPRODCONTROLEVENDA.CODTIPOCONTROLEVENDA
                                      , PCPRODCONTROLEVENDA.QTLIMISENCAOPFMES
                                      , PCPRODCONTROLEVENDA.QTLIMISENCAOPJMES
                                      , PCPRODCONTROLEVENDA.QTLIMISENCAODISTRIBMES
                                      , PCTIPOCONTROLEVENDA.DESCRICAO
                                      , PCTIPOCONTROLEVENDA.CRITICANUMDOC
                                      , PCTIPOCONTROLEVENDA.CRITICADTVALIDADE
                                      , PCTIPOCONTROLEVENDA.TIPOVALIDACAO
                                      , PCTIPOCONTROLEVENDA.DEDUZDEVOLUCOES
                                      , PCTIPOCONTROLEVENDA.UTILIZAPESOLIMITEMES          -- HIS.01687.2017
                                      , PCTIPOCONTROLEVENDA.PESOLIMITEMES                 -- HIS.01687.2017
                                      , PCPRODCONTROLEVENDA.QTLIMPESOMES                  -- HIS.01687.2017
                                   FROM PCPRODCONTROLEVENDA
                                      , PCTIPOCONTROLEVENDA
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') -- DDMEDICA-1586
                                    AND (PCPRODCONTROLEVENDA.CODPROD              = pi_nCodProd)
                                    AND (PCTIPOCONTROLEVENDA.CODTIPOCONTROLEVENDA = PCPRODCONTROLEVENDA.CODTIPOCONTROLEVENDA)
                                    AND (PCTIPOCONTROLEVENDA.TIPOVALIDACAO        IN ('1','2','3'))
                                  UNION -- DDMEDICA-1586
                                 SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                      , 0 QTLIMISENCAOPFMES
                                      , 0 QTLIMISENCAOPJMES
                                      , 0 QTLIMISENCAODISTRIBMES
                                      , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                      , 'S' CRITICANUMDOC
                                      , 'S' CRITICADTVALIDADE
                                      , '1' TIPOVALIDACAO -- Recusar o Item
                                      , 'N' DEDUZDEVOLUCOES
                                      , 'N' UTILIZAPESOLIMITEMES
                                      , 0 PESOLIMITEMES
                                      , 0 QTLIMPESOMES
                                   FROM VIEW_MED_ALVARA_CLIENTE
                                      , PCPRODUT
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'N')
                                    AND (PCPRODUT.CODPROD = pi_nCodProd)
                                    AND ((PCPRODUT.PSICOTROPICO = 'S') AND (VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA = 4))
                                    AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)
                                 UNION
                                 SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                      , 0 QTLIMISENCAOPFMES
                                      , 0 QTLIMISENCAOPJMES
                                      , 0 QTLIMISENCAODISTRIBMES
                                      , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                      , 'S' CRITICANUMDOC
                                      , 'S' CRITICADTVALIDADE
                                      , '1' TIPOVALIDACAO -- Recusar o Item
                                      , 'N' DEDUZDEVOLUCOES
                                      , 'N' UTILIZAPESOLIMITEMES
                                      , 0 PESOLIMITEMES
                                      , 0 QTLIMPESOMES
                                   FROM VIEW_MED_ALVARA_CLIENTE
                                      , PCPRODUT
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'N')
                                    AND (PCPRODUT.CODPROD = pi_nCodProd)
                                    AND ((PCPRODUT.RETINOICO = 'S') AND (VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA = 5))
                                    AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)   
                                 UNION
                                 SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                      , 0 QTLIMISENCAOPFMES
                                      , 0 QTLIMISENCAOPJMES
                                      , 0 QTLIMISENCAODISTRIBMES
                                      , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                      , 'S' CRITICANUMDOC
                                      , 'S' CRITICADTVALIDADE
                                      , '1' TIPOVALIDACAO -- Recusar o Item
                                      , 'N' DEDUZDEVOLUCOES
                                      , 'N' UTILIZAPESOLIMITEMES
                                      , 0 PESOLIMITEMES
                                      , 0 QTLIMPESOMES
                                   FROM VIEW_MED_ALVARA_CLIENTE
                                      , PCPRODUT
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'N')
                                    AND (PCPRODUT.CODPROD = pi_nCodProd)
                                    AND ((NVL(vVALIDALVARAFUNCLIBERADOS,'N') = 'S') AND (VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA = 2)) -- DDMEDICA-6213 - Validar Alvará Funcionamento Produtos Liberados
                                    AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)   
                                 UNION
                                 SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                      , 0 QTLIMISENCAOPFMES
                                      , 0 QTLIMISENCAOPJMES
                                      , 0 QTLIMISENCAODISTRIBMES
                                      , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                      , 'S' CRITICANUMDOC
                                      , 'S' CRITICADTVALIDADE
                                      , '1' TIPOVALIDACAO -- Recusar o Item
                                      , 'N' DEDUZDEVOLUCOES
                                      , 'N' UTILIZAPESOLIMITEMES
                                      , 0 PESOLIMITEMES
                                      , 0 QTLIMPESOMES
                                   FROM VIEW_MED_ALVARA_CLIENTE
                                      , PCPRODUT
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'N')
                                    AND (PCPRODUT.CODPROD = pi_nCodProd)
                                    AND ((PCPRODUT.TIPOMERC IN ('M','MA')) AND (VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA NOT IN (3,4,5,6)))
                                    AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)
                                 UNION
                                 SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                      , 0 QTLIMISENCAOPFMES
                                      , 0 QTLIMISENCAOPJMES
                                      , 0 QTLIMISENCAODISTRIBMES
                                      , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                      , 'S' CRITICANUMDOC
                                      , 'S' CRITICADTVALIDADE
                                      , '1' TIPOVALIDACAO -- Recusar o Item
                                      , 'N' DEDUZDEVOLUCOES
                                      , 'N' UTILIZAPESOLIMITEMES
                                      , 0 PESOLIMITEMES
                                      , 0 QTLIMPESOMES
                                   FROM VIEW_MED_ALVARA_CLIENTE
                                      , PCPRODUT
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'N')
                                    AND (PCPRODUT.CODPROD = pi_nCodProd)
                                    AND (NVL(vIGNORARVALIDACAOALVARASUS,'N') <> 'S')
                                    AND ((PCPRODUT.TIPOMERC IN ('M','MA')) AND (VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA IN (3)))
                                    AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)
                                 UNION
                                 SELECT VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA
                                      , 0 QTLIMISENCAOPFMES
                                      , 0 QTLIMISENCAOPJMES
                                      , 0 QTLIMISENCAODISTRIBMES
                                      , VIEW_MED_ALVARA_CLIENTE.DESCRICAO
                                      , 'S' CRITICANUMDOC
                                      , 'S' CRITICADTVALIDADE
                                      , '1' TIPOVALIDACAO -- Recusar o Item
                                      , 'N' DEDUZDEVOLUCOES
                                      , 'N' UTILIZAPESOLIMITEMES
                                      , 0 PESOLIMITEMES
                                      , 0 QTLIMPESOMES
                                   FROM VIEW_MED_ALVARA_CLIENTE
                                      , PCPRODUT
                                  WHERE (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'N')
                                    AND (PCPRODUT.CODPROD = pi_nCodProd)
                                    AND (NVL(vIGNORARVALIDACAOALVARACRF,'N') <> 'S')
                                    AND ((PCPRODUT.TIPOMERC IN ('M','MA')) AND (VIEW_MED_ALVARA_CLIENTE.CODTIPOCONTROLEVENDA IN (6)))
                                    AND (VIEW_MED_ALVARA_CLIENTE.CODCLI = pi_nCodCli)
                                    ) LOOP
  
        -- SE CONTROLE DE VENDA EXIGIR VALIDAÇÃO PARA O SEGMENTO DO CLIENTE
        IF (F_EXIGEVALIDACAOSEGMENTOCLI(vc_ControleVenProd.CODTIPOCONTROLEVENDA,
                                        vTIPOCLIMED,
                                        vVALIDALVARAPORTIPOCTLVEN) = 'S') THEN -- DDMEDICA-1586
  
          -- Inicializa Variável para identificar se o Cliente pode Comprar o Produto
          vbCliPodeComprarProduto := TRUE;
          
          -- Validação do Cliente
          P_VALIDACLIENTE(vc_ControleVenProd.CODTIPOCONTROLEVENDA,
                          vc_ControleVenProd.CRITICANUMDOC,
                          vc_ControleVenProd.CRITICADTVALIDADE,
                          vc_ControleVenProd.DESCRICAO,
                          vbCliPodeComprarProduto,
                          vvMotivoNaoPodeComprarProd);
                  
          -- Se não restringiu nas primeiras críticas
          IF (vbCliPodeComprarProduto) THEN
                
            -- SE UTILIZA CONTROLE DE GRAMATURA HIS.01687.2017 --------------------------------------
            IF (NVL(vc_ControleVenProd.UTILIZAPESOLIMITEMES,'N') = 'S') THEN
            
              -- Calcula o Peso da Venda do Item do Pedido
              vnPesoVendaItemPedido := (NVL(pi_nQtdeVenda,0) * NVL(vc_ControleVenProd.QTLIMPESOMES,0));
            
              -- Calcula o Total de Venda do Mês em Gramatura (Soma do que já foi vendido + peso da venda do item do Pedido)
              vnTotalVendaMes := NVL(F_OBTEMVENDAMES_GRAMATURA(vc_ControleVenProd.DEDUZDEVOLUCOES,
                                                               vc_ControleVenProd.CODTIPOCONTROLEVENDA),0) + NVL(vnPesoVendaItemPedido,0);
  
              -- Se excedeu o Peso Limite de venda no mês
              IF (NVL(vnTotalVendaMes,0) > NVL(vc_ControleVenProd.PESOLIMITEMES,0)) THEN
                -- Calcula o Peso Total Excedido
                vnPesoTotalExcedido           :=  (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.PESOLIMITEMES,0));
                -- Calcula a Qtde. Equivalente para o Peso Excedido
                IF (NVL(vc_ControleVenProd.QTLIMPESOMES,0) <> 0) THEN
                  vnQtEquivalentePesoExcedido := TRUNC(NVL(vnPesoTotalExcedido,0) / NVL(vc_ControleVenProd.QTLIMPESOMES,0));
                ELSE
                  vnQtEquivalentePesoExcedido := 0;
                END IF;
                -- Cliente não pode comprar Produto    
                vbCliPodeComprarProduto    := FALSE;
                vvMotivoNaoPodeComprarProd := 'Peso total excedido(s) ' || NVL(vnPesoTotalExcedido,0) || ' equivalente a ' || NVL(vnQtEquivalentePesoExcedido,0) || ' unidades ' ||
                                              ' na venda de produtos com Controle de ' || vc_ControleVenProd.DESCRICAO;
                -- Limite que pode comprar (Peso Limite (Peso no Pedido - Peso Excedido) já convertido em Qtde. Limite dentro do procedimento)
                PATU_QTDE_LIMITE_COMPRA_GRAM(vc_ControleVenProd.QTLIMPESOMES,
                                             NVL(vnPesoVendaItemPedido,0),
                                             NVL(vnPesoTotalExcedido,0),
                                             po_nQtdeLimite);
              END IF;
                                                     
            -- NÃO SE UTILIZA CONTROLE DE GRAMATURA (REGRA PADRÃO) ----------------------------------
            ELSE
                
              -- Se DISTRIBUIDOR ou DISTRIBUIDOR MEDICAMENTO
              IF    (NVL(vTIPOCLIMED,' ') IN ('T','U')) THEN
                -- Se cadastrou isenção para Distribuidor
                IF (NVL(vc_ControleVenProd.QTLIMISENCAODISTRIBMES,0) > 0) THEN
                  vnTotalVendaMes := NVL(F_OBTEMVENDAMES(vc_ControleVenProd.DEDUZDEVOLUCOES),0) + NVL(pi_nQtdeVenda,0);
                  -- Se excedeu o limite de venda no mês para pessoa fisica
                  IF (NVL(vnTotalVendaMes,0) > NVL(vc_ControleVenProd.QTLIMISENCAODISTRIBMES,0)) THEN
                    -- Cliente não pode comprar Produto    
                    vbCliPodeComprarProduto    := FALSE;
                    vvMotivoNaoPodeComprarProd := 'Excedida(s) ' || (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.QTLIMISENCAODISTRIBMES,0)) ||
                                                  ' unidade(s) na Isenção Distribuidores: ' || vc_ControleVenProd.DESCRICAO;
                    -- Limite que pode comprar (Quantidade no Pedido - Excedido)
                    PATUALIZA_QTDE_LIMITE_COMPRA(pi_nQtdeVenda,
                                                 (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.QTLIMISENCAODISTRIBMES,0)),
                                                 po_nQtdeLimite);
                  END IF;
                END IF;
              -- Se Pessoa Fisica
              ELSIF (NVL(pi_vTipoFJ,' ') = 'F') THEN
                -- Se cadastrou isenção para pessoa fisica
                IF (NVL(vc_ControleVenProd.QTLIMISENCAOPFMES,0) > 0) THEN
                  vnTotalVendaMes := NVL(F_OBTEMVENDAMES(vc_ControleVenProd.DEDUZDEVOLUCOES),0) + NVL(pi_nQtdeVenda,0);
                  -- Se excedeu o limite de venda no mês para pessoa fisica
                  IF (NVL(vnTotalVendaMes,0) > NVL(vc_ControleVenProd.QTLIMISENCAOPFMES,0)) THEN
                    -- Cliente não pode comprar Produto    
                    vbCliPodeComprarProduto    := FALSE;
                    vvMotivoNaoPodeComprarProd := 'Excedida(s) ' || (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.QTLIMISENCAOPFMES,0)) ||
                                                  ' unidade(s) na Isenção PF: ' || vc_ControleVenProd.DESCRICAO;
                    -- Limite que pode comprar (Quantidade no Pedido - Excedido)
                    PATUALIZA_QTDE_LIMITE_COMPRA(pi_nQtdeVenda,
                                                 (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.QTLIMISENCAOPFMES,0)),
                                                 po_nQtdeLimite);
                  END IF;
                END IF;
              -- Se Pessoa Jurídica
              ELSIF (NVL(pi_vTipoFJ,' ') = 'J') THEN
                -- Se cadastrou isenção para pessoa juridica
                IF (NVL(vc_ControleVenProd.QTLIMISENCAOPJMES,0) > 0) THEN
                  vnTotalVendaMes := NVL(F_OBTEMVENDAMES(vc_ControleVenProd.DEDUZDEVOLUCOES),0) + NVL(pi_nQtdeVenda,0);
                  -- Se excedeu o limite de venda no mês para pessoa juridica
                  IF (NVL(vnTotalVendaMes,0) > NVL(vc_ControleVenProd.QTLIMISENCAOPJMES,0)) THEN
                    -- Cliente não pode comprar Produto    
                    vbCliPodeComprarProduto    := FALSE;
                    vvMotivoNaoPodeComprarProd := 'Excedida(s) ' || (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.QTLIMISENCAOPJMES,0)) ||
                                                  ' unidade(s) na Isenção PJ: ' || vc_ControleVenProd.DESCRICAO;
                    -- Limite que pode comprar (Quantidade no Pedido - Excedido)
                    PATUALIZA_QTDE_LIMITE_COMPRA(pi_nQtdeVenda,
                                                 (NVL(vnTotalVendaMes,0) - NVL(vc_ControleVenProd.QTLIMISENCAOPJMES,0)),
                                                 po_nQtdeLimite);
                  END IF;
                END IF;
              -- Se não tem indicação de Pessoa Fisica e Juridica
              ELSE
                IF ((NVL(vc_ControleVenProd.QTLIMISENCAOPFMES,0) > 0) OR
                    (NVL(vc_ControleVenProd.QTLIMISENCAOPJMES,0) > 0)) THEN 
                  -- Cliente não pode comprar Produto    
                  vbCliPodeComprarProduto    := FALSE;
                  vvMotivoNaoPodeComprarProd := vc_ControleVenProd.DESCRICAO || ' exige campo "Tipo Pessoa" preenchido no cadastro do cliente';
                END IF;
              END IF;
                
            END IF; -- FIM CONDIÇÃO: SE USA CONTROLE DE GRAMATURA - HIS.01687.2017
                
          END IF; -- Fim Condição Se não restringiu nas primeiras críticas
                  
          -- Se o Cliente não pode Comprar Produto, verifica o Tipo de Validação x Origem da Chamada
          IF (NOT vbCliPodeComprarProduto) THEN
          
            -- Se Chamado da Inclusão do Item, somente confirma que não pode comprar se o Tipo de Validação for "1 - Recusar Item" ou '3 - Não pode Iniciar o Pedido"
            -- Se Chamado da Gravação do Pedido, confirma que não pode comprar independente do Tipo de Validação
            -- Se Chamado do Inicio da Digitação do Pedido, confirma que não pode comprar se o Tipo de Validação for '3 - Não pode Iniciar o Pedido"
            IF ((pi_vTipoChamada = 'I') AND (vc_ControleVenProd.TIPOVALIDACAO IN ('1','3'))) OR
               ((pi_vTipoChamada = 'G')) OR
               ((pi_vTipoChamada = 'P') AND (vc_ControleVenProd.TIPOVALIDACAO = '3')) THEN
                        
              -- Altera Retorno confirmando que o cliente não pode comprar o Produto
              po_vPodeComprarProduto := 'N';      
              -- Motivo
              IF (po_vMotivoNaoPodeComprar IS NULL) THEN
                po_vMotivoNaoPodeComprar := vvMotivoNaoPodeComprarProd; 
              ELSE
                po_vMotivoNaoPodeComprar := po_vMotivoNaoPodeComprar || '; ' || vvMotivoNaoPodeComprarProd;
              END IF;
            END IF;
            
          END IF; -- Fim Condição Se o Cliente não pode Comprar Produto
  
        END IF; -- FIM CONDIÇÃO SE CONTROLE DE VENDA EXIGIR VALIDAÇÃO PARA O SEGMENTO DO CLIENTE
        
      END LOOP; -- Fim do Cursor dos Tipos de Controles de Venda associados ao Produto
  
    END IF; -- FIM CONDIÇÃO TIPO CHAMADA
    
  EXCEPTION
    WHEN OTHERS THEN  
      po_vPodeComprarProduto   := 'N';
      po_vMotivoNaoPodeComprar := 'Erro ao validar o controle de venda: ' || SQLERRM;
  END P_VALIDA_CONTROLE_VENDA;
                   
 /*******************************************************************************
  Nome         : F_RESTRICAO_INADIMPLENCIA
  Descricão    : Função para Validar a Inadimplência de Clientes
  ********************************************************************************/    
  FUNCTION F_RESTRICAO_INADIMPLENCIA(pi_nCodCli    IN NUMBER,
                                     po_vMensagem OUT VARCHAR2) RETURN BOOLEAN IS
                                   
    vbRetInadimplencia         BOOLEAN;
    nNUMDIASMAXVENDACLIINADIMP NUMBER;
    vnQtdeTitulos              NUMBER;
    
  BEGIN
    
    -- Inicializa sem Inadimplência
    vbRetInadimplencia := FALSE;
    po_vMensagem       := NULL;
    
    -- Pesquisa Parâmetro 
    POBTEM_PARAMFILIAL_NUMBER('99',
                              'CON_NUMDIASMAXVENDACLIINADIMPLENTE',
                               nNUMDIASMAXVENDACLIINADIMP);
                                  
    -- Verifica Inadimplência 
    IF (NVL(nNUMDIASMAXVENDACLIINADIMP,0) > 0) THEN
    
      SELECT COUNT(*) CONTADOR
       INTO vnQtdeTitulos
       FROM PCPREST
      WHERE (CODCLI = pi_nCodCli)
        AND (TRUNC(SYSDATE) > DTVENC)
        AND (TRUNC(SYSDATE) - DTVENC > NVL(nNUMDIASMAXVENDACLIINADIMP,0));
      
      -- Atualiza Retorno
      IF (NVL(vnQtdeTitulos,0) > 0) THEN
        vbRetInadimplencia := TRUE;
        IF (vnQtdeTitulos = 1) THEN
          po_vMensagem := 'O cliente possui 1 duplicata vencida a mais de ' || nNUMDIASMAXVENDACLIINADIMP || ' dias conforme parâmetro 1184';
        ELSE
          po_vMensagem := 'O cliente possui ' || vnQtdeTitulos || ' duplicatas vencidas a mais de ' || nNUMDIASMAXVENDACLIINADIMP || ' dias conforme parâmetro 1184';
        END IF;
      END IF;
      
    END IF;
    
    -- Retorno
    RETURN vbRetInadimplencia;
    
  END F_RESTRICAO_INADIMPLENCIA;                                                                             

 /*******************************************************************************
  Nome         : F_VALIDAR_MULTIPLO
  Descricão    : Funçao para Validar o Múltiplo de Venda
  ********************************************************************************/   
  FUNCTION F_VALIDAR_MULTIPLO(pi_nCodCli             IN NUMBER,
                              pi_nCondVenda          IN NUMBER,
                              pi_nCodProd            IN NUMBER,
                              pi_nQt                 IN NUMBER,
                              pi_vCodFilial          IN VARCHAR2, -- DDVENDAS-41227
                              po_vDescricaoRejeicao OUT VARCHAR2,
                              po_nMultiplo          OUT NUMBER)   -- DDVENDAS-41227
  RETURN BOOLEAN IS
    vbRetValidarMultiplo    BOOLEAN;
    vVALIDARMULTIPLOVENDA   PCCLIENT.VALIDARMULTIPLOVENDA%TYPE;
    vCHECARMULTIPLOVENDABNF PCPRODUT.CHECARMULTIPLOVENDABNF%TYPE;
    nMULTIPLO               PCPRODUT.MULTIPLO%TYPE;
    vnMultiploValidacao     PCPRODUT.MULTIPLO%TYPE;
    vnQtdeValidacao         NUMBER;
  BEGIN
  
    -- Inicializa Retornos
    vbRetValidarMultiplo  := FALSE;
    po_vDescricaoRejeicao := NULL;
    
    -- Pesquisa Dados do Cliente
    BEGIN
      SELECT VALIDARMULTIPLOVENDA
        INTO vVALIDARMULTIPLOVENDA
        FROM PCCLIENT
       WHERE (CODCLI = pi_nCodCli);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vVALIDARMULTIPLOVENDA := 'N';
    END;
    
    -- Pesquisa Dados do Produto (DDVENDAS-41227 - PCPRODFILIAL)
    BEGIN
      SELECT NVL((SELECT PCPRODFILIAL.MULTIPLO
                    FROM PCPRODFILIAL
                  WHERE PCPRODFILIAL.CODPROD = PCPRODUT.CODPROD
                    AND PCPRODFILIAL.CODFILIAL = '1'), PCPRODUT.MULTIPLO) MULTIPLO
           , NVL((SELECT PCPRODFILIAL.CHECARMULTIPLOVENDABNF
                    FROM PCPRODFILIAL
                  WHERE PCPRODFILIAL.CODPROD = PCPRODUT.CODPROD
                    AND PCPRODFILIAL.CODFILIAL = '1'), PCPRODUT.CHECARMULTIPLOVENDABNF) MULTIPLO         
        INTO nMULTIPLO
           , vCHECARMULTIPLOVENDABNF
        FROM PCPRODUT
      WHERE (PCPRODUT.CODPROD = pi_nCodProd);                      
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        nMULTIPLO               := 1;
        vCHECARMULTIPLOVENDABNF := 'N';
    END;
    
    -- Quantidade para Validação
    vnQtdeValidacao := pi_nQt;
        
    -- Validação
    if (vVALIDARMULTIPLOVENDA= 'S')
         and (((pi_nCondVenda <> 5 ))
           or ((pi_nCondVenda = 5 )
    and (vCHECARMULTIPLOVENDABNF = 'S'))) then

       if nvl(nMULTIPLO,0) <> 0 then

         vnMultiploValidacao := nMULTIPLO;

       end if;


       if vnMultiploValidacao <> 0
       then

         if (vnQtdeValidacao / vnMultiploValidacao) <>
            trunc(vnQtdeValidacao / vnMultiploValidacao)
         then

             vnQtdeValidacao := trunc(vnQtdeValidacao/vnMultiploValidacao) * vnMultiploValidacao;

             if vnQtdeValidacao > 0 then

               po_vDescricaoRejeicao := 'Produto so pode ser vendido múltiplo de : ' || vnMultiploValidacao;

               vbRetValidarMultiplo := TRUE;

             else

               po_vDescricaoRejeicao := 'Produto so pode ser vendido múltiplo de : ' || vnMultiploValidacao;

               vbRetValidarMultiplo := TRUE;

             end if;

         end if;
         
       end if;

    end if;

    -- Retorna também o múltiplo -- DDVENDAS-41227
    po_nMultiplo := nMULTIPLO;
    
    -- Retorno
    RETURN vbRetValidarMultiplo;
  
  END F_VALIDAR_MULTIPLO;

 /*******************************************************************************
  Nome         : F_OBTER_ESTOQUE_MULTIPLO
  Descricão    : Funçao para Obter o Estoque Múltiplo - DDVENDAS-41227
  ********************************************************************************/   
  FUNCTION F_OBTER_ESTOQUE_MULTIPLO(pi_nCodCli            IN NUMBER,
                                    pi_nCondVenda         IN NUMBER,
                                    pi_nCodProd           IN NUMBER,
                                    pi_nQt                IN NUMBER,
                                    pi_vCodFilial         IN VARCHAR2,
                                    pi_nEstoqueDisponivel IN NUMBER)
  RETURN NUMBER IS
    vnRetEstoqueMultiplo NUMBER;
    vvDescricaoRejeicao  VARCHAR2(2000);
    vnMultiplo           NUMBER;
  BEGIN
  
    -- Inicializa Retorno
    vnRetEstoqueMultiplo := 0;

    -- Se Valida o Estoque Múltiplo
    IF F_VALIDAR_MULTIPLO(pi_nCodCli,
                          pi_nCondVenda,
                          pi_nCodProd,
                          pi_nQt,
                          pi_vCodFilial,
                          vvDescricaoRejeicao,
                          vnMultiplo)  THEN

      vnRetEstoqueMultiplo := TRUNC(NVL(pi_nEstoqueDisponivel,0) / NVL(vnMultiplo,0)) * NVL(vnMultiplo,0);                          

    END IF;
    
    -- Retorno
    RETURN vnRetEstoqueMultiplo;
  
  END F_OBTER_ESTOQUE_MULTIPLO;  
  
 /*******************************************************************************
  Nome         : F_VALIDAR_MULTIPLO
  Descricão    : Funçao para Validar Restrição de Venda
  ********************************************************************************/   
  FUNCTION F_VALIDAR_RESTRICAO_VENDA(p_codprod              IN NUMBER,
                                     p_numregiao            IN NUMBER,
                                     p_codcli               IN NUMBER,
                                     p_codusur              IN NUMBER,
                                     p_codfilial            in varchar2 default '0',
                                     p_condvenda            in number  default 0,
                                     p_fretedespacho        in varchar2 default ' ',
                                     p_origemped            in varchar2 default ' ',
                                     p_codplpag             in number default 0,
                                     p_codcob               in varchar2 default ' ',
                                     p_vlatend              in number default 0,
                                     po_vDescricaoRejeicao OUT VARCHAR2) 
  RETURN BOOLEAN IS
    vbRetRestricaoVenda BOOLEAN;
    vicont              NUMBER;
    vncodrestricao      pcrestricaovenda.codrestricao%TYPE;
    vstipofj            pcclient.tipofj%type;
    vncodepto           pcprodut.codepto%type;
    vncodsec            pcprodut.codsec%type;
    p_codfornec         pcprodut.codfornec%type;
    p_classeproduto     pcprodut.classe%type;
    p_codmarca          pcprodut.codmarca%type;
    p_codauxiliar       pcprodut.codauxiliar%type;
    p_codpraca          pcclient.codpraca%type;
    p_codativ           pcclient.codatv1%type;
    p_codsupervisor     pcusuari.codsupervisor%type;
  BEGIN
  
    -- Inicializa Retornos
    vbRetRestricaoVenda   := FALSE;
    po_vDescricaoRejeicao := NULL;

    begin
      select tipofj 
           , codpraca
           , codatv1
        into vstipofj
           , p_codpraca 
           , p_codativ
        from pcclient 
       where codcli = p_codcli;
    exception
      when no_data_found then
        null;
    end;
    
    begin
      select codsec, codepto, 
             codfornec, 
             classe, 
             codmarca, 
             codauxiliar
        into vncodsec, vncodepto, 
             p_codfornec, 
             p_classeproduto, 
             p_codmarca, 
             p_codauxiliar
        from pcprodut
       where codprod = p_codprod;
    exception
      when no_data_found then
        null;
    end;
    
    begin
      select codsupervisor
        into p_codsupervisor
        from pcusuari
       where codusur = p_codusur;
    exception
      when no_data_found then
        null;
    end;

    SELECT COUNT(*)
      INTO vicont
      FROM pcrestricaovenda
     WHERE ((codcli = p_codcli) OR (codcli IS NULL))
       AND ((codprod = p_codprod) OR (codprod IS NULL))
       AND ((numregiao = p_numregiao) OR (numregiao IS NULL))
       AND ((codfornec = p_codfornec) OR (codfornec IS NULL))
       AND ((codpraca = p_codpraca) OR (codpraca IS NULL))
       AND ((codusur = p_codusur) OR (codusur IS NULL))
       AND ((codativ = p_codativ) OR (codativ IS NULL))
       AND ((classeproduto = p_classeproduto) OR (classeproduto IS NULL))
       AND ((codepto = vncodepto) OR (codepto IS NULL))
       AND ((codsec = vncodsec) OR (codsec IS NULL))
       AND ((codsupervisor = p_codsupervisor) OR (codsupervisor IS NULL))
       AND ((tipofj = vstipofj) OR (tipofj IS NULL))
       AND ((codfilial = p_codfilial ) OR (codfilial IS NULL))
       and ((condvenda = p_condvenda ) OR (condvenda is null))
       and ((fretedespacho = p_fretedespacho) OR (fretedespacho is null) OR (fretedespacho = 'T'))
       and ((origemped   = p_origemped ) OR (origemped is null ) OR (origemped = 'O'))
       and ((codauxiliar = p_codauxiliar) OR (codauxiliar is null))
       and ((codcob = p_codcob) OR (codcob is null))
       and ((codplpag = p_codplpag ) OR (codplpag is null))
       AND ((codmarca = p_codmarca) OR (codmarca IS NULL))
       AND (NVL(valorminimovenda,0) = 0); -->> Ignorar esta restrição
       
    IF vicont > 0 THEN
      SELECT pcrestricaovenda.codrestricao
        INTO vncodrestricao
        FROM pcrestricaovenda
       WHERE ((codcli = p_codcli) OR (codcli IS NULL))
         AND ((codprod = p_codprod) OR (codprod IS NULL))
         AND ((numregiao = p_numregiao) OR (numregiao IS NULL))
         AND ((codfornec = p_codfornec) OR (codfornec IS NULL))
         AND ((codpraca = p_codpraca) OR (codpraca IS NULL))
         AND ((codusur = p_codusur) OR (codusur IS NULL))
         AND ((codativ = p_codativ) OR (codativ IS NULL))
         AND ((classeproduto = p_classeproduto) OR (classeproduto IS NULL))
         AND ((codepto = vncodepto) OR (codepto IS NULL))
         AND ((codsec = vncodsec) OR (codsec IS NULL))
         AND ((codsupervisor = p_codsupervisor) OR (codsupervisor IS NULL))
         AND ((tipofj = vstipofj) OR (tipofj IS NULL))
         AND ((codfilial = p_codfilial ) OR (codfilial IS NULL))
         and ((condvenda = p_condvenda ) OR (condvenda is null))
         and ((fretedespacho = p_fretedespacho) OR (fretedespacho is null) OR (fretedespacho = 'T'))
         and ((origemped   = p_origemped ) OR (origemped is null ) OR (origemped = 'O'))
         and ((codauxiliar = p_codauxiliar) OR (codauxiliar is null))
         and ((codcob = p_codcob) OR (codcob is null))
         and ((codplpag = p_codplpag ) OR (codplpag is null))
         AND ((codmarca = p_codmarca) OR (codmarca IS NULL))
         AND (NVL(valorminimovenda,0) = 0) -->> Ignorar esta restrição
         AND rownum = 1;
      vbRetRestricaoVenda   := TRUE;
      po_vDescricaoRejeicao := 'Código da Restrição para esta venda : ' || vncodrestricao;
    END IF;
    
    -- Retorno
    RETURN vbRetRestricaoVenda;
    
  EXCEPTION
    WHEN OTHERS THEN
      po_vDescricaoRejeicao := 'Erro ao Validar Restricao de Venda: ' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
      RETURN TRUE;
  END F_VALIDAR_RESTRICAO_VENDA;    
  
 /*******************************************************************************
  Nome         : F_VALIDAR_PRECO_MAXIMO
  Descricão    : Funçao para Validar o Preço Máximo
  ********************************************************************************/   
  FUNCTION F_VALIDAR_PRECO_MAXIMO(pi_nCodUsur            IN NUMBER,
                                  pi_nPTabela            IN NUMBER,
                                  pi_nPVenda             IN NUMBER,
                                  po_vDescricaoRejeicao OUT VARCHAR2,
                                  po_nCodRotinaRejeicao OUT NUMBER)
  RETURN BOOLEAN IS
    vbRetValidarPrecoMaximo BOOLEAN;
    vnpermaxvenda           NUMBER;
    vnpvendamax             NUMBER;
    nPERMAXVENDA            PCCONSUM.PERMAXVENDA%TYPE;
    nNUMCASASDECVENDA       PCCONSUM.NUMCASASDECVENDA%TYPE;
  BEGIN
  
    -- Inicializa Retornos
    vbRetValidarPrecoMaximo := FALSE;
    po_vDescricaoRejeicao   := NULL;
    po_nCodRotinaRejeicao   := NULL;
    
    -- Inicializa PerMaxVenda
    vnpermaxvenda           := 0;
     
    -- Pesquisa Parâmetros
    BEGIN
      SELECT PCCONSUM.PERMAXVENDA
           , PCCONSUM.NUMCASASDECVENDA
        INTO nPERMAXVENDA
           , nNUMCASASDECVENDA
        FROM PCCONSUM;
    EXCEPTION 
      WHEN NO_DATA_FOUND THEN
        nPERMAXVENDA      := 0;
        nNUMCASASDECVENDA := 2;
    END;
    IF (nPERMAXVENDA > 0) THEN
      vnpermaxvenda         := nPERMAXVENDA;
      po_nCodRotinaRejeicao := 132;
    END IF;
    
    -- Pesquisa Dados do RCA
    BEGIN
      SELECT PCUSUARI.PERMAXVENDA
        INTO nPERMAXVENDA
        FROM PCUSUARI
       WHERE (PCUSUARI.CODUSUR = pi_nCodUsur);
    EXCEPTION 
      WHEN NO_DATA_FOUND THEN
        nPERMAXVENDA := 0;
    END;
    IF (nPERMAXVENDA > 0) THEN
      vnpermaxvenda         := nPERMAXVENDA;
      po_nCodRotinaRejeicao := 517;
    END IF;
    
    -- calculo preco maximo
    IF (vnpermaxvenda > 0) THEN
    
      vnpvendamax   := (ROUND(pi_nPTabela,
                              nNUMCASASDECVENDA)) *
                       (1 + vnpermaxvenda / 100);
  
      vnpvendamax   := ROUND(vnpvendamax, nNUMCASASDECVENDA);
      
      IF pi_nPVenda > vnpvendamax THEN
      
        vbRetValidarPrecoMaximo := TRUE;
        po_vDescricaoRejeicao   := 'Preço de Venda superior ao preço máximo ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnpvendamax,nNUMCASASDECVENDA) || 
                                   ' calculado conforme % máximo permitido ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnpermaxvenda,nNUMCASASDECVENDA) ;
      
      END IF;
      
    END IF;
    
    -- Retorno
    RETURN vbRetValidarPrecoMaximo;
  
  END F_VALIDAR_PRECO_MAXIMO;

 /*******************************************************************************
  Nome         : F_VALIDAR_PRECO_MINIMO
  Descricão    : Funçao para Validar o Preço Mínimo
  ********************************************************************************/   
  FUNCTION F_VALIDAR_PRECO_MINIMO(pi_nNumRegiao          IN NUMBER,
                                  pi_nCodPlPag           IN NUMBER,
                                  pi_nCodPromocao        IN NUMBER,
                                  pi_nCodDesconto        IN NUMBER,
                                  pi_nCodProd            IN NUMBER,
                                  pi_nPVenda             IN NUMBER,
                                  po_vDescricaoRejeicao OUT VARCHAR2)
  RETURN BOOLEAN IS
    vbRetValidarPrecoMinimo        BOOLEAN;
    nNUMCASASDECVENDA              PCCONSUM.NUMCASASDECVENDA%TYPE;
    vVALIDAPRECOMINIMO             PCCONSUM.VALIDAPRECOMINIMO%TYPE;
    nPERTXFIM                      PCPLPAG.PERTXFIM%TYPE;
    nPRECOMINIMOVENDA              PCTABPR.PRECOMINIMOVENDA%TYPE;
    bIGNORARVALIDACAOPRECOMINPROMO BOOLEAN;
    vAPLICDESCPLPAGPRECOMINVENDA   VARCHAR2(200);
    vnPerTxFimAplicPrecoMinimoVen  NUMBER;
    ---------------------------------------------------------
    -- Função para retornar se Promoção com Preço ou Desconto
    ---------------------------------------------------------
    function PromocaoComPrecoOuDesconto(pi_nCodPromocaoMed in number,
                                        pi_nCodDesconto    in number)
    return boolean is
      nPERCDESC             NUMBER;
      nPERCDESCFIN          NUMBER;
      nPRECOFIXOPROMOCAOMED NUMBER;
    begin
      begin
        SELECT PERCDESC
             , PERCDESCFIN
             , PRECOFIXOPROMOCAOMED
          INTO nPERCDESC
             , nPERCDESCFIN
             , nPRECOFIXOPROMOCAOMED
         FROM PCDESCONTO
         WHERE CODPROMOCAOMED = pi_nCodPromocaoMed
           AND CODDESCONTO    = pi_nCodDesconto
           AND ROWNUM         = 1; 
      exception
        when no_data_found then
          nPERCDESC             := 0;
          nPERCDESCFIN          := 0;
          nPRECOFIXOPROMOCAOMED := 0;
      end;
      return ((NVL(nPERCDESC,0) > 0)    or
              (NVL(nPERCDESCFIN,0) > 0) or
              (NVL(nPRECOFIXOPROMOCAOMED,0) > 0));
    end PromocaoComPrecoOuDesconto;
    --
  BEGIN
  
    -- Inicializa Retornos
    vbRetValidarPrecoMinimo := FALSE;
    po_vDescricaoRejeicao   := NULL;
     
    -- Pesquisa Parâmetros
    BEGIN
      SELECT PCCONSUM.NUMCASASDECVENDA
           , PCCONSUM.VALIDAPRECOMINIMO
        INTO nNUMCASASDECVENDA
           , vVALIDAPRECOMINIMO
        FROM PCCONSUM;
    EXCEPTION 
      WHEN NO_DATA_FOUND THEN
        nNUMCASASDECVENDA  := 2;
        vVALIDAPRECOMINIMO := 'N';
    END;
    
    -- Pesquisa Taxa do Plano de Pagamento
    BEGIN
      SELECT PCPLPAG.PERTXFIM
        INTO nPERTXFIM
        FROM PCPLPAG
       WHERE (PCPLPAG.CODPLPAG = pi_nCodPlPag);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        nPERTXFIM := 0;
    END;
    
    -- Pesquisa Regra Específica
    bIGNORARVALIDACAOPRECOMINPROMO := (F_REGRA_MEDICAMENTOS('99','IGNORARVALIDACAOPRECOMINPROMOCAO') = 'S');
    vAPLICDESCPLPAGPRECOMINVENDA   := F_REGRA_MEDICAMENTOS('99','APLICDESCPLPAGPRECOMINVENDA');
    
    vnPerTxFimAplicPrecoMinimoVen := 0;
    IF (vAPLICDESCPLPAGPRECOMINVENDA = 'S') AND
       (nPERTXFIM < 0)                     THEN
      vnPerTxFimAplicPrecoMinimoVen := nPERTXFIM;
    END IF;
    
    -- Pesquisa Dados da Tabela de Preços
    BEGIN
      SELECT PCTABPR.PRECOMINIMOVENDA
        INTO nPRECOMINIMOVENDA
        FROM PCTABPR
       WHERE (PCTABPR.NUMREGIAO = pi_nNumRegiao)
         AND (PCTABPR.CODPROD   = pi_nCodProd);
    EXCEPTION 
      WHEN NO_DATA_FOUND THEN
        nPRECOMINIMOVENDA := 0;
    END;

    -- Aplica o Desconto do Plano de Pagamento
    if (vnPerTxFimAplicPrecoMinimoVen < 0) then
      nPRECOMINIMOVENDA := (nPRECOMINIMOVENDA * (1 - (Abs(NVL(vnPerTxFimAplicPrecoMinimoVen,0)) / 100)));
    end if;

    -- Não validar se venda de promoção com regra específica
    if (bIGNORARVALIDACAOPRECOMINPROMO) and
       (pi_nCodPromocao > 0) then
      -- Se não for uma Promoção zerada
      if (PromocaoComPrecoOuDesconto(pi_nCodPromocao,
                                     pi_nCodDesconto)) then
        nPRECOMINIMOVENDA := 0;
      end if;
    end if;

    -- verifica preco minimo permitido
    IF (vVALIDAPRECOMINIMO = 'S') THEN
      if pi_nPVenda < round(nPRECOMINIMOVENDA,nNUMCASASDECVENDA) then
  
        vbRetValidarPrecoMinimo := TRUE;
        po_vDescricaoRejeicao   := 'Preço abaixo do Preço Mínimo ' || F_FORMATAR_NUMERO_PARA_TEXTO(nPRECOMINIMOVENDA,nNUMCASASDECVENDA);
              
      END IF;
    END IF;
    
    -- Retorno
    RETURN vbRetValidarPrecoMinimo;
  
  END F_VALIDAR_PRECO_MINIMO;
  
 /******************************************************************************************
  Nome         : P_INSERE_TABTEMP
  Descricão    : Procedimento para Inserir na Tabela Temporária Críticas da Troca do Cliente
  ******************************************************************************************/   
  PROCEDURE P_INSERE_TABTEMP(pNUMPED            PCMED_VALIDACAO_GERAL_TROCA.NUMPED%TYPE,
                             pCODPROD           PCMED_VALIDACAO_GERAL_TROCA.CODPROD%TYPE,
                             pNUMSEQ            PCMED_VALIDACAO_GERAL_TROCA.NUMSEQ%TYPE,
                             pDESCRICAO         PCMED_VALIDACAO_GERAL_TROCA.DESCRICAO%TYPE,
                             pCODREJEICAO       PCMED_VALIDACAO_GERAL_TROCA.CODREJEICAO%TYPE,
                             pTIPOREJEICAO      PCMED_VALIDACAO_GERAL_TROCA.TIPOREJEICAO%TYPE,
                             pCODMOTIVONAOATEND PCMED_VALIDACAO_GERAL_TROCA.CODMOTIVONAOATEND%TYPE,
                             pDESCRICAOREJEICAO PCMED_VALIDACAO_GERAL_TROCA.DESCRICAOREJEICAO%TYPE,
                             pCODROTINA         PCMED_VALIDACAO_GERAL_TROCA.CODROTINA%TYPE,
                             pOBSERVACAO        PCMED_VALIDACAO_GERAL_TROCA.OBSERVACAO%TYPE,
                             pALERTACRITICA     PCMED_VALIDACAO_GERAL_TROCA.ALERTACRITICA%TYPE,
                             pio_vAlertas       IN OUT VARCHAR2,
                             pio_vRejeicoes     IN OUT VARCHAR2) IS
  BEGIN
    -- Insere na Tabela Temporária
    INSERT INTO PCMED_VALIDACAO_GERAL_TROCA
              ( NUMPED
              , CODPROD
              , NUMSEQ
              , DESCRICAO
              , CODREJEICAO
              , TIPOREJEICAO
              , CODMOTIVONAOATEND
              , DESCRICAOREJEICAO
              , CODROTINA
              , OBSERVACAO
              , ALERTACRITICA )
       VALUES ( pNUMPED
              , pCODPROD
              , pNUMSEQ
              , SUBSTR(pDESCRICAO,1,80)
              , pCODREJEICAO
              , pTIPOREJEICAO
              , pCODMOTIVONAOATEND
              , SUBSTR(pDESCRICAOREJEICAO,1,40)
              , pCODROTINA
              , SUBSTR(pOBSERVACAO,1,200)
              , pALERTACRITICA );
    -- Atualiza Retorno
    IF (pALERTACRITICA = 'A') THEN
      pio_vAlertas   := 'S';
    END IF;
    IF (pALERTACRITICA = 'R') THEN
      pio_vRejeicoes := 'S';
    END IF;                
  END P_INSERE_TABTEMP;                          

 /******************************************************************************************
  Nome         : P_INSERE_TABTEMP_2
  Descricão    : Procedimento para Inserir na Tabela Temporária Críticas da Troca do Cliente
  ******************************************************************************************/   
  PROCEDURE P_INSERE_TABTEMP_2(pNUMPED              PCMED_VALIDACAO_GERAL_TROCA.NUMPED%TYPE,
                               pCODPROD             PCMED_VALIDACAO_GERAL_TROCA.CODPROD%TYPE,
                               pNUMSEQ              PCMED_VALIDACAO_GERAL_TROCA.NUMSEQ%TYPE,
                               pDESCRICAO           PCMED_VALIDACAO_GERAL_TROCA.DESCRICAO%TYPE,
                               pCODREJEICAO         PCMED_VALIDACAO_GERAL_TROCA.CODREJEICAO%TYPE,
                               pTIPOREJEICAO        PCMED_VALIDACAO_GERAL_TROCA.TIPOREJEICAO%TYPE,
                               pCODMOTIVONAOATEND   PCMED_VALIDACAO_GERAL_TROCA.CODMOTIVONAOATEND%TYPE,
                               pDESCRICAOREJEICAO   PCMED_VALIDACAO_GERAL_TROCA.DESCRICAOREJEICAO%TYPE,
                               pCODROTINA           PCMED_VALIDACAO_GERAL_TROCA.CODROTINA%TYPE,
                               pOBSERVACAO          PCMED_VALIDACAO_GERAL_TROCA.OBSERVACAO%TYPE,
                               pALERTACRITICA       PCMED_VALIDACAO_GERAL_TROCA.ALERTACRITICA%TYPE,
                               pIDENTIFICADORPRINC  PCMED_VALIDACAO_GERAL_TROCA.IDENTIFICADORPRINC%TYPE,
                               pIDENTIFICADORSECUND PCMED_VALIDACAO_GERAL_TROCA.IDENTIFICADORSECUND%TYPE,
                               pio_vAlertas         IN OUT VARCHAR2,
                               pio_vRejeicoes       IN OUT VARCHAR2) IS
  BEGIN
    -- Insere na Tabela Temporária
    INSERT INTO PCMED_VALIDACAO_GERAL_TROCA
              ( NUMPED
              , CODPROD
              , NUMSEQ
              , DESCRICAO
              , CODREJEICAO
              , TIPOREJEICAO
              , CODMOTIVONAOATEND
              , DESCRICAOREJEICAO
              , CODROTINA
              , OBSERVACAO
              , ALERTACRITICA
              , IDENTIFICADORPRINC
              , IDENTIFICADORSECUND )
       VALUES ( pNUMPED
              , pCODPROD
              , pNUMSEQ
              , SUBSTR(pDESCRICAO,1,80)
              , pCODREJEICAO
              , pTIPOREJEICAO
              , pCODMOTIVONAOATEND
              , SUBSTR(pDESCRICAOREJEICAO,1,40)
              , pCODROTINA
              , SUBSTR(pOBSERVACAO,1,200)
              , pALERTACRITICA
              , pIDENTIFICADORPRINC
              , pIDENTIFICADORSECUND );
    -- Atualiza Retorno
    IF (pALERTACRITICA = 'A') THEN
      pio_vAlertas   := 'S';
    END IF;
    IF (pALERTACRITICA = 'R') THEN
      pio_vRejeicoes := 'S';
    END IF;                
  END P_INSERE_TABTEMP_2;                          
  
 /*******************************************************************************
  Nome         : P_VALIDAR_TROCA_CLIPROD
  Descricão    : Procedimento para Validar Troca do Cliente, referente aos produtos
  ********************************************************************************/   
  PROCEDURE P_VALIDAR_TROCA_CLIPROD(pi_vOrigemChamada        IN VARCHAR2,
                                    pi_nMatricula            IN NUMBER,
                                    pi_nNumPed               IN NUMBER,
                                    pi_nCodCli               IN NUMBER,
                                    pi_nCodPlPag             IN NUMBER,
                                    pi_nCodPlPagEtico        IN NUMBER,
                                    pi_nCodPlPagGenerico     IN NUMBER,
                                    pi_vCodCob               IN VARCHAR2,
                                    pi_nCodPromocaoMed       IN NUMBER,
                                    pi_nNumRegiao            IN NUMBER,
                                    pi_vCodFilial            IN VARCHAR2,
                                    pi_vCodFilialNf          IN VARCHAR2,
                                    po_vOcorreramAlertas    OUT VARCHAR2,
                                    po_vOcorreramRejeicoes  OUT VARCHAR2,
                                    po_vPodeGravarPedido    OUT VARCHAR2,
                                    po_vMotivoNaoPodeGravar OUT VARCHAR2,
                                    po_vProblemasTriPrecif  OUT VARCHAR2) IS
                                    
    nCODUSUR                  PCPEDC.CODUSUR%TYPE;
    nCONDVENDA                PCPEDC.CONDVENDA%TYPE;
    vPOSICAO                  PCPEDC.POSICAO%TYPE;
    vORIGEMPED                PCPEDC.ORIGEMPED%TYPE;
    vTIPOFV                   PCPEDC.TIPOFV%TYPE;
    vFRETEDESPACHO            PCPEDC.FRETEDESPACHO%TYPE;
    dDATAPEDIDO               PCPEDC.DATA%TYPE;
    vDESCRICAO                PCPRODUT.DESCRICAO%TYPE;
    vGRUPOFATURAMENTO         PCPRODUT.GRUPOFATURAMENTO%TYPE;
    vnCodPlPagProduto         PCPEDC.CODPLPAG%TYPE;
    vTIPOFJ                   PCCLIENT.TIPOFJ%TYPE;
    vVALIDALVARAPORTIPOCTLVEN PCPARAMFILIAL.VALOR%TYPE;
    vnCodSt                   PCTRIBUT.CODST%TYPE;
    nPVENDA1                  PCTABPR.PVENDA1%TYPE;
    nNUMCASASDECVENDA         NUMBER;
    vDESCRICAORESUMIDA        PCPROMOCAOMED.DESCRICAORESUMIDA%TYPE;
    
    -- Dados Itens Pedido
    TYPE TRecDadosItens       IS RECORD (
         CODPROD              PCPEDI.CODPROD%TYPE,
         NUMSEQ               PCPEDI.NUMSEQ%TYPE,
         QT                   PCPEDI.QT%TYPE,
         CODPROMOCAOMED       PCPEDI.CODPROMOCAOMED%TYPE,
         CODDESCONTO          PCPEDI.CODDESCONTO%TYPE,
         CODFILIALRETIRA      PCPEDI.CODFILIALRETIRA%TYPE,
         PRECOMAXCONSUM       PCPEDI.PRECOMAXCONSUM%TYPE,
         NUMLOTE              PCPEDI.NUMLOTE%TYPE,
         NUMLOTEPROMOCAOMED   PCPEDI.NUMLOTEPROMOCAOMED%TYPE,
         --
         OLD_PTABELA          PCPEDI.PTABELA%TYPE,
         OLD_PERDESC          PCPEDI.PERDESC%TYPE,
         OLD_PVENDA           PCPEDI.PVENDA%TYPE,
         OLD_ST               PCPEDI.ST%TYPE,
         OLD_VLFECP           PCPEDI.VLFECP%TYPE,
         OLD_VLREPASSE        PCPEDI.VLREPASSE%TYPE,
         OLD_VLDESCICMISENCAO PCPEDI.VLDESCICMISENCAO%TYPE, -- DDMEDICA-6874
         OLD_VLDESCSUFRAMA    PCPEDI.VLDESCSUFRAMA%TYPE,    -- DDMEDICA-6874
         --
         NEW_PTABELA          PCPEDI.PTABELA%TYPE,
         NEW_PERDESC          PCPEDI.PERDESC%TYPE,
         NEW_PVENDA           PCPEDI.PVENDA%TYPE,
         NEW_ST               PCPEDI.ST%TYPE,
         NEW_VLFECP           PCPEDI.VLFECP%TYPE,
         NEW_VLREPASSE        PCPEDI.VLREPASSE%TYPE,
         NEW_VLDESCICMISENCAO PCPEDI.VLDESCICMISENCAO%TYPE, -- DDMEDICA-6874
         NEW_VLDESCSUFRAMA    PCPEDI.VLDESCSUFRAMA%TYPE,    -- DDMEDICA-6874
         --
         CRITICA_TRIBUTACAO   VARCHAR2(1),
         DESCRICAO_TRIBUTACAO VARCHAR2(2000),
         ROTINA_TRIBUTACAO    NUMBER,
         CRITICA_PRECIFIC     VARCHAR2(1),
         DESCRICAO_PRECIFIC   VARCHAR(2000));
    vrDadosItens              TRecDadosItens;
    TYPE TTvDadosItens        IS TABLE OF TRecDadosItens INDEX BY BINARY_INTEGER;
    vtDadosItens              TTvDadosItens;
    viIdx                     INTEGER;

    vvDescricaoRejeicao           VARCHAR2(255);
    vnCodRotinaRejeicao           NUMBER;
    vvMsgAux                      VARCHAR2(255);
    vvTipoCriticaProd             VARCHAR2(1);
    vvPodeComprarPromocao         VARCHAR2(2000);

    TYPE TRecRetornoControleVenda IS RECORD(
         vvPodeComprarProduto     VARCHAR2(1),
         vvMotivoNaoPodeComprar   VARCHAR2(2000),
         vnQtdeLimite             NUMBER); 
    vrRetornoControleVenda        TRecRetornoControleVenda;

    TYPE TRecDadosRetValidaProd   IS RECORD(
         vnPercDesc               NUMBER,
         vvTipoRejeicaoProduto    VARCHAR2(1),
         vvMotivoNaoPodeComprar   VARCHAR2(2000),
         vnQtdeLimite             NUMBER);
    vrDadosRetValidaProd          TRecDadosRetValidaProd;

    vnMultiplo                    NUMBER; -- DDVENDAS-41227

  BEGIN

    -- Inicializa Retornos
    po_vOcorreramAlertas    := 'N';
    po_vOcorreramRejeicoes  := 'N';
    po_vPodeGravarPedido    := 'S';
    po_vMotivoNaoPodeGravar := NULL;
    po_vProblemasTriPrecif  := 'N';
    
   /***********************************************
    Pesquisa Dados do Pedido que não serão trocados
    ***********************************************/
    BEGIN
      SELECT PCPEDC.CODUSUR
           , PCPEDC.CONDVENDA
           , PCPEDC.POSICAO
           , PCPEDC.ORIGEMPED
           , PCPEDC.TIPOFV
           , PCPEDC.FRETEDESPACHO
           , PCPEDC.DATA
        INTO nCODUSUR
           , nCONDVENDA
           , vPOSICAO
           , vORIGEMPED
           , vTIPOFV
           , vFRETEDESPACHO
           , dDATAPEDIDO
        FROM PCPEDC
       WHERE (PCPEDC.NUMPED = pi_nNumPed);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        nCODUSUR       := NULL;
        nCONDVENDA     := NULL;
        vPOSICAO       := NULL;
        vORIGEMPED     := NULL;
        vTIPOFV        := NULL;
        vFRETEDESPACHO := NULL;
        dDATAPEDIDO    := NULL;
    END;
    
   /*************************
    Pesquisa Dados do Cliente
    *************************/
    BEGIN
      SELECT PCCLIENT.TIPOFJ
        INTO vTIPOFJ
        FROM PCCLIENT
       WHERE (PCCLIENT.CODCLI = pi_nCodCli);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vTIPOFJ := NULL;
    END;
    
   /*******************
    Pesquisa Parâmetros
    *******************/
    POBTEM_PARAMFILIAL_STRING('99',
                              'VALIDALVARAPORTIPOCTLVEN',
                              'N',
                              vVALIDALVARAPORTIPOCTLVEN);
    BEGIN
      SELECT PCCONSUM.NUMCASASDECVENDA
        INTO nNUMCASASDECVENDA
        FROM PCCONSUM;
    EXCEPTION 
      WHEN NO_DATA_FOUND THEN
        nNUMCASASDECVENDA  := 2;
    END;
                                  
   /*********************************************
    Grava em Array os Valores Atuais dos Produtos
    *********************************************/
    
    viIdx := 0;
    
    FOR vc_Itens IN (SELECT PCPEDI.CODPROD,
                            PCPEDI.NUMSEQ,
                            PCPEDI.QT,
                            PCPEDI.CODPROMOCAOMED,
                            PCPEDI.CODDESCONTO,
                            PCPEDI.CODFILIALRETIRA,
                            PCPEDI.PRECOMAXCONSUM,
                            PCPEDI.NUMLOTE,
                            PCPEDI.NUMLOTEPROMOCAOMED,
                            (NVL(PCPEDI.PTABELA,0)  - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLREPASSE,0) - NVL(PCPEDI.VLFECP,0)) PTABELA,
                            PCPEDI.PERDESC,
                            (NVL(PCPEDI.PVENDA,0)  - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLREPASSE,0) -  NVL(PCPEDI.VLFECP,0)) PVENDA,
                            PCPEDI.ST,
                            PCPEDI.VLFECP,
                            PCPEDI.VLREPASSE,
                            PCPEDI.VLDESCICMISENCAO, -- DDMEDICA-6874
                            PCPEDI.VLDESCSUFRAMA     -- DDMEDICA-6874
                       FROM PCPEDI
                      WHERE (PCPEDI.NUMPED = pi_nNumPed)
                      ORDER BY PCPEDI.CODPROD,
                               PCPEDI.NUMSEQ) LOOP
      
      vrDadosItens.CODPROD              := vc_Itens.CODPROD;
      vrDadosItens.NUMSEQ               := vc_Itens.NUMSEQ;
      vrDadosItens.QT                   := vc_Itens.QT;
      vrDadosItens.CODPROMOCAOMED       := vc_Itens.CODPROMOCAOMED;
      vrDadosItens.CODDESCONTO          := vc_Itens.CODDESCONTO;
      vrDadosItens.CODFILIALRETIRA      := vc_Itens.CODFILIALRETIRA;
      vrDadosItens.PRECOMAXCONSUM       := vc_Itens.PRECOMAXCONSUM;     
      vrDadosItens.NUMLOTE              := vc_Itens.NUMLOTE;     
      vrDadosItens.NUMLOTEPROMOCAOMED   := vc_Itens.NUMLOTEPROMOCAOMED;     
      vrDadosItens.OLD_PTABELA          := vc_Itens.PTABELA;
      vrDadosItens.OLD_PERDESC          := vc_Itens.PERDESC;
      vrDadosItens.OLD_PVENDA           := vc_Itens.PVENDA;
      vrDadosItens.OLD_ST               := vc_Itens.ST;
      vrDadosItens.OLD_VLFECP           := vc_Itens.VLFECP;
      vrDadosItens.OLD_VLREPASSE        := vc_Itens.VLREPASSE;
      vrDadosItens.OLD_VLDESCICMISENCAO := vc_Itens.VLDESCICMISENCAO; -- DDMEDICA-6874
      vrDadosItens.OLD_VLDESCSUFRAMA    := vc_Itens.VLDESCSUFRAMA;    -- DDMEDICA-6874

      viIdx := NVL(viIdx,0) + 1;
            
      vtDadosItens(viIdx) := vrDadosItens;
            
    END LOOP;                               
                       
   /*********************************
    Validação da Tributação dos Itens
    *********************************/
    IF (vtDadosItens.COUNT > 0) THEN
      FOR viIdx IN vtDadosItens.FIRST..vtDadosItens.LAST LOOP
       
        vrDadosItens := vtDadosItens(viIdx);
        
        -- Pesquisa Dados do Produto
        BEGIN
          SELECT PCPRODUT.DESCRICAO
            INTO vDESCRICAO
            FROM PCPRODUT
           WHERE (PCPRODUT.CODPROD = vrDadosItens.CODPROD);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vDESCRICAO := NULL;
        END;
        
        -- Busca a Tributação
        P_OBTER_TRIBUTACAO(vrDadosItens.CODPROD,
                           pi_nCodCli,
                           pi_vCodFilial,
                           pi_nNumRegiao,
                           vnCodSt,
                           vvDescricaoRejeicao,
                           vnCodRotinaRejeicao);
       
        -- Se não tem Tributação
        IF (NVL(vnCodSt,0) = 0) THEN
        
          -- Não pode Gravar o Pedido
          po_vPodeGravarPedido    := 'N';
          po_vMotivoNaoPodeGravar := 'Problemas de Tributação'; 
          po_vProblemasTriPrecif  := 'S';
          
          -- Histórico da Crítica
          vrDadosItens.CRITICA_TRIBUTACAO   := 'S';
          vrDadosItens.DESCRICAO_TRIBUTACAO := vvDescricaoRejeicao;
          vrDadosItens.ROTINA_TRIBUTACAO    := vnCodRotinaRejeicao;
                                       
        -- Se tem Tributação
        ELSE
        
          -- Pesquisa Preço de Venda na Região
          BEGIN
            SELECT PCTABPR.PVENDA1
              INTO nPVENDA1
              FROM PCTABPR
             WHERE (PCTABPR.CODPROD   = vrDadosItens.CODPROD)
               AND (PCTABPR.NUMREGIAO = pi_nNumRegiao);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              nPVENDA1 := 0;
          END;
          
          -- Se não tem Preço
          IF (NVL(nPVENDA1,0) = 0) THEN
          
            -- Não pode Gravar o Pedido
            po_vPodeGravarPedido      := 'N';
            IF (po_vMotivoNaoPodeGravar IS NULL) THEN
              po_vMotivoNaoPodeGravar := 'Problemas de Precificação'; 
            END IF;
            po_vProblemasTriPrecif    := 'S';
                      
            -- Histórico da Crítica
            vrDadosItens.CRITICA_PRECIFIC   := 'S';
            vrDadosItens.DESCRICAO_PRECIFIC := 'Produto sem Preço de Venda na Região ' || pi_nNumRegiao;
                                  
          END IF;
        
        END IF; -- Fim Condição: Se não tem Tributação
        
        vtDadosItens(viIdx) := vrDadosItens;
        
      END LOOP;
    END IF;
                       
    -- Se não ocorreram Problemas de Tributação
    -- (Nem adianta executar a Validação porque Produto sem Tributação dá exceção da Procedure)
    IF (NVL(po_vPodeGravarPedido,'N') = 'S') THEN
    
     /******************************************
      Recálculo dos Preços com os dados da Troca
      *****************************************/
      BEGIN
      
        PKG_PROMOCAO_MED.P_VALIDA_PROMOCAO(10, -->> Recalcular o Pedido ao alterar Plano de Pagamento
                                           pi_nNumPed,
                                           pi_nCodCli,
                                           nCODUSUR,
                                           pi_vCodFilial,
                                           pi_nNumRegiao,
                                           nCONDVENDA,
                                           pi_nCodPlPag,
                                           pi_nCodPromocaoMed,
                                           vPOSICAO,
                                           NULL,  -- pi_nOpcaoTipoEntrega,
                                           2316,  -- pi_nRotinaLanc,
                                           NULL,  -- pi_nQtCombos
                                           po_vPodeGravarPedido,
                                           po_vMotivoNaoPodeGravar,
                                           pi_vCodFilialNF,
                                           pi_vCodCob,
                                           NULL,  -- pi_nCodEdital
                                           NULL,  -- pi_vNumEmpenho
                                           pi_nMatricula,
                                           'S',   -- pi_vVisualizarPromoBloq
                                           NULL,  -- pi_nCodProd
                                           pi_nCodPlPagEtico,
                                           pi_nCodPlPagGenerico,
                                           NULL,  -- pi_nNumOrcamento
                                           NULL,  -- pi_nCodLinhaPrazo
                                           NULL,  -- pi_nCodCondicaoVenda
                                           vORIGEMPED,
                                           vTIPOFV,
                                           NULL,  -- pi_nCodUsurContaCorrente,
                                           NULL,  -- pi_vCodFilialRetira
                                           NULL,  -- pi_nNumTransEntCrossDock
                                           NULL); -- pi_vInProdutosCrossDock
       
        -- Se não ocorreram erros na Validação da Promoção
        IF (NVL(po_vPodeGravarPedido,'N') = 'S') THEN
        
          viIdx := 0;
          
          FOR vc_Itens IN (SELECT (NVL(PCPEDI.PTABELA,0)  - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLREPASSE,0) - NVL(PCPEDI.VLFECP,0)) PTABELA,
                                  PCPEDI.PERDESC,
                                  (NVL(PCPEDI.PVENDA,0)  - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLREPASSE,0) -  NVL(PCPEDI.VLFECP,0)) PVENDA,
                                  PCPEDI.ST,
                                  PCPEDI.VLFECP,
                                  PCPEDI.VLREPASSE,
                                  PCPEDI.VLDESCICMISENCAO, -- DDMEDICA-6874
                                  PCPEDI.VLDESCSUFRAMA     -- DDMEDICA-6874
                             FROM PCPEDI
                            WHERE (PCPEDI.NUMPED = pi_nNumPed)
                            ORDER BY PCPEDI.CODPROD,
                                     PCPEDI.NUMSEQ) LOOP
            
            viIdx := NVL(viIdx,0) + 1;
                  
            vrDadosItens := vtDadosItens(viIdx);
    
            vrDadosItens.NEW_PTABELA          := vc_Itens.PTABELA;
            vrDadosItens.NEW_PERDESC          := vc_Itens.PERDESC;
            vrDadosItens.NEW_PVENDA           := vc_Itens.PVENDA;
            vrDadosItens.NEW_ST               := vc_Itens.ST;
            vrDadosItens.NEW_VLFECP           := vc_Itens.VLFECP;
            vrDadosItens.NEW_VLREPASSE        := vc_Itens.VLREPASSE;
            vrDadosItens.NEW_VLDESCICMISENCAO := vc_Itens.VLDESCICMISENCAO; -- DDMEDICA-6874
            vrDadosItens.NEW_VLDESCSUFRAMA    := vc_Itens.VLDESCSUFRAMA;    -- DDMEDICA-6874
    
            vtDadosItens(viIdx) := vrDadosItens;
            
          END LOOP;    
              
        END IF; -- Fim Condição: Se não ocorreram erros na Validação da Promoção
  
        IF (NVL(pi_vOrigemChamada,'V') = 'V') THEN
          ROLLBACK; -->> DESFAZ ALTERAÇÕES (SOMENTE VALIDAR VALORES CALCULADOS
        END IF;
               
      EXCEPTION
        WHEN OTHERS THEN
          IF (NVL(pi_vOrigemChamada,'V') = 'V') THEN
            ROLLBACK; -->> DESFAZ ALTERAÇÕES (SOMENTE VALIDAR VALORES CALCULADOS
          END IF;
      END;
      
    END IF; -- Fim Condição: Se não ocorreram erros de Tributação
            
   /***************************
    Limpa Tabelas Temporárias
    ***************************/
    DELETE FROM PCMED_VALIDACAO_PRECO_TROCA;
    DELETE FROM PCMED_VALIDACAO_GERAL_TROCA;
                
   /***************************
    Demais Validações dos Itens
    ***************************/
    IF (vtDadosItens.COUNT > 0) THEN
      FOR viIdx IN vtDadosItens.FIRST..vtDadosItens.LAST LOOP
       
        vrDadosItens := vtDadosItens(viIdx);
        
        -- Pesquisa Dados do Produto
        BEGIN
          SELECT PCPRODUT.DESCRICAO
               , PCPRODUT.GRUPOFATURAMENTO
            INTO vDESCRICAO
               , vGRUPOFATURAMENTO
            FROM PCPRODUT
           WHERE (PCPRODUT.CODPROD = vrDadosItens.CODPROD);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vDESCRICAO        := NULL;
            vGRUPOFATURAMENTO := NULL;
        END;
        
        -- Plano de Pagamento do Produto
        IF (NVL(pi_nCodPlPagEtico,0) > 0) AND
           (NVL(pi_nCodPlPagGenerico,0) > 0) THEN
          IF (NVL(vGRUPOFATURAMENTO,'N') = 'E') THEN
            vnCodPlPagProduto := pi_nCodPlPagEtico;
          ELSE
            vnCodPlPagProduto := pi_nCodPlPagGenerico;
          END IF;
        ELSE
          vnCodPlPagProduto := pi_nCodPlPag;
        END IF;

        ----------------------------
        -- Validação da Tributação
        ----------------------------
        IF (vrDadosItens.CRITICA_TRIBUTACAO = 'S') THEN

          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Tributação',
                           vrDadosItens.ROTINA_TRIBUTACAO,
                           vrDadosItens.DESCRICAO_TRIBUTACAO,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);

        END IF;

        ----------------------------
        -- Validação da Precificação
        ----------------------------
        IF (vrDadosItens.CRITICA_PRECIFIC = 'S') THEN
        
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Precificação',
                           201,
                           vrDadosItens.DESCRICAO_PRECIFIC,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        
        END IF;

        -- Se não ocorreram erros na Validação da Promoção, Compara os Preços
        IF (NVL(po_vPodeGravarPedido,'N') = 'S') THEN

          ----------------------------
          -- Validação de Preço Tabela 
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_PTABELA,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_PTABELA,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'Preço de Tabela',
                             NULL,
                             'Variação do Preço de Tabela',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
         
          ----------------------------
          -- Validação de % Desconto
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_PERDESC,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_PERDESC,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             '% Desconto',
                             NULL,
                             'Variação do % Desconto',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
  
          ----------------------------
          -- Validação de Preço Venda
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_PVENDA,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_PVENDA,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'Preço Venda',
                             NULL,
                             'Variação do Preço Venda',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
  
          ----------------------------
          -- Validação de ST
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_ST,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_ST,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'ST',
                             NULL,
                             'Variação do ST',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
  
          ----------------------------
          -- Validação de ST do FECP
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_VLFECP,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_VLFECP,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'ST do FECP',
                             NULL,
                             'Variação do ST do FECP',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
  
          ----------------------------
          -- Validação de Repasse
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_VLREPASSE,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_VLREPASSE,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'Repasse',
                             NULL,
                             'Variação do Repasse',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
          
          ----------------------------
          -- Validação de Desoneração 
          -- DDMEDICA-6874
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_VLDESCICMISENCAO,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_VLDESCICMISENCAO,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'Desc. Isenção ICMS',
                             NULL,
                             'Variação Desc. Isenção ICMS',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;

          ----------------------------
          -- Validação de 
          -- DDMEDICA-6874
          ----------------------------
          IF (ROUND(NVL(vrDadosItens.OLD_VLDESCSUFRAMA,0),nNUMCASASDECVENDA) <> ROUND(NVL(vrDadosItens.NEW_VLDESCSUFRAMA,0),nNUMCASASDECVENDA)) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'Suframa',
                             NULL,
                             'Variação Desc. Suframa',
                             'A',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);
          END IF;
          
        END IF; -- Fim Condição: Se não ocorreram erros na Validação da Promoção, Compara os Preços

        ------------------------
        -- Validação de Múltiplo 
        ------------------------
        IF (F_VALIDAR_MULTIPLO(pi_nCodCli,
                               nCONDVENDA,
                               vrDadosItens.CODPROD,
                               vrDadosItens.QT,
                               pi_vCodFilial,    -- DDVENDAS-41227
                               vvDescricaoRejeicao,
                               vnMultiplo)) THEN -- DDVENDAS-41227
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Múltiplo de Venda',
                           302,
                           vvDescricaoRejeicao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;

        ----------------------------------
        -- Validação de Restrição de Venda
        ----------------------------------
        IF (F_VALIDAR_RESTRICAO_VENDA(vrDadosItens.CODPROD,
                                      pi_nNumRegiao,
                                      pi_nCodCli,
                                      nCODUSUR,
                                      pi_vCodFilial,
                                      nCONDVENDA,
                                      vFRETEDESPACHO,
                                      vORIGEMPED,
                                      vnCodPlPagProduto, -->> Plano de Pagamento do Produto
                                      pi_vCodCob,
                                      0, -- p_vlatend
                                      vvDescricaoRejeicao)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Restrição de Venda',
                           391,
                           vvDescricaoRejeicao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;

        ----------------------------
        -- Validação de Preço Máximo
        ----------------------------
        IF (F_VALIDAR_PRECO_MAXIMO(nCODUSUR,
                                   vrDadosItens.NEW_PTABELA,
                                   vrDadosItens.NEW_PVENDA,
                                   vvDescricaoRejeicao,
                                   vnCodRotinaRejeicao)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Preço Máximo',
                           vnCodRotinaRejeicao,
                           vvDescricaoRejeicao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;

        ----------------------------
        -- Validação de Preço Mínimo
        ----------------------------
        IF (F_VALIDAR_PRECO_MINIMO(pi_nNumRegiao,
                                   vnCodPlPagProduto, -->> Plano de Pagamento do Produto
                                   vrDadosItens.CODPROMOCAOMED,
                                   vrDadosItens.CODDESCONTO,
                                   vrDadosItens.CODPROD,
                                   vrDadosItens.NEW_PVENDA,
                                   vvDescricaoRejeicao)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Preço Mínimo',
                           201,
                           vvDescricaoRejeicao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
        
        ----------------------
        -- Validação de Alvará
        ----------------------
        P_VALIDA_CONTROLE_VENDA('G', -->> Chamada de Validação ao Gravar o Pedido
                                pi_nCodCli,
                                vTIPOFJ,
                                vrDadosItens.CODPROD,
                                vrDadosItens.QT,
                                pi_nNumPed,
                                vrDadosItens.NUMSEQ,
                                vrRetornoControleVenda.vvPodeComprarProduto,
                                vrRetornoControleVenda.vvMotivoNaoPodeComprar,
                                vrRetornoControleVenda.vnQtdeLimite);
        IF (vrRetornoControleVenda.vvPodeComprarProduto = 'N') THEN
          IF (NVL(vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') THEN
           vvMsgAux := '3331';
          ELSE
           vvMsgAux := '302';
          END IF;
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Alvará',
                           vvMsgAux, -->> Código da Rotina conforme Parâmetro
                           vrRetornoControleVenda.vvMotivoNaoPodeComprar,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);      
        END IF;
        
        -----------------------------
        -- Validação Final do Produto
        -----------------------------
        
        -- Chama Proc. de Validação
        PKG_FUNCOESVENDAS_MED.P_VALIDACAO_FINAL_PROD('T', -- Origem Chamada = Televendas
                                                     'I', -- Tipo Chamada = Inclusão do Item do Pedido
                                                     'S', -- Grava Tabela Temporária
                                                     vORIGEMPED,
                                                     vTIPOFV,
                                                     NULL, -- pi_nIntegradora
                                                     pi_vCodFilial,
                                                     pi_vCodFilialNF,
                                                     vrDadosItens.CODFILIALRETIRA,
                                                     pi_nCodCli,
                                                     pi_nNumRegiao,
                                                     nCODUSUR,
                                                     vnCodPlPagProduto,
                                                     vrDadosItens.CODPROMOCAOMED,
                                                     vrDadosItens.CODPROD,
                                                     vrDadosItens.QT,
                                                     vrDadosItens.NEW_PERDESC,
                                                     vrDadosItens.NEW_PVENDA,
                                                     pi_nNumPed,
                                                     vrDadosItens.NUMSEQ,
                                                     vrDadosItens.PRECOMAXCONSUM,
                                                     vrDadosRetValidaProd.vvTipoRejeicaoProduto,
                                                     vrDadosRetValidaProd.vvMotivoNaoPodeComprar,
                                                     vrDadosRetValidaProd.vnQtdeLimite,
                                                     vrDadosItens.CODDESCONTO,
                                                     vrDadosItens.NUMLOTE,
                                                     vrDadosItens.NUMLOTEPROMOCAOMED);
        -->> Primeiro verifica críticas que bloqueiam                                           
        FOR vc_Rejeicoes IN (SELECT PCMED_VALIDACAO_GERAL_PRODUTO.CODREJEICAO
                                  , PCMED_VALIDACAO_GERAL_PRODUTO.CODMOTIVONAOATEND
                                  , PCMED_VALIDACAO_GERAL_PRODUTO.DESCRICAOREJEICAO
                                  , PCMED_VALIDACAO_GERAL_PRODUTO.OBSERVACAO
                                  , PCMED_VALIDACAO_GERAL_PRODUTO.CODROTINA
                               FROM PCMED_VALIDACAO_GERAL_PRODUTO) LOOP 
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           vc_Rejeicoes.CODREJEICAO,
                           NULL,
                           vc_Rejeicoes.CODMOTIVONAOATEND,
                           vc_Rejeicoes.DESCRICAOREJEICAO,
                           vc_Rejeicoes.CODROTINA,
                           vc_Rejeicoes.OBSERVACAO,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);      
        END LOOP;
        
        ------------------------------------------
        -- Validação da Promoção do Item do Pedido
        ------------------------------------------
        vvPodeComprarPromocao := PKG_FUNCOESVENDAS_MED.F_PODECOMPRARPROMOCAO(vrDadosItens.CODPROMOCAOMED,
                                                                             pi_vCodFilial,
                                                                             pi_nCodCli,
                                                                             pi_nNumRegiao,
                                                                             nCODUSUR,
                                                                             vnCodPlPagProduto, -->> Plano de Pagamento do Produto
                                                                             NULL, -- pi_nCodCondicaoVenda
                                                                             vORIGEMPED, 
                                                                             vTIPOFV,
                                                                             dDATAPEDIDO);
        IF (NVL(vvPodeComprarPromocao,'N') <> 'S') THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           vrDadosItens.CODPROD,
                           vrDadosItens.NUMSEQ,
                           vDESCRICAO,
                           NULL,
                           NULL,
                           NULL,
                           'Promoção',
                           2323,
                           'Promoção não permitida: ' || SUBSTR(vvPodeComprarPromocao,5,LENGTH(vvPodeComprarPromocao)),
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);      
        END IF;                                                     
        
        -------------------------------
        -- Gravação da Tabela dos Itens
        -------------------------------
        
        -- Pesquisa a Descrição da Promoção
        BEGIN
          SELECT PCPROMOCAOMED.DESCRICAORESUMIDA
            INTO vDESCRICAORESUMIDA
            FROM PCPROMOCAOMED
           WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vrDadosItens.CODPROMOCAOMED);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vDESCRICAORESUMIDA := NULL;
        END;
        
        -- Define o Tipo de Crítica do Produto
        BEGIN
          SELECT ALERTACRITICA
            INTO vvTipoCriticaProd
            FROM PCMED_VALIDACAO_GERAL_TROCA
           WHERE (NUMPED        = pi_nNumPed)
             AND (CODPROD       = vrDadosItens.CODPROD)
             AND (NUMSEQ        = vrDadosItens.NUMSEQ)
             AND (ALERTACRITICA = 'R')
             AND (ROWNUM        = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            BEGIN
              SELECT ALERTACRITICA
                INTO vvTipoCriticaProd
                FROM PCMED_VALIDACAO_GERAL_TROCA
               WHERE (NUMPED        = pi_nNumPed)
                 AND (CODPROD       = vrDadosItens.CODPROD)
                 AND (NUMSEQ        = vrDadosItens.NUMSEQ)
                 AND (ALERTACRITICA = 'A')
                 AND (ROWNUM        = 1);
            EXCEPTION  
              WHEN NO_DATA_FOUND THEN
                vvTipoCriticaProd := NULL;
            END;
        END;
        
        -- Insere na Tabela Temporária
        INSERT INTO PCMED_VALIDACAO_PRECO_TROCA
                  ( NUMPED            
                  , CODPROD           
                  , NUMSEQ            
                  , DESCRICAOPROD     
                  , CODPROMOCAOMED    
                  , DESCRICAOPROMO    
                  , OLD_PTABELA       
                  , NEW_PTABELA       
                  , OLD_PERDESC       
                  , NEW_PERDESC       
                  , OLD_PVENDA        
                  , NEW_PVENDA        
                  , OLD_ST            
                  , NEW_ST            
                  , OLD_VLFECP        
                  , NEW_VLFECP        
                  , OLD_VLREPASSE     
                  , NEW_VLREPASSE     
                  , ALERTACRITICA )          
           VALUES ( pi_nNumPed
                  , vrDadosItens.CODPROD           
                  , vrDadosItens.NUMSEQ            
                  , SUBSTR(vDESCRICAO,1,80)
                  , vrDadosItens.CODPROMOCAOMED    
                  , SUBSTR(vDESCRICAORESUMIDA,1,40)
                  , vrDadosItens.OLD_PTABELA       
                  , vrDadosItens.NEW_PTABELA       
                  , vrDadosItens.OLD_PERDESC       
                  , vrDadosItens.NEW_PERDESC       
                  , vrDadosItens.OLD_PVENDA        
                  , vrDadosItens.NEW_PVENDA        
                  , vrDadosItens.OLD_ST            
                  , vrDadosItens.NEW_ST            
                  , vrDadosItens.OLD_VLFECP        
                  , vrDadosItens.NEW_VLFECP        
                  , vrDadosItens.OLD_VLREPASSE     
                  , vrDadosItens.NEW_VLREPASSE     
                  , vvTipoCriticaProd );       
                            
      END LOOP;
    END IF;
          
  END P_VALIDAR_TROCA_CLIPROD;                                    
                            
 /*******************************************************************************
  Nome         : P_VALIDAR_TROCA_CLIENTE
  Descricão    : Procedimento para Validar Troca do Cliente
  ********************************************************************************/   
  PROCEDURE P_VALIDAR_TROCA_CLIENTE(pi_vOrigemChamada       IN VARCHAR2,
                                    pi_nMatricula           IN NUMBER,
                                    pi_nNumPed              IN NUMBER,
                                    pi_nCodCli              IN NUMBER,
                                    pi_nCodPlPag            IN NUMBER,
                                    pi_nCodPlPagEtico       IN NUMBER,
                                    pi_nCodPlPagGenerico    IN NUMBER,
                                    pi_vCodCob              IN VARCHAR2,
                                    pi_nCodPromocaoMed      IN NUMBER,
                                    pi_nNumRegiao           IN NUMBER,
                                    pi_vCodFilial           IN VARCHAR2,
                                    pi_vCodFilialNf         IN VARCHAR2,
                                    po_vOcorreramAlertas   OUT VARCHAR2,
                                    po_vOcorreramRejeicoes OUT VARCHAR2) IS
    --
    -- Parâmetros 
    TYPE TRecParametros                 IS RECORD(
         vSOMACREDITOCLIPRINCIPAL       PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         vUSABNFLIMITECREDITO           PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         nPEREXCEDELIMCRED              PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         vBLOQPEDLIMCRED                PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         nNUMCASASDECVENDA              NUMBER,                    -- DDMEDICA-1586 
         vVERIFICALIMCREDCODCOBD        PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         vACEITAVENDAAVISTACLIBLOQ      PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         vVALIDALVARAPORTIPOCTLVEN      PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         vVERIFICABLOQUEIOSEFAZ         PCPARAMFILIAL.VALOR%TYPE,  -- DDMEDICA-1586
         vPERMITIRTROCACLIENTEPFCONSIG  PCPARAMFILIAL.VALOR%TYPE   -- DDMEDICA-6874
    );
        /*
         vBLOQUEARPEDIDOSABAIXOVLMINIMO PCFILIAL.BLOQUEARPEDIDOSABAIXOVLMINIMO%TYPE,
         vVLMINVENDABKFILIAL            PCPARAMFILIAL.VALOR%TYPE,
         nVLMINVENDABKFILIAL            NUMBER,
         nVLMINVENDABK                  NUMBER,
         vTIPOVLMINVENDABK              PCCONSUM.TIPOVLMINVENDABK%TYPE,
         vACEITAVENDASEMEST             PCPARAMFILIAL.VALOR%TYPE, -- Precisa de tamanho 2
         vTIPOPRAZOMEDICAMEN            PCPARAMFILIAL.VALOR%TYPE,
         nVLMINVENDABNF                 PCCONSUM.VLMINVENDABNF%TYPE,
         vVLMINVENDABNFFV               PCPARAMFILIAL.VALOR%TYPE,
         nVLMINVENDABNFFV               NUMBER,
         vVALIDAVLMINVENDABALCAO        PCCONSUM.VALIDAVLMINVENDABALCAO%TYPE,
         nVLMINVENDA                    PCCONSUM.VLMINVENDA%TYPE,
         vVLMINVENDA_FILIAL             PCPARAMFILIAL.VALOR%TYPE,
         nVLMINVENDA_FILIAL             NUMBER,
         vVALIDARVLMINVENDAAPOSCORTE    PCCONSUM.VALIDARVLMINVENDAAPOSCORTE%TYPE,
         vVLMINVENDAFV                  PCPARAMFILIAL.VALOR%TYPE,
         nVLMINVENDAFV                  NUMBER,
         vACEITAVENDABLOQ               PCCONSUM.ACEITAVENDABLOQ%TYPE,
         vFIL_ALTERARCOBBKCHAUTOMATICO  PCPARAMFILIAL.VALOR%TYPE,
         vBLOQUEARPEDBONIFIC            PCCONSUM.BLOQUEARPEDBONIFIC%TYPE,
         vGRAVARPEDVENBLOQMED           PCPARAMFILIAL.VALOR%TYPE,
         vLIBERARPEDIDOPENDENTE         PCCONSUM.LIBERARPEDIDOPENDENTE%TYPE,
         vUTILIZAVENDAPOREMBALAGEM      PCCONSUM.UTILIZAVENDAPOREMBALAGEM%TYPE,
         vACEITAVENDARCASEMSALDOFV      PCPARAMFILIAL.VALOR%TYPE,
         vUSACREDRCA                    PCCONSUM.USACREDRCA%TYPE,
         vTROCAALTDEBCREDRCA            PCCONSUM.TROCAALTDEBCREDRCA%TYPE,
         vCRMALTDEBCREDRCA              PCCONSUM.CRMALTDEBCREDRCA%TYPE,
         vTIPOMOVCCRCA                  PCCONSUM.TIPOMOVCCRCA%TYPE,
         vVALIDARSALDORCAPORITEM        PCPARAMFILIAL.VALOR%TYPE,
         nPERCRATEIOCREDRCASUPERVISOR   NUMBER, -- DDMEDICA-834
         vVALIDARQTCONTGRAVACAOPED      PCPARAMFILIAL.VALOR%TYPE,
         vCON_VERIFICAESTOQUECONT       PCPARAMFILIAL.VALOR%TYPE,
         );
         */
    vrParametros                        TRecParametros;      
    --                                   
    TYPE TRecValoresValidacao           IS RECORD(
         vRejeitado                     VARCHAR2(1),
         vGravarComoBloqueado           VARCHAR2(1),
         vDescricaoRejeicao             VARCHAR2(255),
         vMotivoPosicao                 VARCHAR2(255),
         vObservacao                    VARCHAR2(32000),
         vLogRetorno                    VARCHAR2(32000));
    vrValoresValidacao                  TRecValoresValidacao;
    --
    nOldCODCLI                          PCPEDC.CODCLI%TYPE;
    nOldCODPLPAG                        PCPEDC.CODPLPAG%TYPE;
    nOldCODPLPAGETICO                   PCPEDC.CODPLPAGETICO%TYPE;
    nOldCODPLPAGGENERICO                PCPEDC.CODPLPAGGENERICO%TYPE;
    vOldCODCOB                          PCPEDC.CODCOB%TYPE;
    nOldCODUSUR                         PCPEDC.CODUSUR%TYPE;
    vOldCODFILIAL                       PCPEDC.CODFILIAL%TYPE;
    vOldSULFRAMA                        PCCLIENT.SULFRAMA%TYPE;
    vOldORGAO_PUBLICO                   VARCHAR2(1);
    nOldCODPROMOCAOMED                  PCPEDC.CODPROMOCAOMED%TYPE;
    --
    TYPE TRecCliente                    IS RECORD(
         vnCodAtv1                      PCCLIENT.CODATV1%TYPE,
         vvCondVenda1                   PCCLIENT.CONDVENDA1%TYPE,
         vvTipoFJ                       PCCLIENT.TIPOFJ%TYPE,
         vvSulframa                     PCCLIENT.SULFRAMA%TYPE,
         vvOrgaoPublico                 VARCHAR2(1));
    vrCliente                           TRecCliente;
    --
    vnValorTotalPedido                  NUMBER;
    --   
    vvMsgAux                            VARCHAR2(250);
    --
    TYPE TRecRetornoControleVenda       IS RECORD(
         vvPodeComprarProduto           VARCHAR2(1),
         vvMotivoNaoPodeComprar         VARCHAR2(2000),
         vnQtdeLimite                   NUMBER); 
    vrRetornoControleVenda              TRecRetornoControleVenda;
    --
    vvCartao                            PCCOB.CARTAO%TYPE;
    --
    FUNCTION F_EXISTE_RESTRICAO_ATV(pi_nCodPlPagRestrito IN NUMBER,
                                    pi_nCodAtv1          IN NUMBER) 
    RETURN BOOLEAN IS
      vbRetExisteRestricao BOOLEAN;
      vTipoRestricao       PCPLPAG.TIPORESTRICAO%TYPE;
      viContaRestricao     INTEGER;
    BEGIN
      vbRetExisteRestricao := FALSE;
      BEGIN
        SELECT TIPORESTRICAO
          INTO vTipoRestricao
          FROM PCPLPAG
         WHERE (CODPLPAG = pi_nCodPlPagRestrito);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vTipoRestricao := NULL;
      END;
      IF (vTipoRestricao = 'RA') THEN
        SELECT COUNT(*)
          INTO viContaRestricao
          FROM PCPLPAGRESTRICAO
         WHERE (CODPLPAG     = pi_nCodPlPagRestrito)
           AND (CODRESTRICAO = pi_nCodAtv1);
        IF (NVL(viContaRestricao,0) = 0) THEN
          vbRetExisteRestricao := TRUE;
        END IF;
      END IF;
      RETURN vbRetExisteRestricao; -->> Retorna se tem Restrição
    END F_EXISTE_RESTRICAO_ATV;
    --
  BEGIN
  
    -- Inicializa Retorno
    po_vOcorreramAlertas   := 'N';
    po_vOcorreramRejeicoes := 'N';
  
    -- Limpa Tabela Temporária
    DELETE FROM PCMED_VALIDACAO_GERAL_TROCA;
    
    -- Pesquisa Dados Originais do Pedido
    BEGIN
      SELECT PCPEDC.CODCLI
           , PCPEDC.CODPLPAG
           , PCPEDC.CODPLPAGETICO
           , PCPEDC.CODPLPAGGENERICO
           , PCPEDC.CODCOB
           , PCPEDC.CODUSUR
           , PCPEDC.CODFILIAL
           , PCCLIENT.SULFRAMA
           , CASE WHEN (NVL(PCCLIENT.ORGAOPUBFEDERAL,'N' ) = 'S')  OR
                       (NVL(PCCLIENT.ORGAOPUBMUNICIPAL,'N') = 'S') OR
                       (NVL(PCCLIENT.ORGAOPUB,'N') = 'S')          THEN
               'S'        
             ELSE
               'N'
             END ORGAO_PUBLICO
           , PCPEDC.CODPROMOCAOMED
        INTO nOldCODCLI
           , nOldCODPLPAG
           , nOldCODPLPAGETICO
           , nOldCODPLPAGGENERICO
           , vOldCODCOB
           , nOldCODUSUR
           , vOldCODFILIAL
           , vOldSULFRAMA
           , vOldORGAO_PUBLICO
           , nOldCODPROMOCAOMED
        FROM PCPEDC 
           , PCCLIENT
       WHERE (PCPEDC.NUMPED   = pi_nNumPed)
         AND (PCCLIENT.CODCLI = PCPEDC.CODCLI);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        nOldCODCLI           := NULL;
        nOldCODPLPAG         := NULL;
        nOldCODPLPAGETICO    := NULL;
        nOldCODPLPAGGENERICO := NULL;
        vOldCODCOB           := NULL;
        nOldCODUSUR          := NULL;
        vOldCODFILIAL        := NULL;
        vOldSULFRAMA         := NULL;
        vOldORGAO_PUBLICO    := NULL;
        nOldCODPROMOCAOMED   := NULL;
    END;
    
    -- Pesquisa Parâmetros
    P_OBTER_PARAMETROS(vOldCODFILIAL,
                       vrParametros.vSOMACREDITOCLIPRINCIPAL,
                       vrParametros.vUSABNFLIMITECREDITO,
                       vrParametros.nPEREXCEDELIMCRED,
                       vrParametros.vVERIFICALIMCREDCODCOBD,
                       vrParametros.vACEITAVENDAAVISTACLIBLOQ,
                       vrParametros.vBLOQPEDLIMCRED,
                       vrParametros.nNUMCASASDECVENDA,
                       vrParametros.vVALIDALVARAPORTIPOCTLVEN,
                       vrParametros.vVERIFICABLOQUEIOSEFAZ,
                       vrParametros.vPERMITIRTROCACLIENTEPFCONSIG);
                                   
    -- Pesquisa dados do Novo Cliente
    BEGIN
      SELECT PCCLIENT.CODATV1
           , PCCLIENT.CONDVENDA1
           , PCCLIENT.TIPOFJ
           , PCCLIENT.SULFRAMA
           , CASE WHEN (NVL(PCCLIENT.ORGAOPUBFEDERAL,'N' ) = 'S')  OR
                       (NVL(PCCLIENT.ORGAOPUBMUNICIPAL,'N') = 'S') OR
                       (NVL(PCCLIENT.ORGAOPUB,'N') = 'S')          THEN
               'S'        
             ELSE
               'N'
             END ORGAO_PUBLICO           
        INTO vrCliente.vnCodAtv1
           , vrCliente.vvCondVenda1
           , vrCliente.vvTipoFJ
           , vrCliente.vvSulframa
           , vrCliente.vvOrgaoPublico
        FROM PCCLIENT
       WHERE (CODCLI = pi_nCodCli);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrCliente.vnCodAtv1      := NULL;
        vrCliente.vvCondVenda1   := NULL;
        vrCliente.vvTipoFJ       := NULL;
        vrCliente.vvSulframa     := NULL;
        vrCliente.vvOrgaoPublico := NULL;
    END;
        
    -- Calcula o Valor Total do Pedido
    SELECT SUM(PVENDA*QT) 
      INTO vnValorTotalPedido
      FROM PCPEDI
     WHERE (NUMPED = pi_nNumPed); 
    
    -----------------------------------------------------------------------------------------------
    -- Chamado da Alteração do Cliente
    ------------------------------------- 
    IF    (pi_vOrigemChamada = 'CL') THEN

      -- Permissão para Vender TV1 ----------------------------------------------------------------
      IF (F_MANTEM_CRITICAS_PESSOAFISICA(pi_nMatricula, vrParametros.vPERMITIRTROCACLIENTEPFCONSIG)) THEN -- DDMEDICA-6874
        IF (NVL(vrCliente.vvCondVenda1,'N') <> 'S') THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Permissão para Venda Tipo 1',
                           '308',
                           'Pedido de Venda (Tipo 1) não está liberado para este Cliente',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
      END IF;
    
      -- Alerta de Limite de Crédito --------------------------------------------------------------
      BEGIN -- DDMEDICA-3743
        SELECT NVL(PCCOB.CARTAO,'N')
          INTO vvCartao
          FROM PCCOB 
         WHERE (PCCOB.CODCOB = pi_vCodCob);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvCartao := 'N';
      END;
      IF (NVL(vrParametros.vVERIFICALIMCREDCODCOBD,'N') = 'N') AND 
         ((NVL(pi_vCodCob,'BK') IN ('D','DH')) OR
          (NVL(vvCartao,'N') = 'S')) THEN
      
        NULL; -->> DDMEDICA-3743 - Não faz Validação de Limite de Crédito se "Verificar limite de credito do cliente ao incluir pedido nas cobranças "D", "DH" e "CAR"" = Não
          
      ELSE
      
        P_BLOQUEIO_LIMCRED(pi_nMatricula,
                           2316, -->> A troca só ocorre na 2316
                           pi_nNumPed,
                           pi_nCodCli,
                           nOldCODUSUR,
                           NVL(vnValorTotalPedido,0),
                           vrParametros.vSOMACREDITOCLIPRINCIPAL,
                           vrParametros.vUSABNFLIMITECREDITO,
                           vrParametros.nPEREXCEDELIMCRED,
                           vrParametros.vBLOQPEDLIMCRED,
                           vrParametros.nNUMCASASDECVENDA,
                           NULL, -- pi_vChamadaProcesso
                           NULL, -- pi_vPosicaoFinalPedido
                           vrValoresValidacao.vRejeitado,
                           vrValoresValidacao.vGravarComoBloqueado,
                           vrValoresValidacao.vDescricaoRejeicao,
                           vrValoresValidacao.vMotivoPosicao,
                           vrValoresValidacao.vObservacao,
                           vrValoresValidacao.vLogRetorno);
        IF (vrValoresValidacao.vRejeitado = 'S') THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Limite de Crédito do Cliente',
                           '1203',
                           vrValoresValidacao.vObservacao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
        
      END IF;

      -- Alerta de Alvará --------------------------------------------------------------
      P_VALIDA_CONTROLE_VENDA('P', -->> Chamada de Validação ao abrir o Pedido
                              pi_nCodCli,
                              vrCliente.vvTipoFJ,
                              0,   -->> Ao abrir o Pedido não passa o Produto
                              0,   -->> Ao abrir o Pedido não passa a Qtde. Vendida 
                              0,   -->> Ao abrir o Pedido não passa o NUMPED
                              0,   -->> Ao abrir o Pedido não passa o NUMSEQ
                              vrRetornoControleVenda.vvPodeComprarProduto,
                              vrRetornoControleVenda.vvMotivoNaoPodeComprar,
                              vrRetornoControleVenda.vnQtdeLimite);
      IF (vrRetornoControleVenda.vvPodeComprarProduto = 'N') THEN
        IF (NVL(vrParametros.vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') THEN
         vvMsgAux := '3331';
        ELSE
         vvMsgAux := '302';
        END IF;
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Alvará',
                         vvMsgAux, -->> Código da Rotina conforme Parâmetro
                         vrRetornoControleVenda.vvMotivoNaoPodeComprar,
                         'R',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);      
      END IF;

      -- Alerta de Venda para Cliente 1, 2 e 3 ----------------------------------------------------
      IF (pi_nCodCli IN (1,2,3)) THEN
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Cliente não permitido',
                         NULL,
                         'Cliente ' || pi_nCodCli || ' não permitido neste tipo de venda',
                         'R',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);
      END IF;
      
      -- Alerta de Inadimplência ------------------------------------------------------------------
      IF (F_RESTRICAO_INADIMPLENCIA(pi_nCodCli,
                                    vvMsgAux)) THEN
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Inadimplência',
                         132,
                         vvMsgAux,
                         'R',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);
      END IF; 
      
      -- Alerta de SUFRAMA ------------------------------------------------------------------------
      IF (F_MANTEM_CRITICAS_PESSOAFISICA(pi_nMatricula, vrParametros.vPERMITIRTROCACLIENTEPFCONSIG)) THEN -- DDMEDICA-6874
        IF (NVL(vrCliente.vvSulframa,'X') <> NVL(vOldSULFRAMA,'X')) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'SUFRAMA',
                           302,
                           'Cadastro de SUFRAMA diferente do Cliente original do Pedido',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF; 
      END IF;

      -- Alerta de ORGÃO PÚBLICO ------------------------------------------------------------------
      IF (F_MANTEM_CRITICAS_PESSOAFISICA(pi_nMatricula, vrParametros.vPERMITIRTROCACLIENTEPFCONSIG)) THEN -- DDMEDICA-6874
        IF (NVL(vrCliente.vvOrgaoPublico,'X') <> NVL(vOldORGAO_PUBLICO,'X')) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Órgão Público',
                           302,
                           'Cadastro de Órgão Público diferente do Cliente original do Pedido',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;       
      END IF;       
      
      -- Alerta de Cliente Bloqueado --------------------------------------------------------------
      IF (F_BLOQUEIO_CLIENTE(pi_nCodCli,
                             pi_vCodCob,
                             vrParametros.vVERIFICALIMCREDCODCOBD,
                             vrParametros.vACEITAVENDAAVISTACLIBLOQ,
                             vrValoresValidacao.vObservacao,
                             vrValoresValidacao.vMotivoPosicao)) THEN           
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Cliente Bloqueado',
                         1203,
                         vrValoresValidacao.vObservacao,
                         'R',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);
      END IF;
                              
      -- Alerta de Pessoa Fisica ------------------------------------------------------------------
      IF (F_MANTEM_CRITICAS_PESSOAFISICA(pi_nMatricula, vrParametros.vPERMITIRTROCACLIENTEPFCONSIG)) THEN -- DDMEDICA-6874
        IF (NVL(vrCliente.vvTipoFj,'X') = 'F') THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Pessoa Fisica',
                           302,
                           'Cliente Pessoa Fisica não permitido neste tipo de venda',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;       
      END IF;       
      
      -- Alerta de Bloqueio SEFAZ -----------------------------------------------------------------
      IF (F_BLOQUEIO_SEFAZ(pi_nCodCli,
                           vrValoresValidacao.vObservacao,
                           vrValoresValidacao.vMotivoPosicao)) THEN           
        IF (NVL(vrParametros.vVERIFICABLOQUEIOSEFAZ,'N') = 'S') THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           vrValoresValidacao.vMotivoPosicao,
                           NULL,
                           vrValoresValidacao.vObservacao,
                           'A',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        ELSE
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           vrValoresValidacao.vMotivoPosicao,
                           NULL,
                           vrValoresValidacao.vObservacao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
      END IF;

      -- Alerta de Troca de Cliente -----------------------------------------------------------------
      IF (F_REGIAO_INATIVA(pi_nNumRegiao,
                           vrValoresValidacao.vObservacao)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Região Inativa',
                           519,
                           vrValoresValidacao.vObservacao,
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);      
      END IF;
      
    -----------------------------------------------------------------------------------------------
    -- Chamado da Alteração da Cobrança
    ------------------------------------- 
    ELSIF (pi_vOrigemChamada = 'CB') THEN
    
      -- Alerta de Troca de Cobrança --------------------------------------------------------------
      IF (NVL(vOldCODCOB,'X') <> NVL(pi_vCodCob,'X')) THEN
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Alteração da Cobrança',
                         NULL,
                         'Alteração da Cobrança "' || vOldCODCOB || '" para "' || pi_vCodCob || '"',
                         'A',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);
      END IF;

    -----------------------------------------------------------------------------------------------
    -- Chamado da Alteração do Plano
    ------------------------------------- 
    ELSIF (pi_vOrigemChamada = 'PL') THEN
    
      -- Alteração de Plano -----------------------------------------------------------------------
      IF (NVL(nOldCODPLPAG,0) <> NVL(pi_nCodPlPag,0)) OR
         (NVL(nOldCODPLPAGETICO,0) <> NVL(pi_nCodPlPagEtico,0)) OR
         (NVL(nOldCODPLPAGGENERICO,0) <> NVL(pi_nCodPlPagGenerico,0)) THEN
        --
        IF ((NVL(nOldCODPLPAGETICO,0) > 0) AND (NVL(nOldCODPLPAGGENERICO,0) > 0)) THEN
          vvMsgAux := 'Alteração do Plano Ético "' || nOldCODPLPAGETICO || '" e Genérico "' || nOldCODPLPAGGENERICO || '" para';
        ELSE
          vvMsgAux := 'Alteração do Plano "' || nOldCODPLPAG || '" para';
        END IF;
        --
        IF ((NVL(pi_nCodPlPagEtico,0) > 0) AND (NVL(pi_nCodPlPagGenerico,0) > 0)) THEN
          vvMsgAux := vvMsgAux || ' o Plano Ético "' || pi_nCodPlPagEtico || '" e Genérico "' || pi_nCodPlPagGenerico || '"';
        ELSE
          vvMsgAux := vvMsgAux || ' o Plano "' || pi_nCodPlPag || '"';
        END IF;
        --
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Alteração do Plano de Pagamento',
                         NULL,
                         vvMsgAux,
                         'A',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);
        --
      END IF;
      
      -- Validação do Ramo de Atividade -----------------------------------------------------------
      IF ((NVL(pi_nCodPlPagEtico,0) > 0) AND (NVL(pi_nCodPlPagGenerico,0) > 0)) THEN
        IF (F_EXISTE_RESTRICAO_ATV(pi_nCodPlPagEtico, vrCliente.vnCodAtv1)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Restrição de Plano de Pagamento',
                           NULL,
                           'Plano de Pagamento Ético "' || pi_nCodPlPagEtico || ' com restrição por ramo de atividade',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
        IF (F_EXISTE_RESTRICAO_ATV(pi_nCodPlPagGenerico, vrCliente.vnCodAtv1)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Restrição de Plano de Pagamento',
                           NULL,
                           'Plano de Pagamento Ético "' || pi_nCodPlPagGenerico || ' com restrição por ramo de atividade',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
      ELSE
        IF (F_EXISTE_RESTRICAO_ATV(pi_nCodPlPag, vrCliente.vnCodAtv1)) THEN
          P_INSERE_TABTEMP(pi_nNumPed,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           NULL,
                           'Restrição de Plano de Pagamento',
                           NULL,
                           'Plano de Pagamento "' || pi_nCodPlPag || ' com restrição por ramo de atividade',
                           'R',
                           po_vOcorreramAlertas,
                           po_vOcorreramRejeicoes);
        END IF;
      END IF;
      
    -----------------------------------------------------------------------------------------------
    -- Chamado da Alteração da Promoção
    ------------------------------------- 
    ELSIF (pi_vOrigemChamada = 'PM') THEN

      -- Alerta de Troca de Promoção --------------------------------------------------------------
      IF (NVL(nOldCODPROMOCAOMED,0) <> NVL(pi_nCodPromocaoMed,0)) THEN
        P_INSERE_TABTEMP(pi_nNumPed,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         NULL,
                         'Alteração da Promoção Principal',
                         NULL,
                         'Alteração da Promoção "' || nOldCODPROMOCAOMED || '" para "' || pi_nCodPromocaoMed || '"',
                         'A',
                         po_vOcorreramAlertas,
                         po_vOcorreramRejeicoes);
      END IF;
      
    END IF;
    
  END P_VALIDAR_TROCA_CLIENTE;

 /***********************************************************************************************
  FUNÇÃO...: F_VALIDARESTRICAOVENDAFIL
  DESCRIÇÃO: Validar Cadastro de Restrições de Venda por Filial - DDMEDICA-3464
  ***********************************************************************************************/
  FUNCTION F_VALIDARESTRICAOVENDAFIL(pi_vCodFilial        IN VARCHAR2,
                                     pi_vOrigemPed        IN VARCHAR2,
                                     pi_vTipoFv           IN VARCHAR2,
                                     pi_nVlAtend          IN NUMBER,
                                     pi_nCodCondicaoVenda IN NUMBER,
                                     pi_nCondVenda        IN NUMBER,
                                     po_vMotivoRejeitado  OUT VARCHAR2,
                                     pi_nCodCli           IN NUMBER,
                                     pi_nCodUsur          IN NUMBER, 
                                     pi_nCodPlPag         IN NUMBER,
                                     pi_vCodCob           IN VARCHAR2,
                                     pi_nCodSupervisor    IN NUMBER,
                                     pi_nCodAtv1          IN NUMBER,
                                     pi_vTipoFj           IN VARCHAR2,
                                     pi_nCodPraca         IN NUMBER,
                                     pi_nNumRegiao        IN NUMBER)
  RETURN BOOLEAN IS

    -- Variáveis
    vnCodRestricao             PCRESTRICAOVENDA.CODRESTRICAO%TYPE;
    vvMotivoRestricao          VARCHAR2(32000);
    vstipovalorminimo          PCCONDICAOVENDA.TIPOVALORMINIMO%TYPE;
    vbValido                   BOOLEAN;
    vvOrientacaoCondicaoNaoCad VARCHAR2(32000);

  BEGIN

    -- Inicializa Código e Motivo da Restrição
    vnCodRestricao    := NULL;
    vvMotivoRestricao := NULL;
    
    -- Pesquisa o Tipo de Valor Mínimo da Condição de Venda
    vstipovalorminimo := 'P';
    IF (NVL(pi_nCodCondicaoVenda,0) > 0) AND 
       (NVL(pi_vTipoFv,'FV') IN ('OL','PE')) THEN
      BEGIN
        SELECT NVL(PCCONDICAOVENDA.TIPOVALORMINIMO,'P')
          INTO vstipovalorminimo
          FROM PCCONDICAOVENDA
         WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA = pi_nCodCondicaoVenda);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vstipovalorminimo := 'P';
      END;
    END IF;
        
    -- Verifica Restrições por Valor Mínimo, somente se não for pelo Mínimo da 2311
    IF (NVL(vnCodRestricao,0) = 0) AND
       (NVL(vstipovalorminimo,'P') = 'P') THEN
    
      -----------------------------------------------------------------------
      -- Laço de Restrições por Filial COM Valor Mínimo (Validação Pós Corte)
      -----------------------------------------------------------------------
      FOR vc_Restricao IN (SELECT p.codrestricao 
                                , p.motivo
                                , p.valorminimovenda
                             from pcrestricaovenda p
                            where ((p.codfilial = pi_vCodFilial) OR (codfilial IS NULL))
                            and   ((codcli = pi_nCodCli) OR (codcli IS NULL))
                            and   p.codprod is null
                            and   ((numregiao = pi_nNumRegiao) or (numregiao IS NULL))
                            --
                            and   p.codfornec is null
                            and   ((p.codpraca = pi_nCodPraca) OR (p.codpraca is null))
                            and   ((codusur = pi_nCodUsur) OR (codusur IS NULL))
                            and   ((codativ = pi_nCodAtv1) OR (codativ IS NULL))
                            and   p.classeproduto is null
                            and   p.codepto is null
                            and   p.codsec is null
                            and   ((codsupervisor = pi_nCodSupervisor) OR (codsupervisor IS NULL))
                            and   ((tipofj = pi_vTipoFj) OR (tipofj IS NULL))
                            and   ((NVL(p.origemped,'O') = 'O') or (NVL(p.origemped,'O') = pi_vOrigemPed))
                            --DDMEDICA-7523
                            and   ((p.condvenda is null) or (p.condvenda = pi_nCondVenda))
                            and   (p.fretedespacho is null or p.fretedespacho = 'T')
                            and   ((codplpag = pi_nCodPlPag) OR (codplpag is null))
                            and   ((codcob = pi_vCodCob) OR (codcob is null))
                            and   p.codmarca is null
                            and   (NVL(p.valorminimovenda,0) > 0)  -->> Com Valor Mínimo
                            and   (p.valorminimovenda > pi_nVlAtend)) LOOP
                                    
        -- Código da Restrição
        vnCodRestricao := vc_Restricao.codrestricao;
  
          -- Motivo da Restrição
        IF (vc_Restricao.motivo IS NULL) THEN
          vvMotivoRestricao := SUBSTR('Restrição "' || vnCodRestricao || '" por valor atendido do pedido ' || F_FORMATAR_NUMERO_PARA_TEXTO(pi_nVlAtend,2) || ' abaixo do valor mínimo ' || F_FORMATAR_NUMERO_PARA_TEXTO(vc_Restricao.valorminimovenda,2),1,255);
        ELSE
          vvMotivoRestricao := SUBSTR('Restrição "' || vnCodRestricao || '" por valor atendido do pedido ' || F_FORMATAR_NUMERO_PARA_TEXTO(pi_nVlAtend,2) || ' por valor mínimo ' || F_FORMATAR_NUMERO_PARA_TEXTO(vc_Restricao.valorminimovenda,2) || ' (' || vc_Restricao.motivo || ')',1,255);
        END IF;

        -->> Sai ao achar a primeira restrição VÁLIDA
        EXIT;
  
      END LOOP;
    
    END IF;

    -- Se Rejeitou
    IF (NVL(vnCodRestricao,0) > 0) THEN

      po_vMotivoRejeitado := vvMotivoRestricao;
                                             
    END IF;
    
    -- Atualiza Retorno
    RETURN (NVL(vnCodRestricao,0) > 0);

  END F_VALIDARESTRICAOVENDAFIL;

 /*********************************************************************
  FUNÇÃO   : F_RETORNAR_PLPAG_ITEM
  DESCRIÇÃO: Retorna o Plano de Pagamento do Item
  *********************************************************************/
  FUNCTION F_RETORNAR_PLPAG_ITEM(pi_vTipoPrazoMedicamen IN VARCHAR2,
                                 pi_nCodProd            IN NUMBER,
                                 pi_nCodPlPag_PCPEDI    IN NUMBER,
                                 pi_nCodPlPag_PCPEDC    IN NUMBER,
                                 pi_nCodPlPag_ETICO     IN NUMBER,
                                 pi_nCodPlPag_GENERICO  IN NUMBER,
                                 pi_vGrupoFaturamento   IN VARCHAR2) 
  RETURN NUMBER IS
  
    -- Retorno da Função
    vnRetCodPlPag      PCPLPAG.CODPLPAG%TYPE;
    -- Grupo Faturamento
    vvGrupoFaturamento PCPRODUT.GRUPOFATURAMENTO%TYPE;
    
  BEGIN

    -- Inicializa Plano de Pagamento Por Linha de Prazo
    IF (NVL(pi_vTipoPrazoMedicamen,'2') = '4') THEN
    
       -- Pega Plano de Pagamento do Item
       vnRetCodPlPag := pi_nCodPlPag_PCPEDI;
       -- Se não gravou no item Pega no Pedido
       IF (NVL(vnRetCodPlPag,0) = 0) THEN
         vnRetCodPlPag := pi_nCodPlPag_PCPEDC;
       END IF;
       
    ELSE
    
      -- Inicializa Plano de Pagamento Por Grupo de Faturamento
      IF (NVL(pi_nCodPlPag_ETICO,0)    > 0) AND
         (NVL(pi_nCodPlPag_GENERICO,0) > 0) THEN
         
        -- Pega Grupo de Faturamento do Parâmetro
        vvGrupoFaturamento := pi_vGrupoFaturamento;

        -- Se o Grupo Faturamento passado no parâmetro estava nulo no item do pedido, busca do produto
        IF (vvGrupoFaturamento IS NULL) THEN
          BEGIN
            SELECT GRUPOFATURAMENTO
              INTO vvGrupoFaturamento
              FROM PCPRODUT
             WHERE (CODPROD = pi_nCodProd);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvGrupoFaturamento := NULL;
          END;
        END IF; 
        
        -- Pega Plano de Pagamento Ético
        IF (NVL(vvGrupoFaturamento,' ') = 'E') THEN
          vnRetCodPlPag := pi_nCodPlPag_ETICO;
        -- Pega Plano de Pagamento Genérico/Similar
        ELSE
          vnRetCodPlPag := pi_nCodPlPag_GENERICO;
        END IF;
        
      -- Inicializa Plano de Pagamento Por Pedido
      ELSE
      
        -- Pega Plano de Pagamento do Pedido
        vnRetCodPlPag := pi_nCodPlPag_PCPEDC;
        
      END IF;
      
    END IF;  
    
    -- Retorno da Função
    RETURN vnRetCodPlPag;
     
  END F_RETORNAR_PLPAG_ITEM;

 /*********************************************************************
  FUNÇÃO   : F_MED_MIX_PROMOCAO
  DESCRIÇÃO: Retorna se o Produto faz parte do Mix da Promoção
  *********************************************************************/
  FUNCTION F_MED_MIX_PROMOCAO(pi_nCodPromocaoMed IN NUMBER,
                              pi_nCodProd        IN NUMBER,
                              pi_nCodCli         IN NUMBER,
                              pi_nCodUsur        IN NUMBER)
  RETURN VARCHAR2 IS
    
    vvRetMixPromocao VARCHAR2(1);
    
    vvAchouProduto    VARCHAR2(1);
    vncodfornec       NUMBER;
    vncodepto         NUMBER;
    vncodsec          NUMBER;
    vncodcategoria    NUMBER;
    vncodsubcategoria NUMBER;
    vncodmarca        pcprodut.codmarca%type;
    vncodlinhaprod    pcprodut.codlinhaprod%type;
    vncodprodprinc    pcprodut.codprodprinc%type;
    
  BEGIN
   
    -- Inicializa Retorno
    vvRetMixPromocao := 'N';
    
    -- Buscar dados do produto
    BEGIN
      SELECT 'S',
             CODFORNEC,
             CODEPTO,
             CODSEC,
             CODCATEGORIA,
             CODSUBCATEGORIA,
             CODMARCA,
             CODLINHAPROD,
             CODPRODPRINC
        INTO vvAchouProduto,
             vncodfornec,
             vncodepto,
             vncodsec,
             vncodcategoria,
             vncodsubcategoria,
             vncodmarca,
             vncodlinhaprod,
             vncodprodprinc
        FROM PCPRODUT
       WHERE (CODPROD = pi_nCodProd);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvAchouProduto := 'N';
    END;  
    
    -- Pesquisa se o Produto faz parte do Mix da Promoção para o dia atual
    FOR vc_Promocao IN ( SELECT percdesc,
                                nvl(percdescfin,0) percdescfin,
                                coddesconto
                           FROM pcdesconto
                          WHERE (codpromocaomed = pi_nCodPromocaoMed) -->> Promoção selecionada no Item do Pedido
                            AND ((codepto = vncodepto) OR (codepto IS NULL))
                            AND ((codsec = vncodsec) OR (codsec IS NULL))
                            AND ((codcategoria = vncodcategoria) OR (codcategoria IS NULL))
                            AND ((codprod = pi_nCodProd) OR (codprod IS NULL))
                            AND ((codfornec = vncodfornec) OR (codfornec IS NULL))
                            AND ((codprodprinc = vncodprodprinc) OR (codprodprinc IS NULL))
                            AND ((pcdesconto.codmarca  = vncodmarca) or (pcdesconto.codmarca is null))
                            AND ((pcdesconto.codlinhaprod  = vncodlinhaprod) or (pcdesconto.codlinhaprod is null))
                            -- HIS.01889.2017
                            AND ((PCDESCONTO.TIPOGRUPOREST IS NULL) OR
                                 (PCDESCONTO.CODGRUPOREST  = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                                                FROM PCGRUPOSCAMPANHAI
                                                               WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                                                 AND PCGRUPOSCAMPANHAI.CODGRUPO = PCDESCONTO.CODGRUPOREST
                                                                 AND PCGRUPOSCAMPANHAI.CODITEM  = DECODE(PCDESCONTO.TIPOGRUPOREST,'CL',pi_nCodCli,
                                                                                                                                  'GR',pi_nCodUsur,
                                                                                                                                  'GP',pi_nCodProd)))) ) LOOP
      vvRetMixPromocao := 'S';
      EXIT;      
    END LOOP; 
    
    -- Retorno da Função
    RETURN vvRetMixPromocao;                                                                                                                                
  
  END F_MED_MIX_PROMOCAO;

 /*****************************************************************************
  FUNÇÃO    : F_MED_VERBA_PROMOCAO
  DESCRIÇÃO : Retorna se o Produto tem Cota de Verba Suficiente - DDMEDICA-5009
  OBSERVAÇÃO: O primeiro caracter do retorno poderá ser:
              S - Verba Permitida (Sim)
              A - Verba não permitida gerando um alerta (gravará como bloqueado o pedido)
              R - Verba não permitida gerando uma rejeição (não deixará liberar o pedido)
  ****************************************************************************/
  FUNCTION F_MED_VERBA_PROMOCAO(pi_nNumPed           IN NUMBER,
                                pi_nCodPromocaoMed   IN NUMBER,
                                pi_nNumVerbaCampanha IN NUMBER,
                                po_nCodMotivo        OUT NUMBER,
                                po_vDescricaoMotivo  OUT VARCHAR2)
  RETURN VARCHAR2 IS
    
    vvRetVerbaPromocao             VARCHAR2(255);
    
    vdDtEmissaoVerba               PCVERBA.DTEMISSAO%TYPE;
    vdDtVencVerba                  PCVERBA.DTVENC%TYPE;
    vdDtApuracaoVerba              PCVERBA.DTAPURACAO%TYPE;
    vvAchouVerba                   VARCHAR2(1);
    
    vnCotaVerbaPromocao            NUMBER;
    vvAchouVerbaPromocao           VARCHAR2(1);
    
    vnTotalGeralVerbaUsadaPromocao NUMBER;
    vnTotalPedVerbaUsadaPromocao   NUMBER;
    vnValorExcedidoCota            NUMBER;
    vnTotalGeralVerbaDevolPromocao NUMBER;
        
  BEGIN
   
    -- Inicializa Retorno
    vvRetVerbaPromocao := 'S';
    
    -- Pesquisa a Data Inicial da Verba
    BEGIN
      SELECT PCVERBA.DTEMISSAO
           , PCVERBA.DTVENC
           , PCVERBA.DTAPURACAO
           , 'S'
        INTO vdDtEmissaoVerba
           , vdDtVencVerba
           , vdDtApuracaoVerba
           , vvAchouVerba
        FROM PCVERBA
       WHERE (PCVERBA.NUMVERBA = pi_nNumVerbaCampanha);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vdDtEmissaoVerba  := NULL;
        vdDtVencVerba     := NULL;
        vdDtApuracaoVerba := NULL;
        vvAchouVerba      := 'N';
    END;
    
    -- Se a Verba já foi Apurada
    IF (vdDtApuracaoVerba IS NOT NULL) THEN
     
      vvRetVerbaPromocao  := 'A-Verba já foi Apurada.';
      po_nCodMotivo       := 30;
      po_vDescricaoMotivo := 'Verba da Promoção já foi Apurada';
    
    -- Se a Verba não foi Apurada
    ELSE
    
      -- Pesquisa a Cota da Verba na Promoção
      BEGIN
        SELECT PCPROMOCAOVERBAMED.VALORCOTA
             , 'S'
          INTO vnCotaVerbaPromocao
             , vvAchouVerbaPromocao
          FROM PCPROMOCAOVERBAMED
         WHERE (PCPROMOCAOVERBAMED.CODPROMOCAOMED = pi_nCodPromocaoMed)
           AND (PCPROMOCAOVERBAMED.NUMVERBA       = pi_nNumVerbaCampanha);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCotaVerbaPromocao  := 0;
          vvAchouVerbaPromocao := 'N';
      END;
      
      -- Se não achou a Verba
      IF    (NVL(vvAchouVerba,'N') = 'N') THEN
      
        vvRetVerbaPromocao  := 'A-Verba não cadastrada';
        po_nCodMotivo       := 29;
        po_vDescricaoMotivo := 'Cota de Verba da Promoção Excedida';
        
      ELSIF (NVL(vvAchouVerbaPromocao,'N') = 'N') THEN
        
        vvRetVerbaPromocao  := 'A-Verba não foi encontrada na Promoção';
        po_nCodMotivo       := 29;
        po_vDescricaoMotivo := 'Cota de Verba da Promoção Excedida';
           
      ELSIF (vdDtEmissaoVerba IS NULL) THEN
  
        vvRetVerbaPromocao  := 'A-Verba sem Data de Emissão';
        po_nCodMotivo       := 29;
        po_vDescricaoMotivo := 'Cota de Verba da Promoção Excedida';
  
      ELSIF (vdDtVencVerba IS NULL) THEN
  
        vvRetVerbaPromocao  := 'A-Verba sem Data de Vencimento';
        po_nCodMotivo       := 29;
        po_vDescricaoMotivo := 'Cota de Verba da Promoção Excedida';
        
      ELSE
      
        -- Se Verba Fora da Vigência
        IF NOT (TRUNC(SYSDATE) BETWEEN vdDtEmissaoVerba AND vdDtVencVerba) THEN
  
          vvRetVerbaPromocao  := 'A-Verba fora da Vigência';
          po_nCodMotivo       := 29;
          po_vDescricaoMotivo := 'Cota de Verba da Promoção Excedida';
        
        ELSE
        
          -- COTA DA VERBA NA PROMOÇÃO
          IF (NVL(vnCotaVerbaPromocao,0) > 0) THEN
      
            -- Verifica o total geral de vendas da Verba + Promoção
            SELECT SUM(NVL(DECODE(NVL(PCPEDI.POSICAO,'L'),'C',0,PCPEDI.QT),0) * NVL(PCPEDI.VLDESCCMVPROMOCAOMED,0))
              INTO vnTotalGeralVerbaUsadaPromocao
              FROM PCPEDI
             WHERE (PCPEDI.DATA            >= vdDtEmissaoVerba)
               AND (PCPEDI.DATA            <= vdDtVencVerba)
               AND (PCPEDI.CODPROMOCAOMED   = pi_nCodPromocaoMed)
               AND (PCPEDI.NUMVERBACAMPANHA = pi_nNumVerbaCampanha);
    
            -- Verifica o total geral de devoluções da Verba + Promoção
            SELECT SUM(NVL(PCMOV.QT,0) * NVL(PCMOVCOMPLE.VLDESCCMVPROMOCAOMED,0))
              INTO vnTotalGeralVerbaDevolPromocao
              FROM PCMOV
                 , PCMOVCOMPLE 
             WHERE (PCMOV.NUMTRANSITEM           = PCMOVCOMPLE.NUMTRANSITEM)
               AND (PCMOV.DTMOV                 >= vdDtEmissaoVerba)
               AND (PCMOV.DTMOV                 <= vdDtVencVerba)
               AND (PCMOV.CODOPER                = 'ED')
               AND (PCMOVCOMPLE.CODPROMOCAOMED   = pi_nCodPromocaoMed)
               AND (PCMOVCOMPLE.NUMVERBACAMPANHA = pi_nNumVerbaCampanha);
            -- Abate as Devoluções
            vnTotalGeralVerbaUsadaPromocao := NVL(vnTotalGeralVerbaUsadaPromocao,0) - NVL(vnTotalGeralVerbaDevolPromocao,0);
            IF (vnTotalGeralVerbaUsadaPromocao < 0) THEN
              vnTotalGeralVerbaUsadaPromocao := 0;
            END IF;
               
            -- Verifica o total do pedido de vendas da Verba + Promoção
            SELECT SUM(NVL(DECODE(NVL(PCPEDI.POSICAO,'L'),'C',0,PCPEDI.QT),0) * NVL(PCPEDI.VLDESCCMVPROMOCAOMED,0))
              INTO vnTotalPedVerbaUsadaPromocao
              FROM PCPEDI
             WHERE (PCPEDI.NUMPED           = pi_nNumPed)
               AND (PCPEDI.CODPROMOCAOMED   = pi_nCodPromocaoMed)
               AND (PCPEDI.NUMVERBACAMPANHA = pi_nNumVerbaCampanha);
               
            -- Se Cota Ultrapassada
            IF (NVL(vnTotalGeralVerbaUsadaPromocao,0) > NVL(vnCotaVerbaPromocao,0)) THEN
            
               vnValorExcedidoCota := (NVL(vnTotalGeralVerbaUsadaPromocao,0) - NVL(vnCotaVerbaPromocao,0));
            
               vvRetVerbaPromocao  := 'A-O valor da Cota de Verba da Promoção ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnCotaVerbaPromocao,2) ||
                                      ' foi excedido em ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnValorExcedidoCota,2) ||
                                      ' somando todas as vendas e o valor total utilizado no Pedido foi ' || F_FORMATAR_NUMERO_PARA_TEXTO(vnTotalPedVerbaUsadaPromocao,2) || '.';
               po_nCodMotivo       := 29;
               po_vDescricaoMotivo := 'Cota de Verba da Promoção Excedida';
            
            END IF;
               
          END IF; -- FIM: COTA DA VERBA NA PROMOÇÃO     
          
        END IF; -- Fim: Se Verba Fora da Vigência
        
      END IF; -- Fim: Problemas Cadastrais da Verba
        
    END IF; -- Fim: Verba já foi Apurada
    
    -- Retorno da Função
    RETURN vvRetVerbaPromocao;                                                                                                                                
  
  END F_MED_VERBA_PROMOCAO;

/*******************************************************************************
  Nome         : P_TROCAR_CLIENTE
  Descricão    : Procedimento para Trocar o Cliente do Pedido
  ********************************************************************************/   
  PROCEDURE P_TROCAR_CLIENTE(pi_nMatricula        IN NUMBER,
                             pi_nNumPed           IN NUMBER,
                             pi_nCodCli           IN NUMBER,
                             pi_nCodPlPag         IN NUMBER,
                             pi_nCodPlPagEtico    IN NUMBER,
                             pi_nCodPlPagGenerico IN NUMBER,
                             pi_vCodCob           IN VARCHAR2,
                             pi_nCodPraca         IN NUMBER,
                             pi_nNumRegiao        IN NUMBER,
                             pi_nCodPromocaoMed   IN NUMBER,
                             po_vTrocouCliente   OUT VARCHAR2,
                             po_vMotivoNaoTrocou OUT VARCHAR2) IS
    --
    vnCodPlPagEtico            PCPEDC.CODPLPAGETICO%TYPE;
    vnCodPlPagGenerico         PCPEDC.CODPLPAGGENERICO%TYPE;
    vvCodFilial                PCPEDC.CODFILIAL%TYPE;
    vvCodFilialNF              PCPEDC.CODFILIALNF%TYPE;
    vnCodUsur                  PCPEDC.CODUSUR%TYPE;
    vvOrigemPed                PCPEDC.ORIGEMPED%TYPE;
    vvTipoFv                   PCPEDC.TIPOFV%TYPE;
    vnCodEmitente              PCPEDC.CODEMITENTE%TYPE;
    vnCodPlPagProduto          PCPEDI.CODPLPAG%TYPE;
    vnNovoPerCom1              PCPEDI.PERCOM%TYPE;
    vnNovoPerRedComiss1        PCPEDI.PERREDCOMISS%TYPE;
    vnNovoPerCom2              PCPEDI.PERCOM2%TYPE;
    --
    vMEDUSACOMISSOPERADORTELEV PCPARAMFILIAL.VALOR%TYPE;
    vGRUPOFATURAMENTO          PCPRODUT.GRUPOFATURAMENTO%TYPE;
    --
    vvOcorreramAlertas         VARCHAR2(255);
    vvOcorreramRejeicoes       VARCHAR2(255);
    vvPodeGravarPedido         VARCHAR2(255); 
    vvMotivoNaoPodeGravar      VARCHAR2(255);
    vvProblemasTriPrecif       VARCHAR2(255);
    --
    vvErrosComissao1           VARCHAR2(1);
    vvMsgErrosComissao1        VARCHAR2(2000);
    vvErrosComissao2           VARCHAR2(1);
    vvMsgErrosComissao2        VARCHAR2(2000);
    --
  BEGIN
   
    -- Inicializa Retornos
    po_vTrocouCliente   := 'S';
    po_vMotivoNaoTrocou := NULL;

    IF (NVL(pi_nCodPlPagEtico,0) > 0) AND    
       (NVL(pi_nCodPlPagGenerico,0) > 0) THEN
      vnCodPlPagEtico    := pi_nCodPlPagEtico;
      vnCodPlPagGenerico := pi_nCodPlPagGenerico;
    ELSE
      vnCodPlPagEtico    := NULL;
      vnCodPlPagGenerico := NULL;
    END IF;
    
    UPDATE PCPEDC
       SET CODCLI            = pi_nCodCli
         , CODPRACA          = pi_nCodPraca
         , NUMREGIAO         = pi_nNumRegiao
         , CODPROMOCAOMED    = pi_nCodPromocaoMed
         , CODPLPAG          = pi_nCodPlPag   
         , CODPLPAGETICO     = vnCodPlPagEtico
         , CODPLPAGGENERICO  = vnCodPlPagGenerico
         , CODCOB            = pi_vCodCob
     WHERE (NUMPED = pi_nNumPed);

    UPDATE PCPEDI
       SET CODCLI  = pi_nCodCli
     WHERE (NUMPED = pi_nNumPed);
     
    -- Pesquisa Dados do Pedido
    BEGIN
      SELECT CODFILIAL
           , CODFILIALNF
           , CODUSUR
           , ORIGEMPED
           , TIPOFV
           , CODEMITENTE
        INTO vvCodFilial
           , vvCodFilialNF
           , vnCodUsur
           , vvOrigemPed
           , vvTipoFv
           , vnCodEmitente
        FROM PCPEDC
       WHERE (NUMPED = pi_nNumPed);      
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvCodFilial   := NULL;
        vvCodFilialNF := NULL;
        vnCodUsur     := NULL;
        vvOrigemPed   := NULL;
        vvTipoFv      := NULL;
        vnCodEmitente := NULL;
    END; 
        
    -- Pesquisa Parâmetro de comissão
    POBTEM_PARAMFILIAL_STRING('99',
                              'MEDUSACOMISSOPERADORTELEV',
                              'N',
                              vMEDUSACOMISSOPERADORTELEV);
    
   /******************************************
    Recálculo da Comissão
    *****************************************/
    FOR vc_Item IN (SELECT PCPEDI.CODPROD
                         , PCPEDI.NUMSEQ
                         , PCPEDI.CODPROMOCAOMED
                         , PCPEDI.DATA
                         , PCPEDI.PERCOM
                         , PCPEDI.PERREDCOMISS
                         , PCPEDI.PERCOM2
                         , PCPEDI.QT
                         , PCPEDI.PERDESC
                         , PCPEDI.CODDESCONTO
                         , CASE WHEN NVL(PCPEDI.CODUSUR,0) > 0 THEN
                             PCPEDI.CODUSUR
                           ELSE
                             vnCodUsur
                           END CODUSUR
                         , PCPEDI.CODUSUR2
                      FROM PCPEDI
                     WHERE (PCPEDI.NUMPED = pi_nNumPed)) LOOP
                     
      -- Pega Valores do Cursor
      vnNovoPerCom1       := vc_Item.PERCOM;
      vnNovoPerRedComiss1 := vc_Item.PERREDCOMISS;
      vnNovoPerCom2       := vc_Item.PERCOM2;
                     
      -- Pesquisa Dados do Produto
      BEGIN
        SELECT PCPRODUT.GRUPOFATURAMENTO
          INTO vGRUPOFATURAMENTO
          FROM PCPRODUT
         WHERE (PCPRODUT.CODPROD = vc_Item.CODPROD);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vGRUPOFATURAMENTO := NULL;
      END;
      
      -- Plano de Pagamento do Produto
      IF (NVL(pi_nCodPlPagEtico,0) > 0) AND
         (NVL(pi_nCodPlPagGenerico,0) > 0) THEN
        IF (NVL(vGRUPOFATURAMENTO,'N') = 'E') THEN
          vnCodPlPagProduto := pi_nCodPlPagEtico;
        ELSE
          vnCodPlPagProduto := pi_nCodPlPagGenerico;
        END IF;
      ELSE
        vnCodPlPagProduto := pi_nCodPlPag;
      END IF;
      
      -- Controle de Erros
      vvErrosComissao1 := 'N';
      vvErrosComissao2 := 'N';
                     
      -- Chama Procedimento para Obter a Comissão 1
      PKG_MEDICAMENTOS.P_OBTER_COMISSAO(4, -->> Chamado da Valida Promoção
                                        1, -->> Comissão do Representante
                                        vc_Item.CODPROMOCAOMED,
                                        vc_Item.CODPROD,
                                        pi_nCodCli,
                                        vc_Item.DATA,
                                        vvCodFilial,
                                        pi_nNumRegiao,
                                        vc_Item.CODUSUR, -->> RCA1 Representante
                                        pi_nMatricula,
                                        vvOrigemPed,
                                        vvTipoFv,
                                        vnCodPlPagProduto,
                                        vc_Item.QT,
                                        vc_Item.PERDESC,
                                        vc_Item.CODDESCONTO,
                                        NULL, -->> Passar nulo pra buscar todas as comissões, não um tipo específico
                                        vnNovoPerCom1,
                                        vvErrosComissao1,
                                        vvMsgErrosComissao1);
      -- Chama Procedimento para Obter a Comissão 2
      IF (vMEDUSACOMISSOPERADORTELEV = 'S') THEN
        PKG_MEDICAMENTOS.P_OBTER_COMISSAO(4, -->> Chamado da Valida Promoção
                                          2, -->> Comissão do Televendas
                                          vc_Item.CODPROMOCAOMED,
                                          vc_Item.CODPROD,
                                          pi_nCodCli,
                                          vc_Item.DATA,
                                          vvCodFilial,
                                          pi_nNumRegiao,
                                          vc_Item.CODUSUR2, -->> RCA2 Televendas
                                          pi_nMatricula,
                                          vvOrigemPed,
                                          vvTipoFv,
                                          vnCodPlPagProduto,
                                          vc_Item.QT,
                                          vc_Item.PERDESC,
                                          vc_Item.CODDESCONTO,
                                          NULL, -->> Passar nulo pra buscar todas as comissões, não um tipo específico
                                          vnNovoPerCom2,
                                          vvErrosComissao2,
                                          vvMsgErrosComissao2);
      END IF;                
      
      -- Se não ocorreram erros na Comissão
      IF (NVL(vvErrosComissao1,'N') = 'N') AND   
         (NVL(vvErrosComissao2,'N') = 'N') THEN
         
        -- Aplica Redutor de Comissão na Comissão 1
        P_APLICAR_REDUCAO_COMISSAO(vvCodFilial,
                                   pi_nNumRegiao,
                                   vnCodUsur,
                                   vnCodEmitente,
                                   vnNovoPerCom1,
                                   vnNovoPerRedComiss1);
                                       
        -- Atualiza Item do Pedido
        UPDATE PCPEDI
           SET PERCOM       = vnNovoPerCom1
             , PERREDCOMISS = vnNovoPerRedComiss1
             , PERCOM2      = vnNovoPerCom2
         WHERE (NUMPED  = pi_nNumPed)
           AND (CODPROD = vc_Item.CODPROD)
           AND (NUMSEQ  = vc_Item.NUMSEQ) ;
           
      END IF;
      
    END LOOP; -- Fim Laço de Produtos para Recálculo da Comissão
   
    -- Altera Preços
    P_VALIDAR_TROCA_CLIPROD('A', -- Alterar Itens do Pedido
                            pi_nMatricula,
                            pi_nNumPed,
                            pi_nCodCli,
                            pi_nCodPlPag,
                            pi_nCodPlPagEtico,
                            pi_nCodPlPagGenerico,
                            pi_vCodCob,
                            pi_nCodPromocaoMed,
                            pi_nNumRegiao,
                            vvCodFilial,
                            vvCodFilialNF,
                            vvOcorreramAlertas,
                            vvOcorreramRejeicoes,
                            vvPodeGravarPedido,
                            vvMotivoNaoPodeGravar,
                            vvProblemasTriPrecif);
    -- Valida Retorno da Alteração de Preços                        
    IF    (NVL(vvOcorreramRejeicoes,'N') = 'S') THEN
      po_vTrocouCliente   := 'N';
      po_vMotivoNaoTrocou := 'Existem críticas que impedem a troca do cliente';
      -- Desfaz Transações
      ROLLBACK;
    ELSIF (NVL(vvPodeGravarPedido,'N')  <> 'S') THEN
      po_vTrocouCliente   := 'N';
      po_vMotivoNaoTrocou := vvMotivoNaoPodeGravar;
      -- Desfaz Transações
      ROLLBACK;
    ELSE
      -- Efetiva Transações
      COMMIT; 
    END IF;
           
  EXCEPTION
    WHEN OTHERS THEN           
      po_vTrocouCliente   := 'N';
      po_vMotivoNaoTrocou := 'Erro ao Trocar Cliente: ' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
  END P_TROCAR_CLIENTE;                                 

 /***********************************************************************************************
  PROCEDURE: P_OBTER_TRANSPORTADORA_FREQENT
  DESCRIÇÃO: DDMEDICA-1658 - Obter Transportadora da Frequência de Entrega
  ***********************************************************************************************/   
  PROCEDURE P_OBTER_TRANSPORTADORA_FREQENT(pi_nCodPraca           IN  NUMBER,
                                           pi_vCodFilial          IN VARCHAR2,
                                           po_nCodTransportadora OUT NUMBER,
                                           po_nCodFreqEntrega    OUT NUMBER) IS
    vbAchouTransp BOOLEAN;
    vvDiaSemana   VARCHAR2(1);
    vnCodFilial   NUMBER;
  BEGIN
  
    po_nCodTransportadora := NULL;
    po_nCodFreqEntrega    := NULL;
    
    IF (F_REGRA_MEDICAMENTOS('99','APLICARTRANSPFREQENTPED') = 'S') THEN
      
      vbAchouTransp         := FALSE;
      
      vvDiaSemana           := TO_CHAR(SYSDATE,'D');
      
      BEGIN
        vnCodFilial := TO_NUMBER(pi_vCodFilial);
      EXCEPTION
        WHEN OTHERS THEN
          vnCodFilial := 0;
      END;
  
      FOR vc_TranspPraca IN (SELECT PCFREQENTREGAMED.CODFORNEC
                                  , NVL(PCFREQENTREGAMED.DOMINGO,'N') DOMINGO
                                  , NVL(PCFREQENTREGAMED.SEGUNDA,'N') SEGUNDA
                                  , NVL(PCFREQENTREGAMED.TERCA,'N')   TERCA
                                  , NVL(PCFREQENTREGAMED.QUARTA,'N')  QUARTA
                                  , NVL(PCFREQENTREGAMED.QUINTA,'N')  QUINTA 
                                  , NVL(PCFREQENTREGAMED.SEXTA,'N')   SEXTA
                                  , NVL(PCFREQENTREGAMED.SABADO,'N')  SABADO
                                  , PCFREQENTREGAMED.CODFREQENTREGA
                               FROM PCFREQENTREGAMED
                              WHERE (PCFREQENTREGAMED.TIPOFREQ = 'TP')
                                AND (PCFREQENTREGAMED.CODPRACA = pi_nCodPraca)
                              ORDER BY PCFREQENTREGAMED.CODFREQENTREGA) LOOP
                                
        IF ((vvDiaSemana = '1') AND (vc_TranspPraca.DOMINGO = 'S')) OR
           ((vvDiaSemana = '2') AND (vc_TranspPraca.SEGUNDA = 'S')) OR
           ((vvDiaSemana = '3') AND (vc_TranspPraca.TERCA   = 'S')) OR
           ((vvDiaSemana = '4') AND (vc_TranspPraca.QUARTA  = 'S')) OR
           ((vvDiaSemana = '5') AND (vc_TranspPraca.QUINTA  = 'S')) OR
           ((vvDiaSemana = '6') AND (vc_TranspPraca.SEXTA   = 'S')) OR
           ((vvDiaSemana = '7') AND (vc_TranspPraca.SABADO  = 'S')) THEN
          po_nCodTransportadora := vc_TranspPraca.CODFORNEC;
          po_nCodFreqEntrega    := vc_TranspPraca.CODFREQENTREGA;
          vbAchouTransp         := TRUE;
        END IF;
                                       
      END LOOP;
      
      IF (NOT vbAchouTransp) THEN
      
        FOR vc_TranspPraca IN (SELECT PCFREQENTREGAMED.CODFORNEC
                                    , NVL(PCFREQENTREGAMED.DOMINGO,'N') DOMINGO
                                    , NVL(PCFREQENTREGAMED.SEGUNDA,'N') SEGUNDA
                                    , NVL(PCFREQENTREGAMED.TERCA,'N')   TERCA
                                    , NVL(PCFREQENTREGAMED.QUARTA,'N')  QUARTA
                                    , NVL(PCFREQENTREGAMED.QUINTA,'N')  QUINTA 
                                    , NVL(PCFREQENTREGAMED.SEXTA,'N')   SEXTA
                                    , NVL(PCFREQENTREGAMED.SABADO,'N')  SABADO
                                    , PCFREQENTREGAMED.CODFREQENTREGA
                                 FROM PCFREQENTREGAMED
                                WHERE (PCFREQENTREGAMED.TIPOFREQ = 'TF')
                                  AND (PCFREQENTREGAMED.CODFILIAL = vnCodFilial)
                                ORDER BY PCFREQENTREGAMED.CODFREQENTREGA) LOOP
                                  
          IF ((vvDiaSemana = '1') AND (vc_TranspPraca.DOMINGO = 'S')) OR
             ((vvDiaSemana = '2') AND (vc_TranspPraca.SEGUNDA = 'S')) OR
             ((vvDiaSemana = '3') AND (vc_TranspPraca.TERCA   = 'S')) OR
             ((vvDiaSemana = '4') AND (vc_TranspPraca.QUARTA  = 'S')) OR
             ((vvDiaSemana = '5') AND (vc_TranspPraca.QUINTA  = 'S')) OR
             ((vvDiaSemana = '6') AND (vc_TranspPraca.SEXTA   = 'S')) OR
             ((vvDiaSemana = '7') AND (vc_TranspPraca.SABADO  = 'S')) THEN
            po_nCodTransportadora := vc_TranspPraca.CODFORNEC;
            po_nCodFreqEntrega    := vc_TranspPraca.CODFREQENTREGA;
            vbAchouTransp         := TRUE;
          END IF;
                                         
        END LOOP;
        
        IF (NOT vbAchouTransp) THEN
  
          FOR vc_TranspPraca IN (SELECT PCFREQENTREGAMED.CODFORNEC
                                      , NVL(PCFREQENTREGAMED.DOMINGO,'N') DOMINGO
                                      , NVL(PCFREQENTREGAMED.SEGUNDA,'N') SEGUNDA
                                      , NVL(PCFREQENTREGAMED.TERCA,'N')   TERCA
                                      , NVL(PCFREQENTREGAMED.QUARTA,'N')  QUARTA
                                      , NVL(PCFREQENTREGAMED.QUINTA,'N')  QUINTA 
                                      , NVL(PCFREQENTREGAMED.SEXTA,'N')   SEXTA
                                      , NVL(PCFREQENTREGAMED.SABADO,'N')  SABADO
                                      , PCFREQENTREGAMED.CODFREQENTREGA
                                   FROM PCFREQENTREGAMED
                                  WHERE (PCFREQENTREGAMED.TIPOFREQ = 'T')
                                  ORDER BY PCFREQENTREGAMED.CODFREQENTREGA) LOOP
                                    
            IF ((vvDiaSemana = '1') AND (vc_TranspPraca.DOMINGO = 'S')) OR
               ((vvDiaSemana = '2') AND (vc_TranspPraca.SEGUNDA = 'S')) OR
               ((vvDiaSemana = '3') AND (vc_TranspPraca.TERCA   = 'S')) OR
               ((vvDiaSemana = '4') AND (vc_TranspPraca.QUARTA  = 'S')) OR
               ((vvDiaSemana = '5') AND (vc_TranspPraca.QUINTA  = 'S')) OR
               ((vvDiaSemana = '6') AND (vc_TranspPraca.SEXTA   = 'S')) OR
               ((vvDiaSemana = '7') AND (vc_TranspPraca.SABADO  = 'S')) THEN
              po_nCodTransportadora := vc_TranspPraca.CODFORNEC;
              po_nCodFreqEntrega    := vc_TranspPraca.CODFREQENTREGA;
              vbAchouTransp         := TRUE;
            END IF;
                                           
          END LOOP;
  
        END IF;
        
      END IF;

    END IF; -- Fim Condição: Se Usa Regra Específica)
    
  END P_OBTER_TRANSPORTADORA_FREQENT;
  
 /*********************************************************************
  PROCEDIMENTO: P_OPCAO_LIMITAR_VENDA_EST_MIN
  DESCRIÇÃO   : Retornar se Limita a Venda do Estoque Mínimo - DDMEDICA-73914
                po_nOpcaoLimitarVendaEstMin - 0 = Não Limitar
                                              1 = Limitar
  *********************************************************************/
  PROCEDURE P_OPCAO_LIMITAR_VENDA_EST_MIN(pi_nCodCli                  IN NUMBER,
                                          pi_nCondVenda               IN NUMBER,
                                          po_nOpcaoLimitarVendaEstMin OUT NUMBER,
                                          po_vObservacao              OUT VARCHAR2,
                                          pi_nIntegradora             IN NUMBER DEFAULT NULL) IS    
    vLIMITARVENDAESTOQUEMINIMO     PCREGRASEXCECAOMED.VALOR%TYPE;                                      
    vnCodRede                      PCCLIENT.CODREDE%TYPE;                                          
    vnCodAtv1                      PCCLIENT.CODATV1%TYPE;  
    vvCodigoCadastrado             VARCHAR(255);
    vEXCECAOLIMITARVENDAESTOQUEMIN PCPARAMINTEGRADORAMED.VALOR%TYPE;
  BEGIN
   
    -- Inicializa Retornos
    po_nOpcaoLimitarVendaEstMin := 0;
    po_vObservacao              := NULL;
    
    -- Regra Específica
    vLIMITARVENDAESTOQUEMINIMO := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','LIMITARVENDAESTOQUEMINIMO');
    
    -- Exceção Estoque Mínimo
    vEXCECAOLIMITARVENDAESTOQUEMIN := 'N';
    IF (NVL(pi_nIntegradora,0) > 0) THEN
      vEXCECAOLIMITARVENDAESTOQUEMIN := FOBTEM_PARAM_INTEGRADORA(pi_nIntegradora,
                                                                 'EXCECAOLIMITARVENDAESTOQUEMIN',
                                                                 'N');    
    END IF;
    
    -- Verifica se Limita a Venda do Estoque Mínimo
    IF (NVL(vLIMITARVENDAESTOQUEMINIMO,'N') <> 'S') THEN
    
      po_vObservacao := 'Não limitar: Parâmetro LIMITARVENDAESTOQUEMINIMO';
    
    ELSE
    
      IF    (NVL(vEXCECAOLIMITARVENDAESTOQUEMIN,'N') = 'S') THEN
    
        po_vObservacao := 'Não limitar: Exceção na Integradora';
        
      ELSIF (NVL(pi_nCondVenda,0) = 10) THEN

        po_vObservacao := 'Não limitar: Transferência';
      
      ELSE
      
        -- Atualiza Retorno - Pedido começa limitando
        po_nOpcaoLimitarVendaEstMin := 1;
      
        -- Pesquisa Dados do Cliente
        BEGIN
          SELECT PCCLIENT.CODREDE
               , PCCLIENT.CODATV1
            INTO vnCodRede
               , vnCodAtv1
            FROM PCCLIENT
           WHERE (PCCLIENT.CODCLI = pi_nCodCli);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnCodRede := NULL;
            vnCodAtv1 := NULL;
        END;
      
        -- Verifica Regra
        BEGIN
          SELECT PCRESTRCOMERCIALMED.CODIGO
            INTO vvCodigoCadastrado
            FROM PCRESTRCOMERCIALMED
           WHERE (PCRESTRCOMERCIALMED.TIPORESTRICAO = 'EM')
             AND (PCRESTRCOMERCIALMED.CODFILIAL     = '99')    
             AND (PCRESTRCOMERCIALMED.TIPOCODIGO    = 'CL')
             AND (PCRESTRCOMERCIALMED.CODIGO        = pi_nCodCli);
          po_nOpcaoLimitarVendaEstMin := 0;   
          po_vObservacao              := 'Não Limitar: Cliente ' || vvCodigoCadastrado;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            BEGIN
              SELECT PCRESTRCOMERCIALMED.CODIGO
                INTO vvCodigoCadastrado
                FROM PCRESTRCOMERCIALMED
               WHERE (PCRESTRCOMERCIALMED.TIPORESTRICAO = 'EM')
                 AND (PCRESTRCOMERCIALMED.CODFILIAL     = '99')    
                 AND (PCRESTRCOMERCIALMED.TIPOCODIGO    = 'RC')
                 AND (PCRESTRCOMERCIALMED.CODIGO        = vnCodRede);
              po_nOpcaoLimitarVendaEstMin := 0;   
              po_vObservacao              := 'Não Limitar: Rede de Cliente ' || vvCodigoCadastrado;
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                BEGIN
                  SELECT PCRESTRCOMERCIALMED.CODIGO
                    INTO vvCodigoCadastrado
                    FROM PCRESTRCOMERCIALMED
                   WHERE (PCRESTRCOMERCIALMED.TIPORESTRICAO = 'EM')
                     AND (PCRESTRCOMERCIALMED.CODFILIAL     = '99')    
                     AND (PCRESTRCOMERCIALMED.TIPOCODIGO    = 'RA')
                     AND (PCRESTRCOMERCIALMED.CODIGO        = vnCodAtv1);
                  po_nOpcaoLimitarVendaEstMin := 0;  
                  po_vObservacao              := 'Não Limitar: Ramo de Atividade ' || vvCodigoCadastrado;
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    po_vObservacao := 'Limitar: Sem cadastro que permita venda do estoque mínimo';
                END;              
            END;
        END;      
      
      END IF; -- Fim Condição: Se Transferência
        
    END IF; -- Fim Condição: Sem Parâmetro LIMITARVENDAESTOQUEMINIMO    
  
  END P_OPCAO_LIMITAR_VENDA_EST_MIN;
  
 /***********************************************************************************************
  PROCEDURE: F_EXISTE_INTEGRADORA_CA_PBM
  DESCRIÇÃO: CA PBM - Verifica se existe alguma Integradora com Canal Autorizador PBM
  ***********************************************************************************************/   
  FUNCTION F_EXISTE_INTEGRADORA_CA_PBM
  RETURN VARCHAR2 IS
    vvExiste VARCHAR2(1);
  BEGIN
    BEGIN
      SELECT 'S'
        INTO vvExiste
        FROM PCINTEGRADORA
       WHERE (PCINTEGRADORA.INTEGRADORA IN (SELECT I.INTEGRADORA
                                              FROM PCINTEGRADORA I
                                             WHERE (I.LAYOUT = 58)
                                               AND (I.SITUACAO = 'A')
                                             UNION -- DDVENDAS-38983
                                            SELECT I.INTEGRADORA
                                              FROM PCINTEGRADORA I
                                                 , PCLAYOUTINTEGRAVERSOPERLOG V
                                                 , PCLAYOUTINTEGRACABOPERLOG C
                                             WHERE (I.LAYOUT = V.LAYOUT)
                                               AND (I.SEQVERSAO = V.SEQVERSAO)
                                               AND (C.LAYOUT = V.LAYOUT)
                                               AND (C.ESTRUTURA = 'API')
                                               AND (I.SITUACAO = 'A')
                                               AND (V.ENVIAPREPEDIDOAPI = 'S')))                                             
         AND (ROWNUM = 1);    
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvExiste := 'N';
    END;
    RETURN vvExiste;
  END F_EXISTE_INTEGRADORA_CA_PBM;

 /***********************************************************************************************
  PROCEDURE: F_PEDIDO_PERMITIDO_CA_PBM
  DESCRIÇÃO: CA PBM - Verifica se o Pedido é Permitido no Canal Autorizador PBM
  ***********************************************************************************************/   
  FUNCTION F_PEDIDO_PERMITIDO_CA_PBM(pi_nIntegradora IN NUMBER,
                                     pi_CondVenda    IN NUMBER,
                                     pi_nCodCli      IN NUMBER)
  RETURN VARCHAR2 IS  
    vvRetPermitido                 VARCHAR2(1);
    vIGNORARNFTRANSFNOTAEXTRA      PCPARAMINTEGRADORAMED.VALOR%TYPE;
    vIGNORARNFCONSIGNOTAEXTRA      PCPARAMINTEGRADORAMED.VALOR%TYPE;
    vIGNORARORGAOPUBLICOAPIFIDELIZ PCPARAMINTEGRADORAMED.VALOR%TYPE;
  BEGIN
    -- Inicializa Retorno
    vvRetPermitido := 'S';
    
    -- Obtém Parâmetros da Integradora
    vIGNORARNFTRANSFNOTAEXTRA      := FOBTEM_PARAM_INTEGRADORA(pi_nIntegradora,
                                                               'IGNORARNFTRANSFNOTAEXTRA',
                                                               'N');
    vIGNORARNFCONSIGNOTAEXTRA      := FOBTEM_PARAM_INTEGRADORA(pi_nIntegradora,
                                                               'IGNORARNFCONSIGNOTAEXTRA',
                                                               'N');                                                               
    vIGNORARORGAOPUBLICOAPIFIDELIZ := FOBTEM_PARAM_INTEGRADORA(pi_nIntegradora,
                                                               'IGNORARORGAOPUBLICOAPIFIDELIZE',
                                                               'N');
                                                               
    -- Se Ignora Transferência
    IF (vIGNORARNFTRANSFNOTAEXTRA = 'S') THEN
      IF (pi_CondVenda = 10) THEN
        vvRetPermitido := 'N';
      END IF;
    END IF;                                                                

    -- Se Ignora Consignado
    IF (vIGNORARNFCONSIGNOTAEXTRA = 'S') THEN
      IF (pi_CondVenda = 20) THEN
        vvRetPermitido := 'N';
      END IF;
    END IF;                                                                

    -- Se Ignora Cliente Órgão Público
    IF (vIGNORARORGAOPUBLICOAPIFIDELIZ = 'S') THEN
      BEGIN 
        SELECT 'N'
          INTO vvRetPermitido
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli) 
           AND ( (NVL(PCCLIENT.ORGAOPUB,'N') = 'S') OR
                 (NVL(PCCLIENT.ORGAOPUBMUNICIPAL,'N') = 'S') OR
                 (NVL(PCCLIENT.ORGAOPUBFEDERAL,'N') = 'S') );
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          NULL; -->> Não faz nada se não achar, não é órgão público
      END;
    END IF;                                                                
 
    -- Retorno 
    RETURN vvRetPermitido;
  END F_PEDIDO_PERMITIDO_CA_PBM;

 /***********************************************************************************************
  PROCEDURE: F_PRODUTO_INTEGRADORA_CA_PBM
  DESCRIÇÃO: CA PBM - Verifica se o Produto Participa do Canal Autorizador PBM, retornando a Integradora
  ***********************************************************************************************/   
  FUNCTION F_INTEGRADORA_PRODUTO_CA_PBM(pi_nCodProd IN NUMBER)
  RETURN NUMBER IS
    vnIntegradora       PCINTEGRADORA.INTEGRADORA%TYPE;
    vnCodMarca          PCPRODUT.CODMARCA%TYPE;
    vvExistemRestricoes VARCHAR2(1);
  BEGIN
  
    -- Verifica primeiro se existe cadastro por Produto
    BEGIN
      SELECT PCINTEGRADORAPROD.INTEGRADORA
        INTO vnIntegradora
        FROM PCINTEGRADORA
           , PCINTEGRADORAPROD
       WHERE (PCINTEGRADORA.INTEGRADORA = PCINTEGRADORAPROD.INTEGRADORA)
         AND (PCINTEGRADORA.INTEGRADORA IN (SELECT I.INTEGRADORA
                                              FROM PCINTEGRADORA I
                                             WHERE (I.LAYOUT = 58)
                                               AND (I.SITUACAO = 'A')
                                             UNION -- DDVENDAS-38983
                                            SELECT I.INTEGRADORA
                                              FROM PCINTEGRADORA I
                                                 , PCLAYOUTINTEGRAVERSOPERLOG V
                                                 , PCLAYOUTINTEGRACABOPERLOG C
                                             WHERE (I.LAYOUT = V.LAYOUT)
                                               AND (I.SEQVERSAO = V.SEQVERSAO)
                                               AND (C.LAYOUT = V.LAYOUT)
                                               AND (C.ESTRUTURA = 'API')
                                               AND (I.SITUACAO = 'A')
                                               AND (V.ENVIAPREPEDIDOAPI = 'S'))) 
         AND (PCINTEGRADORAPROD.CODPROD = pi_nCodProd)
         AND (ROWNUM = 1);    
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnIntegradora := NULL;
    END;
    
    -- Se não achou Integradora por Produto
    IF (NVL(vnIntegradora,0) = 0) THEN
    
      -- Procura a Marca do Produto
      BEGIN
        SELECT CODMARCA 
          INTO vnCodMarca
          FROM PCPRODUT
         WHERE (PCPRODUT.CODPROD = pi_nCodProd) ;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCodMarca := NULL;
      END;

      -- Verifica cadastro por Marca
      BEGIN
        SELECT PCCONFIGSISTOPERLOG.INTEGRADORA
          INTO vnIntegradora
          FROM PCINTEGRADORA
             , PCCONFIGSISTOPERLOG
             , PCCONFIGSISTMARCAOPERLOG
         WHERE (PCINTEGRADORA.INTEGRADORA = PCCONFIGSISTOPERLOG.INTEGRADORA)
           AND (PCCONFIGSISTOPERLOG.CODSISTEMA = PCCONFIGSISTMARCAOPERLOG.CODSISTEMA)
           AND (PCCONFIGSISTMARCAOPERLOG.CODMARCA = vnCodMarca) 
           AND (PCINTEGRADORA.INTEGRADORA IN (SELECT I.INTEGRADORA
                                                 FROM PCINTEGRADORA I
                                                WHERE (I.LAYOUT = 58)
                                                  AND (I.SITUACAO = 'A')
                                                UNION -- DDVENDAS-38983
                                               SELECT I.INTEGRADORA
                                                 FROM PCINTEGRADORA I
                                                    , PCLAYOUTINTEGRAVERSOPERLOG V
                                                    , PCLAYOUTINTEGRACABOPERLOG C
                                                WHERE (I.LAYOUT = V.LAYOUT)
                                                  AND (I.SEQVERSAO = V.SEQVERSAO)
                                                 AND (C.LAYOUT = V.LAYOUT)
                                                  AND (C.ESTRUTURA = 'API')
                                                  AND (I.SITUACAO = 'A')
                                                  AND (V.ENVIAPREPEDIDOAPI = 'S')))    
           AND (ROWNUM = 1);    
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnIntegradora := NULL;
      END;     
      
      -- Se achou cadastro por Marca
      IF (NVL(vnIntegradora,0) > 0) THEN
       
        -- Verifica se essa Integradora tem Restrições para outros Produtos (Tanto Layout 58 como API - DDVENDAS-38983)
        BEGIN
          SELECT 'S'
            INTO vvExistemRestricoes
            FROM PCINTEGRADORA
               , PCINTEGRADORAPROD
           WHERE (PCINTEGRADORA.INTEGRADORA = PCINTEGRADORAPROD.INTEGRADORA)
             AND (PCINTEGRADORAPROD.INTEGRADORA = vnIntegradora) -- Integradora Encontrada
             AND (PCINTEGRADORAPROD.CODPROD <> pi_nCodProd)   -- Outros Produtos
             AND (ROWNUM = 1);    
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvExistemRestricoes := 'N';
        END; 
        
        -- Se existem Restrições pra outros Produtos, essa Integradora não é válida
        IF (vvExistemRestricoes = 'S') THEN
          vnIntegradora := NULL;
        END IF;  
      
      END IF;
    
    END IF;
  
    RETURN vnIntegradora;
    
  END F_INTEGRADORA_PRODUTO_CA_PBM;
  
 /***********************************************************************************************
  PROCEDURE: F_OBTER_ACAO_SITUACAO_CA_PBM
  DESCRIÇÃO: CA PBM - Obter Acão a ser executada na Liberação do Pedido conforme Situação da
             Aprovação dos Descontos da Indústria na Indústria no Canal Autorizador
  ***********************************************************************************************/   
  FUNCTION F_OBTER_ACAO_SITUACAO_CA_PBM(pi_nNumPed IN NUMBER)
  RETURN VARCHAR2 IS
    vnNumPedOperLog            NUMBER;
    vvSituacaoPedOperLog       VARCHAR2(255);
    vvDescricaoSituacaoOperLog VARCHAR2(255);
    vnNumTransVendaOriginal    PCPEDCOMPRAOPERLOGCAB.NUMTRANSVENDAORIGINAL%TYPE;
    vvAcao                     VARCHAR2(1);
  BEGIN
  
    -- Obtém dados do Pedido PBM
    P_OBTEM_SITUACAO_PEDIDO_CA_PBM(pi_nNumPed,
                                   vnNumPedOperLog,
                                   vvSituacaoPedOperLog,
                                   vvDescricaoSituacaoOperLog,
                                   vnNumTransVendaOriginal);  

    -- Somente se a Indústria Autorizou o desconto o pedido poderá ser Liberado
    -- Autorizado/Liberado
    IF (NVL(vvSituacaoPedOperLog,'P') IN ('A','L')) THEN
      vvAcao := 'I';
    ELSE
      vvAcao := 'A';
    END IF;
    
    RETURN vvAcao;
    
  END F_OBTER_ACAO_SITUACAO_CA_PBM;
  
 /*********************************************************************
  FUNÇÃO   : F_MED_VALIDA_ENVIO_WMS
  DESCRIÇÃO: Valida se o Pedido já foi enviado para o WMS - DDVENDAS-31376
  *********************************************************************/
  FUNCTION F_MED_VALIDA_ENVIO_WMS(pi_nNumPed          IN NUMBER,
                                  pi_nCodRotina       IN NUMBER,
                                  pi_vChamadaProcesso IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetEnviadoWms VARCHAR2(1);
    vdDtWms         PCPEDC.DTWMS%TYPE;
  BEGIN
  
    -- Inicializa Retorno
    vvRetEnviadoWms := 'N';
    
    -- Se Edição do Pedido na 2316
    IF (pi_nCodRotina       = 2316) AND
       (pi_vChamadaProcesso = 'EP') THEN
      BEGIN
        SELECT DTWMS
          INTO vdDtWms
          FROM PCPEDC
         WHERE (NUMPED = pi_nNumPed);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vdDtWms := NULL;
      END; 
      -- Se o WMS já puxou o Pedido não pode mais alterar a Quantidade
      IF (vdDtWms IS NOT NULL) THEN
        vvRetEnviadoWms := 'S';
      END IF;
    END IF;
    
    RETURN vvRetEnviadoWms;
    
  END F_MED_VALIDA_ENVIO_WMS;  
  
 /*******************************************************************************
  Nome         : P_ESTOQUE_RESERV_ITEM_01
  Descricão    : Atualização do Estoque Reservado
  Parâmetros   : Entrada:
                 pi_nOrigemChamada      = Origem da Chamada
                                          1 - Chamado da Sugestão de Reposição 
                                          2 - Chamado da Gravação do Pedido (2316)
                                          3 - Chamado da Liberação do Pedido (2336)
                                          4 - Chamado do Gravação do Pedido (INTEGRADORA_MED)
                                          5 - Chamado do Faturamento
                                          6 - Chamado da Alteração do Item (2336)
                 pi_vOperacao           = 'IR' - Incluir Reserva 
                                          'BR' - Baixar Reserva
                                          'AR' - Alterar Reserva
                                          'IP' - Incluir Pendente
                                          'BP' - Baixar Pendente
                                          'AP' - Alterar Pendente
                 pi_vCodFilial          = Código da Filial
                 pi_nNumPed             = Número do Pedido
                 pi_nCodProd            = Código do Produto
                 pi_nNumSeq             = Num. Seq. do Item do Pedido
                 pi_nQtde               = Quantidade
                 pi_vPedidoExiste       = Se Pedido Existe (S/N)
                 Saida:
                 po_vOcorreramErros     = 'S' - Sim; 'N'- Não
                 po_vMsgErros           = Mensagem de Erros         
  Alteração    : Anderson Silva - 24/10/2017 - HIS.02098.2017 - Criação da Procedure
               : Anderson Silva - 25/01/2019 - MED-2163 - 'BQ' para baixar reserva
  *******************************************************************************/
  PROCEDURE P_ESTOQUE_RESERV_ITEM_01(pi_nOrigemChamada  IN  NUMBER,
                                     pi_vOperacao       IN  VARCHAR2,
                                     pi_vCodFilial      IN  VARCHAR2,
                                     pi_nNumPed         IN  NUMBER,
                                     pi_nCodProd        IN  NUMBER,
                                     pi_nNumSeq         IN  NUMBER,
                                     pi_nQtde           IN  NUMBER,
                                     pi_vPedidoExiste   IN  VARCHAR2,
                                     po_vOcorreramErros OUT VARCHAR2,
                                     po_vMsgErros       OUT VARCHAR2) 
  IS
    -- Regra Específica
    vvUsaRegraMonitoraReservado  VARCHAR2(250);
    
    -- Versão
    vvVersao                     VARCHAR2(250);  
    
    -- Booleano se Pedido existe
    vbPedidoExiste               BOOLEAN;
    
    -- Booleano se fez alguma chamada na Package Estoque
    vbChamouPkgEstoque           BOOLEAN;
                                 
    -- Retorno PKG_ESTOQUE
    vvSucessoPkgEstoque          VARCHAR2(250);
    vvMsgRetornoPkgEstoque       VARCHAR2(2000);
    
    -- Tratamento de Erros
    e_ErroTratado                EXCEPTION;
    vvMsgErroTratado             VARCHAR2(2000);
    
   /**********************
    INICIO DO PROCEDIMENTO
    **********************/ 
  BEGIN
  
    -- Inicializa Retorno
    po_vMsgErros       := 'N';
    po_vMsgErros       := NULL;
              
    -- Booleano se fez alguma chamada na Package Estoque
    vbChamouPkgEstoque := FALSE;
              
    -- Força a Recompilação da Package (Evita Erro de Objeto Descartado)
    BEGIN
      vvVersao := PKG_ESTOQUE.VERSAO;
    EXCEPTION
     WHEN OTHERS THEN
        BEGIN
          vvVersao := PKG_ESTOQUE.VERSAO;
        EXCEPTION
          WHEN OTHERS THEN
            vvVersao := 'PkgInvalida';
         END;
    END;  
    
    -- Booleano se Pedido existe
    vbPedidoExiste := (NVL(pi_vPedidoExiste,'N') = 'S');  
  
    -------------------------------------------------------------------------------------------------
    -- ATUALIZAÇÃO DO ESTOQUE
    -------------------------
    
    -- Incluindo Reserva   
    IF (pi_vOperacao = 'IR')  THEN
      
      vvSucessoPkgEstoque := PKG_ESTOQUE.RESERVA_INCLUIR(pi_nNumPed
                                                        ,pi_nCodProd
                                                        ,pi_nNumSeq
                                                        ,vbPedidoExiste
                                                        ,'IN'
                                                        ,vvMsgRetornoPkgEstoque);
      IF (NVL(vvSucessoPkgEstoque,'N') <> 'S') THEN
        vvMsgErroTratado := vvMsgRetornoPkgEstoque;
        RAISE e_ErroTratado;
      END IF;    
      
      -- Chamou Package Estoque
      vbChamouPkgEstoque := TRUE;                            
      
    END IF;
    
    -- Baixando Reserva   
    IF (pi_vOperacao = 'BR')  THEN
    
      vvSucessoPkgEstoque := PKG_ESTOQUE.RESERVA_BAIXAR(pi_nNumPed
                                                       ,pi_nCodProd
                                                       ,pi_nNumSeq
                                                       ,'BQ' -- MED-2163
                                                       ,vvMsgRetornoPkgEstoque);
      IF (NVL(vvSucessoPkgEstoque,'N') <> 'S') THEN
        vvMsgErroTratado := vvMsgRetornoPkgEstoque;
        RAISE e_ErroTratado;
      END IF;                                
    
      -- Chamou Package Estoque
      vbChamouPkgEstoque := TRUE;                            
    
    END IF;
  
    -- Alterando Reserva Reserva   
    IF (pi_vOperacao = 'AR')  THEN
    
      vvSucessoPkgEstoque := PKG_ESTOQUE.RESERVA_ALTERAR(pi_nNumPed
                                                        ,pi_nCodProd
                                                        ,pi_nNumSeq
                                                        ,'AQ'
                                                        ,vvMsgRetornoPkgEstoque);
      IF (NVL(vvSucessoPkgEstoque,'N') <> 'S') THEN
        vvMsgErroTratado := vvMsgRetornoPkgEstoque;
        RAISE e_ErroTratado;
      END IF;                                
    
      -- Chamou Package Estoque
      vbChamouPkgEstoque := TRUE;                            
    
    END IF;
    
    -- Incluindo Pendente   
    IF (pi_vOperacao = 'IP') THEN
    
      vvSucessoPkgEstoque := PKG_ESTOQUE.PENDENTE_INCLUIR(pi_nNumPed
                                                         ,pi_nCodProd
                                                         ,pi_nNumSeq
                                                         ,vbPedidoExiste
                                                         ,'IN'
                                                         ,vvMsgRetornoPkgEstoque);   
      IF (NVL(vvSucessoPkgEstoque,'N') <> 'S') THEN
        vvMsgErroTratado := vvMsgRetornoPkgEstoque;
        RAISE e_ErroTratado;
      END IF;                                
  
      -- Chamou Package Estoque
      vbChamouPkgEstoque := TRUE;                            
      
    END IF;
    
    
    -- Baixando Pendente   
    IF (pi_vOperacao = 'BP')  THEN
    
      vvSucessoPkgEstoque := PKG_ESTOQUE.PENDENTE_BAIXAR(pi_nNumPed
                                                        ,pi_nCodProd
                                                        ,pi_nNumSeq
                                                        ,'B'
                                                        ,vvMsgRetornoPkgEstoque);
      IF (NVL(vvSucessoPkgEstoque,'N') <> 'S') THEN
        vvMsgErroTratado := vvMsgRetornoPkgEstoque;
        RAISE e_ErroTratado;
      END IF;                                
    
        -- Chamou Package Estoque
      vbChamouPkgEstoque := TRUE;                            
  
    END IF;
  
    -- Alterar Pendente   
    IF (pi_vOperacao = 'AP')  THEN
    
      vvSucessoPkgEstoque := PKG_ESTOQUE.PENDENTE_ALTERAR(pi_nNumPed
                                                         ,pi_nCodProd
                                                         ,pi_nNumSeq
                                                         ,'AQ'
                                                         ,vvMsgRetornoPkgEstoque);
      IF (NVL(vvSucessoPkgEstoque,'N') <> 'S') THEN
        vvMsgErroTratado := vvMsgRetornoPkgEstoque;
        RAISE e_ErroTratado;
      END IF;                                
    
      -- Chamou Package Estoque
      vbChamouPkgEstoque := TRUE;                            
    
    END IF;
    
    -- Se não chamou a Package Estoque
    IF (NOT vbChamouPkgEstoque) THEN
      vvMsgErroTratado := 'Não foi executada a Package Estoque';
      RAISE e_ErroTratado;
    END IF;
     
  EXCEPTION
    WHEN e_ErroTratado THEN
      po_vOcorreramErros := 'S'; -- Ocorreram Erros
      po_vMsgErros       := vvMsgErroTratado;
    WHEN OTHERS THEN
      po_vOcorreramErros := 'S'; -- Ocorreram Erros
      po_vMsgErros       := SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000); 
  END P_ESTOQUE_RESERV_ITEM_01;
                                                                                 
 /*******************************************************************************
  Nome         : P_GRAVACAO_PEDIDO_01
  Descricão    : Procedimento de Gravação do Pedido, que realiza a Reserva do
                 Estoque, Atualização da Posição e Atualização do Conta-Corrente do RCA
  Parâmetros   : Entrada:
                 pi_nCodRotina              = Código da Rotina
                 pi_nNumPed                 = Número do Pedido
                 pi_nCodUsurContaCorrente   = Código do RCA para Movimentação do Conta-Corrente
                 pi_nMatricula              = Matrícula
                 pi_vGuardaFalta            = Se Guarda Falta
                 pi_vGravarPedidoItensFalta = Se Grava Pedido com os Itens Faltantes
                 pi_vMovimentarSaldoRca     = Se Movimenta Saldo RCA
                 pi_vChamadaProcesso        = Indicador do Processo
                                              'VM' - Validação de Mínimos durante a Digitação do Pedido
                                              'IF' - Validação para definir se Gera Pedido de Itens Faltantes
                                              'GP' - Gravação do Pedido
                                              'EP' - Edição do Pedido
                                              'MP' - Mudar a Posição do Pedido
                                              'CI' - Cancelar Itens
                                              'CC' - Cancelar Pedido Call Center
                                              'LB' - Log de Bloqueios
                 pi_vNovaPosicaoPedido      = Nova Posição do Pedido
                 pi_vBrindes                = Identifica se está chamando para Reservar estoque dos Brindes
                 pi_nCodProdEdicao          = Se estiver realizando uma Edição de um Item na 2336
                 pi_vCodFilial              = Código da Filial (passado se ainda não tiver PCPEDC)
                 pi_nCodCli                 = Código do Cliente (passado se ainda não tiver PCPEDC)
                 pi_nCondVenda              = Tipo de Venda (passado se ainda não tiver PCPEDC)
                 pi_nCodPlPag               = Plano de Pagamento (passado se ainda não tiver PCPEDC)
                 pi_nCodPlPagEtico          = Plano de Pagamento Ético (passado se ainda não tiver PCPEDC)
                 pi_nCodPlPagGenerico       = Plano de Pagamento Genérico (passado se ainda não tiver PCPEDC)
                 pi_vCodCob                 = Código da Cobrança (passado se ainda não tiver PCPEDC)
                 pi_dDtEntrega              = Data de Entrega do Pedido (passado se ainda não tiver PCPEDC)
                 pi_vOrigemPed              = Origem do Pedido (passado se ainda não tiver PCPEDC)
                 pi_vTipoFv                 = Tipo FV (passado se ainda não tiver PCPEDC)
                 pi_nIntegradora            = Integradora (passado se ainda não tiver PCPEDC)
                 pi_nCodCondicaoVenda       = Código da Condição de Venda (passado se ainda não tiver PCPEDC)
                 pi_nCodUsur                = Código do RCA (passado se ainda não tiver PCPEDC)
                 pi_vVendaAssistida         = Flag de Venda Assistida (passado se ainda não tiver PCPEDC)
                 Saida:
                 po_vRetorno                = Se ocorreram Erros, esta variável de retorno estará preenchida,
                                              exceto valores:
                                              '-2' -> Indicar à INTEGRADORA_MED que o Pedido deve ser excluido por
                                                      causa de cortes e trabalhar com parâmetro aceitavendasemestfv = 'RP'
                                              '-3' -> Indicar à INTEGRADORA_MED que o Pedido deve ser excluido por
                                                      causa de cortes e ficar baixo do mínimo da condição de venda
                 po_vMsgErros               = Mensagem de Erros
                 po_vPosicaoFinalPedido     = Posição Final do Pedido
                 po_nCodMotivo              = Código do Motivo                
                 po_vMotivoPosicao          = Motivo da Posição
                 po_vObservacaoMotivo       = Observação Motivo
                 po_vExistemFaltas          = Se Existem Faltas (Sim ou Não)
  Alteração    : Anderson Silva - 08/11/2017
                 Tarefa: HIS.04281.2017 Criação da Procedure *
  Alteração    : Anderson Silva - 06/04/2018 - MED-384 - Melhorar Mensagem exceção Estoque
  Alteração    : Anderson Silva - 03/06/2018 - HIS.05093.2017 - Bloqueio por Desconto Negociado
  Alteração    : Anderson Silva - 17/08/2018 - MED-1199 - Balcão não aceitar venda sem estoque
  Alteração    : Anderson Silva - 13/09/2018 - MED-1669 - Status Saldo RCA
  Alteração    : Anderson Silva - 14/09/2018 - MED-1669 - Validação Saldo RCA com Faltas
  Alteração    : Anderson Silva - 28/11/2018 - MED-1964 - Inclusão Chamada 2312
  Alteração    : Anderson Silva - 30/11/2018 - MED-1981 - Tratamento QTPENDENTE 2336
  Alteração    : Anderson Silva - 25/01/2019 - MED-2161 - Melhorar Log dos Retornos
  Alteração    : Anderson Silva - 15/03/2019 - MED-2349 - Validação Saldo RCA parâmetro ACEITAVENDARCASEMSALDOFV
  Alteração    : Anderson Silva - 18/03/2019 - 4415.029804.2019 - Permissão Liberar Sem Saldo C/C
  Alteração    : Anderson Silva - 02/05/2019 - MED-2524 - Alteração Validação Pedido TV5
  Alteração    : Anderson Silva - 14/05/2019 - MED-2532 - Validar Mínimo sem ST requer opção para ignorar parâmetro 2548
  Alteração    : Anderson Silva - 21/05/2019 - MED-2604 - Validação Valor Mínimo sem Bonificação; Alteração da Validação do Valor Mínumo da Cobramça
  Alteração    : Anderson Silva - 07/06/2019 - MED-2625 - Corte de Produtos sem Estoque em Pedidos Bloqueados
  Alteração    : Anderson Silva - 04/07/2019 - DDMEDICA-198 - Log de Exclusão do Item por Falta de Estoque
  Alteração    : Anderson Silva - 12/08/2019 - MEDICA-477 - Validação Conta-Corrente usando Validar por Item = Não
  Alteração    : Anderson Silva - 15/08/2019 - DDMEDICA-570 - Atualização de Prazos do Pedido
  Alteração    : Anderson Silva - 22/08/2019 - DDMEDICA-641 - Pedido Avaria e CrossDocking
  Alteração    : Anderson Silva - 29/09/2019 - DDMEDICA-614 - Alteração Validação C/C pela 2336
  Alteração    : Anderson Silva - 01/09/2019 - DDMEDICA-683 - Validação C/C com Déb/Créd Faturamento
  Alteração    : Anderson Silva - 17/09/2019 - DDMEDICA-825 - Permissão Pedido Itens Faltantes de Combos
  Alteração    : Anderson Silva - 18/09/2019 - DDMEDICA-834 - Rateio Crédito C/C
  Alteração    : Anderson Silva - 03/10/2019 - DDMEDICA-957 - Não permitir gravar como bloqueado em algumas situações se Montado
  Alteração    : Jorge Humberto - 08/10/2019 - DDMEDICA-1008 - Caso parâmetros de validar estoque contábil esteja marcada, optar pela quantidade contábil para controle de estoque
  Alteração    : Anderson Silva - 29/10/2019 - DDMEDICA-1040 - Totalizar Pedido de Itens Faltantes
  Alteração    : Anderson Silva - 27/10/2019 - DDMEDICA-1147 - Chamada Importação WMS - Rotina 2641
  Alteração    : Anderson Silva - 01/11/2019 - DDMEDICA-1212 - Edição do Pedido enviado para WMS não pode mudar a Posição
  Alteração    : Anderson Silva - 05/11/2019 - DDMEDICA-1249 - Validação Valor Mínimo com Corte Total
  Alteração    : Anderson Silva - 28/12/2019 - DDMEDICA-1691 - PMPF de Medicamentos
  *******************************************************************************/
  PROCEDURE P_GRAVACAO_PEDIDO_01(pi_nCodRotina              IN  NUMBER,
                                 pi_nNumPed                 IN  NUMBER,
                                 pi_nCodUsurContaCorrente   IN  NUMBER,
                                 pi_nMatricula              IN  NUMBER,
                                 pi_vGuardaFalta            IN  VARCHAR2,
                                 pi_vGravarPedidoItensFalta IN  VARCHAR2,
                                 pi_nNumPedidoItensFalta    IN  NUMBER,
                                 pi_vMovimentarSaldoRca     IN  VARCHAR2,
                                 pi_vChamadaProcesso        IN  VARCHAR2,
                                 pi_vNovaPosicaoPedido      IN  VARCHAR2,
                                 pi_vBrindes                IN  VARCHAR2,
                                 pi_nCodProdEdicao          IN  NUMBER,
                                 po_vRetorno                OUT VARCHAR2,
                                 po_vMsgErros               OUT VARCHAR2,
                                 po_vPosicaoFinalPedido     OUT VARCHAR2,
                                 po_nCodMotivo              OUT NUMBER,
                                 po_vMotivoPosicao          OUT VARCHAR2,
                                 po_vObservacaoMotivo       OUT VARCHAR2,
                                 po_vExistemFaltas          OUT VARCHAR2,
                                 pi_vCodFilial              IN  VARCHAR2 DEFAULT NULL,
                                 pi_nCodCli                 IN  NUMBER   DEFAULT NULL,
                                 pi_nCondVenda              IN  NUMBER   DEFAULT NULL,
                                 pi_nCodPlPag               IN  NUMBER   DEFAULT NULL,
                                 pi_nCodPlPagEtico          IN  NUMBER   DEFAULT NULL,
                                 pi_nCodPlPagGenerico       IN  NUMBER   DEFAULT NULL,
                                 pi_vCodCob                 IN  VARCHAR2 DEFAULT NULL,
                                 pi_dDtEntrega              IN  DATE     DEFAULT NULL,
                                 pi_vOrigemPed              IN  VARCHAR2 DEFAULT NULL,
                                 pi_vTipoFv                 IN  VARCHAR2 DEFAULT NULL,
                                 pi_nIntegradora            IN  NUMBER   DEFAULT NULL,
