  -- DDMEDICA-6582
  PROCEDURE P_INC_MENSAGEM_ERRO_RESERVADO(pi_nNumPed             IN NUMBER,
                                          pi_nCodProd            IN NUMBER,
                                          pi_nNumSeq             IN NUMBER,
                                          pi_vOperacaoReservaEst IN VARCHAR2,
                                          pio_vMensagem          IN OUT VARCHAR2) IS
  BEGIN
    BEGIN
      SELECT pio_vMensagem || CHR(13) || 'Posicao do Pedido = ' || POSICAO || ' para operação = ' || pi_vOperacaoReservaEst
        INTO pio_vMensagem 
        FROM PCPEDC
       WHERE (NUMPED  = pi_nNumPed);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pio_vMensagem := pio_vMensagem || CHR(13) || 'Posicao do Pedido = VAZIO';
    END;                       
    BEGIN
      SELECT pio_vMensagem || CHR(13) || 'Posicao do Produto ' || CODPROD || ' = ' || POSICAO
        INTO pio_vMensagem 
        FROM PCPEDI
       WHERE (NUMPED  = pi_nNumPed)
         AND (CODPROD = pi_nCodProd)
         AND (NUMSEQ  = pi_nNumSeq);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        pio_vMensagem := pio_vMensagem || CHR(13) || 'Posicao do Produto ' || vrItemPedido.vnCodProd || ' = VAZIO';
    END;                         
  END P_INC_MENSAGEM_ERRO_RESERVADO;                                                                                    

  /************************************************************************************************************
  ->Nome da FUNCTION  : F_PROX_NUMPED
  ->Objetivo          : Buscar o próximo NUMPED em transação autônoma(separada).
  ->Utilizado por     : ALTERAR PEDIDO DE VENDA(336)
  ------------  ---------------   ---------------------------------------------------------------------------*/
  FUNCTION F_PROX_NUMPED(PCODUSUR NUMBER)
  RETURN NUMBER
  IS
  v_numped  NUMBER; 
  BEGIN

    SELECT NVL(proxnumped, 0)
      INTO v_numped
      FROM pcusuari
     WHERE codusur = PCODUSUR
       FOR UPDATE;

    UPDATE pcusuari
       SET proxnumped = NVL(proxnumped, 0) + 1
     WHERE codusur = PCODUSUR;
 
    RETURN v_numped;

  EXCEPTION
    WHEN OTHERS THEN
      RETURN 0;
  END F_PROX_NUMPED;
  
    ------------------------------------------------------------------------------
    -- FUNÇÃO...: FFORMATAR_NUMERO_PARA_TEXTO
    -- DESCRIÇÃO: Função para Formatar um Número para Texto
    ------------------------------------------------------------------------------
    FUNCTION FFORMATAR_NUMERO_PARA_TEXTO(pi_nNumero            IN NUMBER,
                                         pi_iQtdeCasasDecimais IN INTEGER) RETURN VARCHAR2 IS
      vvTextoRetorno  VARCHAR2(200);
      vvMascara       VARCHAR2(200);
    BEGIN
  
      vvMascara :=  NULL;
  
      -- Monta a parte da Mascara com Casas Decimais
      IF (pi_iQtdeCasasDecimais > 0) THEN
        FOR viIdx IN 1..pi_iQtdeCasasDecimais LOOP
          IF (vvMascara = NULL) THEN
            vvMascara := '0';
          ELSE
            vvMascara := vvMascara || '0';
          END IF;
        END LOOP;
        vvMascara := '0.' || vvMascara;
      -- Monta a parte da Mascara sem Casas Decimais
      ELSE
        vvMascara := '0';
      END IF;
  
      -- Finaliza a Máscara da Parte Inteira
      vvMascara := '999,999,999,999,999,999,999,999,999,999,999,99' || vvMascara;
  
      -- Prepara Texto Retorno
      vvTextoRetorno := TO_CHAR(pi_nNumero,vvMascara);
  
      -- Troca Ponto por um caracter auxiliar
      vvTextoRetorno := REPLACE(vvTextoRetorno,'.','@');
  
      -- Troca Virgulas por ponto
      vvTextoRetorno := REPLACE(vvTextoRetorno,',','.');
  
      -- Troca caracter auxiliar por virgula
      vvTextoRetorno := REPLACE(vvTextoRetorno,'@',',');
  
      -- Elimina espaços em branco
      vvTextoRetorno := TRIM(vvTextoRetorno);
  
      -- Retorno
      RETURN vvTextoRetorno;
  
    END FFORMATAR_NUMERO_PARA_TEXTO;
    
    ------------------------------------------------------------------------------
    -- Função para retornar se movimenta Conta-Corrente no Faturamento por Pedido
    ------------------------------------------------------------------------------
    FUNCTION F_MOVSALDORCAPORPEDIDOFAT RETURN BOOLEAN IS
      -- Parâmetro
      nPERCRATEIOCREDRCASUPERVISOR NUMBER;
      -- Identificação de Erros ao Pesquisar Parâmetros
      vvErroPesqParam              VARCHAR2(1);
      vvMsgErroPesqParam           VARCHAR2(2000);
      -- Retorno
      vbMovSaldoRcaPorPedidoFat    BOOLEAN;
    BEGIN
      -- Inicializa Retorno
      vbMovSaldoRcaPorPedidoFat := FALSE;
        
      -- Regra Específica
      IF (FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','MOVSALDORCAPORPEDIDOFAT') = 'S') THEN
        vbMovSaldoRcaPorPedidoFat := TRUE;
      END IF;
      
      -- Retorno
      RETURN vbMovSaldoRcaPorPedidoFat;                               
    END; --F_MOVSALDORCAPORPEDIDOFAT

