   /********************************************************************
    PROCEDURE: F_OBTER_PEDIDO_SESSAO_ANT
    DESCRIÇÃO: Ver se o Pedido já foi comittado
    ********************************************************************/
    FUNCTION F_OBTER_PEDIDO_SESSAO_ANT(pi_nNumPed IN NUMBER) RETURN NUMBER 
    IS
    PRAGMA AUTONOMOUS_TRANSACTION;
      vnRetNumPed NUMBER;
    BEGIN
      
      BEGIN
        SELECT NUMPED
          INTO vnRetNumPed
          FROM PCPEDC
         WHERE (NUMPED = pi_nNumPed);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnRetNumPed := -1;
      END;
      
      RETURN vnRetNumPed;  
      
    END F_OBTER_PEDIDO_SESSAO_ANT;
  
   /********************************************************************
    PROCEDURE: F_OBTER_PEDIDOITENS_SESSAO_ANT
    DESCRIÇÃO: Ver se Itens do Pedido Pedido já foi comittado
    ********************************************************************/
    FUNCTION F_OBTER_PEDIDOITENS_SESSAO_ANT(pi_nNumPed IN NUMBER) RETURN NUMBER 
    IS
    PRAGMA AUTONOMOUS_TRANSACTION;
      vnRetNumPed NUMBER;
    BEGIN
      
      BEGIN
        SELECT NUMPED
          INTO vnRetNumPed
          FROM PCPEDI
         WHERE (NUMPED = pi_nNumPed)
           AND (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnRetNumPed := -1;
      END;
      
      RETURN vnRetNumPed;  
      
    END F_OBTER_PEDIDOITENS_SESSAO_ANT;
  
   /********************************************************************
    PROCEDURE: P_TESTE_UNITARIO
    DESCRIÇÃO: Insere Dados para Teste Unitário
    ********************************************************************/
    PROCEDURE P_TESTE_UNITARIO(pi_nId IN NUMBER) IS
      vnProxNumPed NUMBER;
    BEGIN
      IF (pi_nId = 1) THEN
        --FUNCOES_MED.FOBTEM_PROX_NUMPED_PRAGMA(1235);
        FUNCOES_MED.P_DUPLICAR_PCPEDC(1235010516,
                                      pi_nNumPed,
                                      vvOcorreramErrosCabPedFalta,
                                      vvMsgErrosCabPedFalta);
        IF (vvOcorreramErrosCabPedFalta = 'S') THEN
          RAISE e_CabPedFalta;
        END IF;
        FOR vc_Item IN (SELECT NUMPED, CODPROD, NUMSEQ FROM PCPEDI WHERE NUMPED = 1235010516)  LOOP
        FUNCOES_MED.P_DUPLICAR_PCPEDI(1235010516,
                                      pi_nNumPed,
                                      vc_Item.CODPROD,
                                      vc_Item.NUMSEQ,
                                      vc_Item.NUMSEQ,
                                      vvOcorreramErrosItePedFalta,
                                      vvMsgErrosItePedFalta);
        IF (vvOcorreramErrosItePedFalta = 'S') THEN
          RAISE e_ItePedFalta;
        END IF;    
        END LOOP;
      END IF;
      IF (pi_nId = 2) THEN
        UPDATE PCPEDI SET QT = 60 WHERE NUMPED = pi_nNumPed AND CODPROD = 75110;
      END IF;
      IF (pi_nId = 3) THEN
        UPDATE PCPEDI SET POSICAO = 'C', MOTIVOCANCELAMENTOMED = 'TESTE CANCELAMENTO' WHERE NUMPED = pi_nNumPed AND CODPROD = 106218;
      END IF;
    END;  
      
   /********************************************************************
    PROCEDURE : P_INSERE_LOG_ALTERACAO_DADOS
    DESCRIÇÃO : Insere Log de Alteração de Dados
    OBSERVACAO: pi_vTipoColuna = 'A' - Alfanumérico
                                 'N' - Number
    ********************************************************************/
    PROCEDURE P_INSERE_LOG_ALTERACAO_DADOS(pi_vTipoColuna      IN VARCHAR2,
                                           pi_nNumPed          IN NUMBER,
                                           pi_nCodProd         IN NUMBER,
                                           pi_nNumSeq          IN NUMBER,
                                           pi_vTabela          IN VARCHAR2,
                                           pi_nColuna          IN VARCHAR2,
                                           pi_vTextoNew        IN VARCHAR2,
                                           pi_vTextoOld        IN VARCHAR2,
                                           pi_vNumeroNew       IN NUMBER,
                                           pi_vNumeroOld       IN NUMBER,
                                           pi_vMotivoResumido  IN VARCHAR2,
                                           pi_vMotivoDetalhado IN VARCHAR2) IS
      vvPrograma VARCHAR2(80);
      vvHost     VARCHAR2(64);
      vvModule   VARCHAR2(30);
      vvOsUser   VARCHAR2(30);
    BEGIN
      
      BEGIN
      
        -- Nome do Programa
        BEGIN
           SELECT SUBSTR(program,1,80)
             INTO vvPrograma
             FROM usuarios_logados
            WHERE audsid = USERENV ('SESSIONID')
              AND rownum = 1;
        EXCEPTION
           WHEN NO_DATA_FOUND THEN
              vvPrograma := NULL;
        END;
    
        -- Sessão
        SELECT SUBSTR(sys_context ('USERENV', 'HOST'),1,64)
             , SUBSTR(sys_context ('USERENV', 'MODULE'),1,30)
             , SUBSTR(sys_context ('USERENV', 'OS_USER'),1,30)
          INTO vvHost
             , vvModule
             , vvOsUser
          FROM DUAL;
       
         -- Insere Log     
         INSERT INTO PCLOGALTERACAODADOS
                  ( DATA,
                    CODFUNC,
                    CODROTINA,
                    TABELA,
                    COLUNA,
                    TIPOVALOR,
                    VALORNUM,
                    VALORNUMANT,
                    VALORALFA,
                    VALORALFAANT,
                    OBSERVACOES,
                    OBSERVACOES2,
                    OBSERVACOES3,
                    MAQUINA,
                    PROGRAMA,
                    OSUSER )
           VALUES ( SYSDATE,
                    pi_nMatricula,
                    pi_nCodRotina,
                    pi_vTabela,
                    pi_nColuna,
                    pi_vTipoColuna,
                    DECODE(pi_vTipoColuna,'N',pi_vNumeroNew,NULL),
                    DECODE(pi_vTipoColuna,'N',pi_vNumeroOld,NULL),
                    DECODE(pi_vTipoColuna,'A',pi_vTextoNew,NULL),
                    DECODE(pi_vTipoColuna,'A',pi_vTextoOld,NULL),
                    SUBSTR(pi_vMotivoResumido ||' DO PEDIDO: ' || pi_nNumPed,1,100),
                    pi_vMotivoDetalhado,
                    DECODE(NVL(pi_nCodProd,0), 0, NULL, 'PRODUTO: ' || pi_nCodProd || ' NUMSEQ: ' || pi_nNumSeq),
                    vvHost,
                    vvModule,
                    vvOsUser);
                          
      EXCEPTION 
        WHEN OTHERS THEN
          NULL;
      END;
      
    END P_INSERE_LOG_ALTERACAO_DADOS;  
          
   /********************************************************************
    PROCEDURE: P_INSERE_LOG_PED_SESSAOANT
    DESCRIÇÃO: Insere Log de Commit do Pedido da Sessão anterior MED-2161
    ********************************************************************/
    PROCEDURE P_INSERE_LOG_PED_SESSAOANT IS
      viIdxLog          INTEGER;
      vnNumPedSessaoAnt NUMBER;
      vvMensagem      VARCHAR2(200);
    BEGIN
      -- Log somente se Gravar Pedido ou Mudar a Posição ou Cancelar Itens
      IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) THEN
        
        vnNumPedSessaoAnt := F_OBTER_PEDIDO_SESSAO_ANT(pi_nNumPed);
        vvMensagem        := vvMensagem || 'NUMPED SESSAO ANTERIOR: ' || vnNumPedSessaoAnt || CHR(13);
        vnNumPedSessaoAnt := F_OBTER_PEDIDOITENS_SESSAO_ANT(pi_nNumPed);
        vvMensagem        := vvMensagem || 'NUMPED ITENS SESSAO ANTERIOR: ' || vnNumPedSessaoAnt || CHR(13);
        
        viIdxLog := NVL(vtLogProcessamento.COUNT,0) + 1;
        vtLogProcessamento(viIdxLog).vnNumPed   := pi_nNumPed;
        vtLogProcessamento(viIdxLog).vvMensagem := vvMensagem;
        
      END IF;    
    END P_INSERE_LOG_PED_SESSAOANT;  
          
   /********************************************************************
    PROCEDURE: P_INSERE_LOG_PROCESSAMENTO
    DESCRIÇÃO: Insere Log de Processamento
    ********************************************************************/
    PROCEDURE P_INSERE_LOG_PROCESSAMENTO(pi_vMensagem IN VARCHAR2,
                                         pi_nCodProd  IN NUMBER DEFAULT NULL) IS
      viIdxLog INTEGER;
    BEGIN
      -- Log somente se Gravar Pedido ou Mudar a Posição ou Cancelar Itens
      IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) THEN
        viIdxLog := NVL(vtLogProcessamento.COUNT,0) + 1;
        vtLogProcessamento(viIdxLog).vnNumPed     := pi_nNumPed;
        IF (NVL(pi_nCodProd,0) > 0) THEN
          vtLogProcessamento(viIdxLog).vvMensagem := '[' || pi_nCodProd || '] ' ||  pi_vMensagem;
        ELSE
          vtLogProcessamento(viIdxLog).vvMensagem := pi_vMensagem;
        END IF;
      END IF;
    END P_INSERE_LOG_PROCESSAMENTO;  
  
   /********************************************************************
    PROCEDURE: P_GRAVA_LOG_PROCESSAMENTO
    DESCRIÇÃO: Gravar Log de Processamento
    ********************************************************************/
    PROCEDURE P_GRAVA_LOG_PROCESSAMENTO(pi_vRetorno  IN VARCHAR2 DEFAULT NULL,
                                        pi_vMsgErros IN VARCHAR2 DEFAULT NULL)
    IS PRAGMA AUTONOMOUS_TRANSACTION;
      vcMsgLog          CLOB;
      vnNumPedSessaoAnt NUMBER;
    BEGIN
    
      IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) THEN
    
        BEGIN
          -- Inicializa Msg
          vcMsgLog := 'INICIO LOG: ' || CHR(13);
          vnNumPedSessaoAnt := F_OBTER_PEDIDO_SESSAO_ANT(pi_nNumPed);
          vcMsgLog          := vcMsgLog || 'NUMPED SESSAO ANTERIOR: ' || vnNumPedSessaoAnt || CHR(13);
          vnNumPedSessaoAnt := F_OBTER_PEDIDOITENS_SESSAO_ANT(pi_nNumPed);
          vcMsgLog          := vcMsgLog || 'NUMPED ITENS SESSAO ANTERIOR: ' || vnNumPedSessaoAnt || CHR(13);
          IF (pi_vRetorno IS NOT NULL OR pi_vMsgErros IS NOT NULL) THEN
            vcMsgLog := vcMsgLog || 'RETORNO : ' || pi_vRetorno || ' ; MSGERROS : ' || pi_vMsgErros || CHR(13);
          END IF;
          IF (vtLogProcessamento.COUNT > 0) THEN
            -- Laço Processamento para Concatenar Logs
            FOR viIdxLog IN vtLogProcessamento.FIRST..vtLogProcessamento.LAST LOOP
              vcMsgLog := vcMsgLog || vtLogProcessamento(viIdxLog).vvMensagem || CHR(13);
            END LOOP;
          END IF;
          -- Grava Log do Pedido
          vcMsgLog := vcMsgLog || 'FIM LOG';
          INSERT INTO PCLOGPROCFATURMED
                    ( DTLOG,
                      NUMPED,
                      NUMCAR,
                      OBSERVACAO)
             VALUES ( SYSDATE
                    , pi_nNumPed
                    , -10
                    , vcMsgLog);
          -- Efetiva Transações
          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            NULL;
        END;
      
      END IF;
      
    END P_GRAVA_LOG_PROCESSAMENTO;
      
   /************************************************************************
    PROCEDURE  : P_GERAR_TEXTO_LOG_BLOQUEIO
    DESCRIÇÃO  : Gerar o Texto com a Observação de Log do Motivo do Bloqueio
    ************************************************************************/
    PROCEDURE P_GERAR_TEXTO_LOG_BLOQUEIO(pi_nCodMotivo          IN NUMBER,
                                         pi_vDescricao          IN VARCHAR2,
                                         pi_vDescricaoCompleta  IN VARCHAR2,
                                         pio_nCodMotivoBloqueio IN OUT NUMBER,
                                         pio_vMotivoBloqueio    IN OUT VARCHAR2,
                                         pio_vLogBloqueio       IN OUT VARCHAR2) IS
    BEGIN
      BEGIN
        -- Retornará o Código e Descrição do último Motivo de Bloqueio
        pio_nCodMotivoBloqueio := pi_nCodMotivo;
        pio_vMotivoBloqueio    := SUBSTR(pi_vDescricao,1,60);
        -- Retornará texto concatenado com todos os Motivos de Bloqueio
        IF (pio_vLogBloqueio IS NOT NULL) THEN
          pio_vLogBloqueio := pio_vLogBloqueio || CHR(13);
        ELSE
          pio_vLogBloqueio := pio_vLogBloqueio || CHR(13) || TO_CHAR(SYSDATE,'DD/MM/YYYY HH24:MI:SS') || ' - ' || NVL(pi_nCodMotivo,0) || ' - ' || pi_vDescricaoCompleta;
        END IF;      
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END; 
    END P_GERAR_TEXTO_LOG_BLOQUEIO;
    
   /************************************************************************
    PROCEDURE  : P_ATUALIZAR_TOTAIS_PEDIDO
    DESCRIÇÃO  : Procedure para Atualizar os Totais do Pedido
    ************************************************************************/
    PROCEDURE P_ATUALIZAR_TOTAIS_PEDIDO (pAtualizaVlTotal IN VARCHAR2,
                                         pNumPedAtualizar IN NUMBER) IS
    
      -- Totais do Pedido
      vnVlAtend     PCPEDC.VLATEND%TYPE;
      vnVlTotal     PCPEDC.VLTOTAL%TYPE;
      vnVlTabela    PCPEDC.VLTABELA%TYPE;
      vnvlbnftv1    PCPEDC.VLBONIFIC%TYPE;
      --
      nVLOUTRASDESP PCPEDC.VLOUTRASDESP%TYPE;
      nVLFRETE      PCPEDC.VLFRETE%TYPE;
      nVLDESCONTO   PCPEDC.VLDESCONTO%TYPE;
      nCONDVENDA    PCPEDC.CONDVENDA%TYPE;
      --
      vnVlCustoFin  PCPEDC.VLCUSTOFIN%TYPE;
      vnVlCustoReal PCPEDC.VLCUSTOREAL%TYPE;
      vnVlCustoCont PCPEDC.VLCUSTOCONT%TYPE;
      vnVlCustoRep  PCPEDC.VLCUSTOREP%TYPE;
      vnTotPeso     PCPEDC.TOTPESO%TYPE;
      vnTotVolume   PCPEDC.TOTVOLUME%TYPE;
      
    BEGIN
        
      -- Recalculo do cabecalho do pedido
      BEGIN
  
        -- Pesquisa Totais do Pedido
        SELECT SUM(DECODE(PCPEDC.CONDVENDA,
                          4,
                          0,
                          5,
                          0,
                          8,
                          0,
                          11,
                          0,
                          NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0))) VLATEND
             , SUM(DECODE(PCPEDC.CONDVENDA,
                          4,
                          0,
                          7,
                          0,
                          NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PTABELA, 0))) VLTABELA
             , SUM((NVL(PCPEDI.QT, 0) + NVL(PCPEDI.QTFALTA, 0)) * NVL(PCPEDI.PVENDA, 0)) VLTOTAL
             , PCPEDC.VLOUTRASDESP
             , PCPEDC.VLFRETE
             , PCPEDC.VLDESCONTO
             , PCPEDC.CONDVENDA
             , SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOFIN, 0))
             , SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOREAL, 0))
             , SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOCONT, 0))
             , SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOREP, 0))
             , SUM(NVL(PCPEDI.QT, 0) * NVL(PCPRODUT.VOLUME, 0))
             , SUM(PCPEDI.QT *
                   DECODE (
                       NVL(vrParametros.vUTILIZAVENDAPOREMBALAGEM,'N')
                     , 'S'
                     , DECODE (
                           NVL (
                               (SELECT NVL (PCEMBALAGEM.PESOBRUTO, 0)
                                FROM PCEMBALAGEM
                                WHERE PCEMBALAGEM.CODFILIAL = PCPEDC.CODFILIAL
                                  AND PCEMBALAGEM.CODPROD = PCPEDI.CODPROD
                                  AND PCEMBALAGEM.CODAUXILIAR =
                                          PCPEDI.CODAUXILIAR)
                             , 0)
                         , 0
                         , PCPRODUT.PESOBRUTO
                         , (SELECT NVL (PCEMBALAGEM.PESOBRUTO, 0) /
                                   DECODE (NVL (PCEMBALAGEM.QTUNIT, 0),
                                           0, 1,
                                           PCEMBALAGEM.QTUNIT)
                            FROM PCEMBALAGEM
                            WHERE PCEMBALAGEM.CODFILIAL = PCPEDC.CODFILIAL
                              AND PCEMBALAGEM.CODPROD = PCPEDI.CODPROD
                              AND PCEMBALAGEM.CODAUXILIAR = PCPEDI.CODAUXILIAR))
                     , PCPRODUT.PESOBRUTO))
          INTO vnVlAtend
             , vnVlTabela
             , vnVlTotal 
             , nVLOUTRASDESP
             , nVLFRETE
             , nVLDESCONTO
             , nCONDVENDA
             , vnVlCustoFin
             , vnVlCustoReal
             , vnVlCustoCont
             , vnVlCustoRep
             , vnTotVolume
             , vnTotPeso
          FROM PCPEDI
             , PCPEDC
             , PCPRODUT
         WHERE (PCPEDI.NUMPED    = PCPEDC.NUMPED)
           AND (PCPRODUT.CODPROD = PCPEDI.CODPROD)
           AND (PCPEDC.NUMPED    = pNumPedAtualizar)
         GROUP BY PCPEDC.VLOUTRASDESP
                , PCPEDC.VLFRETE
                , PCPEDC.VLDESCONTO
                , PCPEDC.CONDVENDA;
                
        -- Totais BNF em TV1
        SELECT SUM(PBONIFIC * QT)
          INTO vnvlbnftv1
          FROM PCPEDI
         WHERE NUMPED  = pNumPedAtualizar
           AND BONIFIC = 'F';       
    
        vnVlAtend  := ROUND(NVL(vnVlAtend,0)  + NVL(nVLOUTRASDESP,0) + NVL(nVLFRETE,0) - NVL(nVLDESCONTO,0) -
                            nvl(vnvlbnftv1,0), 2);
        vnVlTabela := ROUND(NVL(vnVlTabela,0) + NVL(nVLOUTRASDESP,0) + NVL(nVLFRETE,0) - NVL(nVLDESCONTO,0),2);
        vnVlTotal  := ROUND(NVL(vnVlTotal,0)  + NVL(nVLOUTRASDESP,0) + NVL(nVLFRETE,0) - NVL(nVLDESCONTO,0),2);
    
        IF (nCONDVENDA IN (4, 7)) THEN
          vnVlTabela := 0;
        END IF;
    
        IF (nCONDVENDA IN (4, 5, 8, 11)) THEN
          vnVlAtend := 0;
        END IF;
        
        -- Atualiza Total do Pedido
        UPDATE PCPEDC
           SET VLATEND     = NVL(vnVlAtend,0)
             , VLTABELA    = NVL(vnVlTabela,0)
             , VLCUSTOFIN  = vnVlCustoFin
             , VLCUSTOREAL = vnVlCustoReal
             , VLCUSTOCONT = vnVlCustoCont
             , VLCUSTOREP  = vnVlCustoRep
             , TOTVOLUME   = vnTotVolume
             , TOTPESO     = vnTotPeso           
         WHERE (NUMPED = pNumPedAtualizar);
         
        IF pAtualizaVlTotal = 'S' THEN
          UPDATE PCPEDC
             SET VLTOTAL     = NVL(vnVlTotal,0)
           WHERE (NUMPED = pNumPedAtualizar);
        END IF;
         
        -- Totais BNF em TV1
        IF (NVL(vnvlbnftv1,0) > 0) THEN
          UPDATE pcpedc
             SET vlbonific = vnvlbnftv1
           WHERE numped = pNumPedAtualizar;
        END IF;           
                
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          NULL;
        WHEN OTHERS THEN
          NULL;
      END;                    
      
    END P_ATUALIZAR_TOTAIS_PEDIDO;
    
   /*********************************************************************
    FUNÇÃO   : F_PODE_VALIDAR_BLOQUEIO
    DESCRIÇÃO: Verifica se pode validar o bloqueio 
               (para somente validar o bloqueio uma única vez)
    *********************************************************************/
    FUNCTION F_PODE_VALIDAR_BLOQUEIO(pi_nNumPed      IN NUMBER,
                                     pi_nCodRejeicao IN NUMBER) RETURN BOOLEAN IS
      vvInseriuReg VARCHAR2(1);
    BEGIN
    
      -- Verifica se ainda não inseriu o Registro
      BEGIN
        SELECT 'S'
          INTO vvInseriuReg
          FROM PCMED_VALIDACAO_ESTOQUE_RESERV
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0) -- Sem Plano de Pagamento
           AND (CODREJEICAO = pi_nCodRejeicao); 
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvInseriuReg := 'N';
      END; 

      -- Atualiza Retorno
      RETURN (vvInseriuReg = 'N');
      
    END F_PODE_VALIDAR_BLOQUEIO; 
    
    /*******************************************************************************
     Nome         : P_OBTEM_PMPF
     Descricão    : Procedimento Obter o PMPF dos Medicamentos
     Parâmetros   : ENTRADA:
                    pi_nCodSt   = Código da Tributação
                    pi_nCodProd = Código do Produto
                    pi_nCodCli  = Código do Cliente
                    SAIDA:
                    po_nPmPf    = PMPF
    **********************************************************************************/                                       
    PROCEDURE P_OBTEM_PMPF(pi_nCodSt   IN  VARCHAR2,
                           pi_nCodProd IN  NUMBER,
                           pi_nCodCli  IN  VARCHAR2,                               
                           po_nPmPf    OUT NUMBER) IS
      vvUsaPmPfBaseSt PCTRIBUT.USAPMPFBASEST%TYPE;
      vvEstEnt        PCCLIENT.ESTENT%TYPE;
    BEGIN
     
      -- Inicializa Retorno
      po_nPmPf := NULL;
    
      -- Pesquisa Tributação do Produto
      BEGIN
        SELECT PCTRIBUT.USAPMPFBASEST
          INTO vvUsaPmPfBaseSt
          FROM PCTRIBUT
         WHERE (PCTRIBUT.CODST = pi_nCodSt);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvUsaPmPfBaseSt := 'N';
      END;
      
      -- Se a Tributação Usa PMPF na Base do ST
      IF (vvUsaPmPfBaseSt = 'S') THEN
      
        -- Pesquisa UF do Cliente
        BEGIN
          SELECT ESTENT
            INTO vvEstEnt
            FROM PCCLIENT
           WHERE (CODCLI = pi_nCodCli);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvEstEnt := NULL;
        END;
      
        -- Pesquisa PMPF
        BEGIN
          SELECT PMPF
            INTO po_nPmPf
            FROM PCTABMEDABCFARMA
           WHERE (CODPROD = pi_nCodProd)
             AND (UF      = vvEstEnt);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            po_nPmPf := 0;
        END;
        
      END IF; -- Fim Condição: Se a Tributação Usa PMPF na Base do ST
      
    END P_OBTEM_PMPF;
      
   /**********************************************************************
    PROCEDURE  : atualizar_prazos_datavenc_fixa
    DESCRIÇÃO  : Atualizar os Prazos a partir das datas de vencimento fixa
    OBSERVACAO : PACKAGE FATURAMENTO possui procedimento similar
    **********************************************************************/
    PROCEDURE atualizar_prazos_datavenc_fixa(pi_dDtEntrega IN PCNFSAID.DTENTREGA%TYPE,
                                             pi_dDtVenc1   IN PCPLPAG.DTVENC1%TYPE,
                                             pi_dDtVenc2   IN PCPLPAG.DTVENC2%TYPE,
                                             pi_dDtVenc3   IN PCPLPAG.DTVENC3%TYPE,
                                             pio_nPrazo1   IN OUT PCPLPAG.PRAZO1%TYPE,
                                             pio_nPrazo2   IN OUT PCPLPAG.PRAZO2%TYPE,
                                             pio_nPrazo3   IN OUT PCPLPAG.PRAZO3%TYPE) IS
    BEGIN
  
      IF (pi_dDtVenc1 IS NOT NULL) THEN
  
        -- Prazo 1
        pio_nPrazo1 := (pi_dDtVenc1 - pi_dDtEntrega);
        IF (pio_nPrazo1 < 0) THEN
          pio_nPrazo1 := 0;
        END IF;
  
        IF (pi_dDtVenc2 IS NOT NULL) THEN
  
          -- Prazo 2
          pio_nPrazo2 := (pi_dDtVenc2 - pi_dDtEntrega);
          IF (pio_nPrazo2 < 0) THEN
            pio_nPrazo2 := 0;
          END IF;
  
          IF (pi_dDtVenc3 IS NOT NULL) THEN
  
            -- Prazo 3
            pio_nPrazo3 := (pi_dDtVenc3 - pi_dDtEntrega);
            IF (pio_nPrazo3 < 0) THEN
              pio_nPrazo3 := 0;
            END IF;
  
          END IF;
  
        END IF;
  
      END IF;
    END atualizar_prazos_datavenc_fixa;
    
   /*********************************************************************
    PROCEDIMENTO : P_CARREGAR_ARRAY_PARCELAS
    DESCRIÇÃO    : Procedimento para carregar Array Auxiliar para uno
                   na Carga da Tabela Temporária com os Títulos a Receber
                   (Usado em Multiplos Planos de Pagamento)
    OBSERVACAO   : PACKAGE FATURAMENTO possui procedimento similar
    *********************************************************************/
    PROCEDURE P_CARREGAR_ARRAY_PARCELAS(pi_nCodPlPag      IN  NUMBER,
                                        pi_dDtEntrega     IN  DATE,
                                        po_aArrayParcelas OUT TTArrayParcelas,
                                        po_nPrazoMedio    OUT NUMBER) IS
  
      -- Array para Armazenar os Dados do Plano de Pagamento
      TYPE TRecDadosPlPag IS RECORD(
           vnCodPlPag PCPLPAG.CODPLPAG%TYPE,
           vnPrazo1   PCPLPAG.PRAZO1%TYPE,
           vnPrazo2   PCPLPAG.PRAZO2%TYPE,
           vnPrazo3   PCPLPAG.PRAZO3%TYPE,
           vnPrazo4   PCPLPAG.PRAZO4%TYPE,
           vnPrazo5   PCPLPAG.PRAZO5%TYPE,
           vnPrazo6   PCPLPAG.PRAZO6%TYPE,
           vnPrazo7   PCPLPAG.PRAZO7%TYPE,
           vnPrazo8   PCPLPAG.PRAZO8%TYPE,
           vnPrazo9   PCPLPAG.PRAZO9%TYPE,
           vnPrazo10  PCPLPAG.PRAZO10%TYPE,
           vnPrazo11  PCPLPAG.PRAZO11%TYPE,
           vnPrazo12  PCPLPAG.PRAZO12%TYPE,
           vdDtVenc1  PCPLPAG.DTVENC1%TYPE,
           vdDtVenc2  PCPLPAG.DTVENC2%TYPE,
           vdDtVenc3  PCPLPAG.DTVENC3%TYPE,
           vvFormaParcelamento PCPLPAG.FORMAPARCELAMENTO%TYPE
           );
      vrDadosPlPag    TRecDadosPlPag;
  
      -- Contador de Vencimentos
      viContaVencVariavel INTEGER;
  
      -- Record para armazenar dados do Plano Dia Fixo - 4663.107370.2018
      TYPE TRecDadosPlPagDiaFixo IS RECORD(
           carencia    PCPLPAG.diascarencia%TYPE,
           diafixo     PCPLPAG.diafixo%TYPE,
           numparcelas PCPLPAG.numeroparcelasdiafixo%TYPE);
      vrDadosPlPagDiaFixo TRecDadosPlPagDiaFixo;
      -- Variáveis para Vencimento da Parcela Dia Fixo - 4663.107370.2018
      viVencDiaFixo          INTEGER;
      vdDtVencParcelaDiaFixo DATE;
  
      -- DDMEDICA-570   
      -- Record para armazenar dados do Plano Mensal
      TYPE TRecDadosPlPagMensal IS RECORD(
           numdiascarencia  PCPLPAG.diascarencia%TYPE,
           numparcelas      PCPLPAG.numparcelas%TYPE);
      vrDadosPlPagMensal TRecDadosPlPagMensal;
      -- Variáveis para Vencimento da Parcela Dia Fixo - 4663.107370.2018
      viVencMensal          INTEGER;
      vdDtVencParcelaMensal DATE;
      
      -- Prazo Médio Plano Variável - DDMEDICA-5675
      vnNumDiasPlanoVariavel PCPLPAG.NUMDIAS%TYPE;
  
    BEGIN
  
      -- Inicializa Retorno
      po_aArrayParcelas.DELETE;
      po_nPrazoMedio := 0;
  
      -- Pesquisa informações do Plano de Pagamento
      BEGIN
        SELECT PCPLPAG.PRAZO1
             , PCPLPAG.PRAZO2
             , PCPLPAG.PRAZO3
             , PCPLPAG.PRAZO4
             , PCPLPAG.PRAZO5
             , PCPLPAG.PRAZO6
             , PCPLPAG.PRAZO7
             , PCPLPAG.PRAZO8
             , PCPLPAG.PRAZO9
             , PCPLPAG.PRAZO10
             , PCPLPAG.PRAZO11
             , PCPLPAG.PRAZO12
             , PCPLPAG.DTVENC1
             , PCPLPAG.DTVENC2
             , PCPLPAG.DTVENC3
             , PCPLPAG.FORMAPARCELAMENTO
          INTO vrDadosPlPag.vnPrazo1
             , vrDadosPlPag.vnPrazo2
             , vrDadosPlPag.vnPrazo3
             , vrDadosPlPag.vnPrazo4
             , vrDadosPlPag.vnPrazo5
             , vrDadosPlPag.vnPrazo6
             , vrDadosPlPag.vnPrazo7
             , vrDadosPlPag.vnPrazo8
             , vrDadosPlPag.vnPrazo9
             , vrDadosPlPag.vnPrazo10
             , vrDadosPlPag.vnPrazo11
             , vrDadosPlPag.vnPrazo12
             , vrDadosPlPag.vdDtVenc1
             , vrDadosPlPag.vdDtVenc2
             , vrDadosPlPag.vdDtVenc3
             , vrDadosPlPag.vvFormaParcelamento
          FROM PCPLPAG
         WHERE (PCPLPAG.CODPLPAG = pi_nCodPlPag);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrDadosPlPag.vnPrazo1  := NULL;
          vrDadosPlPag.vnPrazo2  := NULL;
          vrDadosPlPag.vnPrazo3  := NULL;
          vrDadosPlPag.vnPrazo4  := NULL;
          vrDadosPlPag.vnPrazo5  := NULL;
          vrDadosPlPag.vnPrazo6  := NULL;
          vrDadosPlPag.vnPrazo7  := NULL;
          vrDadosPlPag.vnPrazo8  := NULL;
          vrDadosPlPag.vnPrazo9  := NULL;
          vrDadosPlPag.vnPrazo10 := NULL;
          vrDadosPlPag.vnPrazo11 := NULL;
          vrDadosPlPag.vnPrazo12 := NULL;
          vrDadosPlPag.vdDtVenc1 := NULL;
          vrDadosPlPag.vdDtVenc2 := NULL;
          vrDadosPlPag.vdDtVenc3 := NULL;
          vrDadosPlPag.vvFormaParcelamento := NULL;
      END;
  
      -- Contador de Vencimentos Variáveis
      viContaVencVariavel := 0;
  
      -- ORIGEM = DATAS DE VENCIMENTO INFORMADAS NO PEDIDO ----------------------------------------
      IF (NVL(vrDadosPlPag.vvFormaParcelamento,'C') = 'V') THEN
  
        -- Preeche Arrray a partir dos vencimentos pré-informados
        FOR vc_VencVariavel IN (SELECT (PCPEDCVCTO.DTVENC - TRUNC(pi_dDtEntrega)) PRAZO
                                  FROM PCPEDCVCTO
                                 WHERE (PCPEDCVCTO.NUMPED = pi_nNumPed)-->> Depois de Faturar
                                 ORDER BY 1 -- PRAZO
                                ) LOOP
          viContaVencVariavel := NVL(viContaVencVariavel,0) + 1;
          po_aArrayParcelas(viContaVencVariavel) := NVL(vc_VencVariavel.PRAZO,0);
        END LOOP;  
        -- DDMEDICA-5675 - Para não ficar sem Prazo Médio, pega do Plano      
        IF (viContaVencVariavel = 0) THEN
          BEGIN
            SELECT NUMDIAS
              INTO vnNumDiasPlanoVariavel
              FROM PCPLPAG
             WHERE (CODPLPAG = pi_nCodPlPag);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vnNumDiasPlanoVariavel := 0;
          END;
          viContaVencVariavel := NVL(viContaVencVariavel,0) + 1;
          po_aArrayParcelas(viContaVencVariavel) := NVL(vnNumDiasPlanoVariavel,0);
        END IF;
  
      -- 4663.107370.2018 - Implementação Regra Data Fixa   
      ELSIF (vrDadosPlPag.vvFormaParcelamento = 'T') THEN
        
        BEGIN
          SELECT NVL(pcplpag.diascarencia, 0),
                 NVL(pcplpag.diafixo, 1),
                 NVL(pcplpag.numeroparcelasdiafixo, 1)
            INTO vrDadosPlPagDiaFixo.carencia, 
                 vrDadosPlPagDiaFixo.diafixo, 
                 vrDadosPlPagDiaFixo.numparcelas
            FROM pcplpag
           WHERE (pcplpag.codplpag = pi_nCodPlPag);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrDadosPlPagDiaFixo.carencia    := NULL;
            vrDadosPlPagDiaFixo.diafixo     := NULL;
            vrDadosPlPagDiaFixo.numparcelas := NULL;
        END;
        
        -- Se Calcula Parcelas Dia Fixo
        IF (NVL(vrDadosPlPagDiaFixo.numparcelas,0) > 0) THEN
  
          BEGIN
          
            viVencDiaFixo := 0;
          
            FOR vi IN 1 .. vrDadosPlPagDiaFixo.numparcelas LOOP
            
              -- Se Fevereiro for o mês do Vencimento e no Plano de Pagamento estiver como dia fixo igual ou superior a 29 dias
              IF ((TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE), NVL(viVencDiaFixo,0)),'MM') = '02') AND
                  (NVL(vrDadosPlPagDiaFixo.diafixo,0) >= 29)) THEN
    
                -- Pega o último dia de fevereiro a partir do primeiro dia do próximo mês - 1
                SELECT TO_DATE(TO_CHAR('01') || '/' ||
                               TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE), viVencDiaFixo + 1),
                                       'MM/YYYY'),
                               'DD/MM/YYYY') - 1
                  INTO vdDtVencParcelaDiaFixo
                  FROM DUAL;
    
              -- Se não for Fevereiro
              ELSE
    
                SELECT TO_DATE(TO_CHAR(vrDadosPlPagDiaFixo.diafixo) || '/' ||
                               TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE), viVencDiaFixo),
                                       'MM/YYYY'),
                               'DD/MM/YYYY')
                  INTO vdDtVencParcelaDiaFixo
                  FROM DUAL;
    
              END IF;
    
              IF vi = 1 THEN
                IF (TRUNC(SYSDATE) + vrDadosPlPagDiaFixo.carencia) >= vdDtVencParcelaDiaFixo THEN
                  vdDtVencParcelaDiaFixo := ADD_MONTHS(vdDtVencParcelaDiaFixo, 1);
                  viVencDiaFixo          := viVencDiaFixo + 2;
                ELSE
                  viVencDiaFixo := viVencDiaFixo + 1;
                END IF;
              ELSE
                viVencDiaFixo := viVencDiaFixo + 1;
              END IF;
            
              viContaVencVariavel := NVL(viContaVencVariavel,0) + 1;
              po_aArrayParcelas(viContaVencVariavel) := (vdDtVencParcelaDiaFixo - TRUNC(SYSDATE));
              IF (po_aArrayParcelas(viContaVencVariavel) < 0) THEN
                po_aArrayParcelas(viContaVencVariavel) := 0;
              END IF;
            
            END LOOP;
            
          EXCEPTION
            WHEN OTHERS THEN
              NULL;
          END;      
        
        END IF; -- Fim Condição: Se Calcula Parcelas Dia Fixo
      
      -- DDMEDICA-570 - Implementação Regra Mensal
      ELSIF (vrDadosPlPag.vvFormaParcelamento = 'M') THEN
  
        BEGIN
          SELECT NVL(pcplpag.numdiascarencia, 0),
                 NVL(pcplpag.numparcelas, 1)
            INTO vrDadosPlPagMensal.numdiascarencia,
                 vrDadosPlPagMensal.numparcelas
            FROM pcplpag
           WHERE (pcplpag.codplpag = pi_nCodPlPag);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrDadosPlPagMensal.numdiascarencia := NULL;
            vrDadosPlPagMensal.numparcelas := NULL;
        END;
  
        -- Se Calcula Parcelas Mensal
        IF (NVL(vrDadosPlPagMensal.numparcelas,0) > 0) THEN
  
          BEGIN
  
            viVencMensal := 0;
  
            FOR vi IN 1 .. vrDadosPlPagMensal.numparcelas LOOP
  
              IF (vi = 1) THEN
                vdDtVencParcelaMensal := (pi_dDtEntrega + NVL(vrDadosPlPagMensal.numdiascarencia,0));
              ELSE
                vdDtVencParcelaMensal := ADD_MONTHS((pi_dDtEntrega + NVL(vrDadosPlPagMensal.numdiascarencia,0)), (vi - 1));
              END IF;
  
              viContaVencVariavel := NVL(viContaVencVariavel,0) + 1;
              po_aArrayParcelas(viContaVencVariavel) := (vdDtVencParcelaMensal - pi_dDtEntrega);
              IF (po_aArrayParcelas(viContaVencVariavel) < 0) THEN
                po_aArrayParcelas(viContaVencVariavel) := 0;
              END IF;
  
            END LOOP;
  
          EXCEPTION
            WHEN OTHERS THEN
              NULL;
          END;
  
        END IF; -- Fim Condição: Se Calcula Parcelas Dia Fixo
  
      END IF; -- FIM CONDIÇÃO: -- Se Vencimemto Variável
      
      -- Se não preencheu os Parcelamentos Variáveis
      IF (NVL(viContaVencVariavel,0) = 0) THEN
      
        -- Se preencheu a Data Vencimento Fixa
        IF (vrDadosPlPag.vdDtVenc1 IS NOT NULL) THEN
    
          atualizar_prazos_datavenc_fixa(pi_dDtEntrega,
                                         vrDadosPlPag.vdDtVenc1,
                                         vrDadosPlPag.vdDtVenc2,
                                         vrDadosPlPag.vdDtVenc3,
                                         vrDadosPlPag.vnPrazo1,
                                         vrDadosPlPag.vnPrazo2,
                                         vrDadosPlPag.vnPrazo3);
                                         
          po_aArrayParcelas(1) := NVL(vrDadosPlPag.vnPrazo1,0);
          IF (vrDadosPlPag.vdDtVenc2 IS NOT NULL) THEN
            po_aArrayParcelas(2) := NVL(vrDadosPlPag.vnPrazo2,0);
            IF (vrDadosPlPag.vdDtVenc3 IS NOT NULL) THEN
              po_aArrayParcelas(3) := NVL(vrDadosPlPag.vnPrazo3,0);
            END IF;
          END IF;
                                         
        ELSE
        
          -- Laço de Prazos
          FOR viIdxPrazo IN 1..12 LOOP
      
            -- Pega Prazo
            IF    ((viIdxPrazo = 1)) THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo1;
            ELSIF ((viIdxPrazo = 2) AND (NVL(vrDadosPlPag.vnPrazo2,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo2;
            ELSIF ((viIdxPrazo = 3) AND (NVL(vrDadosPlPag.vnPrazo3,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo3;
            ELSIF ((viIdxPrazo = 4) AND (NVL(vrDadosPlPag.vnPrazo4,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo4;
            ELSIF ((viIdxPrazo = 5) AND (NVL(vrDadosPlPag.vnPrazo5,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo5;
            ELSIF ((viIdxPrazo = 6) AND (NVL(vrDadosPlPag.vnPrazo6,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo6;
            ELSIF ((viIdxPrazo = 7) AND (NVL(vrDadosPlPag.vnPrazo7,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo7;
            ELSIF ((viIdxPrazo = 8) AND (NVL(vrDadosPlPag.vnPrazo8,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo8;
            ELSIF ((viIdxPrazo = 9) AND (NVL(vrDadosPlPag.vnPrazo9,0) > 0))   THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo9;
            ELSIF ((viIdxPrazo = 10) AND (NVL(vrDadosPlPag.vnPrazo10,0) > 0)) THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo10;
            ELSIF ((viIdxPrazo = 11) AND (NVL(vrDadosPlPag.vnPrazo11,0) > 0)) THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo11;
            ELSIF ((viIdxPrazo = 12) AND (NVL(vrDadosPlPag.vnPrazo12,0) > 0)) THEN
              po_aArrayParcelas(viIdxPrazo) := vrDadosPlPag.vnPrazo12;
            END IF;
      
          END LOOP; -- Fim Laço de Prazos
          
        END IF; -- Fim Condição Se preencheu a Data Vencimento Fixa
  
      END IF; -- Fim Condição: Se não preencheu os Parcelamentos Variáveis
      
      -- Calcula Prazo Médio
      IF (po_aArrayParcelas.COUNT > 0) THEN
        FOR viPrazo IN po_aArrayParcelas.FIRST..po_aArrayParcelas.LAST LOOP
          po_nPrazoMedio := NVL(po_nPrazoMedio,0) + NVL(po_aArrayParcelas(viPrazo),0);
        END LOOP;
        po_nPrazoMedio := TRUNC((NVL(po_nPrazoMedio,0) / po_aArrayParcelas.COUNT));
      END IF;
  
    END P_CARREGAR_ARRAY_PARCELAS;
  
   /*********************************************************************
    PROCEDIMENTO : P_ATU_CRITICAS_VALOR_MINIMO
    DESCRIÇÃO    : Procedimento para atualizar a Tabela Temporária de
                   Críticas de Valor Mínimo
    *********************************************************************/
    PROCEDURE P_ATU_CRITICAS_VALOR_MINIMO(pi_nQtdePedido          IN NUMBER,
                                          pi_nQtdeComCorte        IN NUMBER,
                                          pi_nPVenda              IN NUMBER,
                                          pi_nCodPlPagItem        IN NUMBER,
                                          pi_nCodProd             IN NUMBER,
                                          pi_nNumSeq              IN NUMBER,
                                          pi_nSt                  IN NUMBER,
                                          pi_nPBaseRca            IN NUMBER,
                                          pi_nStPBaseRca          IN NUMBER,
                                          pi_vBonific             IN VARCHAR2,
                                          pi_nCodMotivoPosicaoMed IN NUMBER,
                                          pi_vMotivoPosicaoMed    IN VARCHAR2,
                                          pi_vGrupoFaturamento    IN VARCHAR2,
                                          pi_vTipoPrazoMedicam    IN VARCHAR2,
                                          pi_nCodLinhaPrazo       IN NUMBER,
                                          pi_nVlCustoFin          IN NUMBER,
                                          pi_nCodPromocaoItem     IN NUMBER) IS
                               
      -- Qtde. para usar nos Cálculos dos Valores Mínimos
      vnQtdeValidaValorMinimo             NUMBER;
      vnQtdeValidaVlMinComSemCorte        NUMBER;
                                          
      -- Dados do Plano de Pamento do Item  
      TYPE TRecPlanoPagto                 IS RECORD(
           vnNumItensMinimo               PCPLPAG.NUMITENSMINIMO%TYPE,
           vnVlMinPedido                  PCPLPAG.VLMINPEDIDO%TYPE,
           vDescricao                     PCPLPAG.DESCRICAO%TYPE,
           vnNumDias                      PCPLPAG.NUMDIAS%TYPE,
           vnMargemMin                    PCPLPAG.MARGEMMIN%TYPE);
      vrPlanoPagto                        TRecPlanoPagto;
      
      -- Array de Parcelas
      vtArrayParcelas                     TTArrayParcelas;
      
      -- Outras Variáveis
      viQtdeParcelas                      INTEGER;
      vnValorAtingidoBoletoBancario       NUMBER;
      vnQtValidaSaldoRca                  NUMBER;
      vnSaldoItemRca                      NUMBER;                          
      vvVendaPermitida                    VARCHAR2(1);
      vvSolucaoP4                         VARCHAR2(2000);
      vvSolucaoPL                         VARCHAR2(2000);
      -- MEDICA-477
      vvTipoMovCCRca                      PCCONSUM.TIPOMOVCCRCA%TYPE;
      
      -- DDMEDICA-1586
      vvDescricaoRejeicao                 VARCHAR2(2000);
      vvMotivoPosicao                     VARCHAR2(2000);

      -- Plano do Cliente
      vnCodPlPagCliente                   PCCLIENT.CODPLPAG%TYPE;  
      vvDescricaoPlPagCliente             PCPLPAG.DESCRICAO%TYPE;
      vtArrayParcelasPlPagCliente         TTArrayParcelas;
      vnPrazoMedioPlPagCliente            NUMBER;  
      vvMsgPrazoMedioCliente              VARCHAR2(2000);
      
      -- Retorno da Validação do Alvará
      TYPE TRecRetAlvara                  IS RECORD(
           vvPodeComprarProduto           VARCHAR2(1),
           vvMotivoNaoPodeComprar         VARCHAR2(2000),
           vnQtdeLimite                   NUMBER);
      vrRetAlvara                         TRecRetAlvara;
      
      -- Ação do Alvará
      vvAuxAcaoAlvara                     VARCHAR2(1);
      
      -- DDMEDICA-3017 - Promoção do Pedido tem Plano Mandatório
      vvPrazoPlPagMandatorio              PCPROMOCAOMED.PRAZOPLPAGMANDATORIO%TYPE;
      vnCodPlPagMandatorioPromocao        PCPLPAG.CODPLPAG%TYPE;
      
      -- DDMEDICA-3103
      vvBonificAltDebCredRca              PCPEDC.BONIFICALTDEBCREDRCA%TYPE;

      -- DDMEDICA-3918 - Valor Total Atingido
      vnValorTotalAtingidoValidaMin       NUMBER;
      
      -- DDMEDICA-5009 - Cota de Verba da Promoção
      viContaCotaVerba                    INTEGER;
      vvDescricaoCotaVerba                VARCHAR2(2000);
      
      -- DDMEDICA-5401 - Ação para Verba de Promoção já Apurada
      vvAcaoVerbaPromocaoApurada          VARCHAR2(1);
      
      -- Variáveis de Controle do Canal Autorizador PBM - CA PBM
      vnIntegradoraCaPbm                  PCINTEGRADORA.INTEGRADORA%TYPE;
      vnNumPedOperLogCaPbm                PCPEDCOMPRAOPERLOGCAB.NUMPED%TYPE;
	  vvPosicaoOrcamento                  PCORCAVENDAI.POSICAO%TYPE;
            
      -- DDMEDICA-3918 - Bloqueios Automáticos
      CURSOR C_PCBLOQUEIO(PNUMPED            NUMBER,
                          PCODCLI            NUMBER,
                          PCONDVENDA         NUMBER,
                          PCODPRACA          NUMBER,
                          PCODPLPAG          NUMBER,
                          PCODFUNC           NUMBER,
                          PCODCOB            VARCHAR2,
                          PFRETEDESPACHO     VARCHAR2,
                          PORIGEMPED         VARCHAR2,
                          PCLIENTEMONITORADO VARCHAR2,
                          PVALORPEDIDO       NUMBER,
                          PCODFILIAL         VARCHAR2,
                          PCODPROD           NUMBER) IS
        SELECT CODMOTBLOQUEIO,
               CODMOTIVO,
               (SELECT UPPER(descricao)
                  FROM pcmotbloqueio
                 WHERE codmotivo = B1.CODMOTIVO) DESCRICAO_MOTIVO
          FROM PCBLOQUEIO B1
         WHERE NVL(CodProd, PCODPROD) = PCODPROD
           AND NVL(CODCLI, PCODCLI) = PCODCLI
           AND NVL(CONDVENDA, PCONDVENDA) = PCONDVENDA
           AND NVL(CODPRACA, PCODPRACA) = PCODPRACA
           AND NVL(CODPLPAG, PCODPLPAG) = PCODPLPAG
           AND NVL(MATRICULAEMPR, PCODFUNC) = PCODFUNC
           AND NVL(CODCOB, PCODCOB) = PCODCOB
    --       AND NVL(FRETEDESPACHO, PFRETEDESPACHO) = PFRETEDESPACHO
           AND ((FRETEDESPACHO = PFRETEDESPACHO) OR (NVL(FRETEDESPACHO,'T') = 'T'))
           AND ((ORIGEMPED = PORIGEMPED) OR (ORIGEMPED = 'O'))
           AND ((NVL(B1.clientemonitorado, 'N') = 'N') OR
               ((B1.clientemonitorado = 'S') AND
               (PClientemonitorado = 'S')))
           AND ((PVALORPEDIDO > NVL(VLMAXPEDIDO,PVALORPEDIDO)) OR (VLMAXPEDIDO IS NULL))
           -- DDVENDAS-31792  
           AND (NOT EXISTS (SELECT *
                              FROM PCBLOQUEIOMULT M
                             WHERE M.CODMOTBLOQUEIO = B1.CODMOTBLOQUEIO
                               AND M.TIPO IN (1, 2, 3, 4, 5, 6)))
               OR EXISTS (
                    SELECT * FROM PCBLOQUEIO B
                            WHERE ((ORIGEMPED = PORIGEMPED) OR (B.ORIGEMPED = 'O'))
                              AND B1.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO
                              AND NVL(MATRICULAEMPR, PCODFUNC) = PCODFUNC
                              AND ((NVL(B.CLIENTEMONITORADO, 'N') = 'N') OR
                                   ((B.CLIENTEMONITORADO = 'S') AND
                                   (PCLIENTEMONITORADO = 'S')))
                              AND ((PVALORPEDIDO > NVL(VLMAXPEDIDO,PVALORPEDIDO)) OR (VLMAXPEDIDO IS NULL))
                              AND ((FRETEDESPACHO = PFRETEDESPACHO) OR (NVL(FRETEDESPACHO,'T') = 'T')) -- DDVENDAS-31792
                              AND (NVL(CONDVENDA, PCONDVENDA) = PCONDVENDA)
                              AND EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO )
                              AND (EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 1 AND CODIGOA = PCODFILIAL)
                                          OR (/*PCODFILIAL IS NULL AND  */
                                          NOT EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 1)))
                              AND (EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 2 AND CODIGOA = TO_CHAR(PCODPRACA))
                                          OR (B.CODPRACA IS NULL AND
                                          NOT EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 2)))
                              AND (EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 3 AND CODIGOA = TO_CHAR(PCODCLI))
                                          OR (B.CODCLI IS NULL AND
                                          NOT EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 3)))
                              AND (EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 4 AND CODIGOA = PCODCOB)
                                          OR (B.CODCOB IS NULL AND
                                          NOT EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 4)))
                              AND (EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 5 AND CODIGOA = TO_CHAR(PCODPLPAG))
                                          OR (B.CODPLPAG IS NULL
                                          AND NOT EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 5)))
                              AND (EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 6 AND CODIGOA = TO_CHAR(PCODPROD))
                                          OR (B.CODPROD IS NULL AND
                                          NOT EXISTS(SELECT * FROM PCBLOQUEIOMULT M WHERE M.CODMOTBLOQUEIO = B.CODMOTBLOQUEIO AND M.TIPO = 6)))
                              )
         ORDER BY CODMOTBLOQUEIO;

      VCPCBLOQUEIO C_PCBLOQUEIO%ROWTYPE;
      
    BEGIN
  
      --------------------------------------------------------------------------
      -- DEFINIÇÃO DA QUANTIDADE QUE SERÁ UTILIZADA NA VALIDAÇÃO DO VALOR MÍNIMO
      --------------------------------------------------------------------------
      -- OPERADOR LOGÍSTICO
      IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') = 'S') THEN
        -- Ao validar o Valor Mínimo, que ocorre antes de Baixar o Estoque, o campo "PCCONDICAOVENDA.TIPOVALORMINIMO"
        -- dá a opção se Validar pelo Valor Total ou pelo Valor Total menos o Corte
        IF (NVL(vrCondicaoVenda.vvTipoValorMinimo,'C') = 'A')  THEN
          -- Após o Corte
          vnQtdeValidaValorMinimo := NVL(pi_nQtdeComCorte,0);
          vvSolucaoP4             := ' com estoque disponivel';
        ELSE
          -- Antes do Corte
          vnQtdeValidaValorMinimo := NVL(pi_nQtdePedido,0);
          vvSolucaoP4             := '';
        END IF;
      -- DEMAIS VENDAS
      ELSE
        -- Ao validar o Valor Mínimo, que ocorre antes de Baixar o Estoque, o Parâmetro "ACEITAVENDASEMEST"
        -- dá a opção se Validar pelo Valor Total ou pelo Valor Total menos o Corte
        IF (NVL(vrParametros.vACEITAVENDASEMEST,'N') = 'N')  THEN
          vnQtdeValidaValorMinimo := NVL(pi_nQtdeComCorte,0);
          vvSolucaoP4             := ' com estoque disponivel';
        ELSE
          vnQtdeValidaValorMinimo := NVL(pi_nQtdePedido,0);
          vvSolucaoP4             := '';
        END IF;
      END IF;
      
      --------------------------------------------------
      -- Calcula Valor Acumulado do Pedido até o momento
      --------------------------------------------------
      SELECT SUM(PCMED_VALIDACAO_ESTOQUE_RESERV.VALORATINGIDO)
        INTO vnValorTotalAtingidoValidaMin
        FROM PCMED_VALIDACAO_ESTOQUE_RESERV
       WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.NUMPED      = pi_nNumPed)
         AND (PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO = -1);
      
      -------------------------------------------------
      -- Pesquisa Valores do Plano de Pagamento do Item
      -------------------------------------------------
      BEGIN
        SELECT DESCRICAO
             , NUMITENSMINIMO
             , VLMINPEDIDO
             , MARGEMMIN
          INTO vrPlanoPagto.vDescricao
             , vrPlanoPagto.vnNumItensMinimo
             , vrPlanoPagto.vnVlMinPedido
             , vrPlanoPagto.vnMargemMin
          FROM PCPLPAG
         WHERE (CODPLPAG = pi_nCodPlPagItem);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrPlanoPagto.vDescricao       := NULL;
          vrPlanoPagto.vnNumItensMinimo := 0;
          vrPlanoPagto.vnVlMinPedido    := 0;  
          vrPlanoPagto.vnMargemMin      := 0;
      END;
      
      -----------------------------------------------------------------------
      -- Exceção na Integradora para não validar Mínimo do Plano de Pagamento
      -----------------------------------------------------------------------
      IF (NVL(vrParametros.vIGNORARMINIMOPLANOPLPAG,'N') = 'S') THEN
        vrPlanoPagto.vnNumItensMinimo := 0;
        vrPlanoPagto.vnVlMinPedido    := 0;  
      END IF;
    
      ----------------------------
      -- Pesquisa Qtde de Parcelas
      ----------------------------
      -- Carrega Array de Parcelas
      P_CARREGAR_ARRAY_PARCELAS(pi_nCodPlPagItem,
                                vrPedido.vdDtEntrega,
                                vtArrayParcelas,
                                vrPlanoPagto.vnNumDias);        
      -- Calcula Qtde de Parcelas                                  
      viQtdeParcelas := NVL(vtArrayParcelas.COUNT,0);
              
      --------------------------------------------------------------------------------------
      -- CRÍTICA - TOTALIZAÇÃO DO PEDIDO - Para permitir usa o vnValorTotalAtingidoValidaMin
      --------------------------------------------------------------------------------------
      P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                    , pi_nNumPed
                                    , 0  -- Sem Plano de Pagamento
                                    , -1 -- CODREJEICAO
                                    , 'I'
                                    , 'Total do Pedido com Corte'
                                    , 0
                                    , 0  -- Sem Validação
                                    , (NVL(pi_nPVenda,0) * NVL(pi_nQtdeComCorte,0))
                                    , 'X'
                                    , vrAcaoSobreCritica.vvParamsClienteSemCredito
                                    , NULL -- Código do Motivo
                                    , NULL -- Código Motivo Bloqueio
                                    , 'Total do Pedido com Corte'
                                    , NULL
                                    , vvSolucaoP4 );
              
      -------------------------------------------------------------
      -- CRÍTICA - Quantidade de Itens Máximo do Plano de Pagamento
      -------------------------------------------------------------
      IF (vrPedido.vnCondVenda NOT IN (4,5,11))     AND
         (NVL(vrPlanoPagto.vnNumItensMinimo,0) > 0) THEN
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + DECODE(NVL(vnQtdeValidaValorMinimo,0),0,0,1)
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = pi_nCodPlPagItem)
           AND (CODREJEICAO = 1); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , pi_nCodPlPagItem
                    , 1 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoNumItensMinPlPag
                    , SUBSTR('Qtde. Mínima de Itens do Plano Pagto: ' || NVL(pi_nCodPlPagItem,0) || ' - ' || vrPlanoPagto.vDescricao,1,100)
                    , 523
                    , vrPlanoPagto.vnNumItensMinimo 
                    , DECODE(NVL(vnQtdeValidaValorMinimo,0),0,0,1)
                    , 'X'
                    , NULL
                    , 0 -- Este Motivo não tem Código
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido para o Plano de Pagamento',1,60)
                    , vvSolucaoP4 );
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Quantidade de Itens Máximo do Plano de Pagamento
  
      -----------------------------------------------
      -- CRÍTICA - Valor Mínimo do Plano de Pagamento
      -----------------------------------------------
      IF (NVL(vrPlanoPagto.vnVlMinPedido,0) > 0) AND
         (vrPedido.vnCondVenda NOT IN (10))      THEN -- DDMEDICA-6573 - Incluido TRANSF
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = pi_nCodPlPagItem)
           AND (CODREJEICAO = 2); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , pi_nCodPlPagItem
                    , 2 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinPlPag
                    , SUBSTR('Valor Mínimo do Plano Pagto: ' || NVL(pi_nCodPlPagItem,0) || ' - ' || vrPlanoPagto.vDescricao,1,100)
                    , 523
                    , vrPlanoPagto.vnVlMinPedido 
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsValorMinPlPag
                    , 10
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido para o plano de pagamento',1,60)
                    , vrAcaoSobreCritica.vnPermissValorMinPlPag
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibValorMinPlPag );
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo do Plano de Pagamento
        
      ----------------------------------
      -- CRÍTICA - Valor Mínimo Venda BK
      ----------------------------------
      IF ((NVL(vrPedido.vvCodCob,' ') = 'BK') OR (NVL(vrCobranca.vvBoleto,'N') = 'S')) AND
         (NVL(vrParametros.nVLMINVENDABK,0) > 0)                                       THEN
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = DECODE(NVL(vrParametros.vTIPOVLMINVENDABK,'VT'),'VP',pi_nCodPlPagItem,0)) -- DDMEDICA-3689
           AND (CODREJEICAO = 3); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , QTDEPARCELAS
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , PROCEDIMENTO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , DECODE(NVL(vrParametros.vTIPOVLMINVENDABK,'VT'),'VP',pi_nCodPlPagItem,0) -- DDMEDICA-3689
                    , 3 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk
                    , DECODE(NVL(vrParametros.vTIPOVLMINVENDABK,'VT'),'VP',SUBSTR('Valor Mínimo - Boleto Bancário para o Plano de Pagamento ' || NVL(pi_nCodPlPagItem,0) || ' - ' || vrPlanoPagto.vDescricao,1,100),
                                                                           SUBSTR('Valor Mínimo - Boleto Bancário',1,100))
                    , 132
                    , vrParametros.nVLMINVENDABK 
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , viQtdeParcelas
                    , 'X'
                    , '1261,2676,1025' 
                    , 15
                    , NULL
                    , SUBSTR('Venda com cobrança boleto ("BK") abaixo do valor mínimo',1,60)
                    , vrAcaoSobreCritica.vnPermissValorMinimoVendaBk
                    , vrAcaoSobreCritica.vnProcedimValorMinimoVendaBk
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibValorMinimoVendaBk );
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo Venda BK
  
      -----------------------------------
      -- CRÍTICA - Valor Mínimo Venda BNF
      -----------------------------------
      IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') <> 'S') AND
         (vrPedido.vnCondVenda IN (5,11))                         AND
         (NVL(vrParametros.nVLMINVENDABNF,0) > 0)                 THEN
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
           AND (CODREJEICAO = 4); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , QTDEPARCELAS
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , 0 -- Sem Plano de Pagamento
                    , 4 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinVendaBnf
                    , SUBSTR('Valor Mínimo para Venda Bonificada',1,100)
                    , 132
                    , vrParametros.nVLMINVENDABNF
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 1
                    , 'X'
                    , '2199,2834'
                    , 11
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido pela Presidência',1,60)
                    , vrAcaoSobreCritica.vnPermissValorMinVendaBnf
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibValorMinVendaBnf );
                    
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo Venda BNF
  
      -----------------------------------
      -- CRÍTICA - Valor Mínimo Venda RCA
      -----------------------------------
      IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') <> 'S') AND
         (vrPedido.vnCondVenda NOT IN (4, 5, 8, 13, 20))          AND -- MED-2604 - Incluído BNF
         (NVL(vrRca.vnVlVendaMinPed,0) > 0)                       THEN
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
           AND (CODREJEICAO = 5); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , QTDEPARCELAS
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0 -- Sem Plano de Pagamento
                    , 5 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinRca
                    , SUBSTR('Valor Mínimo para o RCA',1,100)
                    , 517
                    , vrRca.vnVlVendaMinPed
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 1
                    , 'X'
                    , NULL
                    , 8
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido para o RCA',1,60)
                    , vvSolucaoP4 );
  
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo Venda RCA
  
      --------------------------------------------
      -- CRÍTICA - Valor Mínimo do Pedido de Venda
      --------------------------------------------
      IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') <> 'S') AND
         (vrPedido.vnCondVenda NOT IN (5,10))                     AND -- MED-2604 - Incluído BNF -- DDMEDICA-6573 - Incluido TRANSF
         (NVL(vrParametros.nVLMINVENDA,0) > 0)                    THEN
      
        -- Qtde. para usar nos Cálculo do Valor Mínimo com ou sem Corte
        IF (NVL(vrParametros.vVALIDARVLMINVENDAAPOSCORTE,'N') = 'S') THEN
          -- Com os Cortes
          vnQtdeValidaVlMinComSemCorte := NVL(pi_nQtdeComCorte,0); 
        ELSE
          -- Sem os Cortes
          vnQtdeValidaVlMinComSemCorte := NVL(pi_nQtdePedido,0);
        END IF;
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaVlMinComSemCorte,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
           AND (CODREJEICAO = 6); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , QTDEPARCELAS
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , 0 -- Sem Plano de Pagamento
                    , 6 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda
                    , SUBSTR('Valor Mínimo do Pedido de Venda',1,100)
                    , 132
                    , vrParametros.nVLMINVENDA
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaVlMinComSemCorte,0))
                    , 1
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsValorMinimoPedVenda
                    , 11
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido pela Presidência',1,60)
                    , vrAcaoSobreCritica.vnPermissValorMinimoPedVenda
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibValorMinimoPedVenda );
  
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo do Pedido de Venda
      
      ----------------------------------------------------------------------------------------------------
      -- CRÍTICA - Se Bonificação estiver Parametrizado para Gravar Sempre como Bloqueado no Telemarketing
      ----------------------------------------------------------------------------------------------------
      IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') <> 'S') AND
         (vrAcaoSobreCritica.vvAcaoPedidoBonific IS NOT NULL)     THEN
  
        BEGIN
          SELECT 'S'
            INTO vvAchouAcao
            FROM PCMED_VALIDACAO_ESTOQUE_RESERV
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
             AND (CODREJEICAO = 7); -- CODREJEICAO
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouAcao := 'N';
        END;
      
        IF (NVL(vvAchouAcao,'N') = 'N') THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , 0   -- Sem Plano de Pagamento
                    , 7   -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoPedidoBonific
                    , SUBSTR('Gravar Pedidos Bonificados como Bloqueados',1,100)
                    , 132
                    , 'X'
                    , '1168'
                    , 7
                    , NULL
                    , SUBSTR('Pedido Bonificado',1,60)
                    , vrAcaoSobreCritica.vnPermissPedidoBonific
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibPedidoBonific );
        END IF;
        
      END IF; -- Fim Condição: CRÍTICA - Se Bonificação estiver Parametrizado para Gravar Sempre como Bloqueado no Telemarketing
      
      --------------------------------------------------------------------------------
      -- CRÍTICA - Se Empresa Parametrizado para Gravar o Pedido Sempre como Bloqueado
      --------------------------------------------------------------------------------
      IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') <> 'S') AND
         (vrAcaoSobreCritica.vvAcaoGravarPedBloq IS NOT NULL)     THEN
      
        BEGIN
          SELECT 'S'
            INTO vvAchouAcao
            FROM PCMED_VALIDACAO_ESTOQUE_RESERV
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
             AND (CODREJEICAO = 8); -- CODREJEICAO
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouAcao := 'N';
        END;
      
        IF (NVL(vvAchouAcao,'N') = 'N') THEN
          -- Grava Ação de Bloqueio
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0   -- Sem Plano de Pagamento
                    , 8   -- CODREJEICAO
                    , 'P' -- ACAO
                    , SUBSTR('Gravar Pedidos como Bloqueados',1,100)
                    , 132
                    , 'X'
                    , '9854'
                    , 701
                    , NULL
                    , SUBSTR('Pedido Bloqueado por Parâmetro da Presidência',1,60)
                    , vvSolucaoP4 );
        END IF;          
      
      END IF; -- Fim Condição: -- CRÍTICA - Se Empresa Parametrizado para Gravar o Pedido Sempre como Bloqueado            
      
      ----------------------------------------------
      -- CRÍTICA - Valor Mínimo da Condição de Venda
      ----------------------------------------------
      IF (vrPedido.vvValidarMinOperadorLogistico = 'S') AND
         (NVL(vrCondicaoVenda.vnValorMinimoPed,0) > 0)  THEN
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
           AND (CODREJEICAO = 9); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0 -- Sem Plano de Pagamento
                    , 9 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoVlMinOperadorLogistico
                    , SUBSTR('Valor Mínimo da Condição de Venda: ' || NVL(vrPedido.vnCodCondicaoVenda,0) || ' - ' || 'Atingido'|| ' - ' || (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0)) || ' - ' ||vrCondicaoVenda.vvDescricao,1,100)
                    , 2311
                    , vrCondicaoVenda.vnValorMinimoPed
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 'X'
                    , NULL 
                    , 11
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido para condição de venda',1,60)
                    , vvSolucaoP4 );
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo da Condição de Venda
      
      -------------------------------------------------------------------------------------------------
      -- CRÍTICA - Gravar Pedido como Bloqueado quando tem Valor de Desconto Negociado - HIS.05093.2017
      -------------------------------------------------------------------------------------------------
      IF (NVL(vrPedido.vnVlDescNeg,0) > 0) AND
         (vrAcaoSobreCritica.vvAcaoValorDescNeg IS NOT NULL) THEN
      
        BEGIN
          SELECT 'S'
            INTO vvAchouAcao
            FROM PCMED_VALIDACAO_ESTOQUE_RESERV
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
             AND (CODREJEICAO = 10); -- CODREJEICAO
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouAcao := 'N';
        END;
      
        IF (NVL(vvAchouAcao,'N') = 'N') THEN
          -- Grava Ação de Bloqueio
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , VALORVALIDACAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 10 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorDescNeg
                    , SUBSTR('Pedido com Desconto Negociado para Aprovação',1,100)
                    , 2316
                    , 'X'
                    , NULL
                    , 702
                    , NULL
                    , SUBSTR('Pedido com Desconto Negociado para Aprovação',1,60)
                    , NVL(vrPedido.vnVlDescNeg,0)
                    , vvSolucaoP4 );
        END IF;          
      
      END IF; -- Fim Condição: -- CRÍTICA - Gravar Pedido como Bloqueado quando tem Valor de Desconto Negociado              
  
      -----------------------------------------------------------------------
      -- CRÍTICA - Valor Mínimo Aprovação Desconto Negociado - HIS.05093.2017
      -----------------------------------------------------------------------
      IF (NVL(vrAprovacao.VLVENDASEMIMPAPROV,0) > 0) AND
         (vrAcaoSobreCritica.vvAcaoValorMinDescNeg IS NOT NULL) THEN
      
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)  -- Sem Plano de Pagamento
           AND (CODREJEICAO = 11); -- CODREJEICAO
      
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          -- Grava Ação de Bloqueio
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 11 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinDescNeg
                    , SUBSTR('Pedido com valor total liquido abaixo do aprovado para aplicação do Desconto Negociado',1,100)
                    , 2336
                    , NVL(vrAprovacao.VLVENDASEMIMPAPROV,0)
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 'X'
                    , NULL
                    , 703
                    , NULL
                    , SUBSTR('Pedido com valor liq. abaixo do aprovado (Desc. Negociado)',1,60)
                    , vvSolucaoP4 );
        END IF;          
      
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo Aprovação Desconto Negociado - HIS.05093.2017      
  
      -----------------------------------------------------------------------
      -- CRÍTICA - Venda de Rca sem Saldo - MED-1669
      -----------------------------------------------------------------------
      IF (pi_vMovimentarSaldoRca = 'S') AND
         (vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo IS NOT NULL) THEN
      
        -- Quantidade para Validação do Saldo
        IF (NVL(po_vPosicaoFinalPedido,'L') = 'B') THEN
          vnQtValidaSaldoRca := NVL(pi_nQtdePedido,0);
        ELSE
          vnQtValidaSaldoRca := NVL(pi_nQtdeComCorte,0);
        END IF;
        
        -- MEDICA-477 - Quando Movimenta Pedido no Faturamento, precisa considerar no Saldo os Créditos que vieram no Pedido
        IF (F_MOVSALDORCAPORPEDIDOFAT) THEN
          -- Para fins de validação de saldo rca excedido, tem que passar FF como validação no pedido para não retornar zero
          vvTipoMovCCRca := 'VV';
        -- No Processo Pacote, incremento do saldo no mesmo pedido dependede dos parâmetros
        -- (Ex VF: Positivo = Garante que não entra a bola de cristal aqui; Negativo = Pode cortar item que deixou vender por gerar saldo no mesmo pedido)
        ELSE
          vvTipoMovCCRca := vrParametros.vTIPOMOVCCRCA;
        END IF;
             
        -- DDMEDICA-3103 - Bonificação por Campanha, deve observar se o tipo de bonificação da promoção movimenta conta-corrente
        vvBonificAltDebCredRca := vrPedido.vvBonificAltDebCredRca;
        IF (NVL(pi_vBonific,'N') = 'F') THEN
          BEGIN
            SELECT NVL(PCTIPOBONIFIC.MOVIMENTACCRCA,'N')
              INTO vvBonificAltDebCredRca
              FROM PCPROMOCAOMED
                 , PCTIPOBONIFIC
             WHERE (PCTIPOBONIFIC.CODBNF         = PCPROMOCAOMED.CODBNF)
               AND (PCPROMOCAOMED.CODPROMOCAOMED = pi_nCodPromocaoItem);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              NULL; -->> Se não achar mantém a Regra do Cabeçalho do Peedido
          END;
        END IF;
             
        -- Calcula o Saldo do Item
        vnSaldoItemRca := PC_PKG_CONTROLARSALDORCA_MED.CCRCA_SALDO_ITEM(vrParametros.vUSACREDRCA,
                                                                    vrPedido.vvUsaDebCredRca,
                                                                    'N', -- Broker
                                                                    vrPedido.vvOrigemPed,
                                                                    vrPedido.vvBonificAltDebCredRca, --//MED-2524//-- 'S', -- Se pi_vMovimentarSaldoRca = SIM, PCPEDC.BONIFICALTDEBCREDRCA = SIM
                                                                    vrParametros.vTROCAALTDEBCREDRCA,
                                                                    vrParametros.vCRMALTDEBCREDRCA,
                                                                    'N', -- PCCONSUM.BROKER
                                                                    vvTipoMovCCRca, -- MEDICA-477 -- Depende de Regra Específica -- vrParametros.vTIPOMOVCCRCA,
                                                                    vrPedido.vnCondVenda,
                                                                    'N', -- Brinde
                                                                    pi_nCodUsurContaCorrente,
                                                                    'V', -- Tipo
                                                                    NVL(pi_nPVenda,0),
                                                                    NVL(pi_nPBaseRca,0),
                                                                    NVL(pi_nPBaseRca,0),
                                                                    NVL(vnQtValidaSaldoRca,0), -->> Qtde. para Validar o Saldo RCA depende da Posição do Pedido
                                                                    NULL, -- PCPEDI.USADEBCREDRCABRIND
                                                                    'S',  -- PCPEDI.MOVIMENTACONTACORRENTERCA 
                                                                    NVL(pi_nSt,0),
                                                                    NVL(pi_nStPBaseRca,0),
                                                                    NVL(pi_nStPBaseRca,0),
                                                                    pi_vBonific);
                                              
        -- DDMEDICA-834 - Se Crédito
        IF (NVL(F_TIPOSALDORESERVADOPEDIDOFAT,'0') <> '3') THEN -- DDMEDICA-2798 - Se o Rateio de C/C é no Saldo do Pedido, não pode ratear nos Itens
          IF (NVL(vnSaldoItemRca,0) > 0) THEN
            vnSaldoItemRca := ROUND(NVL(vnSaldoItemRca,0) * (NVL(vrParametros.nPERCRATEIOCREDRCASUPERVISOR,0) / 100),2);
          END IF;
        END IF;
                                                                    
        -- Insere na Tabela Temporária Detalhe
        INSERT INTO PCMED_VALIDACAO_SALDO_ITEM
                  ( NUMPED
                  , CODPROD
                  , NUMSEQ
                  , CODREJEICAO
                  , ACAO 
                  , VALORVALIDACAO
                  , PVENDA
                  , ST
                  , PBASERCA
                  , STPBASERCA
                  , SALDORCA
                  , SALDOPED
                  , SALDOITEM
                  , VENDAPERMITIDA
                  , QT
                  )
           VALUES ( pi_nNumPed
                  , pi_nCodProd
                  , pi_nNumSeq
                  , 12 -- CODREJEICAO
                  , vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo
                  , vnSaldoItemRca
                  , pi_nPVenda
                  , pi_nSt
                  , pi_nPBaseRca
                  , pi_nStPBaseRca
                  , NULL -- SALDORCA - Vai atualizar depois
                  , NULL -- SALDOPED - Vai atualizar depois
                  , vnSaldoItemRca
                  , NULL -- VENDAPERMITIDA - Vai atualizar depois
                  , vnQtValidaSaldoRca );
        
      END IF; -- Fim Condição: -- CRÍTICA - Venda de Rca sem Saldo - MED-1669
  
      -----------------------------------------------------------------------
      -- CRÍTICA - Ter Estoque Total
      -----------------------------------------------------------------------
      IF (NVL(po_vPosicaoFinalPedido,'L') IN ('L','M')) AND
         (vrAcaoSobreCritica.vvAcaoTerEstoqueTotal IS NOT NULL) THEN
      
        -- Verifica se aceita o Produto
        vvVendaPermitida := 'S';
        IF (NVL(pi_nQtdeComCorte,0) < NVL(pi_nQtdePedido,0)) THEN
          vvVendaPermitida := 'N';
        END IF;
                                                                    
        -- Insere na Tabela Temporária Detalhe
        INSERT INTO PCMED_VALIDACAO_SALDO_ITEM
                  ( NUMPED
                  , CODPROD
                  , NUMSEQ
                  , CODREJEICAO
                  , ACAO 
                  , VALORVALIDACAO
                  , PVENDA
                  , VENDAPERMITIDA
                  , QT
                  )
           VALUES ( pi_nNumPed
                  , pi_nCodProd
                  , pi_nNumSeq
                  , 13 -- CODREJEICAO
                  , vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo
                  , vnSaldoItemRca
                  , pi_nPVenda
                  , vvVendaPermitida
                  , NVL(pi_nQtdeComCorte,0) );
  
        -- Atualiza Tabela Master    
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO  = NVL(VALORATINGIDO,0)  + NVL(pi_nQtdeComCorte,0)
             , VALORVALIDACAO = NVL(VALORVALIDACAO,0) + NVL(pi_nQtdePedido,0)
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
           AND (CODREJEICAO = 13); -- CODREJEICAO
      
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          -- Grava Ação de Bloqueio
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 13 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo
                    , SUBSTR('Não tem estoque total para todos os itens',1,100)
                    , 132
                    , NVL(pi_nQtdePedido,0)
                    , NVL(pi_nQtdeComCorte,0)
                    , 'X'
                    , '2548'
                    , NULL
                    , NULL
                    , SUBSTR('Não tem estoque total para todos os itens',1,60)
                    , vvSolucaoP4 );
        END IF;          
            
      END IF; -- Fim Condição: ---- CRÍTICA - Ter Estoque Total
    
      -------------------------------------
      -- CRÍTICA - Valor Mínimo da Cobrança
      -------------------------------------
      IF (NVL(vrCobranca.vnVlMinPedido,0) > 0) THEN
  
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
           AND (CODREJEICAO = 14); -- CODREJEICAO
  
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 14 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoValorMinCob
                    , SUBSTR('Valor Mínimo da Cobrança: ' || vrPedido.vvCodCob || ' - ' || vrCobranca.vvCobranca,1,100)
                    , 522
                    , vrCobranca.vnVlMinPedido
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsValorMinCob
                    , 9
                    , NULL
                    , SUBSTR('Pedido com valor abaixo do mínimo permitido para a cobrança',1,60)
                    , vrAcaoSobreCritica.vnPermissValorMinCob
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibValorMinCob );
        END IF;
  
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo da Cobrança
  
      ------------------------------------------
      -- CRÍTICA - RCA Bloqueado - DDMEDICA-1586
      ------------------------------------------
      IF (F_PODE_VALIDAR_BLOQUEIO(pi_nNumPed,
                                  15)) THEN -- CODREJEICAO
        IF (F_BLOQUEIO_RCA(vrPedido.vnCodUsur,
                           vvDescricaoRejeicao,
                           vvMotivoPosicao)) THEN
        
          P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                        , pi_nNumPed
                                        , 0  -- Sem Plano de Pagamento
                                        , 15 -- CODREJEICAO
                                        , vrAcaoSobreCritica.vvAcaoRcaBloqueado
                                        , SUBSTR(vvDescricaoRejeicao,1,100)
                                        , 1203
                                        , 0  -- Valor Validação = Zero RCAs Bloqueados
                                        , 1  -- Valor Atingido  = + 1 RCA Bloqueado
                                        , 'X'
                                        , vrAcaoSobreCritica.vvParamsRcaBloqueado
                                        , 1    -- Código do Motivo
                                        , NULL -- Código Motivo Bloqueio
                                        , SUBSTR(vvMotivoPosicao,1,60)
                                        , NULL -- PERMISSAO
                                        , vvSolucaoP4 );
    
        END IF;
      END IF; -- Fim Condição: -- CRÍTICA - RCA Bloqueado
      
      ----------------------------------------------
      -- CRÍTICA - Cliente Bloqueado - DDMEDICA-1586
      ---------------------------------------------
      IF (F_PODE_VALIDAR_BLOQUEIO(pi_nNumPed,
                                  16)) THEN -- CODREJEICAO
        IF (F_BLOQUEIO_CLIENTE(vrPedido.vnCodCli,
                               vrPedido.vvCodCob,        
                               vrParametros.vVERIFICALIMCREDCODCOBD,
                               vrParametros.vACEITAVENDAAVISTACLIBLOQ,
                               vvDescricaoRejeicao,
                               vvMotivoPosicao)) THEN
                                      
          P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                        , pi_nNumPed
                                        , 0  -- Sem Plano de Pagamento
                                        , 16 -- CODREJEICAO
                                        , vrAcaoSobreCritica.vvAcaoClienteBloqueado
                                        , SUBSTR(vvDescricaoRejeicao,1,100)
                                        , 1203
                                        , 0  -- Valor Validação = Zero Clientes Bloqueados
                                        , 1  -- Valor Atingido  = + 1 Cliente Bloqueado
                                        , 'X'
                                        , vrAcaoSobreCritica.vvParamsClienteBloqueado
                                        , 2    -- Código do Motivo
                                        , NULL -- Código Motivo Bloqueio
                                        , SUBSTR(vvMotivoPosicao,1,60)
                                        , NULL -- PERMISSAO
                                        , vvSolucaoP4 );
    
        END IF;
      END IF; -- Fim Condição: -- CRÍTICA - Cliente Bloqueado
  
      -----------------------------------------------
      -- CRÍTICA - Cliente sem Crédito - DDMEDICA-1586
      -----------------------------------------------
      IF (vrPedido.vnCondVenda NOT IN (4,5,8,11,20)) THEN
        
        IF (NVL(vrParametros.vVERIFICALIMCREDCODCOBD,'N') = 'N') AND 
           ((NVL(vrPedido.vvCodCob,'BK') IN ('D','DH')) OR
            (NVL(vrCobranca.vvCartao,'N') = 'S')) THEN
            
          NULL; -->> DDMEDICA-3743 - Não faz Validação de Limite de Crédito se "Verificar limite de credito do cliente ao incluir pedido nas cobranças "D", "DH" e "CAR"" = Não
          
        ELSE
        
          P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                        , pi_nNumPed
                                        , 0  -- Sem Plano de Pagamento
                                        , 17 -- CODREJEICAO
                                        , vrAcaoSobreCritica.vvAcaoClienteSemCredito
                                        , SUBSTR('Cliente sem limite de credito / data vencto. limite credito.',1,100)
                                        , 1203
                                        , 0  -- Valor da Validação será calculada no Final
                                        , (NVL(pi_nPVenda,0) * NVL(pi_nQtdeComCorte,0))
                                        , 'X'
                                        , vrAcaoSobreCritica.vvParamsClienteSemCredito
                                        , 3    -- Código do Motivo
                                        , NULL -- Código Motivo Bloqueio
                                        , SUBSTR('Cliente sem limite de credito / data vencto. limite credito.',1,60)
                                        , vrAcaoSobreCritica.vnPermissClienteSemCredito
                                        , vvSolucaoP4 );
                                       
        END IF;                               
    
      END IF; -- Fim Condição: -- CRÍTICA - Cliente Bloqueado
  
      ----------------------------------
      -- CRÍTICA - Valor Máximo de Venda
      ---------------------------------
      IF (vrPedido.vnCondVenda NOT IN (5)) AND
         (NVL(vrParametros.nVLMAXVENDA,0) > 0) THEN
         
        P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                      , pi_nNumPed
                                      , 0  -- Sem Plano de Pagamento
                                      , 18 -- CODREJEICAO
                                      , vrAcaoSobreCritica.vvAcaoVlMaxVenda
                                      , SUBSTR('Valor Máximo de Venda',1,100)
                                      , 132
                                      , vrParametros.nVLMAXVENDA
                                      , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                                      , 'X'
                                      , vrAcaoSobreCritica.vvParamsVlMaxVenda
                                      , 4    -- Código do Motivo
                                      , NULL -- Código Motivo Bloqueio
                                      , SUBSTR('Pedido excede o valor máximo de venda dos parâmetros da presidência',1,60)
                                      , vrAcaoSobreCritica.vnPermissVlMaxVenda
                                      , vvSolucaoP4 );
         
      END IF; -- Fim Condição: -- CRÍTICA - Valor Máximo de Venda

      -------------------------------------
      -- CRÍTICA - Valor Máximo de Venda PF
      -------------------------------------
      /*
      IF (vrPedido.vnCondVenda NOT IN (5)) AND
         (NVL(vrParametros.nVLMAXVENDAPF,0) > 0) THEN
  
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
           AND (CODREJEICAO = 19); -- CODREJEICAO
  
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 19 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoVlMaxVendaPF
                    , SUBSTR('Valor Máximo de Venda Pessoa Fisica',1,100)
                    , 132
                    , vrParametros.nVLMAXVENDAPF                    
                    , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsVlMaxVendaPF
                    , 4
                    , NULL
                    , SUBSTR('Pedido excede o valor máximo de venda pessoa fisica dos parâmetros da presidência',1,60)
