      END IF; -- Fim Condição: -- CRÍTICA - Valor Máximo de Venda PF
      */
      
      --------------------------------------
      -- CRÍTICA - Valor Máximo de Venda BNF
      --------------------------------------
      IF (vrPedido.vnCondVenda IN (5)) AND
         (NVL(vrParametros.nVLMAXVENDABNF,0) > 0) THEN
    
        P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                      , pi_nNumPed
                                      , 0  -- Sem Plano de Pagamento
                                      , 20 -- CODREJEICAO
                                      , vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF
                                      , SUBSTR('Valor Máximo de Veda Bonificada',1,100)
                                      , 132
                                      , vrParametros.nVLMAXVENDABNF
                                      , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                                      , 'X'
                                      , vrAcaoSobreCritica.vvParamsVlMaxVendaBNF
                                      , 4    -- Código do Motivo
                                      , NULL -- Código Motivo Bloqueio
                                      , SUBSTR('Pedido excede o valor máximo de venda bonificada dos parâmetros da presidência',1,60)
                                      , vrAcaoSobreCritica.vnPermissVlMaxVendaBNF
                                      , vvSolucaoP4
                                      , NULL
                                      , NULL
                                      , NULL
                                      , NULL
                                      , NULL
                                      , NULL
                                      , vrAcaoSobreCritica.vvLibVlMaxVendaBNF );
     
      END IF; -- Fim Condição: -- CRÍTICA - Valor Máximo de Venda BNF      

      -----------------------------------
      -- CRÍTICA - Preço Abaixo do Mínimo
      -----------------------------------
	  -->> Verifica Posicao do item do Orcamento
	  BEGIN
        SELECT POSICAO
          into vvPosicaoOrcamento
          FROM PCORCAVENDAI
         WHERE NUMORCA = pi_nNumPed
           AND CODPROD = pi_nCodProd
		   AND NUMSEQ  = pi_nNumSeq;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvPosicaoOrcamento := ''; 
      END;
	  
      IF ( ((pi_nCodRotina = 2316) AND (NVL(vrParametros.vACEITADESCTMK,'N') = 'S') AND (vrPedido.vvOrigemPed NOT IN ('R'))) OR       -- DDVENDAS-35974
           ((pi_nCodRotina = 2316) AND (NVL(vrParametros.vACEITADESCBALCAORESERVA,'N') = 'S') AND (vrPedido.vvOrigemPed IN ('R'))) OR -- DDVENDAS-35974
           ((pi_nCodRotina = 2513) AND (vrParametros.vACEITADESCTMKFV = 'S')) )  AND
         ((NVL(pi_nCodMotivoPosicaoMed,0) > 0)or (vvPosicaoOrcamento = 'X')) THEN
  
        P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                      , pi_nNumPed
                                      , pi_nCodProd
                                      , 21 -- CODREJEICAO
                                      , vrAcaoSobreCritica.vvAcaoPrecoMinimo
                                      , SUBSTR('Preço Abaixo do Mínimo Permitido',1,100)
                                      , 301
                                      , 0  -- Valor Validação = Zero Produtos com Preço Abaixo do Mínimo
                                      , 1  -- Valor Atingido  = + 1 Cliente com Preço Abaixo do Mínimo
                                      , 'X'
                                      , vrAcaoSobreCritica.vvParamsPrecoMinimo
                                      , 5    -- Código do Motivo
                                      , NULL -- Código Motivo Bloqueio
                                      , SUBSTR('Preço Abaixo do Mínimo Permitido',1,60)
                                      , vrAcaoSobreCritica.vnPermissPrecoMinimo
                                      , pi_vMotivoPosicaoMed );
    
      END IF; -- Fim Condição: -- CRÍTICA - Preço Abaixo do Mínimo    

      ---------------------------------------------------------------------
      -- CRÍTICA - Prazo Médio do Pedido Superior ao Prazo Médio do Cliente
      ---------------------------------------------------------------------
      IF (NVL(vrCobranca.vvNaoValidaPrazoMedio,'N') <> 'S') AND
         (NVL(pi_vTipoPrazoMedicam,'0') <> '4')             AND
         (NVL(vrParametros.vEXISTE_PCPLPAGCLI,'N')  <> 'S') THEN
          
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO = vrPlanoPagto.vnNumDias
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = pi_nCodLinhaPrazo)
           AND (CODREJEICAO = 22); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
        
          -- DDMEDICA-3017 - Inicializa Variável de Plano Mandatório da Promoção
          vnCodPlPagMandatorioPromocao := NULL;
        
          -- DDMEDICA-3017 - Verifica se a Promoção do Pedido tem Plano Mandatório
          BEGIN
            SELECT NVL(PRAZOPLPAGMANDATORIO,'N')
              INTO vvPrazoPlPagMandatorio
              FROM PCPROMOCAOMED
             WHERE (CODPROMOCAOMED = vrPedido.vnCodPromocaoMed);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvPrazoPlPagMandatorio := NULL;
          END;
                    
          -- DDMEDICA-3017 - Se a Promoçãod do Pedido tem Plano Mandatório
          IF (NVL(vvPrazoPlPagMandatorio,'N') = 'S') THEN
                                
            -- Plano de Pagamento com tratamento para o Prazo Mandatório da Promoção - HIS.02239.2018
            IF (NVL(vrRegrasEspecificas.vUSAREGRANORMALIZADESC,'N') = 'S') THEN
      
              -- Pega maior Prazo Médio da Tabela Normalizada
              FOR vc_Prazo IN (SELECT PCPLPAG.CODPLPAG
                                    , PCPLPAG.NUMDIAS
                                 FROM PCPLPAG
                                    , PCPROMOCAOPLPAGMED
                                WHERE (PCPROMOCAOPLPAGMED.CODPLPAG       = PCPLPAG.CODPLPAG)
                                  AND (PCPROMOCAOPLPAGMED.CODPROMOCAOMED = vrPedido.vnCodPromocaoMed)
                                ORDER BY PCPLPAG.NUMDIAS DESC) LOOP
                -- Pega primeiro e sai
                vnCodPlPagMandatorioPromocao := vc_Prazo.CODPLPAG;
                EXIT;
              END LOOP;
      
            ELSE
      
              -- Pega maior Prazo Médio da Tabela Normalizada
              FOR vc_Prazo IN (SELECT DISTINCT
                                      PCPLPAG.CODPLPAG
                                    , PCPLPAG.NUMDIAS
                                    , PCPLPAG.DESCRICAO
                                 FROM PCPLPAG
                                    , PCDESCONTO
                                WHERE (PCDESCONTO.CODPLPAG       = PCPLPAG.CODPLPAG)
                                  AND (PCDESCONTO.CODPROMOCAOMED = vrPedido.vnCodPromocaoMed)
                                ORDER BY PCPLPAG.NUMDIAS DESC) LOOP
                -- Pega primeiro e sai
                vnCodPlPagMandatorioPromocao := vc_Prazo.CODPLPAG;
                EXIT;
              END LOOP;
      
            END IF;
          
            BEGIN
              SELECT CODPLPAG
                   , DESCRICAO
                   , 'Prazo Médio do Pedido superior ao Prazo Médio do Plano Mandatório da Promoção'
                INTO vnCodPlPagCliente
                   , vvDescricaoPlPagCliente
                   , vvMsgPrazoMedioCliente
                FROM PCPLPAG
               WHERE (CODPLPAG = vnCodPlPagMandatorioPromocao);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnCodPlPagCliente       := NULL;
                vvDescricaoPlPagCliente := NULL;
                vvMsgPrazoMedioCliente  := 'Prazo Médio do Pedido superior ao Prazo Médio do Plano Mandatório da Promoção';
            END;
          
          END IF; -- Fim Condição: Se Promoção com Plano Mandatório
          
          -- DDMEDICA-3017 - Sem Plano Mandatório na Promoção
          IF (NVL(vnCodPlPagMandatorioPromocao,0) = 0) THEN
        
            -- Se Plano do Grupo de Faturamento
            IF (NVL(pi_vTipoPrazoMedicam,'0') = '1') THEN
            
              BEGIN
                SELECT CASE WHEN (NVL(pi_vGrupoFaturamento,'G') = 'E') THEN
                         CODPLPAGETICO
                       ELSE
                         CODPLPAGGENERICO
                       END
                     , CASE WHEN (NVL(pi_vGrupoFaturamento,'G') = 'E') THEN
                         (SELECT P.DESCRICAO FROM PCPLPAG P WHERE P.CODPLPAG = PCCLIENT.CODPLPAGETICO)
                       ELSE
                         (SELECT P.DESCRICAO FROM PCPLPAG P WHERE P.CODPLPAG = PCCLIENT.CODPLPAGGENERICO)
                       END
                     , CASE WHEN (NVL(pi_vGrupoFaturamento,'G') = 'E') THEN
                         'Prazo Médio do Pedido superior ao Prazo Médio Ético do Cliente'
                       ELSE
                         'Prazo Médio do Pedido superior ao Prazo Médio Genérico do Cliente'
                       END
                  INTO vnCodPlPagCliente
                     , vvDescricaoPlPagCliente
                     , vvMsgPrazoMedioCliente
                  FROM PCCLIENT
                 WHERE (CODCLI = vrPedido.vnCodCli);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vnCodPlPagCliente       := NULL;
                  vvDescricaoPlPagCliente := NULL;
                  vvMsgPrazoMedioCliente  := 'Prazo Médio do Pedido superior ao Prazo Médio Ético/Genérico do Cliente';
              END;
                          
            -- Se Plano do Cliente
            ELSE
            
              BEGIN
                SELECT CODPLPAG
                     , (SELECT P.DESCRICAO FROM PCPLPAG P WHERE P.CODPLPAG = PCCLIENT.CODPLPAG)
                     , 'Prazo Médio do Pedido superior ao Prazo Médio do Cliente'
                  INTO vnCodPlPagCliente
                     , vvDescricaoPlPagCliente
                     , vvMsgPrazoMedioCliente
                  FROM PCCLIENT
                 WHERE (CODCLI = vrPedido.vnCodCli);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vnCodPlPagCliente       := NULL;
                  vvDescricaoPlPagCliente := NULL;
                  vvMsgPrazoMedioCliente  := 'Prazo Médio do Pedido superior ao Prazo Médio do Cliente';
              END;
              
            END IF; -- Fim Condição: Tipo de Prazo de Medicamento
        
          END IF; -- Fim Condição: Se Promoção com Plano Mandatório
          
          -- Calcula Prazo Médio do Plano do Cliente
          IF (NVL(vnCodPlPagCliente,0) > 0) THEN
            P_CARREGAR_ARRAY_PARCELAS(vnCodPlPagCliente,
                                      vrPedido.vdDtEntrega,
                                      vtArrayParcelasPlPagCliente,
                                      vnPrazoMedioPlPagCliente);        
          ELSE
            vnPrazoMedioPlPagCliente := 0;
          END IF;
        
          -- DDMEDICA-3017 - Mensagem diferenciada para Plano Mandatório na Promoção
          IF (NVL(vnCodPlPagMandatorioPromocao,0) > 0) THEN
            vvSolucaoPL := 'O Prazo Médio do Pedido (Plano de Pagamento do Pedido igual a "' || pi_nCodPlPagItem || ' - ' || vrPlanoPagto.vDescricao || '" com Prazo Médio igual a "' || vrPlanoPagto.vnNumDias || '" dias)' ||
                           ' é superior ao Prazo Médio do Plano de Pagamento Mandatório da Promoção (Plano de Pagamento Mandatório igual a "' || vnCodPlPagCliente || ' - ' || vvDescricaoPlPagCliente || '" com Prazo Médio igual a "' || vnPrazoMedioPlPagCliente || '" dias)';
          ELSE
            vvSolucaoPL := 'O Prazo Médio do Pedido (Plano de Pagamento do Pedido igual a "' || pi_nCodPlPagItem || ' - ' || vrPlanoPagto.vDescricao || '" com Prazo Médio igual a "' || vrPlanoPagto.vnNumDias || '" dias)' ||
                           ' é superior ao Prazo Médio do Cliente (Plano de Pagamento do Cliente igual a "' || vnCodPlPagCliente || ' - ' || vvDescricaoPlPagCliente || '" com Prazo Médio igual a "' || vnPrazoMedioPlPagCliente || '" dias)';
          END IF;

          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , pi_nCodLinhaPrazo
                    , 22 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoPrazoMedio
                    , SUBSTR(vvMsgPrazoMedioCliente,1,100)
                    , 523
                    , vnPrazoMedioPlPagCliente
                    , vrPlanoPagto.vnNumDias
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsPrazoMedio
                    , 13
                    , NULL
                    , SUBSTR('Prazo Médio do Pedido superior ao Prazo Médio do Cliente',1,60)
                    , vrAcaoSobreCritica.vnPermissPrazoMedio
                    , vvSolucaoPL
                    , vrAcaoSobreCritica.vvLibVendaPrazoMedio );
                    
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Valor Mínimo do Plano de Pagamento

      ------------------------------------------------
      -- CRÍTICA - Margem Mínima do Plano de Pagamento
      ------------------------------------------------
      IF (vrPedido.vnCondVenda <> (10)) AND -- DDMEDICA-5031
         (NVL(vrPlanoPagto.vnMargemMin,0) <> 0) THEN
          
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO  = NVL(VALORATINGIDO,0)  + (NVL(pi_nPVenda,0) * NVL(pi_nQtdeComCorte,0))
             , VALORATINGIDO2 = NVL(VALORATINGIDO2,0) + (NVL(pi_nVlCustoFin,0) * NVL(pi_nQtdeComCorte,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = pi_nCodPlPagItem)
           AND (CODREJEICAO = 23); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
                
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VALORATINGIDO2
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , pi_nCodPlPagItem
                    , 23 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoMargemMinima
                    , SUBSTR('Margem de lucro abaixo do mínimo permitido no plano pgto: ' || NVL(pi_nCodPlPagItem,0) || ' - ' || vrPlanoPagto.vDescricao,1,100)
                    , 523
                    , NVL(vrPlanoPagto.vnMargemMin,0)
                    , (NVL(pi_nPVenda,0) * NVL(pi_nQtdeComCorte,0))
                    , (NVL(pi_nVlCustoFin,0) * NVL(pi_nQtdeComCorte,0))
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsMargemMinima
                    , 16
                    , NULL
                    , SUBSTR('Margem de lucro abaixo do mínimo permitido no plano pgto',1,60)
                    , vrAcaoSobreCritica.vnPermissMargemMinima 
                    , ' com estoque disponivel'
                    , vrAcaoSobreCritica.vvLibMargemMinima );
                    
        END IF;
        
      END IF; -- Fim Condição: -- CRÍTICA - Margem Mínima do Plano de Pagamento

      ---------------------------------
      -- CRÍTICA - Margem Mínima da 132
      ---------------------------------
      IF (vrPedido.vnCondVenda <> (10)) AND -- DDMEDICA-5031
         (NVL(vrParametros.nPERCMARGEMMINVENDAMED,0) <> 0) THEN
          
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO  = NVL(VALORATINGIDO,0)  + (NVL(pi_nPVenda,0) * NVL(pi_nQtdeComCorte,0))
             , VALORATINGIDO2 = NVL(VALORATINGIDO2,0) + (NVL(pi_nVlCustoFin,0) * NVL(pi_nQtdeComCorte,0))
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = 0)   -- DDMEDICA-3712 - Agrupar pelo Pedido
           AND (CODREJEICAO = 24); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
                
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VALORATINGIDO2
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0  -- DDMEDICA-3712 - Agrupar pelo Pedido
                    , 24 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoMargemMinima132
                    , SUBSTR('Margem de lucro abaixo do mínimo permitido nos parâmetros da presidência',1,100)
                    , 132
                    , NVL(vrParametros.nPERCMARGEMMINVENDAMED,0)
                    , (NVL(pi_nPVenda,0) * NVL(pi_nQtdeComCorte,0))
                    , (NVL(pi_nVlCustoFin,0) * NVL(pi_nQtdeComCorte,0))
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsMargemMinima132
                    , 16
                    , NULL
                    , SUBSTR('Margem de lucro abaixo do mínimo permitido nos parâmetros da presidência',1,60)
                    , vrAcaoSobreCritica.vnPermissMargemMinima132
                    , ' com estoque disponivel' );
                    
        END IF;

      END IF; -- Fim Condição: -- CRÍTICA - Margem Mínima da 132

      -------------------
      -- CRÍTICA - Alvará
      -------------------
      IF  (vrAcaoSobreCritica.vvAcaoAlvara <> 'I') THEN

        ------------------------------------------------------------------------------------------------------
        -- Obs: Os Itens que chegaram até aqui foram somente os autorizados;
        --      Os proibidos por alvará foram cortados na integradora ou impedidos de serem incluídos na 2316.
        --      Por isso aqui prevalece a gravação do pedido como bloquedo e não abortar o pedido, bem como 
        --      não trata a rejeição do produto conforme configuração no Controle de Venda.
        --      Até porque esta última validação foi desenvolvida exclusivamente para registrar o produto 
        --      e o Alvará que motivou o Motivo do Bloqueio.
        
        -- Inicializa a Ação
        vvAuxAcaoAlvara := 'I';
        
        -- Inicialzia Retornos da Validação
        vrRetAlvara.vvPodeComprarProduto   := NULL;
        vrRetAlvara.vvMotivoNaoPodeComprar := NULL;
        vrRetAlvara.vnQtdeLimite           := NULL;
        
        -- Se Liberação do Pedido
        P_VALIDA_CONTROLE_VENDA('P', -- Validar ao Iniciar o Pedido
                                vrPedido.vnCodCli,
                                vrCliente.vvTipoFJ,
                                pi_nCodProd,
                                NVL(pi_nQtdeComCorte,0),   
                                pi_nNumPed,
                                pi_nNumSeq,
                                vrRetAlvara.vvPodeComprarProduto,
                                vrRetAlvara.vvMotivoNaoPodeComprar,
                                vrRetAlvara.vnQtdeLimite,
                                pi_nCodRotina);
        IF (vrRetAlvara.vvPodeComprarProduto = 'N') THEN
          IF (pi_nCodRotina = 2641) THEN
            vvAuxAcaoAlvara := 'B';
          ELSE
            IF    (vrAcaoSobreCritica.vvAcaoAlvara = 'B') THEN
              vvAuxAcaoAlvara := 'B';
            ELSIF (vrAcaoSobreCritica.vvAcaoAlvara = 'P') THEN
              vvAuxAcaoAlvara := 'P';
            ELSE
              vvAuxAcaoAlvara := 'A';
            END IF;
          END IF;
        ELSE                              
          P_VALIDA_CONTROLE_VENDA('I', -- Validar ao Incluir o Item
                                  vrPedido.vnCodCli,
                                  vrCliente.vvTipoFJ,
                                  pi_nCodProd,
                                  NVL(pi_nQtdeComCorte,0),   
                                  pi_nNumPed,
                                  pi_nNumSeq,
                                  vrRetAlvara.vvPodeComprarProduto,
                                  vrRetAlvara.vvMotivoNaoPodeComprar,
                                  vrRetAlvara.vnQtdeLimite,
                                  pi_nCodRotina);
          IF (vrRetAlvara.vvPodeComprarProduto = 'N') THEN
            IF (pi_nCodRotina = 2641) THEN
              vvAuxAcaoAlvara := 'B';
            ELSE
              IF    (vrAcaoSobreCritica.vvAcaoAlvara = 'B') THEN
                vvAuxAcaoAlvara := 'B';
              ELSIF (vrAcaoSobreCritica.vvAcaoAlvara = 'P') THEN
                vvAuxAcaoAlvara := 'P';
              ELSE
                vvAuxAcaoAlvara := 'A';
              END IF;
            END IF;
          ELSE                              
            P_VALIDA_CONTROLE_VENDA('G', -- Validar ao Gravar o Pedido
                                    vrPedido.vnCodCli,
                                    vrCliente.vvTipoFJ,
                                    pi_nCodProd,
                                    NVL(pi_nQtdeComCorte,0),   
                                    pi_nNumPed,
                                    pi_nNumSeq,
                                    vrRetAlvara.vvPodeComprarProduto,
                                    vrRetAlvara.vvMotivoNaoPodeComprar,
                                    vrRetAlvara.vnQtdeLimite,
                                    pi_nCodRotina);
            IF (vrRetAlvara.vvPodeComprarProduto = 'N') THEN
              IF (pi_nCodRotina = 2641) THEN
                vvAuxAcaoAlvara := 'B';
              ELSE
                IF (vrAcaoSobreCritica.vvAcaoAlvara = 'B') THEN
                  vvAuxAcaoAlvara := 'B';
                ELSE
                  vvAuxAcaoAlvara := 'P';
                END IF;
              END IF;
            END IF;
          END IF;
        END IF;
  
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
           SET VALORATINGIDO  = 1
         WHERE (NUMPED      = pi_nNumPed)
           AND (CODPLPAG    = pi_nCodProd)
           AND (CODREJEICAO = 25); -- CODREJEICAO
           
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
                
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , pi_nCodProd
                    , 25 -- CODREJEICAO
                    , vvAuxAcaoAlvara
                    , SUBSTR('Pedido com restrição de alvará',1,100)
                    , vrAcaoSobreCritica.vnCodRotinaAlvara
                    , 1
                    , 1
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsAlvara
                    , 17
                    , NULL
                    , SUBSTR('Pedido com restrição de alvará',1,60)
                    , vrAcaoSobreCritica.vnPermissAlvara
                    , vrRetAlvara.vvMotivoNaoPodeComprar );
                                          
        END IF; -- Fim: Se Rejeita ou Bloqueia por Alvará
 
      END IF; -- Fim Condição: -- CRÍTICA - Alvará
      
      ------------------------------------------------------------------------------------
      -- CRÍTICA - Se Integradora Parametrizada para Gravar o Pedido Sempre como Bloqueado
      ------------------------------------------------------------------------------------
      IF (NVL(vrIntegradora.vvGeraPedBloq,'N') = 'S')        AND
         (vrAcaoSobreCritica.vvAcaoGerarPedBloq IS NOT NULL) THEN
      
        BEGIN
          SELECT 'S'
            INTO vvAchouAcao
            FROM PCMED_VALIDACAO_ESTOQUE_RESERV
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
             AND (CODREJEICAO = 26); -- CODREJEICAO
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouAcao := 'N';
        END;
      
        IF (NVL(vvAchouAcao,'N') = 'N') THEN
          -- Grava Ação de Bloqueio
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4 )
             VALUES ( pi_nNumPed
                    , 0   -- Sem Plano de Pagamento
                    , 26  -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoGerarPedBloq -- ACAO
                    , SUBSTR('Pedido com Bloqueio Automático da Integradora',1,100)
                    , 2302
                    , 'X'
                    , NULL
                    , 704
                    , NULL
                    , SUBSTR('Pedido com Bloqueio Automático da Integradora',1,60)
                    , NULL );
        END IF;          
      
      END IF; -- Fim Condição: -- CRÍTICA - Se Empresa Parametrizado para Gravar o Pedido Sempre como Bloqueado            
      
      ------------------------------------------------------------------------------
      -- CRÍTICA - Restrição de Venda para a Filial por Valor Mínimo - DDMEDICA-3464
      ------------------------------------------------------------------------------
      UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
         SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
       WHERE (NUMPED      = pi_nNumPed)
         AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
         AND (CODREJEICAO = 27); -- CODREJEICAO

      IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
        INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                  ( NUMPED
                  , CODPLPAG
                  , CODREJEICAO
                  , ACAO
                  , DESCRICAOREJEICAO
                  , CODROTINA
                  , VALORVALIDACAO
                  , VALORATINGIDO
                  , VENDAPERMITIDA
                  , NUMEROPARAMETRO
                  , CODMOTIVO
                  , CODMOTBLOQUEIO
                  , MOTIVOPOSICAO
                  , PERMISSAO
                  , SOLUCAOP4 )
           VALUES ( pi_nNumPed
                  , 0  -- Sem Plano de Pagamento
                  , 27 -- CODREJEICAO
                  , vrAcaoSobreCritica.vvAcaoValorMinRestr
                  , SUBSTR('Restrição de Venda para a Filial por Valor Mínimo',1,100)
                  , 391
                  , 0  -- Valor Mínimo será calculado em Função
                  , (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
                  , 'X'
                  , NULL
                  , NULL
                  , NULL
                  , SUBSTR('Pedido com valor abaixo do mínimo para restrição de venda',1,60)
                  , NULL
                  , vvSolucaoP4 );
      END IF;
            
      -------------------------------------------------
      -- CRÍTICA - Bloqueios Comerciais - DDMEDICA-3918
      -------------------------------------------------   
      IF (NVL(vnQtdeValidaValorMinimo,0) > 0) THEN  

        OPEN C_PCBLOQUEIO(pi_nNumPed,
                          vrPedido.vnCodCli,
                          vrPedido.vnCondVenda,
                          vrCliente.vnCodPraca,
                          pi_nCodPlPagItem,
                          pi_nMatricula,
                          vrPedido.vvCodCob,
                          vrPedido.vvFreteDespacho,
                          vrPedido.vvOrigemPed,
                          vrCliente.vvClienteMonitorado,
                          (NVL(vnValorTotalAtingidoValidaMin,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))),
                          vrPedido.vvCodFilial,
                          pi_nCodProd);
        LOOP
        
          FETCH C_PCBLOQUEIO
            INTO VCPCBLOQUEIO;
          EXIT WHEN C_PCBLOQUEIO%NOTFOUND;
          
          UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
             SET VALORATINGIDO = LEAST( (NVL(vnValorTotalAtingidoValidaMin,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))) , 999999999999.99 )
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = NVL(VCPCBLOQUEIO.CODMOTBLOQUEIO,0))
             AND (CODREJEICAO = 28); -- CODREJEICAO
    
          IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
            INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                      ( NUMPED
                      , CODPLPAG
                      , CODREJEICAO
                      , ACAO
                      , DESCRICAOREJEICAO
                      , CODROTINA
                      , VALORVALIDACAO
                      , VALORATINGIDO
                      , VENDAPERMITIDA
                      , NUMEROPARAMETRO
                      , CODMOTIVO
                      , CODMOTBLOQUEIO
                      , MOTIVOPOSICAO
                      , PERMISSAO
                      , SOLUCAOP4 )
               VALUES ( pi_nNumPed
                      , NVL( VCPCBLOQUEIO.CODMOTBLOQUEIO,0)
                      , 28 -- CODREJEICAO
                      , vrAcaoSobreCritica.vvAcaoBloqueioComercial
                      , SUBSTR('Bloqueios Comerciais',1,100)
                      , 307
                      , 0  -- Não terá validação de Valor Mínimo
                      , LEAST( (NVL(vnValorTotalAtingidoValidaMin,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))) , 999999999999.99 )
                      , 'X'
                      , NULL
                      , NVL(VCPCBLOQUEIO.CODMOTIVO,-1) -- Grava motivo manual se não for informado o motivo de bloqueio
                      , VCPCBLOQUEIO.CODMOTBLOQUEIO
                      , SUBSTR(NVL(VCPCBLOQUEIO.DESCRICAO_MOTIVO,'MOTIVO DE BLOQUEIO NÃO INFORMADO'),1,60)
                      , vrAcaoSobreCritica.vvPermissBloqueioComercial
                      , vvSolucaoP4 );
          END IF;
            
        END LOOP;
        
      END IF;
      
      ----------------------------------------------------------
      -- CRÍTICA - Cota de Verba para a Promoção - DDMEDICA-5009
      ----------------------------------------------------------      
      IF (NVL(pi_nQtdeComCorte,0) > 0) THEN -->> SOMENTE PRODUTOS COM ESTOQUE

        -- Laço Para Cada Promoção gera um Motivo
        FOR vc_AlertaCota IN (SELECT DISTINCT 
                                     IDENTIFICADORPRINC
                                FROM PCMED_VALIDACAO_GERAL_TROCA
                               WHERE (NUMPED      = pi_nNumPed)
                                 AND (CODPROD     = pi_nCodProd)
                                 AND (NUMSEQ      = pi_nNumSeq)
                                 AND (CODREJEICAO = 29)
                               ORDER BY IDENTIFICADORPRINC) LOOP

          viContaCotaVerba     := 0;
          vvDescricaoCotaVerba := NULL; 
          FOR vc_AlertaCotaDetail IN (SELECT DISTINCT 
                                             IDENTIFICADORSECUND
                                        FROM PCMED_VALIDACAO_GERAL_TROCA
                                       WHERE (NUMPED             = pi_nNumPed)
                                         AND (CODPROD            = pi_nCodProd)
                                         AND (NUMSEQ             = pi_nNumSeq)
                                         AND (CODREJEICAO        = 29)
                                         AND (IDENTIFICADORPRINC = vc_AlertaCota.IDENTIFICADORPRINC) 
                                       ORDER BY IDENTIFICADORSECUND) LOOP
            BEGIN        
              -- Mensagem
              IF (vvDescricaoCotaVerba IS NOT NULL) THEN
                vvDescricaoCotaVerba := vvDescricaoCotaVerba || ', ';
              END IF;     
              viContaCotaVerba     := NVL(viContaCotaVerba,0) + 1;
              vvDescricaoCotaVerba := vvDescricaoCotaVerba || vc_AlertaCotaDetail.IDENTIFICADORSECUND;
            EXCEPTION
              WHEN OTHERS THEN 
                NULL;
            END;
          END LOOP;      
          
          IF (NVL(viContaCotaVerba,0) = 1) THEN
            vvDescricaoCotaVerba := 'na Verba: ' || vvDescricaoCotaVerba;
          ELSE
            vvDescricaoCotaVerba := 'nas Verbas: ' || vvDescricaoCotaVerba;
          END IF;                                                                  
          
          UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
             SET VALORATINGIDO = NVL(VALORATINGIDO,0) + 1
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = NVL(vc_AlertaCota.IDENTIFICADORPRINC,0)) -- CODIGO DA PROMOÇÃO
             AND (CODREJEICAO = 29); -- CODREJEICAO
    
          IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
            INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                      ( NUMPED
                      , CODPLPAG
                      , CODREJEICAO
                      , ACAO
                      , DESCRICAOREJEICAO
                      , CODROTINA
                      , VALORVALIDACAO
                      , VALORATINGIDO
                      , VENDAPERMITIDA
                      , NUMEROPARAMETRO
                      , CODMOTIVO
                      , CODMOTBLOQUEIO
                      , MOTIVOPOSICAO
                      , PERMISSAO
                      , SOLUCAOP4 )
               VALUES ( pi_nNumPed
                      , NVL(vc_AlertaCota.IDENTIFICADORPRINC,0)
                      , 29 -- CODREJEICAO
                      , 'P' -- ACAO
                      , SUBSTR('Cota de Verba da Promoção excedida',1,100)
                      , 2323
                      , 0  -- Não terá validação de Valor Mínimo
                      , 1  -- Não terá validação de Valor Mínimo
                      , 'X'
                      , NULL
                      , 705
                      , NULL
                      , SUBSTR('Cota de Verba da Promoção excedida',1,60)
                      , NULL
                      , SUBSTR('Cota de Verba da Promoção "' || vc_AlertaCota.IDENTIFICADORPRINC || '" foi excedida ' || vvDescricaoCotaVerba,1,2000) );
          END IF;
            
        END LOOP; -- Fim: Laço Para Cada Promoção gera um Motivo
        
      END IF;

      -------------------------------------------------------------
      -- CRÍTICA - Verba da Promoção já foi Apurada - DDMEDICA-5401
      -------------------------------------------------------------      
      IF (NVL(pi_nQtdeComCorte,0) > 0) THEN -->> SOMENTE PRODUTOS COM ESTOQUE

        -- Laço Para Cada Promoção gera um Motivo
        FOR vc_AlertaCota IN (SELECT DISTINCT 
                                     IDENTIFICADORPRINC
                                FROM PCMED_VALIDACAO_GERAL_TROCA
                               WHERE (NUMPED      = pi_nNumPed)
                                 AND (CODPROD     = pi_nCodProd)
                                 AND (NUMSEQ      = pi_nNumSeq)
                                 AND (CODREJEICAO = 30)
                               ORDER BY IDENTIFICADORPRINC) LOOP

          viContaCotaVerba     := 0;
          vvDescricaoCotaVerba := NULL; 
          FOR vc_AlertaCotaDetail IN (SELECT DISTINCT 
                                             IDENTIFICADORSECUND
                                        FROM PCMED_VALIDACAO_GERAL_TROCA
                                       WHERE (NUMPED             = pi_nNumPed)
                                         AND (CODPROD            = pi_nCodProd)
                                         AND (NUMSEQ             = pi_nNumSeq)
                                         AND (CODREJEICAO        = 30)
                                         AND (IDENTIFICADORPRINC = vc_AlertaCota.IDENTIFICADORPRINC) 
                                       ORDER BY IDENTIFICADORSECUND) LOOP
            BEGIN        
              -- Mensagem
              IF (vvDescricaoCotaVerba IS NOT NULL) THEN
                vvDescricaoCotaVerba := vvDescricaoCotaVerba || ', ';
              END IF;     
              viContaCotaVerba     := NVL(viContaCotaVerba,0) + 1;
              vvDescricaoCotaVerba := vvDescricaoCotaVerba || vc_AlertaCotaDetail.IDENTIFICADORSECUND;
            EXCEPTION
              WHEN OTHERS THEN 
                NULL;
            END;
          END LOOP;      
          
          IF (NVL(viContaCotaVerba,0) = 1) THEN
            vvDescricaoCotaVerba := 'Verba: ' || vvDescricaoCotaVerba;
          ELSE
            vvDescricaoCotaVerba := 'Verbas: ' || vvDescricaoCotaVerba;
          END IF;                                                                  
          
          UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
             SET VALORATINGIDO = NVL(VALORATINGIDO,0) + 1
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = NVL(vc_AlertaCota.IDENTIFICADORPRINC,0)) -- CODIGO DA PROMOÇÃO
             AND (CODREJEICAO = 30); -- CODREJEICAO
    
          IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
            -- Se Rotina 2336
            IF (NVL(pi_nCodRotina,0) = 2336) THEN
              -- Não deixará liberar
              vvAcaoVerbaPromocaoApurada := 'A';
            -- Se Rotinas que passam Pedido
            ELSE
              vvAcaoVerbaPromocaoApurada := 'P';
            END IF;
            INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                      ( NUMPED
                      , CODPLPAG
                      , CODREJEICAO
                      , ACAO
                      , DESCRICAOREJEICAO
                      , CODROTINA
                      , VALORVALIDACAO
                      , VALORATINGIDO
                      , VENDAPERMITIDA
                      , NUMEROPARAMETRO
                      , CODMOTIVO
                      , CODMOTBLOQUEIO
                      , MOTIVOPOSICAO
                      , PERMISSAO
                      , SOLUCAOP4 )
               VALUES ( pi_nNumPed
                      , NVL(vc_AlertaCota.IDENTIFICADORPRINC,0)
                      , 30 -- CODREJEICAO
                      , vvAcaoVerbaPromocaoApurada
                      , SUBSTR('Verba da Promoção já foi apurada',1,100)
                      , 2323
                      , 0  -- Não terá validação de Valor Mínimo
                      , 1  -- Não terá validação de Valor Mínimo
                      , 'X'
                      , NULL
                      , 706
                      , NULL
                      , SUBSTR('Verba da Promoção já foi apurada',1,60)
                      , NULL
                      , SUBSTR('Verba da Promoção "' || vc_AlertaCota.IDENTIFICADORPRINC || '" já foi apurada. ' || vvDescricaoCotaVerba,1,2000) );
          END IF;
            
        END LOOP; -- Fim: Laço Para Cada Promoção gera um Motivo
        
      END IF;
                 
      -------------------------------------
      -- CRÍTICA - Item Bonificado
      -------------------------------------
      IF (NVL(vrParametros.nPERCLIMITEVLTV5,0) > 0) AND
         (NVL(vrRegrasEspecificas.vUSAPARAMLIMITEITEMBNFTV1,'N') = 'S') THEN
  
        IF (NVL(pi_vBonific,'N') = 'F') THEN
          UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
             SET VALORATINGIDO = NVL(VALORATINGIDO,0) + (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0))
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
             AND (CODREJEICAO = 31); -- CODREJEICAO
        ELSE
          UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV
             SET VALORVALIDACAO = NVL(VALORVALIDACAO,0) + ((NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0)) * (NVL(vrParametros.nPERCLIMITEVLTV5,0)/100))
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODPLPAG    = 0)   -- Sem Plano de Pagamento
             AND (CODREJEICAO = 31); -- CODREJEICAO
        END IF;
  
        IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , PERMISSAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 31 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoItemBnfTV1
                    , SUBSTR('Percentual limite de bonificações',1,100)
                    , 132
                    , DECODE(NVL(pi_vBonific,'N'), 'F', 0, ((NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0)) * (NVL(vrParametros.nPERCLIMITEVLTV5,0)/100)))
                    , DECODE(NVL(pi_vBonific,'N'), 'F', (NVL(pi_nPVenda,0) * NVL(vnQtdeValidaValorMinimo,0)), 0)
                    , 'X'
                    , vrAcaoSobreCritica.vvParamsItemBnfTV1
                    , 18
                    , vrAcaoSobreCritica.vnPermissItemBnfTV1
                    , SUBSTR('Itens Bonificados com valor acima de ' || NVL(vrParametros.nPERCLIMITEVLTV5,0) || '% do Valor de Venda',1,60)
                    , NULL
                    , vvSolucaoP4
                    , vrAcaoSobreCritica.vvLibItemBnfTV1 );
                    
        END IF;
  
      END IF; -- Fim Condição: -- CRÍTICA - Item Bonificado

      -------------------------------------------------
      -- CRÍTICA - Faturamento Integral - DDMEDICA-6533
      -------------------------------------------------
      IF (vrPedido.vvOrigemPed = 'F') AND
         (vrPedido.vvTipoFv IN ('OL','PE')) AND
         (vrPedido.vvFaturamentoIntegral IN ('S','1')) THEN
         
        P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                      , pi_nNumPed
                                      , 0  -- Agrupar pelo Pedido
                                      , 32 -- CODREJEICAO
                                      , vrAcaoSobreCritica.vvAcaoFaturamentoIntegral
                                      , SUBSTR('Faturamento Integral',1,100)
                                      , 2302
                                      , vrPedido.vnQtdeTotalPedidoFatIntegral
                                      , NVL(pi_nQtdeComCorte,0)
                                      , 'X'
                                      , NULL -- Parâmetros
                                      , NULL -- Código do Motivo
                                      , NULL -- Código Motivo Bloqueio
                                      , SUBSTR('Faturamento Integral exige Faturamento Integral',1,60)
                                      , NULL -- Permissão
                                      , NULL );
                                
      END IF; -- Fim Condição: -- CRÍTICA - Faturamento Integral
      
      -------------------------------------------------
      -- CRÍTICA - Canal Autorizador PBM - CA PBM
      -------------------------------------------------
      IF (vrPedido.vvOrigemPed = 'T') AND
         -- DDVENDAS-38983-(NVL(vrPedido.vnCodPromocaoMed,0) > 0) AND
         (NVL(vrParametros.vHABILITCANALAUTORIZPBMTELEV,'N') = 'S') THEN
                            
        -- Se existe Integradora CA PBM
        IF (F_EXISTE_INTEGRADORA_CA_PBM = 'S') THEN
          
          -- Verifica se o Produto faz parte de alguma Integradora CA PBM
          vnIntegradoraCaPbm := F_INTEGRADORA_PRODUTO_CA_PBM(pi_nCodProd);
           
          -- Se o Produto e o Pedido participa de alguma Integradora CA PBM
          IF (NVL(vnIntegradoraCaPbm,0) > 0) AND
             (F_PEDIDO_PERMITIDO_CA_PBM(vnIntegradoraCaPbm,
                                        vrPedido.vnCondVenda,
                                        vrPedido.vnCodCli) = 'S') THEN 
          
            P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                          , pi_nNumPed
                                          , 0  -- Agrupar pelo Pedido
                                          , 33 -- CODREJEICAO
                                          , vrAcaoSobreCritica.vvAcaoCanalAutorizadorPbm
                                          , SUBSTR('Canal Autorizador PBM',1,100)
                                          , 2302
                                          , 1    -- Valor Validação
                                          , 1    -- Valor Atingido
                                          , 'X'
                                          , NULL -- Parâmetros
                                          , 707  -- Código do Motivo
                                          , NULL -- Código Motivo Bloqueio
                                          , SUBSTR('Canal Autorizador PBM exige aprovação do desconto na Indústria',1,60)
                                          , NULL -- Permissão
                                          , NULL );
                                          
            -- Insere o Pedido de Operador Logístico
            P_GRAVAR_PEDIDO_CA_PBM(pi_nNumPed,
                                   vrPedido.vnCodCli, -- DDVENDAS-38983
                                   pi_nCodProd,
                                   pi_nNumSeq,
                                   vnIntegradoraCaPbm,
                                   vrPedido.vvCodFilial,
                                   pi_nMatricula,
                                   pi_nQtdePedido,
                                   vnNumPedOperLogCaPbm);
            -- Log:
            P_INSERE_LOG_PROCESSAMENTO('Canal Autorizador:  '    || CHR(13)              ||
                                       'pi_nCodProd = '          || pi_nCodProd          || CHR(13) ||
                                       'vnNumPedOperLogCaPbm = ' || vnNumPedOperLogCaPbm || CHR(13) ||
                                       'pi_vChamadaProcesso = '  || pi_vChamadaProcesso  || CHR(13));                                     
                                                             
          END IF;
          
        END IF;
                                
      END IF; -- Fim Condição: -- CRÍTICA - Canal Autorizador PBM - CA PBM
            
    END P_ATU_CRITICAS_VALOR_MINIMO;  
    
   /*********************************************************************
    PROCEDIMENTO : P_PROC_CRITICAS_VALOR_MINIMO
    DESCRIÇÃO    : Procedimento para processar a Tabela Temporária de
                   Críticas de Valor Mínimo
    *********************************************************************/
    PROCEDURE P_PROC_CRITICAS_VALOR_MINIMO(pi_nSaldoRcaDisponivel      IN NUMBER,
                                           pi_vRejeitaPedRcaSemSaldoFv IN VARCHAR2) IS
      vnSaldoPedRca    NUMBER;
      vvVendaPermitida VARCHAR2(1);
      vnSaldoItemRca   NUMBER;
    BEGIN
  
      -----------------------------------------------------------------------
      -- CONTINUAÇÃO DA CRÍTICA - Venda de Rca sem Saldo - MED-1669
      -----------------------------------------------------------------------
      IF (pi_vMovimentarSaldoRca = 'S') AND
         (vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo IS NOT NULL) THEN
        
        -- Inicializa Saldo Acumulado do Pedido
        vnSaldoPedRca := 0;
        
        -- Processamento dos valores calculados do maior saldo para o menor saldo
        FOR vc_CriticasCalc IN (SELECT CODPROD
                                     , NUMSEQ
                                     , NVL(SALDOITEM,0) SALDOITEM
                                  FROM PCMED_VALIDACAO_SALDO_ITEM
                                 WHERE (NUMPED      = pi_nNumPed)
                                   AND (CODREJEICAO = 12) -- Crítica de Saldo RCA
                                  ORDER BY NVL(SALDOITEM,0) DESC) LOOP -->> FUNDAMENTAL: NÃO MEXER: Ordenar do maior saldo positivo para o menor saldo
                                  
          -- Pega o Saldo Total do Item do Cursor
          vnSaldoItemRca := NVL(vc_CriticasCalc.SALDOITEM,0);
                                  
          -- Verifica se o RCA pode Vender                                                                  
          vvVendaPermitida := 'S';
  
          -- Atualiza Valores Calculados
          UPDATE PCMED_VALIDACAO_SALDO_ITEM
             SET SALDORCA = pi_nSaldoRcaDisponivel
               , SALDOPED = vnSaldoPedRca
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = vc_CriticasCalc.CODPROD)
             AND (NUMSEQ  = vc_CriticasCalc.NUMSEQ)
             AND (CODREJEICAO = 12); -- Crítica de Saldo RCA
  
          -- Se validar o saldo a cada inclusão do item
          -- ATENÇÃO: Se vvVendaPermitida = N, os itens serão excluídos ou bloqueados conforme ação automaticamente na INTEGRADORA_MED
          IF (NVL(vrParametros.vVALIDARSALDORCAPORITEM,'N') = 'S') THEN      
          
            -- Valida o Saldo do Item
            IF ((NVL(pi_nSaldoRcaDisponivel,0) + NVL(vnSaldoItemRca,0) + NVL(vnSaldoPedRca,0)) < 0) AND
               (NVL(vnSaldoItemRca,0) < 0) THEN
              vvVendaPermitida := 'N';
              -- 4415.029804.2019 - Exceção: Rotina 2336 tem uma permissão que permite liberar sem Saldo
              IF (pi_nCodRotina = 2336) THEN
                IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
                  vvVendaPermitida := 'S';
                ELSIF (NOT F_VERIFICARACESSOCONTROLE(2336,67,pi_nMatricula)) THEN -->> Não liberar pedido de venda de rca sem saldo c/c
                  vvVendaPermitida := 'S';
                END IF;          
              END IF;
            END IF;
            
            -- Atualiza Flag de Venda Permitida Item a Item nesta Condição
            UPDATE PCMED_VALIDACAO_SALDO_ITEM
               SET VENDAPERMITIDA = vvVendaPermitida
             WHERE (NUMPED  = pi_nNumPed)
               AND (CODPROD = vc_CriticasCalc.CODPROD)
               AND (NUMSEQ  = vc_CriticasCalc.NUMSEQ)
               AND (CODREJEICAO = 12); -- Crítica de Saldo RCA
            
          END IF; -- Fim: Se validar o saldo a cada inclusão do item 
          
          -- Incrementar Saldo Acumulado do Pedido com o Saldo do Item
          vnSaldoPedRca := NVL(vnSaldoPedRca,0) + NVL(vnSaldoItemRca,0);
                                  
        END LOOP;                                
                                   
        -- MEDICA-477 - Se validar o saldo somente no total do pedido
        -- ATENÇÃO: Se vvVendaPermitida = N, os itens serão excluídos ou bloqueados conforme ação automaticamente na INTEGRADORA_MED
        IF (NVL(vrParametros.vVALIDARSALDORCAPORITEM,'N') <> 'S') THEN      
        
          -- Atualiza Venda Permitida para todos os itens (depois mudará para não os que ficarem negativos)
          UPDATE PCMED_VALIDACAO_SALDO_ITEM
             SET VENDAPERMITIDA = 'S'
           WHERE (NUMPED      = pi_nNumPed)
             AND (CODREJEICAO = 12); -- Crítica de Saldo RCA
        
          -- Valida o Saldo do Pedido
          IF ((NVL(pi_nSaldoRcaDisponivel,0) + NVL(vnSaldoPedRca,0)) < 0) AND
             (NVL(vnSaldoPedRca,0) < 0) THEN
             
            vvVendaPermitida := 'N';
            -- 4415.029804.2019 - Exceção: Rotina 2336 tem uma permissão que permite liberar sem Saldo
            IF (pi_nCodRotina = 2336) THEN
              IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
                vvVendaPermitida := 'S';
              ELSIF (NOT F_VERIFICARACESSOCONTROLE(2336,67,pi_nMatricula)) THEN -->> Não liberar pedido de venda de rca sem saldo c/c
                vvVendaPermitida := 'S';
              END IF;          
            END IF;
            
            -- Atualiza Venda NÃO Permitida para os itens que negativaram o saldo do rca 
            -- (que não é a mesma coisa de item com saldo negativo, podemos ter itens negativos, porém se tiver saldo positivo acumulado deve permitir vender)
            UPDATE PCMED_VALIDACAO_SALDO_ITEM
               SET VENDAPERMITIDA = vvVendaPermitida
             WHERE (NUMPED      = pi_nNumPed)
               AND ((NVL(SALDORCA,0) + NVL(SALDOPED,0) + NVL(SALDOITEM,0)) < 0)
               AND (CODREJEICAO = 12); -- Crítica de Saldo RCA
            
          END IF;
                 
        END IF; -- Fim: Se validar o saldo a cada inclusão do item 
        
        -- DDMEDICA-6363 - Parâmetro para rejeitar o Pedido caso o RCA não tenha saldo de conta corrente
        IF (pi_vRejeitaPedRcaSemSaldoFv = 'S') THEN
          -- Verifica se algum item ficou com saldo de conta corrente insuficiente
          BEGIN
            SELECT VENDAPERMITIDA
              INTO vvVendaPermitida
              FROM PCMED_VALIDACAO_SALDO_ITEM
             WHERE (NUMPED         = pi_nNumPed)
               AND (CODREJEICAO    = 12)  -- Crítica de Saldo RCA
               AND (VENDAPERMITIDA = 'N') -- Item com venda não permitida
               AND (ROWNUM         = 1);  -- Ao menos um item              
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvVendaPermitida := 'S';
          END;
          IF (vvVendaPermitida = 'N') THEN
            UPDATE PCMED_VALIDACAO_SALDO_ITEM
               SET VENDAPERMITIDA = 'N'
             WHERE (NUMPED         = pi_nNumPed)
               AND (VENDAPERMITIDA = 'S') 
               AND (CODREJEICAO    = 12); -- Crítica de Saldo RCA
          END IF;
        END IF;
       
        -- Se Integradora: Somente grava Ação se for para Bloquear o Pedido ou Rejeitar o Pedido
        -- Demais chamadas (2316,2336): Sempre grava a Ação.      
        IF ((pi_nCodRotina = 2513) AND (vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo IN ('A','B','P'))) OR
           (pi_nCodRotina <> 2513) THEN
          INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESERV
                    ( NUMPED
                    , CODPLPAG
                    , CODREJEICAO 
                    , ACAO
                    , DESCRICAOREJEICAO
                    , CODROTINA
                    , VALORVALIDACAO
                    , VALORATINGIDO
                    , VENDAPERMITIDA
                    , NUMEROPARAMETRO
                    , CODMOTIVO
                    , CODMOTBLOQUEIO
                    , MOTIVOPOSICAO
                    , SOLUCAOP4
                    , REGRAPERMISSAO )
             VALUES ( pi_nNumPed
                    , 0  -- Sem Plano de Pagamento
                    , 12 -- CODREJEICAO
                    , vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo
                    , SUBSTR('RCA sem saldo de conta corrente disponivel',1,100)
                    , 356
                    , NVL(pi_nSaldoRcaDisponivel,0)
                    ,  NVL(vnSaldoPedRca,0)
                    , 'X'
                    , (SELECT CASE WHEN (pi_nCodRotina = 2513) THEN '2552' ELSE NULL END FROM DUAL)
                    , 22
                    , NULL
                    , SUBSTR('RCA sem saldo de conta corrente disponivel',1,60)
                    , NULL -- Não precisa de mensagem "com estoque disponível"
                    , vrAcaoSobreCritica.vvLibVendaRcaSemSaldo );
        END IF; -- Fim Condição: Grava Ação de Bloqueio se não for chamado a integradora (a integradora valida item a item, portanto perde a finalidade a crítica de valor mínimo do pedido)                 
       
      END IF;  -- Fim Condição: -- CONTINUAÇÃO DA CRÍTICA - Venda de Rca sem Saldo - MED-1669
     
    END P_PROC_CRITICAS_VALOR_MINIMO;
  
   /*********************************************************************
    FUNÇÃO     : F_ATENDEU_VALOR_MINIMO
    DESCRIÇÃO  : Função para Verificar se Atendeu o Valor Mínimo
    OBSERVACAO : Requer Tabela Temporária Preenchida
    *********************************************************************/
    FUNCTION F_ATENDEU_VALOR_MINIMO RETURN BOOLEAN IS
  
      -- Variável para Receber o Retorno
      vbRetAtendeuValorMinimo       BOOLEAN;
      -- Variáveis auxiliares para Críticas
      vvVendaPermitida              VARCHAR2(1);
      vvObsVendaNaoPermitida        VARCHAR2(2000);
      -- Qtde Ocorrências das Críticas
      viQtdeAcoesIgnorar            INTEGER;
      viQtdeAcoesAbortar            INTEGER;
      viQtdeAcoesPerguntar          INTEGER;
      viQtdeAcoesBloquear           INTEGER;
      -- Outras Variáveis
      vnValorAtingidoBoletoBancario NUMBER;
      viQtdeProdutosNegativamSaldo  INTEGER;
      vbValidaValorPedidoAposCorte  BOOLEAN; -- DDMEDICA-1249
      -- DDMEDICA-1586
      TYPE TRecValoresValidacao     IS RECORD(
           vRejeitado               VARCHAR2(1),
           vGravarComoBloqueado     VARCHAR2(1),
           vDescricaoRejeicao       VARCHAR2(255),
           vMotivoPosicao           VARCHAR2(255),
           vObservacao              VARCHAR2(32000),
           vLogRetorno              VARCHAR2(32000));
      vrValoresValidacao            TRecValoresValidacao;
      -- Percentual de Margem
      vnPercMargem                  NUMBER;
      -- Regra de Permissão
      vvUsaRegraPermissao           VARCHAR2(1);
      vvRegraPermissao              VARCHAR2(1);
      -- Liberação de Bloqueio da Rotina 320 - DDMEDICA-3918
      vvIgnoraAutoriLibBloq         VARCHAR2(1);
      -- Descrição do Plano de Pagamento - DDMEDICA-4032
      vvDescricaoPlPag              PCPLPAG.DESCRICAO%TYPE;
      -- Criticas CA PBM
      vvCriticasCaPbm               VARCHAR2(255);
      vvAcaoExcecao                 VARCHAR2(255);

    BEGIN
    
      -- Verifica se utiliza Regra de Permissão da Rotina 2345
      vvUsaRegraPermissao   := F_USA_REGRA_PERMISSAO;
      -- Verifica se Ignora Autorização do Bloqueio da Rotina 320 - DDMEDICA-3918
      vvIgnoraAutoriLibBloq := F_IGNORA_AUTORIZACAO_LIB_BLOQ;
    
      ----------------------------------------------------------------------------------------------
      -- DDMEDICA-1249 - Tratamento para no Corte Total do Pedido não mandar Pedidos para o Bloqueio
      -- Críticas:
      -- Valor Mínimo do Pedido
      -- Valor Mínimo do RCA
      -- Valor Mínimo da Cobrança
      ----------------------------------------------------------------------------------------------
      IF (pi_nCodRotina = 2513) THEN
      
        -- Verifica se Valida o Valor do Pedido Após o Corte
        vbValidaValorPedidoAposCorte := FALSE;
        
        -- OPERADOR LOGÍSTICO
        IF (NVL(vrPedido.vvValidarMinOperadorLogistico,'N') = 'S') THEN
          -- Ao validar o Valor Mínimo, que ocorre antes de Baixar o Estoque, o campo "PCCONDICAOVENDA.TIPOVALORMINIMO"
          -- dá a opção se Validar pelo Valor Total ou pelo Valor Total menos o Corte
          IF (NVL(vrCondicaoVenda.vvTipoValorMinimo,'C') = 'A')  THEN
            -- Após o Corte
            vbValidaValorPedidoAposCorte := TRUE;
          END IF;
        -- DEMAIS VENDAS
        ELSE
          -- Ao validar o Valor Mínimo, que ocorre antes de Baixar o Estoque, o Parâmetro "ACEITAVENDASEMEST"
          -- dá a opção se Validar pelo Valor Total ou pelo Valor Total menos o Corte
          IF (NVL(vrParametros.vACEITAVENDASEMEST,'N') = 'N')  THEN
            vbValidaValorPedidoAposCorte := TRUE;
          END IF;
        END IF;
        
        -- Se Valida o Valor do Pedido Após o Corte
        IF (vbValidaValorPedidoAposCorte) THEN
          FOR vc_Criticas IN (SELECT PCMED_VALIDACAO_ESTOQUE_RESERV.NUMPED
                                   , PCMED_VALIDACAO_ESTOQUE_RESERV.CODPLPAG
                                   , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                                FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                               WHERE (NVL(VALORATINGIDO,0) = 0)) LOOP
            -- CRÍTICA - Valor Mínimo Venda RCA
            -- CRÍTICA - Valor Mínimo Pedido de Venda
            -- CRÍTICA - Valor Mínimo da Cobrança
            IF (vc_Criticas.CODREJEICAO IN (5))  OR
               (vc_Criticas.CODREJEICAO IN (6))  OR
               (vc_Criticas.CODREJEICAO IN (14)) THEN
              -- Atualiza Tabela Temporária para Abortar o Pedido como vai ter Corte Total
              UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV 
                 SET ACAO = 'A'
               WHERE NUMPED      = vc_Criticas.NUMPED  
                 AND CODPLPAG    = vc_Criticas.CODPLPAG
                 AND CODREJEICAO = vc_Criticas.CODREJEICAO;           
            END IF; 
          END LOOP;
        END IF;
        
      END IF; -- FIM: DDMEDICA-1249 - Tratamento para no Corte Total do Pedido não mandar Pedidos para o Bloqueio
      
      ----------------------------------------------------------------------------------------------
      -- Laço de Processamento das Críticas
      ----------------------------------------------------------------------------------------------
      FOR vc_Criticas IN (SELECT PCMED_VALIDACAO_ESTOQUE_RESERV.NUMPED
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.CODPLPAG
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.VALORVALIDACAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.VALORATINGIDO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.QTDEPARCELAS
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.SOLUCAOP4
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO -- DDMEDICA-1586
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.VALORATINGIDO2
                            FROM PCMED_VALIDACAO_ESTOQUE_RESERV) LOOP
         
        -- Inicializa Flag
        vvVendaPermitida       := NULL;
        vvObsVendaNaoPermitida := NULL;
                           
        -------------------------------------------------------------
        -- CRÍTICA - Quantidade de Itens Máximo do Plano de Pagamento
        -------------------------------------------------------------
        IF    (vc_Criticas.CODREJEICAO IN (1)) THEN             
                     
          IF (NVL(vc_Criticas.VALORATINGIDO,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';                          
          ELSE
            vvVendaPermitida       := 'N';       
            vvObsVendaNaoPermitida := 'Qtde. de Itens do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),0) ||
                                      ' inferior à Qtde. Mínima do Plano de Pagamento: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),0);
          END IF;    
          
        END IF;
          
        -----------------------------------------------
        -- CRÍTICA - Valor Mínimo do Plano de Pagamento
        -----------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (2)) THEN  
        
          -- DDMEDICA-4032
          BEGIN
            SELECT DESCRICAO
              INTO vvDescricaoPlPag
              FROM PCPLPAG
             WHERE (CODPLPAG = vc_Criticas.CODPLPAG);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvDescricaoPlPag := NULL;
          END;
           
          -- DDMEDICA-4032 - Se Cortar todos os produtos do Plano de Pagamento, não entra na Crítica de Valor Mínimo do Plano de Pagamento
          IF    (NVL(vc_Criticas.VALORATINGIDO,0) = 0) THEN
            vvVendaPermitida       := 'S';                          
          ELSIF ((NVL(vc_Criticas.VALORATINGIDO,0) + 0.10) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';                          
          ELSE
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Mínimo do Plano de Pagamento "' || vvDescricaoPlPag || '": ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          END IF;   
    
        END IF;   
        
        -----------------------------------------
        -- CRÍTICA - Valor Mínimo Boleto Bancário
        -----------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (3)) THEN   
        
          -- Valor da Parcela
          IF    (vrParametros.vTIPOVLMINVENDABK = 'VP') THEN
            IF (NVL(vc_Criticas.QTDEPARCELAS,0) > 0) THEN
              vnValorAtingidoBoletoBancario := ROUND((NVL(vc_Criticas.VALORATINGIDO,0) + 0.10) / NVL(vc_Criticas.QTDEPARCELAS,0),2);
            ELSE
              vnValorAtingidoBoletoBancario := (NVL(vc_Criticas.VALORATINGIDO,0) + 0.10);
            END IF;
            
            IF (NVL(vnValorAtingidoBoletoBancario,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
              vvVendaPermitida       := 'S';                          
            ELSE
              vvVendaPermitida       := 'N';                          
              vvObsVendaNaoPermitida := 'Valor' || vc_Criticas.SOLUCAOP4  || ' da Parcela: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vnValorAtingidoBoletoBancario,0),2) ||
                                        ' inferior ao Valor Mínimo de Venda Boleto Bancário: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2) || CHR(13) || 
                                        'Qtde. Parcelas: ' || vc_Criticas.QTDEPARCELAS;
            END IF;              
          -- Valor Total
          ELSIF (vrParametros.vTIPOVLMINVENDABK = 'VT') THEN
            IF (NVL(vc_Criticas.VALORATINGIDO,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
              vvVendaPermitida       := 'S';                          
            ELSE
              vvVendaPermitida       := 'N';                          
              vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                        ' inferior ao Valor Mínimo de Venda Boleto Bancário: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
            END IF;              
          END IF;
        
        END IF;
         
        ------------------------------------------
        -- CRÍTICA - Valor Mínimo Venda Bonificada
        ------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (4)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';                          
          ELSE
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Mínimo para Venda Bonificada: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          END IF;              
          
        END IF;  
        
        -----------------------------------
        -- CRÍTICA - Valor Mínimo Venda RCA
        -----------------------------------
        IF (vc_Criticas.CODREJEICAO IN (5)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';                          
          ELSE
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Mínimo: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2) || 
                                      ' cadastrado para o RCA ' || vrPedido.vnCodUsur;
          END IF;              
    
        END IF;
        
        -----------------------------------------
        -- CRÍTICA - Valor Mínimo Pedido de Venda
        -----------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (6)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';                          
          ELSE
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Mínimo do Pedido de Venda: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          END IF;                      
    
        END IF;   
    
        ------------------------
        -- CRÍTICA - Bonificação
        ------------------------
        IF (vc_Criticas.CODREJEICAO IN (7)) THEN   
        
          vvVendaPermitida       := 'N';                          
          vvObsVendaNaoPermitida := 'Pedido Bonificado bloqueado automaticamente conforme parâmetro da presidência "Bloquear pedido bonificado no Telemarketing ou Força de Vendas"';
    
        END IF;   
    
        -----------------------------------------
        -- CRÍTICA - Gravar Pedido como Bloqueado
        -----------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (8)) THEN   
        
          vvVendaPermitida       := 'N';                          
          vvObsVendaNaoPermitida := 'Pedido bloqueado automaticamente conforme parâmetro da presidência "Gravar Pedidos de Venda como Bloqueados"';
    
        END IF;   
        
        ----------------------------------------------
        -- CRÍTICA - Valor Mínimo da Condição de Venda
        ----------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (9)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';                          
          ELSE
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Mínimo da Condição de Venda: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          END IF;                      
    
        END IF;         
  
        -------------------------------------------------------------------------------------------------
        -- CRÍTICA - Gravar Pedido como Bloqueado quando tem Valor de Desconto Negociado - HIS.05093.2017
        -------------------------------------------------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (10)) THEN   
        
          vvVendaPermitida       := 'N';                          
          vvObsVendaNaoPermitida := 'Pedido com Valor de Desconto Negociado: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2) || '.' ||
                                    ' (requer Aprovação do Pedido na Rotina 2336)';
    
        END IF;         
  
        -----------------------------------------
        -- CRÍTICA - Valor Mínimo Pedido de Venda
        -----------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (11)) THEN   
        
          IF ((NVL(vc_Criticas.VALORATINGIDO,0) + 1) < NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor Liquido do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Liquido aprovado para aplicação do Desconto Negociado: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);                                    
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
    
        END IF;   
  
        ----------------------------------------------
        -- CRÍTICA - Venda de Rca sem Saldo - MED-1669
        ----------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (12)) THEN   
        
          -- DDMEDICA-614
          -- Se 2336, validar de forma diferente, se o saldo total do pedido está negativo
          -- e se o saldo atual + limite de crédito está negativo
          IF (pi_nCodRotina = 2336) AND 
             (NOT F_MOVSALDORCAPORPEDIDOFAT) THEN -->> DDMEDICA-683 - Exclui-se o processo de movimentação no faturamento, porque neste caso o saldo não fica negativo na venda
  
          
            -- Se Saldo do Pedido Negativo e se o Saldo RCA for ficar negativo
            IF (NVL(vc_Criticas.VALORATINGIDO,0) < 0) AND (NVL(vc_Criticas.VALORVALIDACAO,0) < 0) THEN
              vvVendaPermitida       := 'N';                          
              vvObsVendaNaoPermitida := 'Valor de conta corrente movimentado no Pedido: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                        ' não permitido para saldo atual de conta corrente do RCA : ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);                                    
            ELSE
              vvVendaPermitida       := 'S';                          
            END IF;        
          
          -- Outras chamadas, valida valor movimentado com o saldo atual
          ELSE
        
            -- MEDICA-477 - Aqui mantido a validação de cabeçalho
          
            -- Se validar o saldo a cada inclusão do item
            IF (NVL(vrParametros.vVALIDARSALDORCAPORITEM,'N') = 'S') THEN
              
              -- Verifica se algum item ficou com saldo negativo
              SELECT COUNT(*)
                INTO viQtdeProdutosNegativamSaldo
                FROM PCMED_VALIDACAO_SALDO_ITEM
               WHERE (NUMPED         = pi_nNumped)
                 AND (CODREJEICAO    = 12) -- CODREJEICAO
                 AND (VENDAPERMITIDA = 'N');
              IF (NVL(viQtdeProdutosNegativamSaldo,0) > 0) THEN
                vvVendaPermitida := 'N';
              ELSE
                vvVendaPermitida := 'S';
              END IF;
    
              -- Se Saldo do Item Negativo
              IF (vvVendaPermitida = 'N') THEN
                IF (viQtdeProdutosNegativamSaldo = 1) THEN
                  vvObsVendaNaoPermitida := 'RCA sem saldo disponivel para atender 1 produto do pedido que debita o conta-corrente';
                ELSE
                  vvObsVendaNaoPermitida := 'RCA sem saldo disponivel para atender ' || viQtdeProdutosNegativamSaldo || 'produtos do pedido que debitam o conta-corrente';
                END IF;
              END IF;
              
            -- Se validar o saldo no final do pedido
            ELSE
            
              -- Se Saldo do Pedido Negativo e se o Saldo RCA for ficar negativo
              IF (NVL(vc_Criticas.VALORATINGIDO,0) < 0) AND
                 ((NVL(vc_Criticas.VALORVALIDACAO,0) + NVL(vc_Criticas.VALORATINGIDO,0)) < 0) THEN
                vvVendaPermitida       := 'N';                          
                vvObsVendaNaoPermitida := 'Valor de conta corrente movimentado no Pedido: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                          ' não permitido para saldo atual de conta corrente do RCA : ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);                                    
              ELSE
                vvVendaPermitida       := 'S';                          
              END IF;
              
            END IF;                      
            
          END IF; -- Fim Condição: Rotina Origem - DDMEDICA-614
    
        END IF;   
        
        ------------------------------
        -- CRÍTICA - Ter Estoque Total
        ------------------------------
        IF (vc_Criticas.CODREJEICAO IN (13)) THEN   
        
          -- Se Saldo do Pedido Negativo e se o Saldo RCA for ficar negativo
          IF (NVL(vc_Criticas.VALORATINGIDO,0) < NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Quantidade de total de estoque disponível: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),0) ||
                                      ' insuficiente para atender a quantidade total pedida: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),0);                                    
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;
              
        END IF;   
  
        -------------------------------------
        -- CRÍTICA - Valor Mínimo da Cobrança
        -------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (14)) THEN
  
          IF ((NVL(vc_Criticas.VALORATINGIDO,0) + 0.10) >= NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'S';
          ELSE
            vvVendaPermitida       := 'N';
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' inferior ao Valor Mínimo da Cobrança: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          END IF;
  
        END IF;
  
        ------------------------------------------
        -- CRÍTICA - RCA Bloqueado - DDMEDICA-1586
        ------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (15)) THEN
  
          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.DESCRICAOREJEICAO;
  
        END IF;      
  
        ----------------------------------------------
        -- CRÍTICA - Cliente Bloqueado - DDMEDICA-1586
        ---------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (16)) THEN
  
          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.DESCRICAOREJEICAO;
          -- Observação Adicional
          BEGIN
            SELECT SUBSTR(vvObsVendaNaoPermitida || ' [Obs: ' || PCCLIENT.OBS || ' ; ' || 'Obs2: ' || PCCLIENT.OBS2 || ']', 1, 2000)
              INTO vvObsVendaNaoPermitida
              FROM PCCLIENT 
             WHERE (PCCLIENT.CODCLI = vrPedido.vnCodCli);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              NULL;
          END;
  
        END IF;
  
        ------------------------------------------------
        -- CRÍTICA - Cliente sem Crédito - DDMEDICA-1586
        ------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (17)) THEN   

          -- Pedido de Avaria não valida Limite de Crédito
          IF (NVL(pi_vPedidoAvaria,'N') = 'S') THEN
            vrValoresValidacao.vRejeitado := 'N';
          ELSE
            P_BLOQUEIO_LIMCRED(pi_nMatricula,
                               pi_nCodRotina,
                               pi_nNumPed,
                               vrPedido.vnCodCli,
                               vrPedido.vnCodUsur,
                               NVL(vc_Criticas.VALORATINGIDO,0),
                               vrParametros.vSOMACREDITOCLIPRINCIPAL,
                               vrParametros.vUSABNFLIMITECREDITO,
                               vrParametros.nPEREXCEDELIMCRED,
                               vrParametros.vBLOQPEDLIMCRED,
                               vrParametros.nNUMCASASDECVENDA,
                               pi_vChamadaProcesso,
                               po_vPosicaoFinalPedido,
                               vrValoresValidacao.vRejeitado,
                               vrValoresValidacao.vGravarComoBloqueado,
                               vrValoresValidacao.vDescricaoRejeicao,
                               vrValoresValidacao.vMotivoPosicao,
                               vrValoresValidacao.vObservacao,
                               vrValoresValidacao.vLogRetorno);                             
          END IF;
                                                            
          IF (vrValoresValidacao.vRejeitado = 'S') THEN
            vvVendaPermitida       := 'N';
            vvObsVendaNaoPermitida := SUBSTR(vrValoresValidacao.vObservacao,1,2000);
          ELSE
            vvVendaPermitida       := 'S';
            vvObsVendaNaoPermitida := NULL;
          END IF;
         
          -- Log: Limite de Crédito
          P_INSERE_LOG_PROCESSAMENTO('Detalhamento do Limite de Crédito:  ' || CHR(13) || vrValoresValidacao.vLogRetorno);
         
        END IF;   

        ----------------------------------
        -- CRÍTICA - Valor Máximo de Venda
        ----------------------------------
        IF (vc_Criticas.CODREJEICAO IN (18)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) > NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' superior ao valor máximo de venda: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
    
        END IF;   

        -------------------------------------
        -- CRÍTICA - Valor Máximo de Venda PF
        -------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (19)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) > NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' superior ao valor máximo de venda para pessoa fisica: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
    
        END IF;   

        --------------------------------------
        -- CRÍTICA - Valor Máximo de Venda BNF
        --------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (20)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) > NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' superior ao valor máximo de venda bonificada: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
    
        END IF;   

        ----------------------------------------------------
        -- CRÍTICA - Preço Abaixo do Mínimo - DDMEDICA-1586
        ----------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (21)) THEN
  
          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.SOLUCAOP4;
          -- Observação Adicional
          BEGIN
            SELECT 'Produto ' || CODPROD || ': ' || vvObsVendaNaoPermitida || ' (' || DESCRICAO || ')'
              INTO vvObsVendaNaoPermitida
              FROM PCPRODUT
             WHERE (CODPROD = vc_Criticas.CODPLPAG);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              NULL;
          END;
  
        END IF;      

        ---------------------------------------------------------------------
        -- CRÍTICA - Prazo Médio do Pedido Superior ao Prazo Médio do Cliente
        ---------------------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (22)) THEN   
  
          IF (NVL(vc_Criticas.VALORATINGIDO,0) > NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := vc_Criticas.SOLUCAOP4;
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
         
        END IF;   

        ------------------------------------------------
        -- CRÍTICA - Margem Mínima do Plano de Pagamento
        ------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (23)) THEN  
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) = 0) THEN
            vnPercMargem := 0;
          ELSE
            vnPercMargem := ((NVL(vc_Criticas.VALORATINGIDO,0) - NVL(vc_Criticas.VALORATINGIDO2,0)) / NVL(vc_Criticas.VALORATINGIDO,0)) * 100;
          END IF;
        
          IF (NVL(vnPercMargem,0) <  NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'O Percentual de Margem do Pedido: ' || FFORMATAR_NUMERO_PARA_TEXTO(nvl(vnPercMargem,0),2) || CHR(13) ||
                                      'inferior ao Percentual Mínimo: ' || FFORMATAR_NUMERO_PARA_TEXTO(nvl(vc_Criticas.VALORVALIDACAO,0),2);
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
    
        END IF;   

        ---------------------------------
        -- CRÍTICA - Margem Mínima da 132
        ---------------------------------
        IF (vc_Criticas.CODREJEICAO IN (24)) THEN  
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) = 0) THEN
            vnPercMargem := 0;
          ELSE
            vnPercMargem := ((NVL(vc_Criticas.VALORATINGIDO,0) - NVL(vc_Criticas.VALORATINGIDO2,0)) / NVL(vc_Criticas.VALORATINGIDO,0)) * 100;
          END IF;
        
          IF (NVL(vnPercMargem,0) <  NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'O Percentual de Margem do Pedido: ' || FFORMATAR_NUMERO_PARA_TEXTO(nvl(vnPercMargem,0),2) || CHR(13) ||
                                      'inferior ao Percentual Mínimo: ' || FFORMATAR_NUMERO_PARA_TEXTO(nvl(vc_Criticas.VALORVALIDACAO,0),2);
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;                      
    
        END IF;   

        -------------------
        -- CRÍTICA - Alvará
        -------------------
        IF (vc_Criticas.CODREJEICAO IN (25)) THEN  
        
          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.SOLUCAOP4;
          -- Observação Adicional
          BEGIN
            SELECT 'Produto ' || CODPROD || ': ' || vvObsVendaNaoPermitida || ' (' || DESCRICAO || ')'
              INTO vvObsVendaNaoPermitida
              FROM PCPRODUT
             WHERE (CODPROD = vc_Criticas.CODPLPAG);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              NULL;
          END;
    
        END IF;   

        ------------------------------------------------------------------------------------
        -- CRÍTICA - Se Integradora Parametrizada para Gravar o Pedido Sempre como Bloqueado
        ------------------------------------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (26)) THEN   
        
          -- Observação Adicional
          BEGIN
            SELECT INTEGRADORA || ' - ' || DESCRICAO
              INTO vvObsVendaNaoPermitida
              FROM PCINTEGRADORA
             WHERE (INTEGRADORA = vrPedido.vnIntegradora);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvObsVendaNaoPermitida := vrPedido.vnIntegradora;
          END;
        
          vvVendaPermitida       := 'N';                          
          vvObsVendaNaoPermitida := 'Pedido bloqueado automaticamente conforme oção "Bloquer Pedidos na Importação" da Integradora "' || vvObsVendaNaoPermitida || '"';
    
        END IF;   

        -------------------------------------------------------------------------
        -- CRÍTICA - Motivo do Pedido (Motivo ainda não Implementado nos Motivos)
        -------------------------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (9999)) THEN  

          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.DESCRICAOREJEICAO;
    
        END IF;   
        
        ------------------------------------------------------------------------------
        -- CRÍTICA - Restrição de Venda para a Filial por Valor Mínimo - DDMEDICA-3464
        ------------------------------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (27)) THEN

          IF (F_VALIDARESTRICAOVENDAFIL(vrPedido.vvCodFilial,
                                        vrPedido.vvOrigemPed,
                                        vrPedido.vvTipoFv,
                                        NVL(vc_Criticas.VALORATINGIDO,0),
                                        vrPedido.vnCodCondicaoVenda,
                                        vrPedido.vnCondVenda, -- DDMEDICA-7580
                                        vrValoresValidacao.vObservacao,                                        
                                        vrPedido.vnCodCli, -- DDVENDAS-38264
                                        vrPedido.vnCodUsur, 
                                        vrPedido.vnCodPlPag,
                                        vrPedido.vvCodCob,
                                        vrPedido.vnCodSupervisor,
                                        vrCliente.vnCodAtv1,
                                        vrCliente.vvTipoFj,
                                        vrCliente.vnCodPraca,
                                        pi_nNumRegiao
                                        )) THEN

            vvVendaPermitida       := 'N';
            vvObsVendaNaoPermitida := SUBSTR(vrValoresValidacao.vObservacao,1,2000);
         
          ELSE
          
            vvVendaPermitida       := 'S';
            
          END IF;
  
        END IF;

        -------------------------------------------------
        -- CRÍTICA - Bloqueios Comerciais - DDMEDICA-3918
        -------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (28)) THEN   
        
          -- Observação Adicional
          BEGIN
            SELECT PCMOTBLOQUEIO.DESCRICAO || ' do tipo ' || DECODE(TIPO,1,'FINANCEIRO','COMERCIAL')
              INTO vvObsVendaNaoPermitida
              FROM PCMOTBLOQUEIO
             WHERE (CODMOTIVO = vc_Criticas.CODMOTIVO);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvObsVendaNaoPermitida := NULL;
          END;
          
          vvVendaPermitida       := 'N';                          
          vvObsVendaNaoPermitida := vvObsVendaNaoPermitida || ' gerado automaticamente a partir do bloqueio número "' || vc_Criticas.CODMOTBLOQUEIO || '" cadastrado na rotina 307';
    
        END IF;   

        ----------------------------------------------------------
        -- CRÍTICA - Cota de Verba para a Promoção - DDMEDICA-5009
        ----------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (29)) THEN   
        
          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.SOLUCAOP4;
        
        END IF;

        -------------------------------------------------------------
        -- CRÍTICA - Verba para a Promoção já Apurada - DDMEDICA-5401
        -------------------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (30)) THEN   
        
          vvVendaPermitida       := 'N';
          vvObsVendaNaoPermitida := vc_Criticas.SOLUCAOP4;
        
        END IF;

        ------------------------------------------
        -- CRÍTICA - Item Bonificado
        ------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (31)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) > NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Valor em Itens Bonificados do Pedido' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),2) ||
                                      ' superior ao Limite Permitido: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),2);
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;              
          
        END IF;  

        -------------------------------------------------
        -- CRÍTICA - Faturamento Integral - DDMEDICA-6533
        -------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (32)) THEN   
        
          IF (NVL(vc_Criticas.VALORATINGIDO,0) < NVL(vc_Criticas.VALORVALIDACAO,0)) THEN
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := 'Quantidade total atendida' || vc_Criticas.SOLUCAOP4  || ': ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORATINGIDO,0),0) ||
                                      ' inferior à quantidade total pedida: ' || FERRAMENTAS_MED.FFORMATAR_NUMERO_PARA_TEXTO(NVL(vc_Criticas.VALORVALIDACAO,0),0) || ' não atingindo o critério de Faturamento Integral';
          ELSE
            vvVendaPermitida       := 'S';                          
          END IF;              
          
        END IF;  

        -------------------------------------------------
        -- CRÍTICA - Canal Autorizador PBM - CA PBM
        -------------------------------------------------
        IF (vc_Criticas.CODREJEICAO IN (33)) THEN   
        
          -- Verifica Críticas do Canal Autorizador
          vvCriticasCaPbm := F_CRITICA_PEDIDO_CA_PBM(pi_nNumPed,
                                                     vrPedido.vnCodCli); -- DDVENDAS-38983
          
          -- Se tem Críticas do Canal Autorizador
          IF (vvCriticasCaPbm IS NOT NULL) THEN
          
            vvVendaPermitida       := 'N';                          
            vvObsVendaNaoPermitida := vvCriticasCaPbm;

            -- Altera a Ação para Abortar Processo (não obedece a Ação Padrão no Motivo de Bloqueio)
            UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV 
               SET ACAO = 'A'
             WHERE NUMPED             = vc_Criticas.NUMPED  
               AND NVL(CODPLPAG,0)    = NVL(vc_Criticas.CODPLPAG,0)
               AND NVL(CODREJEICAO,0) = NVL(vc_Criticas.CODREJEICAO,0);            
                        
          ELSE
        
            -- Produto possui 1 produto do Canal Autorizador, vai gravar como Bloqueado
            IF    (NVL(vc_Criticas.VALORATINGIDO,0) = 1) THEN
              vvVendaPermitida       := 'N';                          
              vvObsVendaNaoPermitida := 'Pedido possui um produto que participa do Canal Autorizador PBM e exige aprovação do desconto na Indústria para Liberação do Pedido';
            -- Produto possui mais de um produto do Canal Autorizador, vai gravar como Bloqueado
            ELSIF (NVL(vc_Criticas.VALORATINGIDO,0) > 1) THEN
              vvVendaPermitida       := 'N';                          
              vvObsVendaNaoPermitida := 'Pedido possui produtos que participam do Canal Autorizador PBM e exige aprovação dos descontos na Indústria para Liberação do Pedido';
            -- Produto não possui Produtos do Canal Autorizador, venda é permitida
            ELSE
              vvVendaPermitida       := 'S';                          
            END IF;
            
          END IF;
          
        END IF;  

        --------------------------------------------------------
        -- Regra de Permissão da Matrícula ao Motivo de Bloqueio
        --------------------------------------------------------
        vvRegraPermissao := F_REGRA_PERMISSAO_MATRICULA(vvUsaRegraPermissao,
                                                        pi_nMatricula,
                                                        vc_Criticas.CODMOTIVO,
                                                        vvIgnoraAutoriLibBloq,
                                                        vc_Criticas.CODMOTBLOQUEIO);
                
        --------------------
        -- Atualiza Críticas
        --------------------
        
        -- Atualiza Tabela Temporária
        UPDATE PCMED_VALIDACAO_ESTOQUE_RESERV 
           SET VENDAPERMITIDA = vvVendaPermitida
             , OBSERVACAO     = SUBSTR('Motivo ' || vc_Criticas.CODMOTIVO || ': ' || vvObsVendaNaoPermitida,1,400)
             , SOLUCAOP4      = NULL -->> Limpa campo usado temporariamente
             , REGRAPERMISSAO = DECODE(NVL(REGRAPERMISSAO,'X'),'A',REGRAPERMISSAO,vvRegraPermissao) -->> Priorizar o Flag para indicar que não tem permissão da 530 e assim a chave ficar amarela na 2336
         WHERE NUMPED             = vc_Criticas.NUMPED  
           AND NVL(CODPLPAG,0)    = NVL(vc_Criticas.CODPLPAG,0)
           AND NVL(CODREJEICAO,0) = NVL(vc_Criticas.CODREJEICAO,0);
                                      
      END LOOP; -- Fim Laço de Processamento das Críticas

      ------------------
      -- Guarda Críticas
      ------------------
      DELETE FROM PCMED_VALIDACAO_ESTOQUE_RESE_H;
      INSERT INTO PCMED_VALIDACAO_ESTOQUE_RESE_H
                ( NUMPED
                , CODPLPAG
                , CODREJEICAO
                , ACAO
                , CODMOTIVONAOATEND
                , TIPOREJEICAO
                , DESCRICAOREJEICAO
                , CODROTINA
                , OBSERVACAO
                , VALORVALIDACAO
                , VALORATINGIDO
                , QTDEPARCELAS
                , VENDAPERMITIDA
                , NUMEROPARAMETRO
                , CODMOTIVO
                , CODMOTBLOQUEIO
                , MOTIVOPOSICAO
                , PERMISSAO
                , PROCEDIMENTO
                , CODROTINAS
                , SOLUCAOP1
                , SOLUCAOP2
                , SOLUCAOP3
                , SOLUCAOP4
                , GRUPOFATURAMENTO
                , DESCRICAOGRUPOFAT
                , SITUACAO
                , CODFUNCAPROVADOR
                , NOMEFUNCAPROVADOR
                , DTAPROVACAO
                , DTINCLUSAO
                , VALORATINGIDO2
                , REGRAPERMISSAO )
           SELECT NUMPED
                , CODPLPAG
                , CODREJEICAO
                , ACAO
                , CODMOTIVONAOATEND
                , TIPOREJEICAO
                , DESCRICAOREJEICAO
                , CODROTINA
                , OBSERVACAO
                , VALORVALIDACAO
                , VALORATINGIDO
                , QTDEPARCELAS
                , VENDAPERMITIDA
                , NUMEROPARAMETRO
                , CODMOTIVO
                , CODMOTBLOQUEIO
                , MOTIVOPOSICAO
                , PERMISSAO
                , PROCEDIMENTO
                , CODROTINAS
                , SOLUCAOP1
                , SOLUCAOP2
                , SOLUCAOP3
                , SOLUCAOP4
                , GRUPOFATURAMENTO
                , DESCRICAOGRUPOFAT
                , SITUACAO
                , CODFUNCAPROVADOR
                , NOMEFUNCAPROVADOR
                , DTAPROVACAO
                , DTINCLUSAO
                , VALORATINGIDO2
                , REGRAPERMISSAO
             FROM PCMED_VALIDACAO_ESTOQUE_RESERV;
      
      --------------------
      -- Atualiza Críticas
      --------------------
      
      -- Atualiza Tabela Temporária - Deixa somente VENDAPERMITIDA = 'N-Não' 
      DELETE FROM PCMED_VALIDACAO_ESTOQUE_RESERV 
       WHERE (NVL(VENDAPERMITIDA,'X') <> 'N');
  
      --------------------
      -- Qtde. de Críticas
      --------------------
      
      -- Verifica a Qtde de Ocorrências de Críticas
      SELECT COUNT(DISTINCT PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO)
        INTO viQtdeAcoesIgnorar
        FROM PCMED_VALIDACAO_ESTOQUE_RESERV
       WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'I');
      --
      SELECT COUNT(DISTINCT PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO)
        INTO viQtdeAcoesAbortar
        FROM PCMED_VALIDACAO_ESTOQUE_RESERV
       WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'A');
      --
      SELECT COUNT(DISTINCT PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO)
        INTO viQtdeAcoesPerguntar
        FROM PCMED_VALIDACAO_ESTOQUE_RESERV
       WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'P');
      --
      SELECT COUNT(DISTINCT PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO)
        INTO viQtdeAcoesBloquear
        FROM PCMED_VALIDACAO_ESTOQUE_RESERV
       WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'B');
       
      -- Log: Ocorrência de Críticas
      P_INSERE_LOG_PROCESSAMENTO('Ocorrência de Críticas:  ' || CHR(13)              ||
                                 'viQtdeAcoesIgnorar = '     || viQtdeAcoesIgnorar   || CHR(13) ||
                                 'viQtdeAcoesAbortar = '     || viQtdeAcoesAbortar   || CHR(13) ||
                                 'viQtdeAcoesPerguntar = '   || viQtdeAcoesPerguntar || CHR(13) ||
                                 'viQtdeAcoesBloquear = '    || viQtdeAcoesBloquear  || CHR(13));
  
      -- Atualiza Retorno se ocorreram Críticas que impedem a Liberação do Pedido por Valor Mínimo
      IF ((NVL(viQtdeAcoesAbortar,0) + NVL(viQtdeAcoesPerguntar,0) + NVL(viQtdeAcoesBloquear,0)) > 0) THEN
        vbRetAtendeuValorMinimo := FALSE;
      END IF;
      
      -- Retorno da Função
      RETURN vbRetAtendeuValorMinimo;    
    
    END F_ATENDEU_VALOR_MINIMO;
    
   /*********************************************************************
    PROCEDIMENTO: P_RETORNAR_TIPOPRAZOMEDICAM
    DESCRIÇÃO   : Retorna o Tipo de Prazo de Medicamento e a Linha de Prazo
    *********************************************************************/
    PROCEDURE P_RETORNAR_TIPOPRAZOMEDICAM(pi_vTipoPrazoMedicamen IN VARCHAR2,
                                         pi_nCodProd            IN NUMBER,
                                         pi_nCodPlPag_PCPEDI    IN NUMBER,
                                         pi_nCodPlPag_PCPEDC    IN NUMBER,
                                         pi_nCodPlPag_ETICO     IN NUMBER,
                                         pi_nCodPlPag_GENERICO  IN NUMBER,
                                         pi_vGrupoFaturamento   IN VARCHAR2,
                                         po_vTipoPrazoMedicamen OUT VARCHAR2,
                                         po_nCodLinhaPrazo      OUT NUMBER) IS
          
    BEGIN
  
      -- plano de Pagamento Por Linha de Prazo
      IF (NVL(pi_vTipoPrazoMedicamen,'2') = '4') THEN
      
        po_vTipoPrazoMedicamen := NVL(pi_vTipoPrazoMedicamen,'2');
        BEGIN
          SELECT CODLINHAPRAZO
            INTO po_nCodLinhaPrazo
            FROM PCPRODUT
           WHERE (CODPROD = pi_nCodProd);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            po_nCodLinhaPrazo := NULL;
        END;
         
      ELSE
      
        -- Plano de Pagamento Por Grupo de Faturamento
        IF (NVL(pi_nCodPlPag_ETICO,0)    > 0) AND
           (NVL(pi_nCodPlPag_GENERICO,0) > 0) THEN
           
          po_vTipoPrazoMedicamen := '1';
          
          IF (NVL(pi_vGrupoFaturamento,'G') = 'E')  THEN
            po_nCodLinhaPrazo    := 1;
          ELSE
            po_nCodLinhaPrazo    := 2;
          END IF;
           
        -- Plano de Pagamento Por Pedido
        ELSE
        
          po_vTipoPrazoMedicamen := '2';
          
          po_nCodLinhaPrazo      := 1;
          
        END IF;
        
      END IF;  
      
    END P_RETORNAR_TIPOPRAZOMEDICAM;
    
    ---------------------------------------------------------------------
    -- Função para Verificar se usa Rateio Crédito C/C RCA
    ---------------------------------------------------------------------
    FUNCTION F_USARATEIOCREDRCASUPERVISOR(pi_nCodUsur                    IN NUMBER,
                                          p_nPercRateioCredRcaSupervisor IN NUMBER,
                                          p_nValorLanc                   IN NUMBER) RETURN BOOLEAN IS
      -- Dados Supervisor
      vncodsupervisor             PCUSUARI.CODSUPERVISOR%TYPE;
      vncod_cadrca_supervisor     PCSUPERV.COD_CADRCA%TYPE;
      -- Retorno
      bUSARATEIOCREDRCASUPERVISOR BOOLEAN;
    BEGIN
      bUSARATEIOCREDRCASUPERVISOR := FALSE;
      
      -- Pesquisa Supervisor do RCA
      BEGIN
        SELECT PCUSUARI.CODSUPERVISOR
          INTO vncodsupervisor
          FROM PCUSUARI
         WHERE (PCUSUARI.CODUSUR = pi_nCodUsur);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vncodsupervisor := NULL;
      END;
      -- Pesquisa o RCA vinculado ao Supervisor
      BEGIN
        SELECT PCUSUARI.CODUSUR
          INTO vncod_cadrca_supervisor
          FROM PCSUPERV
             , PCUSUARI
         WHERE (PCSUPERV.CODSUPERVISOR = vncodsupervisor)
           AND (PCUSUARI.CODUSUR       = PCSUPERV.COD_CADRCA);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vncod_cadrca_supervisor := NULL;
      END; 
        
      -- Se o RCA está vinculado a um Supervisor que movimenta C/C
      IF (NVL(vncod_cadrca_supervisor,0) > 0) THEN  
      
        -- Se Crédito
        IF (NVL(p_nValorLanc,0) > 0) THEN    
          -- Se não tiver % para Rateio
          IF (NVL(p_nPercRateioCredRcaSupervisor,0) <= 0)   OR
             (NVL(p_nPercRateioCredRcaSupervisor,0)  > 100) THEN
            bUSARATEIOCREDRCASUPERVISOR := FALSE;
          -- Se tiver % para Rateio
          ELSE
            bUSARATEIOCREDRCASUPERVISOR := TRUE;
          END IF;
        END IF;
        
      END IF;
      
      -- Retorno
      RETURN bUSARATEIOCREDRCASUPERVISOR;                           
    END; --F_USARATEIOCREDRCASUPERVISOR
    
    ---------------------------------------------------------------------
    -- Função para ler % Rateio Crédito C/C RCA
    ---------------------------------------------------------------------
    FUNCTION F_PERCRATEIOCREDRCASUPERVISOR RETURN NUMBER IS
      -- Identificação de Erros ao Pesquisar Parâmetros
      vvErroPesqParam              VARCHAR2(1);
      vvMsgErroPesqParam           VARCHAR2(2000);
      -- Retorno
      nPERCRATEIOCREDRCASUPERVISOR NUMBER;
    BEGIN
    
      -- Parâmetro Perc. Taxa Prazo CMV
      FUNCOES_MED.POBTEM_PARAMFILIAL_NUMBER('99',
                                            'PERCRATEIOCREDRCASUPERVISOR',
                                            nPERCRATEIOCREDRCASUPERVISOR, --> Valor do Parâmetro
                                            vvErroPesqParam,
                                            vvMsgErroPesqParam);
      IF (NVL(nPERCRATEIOCREDRCASUPERVISOR,0) <= 0)  OR
         (NVL(nPERCRATEIOCREDRCASUPERVISOR,0) > 100) THEN
        nPERCRATEIOCREDRCASUPERVISOR := 100; --// Garante 100% se não tiver parâmetro informado ou valor informado incorretamente
      END IF;
      -- Retorno
      RETURN nPERCRATEIOCREDRCASUPERVISOR;                           
    END F_PERCRATEIOCREDRCASUPERVISOR;
    
   /***********************************************************************
    FUNÇÃO...: F_CCRCA_OBTER_VALOR_LANC_ATUAL
    DESCRIÇÃO: Retorna o Valor do Lançamento a partir da PCPEDI Atual
    ***********************************************************************/
    FUNCTION F_CCRCA_OBTER_VALOR_LANC_ATUAL(p_rotinalanc IN pclogrca.rotina%TYPE,
                                            p_codusur    IN pcpedc.codusur%TYPE,
                                            p_numped     IN pcpedc.numped%TYPE,
                                            p_codprod    IN pcpedi.codprod%TYPE,
                                            p_numseq     IN pcpedi.numseq%TYPE) RETURN NUMBER IS
      -- Variáveis processo anterior                                         
      vnvalorlanc                  NUMBER;
      vnvlcorrente_ant             pcusuari.vlcorrente%TYPE;
      vsusadebcredrca              pcusuari.usadebcredrca%TYPE;
      vnvllimcred                  pcusuari.vllimcred%TYPE;
      vnvlcorrente_atual           pcusuari.vlcorrente%TYPE;
      vddata                       pcpedc.DATA%TYPE;
      vnnumtransvenda              pcpedc.numtransvenda%TYPE;
      vsposicao                    pcpedc.posicao%TYPE;
      vnqt                         pcpedi.qt%TYPE;
      vbvalido                     BOOLEAN;
      -- RCA que movimenta o C/C
      vncodusur                    pcpedc.codusur%type;
      -- Variáveis para Rateio Crédito C/C RCA
      nPERCRATEIOCREDRCASUPERVISOR NUMBER;
      -- LIMITE_FLEX
      vvtipomovccrca               pcpedc.tipomovccrca%type;
    BEGIN
  
      -- Inicializa Valor do Lançamento
      vnvalorlanc := 0;
  
      -- Obter % Rateio de Crédito de C/C RCA
      nPERCRATEIOCREDRCASUPERVISOR := F_PERCRATEIOCREDRCASUPERVISOR;    
  
      --------------------------------------
      -- Já passa no Parâmetro do RCA do C/C
      --------------------------------------
      vncodusur := p_codusur;
      --------------------------------------                 
    
      SELECT pcpedc.DATA, pcpedc.numtransvenda, pcpedc.posicao, pcpedc.tipomovccrca
        INTO vddata, vnnumtransvenda, vsposicao, vvtipomovccrca
        FROM pcpedc
       WHERE numped = p_numped;
       
      ---------------------------------------------------------------------------------
      -- HIS.00052.2017 - Força encerrar o processo se Débito e Crédito no Faturamento, 
      -- movimentando o conta corrente do RCA por Pedido no Faturamento
      ---------------------------------------------------------------------------------
      IF (vvtipomovccrca = 'FF') AND
         (F_MOVSALDORCAPORPEDIDOFAT) THEN
        RETURN(0);
      END IF;       
      --------------------------------------------------------------------------------- 
    
      BEGIN
        SELECT qt
          INTO vnqt
          FROM pcpedi
         WHERE numped = p_numped
           AND codprod = p_codprod
           AND numseq = p_numseq;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnqt := 0;
      END;
    
      SELECT pcusuari.usadebcredrca, pcusuari.vlcorrente, pcusuari.vllimcred
        INTO vsusadebcredrca, vnvlcorrente_ant, vnvllimcred
        FROM pcusuari
       WHERE codusur = vncodusur;
                                                                
      --------------------------                                               
      -- Se não usar LIMITE_FLEX
      --------------------------
      IF (NVL(vvtipomovccrca,' ') <> 'LL') THEN   
            
        -- Pkg MED
        IF (NVL(vvUsaPkgSaldoRcaMed,'N') = 'S') THEN
        
          EXECUTE IMMEDIATE 'SELECT PC_PKG_CONTROLARSALDORCA_MED.ccrca_retorna_saldo_itempedido( ' || NVL(p_numped,0) || ',' ||
                                    NVL(vncodusur,0)    || ',' ||
                                    NVL(p_codprod,0)    || ',' ||
                                    NVL(p_numseq,0)     || ',' ||
                                    NVL(vnqt,0)         || ',' ||
                                    '''' || 'I' || '''' || ',' ||
                                    NVL(p_rotinalanc,0) || ') FROM DUAL'
            INTO vnvalorlanc;
  
        -- Pkg Pacote
        ELSE
  
          EXECUTE IMMEDIATE 'SELECT PC_PKG_CONTROLARSALDORCA_MED.ccrca_retorna_saldo_itempedido( ' || NVL(p_numped,0) || ',' ||
                                    NVL(vncodusur,0)    || ',' ||
                                    NVL(p_codprod,0)    || ',' ||
                                    NVL(p_numseq,0)     || ',' ||
                                    NVL(vnqt,0)         || ',' ||
                                    '''' || 'I' || '''' || ') FROM DUAL'
            INTO vnvalorlanc;
                                                                                 
        END IF;
        
        
      END IF; -- FIM: SE NÃO FOR LIMITE_FLEX
    
      RETURN(vnvalorlanc);
          
    END F_CCRCA_OBTER_VALOR_LANC_ATUAL;
      
   /*********************************************************************
    FUNÇÃO...: F_CCRCA_ATUALIZAR_VLSALDORCA
    DESCRIÇÃO: Atualização dos campos da PCPEDI: QTSALDORCA e VLSALDORCA
    *********************************************************************/
    FUNCTION F_CCRCA_ATUALIZAR_VLSALDORCA(p_rotinalanc IN pclogrca.rotina%TYPE,
                                          p_codusur    IN pcpedc.codusur%TYPE,
                                          p_numped     IN pcpedc.numped%TYPE,
                                          p_codprod    IN pcpedi.codprod%TYPE,
                                          p_numseq     IN pcpedi.numseq%TYPE)
    RETURN BOOLEAN IS
      -- Variáveis processo anterior                                         
      vnvalorlanc                     NUMBER;
      vnvlcorrente_ant                pcusuari.vlcorrente%TYPE;
      vsusadebcredrca                 pcusuari.usadebcredrca%TYPE;
      vnvllimcred                     pcusuari.vllimcred%TYPE;
      vnvlcorrente_atual              pcusuari.vlcorrente%TYPE;
      vddata                          pcpedc.DATA%TYPE;
      vnnumtransvenda                 pcpedc.numtransvenda%TYPE;
      vsposicao                       pcpedc.posicao%TYPE;
      vnqt                            pcpedi.qt%TYPE;
      vbvalido                        BOOLEAN;
      -- RCA que movimenta o C/C
      vncodusur                       pcpedc.codusur%type;
      -- Variáveis para Rateio Crédito C/C RCA
      nPERCRATEIOCREDRCASUPERVISOR    NUMBER;
      -- LIMITE_FLEX
      vvtipomovccrca                  pcpedc.tipomovccrca%type;
    BEGIN
      vbvalido := FALSE;
      
      -- Obter % Rateio de Crédito de C/C RCA
      nPERCRATEIOCREDRCASUPERVISOR := F_PERCRATEIOCREDRCASUPERVISOR;    
  
      --------------------------------------
      -- Já passa no Parâmetro do RCA do C/C
      --------------------------------------
      vncodusur := p_codusur;
      --------------------------------------                 
    
      SELECT pcpedc.DATA, pcpedc.numtransvenda, pcpedc.posicao, pcpedc.tipomovccrca
        INTO vddata, vnnumtransvenda, vsposicao, vvtipomovccrca
        FROM pcpedc
       WHERE numped = p_numped;
       
      ---------------------------------------------------------------------------------
      -- HIS.00052.2017 - Força encerrar o processo se Débito e Crédito no Faturamento, 
      -- movimentando o conta corrente do RCA por Pedido no Faturamento
      ---------------------------------------------------------------------------------
      IF (vvtipomovccrca = 'FF') AND
         (F_MOVSALDORCAPORPEDIDOFAT) THEN
        RETURN(TRUE);
      END IF;       
      --------------------------------------------------------------------------------- 
    
      SELECT qt
        INTO vnqt
        FROM pcpedi
       WHERE numped = p_numped
         AND codprod = p_codprod
         AND numseq = p_numseq;
    
      SELECT pcusuari.usadebcredrca, pcusuari.vlcorrente, pcusuari.vllimcred
        INTO vsusadebcredrca, vnvlcorrente_ant, vnvllimcred
        FROM pcusuari
       WHERE codusur = vncodusur;
            
      --------------------------                                               
      -- Se não usar LIMITE_FLEX
      --------------------------
      IF (NVL(vvtipomovccrca,' ') <> 'LL') THEN
      
        -- Obtém Valor do Lançamento da partir da PCPEDI Atual
        vnvalorlanc := F_CCRCA_OBTER_VALOR_LANC_ATUAL(p_rotinalanc,
                                                      p_codusur,
                                                      p_numped,
                                                      p_codprod,
                                                      p_numseq);
        
        -- Atualiza PCPEDI
        UPDATE PCPEDI
           SET QTSALDORCAMED = NVL(vnqt,0)
             , VLSALDORCA    = DECODE(NVL(vnqt,0),0,0,(NVL(vnvalorlanc,0) / NVL(vnqt,0)))
         WHERE numped = p_numped
           AND codprod = p_codprod
           AND numseq = p_numseq;
        
      END IF; -- Fim Condição: Se não usar LIMITE_FLEX
  
      RETURN(vbvalido);
      
    END F_CCRCA_ATUALIZAR_VLSALDORCA;
    
   /*********************************************************************
    FUNÇÃO   : F_CCRCA_ALTERAR_VLSALDORCA
    DESCRIÇÃO: Alternativa para os Clientes que não usam a PKG MED
               de Controle de Saldo do RCA
    *********************************************************************/
    FUNCTION F_CCRCA_ALTERAR_VLSALDORCA(p_codfunclanc         IN pclogrca.codfunc%TYPE,
                                        p_rotinalanc          IN pclogrca.rotina%TYPE,
                                        p_codusur             IN pcpedc.codusur%TYPE,
                                        p_numped              IN pcpedc.numped%TYPE,
                                        p_codprod             IN pcpedi.codprod%TYPE,
                                        p_numseq              IN pcpedi.numseq%TYPE,
                                        p_qtanterior          IN NUMBER,
                                        p_pvlsaldorcaanterior IN NUMBER) RETURN BOOLEAN IS
      vnqt                 pcpedi.qt%TYPE;
      vsusadebcredrcabrind pcpedi.usadebcredrcabrind%TYPE;
      vbvalido             BOOLEAN;
      vnvalorlanc          NUMBER;
      vnvlcorrente_ant     pcusuari.vlcorrente%TYPE;
      vsusadebcredrca      pcusuari.usadebcredrca%TYPE;
      vnvllimcred          pcusuari.vllimcred%TYPE;
      vnvlcorrente_atual   pcusuari.vlcorrente%TYPE;
      vddata               pcpedc.DATA%TYPE;
      vnnumtransvenda      pcpedc.numtransvenda%TYPE;
      vsposicao            pcpedc.posicao%TYPE;
    BEGIN
      vbvalido := FALSE;
    
      IF p_qtanterior > 0 THEN
      
        SELECT pcpedc.DATA, pcpedc.numtransvenda, pcpedc.posicao
          INTO vddata, vnnumtransvenda, vsposicao
          FROM pcpedc
         WHERE numped = p_numped;
          
        SELECT pcusuari.usadebcredrca,
               pcusuari.vlcorrente,
               pcusuari.vllimcred
          INTO vsusadebcredrca, vnvlcorrente_ant, vnvllimcred
          FROM pcusuari
         WHERE codusur = p_codusur;
          
        -- Calcula Valor Movimentado anteriormente  
        vnvalorlanc := (p_qtanterior * p_pvlsaldorcaanterior);
                                                                                                     
        -- incluído por sabrina ( E - Estorno)
        vnvlcorrente_atual := NVL(vnvlcorrente_ant, 0) - NVL(vnvalorlanc, 0);
      
        -- a package não deve barrar a movimentacao do saldo, os programas eh que fazem isso
        --IF vnvlcorrente_atual >= 0 THEN
        UPDATE pcusuari
           SET vlcorrente = vnvlcorrente_atual
         WHERE codusur = p_codusur;
      
        INSERT INTO pclogrca
          (numped,
           posicao,
           numtransvenda,
           DATA,
           codfunc,
           codusur,
           rotina,
           vlcorrente,
           vllimcred,
           vlcorrenteant,
           vllimcredant,
           codprod,
           numseq,
           historico)
        VALUES
          (p_numped,
           vsposicao,
           vnnumtransvenda,
           SYSDATE,
           p_codfunclanc,
           p_codusur,
           p_rotinalanc,
           vnvlcorrente_atual,
           vnvllimcred,
           vnvlcorrente_ant,
           vnvllimcred,
           p_codprod,
           p_numseq,
           SUBSTR('CTRLCCRCA AS.: ESTORNO DE SALDO DE ITEM PEDIDO', 1, 60));
              
        BEGIN
          SELECT qt
            INTO vnqt
            FROM pcpedi
           WHERE numped = p_numped
             AND codprod = p_codprod
             AND numseq = p_numseq;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnqt := 0;
        END;
            
        IF (vnqt > 0) THEN
          vbvalido := PC_PKG_CONTROLARSALDORCA_MED.ccrca_incluir_item_pedido(p_codfunclanc,
                                                                         p_rotinalanc,
                                                                         p_codusur,
                                                                         p_numped,
                                                                         p_codprod,
                                                                         p_numseq);
        END IF;
        
      END IF; -- (vnqt > 0)
    
      RETURN(vbvalido);
      
    END F_CCRCA_ALTERAR_VLSALDORCA;
  
  /*********************************************************************
    PROCEDIMENTO : P_ATU_STATUS_PROCESSAMENTO
    DESCRIÇÃO    : Procedimento para Atualizar o Status de Processamento 
    *********************************************************************/
    PROCEDURE P_ATU_STATUS_PROCESSAMENTO(pi_vChamadaProcesso IN VARCHAR2,
                                         pi_vNovoStatus      IN VARCHAR2,
                                         pio_vStatusAtual    IN OUT VARCHAR2) 
    IS
    BEGIN
  
      -- Se Chamado da Gravação do Pedido   
      IF (pi_vChamadaProcesso = 'GP') THEN
     
        -- Atualiza Status de Gravação do Pedido
        UPDATE PCPEDC 
           SET STATUSPROCESSAMENTOMED = pi_vNovoStatus
         WHERE (NUMPED = pi_nNumPed);
     
      END IF;       
      
      -- Atualiza Retorno com o novo Status
      pio_vStatusAtual := pi_vNovoStatus;   
      
    END P_ATU_STATUS_PROCESSAMENTO;
    
