           , NVL(BROKER,'N')
           , NVL(VENDAASSISTIDA,'N')         
           , TIPOFV
           , CODCONDICAOVENDA
           , STATUSPROCESSAMENTOMED
           , 'N'
           , VLDESCNEG
           , USADEBCREDRCA
           , CODBNF
           , BONIFICALTDEBCREDRCA
           , NUMTRANSENTCROSSDOCK
           , DTWMS
           , CODPROMOCAOMED
           , FRETEDESPACHO
           , CODSUPERVISOR -- DDVENDAS-38228
        INTO vrPedido.vnCodCli
           , vrPedido.vnCondVenda
           , vrPedido.vnCodPlPag
           , vrPedido.vnCodPlPagEtico
           , vrPedido.vnCodPlPagGenerico
           , vrPedido.vvCodCob
           , vrPedido.vdData
           , vrPedido.vdDtEntrega
           , vrPedido.vvOrigemPed
           , vrPedido.vvPosicaoAtual
           , vrPedido.vnCodUsur
           , vrPedido.vvCodFilial
           , vrPedido.vvPedidoAvaria
           , vrPedido.vvBroker
           , vrPedido.vvVendaAssistida         
           , vrPedido.vvTipoFv
           , vrPedido.vnCodCondicaoVenda
           , vrPedido.vvStatusProcessamentoMed
           , vrPedido.vvValidarMinOperadorLogistico
           , vrPedido.vnVlDescNeg
           , vrPedido.vvUsaDebCredRca
           , vrPedido.vvCodBnf
           , vrPedido.vvBonificAltDebCredRca
           , vrPedido.vnNumTransEntCrossDock
           , vrPedido.vdDtWms
           , vrPedido.vnCodPromocaoMed
           , vrPedido.vvFreteDespacho
           , vrPedido.vnCodSupervisor -- DDVENDAS-38228
        FROM PCPEDC
       WHERE (NUMPED = pi_nNumPed); 
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrPedido.vnCodCli                      := pi_nCodCli;
        vrPedido.vnCondVenda                   := pi_nCondVenda;
        vrPedido.vnCodPlPag                    := pi_nCodPlPag;
        vrPedido.vnCodPlPagEtico               := pi_nCodPlPagEtico;
        vrPedido.vnCodPlPagGenerico            := pi_nCodPlPagGenerico;
        vrPedido.vvCodCob                      := pi_vCodCob;
        vrPedido.vdData                        := TRUNC(SYSDATE);
        vrPedido.vdDtEntrega                   := pi_dDtEntrega;
        vrPedido.vvOrigemPed                   := pi_vOrigemPed;
        vrPedido.vvPosicaoAtual                := pi_vNovaPosicaoPedido;
        vrPedido.vnCodUsur                     := pi_nCodUsur;
        vrPedido.vvCodFilial                   := pi_vCodFilial;
        vrPedido.vvPedidoAvaria                := pi_vPedidoAvaria;
        vrPedido.vvBroker                      := 'N';
        vrPedido.vvVendaAssistida              := pi_vVendaAssistida;
        vrPedido.vvTipoFv                      := pi_vTipoFv;
        vrPedido.vnCodCondicaoVenda            := pi_nCodCondicaoVenda;
        vrPedido.vvStatusProcessamentoMed      := NULL;
        vrPedido.vvValidarMinOperadorLogistico := 'N';
        vrPedido.vnVlDescNeg                   := pi_nVlDescNeg;
        vrPedido.vvUsaDebCredRca               := NVL(pi_vMovimentarSaldoRca,'N');
        vrPedido.vvCodBnf                      := NULL;
        vrPedido.vvBonificAltDebCredRca        := 'N';  
        vrPedido.vnNumTransEntCrossDock        := pi_nNumTransEntCrossDock; 
        vrPedido.vdDtWms                       := NULL;
        vrPedido.vnCodPromocaoMed              := pi_nCodPromocaoMedPedido;
        vrPedido.vvFreteDespacho               := NULL;
        vrPedido.vnCodSupervisor               := NULL; -- DDVENDAS-38228
    END;
    
    -- DDVENDAS-38228
    IF (NVL(vrPedido.vnCodSupervisor,0) = 0) THEN
      BEGIN
        SELECT CODSUPERVISOR
          INTO vrPedido.vnCodSupervisor
          FROM PCUSUARI
         WHERE CODUSUR = vrPedido.vnCodUsur;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrPedido.vnCodSupervisor := NULL;
      END;
    END IF;

    -- Integradora do Parâmetro
    vrPedido.vnIntegradora                := pi_nIntegradora;
    -- Inicializa Regra de Faturamento Integral - DDMEDICA-6533
    vrPedido.vvFaturamentoIntegral        := pi_vFaturamentoIntegral;
    vrPedido.vnQtdeTotalPedidoFatIntegral := NVL(pi_nQtdeFaturamentoIntegral,0);
    -- Pesquisa Dados do Pedido da 2302
    IF (NVL(vrPedido.vnIntegradora,0) = 0) AND
       (vrPedido.vvOrigemPed = 'F')        AND
       (vrPedido.vvTipoFv IN ('OL','PE'))  THEN
      BEGIN
        SELECT INTEGRADORA
             , FATURAMENTOINTEGRAL
          INTO vrPedido.vnIntegradora
             , vrPedido.vvFaturamentoIntegral
          FROM PCPEDRETORNO
         WHERE (NUMPED = pi_nNumPed)
           AND (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrPedido.vnIntegradora         := NULL;
          vrPedido.vvFaturamentoIntegral := NULL;
      END;
      -- Total do Pedido para Validação de Faturamento Integral - DDMEDICA-6533
      IF (NVL(vrPedido.vnIntegradora,0) > 0)    AND
         (vrPedido.vvFaturamentoIntegral IN ('S','1')) THEN
        SELECT SUM(QT)
          INTO vrPedido.vnQtdeTotalPedidoFatIntegral
          FROM PCPEDCFV
             , PCPEDIFV
         WHERE (PCPEDCFV.NUMPEDRCA         = PCPEDIFV.NUMPEDRCA)
           AND (PCPEDCFV.CODUSUR           = PCPEDIFV.CODUSUR)
           AND (PCPEDCFV.CGCCLI            = PCPEDIFV.CGCCLI)
           AND (PCPEDCFV.DTABERTURAPEDPALM = PCPEDIFV.DTABERTURAPEDPALM)
           AND (PCPEDCFV.NUMPED            = pi_nNumPed);
      END IF;
    END IF;
    
    -- Opção de Limitar Venda do Estoque Mínimo - DDMEDICA-7391
    P_OPCAO_LIMITAR_VENDA_EST_MIN(vrPedido.vnCodCli,
                                  vrPedido.vnCondVenda,
                                  vrPedido.vnOpcaoLimitarVendaEstMin,
                                  vvObsLimitarVendaEstMin,
                                  vrPedido.vnIntegradora);
    -- LOG: 
    P_INSERE_LOG_PROCESSAMENTO('vnOpcaoLimitarVendaEstMin = ' || vrPedido.vnOpcaoLimitarVendaEstMin || CHR(13) ||
                               'vvObsLimitarVendaEstMin = '   || vvObsLimitarVendaEstMin);    
      
    -- Pesquuisa Dados do Cliente
    BEGIN
      SELECT PCCLIENT.FANTASIA
           , PCCLIENT.TIPOFJ
           , PCCLIENT.CODPRACA
           , NVL(PCCLIENT.FRETEDESPACHO,'C')
           , NVL(PCCLIENT.CLIENTEMONITORADO,'N')
           , PCCLIENT.CODATV1 -- DDVENDAS-38228
        INTO vrCliente.vvFantasia
           , vrCliente.vvTipoFJ
           , vrCliente.vnCodPraca
           , vrCliente.vvFreteDespacho
           , vrCliente.vvClienteMonitorado
           , vrCliente.vnCodAtv1 -- DDVENDAS-38228
        FROM PCCLIENT
       WHERE (PCCLIENT.CODCLI = vrPedido.vnCodCli);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrCliente.vvFantasia          := NULL;
        vrCliente.vvTipoFJ            := NULL;
        vrCliente.vnCodPraca          := NULL;
        vrCliente.vvFreteDespacho     := NULL;
        vrCliente.vvClienteMonitorado := NULL;
        vrCliente.vnCodAtv1           := NULL; 
    END;
    
    -- Se não tem Frete Despacho no Pedido, pega do Cliente - DDMEDICA-3918
    IF (vrPedido.vvFreteDespacho IS NULL) THEN
      vrPedido.vvFreteDespacho := vrCliente.vvFreteDespacho;
    END IF;
    
    -- Pesquuisa Dados do RCA do Pedido (Não usar o do Parâmetro que é o do Conta-Corrente)
    BEGIN
      SELECT PCUSUARI.VLVENDAMINPED
        INTO vrRca.vnVlVendaMinPed
        FROM PCUSUARI
       WHERE (PCUSUARI.CODUSUR = vrPedido.vnCodUsur);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrRca.vnVlVendaMinPed := NULL;
    END; 
      
    -- Dados da Cobrança
    BEGIN
      SELECT BOLETO
           , COBRANCA
           , VLMINPEDIDO
           , NAOVALIDAPRAZOMEDIO
           , NVL(CARTAO,'N')
        INTO vrCobranca.vvBoleto
           , vrCobranca.vvCobranca
           , vrCobranca.vnVlMinPedido
           , vrCobranca.vvNaoValidaPrazoMedio
           , vrCobranca.vvCartao
        FROM PCCOB
       WHERE (CODCOB = vrPedido.vvCodCob);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrCobranca.vvBoleto              := 'N';
        vrCobranca.vvCobranca            := NULL;
        vrCobranca.vnVlMinPedido         := 0;
        vrCobranca.vvNaoValidaPrazoMedio := 'N';
        vrCobranca.vvCartao              := 'N';
    END;  
    
    -- Parâmetros PCCONSUM
    BEGIN
      SELECT TIPOVLMINVENDABK
           , VLMINVENDABNF
           , NVL(VALIDAVLMINVENDABALCAO,'N') VALIDAVLMINVENDABALCAO
           , VLMINVENDA
           , NVL(VALIDARVLMINVENDAAPOSCORTE,'N')
           , NVL(ACEITAVENDABLOQ,'N')
           , NVL(BLOQUEARPEDBONIFIC,'N')
           , NVL(LIBERARPEDIDOPENDENTE,'N')
           , NVL(UTILIZAVENDAPOREMBALAGEM,'N')
           , NVL(USACREDRCA,'N')         
           , NVL(TROCAALTDEBCREDRCA,'N')
           , NVL(CRMALTDEBCREDRCA,'N')
           , NVL(TIPOMOVCCRCA,'N')
           , NVL(PEREXCEDELIMCRED,0)
           , NVL(NUMCASASDECVENDA,2)
           , NVL(VERIFICAMARGEMLIBPEDIDO,'N')
        INTO vrParametros.vTIPOVLMINVENDABK
           , vrParametros.nVLMINVENDABNF
           , vrParametros.vVALIDAVLMINVENDABALCAO
           , vrParametros.nVLMINVENDA
           , vrParametros.vVALIDARVLMINVENDAAPOSCORTE
           , vrParametros.vACEITAVENDABLOQ
           , vrParametros.vBLOQUEARPEDBONIFIC
           , vrParametros.vLIBERARPEDIDOPENDENTE
           , vrParametros.vUTILIZAVENDAPOREMBALAGEM         
           , vrParametros.vUSACREDRCA
           , vrParametros.vTROCAALTDEBCREDRCA
           , vrParametros.vCRMALTDEBCREDRCA
           , vrParametros.vTIPOMOVCCRCA
           , vrParametros.nPEREXCEDELIMCRED
           , vrParametros.nNUMCASASDECVENDA
           , vrParametros.vVERIFICAMARGEMLIBPEDIDO
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vTIPOVLMINVENDABK           := NULL;
        vrParametros.nVLMINVENDABNF              := 0;
        vrParametros.vVALIDAVLMINVENDABALCAO     := 'N';
        vrParametros.nVLMINVENDA                 := 0;
        vrParametros.vVALIDARVLMINVENDAAPOSCORTE := 'N';
        vrParametros.vACEITAVENDABLOQ            := 'N';
        vrParametros.vBLOQUEARPEDBONIFIC         := 'N';
        vrParametros.vLIBERARPEDIDOPENDENTE      := 'N';
        vrParametros.vUTILIZAVENDAPOREMBALAGEM   := 'N';
        vrParametros.vUSACREDRCA                 := 'N';
        vrParametros.vTROCAALTDEBCREDRCA         := 'N';
        vrParametros.vCRMALTDEBCREDRCA           := 'N';
        vrParametros.vTIPOMOVCCRCA               := 'VV';
        vrParametros.nPEREXCEDELIMCRED           := 0;
        vrParametros.nNUMCASASDECVENDA           := 0;
        vrParametros.vVERIFICAMARGEMLIBPEDIDO    := 'N';
    END;  
    -- Parâmetros PCFILIAL
    BEGIN
      SELECT NVL(BLOQUEARPEDIDOSABAIXOVLMINIMO,'N') BLOQUEARPEDIDOSABAIXOVLMINIMO
           , NVL(ACEITAVENDASEMEST,'N') vACEITAVENDASEMEST
        INTO vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO
           , vrParametros.vACEITAVENDASEMEST
        FROM PCFILIAL
       WHERE (CODIGO = vrPedido.vvCodFilial); 
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO := 'N';
        vrParametros.vACEITAVENDASEMEST             := 'N';
    END; 

    -- DDMEDICA-1924
    -- Inicializa Variáveis a partir dos Parâmetros
    vvNovaPosicaoPedido      := pi_vNovaPosicaoPedido;
    vvGravarPedidoItensFalta := pi_vGravarPedidoItensFalta;
    vnNumPedidoItensFalta    := pi_nNumPedidoItensFalta;
  
    -- DDMEDICA-1924
    -- Se Aceita Venda Sem Estoque e Libera Pedido Pendente Automáticamente, o Sistema não gravará o Pedido como Pendente.
    -- Será Simulado o processo que grava o Pedido como Liberado e gera o Pedido de Itens Faltantes na posição P,
    -- que resolverá o problema de outra forma.
    IF (pi_nCodRotina = 2316)       AND
       (pi_vChamadaProcesso = 'GP') THEN
      IF (vvNovaPosicaoPedido                 = 'P') AND
         (vrParametros.vACEITAVENDASEMEST     = 'S') AND
         (vrParametros.vLIBERARPEDIDOPENDENTE = 'S') THEN
        -- Não gravará o Pedido como Pendente  
        vrParametros.vACEITAVENDASEMEST := 'N';
        vvNovaPosicaoPedido             := 'L'; -->> Gravará o Pedido como Liberado 
        -- Criará um Pedido de Itens Faltantes
        vvGravarPedidoItensFalta := 'S';
        IF (NVL(pi_nNumPedidoItensFalta,0) = 0) THEN
          vnNumPedidoItensFalta  := F_PROX_NUMPED(vrPedido.vnCodUsur);
        END IF;
        -- LOG: Itens do Pedido Faltante
        P_INSERE_LOG_PROCESSAMENTO('GravarPedidoItensFalta ao Lib. Automaticamente = ' || vvGravarPedidoItensFalta || CHR(13) ||
                                   'vnNumPedidoItensFalta = '                          || vnNumPedidoItensFalta);    
      END IF;
    END IF;
  
    -- Parâmetros PCPARAMFILIAL
    BEGIN
      SELECT REPLACE(NVL(VALOR,'0'),',','.')
        INTO vrParametros.vVLMINVENDABKFILIAL
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'VLMINVENDABKFILIAL');
       BEGIN
         vrParametros.nVLMINVENDABKFILIAL := TO_NUMBER(vrParametros.vVLMINVENDABKFILIAL);
       EXCEPTION
         WHEN OTHERS THEN
           vrParametros.nVLMINVENDABKFILIAL := 0;
       END;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.nVLMINVENDABKFILIAL := 0;
    END;   
    IF (NVL(vrParametros.nVLMINVENDABKFILIAL,0) > 0) THEN
      vrParametros.nVLMINVENDABK := vrParametros.nVLMINVENDABKFILIAL;
    END IF;
    --
    IF (vrPedido.vvOrigemPed = 'F') THEN
      BEGIN
        SELECT REPLACE(NVL(VALOR,'0'),',','.')
          INTO vrParametros.vVLMINVENDABNFFV
          FROM PCPARAMFILIAL
         WHERE (CODFILIAL = vrPedido.vvCodFilial)
           AND (NOME      = 'VLMINVENDABNFFV');
         BEGIN
           vrParametros.nVLMINVENDABNFFV := TO_NUMBER(vrParametros.vVLMINVENDABNFFV);
         EXCEPTION
           WHEN OTHERS THEN
             vrParametros.nVLMINVENDABNFFV := 0;
         END;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParametros.nVLMINVENDABNFFV := 0;
      END;     
      IF (NVL(vrParametros.nVLMINVENDABNFFV,0) > 0) THEN
        vrParametros.nVLMINVENDABNF := vrParametros.nVLMINVENDABNFFV;
      END IF;
    END IF;
    --  
    BEGIN
      SELECT REPLACE(NVL(VALOR,'0'),',','.')
        INTO vrParametros.vVLMINVENDA_FILIAL
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'VLMINVENDA');
       BEGIN
         vrParametros.nVLMINVENDA_FILIAL := TO_NUMBER(vrParametros.vVLMINVENDA_FILIAL);
       EXCEPTION
         WHEN OTHERS THEN
           vrParametros.nVLMINVENDA_FILIAL := 0;
       END;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.nVLMINVENDA_FILIAL := 0;
    END;   
    IF (NVL(vrParametros.nVLMINVENDA_FILIAL,0) > 0) THEN
      vrParametros.nVLMINVENDA := vrParametros.nVLMINVENDA_FILIAL;
    END IF;
    IF (vrPedido.vvOrigemPed = 'F') THEN
      BEGIN
        SELECT REPLACE(NVL(VALOR,'0'),',','.')
          INTO vrParametros.vVLMINVENDAFV
          FROM PCPARAMFILIAL
         WHERE (CODFILIAL = vrPedido.vvCodFilial)
           AND (NOME      = 'VLMINVENDAFV');
         BEGIN
           vrParametros.nVLMINVENDAFV := TO_NUMBER(vrParametros.vVLMINVENDAFV);
         EXCEPTION
           WHEN OTHERS THEN
             vrParametros.nVLMINVENDAFV := 0;
         END;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParametros.nVLMINVENDAFV := 0;
      END;     
      IF (NVL(vrParametros.nVLMINVENDAFV,0) > 0) THEN
        vrParametros.nVLMINVENDA := vrParametros.nVLMINVENDAFV;
      END IF;    
    END IF;  
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vFIL_ALTERARCOBBKCHAUTOMATICO
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'FIL_ALTERARCOBBKCHAUTOMATICO');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vFIL_ALTERARCOBBKCHAUTOMATICO := 'N';
    END;     
    --
    BEGIN
      SELECT NVL(VALOR,'2')
        INTO vrParametros.vTIPOPRAZOMEDICAMEN
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'TIPOPRAZOMEDICAMEN');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        -- Default = 2 - Cliente
        vrParametros.vTIPOPRAZOMEDICAMEN := '2';
    END;     
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vGRAVARPEDVENBLOQMED
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'GRAVARPEDVENBLOQMED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vGRAVARPEDVENBLOQMED := 'N';
    END;     
    -- MED-1199 - Balcão não aceitar usar parâmetro Gravar Como Bloqueado
    IF (vrPedido.vvOrigemPed IN ('B''R')) THEN
      vrParametros.vGRAVARPEDVENBLOQMED := 'N';
    END IF;
    -- DDMEDICA-957 - Montado Idem, não aceitar usar parâmetro Gravar Como Bloqueado
    IF (vvNovaPosicaoPedido = 'M') THEN
      vrParametros.vGRAVARPEDVENBLOQMED := 'N';
    END IF;
    --
    IF    (vrPedido.vvOrigemPed = 'F') THEN
      BEGIN
        SELECT NVL(VALOR,'N')
          INTO vrParametros.vACEITAVENDASEMEST
          FROM PCPARAMFILIAL
         WHERE (CODFILIAL = vrPedido.vvCodFilial)
           AND (NOME      = 'ACEITAVENDASEMESTFV');
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParametros.vACEITAVENDASEMEST := 'N';
      END;  
      -- MED-2532 - Validar Mínimo sem ST requer opção para ignorar parâmetro 2548
      IF (vrPedido.vnIntegradora > 0) THEN
        IF (FOBTEM_PARAM_INTEGRADORA(vrPedido.vnIntegradora,
                                     'IGNORARACEITAVENDASEMESTFV',
                                     'N') = 'S') THEN
          vrParametros.vACEITAVENDASEMEST := 'N';
        END IF;
      END IF;
    ELSIF (vrPedido.vvOrigemPed IN ('B''R')) THEN
      -- MED-1199 - Balcão não aceitar venda sem estoque    
      vrParametros.vACEITAVENDASEMEST := 'N';
    END IF;
    -- DDMEDICA-957 - Montado não aceitar venda sem estoque
    IF (vvNovaPosicaoPedido = 'M') THEN
      vrParametros.vACEITAVENDASEMEST := 'N';
    END IF;  
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vACEITAVENDARCASEMSALDOFV
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial) -- MED-2349
         AND (NOME      = 'ACEITAVENDARCASEMSALDOFV');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vACEITAVENDARCASEMSALDOFV := 'N';
    END;       
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vVALIDARSALDORCAPORITEM
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'VALIDARSALDORCAPORITEM');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vVALIDARSALDORCAPORITEM := 'N';
    END;          
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vSOMACREDITOCLIPRINCIPAL
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99') -- DDMEDICA-4732
         AND (NOME      = 'SOMACREDITOCLIPRINCIPAL');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vSOMACREDITOCLIPRINCIPAL := 'N';
    END;          
    -- DDMEDICA-1586
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vUSABNFLIMITECREDITO
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99') -- DDMEDICA-4732
         AND (NOME      = 'USABNFLIMITECREDITO');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vUSABNFLIMITECREDITO := 'N';
    END;            
    -- DDMEDICA-1586
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vVERIFICALIMCREDCODCOBD
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_VERIFICALIMCREDCODCOBD');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vVERIFICALIMCREDCODCOBD := 'N';
    END;            
    -- DDMEDICA-1586
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vACEITAVENDAAVISTACLIBLOQ
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'ACEITAVENDAAVISTACLIBLOQ');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vACEITAVENDAAVISTACLIBLOQ := 'N';
    END;            
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vBLOQPEDLIMCRED
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'BLOQPEDLIMCRED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vBLOQPEDLIMCRED := 'N';
    END;            
    --
    BEGIN
      SELECT REPLACE(NVL(VALOR,'0'),',','.')
        INTO vrParametros.nVLMAXVENDA
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_VLMAXVENDA');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.nVLMAXVENDA := 0;
    END;   
    BEGIN
      SELECT REPLACE(NVL(VALOR,'0'),',','.')
        INTO vrParametros.nVLMAXVENDAPF
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_VLMAXVENDAPF');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.nVLMAXVENDAPF := 0;
    END;   
    BEGIN
      SELECT REPLACE(NVL(VALOR,'0'),',','.')
        INTO vrParametros.nVLMAXVENDABNF
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_VLMAXVENDABNF');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.nVLMAXVENDABNF := 0;
    END;   
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vACEITADESCTMK
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_ACEITADESCTMK');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vACEITADESCTMK := 'N';
    END;    
    -- DDVENDAS-35974
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vACEITADESCBALCAORESERVA
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_ACEITADESCBALCAORESERVA');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vACEITADESCBALCAORESERVA := 'N';
    END;        
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vBLOQPRAZOMDVENDA
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CON_BLOQPRAZOMDVENDA');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vBLOQPRAZOMDVENDA := 'N';
    END;                
    --
    BEGIN
      SELECT 'S'
        INTO vrParametros.vEXISTE_PCPLPAGCLI
        FROM PCPLPAGCLI 
       WHERE (PCPLPAGCLI.CODCLI = vrPedido.vnCodCli)
         AND (ROWNUM = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vEXISTE_PCPLPAGCLI := 'N';
    END;
    --
    BEGIN
      SELECT REPLACE(NVL(VALOR,'0'),',','.')
        INTO vrParametros.nPERCMARGEMMINVENDAMED  
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'PERCMARGEMMINVENDAMED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.nPERCMARGEMMINVENDAMED := 0;
    END;                    
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vTIPOVALIDMARGEMMINVENDAMED
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'TIPOVALIDMARGEMMINVENDAMED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vTIPOVALIDMARGEMMINVENDAMED := 'N';
    END;                    
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vBLOQPEDABAIXOMARGEMFV
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'BLOQPEDABAIXOMARGEMFV');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vBLOQPEDABAIXOMARGEMFV := 'N';
    END;           
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vVALIDALVARAPORTIPOCTLVEN
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'VALIDALVARAPORTIPOCTLVEN');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vVALIDALVARAPORTIPOCTLVEN := 'N';
    END;              
    --
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vACEITADESCTMKFV
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial)
         AND (NOME      = 'ACEITADESCTMKFV');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vACEITADESCTMKFV := 'N';
    END;              
    --
    POBTEM_PARAMFILIAL_STRING('99',
                              'MEDPERMITEDISTRIBDIFRCA',
                              'N',
                              vrParametros.vMEDPERMITEDISTRIBDIFRCA);
    --
    POBTEM_PARAMFILIAL_NUMBER(vrPedido.vvCodFilial,
                              'PERCLIMITEVLTV5',
                              vrParametros.nPERCLIMITEVLTV5);
    --
    
    -- DDMEDICA-834 - Rateio RCA Supervisor
    vrParametros.nPERCRATEIOCREDRCASUPERVISOR := F_PERCRATEIOCREDRCASUPERVISOR;
    IF (NVL(vrParametros.nPERCRATEIOCREDRCASUPERVISOR,0) = 0) THEN
      vrParametros.nPERCRATEIOCREDRCASUPERVISOR := 100;
    END IF;  
    
    -- Regras Específicas - PCREGRASEXCECAOMED
    vrRegrasEspecificas.vREALIZARCORTETOTALKIT       := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','REALIZARCORTETOTALKIT');
    vrRegrasEspecificas.vNEGOCIARVALORDESCOMPEDIDO   := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','NEGOCIARVALORDESCOMPEDIDO');   -- HIS.05093.2017
    vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQFV   := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','CORTARITEMSEMESTPEDBLOQFV');   -- MED-2625
    vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQEC   := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','CORTARITEMSEMESTPEDBLOQEC');   -- MED-2625
    vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQOL   := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','CORTARITEMSEMESTPEDBLOQOL');   -- MED-2625
    vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQPV   := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','CORTARITEMSEMESTPEDBLOQPV');   -- MED-2625
    vrRegrasEspecificas.vUSAVENDASEMESTBALCAORESERVA := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','USAVENDASEMESTBALCAORESERVA'); -- DDMEDICA-2551
    vrRegrasEspecificas.vUSAREGRANORMALIZADESC       := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','USAREGRANORMALIZADESC');       -- DDMEDICA-3017
    vrRegrasEspecificas.vREVALIDAPROMOCAOGRAVACAOPED := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','REVALIDAPROMOCAOGRAVACAOPED2316');
    vrRegrasEspecificas.vUSALIMCREDSANZONALPEDIDO    := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','USALIMCREDSANZONALPEDIDO');
    vrRegrasEspecificas.vUSAPARAMLIMITEITEMBNFTV1    := FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','USAPARAMLIMITEITEMBNFTV1');
  
    -- Cortar Produtos sem Estoque em Pedidos Bloqueados - MED-2625
    -- (CHAMADO DA GRAVAÇÃO DO PEDIDO PELA 2316 E INTEGRADORA)
    vvCortarItemSemEstPedBloq := 'N';
    IF (pi_nCodRotina IN (2316,2513)) AND (pi_vChamadaProcesso = 'GP') THEN
      IF ( (NVL(vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQFV,'N') = 'S') AND (NVL(vrPedido.vvOrigemPed,'X')  = 'F') AND (NVL(vrPedido.vvTipoFv,'FV') = 'FV') )         OR
         ( (NVL(vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQEC,'N') = 'S') AND (NVL(vrPedido.vvOrigemPed,'X')  = 'W') )                                                  OR
         ( (NVL(vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQOL,'N') = 'S') AND (NVL(vrPedido.vvOrigemPed,'X')  = 'F') AND (NVL(vrPedido.vvTipoFv,'FV') IN ('OL','PE')) ) OR
         ( (NVL(vrRegrasEspecificas.vCORTARITEMSEMESTPEDBLOQPV,'N') = 'S') AND (NVL(vrPedido.vvOrigemPed,'X') <> 'F') )                                                  THEN
        vvCortarItemSemEstPedBloq := 'S';
      END IF;
    END IF;
  
    -- Valor Mínimo para Pedidos OL e PE
    IF (vrPedido.vvOrigemPed = 'F') AND
       (vrPedido.vvTipoFv    IN ('OL','PE')) THEN
  
      -- Pesquisa Regra de Valor Mínimo da Condição de Venda
      BEGIN
        SELECT DESCRICAO
             , TIPOVALORMINIMO
             , VALORMINIMOPED
          INTO vrCondicaoVenda.vvDescricao
             , vrCondicaoVenda.vvTipoValorMinimo
             , vrCondicaoVenda.vnValorMinimoPed
          FROM PCCONDICAOVENDA
         WHERE (CODCONDICAOVENDA = vrPedido.vnCodCondicaoVenda);
      EXCEPTION 
        WHEN NO_DATA_FOUND THEN
          vrCondicaoVenda.vvDescricao       := NULL;
          vrCondicaoVenda.vvTipoValorMinimo := NULL;
          vrCondicaoVenda.vnValorMinimoPed  := 0;
      END;
      
      -- Se faz Validação do Valor Mínimo baseado na Condição de Venda
      IF (vrCondicaoVenda.vvTipoValorMinimo IN ('C','A')) THEN
        vrPedido.vvValidarMinOperadorLogistico := 'S';
      END IF;
             
    END IF; -- Valor Mínimo para Pedidos OL e PE
    
    -- DDMEDICA-2364 Parâmetro da Integradora para Ignorar Valor Mínimo do Plano de Pagamento
    vrParametros.vIGNORARMINIMOPLANOPLPAG := 'N';
    IF (vrPedido.vnIntegradora > 0) THEN
      vrParametros.vIGNORARMINIMOPLANOPLPAG := FOBTEM_PARAM_INTEGRADORA(vrPedido.vnIntegradora,
                                                                        'IGNORARMINIMOPLANOPLPAG',
                                                                        'N');
    END IF;
    
    -- DDMEDICA-2680 Parâmetro da Integradora para Ignorar a Margem Mínima do Plano de Pagamento
    vrParametros.vVALIDARMARGEMMINIMA := 'S';
    IF (vrPedido.vnIntegradora > 0) THEN
      vrParametros.vVALIDARMARGEMMINIMA := FOBTEM_PARAM_INTEGRADORA(vrPedido.vnIntegradora,
                                                                    'VALIDARMARGEMMINIMA',
                                                                    'N');
    END IF;

    -- DDMEDICA-3017 - Parâmetro da Integradora para Ignorar o Prazo Médio do Cliente
    vrParametros.vIGNORARPRAZOMEDIOCLIENTE := 'N';
    IF (vrPedido.vnIntegradora > 0) THEN
      vrParametros.vIGNORARPRAZOMEDIOCLIENTE := FOBTEM_PARAM_INTEGRADORA(vrPedido.vnIntegradora,
                                                                         'IGNORARPRAZOMEDIOCLIENTE',
                                                                         'N');
    ELSE
      IF    (vrPedido.vvOrigemPed = 'T') THEN
        vrParametros.vIGNORARPRAZOMEDIOCLIENTE := NVL(F_REGRA_MEDICAMENTOS('99','IGNORARPRAZOMEDIOCLIENTE_T'),'N');
      ELSIF (vrPedido.vvOrigemPed = 'F') THEN
        vrParametros.vIGNORARPRAZOMEDIOCLIENTE := NVL(F_REGRA_MEDICAMENTOS('99','IGNORARPRAZOMEDIOCLIENTE_F'),'N');
      ELSIF (vrPedido.vvOrigemPed = 'W') THEN
        vrParametros.vIGNORARPRAZOMEDIOCLIENTE := NVL(F_REGRA_MEDICAMENTOS('99','IGNORARPRAZOMEDIOCLIENTE_W'),'N');
      END IF;        
    END IF;
    
    -- Gravar Pedido como Bloqueado OL e PE
    vrIntegradora.vvGeraPedBloq := NULL;
    IF (NVL(vrPedido.vnIntegradora,0) > 0)   AND
       (vrPedido.vvOrigemPed = 'F')          AND
       (vrPedido.vvTipoFv    IN ('OL','PE')) THEN
  
      -- Pesquisa Regra de Valor Mínimo da Condição de Venda
      BEGIN
        SELECT GERAPEDBLOQ
          INTO vrIntegradora.vvGeraPedBloq
          FROM PCINTEGRADORA
         WHERE (INTEGRADORA = vrPedido.vnIntegradora);
      EXCEPTION 
        WHEN NO_DATA_FOUND THEN
          vrIntegradora.vvGeraPedBloq := NULL;
      END;
                   
    END IF; -- Valor Mínimo para Pedidos OL e PE
      
    -- DDMEDICA-6213
    vrParametros.vVALIDALVARAFUNCLIBERADOS     := F_REGRA_MEDICAMENTOS('99','VALIDALVARAFUNCLIBERADOS');
    -- DDMEDICA-6491
    vrParametros.vIGNORARVALIDACAOALVARASUS    := F_REGRA_MEDICAMENTOS('99','IGNORARVALIDACAOALVARASUS');
    -- DDMEDICA-6491
    vrParametros.vIGNORARVALIDACAOALVARACRF    := F_REGRA_MEDICAMENTOS('99','IGNORARVALIDACAOALVARACRF');
    -- DDMEDICA-6491
    vrParametros.vACEITARPEDALVARAVENCINTEGRAD := F_REGRA_MEDICAMENTOS('99','ACEITARPEDALVARAVENCINTEGRADORA');
      
    -- DDMEDICA-6363 - Parâmetro para Rejeitar Pedido FV de RCA com Saldo Insuficiente
    vrParametros.vREJEITAPEDRCASEMSALDOFV := NULL;
    IF (pi_nCodRotina = 2513) AND
       (vrPedido.vvOrigemPed = 'F') THEN
      vrParametros.vREJEITAPEDRCASEMSALDOFV := F_REGRA_MEDICAMENTOS('99','REJEITAPEDRCASEMSALDOFV');       
    END IF;
 
    -- CA PBM   
    vrParametros.vHABILITCANALAUTORIZPBMTELEV := F_REGRA_MEDICAMENTOS('99','HABILITCANALAUTORIZPBMTELEV');

    -- LOG: Integradora
    P_INSERE_LOG_PROCESSAMENTO('vnIntegradora = ' || vrPedido.vnIntegradora || CHR(13) ||
                               'vvOrigemPed = '   || vrPedido.vvOrigemPed   || CHR(13) ||
                               'vvTipoFv = '      || vrPedido.vvTipoFv      || CHR(13) ||
                               'vnIntegradora = ' || vrPedido.vnIntegradora);    
                                          
    -- Inicializa a Descrição da Exclusão do Pedido
    vvDescricaoExclusaoPedido := SUBSTR('Cliente: ' || TO_CHAR(vrPedido.vnCodCli) || '-' || vrCliente.vvFantasia || ' PEDIDO: ' || TO_CHAR(pi_nNumPed), 1, 80);
    
    -- Inicializa Flag que identifica se pode ou não pode Atualizar Estoque
    vbPedidoPodeAtualizarEstoque := TRUE; -->> Como Padrão, sempre atualiza o estoque
    IF (vrPedido.vvBroker = 'S') THEN
      vbPedidoPodeAtualizarEstoque := FALSE;
    END IF;
    IF (vrPedido.vnCondVenda IN (4, 14)) THEN
      vbPedidoPodeAtualizarEstoque := FALSE;
    END IF;
    IF (vrPedido.vnCondVenda = 7) AND (vrPedido.vvVendaAssistida = 'N') THEN
      vbPedidoPodeAtualizarEstoque := FALSE;
    END IF;  
  
    -- INICIALIZA VARIAVEIS DE GERAÇÃO DO PEDIDO DE ITENS FALTANTES
    vbGerouCabPedItensFaltantes := FALSE;
    vnNumPedItensFaltantes      := NVL(vnNumPedidoItensFalta,0);  
    IF (vbPedidoPodeAtualizarEstoque)                     AND
       (NVL(pi_vChamadaProcesso,' ') IN ('GP','EP','MP')) AND 
       (vvGravarPedidoItensFalta = 'S')                   AND
       (vvNovaPosicaoPedido IN ('L','M'))                 AND
       (NVL(vnNumPedItensFaltantes,0) = 0)                THEN
      -- Se deve gerar o Pedido de Itens Faltantes, mas não passou o Número do Pedido
      RAISE e_NumPedFaltasNaoInformado;     
    END IF;   
  
    --DDMEDICA-1008
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vVALIDARQTCONTGRAVACAOPED
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99') -- MED-2349
         AND (NOME      = 'VALIDARQTCONTGRAVACAOPED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vVALIDARQTCONTGRAVACAOPED := 'N';
    END;   
    
    BEGIN
      SELECT NVL(VALOR,'N')
        INTO vrParametros.vCON_VERIFICAESTOQUECONT
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = vrPedido.vvCodFilial) -- MED-2349
         AND (NOME      = 'VERIFICAESTOQUECONT');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        BEGIN
          SELECT NVL(VALOR,'N')
            INTO vrParametros.vCON_VERIFICAESTOQUECONT
            FROM PCPARAMFILIAL
           WHERE (CODFILIAL = '99') -- MED-2349
             AND (NOME      = 'CON_VERIFICAESTOQUECONT');
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrParametros.vCON_VERIFICAESTOQUECONT := 'N';
        END;
    END;   
       
    -- Verifica se utiliza Regra de Permissão da Rotina 2345 - DDMEDICA-4851
    vrParametros.vUSAREGRAPERMISSAO := F_USA_REGRA_PERMISSAO;
  
    -------------------------------------------------------
    -- Pesquisa Valor do Desconto Aprovado - HIS.05093.2017
    -------------------------------------------------------
    vbAplicouDescontoNegociado := FALSE;
    vrAprovacao                := vrLimpaAprovacao;
    IF (pi_nCodRotina = 2336) THEN  
      FOR vc_Aprovacao IN (SELECT PCAPROVACAOVLDESCNEGMED.DTAPROVACAO
                                , PCAPROVACAOVLDESCNEGMED.MATRICULA
                                , PCAPROVACAOVLDESCNEGMED.TIPODESCONTO
                                , PCAPROVACAOVLDESCNEGMED.VLDESCNEGAPROVADO
                                , PCAPROVACAOVLDESCNEGMED.ACAO
                                , PCAPROVACAOVLDESCNEGMED.VLVENDASEMIMPAPROV
                                , PCAPROVACAOVLDESCNEGMED.DTAPLICACAO
                             FROM PCAPROVACAOVLDESCNEGMED
                            WHERE (NUMPED = pi_nNumPed)
                            ORDER BY PCAPROVACAOVLDESCNEGMED.DTAPROVACAO) LOOP
        -- A última Aprovação é que valerá (Ainda não pode ter aplicado)
        vrAprovacao.ACAO               := vc_Aprovacao.ACAO;     
        vrAprovacao.VLDESCNEGAPROVADO  := vc_Aprovacao.VLDESCNEGAPROVADO;                            
        vrAprovacao.VLVENDASEMIMPAPROV := vc_Aprovacao.VLVENDASEMIMPAPROV; 
        -- Se aplicou o Desconto Negociado no Pedido, não vai ter mais validações
        IF (vc_Aprovacao.DTAPLICACAO IS NOT NULL) THEN
          vbAplicouDescontoNegociado := TRUE;
        END IF;
      END LOOP;     
      -- Se aplicou o Desconto Negociado no Pedido, não vai ter mais validações
      IF (vbAplicouDescontoNegociado) THEN
        vrAprovacao := vrLimpaAprovacao;
      END IF;
    END IF; -- Fim Condição: Chamado da Rotina 2336
    -------------------------------------------------------  
  
  
   /*************************************************************************************************
                                       INICIALIZAÇÃO DE VARIÁVEIS
                                                F I M   
    **************************************************************************************************/ 
  
  
  
  
  
   /*************************************************************************************************
                                             I N I C I O
                                   DEFINIÇÃO DA POSIÇÃO DO PEDIDO
    **************************************************************************************************/ 
  
  
    -- A nova Posição será recebida do Parâmetro, podendo mudar
    po_vPosicaoFinalPedido := vvNovaPosicaoPedido;
  
    -- Inicializa Código do Motivo
    po_nCodMotivo          := NULL;
    -- Inicializa Descrição do Motivo
    po_vMotivoPosicao      := NULL;
    -- Inicializa Observação do Motivo
    po_vObservacaoMotivo   := NULL;
  
  
    -----------------------------------------------------------------------------------------------
    -- Avalia se Grava o Pedido como Pendente 
    -- (Precisa ser em todas as chamadas, algumas validações dependendem da Posição do Pedido)
    -----------------------------------------------------------------------------------------------
    -- Verifica Regra Específica - DDMEDICA-2551
    IF (NVL(vrRegrasEspecificas.vUSAVENDASEMESTBALCAORESERVA,'N') = 'S') THEN
      vvBalcaoReservaVendaSemEst := ' ';
    ELSE
      vvBalcaoReservaVendaSemEst := 'R';
    END IF;
    -- Se o Pedido Chegar como Liberado, e estiver parametrizado para Aceitar Venda sem Estoque
    -- (Televendas e INTEGRADORA_MED)
    --
    IF (pi_nCodRotina                  IN (2316,2513)) AND
       (vrParametros.vACEITAVENDASEMEST = 'S')         AND
       (NVL(vrPedido.vvOrigemPed,' ')   NOT IN ('B',vvBalcaoReservaVendaSemEst)) AND -- DDMEDICA-2213 -- DDMEDICA-2551
       (po_vPosicaoFinalPedido          = 'L')         THEN
      -- A 2316 sempre gravava o Pedido como pendente com o motivo "PRODUTO SEM ESTOQUE"     
      po_vPosicaoFinalPedido := 'P';
      -- Motivo do Pedido ficar como Pendente
      P_GERAR_TEXTO_LOG_BLOQUEIO(0,
                                 'PARAMETRO "ACEITAR VENDA SEM ESTOQUE"', -->> Para ficar mais fácil entender, mudei de Produto Sem Estoque para a descrição da Parametrização
                                 'Parâmetro "Aceitar venda sem estoque" igual = SIM, grava Pedido como Pendente e com motivo "ACEITAR VENDA SEM ESTOQUE"',
                                 po_nCodMotivo,
                                 po_vMotivoPosicao,
                                 po_vObservacaoMotivo);
    END IF;
        
    -- Regra Broker
    IF (pi_nCodRotina = 2316)             AND
       (NVL(vrPedido.vvBroker,'N') = 'S') AND
       (po_vPosicaoFinalPedido = 'L')     THEN
      po_vPosicaoFinalPedido := 'P';
      -- Motivo do Pedido ficar como Pendente
      P_GERAR_TEXTO_LOG_BLOQUEIO(0,
                                 'BROKER',
                                 'Pedido Broker é gravado como Pendente',
                                 po_nCodMotivo,
                                 po_vMotivoPosicao,
                                 po_vObservacaoMotivo);
    END IF;
       
  
   /*************************************************************************************************
                                   DEFINIÇÃO DA POSIÇÃO DO PEDIDO
                                             F I M
    **************************************************************************************************/ 
  
  
  
  
  
   /*************************************************************************************************
                                             I N I C I O
                            DEFINIÇÃO DA AÇÃO AO NÃO ATINGIR VALORES MÍNIMOS
    **************************************************************************************************/ 
  
    --------------------------------------------------------------------------------------------------
    -- CHAMANDO DA 2316 ------------------------------------------------------------------------------
    --------------------------------------------------------------------------------------------------
    IF    (pi_nCodRotina = 2316) THEN
    
      -- Validará Valor Mínimo - MED-1964
      vbValidarValorMinimo := TRUE;
    
      -- Se Chamado da Validação do Mínimo durante a Digitação do Pedido --
      ----------------------------------------------------------------------
      IF    (pi_vChamadaProcesso IN ('VM','LB')) THEN
    
        --********** VALOR MÍNIMO DO PLANO DE PAGAMENTO **********--
        -- Balcão/Balcão Reserva não tem tratamento diferenciado para Mínimo do Plano
        -- Perguntar se Bloqueia
        IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'P';
        -- Abortar Continuação do Processo
        ELSE       
          vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'A';
        END IF;
        vrAcaoSobreCritica.vvParamsValorMinPlPag := '2207';
        
        --********** QTDE. MIN. ITENS DO PLANO DE PAGAMENTO **********--
        -- Balcão/Balcão Reserva não tem tratamento diferenciado para Mínimo do Plano
        -- Abortar Continuação do Processo
        vrAcaoSobreCritica.vvAcaoNumItensMinPlPag := 'A';
        
        --********** VALOR MÍNIMO VENDA BK **********--
        -- Abortar Continuação do Processo
        IF (NVL(vrParametros.vACEITAVENDABLOQ,'N') = 'N') THEN
          vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'A';
        ELSE 
          -- Balcão/Balcão Reserva não tem tratamento diferenciado para Mínimo BK
          -- Perguntar se Bloqueia
          IF (NVL(vrParametros.vFIL_ALTERARCOBBKCHAUTOMATICO,'N') = 'N') AND 
             (NVL(vrPedido.vvOrigemPed,' ') NOT IN ('B','R'))            THEN
            vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'P';
          ELSE
            -- Abortar Continuação do Processo
            IF (F_VERIFICARACESSOCONTROLE(2316,56,pi_nMatricula)) THEN -->> Não permitir gravar pedido alterando Cobrança
              vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'A';
            ELSE
              -- Perguntar se Altera Cobrança para Cheque
              vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk     := 'P';
              vrAcaoSobreCritica.vnProcedimValorMinimoVendaBk := 'AlterarCobrancaParaCheque'; -->> Esta descrição não pode ser alterada (Case Sensitive)
            END IF;
          END IF;
        END IF;
        vrAcaoSobreCritica.vnPermissValorMinimoVendaBk := 56;
  
        --********** VALOR MÍNIMO VENDA BNF **********--
        -- Balcão/Balcão Reserva não tem tratamento diferenciado para Mínimo BNF
        -- Perguntar se Bloqueia
        IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'P';
        -- Abortar Continuação do Processo
        ELSE       
          vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'A';
        END IF;
  
        --********** VALOR MÍNIMO DO RCA **********--
        IF (vrPedido.vvOrigemPed IN ('B','R') AND NVL(vrParametros.vVALIDAVLMINVENDABALCAO,'N') = 'N') THEN
          -- Ignorar Ação (Balcão depende do parâmetro "VALIDAVLMINVENDABALCAO")
          vrAcaoSobreCritica.vvAcaoValorMinRca := 'I';
        ELSE
          -- Perguntar se Bloqueia
          IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
            vrAcaoSobreCritica.vvAcaoValorMinRca := 'P';
          -- Abortar Continuação do Processo
          ELSE       
            vrAcaoSobreCritica.vvAcaoValorMinRca := 'A';
          END IF;        
        END IF;
  
        --********** VALOR MÍNIMO DO PEDIDO **********--
        IF (vrPedido.vvOrigemPed IN ('B','R') AND NVL(vrParametros.vVALIDAVLMINVENDABALCAO,'N') = 'N') THEN -->> A 2316 não usava com o Parâmetro "VLMINVENDA"
          -- Ignorar Ação (Balcão depende do parâmetro "VALIDAVLMINVENDABALCAO")
          vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
        ELSE
          -- Perguntar se Bloqueia
          IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
            vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'P';
          -- Abortar Continuação do Processo
          ELSE       
            vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'A';
          END IF;       
          vrAcaoSobreCritica.vvParamsValorMinimoPedVenda := '1458,2325';  
        END IF;
        
        --*** BLOQUEAR PEDIDOS BONIFICADOS ***--
        -- Balcão/Balcão Reserva não tem tratamento diferenciado para esta Validação
        -- Se Bonificação estiver Parametrizado para Gravar Sempre como Bloqueado no Telemarketing
        IF    (NVL(vrParametros.vBLOQUEARPEDBONIFIC,'N') = 'S') AND
              (NVL(vrPedido.vnCondVenda,0) IN (5,6,11))         AND
              (NVL(vrPedido.vvOrigemPed,' ') IN ('T','F'))      THEN
          -- Perguntar se Bloqueia
          vrAcaoSobreCritica.vvAcaoPedidoBonific := 'P';
        END IF;
        
        --*** BLOQUEAR PEDIDOS na 2316 ***--
        -- Se Empresa Parametrizado para Gravar o Pedido Sempre como Bloqueado (Exceto Balcão e Avaria e Exceto CrossDocking)
        IF (NVL(vrParametros.vGRAVARPEDVENBLOQMED,'N') = 'S') AND
           (NVL(vrPedido.vvOrigemPed,' ') NOT IN ('B'))       AND
           (NVL(vrPedido.vvPedidoAvaria,'N') <> 'S')          AND
           (NVL(vrPedido.vnNumTransEntCrossDock,0) = 0)       THEN
          -- Perguntar se Bloqueia
          vrAcaoSobreCritica.vvAcaoGravarPedBloq := 'P';
        END IF;
  
        --*** BLOQUEAR PEDIDOS na 2316 ***--
        -- Se Pedido com valor de Desconto Negociado  - HIS.05093.2017 (Exceto Balcão)
        IF (NVL(vrRegrasEspecificas.vNEGOCIARVALORDESCOMPEDIDO,'N') = 'S') AND
           (NVL(vrPedido.vvOrigemPed,' ') NOT IN ('B'))                    THEN
