        ELSIF (NVL(vrParametros.vBLOQPRAZOMDVENDA,'N') = 'S') THEN -- Não aceita planos de pagamento com prazo médio superior ao prazo médio do plano de pagamento do cliente.
          vrAcaoSobreCritica.vvAcaoPrazoMedio := 'A';
        ELSE
