            ELSE
              vrAcaoSobreCritica.vvAcaoMargemMinima := 'A';
            END IF;
          END IF;
          vrAcaoSobreCritica.vnPermissMargemMinima := 20;
        END IF;
        vrAcaoSobreCritica.vvParamsMargemMinima  := '1429';

        --********** MARGEM MÍNIMA DA 132 **********--
        -- Perguntar se Bloqueia
        IF    (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132  := 'I';
          vrAcaoSobreCritica.vnPermissMargemMinima132 := NULL;
        ELSIF (NVL(vrPedido.vvPedidoAvaria,'N') = 'S') THEN
          IF (F_VERIFICARACESSOCONTROLE(2316,86,pi_nMatricula)) THEN
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
          ELSE
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'P';
          END IF;
          vrAcaoSobreCritica.vnPermissMargemMinima132 := 86;
        ELSIF (NVL(vrPedido.vnNumTransEntCrossDock,0) > 0) THEN
          IF (F_VERIFICARACESSOCONTROLE(2316,92,pi_nMatricula)) THEN
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
          ELSE
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'P';
          END IF;
          vrAcaoSobreCritica.vnPermissMargemMinima132 := 92;
        ELSE
          IF (NVL(vrParametros.vTIPOVALIDMARGEMMINVENDAMED,'0') = '2') THEN
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'P';
          ELSE
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'A';
          END IF;
          vrAcaoSobreCritica.vnPermissMargemMinima132 := NULL;
        END IF;
        vrAcaoSobreCritica.vvParamsMargemMinima132  := '9894,9897';
        
        --********** ALVARA **********--
        -- Perguntar se Bloqueia
        vrAcaoSobreCritica.vvAcaoAlvara    := 'P';
        vrAcaoSobreCritica.vnPermissAlvara := NULL;
        IF (NVL(vrParametros.vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') THEN
          vrAcaoSobreCritica.vvParamsAlvara    := '9818';
          vrAcaoSobreCritica.vnCodRotinaAlvara := 3331;
        ELSE
          vrAcaoSobreCritica.vvParamsAlvara    := '9818,2521,2516';
          vrAcaoSobreCritica.vnCodRotinaAlvara := 302;
        END IF;
        
        --********** BLOQUEIO AUTOMATICO DA INTEGRADORA **********--        
        -- Sem Ação
        vrAcaoSobreCritica.vvAcaoGerarPedBloq := NULL;

        --********** VALOR MÍNIMO DA RESTRIÇÃO DE VENDA **********--
        -- Abortar Continuação do Processo
        vrAcaoSobreCritica.vvAcaoValorMinRestr := 'A';
        
        --********** BLOQUEIOS COMERCIAIS **********--
        -- Perguntar se Bloqueia
        vrAcaoSobreCritica.vvAcaoBloqueioComercial    := 'P';
        vrAcaoSobreCritica.vvPermissBloqueioComercial := NULL;
        
        --********** ITEM BNF **********--
        -- Abortar Continuação do Processo
        vrAcaoSobreCritica.vvAcaoItemBnfTV1 := 'A';
        
        --********** FATURAMENTO INTEGRAL **********--
        -- Abortar Continuação do Processo
        vrAcaoSobreCritica.vvAcaoFaturamentoIntegral := 'A';

        --********** CANAL AUTORIZADOR PBM CA PBM **********--
        -- Perguntar se Bloqueia
        vrAcaoSobreCritica.vvAcaoCanalAutorizadorPbm := 'P';

      -- Se Chamado da Gravação do Pedido ou da Edição do Pedido --
      -------------------------------------------------------------
      ELSIF (pi_vChamadaProcesso IN ('GP','EP')) THEN
      
        -->>
        -->> Verificar como Fica o Balcão, já que fatura direto
        -->>     
       
        --********** VALOR MÍNIMO DO PLANO DE PAGAMENTO **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'B';
  
        --********** QTDE. MIN. ITENS DO PLANO DE PAGAMENTO **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoNumItensMinPlPag := 'B';
        
        --********** VALOR MÍNIMO VENDA BK **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'B';
      
        --********** VALOR MÍNIMO VENDA BNF **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'B';
        
        --********** VALOR MÍNIMO DO RCA **********--
        IF (vrPedido.vvOrigemPed IN ('B','R') AND NVL(vrParametros.vVALIDAVLMINVENDABALCAO,'N') = 'N') THEN
          -- Ignorar Ação (Balcão depende do parâmetro "VALIDAVLMINVENDABALCAO")
          vrAcaoSobreCritica.vvAcaoValorMinRca := 'I';
        ELSE
          -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
          vrAcaoSobreCritica.vvAcaoValorMinRca := 'B';
        END IF;
              
        --********** VALOR MÍNIMO DO PEDIDO **********--
        IF (vrPedido.vvOrigemPed IN ('B','R') AND NVL(vrParametros.vVALIDAVLMINVENDABALCAO,'N') = 'N') THEN -->> A 2316 não usava com o Parâmetro "VLMINVENDA"
          -- Ignorar Ação (Balcão depende do parâmetro "VALIDAVLMINVENDABALCAO")
          vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
        ELSE
          -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
          vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'B';
        END IF;
      
