        IF    (NVL(vrParametros.vBLOQUEARPEDBONIFIC,'N') = 'S') AND
              (NVL(vrPedido.vnCondVenda,0) IN (5,6,11))         AND
              (NVL(vrPedido.vvOrigemPed,' ') IN ('T','F'))      THEN
          vrAcaoSobreCritica.vvAcaoPedidoBonific := 'B';
        END IF;
        
