        -- Se Empresa Parametrizado para Gravar o Pedido Sempre como Bloqueado (Exceto Balcão e Avaria e Exceto CrossDocking)
        IF (NVL(vrParametros.vGRAVARPEDVENBLOQMED,'N') = 'S') AND
           (NVL(vrPedido.vvOrigemPed,' ') NOT IN ('B'))       AND
           (NVL(vrPedido.vvPedidoAvaria,'N') <> 'S')          AND
           (NVL(vrPedido.vnNumTransEntCrossDock,0) = 0)       THEN
          vrAcaoSobreCritica.vvAcaoGravarPedBloq := 'B';
