        vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF := 'B';

        --********** PREÇO ABAIXO DO MÍMIMO **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoPrecoMinimo := 'B';

