        IF    (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132  := 'I';
        ELSIF (NVL(vrPedido.vvPedidoAvaria,'N') = 'S') THEN
          IF (F_VERIFICARACESSOCONTROLE(2316,86,pi_nMatricula)) THEN
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
          ELSE
            -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'B';
          END IF;
        ELSIF (NVL(vrPedido.vnNumTransEntCrossDock,0) > 0) THEN
          IF (F_VERIFICARACESSOCONTROLE(2316,92,pi_nMatricula)) THEN
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
          ELSE
            -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
            vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'B';
          END IF;
        ELSE
          -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'B';
        END IF;
                 
        --********** ALVARA **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoAlvara := 'B';

        --********** BLOQUEIO AUTOMATICO DA INTEGRADORA **********--        
        -- Sem Ação
        vrAcaoSobreCritica.vvAcaoGerarPedBloq := NULL;

        --********** VALOR MÍNIMO DA RESTRIÇÃO DE VENDA **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoValorMinRestr := 'B';

        --********** BLOQUEIOS COMERCIAIS **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoBloqueioComercial    := 'B';
        vrAcaoSobreCritica.vvPermissBloqueioComercial := NULL;

        --********** ITEM BNF **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoItemBnfTV1 := 'B';

        --********** FATURAMENTO INTEGRAL **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoFaturamentoIntegral := 'B';

        --********** CANAL AUTORIZADOR PBM CA PBM **********--
        -- Bloquear o Pedido (Não tem mais como voltar - baixou estoque)
        vrAcaoSobreCritica.vvAcaoCanalAutorizadorPbm := 'B';

      END IF; -- Fim Condição: Tipo Chamada
     
    --------------------------------------------------------------------------------------------------
    -- CHAMANDO DA 2336 ------------------------------------------------------------------------------
    --------------------------------------------------------------------------------------------------
    ELSIF (pi_nCodRotina = 2336) THEN  
  
      -- Validará Valor Mínimo - MED-1964
      vbValidarValorMinimo := TRUE;
      
      -- Se a Posição do Pedido ficar como Liberado ou Montado
      -- Ou Log dos Bloqueios
      IF (NVL(po_vPosicaoFinalPedido,' ') IN ('L','M')) OR
         (pi_vChamadaProcesso IN ('LB')) THEN

        --********** VALOR MÍNIMO DO PLANO DE PAGAMENTO **********--
        -- Abortar a Liberação do Pedido
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinPlPag    := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,33,pi_nMatricula)) THEN    
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinPlPag    := 'I';
          vrAcaoSobreCritica.vnPermissValorMinPlPag := 33;
        ELSE
          -- Abortar a Liberação do Pedido por NÃO ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinPlPag    := 'A';
          vrAcaoSobreCritica.vnPermissValorMinPlPag := 33;
          vrAcaoSobreCritica.vvLibValorMinPlPag     := 'A';
        END IF;
  
        --********** QTDE. MIN. ITENS DO PLANO DE PAGAMENTO **********--
        -- Perguntar para a Ação
        vrAcaoSobreCritica.vvAcaoNumItensMinPlPag := 'P';
        
        --********** VALOR MÍNIMO VENDA BK **********--
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk    := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,34,pi_nMatricula)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk    := 'I';
          vrAcaoSobreCritica.vnPermissValorMinimoVendaBk := 34;
        ELSE
          -- Abortar a Liberação do Pedido por NÃO ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk    := 'A';
          vrAcaoSobreCritica.vnPermissValorMinimoVendaBk := 34;
          vrAcaoSobreCritica.vvLibValorMinimoVendaBk     := 'A';
        END IF;
  
        --********** VALOR MÍNIMO VENDA BNF **********--
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinVendaBnf    := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,36,pi_nMatricula)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinVendaBnf    := 'I';
          vrAcaoSobreCritica.vnPermissValorMinVendaBnf := 36;
        ELSE
          -- Abortar a Liberação do Pedido por NÃO ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinVendaBnf    := 'A';
          vrAcaoSobreCritica.vnPermissValorMinVendaBnf := 36;
          vrAcaoSobreCritica.vvLibValorMinVendaBnf     := 'A';
        END IF;
        
        --********** VALOR MÍNIMO DO RCA **********--
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN -- DDMEDICA-5689
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinRca        := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,73,pi_nMatricula)) THEN -- DDMEDICA-5689
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinRca        := 'I';
        -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
        ELSIF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoValorMinRca        := F_OBTER_ACAO_CONFORME_ACESSO(8,pi_nMatricula);
        -- Abortar a Liberação do Pedido (Não tem permissão de Acesso)
        ELSE        
          vrAcaoSobreCritica.vvAcaoValorMinRca        := 'A';
          vrAcaoSobreCritica.vnPermissAcaoValorMinRca := 73;
        END IF;
        
        --********** VALOR MÍNIMO DO PEDIDO **********--
        -- Abortar a Liberação do Pedido (Não tem permissão de Acesso)
        -- AO TENTAR LIBERAR PEDIDO E TIVER A PERMISSÃO 74 OU 75 DEVERA REALIZAR O PROCESSO POIS
        -- SÃO AS DUAS PERMISSOES PARA LIBERAR ABAIXO DO VALOR MINIMO (74 = balcao,75- balcao reserva)
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
           vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,74,pi_nMatricula) AND (NVL(vrPedido.vvOrigemPed,'') IN ('B')))  THEN
           vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,75,pi_nMatricula) AND (NVL(vrPedido.vvOrigemPed,'') IN ('R'))) THEN
           vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
        ELSIF ((NVL(vrPedido.vvOrigemPed,'') IN ('R')) AND ( NOT F_VERIFICARACESSOCONTROLE(2336,74,pi_nMatricula))) THEN
           vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda    := 'A';
           vrAcaoSobreCritica.vnPermissValorMinimoPedVenda := '75';
           vrAcaoSobreCritica.vvLibValorMinimoPedVenda     := 'A';
        ELSIF((NVL(vrPedido.vvOrigemPed,'') IN ('B')) AND (NOT F_VERIFICARACESSOCONTROLE(2336,75,pi_nMatricula))) THEN
           vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda    := 'A';
           vrAcaoSobreCritica.vnPermissValorMinimoPedVenda := '74';
           vrAcaoSobreCritica.vvLibValorMinimoPedVenda     := 'A';
        ELSE
           vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda      := 'A';
           IF    (NVL(vrPedido.vvOrigemPed,'') IN ('B')) THEN
             vrAcaoSobreCritica.vnPermissValorMinimoPedVenda := '74';
           ELSIF (NVL(vrPedido.vvOrigemPed,'') IN ('R')) THEN
             vrAcaoSobreCritica.vnPermissValorMinimoPedVenda := '75';
           ELSE
             vrAcaoSobreCritica.vnPermissValorMinimoPedVenda := NULL;
           END IF;
           vrAcaoSobreCritica.vvLibValorMinimoPedVenda       := 'A';
        END IF;
        IF (vrPedido.vvOrigemPed = 'F') THEN
          vrAcaoSobreCritica.vvParamsValorMinimoPedVenda := '1458,2325,2833';
        ELSE
          vrAcaoSobreCritica.vvParamsValorMinimoPedVenda := '1458,2325';
        END IF;
  
        --********** VALOR MINIMO OPERADOR LOGISTICO **********--
        -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
        IF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoVlMinOperadorLogistico := F_OBTER_ACAO_CONFORME_ACESSO(11,pi_nMatricula);
        -- Abortar Continuação do Processo
        ELSE        
          vrAcaoSobreCritica.vvAcaoVlMinOperadorLogistico := 'A';
        END IF;
        
        --*** BLOQUEAR PEDIDOS BONIFICADOS ***--
        -- Balcão/Balcão Reserva não tem tratamento diferenciado para esta Validação
        -- Se Bonificação estiver Parametrizado para Gravar Sempre como Bloqueado no Telemarketing
        IF    (NVL(vrParametros.vBLOQUEARPEDBONIFIC,'N') = 'S') AND
              (NVL(vrPedido.vnCondVenda,0) IN (5,6,11))         AND
              (NVL(vrPedido.vvOrigemPed,' ') IN ('T','F'))      THEN
          IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
            -- Ignorar Ação por ter permissão de acesso
            vrAcaoSobreCritica.vvAcaoPedidoBonific    := 'I';
          ELSIF (NVL(vrPedido.vnCondVenda,0) IN (5,6)) AND
                (NOT F_VERIFICARACESSOCONTROLE(2336,26,pi_nMatricula)) THEN
            -- Ignorar Ação por ter permissão de acesso
            vrAcaoSobreCritica.vvAcaoPedidoBonific    := 'I';
            vrAcaoSobreCritica.vnPermissPedidoBonific := '26';
          ELSIF (NVL(vrPedido.vnCondVenda,0) IN (11)) AND
                (NOT F_VERIFICARACESSOCONTROLE(2336,27,pi_nMatricula)) THEN
            -- Ignorar Ação por ter permissão de acesso
            vrAcaoSobreCritica.vvAcaoPedidoBonific    := 'I';
            vrAcaoSobreCritica.vnPermissPedidoBonific := '27';
          ELSE
            -- Abortar a Liberação do Pedido (Não tem permissão de Acesso)
            vrAcaoSobreCritica.vvAcaoPedidoBonific      := 'A';
            IF (NVL(vrPedido.vnCondVenda,0) IN (5,6)) THEN
              vrAcaoSobreCritica.vnPermissPedidoBonific := '26';
            ELSE
              vrAcaoSobreCritica.vnPermissPedidoBonific := '27';
            END IF;
            vrAcaoSobreCritica.vvLibPedidoBonific       := 'A';
          END IF;
        END IF;
        
        --*** BLOQUEAR PEDIDOS na 2316 ***--
        vrAcaoSobreCritica.vvAcaoGravarPedBloq := NULL;
        
        --*** VALOR MINIMO APROVADO PARA APLICACAO DO DESCONTO NEGOCIADO ***--
        -- Se Pedido com valor de Desconto Negociado  - HIS.05093.2017 (Exceto Balcão)
        IF (NVL(vrRegrasEspecificas.vNEGOCIARVALORDESCOMPEDIDO,'N') = 'S') AND
           (NVL(vrPedido.vvOrigemPed,' ') NOT IN ('B'))                    THEN
          -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
          IF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
            vrAcaoSobreCritica.vvAcaoValorMinDescNeg := F_OBTER_ACAO_CONFORME_ACESSO(703,pi_nMatricula);
          -- Abortar a Liberação do Pedido
          ELSE
            vrAcaoSobreCritica.vvAcaoValorMinDescNeg := 'A';
          END IF;
        END IF;
  
        --********** SALDO CONTA-CORRENTE RCA **********--    
        IF (NVL(pi_vMovimentarSaldoRca,'N') = 'S') THEN
          IF (NOT F_VERIFICARACESSOCONTROLE(2336,67,pi_nMatricula)) THEN
            vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo := 'I';
          ELSE
            -- Abortar a Liberação do Pedido
            vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo := 'A';
            vrAcaoSobreCritica.vvLibVendaRcaSemSaldo  := 'A';
          END IF;
        END IF;
        
        --********** TER ESTOQUE TOTAL **********--    
        vrAcaoSobreCritica.vvAcaoTerEstoqueTotal := NULL;
        
        --********** VALOR MÍNIMO DA COBRANÇA **********--
        -- Abortar a Liberação do Pedido
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinCob    := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,34,pi_nMatricula)) THEN
          -- Ignorar Ação por ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinCob    := 'I';
          vrAcaoSobreCritica.vnPermissValorMinCob := 34;
        ELSE
          -- Abortar a Liberação do Pedido por NÃO ter permissão de acesso
          vrAcaoSobreCritica.vvAcaoValorMinCob    := 'A';
          vrAcaoSobreCritica.vnPermissValorMinCob := 34;
          vrAcaoSobreCritica.vvLibValorMinCob     := 'A';
        END IF;      
  
        --********** RCA BLOQUEADO **********
        -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
        IF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoRcaBloqueado := F_OBTER_ACAO_CONFORME_ACESSO(1,pi_nMatricula);
        ELSE
          -- Abortar Continuação do Processo
          vrAcaoSobreCritica.vvAcaoRcaBloqueado := 'A';
        END IF;
        vrAcaoSobreCritica.vvParamsRcaBloqueado := '1429';
        
        --********** CLIENTE BLOQUEADO **********--
        -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
        IF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoClienteBloqueado := F_OBTER_ACAO_CONFORME_ACESSO(2,pi_nMatricula);
        -- Abortar Continuação do Processo
        ELSE
          vrAcaoSobreCritica.vvAcaoClienteBloqueado := 'A';
        END IF;
        vrAcaoSobreCritica.vvParamsClienteBloqueado := '1429';
  
        --********** CLIENTE SEM CREDITO **********--
        -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
        IF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoClienteSemCredito  := F_OBTER_ACAO_CONFORME_ACESSO(3,pi_nMatricula);
        -- Abortar Continuação do Processo
        ELSE
          vrAcaoSobreCritica.vvAcaoClienteSemCredito  := 'A';
        END IF;
        vrAcaoSobreCritica.vnPermissClienteSemCredito := 46;

        --********** VALOR MÁXIMO VENDA **********--
        -- Ignorar Ação (Não existe permissão)
        vrAcaoSobreCritica.vvAcaoVlMaxVenda   := 'I';
        vrAcaoSobreCritica.vvParamsVlMaxVenda := '2198';

        --********** VALOR MÁXIMO VENDA PF **********--
        -- Ignorar Ação (Não existe permissão)
        vrAcaoSobreCritica.vvAcaoVlMaxVendaPF   := 'I';
        vrAcaoSobreCritica.vvParamsVlMaxVendaPF := '2198';

        --********** VALOR MÁXIMO VENDA BNF **********--
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF  := 'I';
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,37,pi_nMatricula)) THEN
          vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF  := 'I';
        ELSE
          -- Abortar Continuação do Processo
          vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF   := 'A';
          vrAcaoSobreCritica.vvLibVlMaxVendaBNF    := 'A';
        END IF;
        vrAcaoSobreCritica.vvParamsVlMaxVendaBNF   := '2198';
        vrAcaoSobreCritica.vnPermissVlMaxVendaBNF  := '37';

        --********** PREÇO ABAIXO DO MÍMIMO **********--
        -- Ignorar Ação (Não existe permissão)
        vrAcaoSobreCritica.vvAcaoPrecoMinimo   := 'I';
        vrAcaoSobreCritica.vvParamsPrecoMinimo := '1942';

        --********** PRAZO MÉDIO DO PEDIDO **********--
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          vrAcaoSobreCritica.vvAcaoPrazoMedio     := 'I';
        -- Ignorar Ação (Se OL sem validar Prazo Médio)
        ELSIF (NVL(vrParametros.vIGNORARPRAZOMEDIOCLIENTE,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoPrazoMedio     := 'I';
        -- Ignorar Ação (Se permissão)
        ELSIF (F_VERIFICARACESSOCONTROLE(2336,64,pi_nMatricula)) THEN
          vrAcaoSobreCritica.vvAcaoPrazoMedio     := 'I';
        ELSE
          -- Abortar Continuação do Processo
          vrAcaoSobreCritica.vvAcaoPrazoMedio     := 'A';
          vrAcaoSobreCritica.vvLibVendaPrazoMedio := 'A';
          vrAcaoSobreCritica.vnPermissPrazoMedio  := '64';
        END IF;

        --********** MARGEM MÍNIMA DO PLANO DE PAGAMENTO **********--
        -- Perguntar se Bloqueia
        IF    (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
        ELSIF (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
        ELSIF (NVL(vrPedido.vnNumTransEntCrossDock,0) > 0) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
        ELSIF (vrPedido.vvOrigemPed = 'F') AND
              (NVL(vrPedido.vvTipoFv,'FV') IN ('OL','PE')) AND
              (NVL(vrParametros.vVALIDARMARGEMMINIMA,'N') <> 'S') THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
        ELSE
          IF (F_VERIFICARACESSOCONTROLE(2336,7,pi_nMatricula)) THEN
            vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
          ELSE
            IF (NVL(vrParametros.vVERIFICAMARGEMLIBPEDIDO,'N') = 'S') THEN
              -- Abortar Continuação do Processo
              vrAcaoSobreCritica.vvAcaoMargemMinima := 'A';
              vrAcaoSobreCritica.vvLibMargemMinima  := 'A';
            ELSE
              vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
            END IF;
          END IF;
        END IF;
        vrAcaoSobreCritica.vnPermissMargemMinima := 7;
        vrAcaoSobreCritica.vvParamsMargemMinima  := '1982,1429';

        --********** MARGEM MÍNIMA DA 132 **********--
        -- Perguntar se Bloqueia
        IF    (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
        ELSIF (NVL(vrPedido.vvPedidoAvaria,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
        ELSIF (NVL(vrPedido.vnNumTransEntCrossDock,0) > 0) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
        ELSIF (vrPedido.vvOrigemPed = 'F') AND
              (NVL(vrPedido.vvTipoFv,'FV') IN ('OL','PE')) AND
              (NVL(vrParametros.vVALIDARMARGEMMINIMA,'N') <> 'S') THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
        ELSE
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
        END IF;
        vrAcaoSobreCritica.vnPermissMargemMinima132 := NULL;
        vrAcaoSobreCritica.vvParamsMargemMinima132  := '9894,9897';

        --********** ALVARA **********--
        -- Não deixa Liberar porque a Liberação Corta Itens com Problema de Alvará,
        -- dessa forma não dá pra adiantar o comercial e financeiro sem resolver primeiro o alvará
        vrAcaoSobreCritica.vvAcaoAlvara        := 'A';
        IF (NVL(vrParametros.vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') THEN
          vrAcaoSobreCritica.vvParamsAlvara    := '9818';
          vrAcaoSobreCritica.vnCodRotinaAlvara := 3331;
        ELSE
          vrAcaoSobreCritica.vvParamsAlvara    := '9818,2521,2516';
          vrAcaoSobreCritica.vnCodRotinaAlvara := 302;
        END IF;

        --********** BLOQUEIO AUTOMATICO DA INTEGRADORA **********--        
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoGerarPedBloq := 'I';

        --********** VALOR MÍNIMO DA RESTRIÇÃO DE VENDA **********--
        -- Serão liberados os demais motivos que a matrícula tem acesso mas o pedido continuará como bloqueado - DDMEDICA-4851
        IF (NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoValorMinRestr := F_OBTER_ACAO_CONFORME_ACESSO(-1,pi_nMatricula);
        ELSE
          vrAcaoSobreCritica.vvAcaoValorMinRestr := 'A';
        END IF;

        --********** BLOQUEIOS COMERCIAIS **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoBloqueioComercial      := 'I';
        IF (F_IGNORA_AUTORIZACAO_LIB_BLOQ = 'S') THEN
          vrAcaoSobreCritica.vvPermissBloqueioComercial := NULL;
        ELSE
          vrAcaoSobreCritica.vvPermissBloqueioComercial := 'Rotina 320';
        END IF;

        --********** ITEM BNF **********--
        -- Abortar Continuação do Processo
        vrAcaoSobreCritica.vvAcaoItemBnfTV1 := 'A';
        vrAcaoSobreCritica.vvLibItemBnfTV1  := 'A';

        --********** FATURAMENTO INTEGRAL **********--
        -- Abortar Continuação do Processo
        vrAcaoSobreCritica.vvAcaoFaturamentoIntegral := 'A';

        --********** CANAL AUTORIZADOR PBM CA PBM **********--
        -- Ignora ou Aborta Continuação do Processo conforme Situação do Pedido na Integradora
        vrAcaoSobreCritica.vvAcaoCanalAutorizadorPbm := F_OBTER_ACAO_SITUACAO_CA_PBM(pi_nNumPed);

      -- Se a Posição do Pedido ficar como Bloqueado ou Pendente
      ELSE
      
        --********** VALOR MÍNIMO DO PLANO DE PAGAMENTO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'I';
      
        --********** QTDE. MIN. ITENS DO PLANO DE PAGAMENTO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoNumItensMinPlPag := 'I';
  
        --********** VALOR MÍNIMO VENDA BK **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'I';
      
        --********** VALOR MÍNIMO VENDA BNF **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'I';
  
        --********** VALOR MÍNIMO DO RCA **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinRca := 'I';
      
        --********** VALOR MÍNIMO DO PEDIDO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
      
        --********** VALOR MINIMO OPERADOR LOGISTICO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoVlMinOperadorLogistico := 'I';
  
        --*** VALOR MINIMO APROVADO PARA APLICACAO DO DESCONTO NEGOCIADO ***--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinDescNeg := 'I';
  
        --********** SALDO CONTA-CORRENTE RCA **********--    
        IF (NVL(pi_vMovimentarSaldoRca,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo := 'I';
        END IF;
  
        --********** TER ESTOQUE TOTAL **********--    
        vrAcaoSobreCritica.vvAcaoTerEstoqueTotal := NULL;
           
        --********** VALOR MÍNIMO DA COBRANÇA **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinCob := 'I';
  
        --********** RCA BLOQUEADO **********
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoRcaBloqueado := 'I';
  
        --********** CLIENTE BLOQUEADO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoClienteBloqueado := 'I';
  
        --********** CLIENTE SEM CREDITO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoClienteSemCredito := 'I';

        --********** VALOR MÁXIMO VENDA **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoVlMaxVenda := 'I';

        --********** VALOR MÁXIMO VENDA PF **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoVlMaxVendaPF := 'I';

        --********** VALOR MÁXIMO VENDA BNF **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF := 'I';

        --********** PREÇO ABAIXO DO MÍMIMO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoPrecoMinimo := 'I';

        --********** PRAZO MÉDIO DO PEDIDO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoPrazoMedio := 'I';

        --********** MARGEM MÍNIMA DO PLANO DE PAGAMENTO **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';

        --********** MARGEM MÍNIMA DA 132 **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';

        --********** ALVARA **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoAlvara := 'I';

        --********** BLOQUEIO AUTOMATICO DA INTEGRADORA **********--        
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoGerarPedBloq := 'I';

        --********** VALOR MÍNIMO DA RESTRIÇÃO DE VENDA **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoValorMinRestr := 'I';

        --********** BLOQUEIOS COMERCIAIS **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoBloqueioComercial    := 'I';
        vrAcaoSobreCritica.vvPermissBloqueioComercial := 'Rotina 320';

        --********** ITEM BNF **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoItemBnfTV1 := 'I';

        --********** FATURAMENTO INTEGRAL **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoFaturamentoIntegral := 'I';

        --********** CANAL AUTORIZADOR PBM CA PBM **********--
        -- Ignorar Ação
        vrAcaoSobreCritica.vvAcaoCanalAutorizadorPbm := 'I';

      END IF; -- Fim Condição: Para Qual Posição o Pedido será Alterado
  
    --------------------------------------------------------------------------------------------------
    -- CHAMANDO DA INTEGRADORA_MED -------------------------------------------------------------------
    --------------------------------------------------------------------------------------------------
    ELSIF (pi_nCodRotina = 2513) THEN
  
      -- Validará Valor Mínimo - MED-1964
      vbValidarValorMinimo := TRUE;
    
      --********** VALOR MÍNIMO DO PLANO DE PAGAMENTO **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'B';
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsValorMinPlPag := '2207';
      
      --********** QTDE. MIN. ITENS DO PLANO DE PAGAMENTO **********--
      -- Abortar Continuação do Processo
      vrAcaoSobreCritica.vvAcaoNumItensMinPlPag := 'A';
      
      --********** VALOR MÍNIMO VENDA BK **********--
      -- Abortar Continuação do Processo
      IF (NVL(vrParametros.vACEITAVENDABLOQ,'N') = 'N') THEN
        vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'A';
      ELSE
        vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'B';
      END IF;
  
      --********** VALOR MÍNIMO VENDA BNF **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'B';
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'A';
      END IF;
  
      --********** VALOR MÍNIMO DO RCA **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoValorMinRca := 'B';
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoValorMinRca := 'A';
      END IF;        
  
      --********** VALOR MÍNIMO DO PEDIDO **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'B';
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'A';
      END IF;  
      vrAcaoSobreCritica.vvParamsValorMinimoPedVenda := '1458,2325,2833';
      
      --*** BLOQUEAR PEDIDOS BONIFICADOS ***--
      -- Se Bonificação estiver Parametrizado para Gravar Sempre como Bloqueado
      IF    (NVL(vrParametros.vBLOQUEARPEDBONIFIC,'N') = 'S') AND
            (NVL(vrPedido.vnCondVenda,0) IN (5,6,11))         THEN
        -- Perguntar se Bloqueia
        vrAcaoSobreCritica.vvAcaoPedidoBonific := 'B';
      END IF;
      
      --*** BLOQUEAR PEDIDOS na 2316 ***--
      -- (Não tem na Integradora)
                             
      --********** VALOR MINIMO OPERADOR LOGISTICO **********--
      -- Abortar Continuação do Processo
      vrAcaoSobreCritica.vvAcaoVlMinOperadorLogistico := 'A';
      
      --********** SALDO CONTA-CORRENTE RCA **********--    
      IF (NVL(pi_vMovimentarSaldoRca,'N') = 'S') THEN
        IF    (NVL(vrParametros.vACEITAVENDARCASEMSALDOFV,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo := 'B';
        ELSE
          --> Se vACEITAVENDARCASEMSALDOFV = Não, SEMPRE corta na integradora os itens que negativam o saldo.
          --> Na Integradora, neste caso, fará o corte automaticamente em bloco à parte, validando item a item.
          --> Por isso sou forçado a colocar a Ação I para não entrar na regra da validação geral do pedido,
          --> gravando o pedido como liberado, sem os itens que negativam o conta-corrente
          vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo := 'I'; 
        END IF;    
      END IF;
  
      --********** TER ESTOQUE TOTAL **********--    
      IF (vrParametros.vACEITAVENDASEMEST = 'RP') THEN
        vrAcaoSobreCritica.vvAcaoTerEstoqueTotal := 'A';
      ELSE
        vrAcaoSobreCritica.vvAcaoTerEstoqueTotal := NULL;
      END IF;
                                      
      --********** VALOR MÍNIMO DA COBRANÇA **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vACEITAVENDABLOQ,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoValorMinCob := 'B';
      -- Abortar Continuação do Processo
      ELSE
        vrAcaoSobreCritica.vvAcaoValorMinCob := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsValorMinCob := '1429';
  
      --********** RCA BLOQUEADO **********
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vACEITAVENDABLOQ,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoRcaBloqueado := 'B';
      -- Abortar Continuação do Processo
      ELSE
        vrAcaoSobreCritica.vvAcaoRcaBloqueado := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsRcaBloqueado := '1429';
  
      --********** CLIENTE BLOQUEADO **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      -- Exceção: if (nvl(p_regpedido.tipocriticaclientebloqmed,'BP') = 'RP') THEN
      IF (NVL(vrParametros.vACEITAVENDABLOQ,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoClienteBloqueado := 'B';
      -- Abortar Continuação do Processo
      ELSE
        vrAcaoSobreCritica.vvAcaoClienteBloqueado := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsClienteBloqueado := '1429';
  
      --********** CLIENTE SEM CREDITO **********--
      -- Perguntar se Bloqueia (Na Integradora não tem pergunta, logo Bloqueia)
      IF (NVL(vrParametros.vBLOQPEDLIMCRED,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoClienteSemCredito := 'B';
      -- Abortar Continuação do Processo
      ELSE
        vrAcaoSobreCritica.vvAcaoClienteSemCredito := 'A';
      END IF;

      --********** VALOR MÁXIMO VENDA **********--
      -- Perguntar se Bloqueia
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        IF (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoVlMaxVenda := 'A';
        ELSE
          vrAcaoSobreCritica.vvAcaoVlMaxVenda := 'B';
        END IF;
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoVlMaxVenda := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsVlMaxVenda := '1309';

      --********** VALOR MÁXIMO VENDA PF **********--
      -- Perguntar se Bloqueia
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        IF (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoVlMaxVendaPF := 'A';
        ELSE
          vrAcaoSobreCritica.vvAcaoVlMaxVendaPF := 'B';
        END IF;
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoVlMaxVendaPF := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsVlMaxVendaPF := '1337';

      --********** VALOR MÁXIMO VENDA BNF **********--
      -- Perguntar se Bloqueia
      IF (NVL(vrParametros.vBLOQUEARPEDIDOSABAIXOVLMINIMO,'N') = 'S') THEN
        IF (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
          vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF := 'A';
        ELSE
          vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF := 'B';
        END IF;
      -- Abortar Continuação do Processo
      ELSE       
        vrAcaoSobreCritica.vvAcaoVlMaxVendaBNF := 'A';
      END IF;
      vrAcaoSobreCritica.vvParamsVlMaxVendaBNF := '2198';

      --********** PREÇO ABAIXO DO MÍMIMO **********--
      -- Perguntar se Bloqueia
      IF (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
        vrAcaoSobreCritica.vvAcaoPrecoMinimo := 'B'; -- DDMEDICA-3502
      ELSE
        vrAcaoSobreCritica.vvAcaoPrecoMinimo := 'B';
      END IF;
      vrAcaoSobreCritica.vvParamsPrecoMinimo := '2551';

      --********** PRAZO MÉDIO DO PEDIDO **********--
      -- Ignora se Integradora Parametrizada - DDMEDICA-3017
      IF (NVL(vrParametros.vIGNORARPRAZOMEDIOCLIENTE,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoPrazoMedio := 'I';
      ELSE
        -- DDMEDICA-3502 - Correção da Regra
        IF (NVL(vrParametros.vBLOQPRAZOMDVENDA,'N') = 'S') THEN -- Não aceita planos de pagamento com prazo médio superior ao prazo médio do plano de pagamento do cliente.
          vrAcaoSobreCritica.vvAcaoPrazoMedio := 'A';
        ELSE
          IF (NVL(vrParametros.vACEITAVENDABLOQ,'N') = 'S') THEN
            vrAcaoSobreCritica.vvAcaoPrazoMedio := 'B';
          ELSE
            vrAcaoSobreCritica.vvAcaoPrazoMedio := 'A';
          END IF;
        END IF;
        vrAcaoSobreCritica.vvParamsPrazoMedio := '1456,1429';
      END IF;

      --********** MARGEM MÍNIMA DO PLANO DE PAGAMENTO **********--
      -- Perguntar se Bloqueia
      IF    (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
        vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
      ELSIF (vrPedido.vvOrigemPed = 'F') AND
            (NVL(vrPedido.vvTipoFv,'FV') IN ('OL','PE')) THEN
        IF (NVL(vrParametros.vVALIDARMARGEMMINIMA,'N') <> 'S') THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'I';
        ELSIF (NVL(vrParametros.vBLOQPEDABAIXOMARGEMFV,'N') = 'S') THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'B';
        ELSE
          vrAcaoSobreCritica.vvAcaoMargemMinima := 'A';
        END IF;
      ELSIF (vrPedido.vvOrigemPed = 'F') AND
            (NVL(vrPedido.vvTipoFv,'FV') NOT IN ('OL','PE')) AND
            (NVL(vrParametros.vBLOQPEDABAIXOMARGEMFV,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoMargemMinima := 'B';
      ELSE
        vrAcaoSobreCritica.vvAcaoMargemMinima := 'A';
      END IF;
      vrAcaoSobreCritica.vnPermissMargemMinima := NULL;
      vrAcaoSobreCritica.vvParamsMargemMinima  := '2899';

      --********** MARGEM MÍNIMA **********--
      -- Perguntar se Bloqueia
      IF (NVL(vrPedido.vvOrigemPed,' ') IN ('B','R')) THEN
        vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
      ELSIF (vrPedido.vvOrigemPed = 'F') AND
            (NVL(vrPedido.vvTipoFv,'FV') IN ('OL','PE')) AND
            (NVL(vrParametros.vVALIDARMARGEMMINIMA,'N') <> 'S') THEN -- DDMEDICA-4072
        vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'I';
      ELSE
        IF (NVL(vrParametros.vTIPOVALIDMARGEMMINVENDAMED,'0') IN ('2')) THEN
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'B';
        ELSE
          vrAcaoSobreCritica.vvAcaoMargemMinima132 := 'A';
        END IF;
      END IF;
      vrAcaoSobreCritica.vnPermissMargemMinima132 := NULL;
      vrAcaoSobreCritica.vvParamsMargemMinima132  := '9894,9897';

      --********** ALVARA **********--
      -- Perguntar se Bloqueia
      vrAcaoSobreCritica.vvAcaoAlvara    := 'B';
      vrAcaoSobreCritica.vnPermissAlvara := NULL;
      IF (NVL(vrParametros.vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') THEN
        vrAcaoSobreCritica.vvParamsAlvara    := '9818';
        vrAcaoSobreCritica.vnCodRotinaAlvara := 3331;
      ELSE
        vrAcaoSobreCritica.vvParamsAlvara    := '9818,2521,2516';
        vrAcaoSobreCritica.vnCodRotinaAlvara := 302;
      END IF;

      --********** BLOQUEIO AUTOMATICO DA INTEGRADORA **********--        
      -- Bloqueia
      IF (NVL(vrIntegradora.vvGeraPedBloq,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoGerarPedBloq := 'B';
      ELSE 
        vrAcaoSobreCritica.vvAcaoGerarPedBloq := NULL;
      END IF;

      --********** VALOR MÍNIMO DA RESTRIÇÃO DE VENDA **********--
      -- Abortar Continuação do Processo
      vrAcaoSobreCritica.vvAcaoValorMinRestr := 'A';

      --********** BLOQUEIOS COMERCIAIS **********--
      -- Bloquear
      vrAcaoSobreCritica.vvAcaoBloqueioComercial    := 'B';
      vrAcaoSobreCritica.vvPermissBloqueioComercial := NULL;

      --********** ITEM BNF **********--
      -- Abortar Continuação do Processo
      vrAcaoSobreCritica.vvAcaoItemBnfTV1 := 'A';

      --********** FATURAMENTO INTEGRAL **********--
      -- Abortar Continuação do Processo
      vrAcaoSobreCritica.vvAcaoFaturamentoIntegral := 'A';

      --********** CANAL AUTORIZADOR PBM CA PBM **********--
      -- Bloqueia
      vrAcaoSobreCritica.vvAcaoCanalAutorizadorPbm := 'B';

    --------------------------------------------------------------------------------------------------
    -- CHAMANDO DA 2312 ------------------------------------------------------------------------------
    --------------------------------------------------------------------------------------------------
    ELSIF (pi_nCodRotina = 2312) THEN
  
      -- NÃO Validará Valor Mínimo - MED-1964
      vbValidarValorMinimo := FALSE;
    
      --********** VALOR MÍNIMO DO PLANO DE PAGAMENTO **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinPlPag := 'I';
    
      --********** QTDE. MIN. ITENS DO PLANO DE PAGAMENTO **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoNumItensMinPlPag := 'I';
  
      --********** VALOR MÍNIMO VENDA BK **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinimoVendaBk := 'I';
    
      --********** VALOR MÍNIMO VENDA BNF **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinVendaBnf := 'I';
  
      --********** VALOR MÍNIMO DO RCA **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinRca := 'I';
    
      --********** VALOR MÍNIMO DO PEDIDO **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinimoPedVenda := 'I';
  
      --*** BLOQUEAR PEDIDOS BONIFICADOS ***--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoPedidoBonific := 'I';
      
      --*** BLOQUEAR PEDIDOS na 2316 ***--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoGravarPedBloq := 'I';
  
      --*** BLOQUEAR PEDIDOS na 2316 ***--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorDescNeg := 'I';
          
      --********** VALOR MINIMO OPERADOR LOGISTICO **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoVlMinOperadorLogistico := 'I';
  
      --*** VALOR MINIMO APROVADO PARA APLICACAO DO DESCONTO NEGOCIADO ***--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinDescNeg := 'I';
  
      --********** SALDO CONTA-CORRENTE RCA **********--    
      IF (NVL(pi_vMovimentarSaldoRca,'N') = 'S') THEN
        vrAcaoSobreCritica.vvAcaoVendaRcaSemSaldo := 'I';
      END IF;
  
      --********** TER ESTOQUE TOTAL **********--    
      vrAcaoSobreCritica.vvAcaoTerEstoqueTotal := NULL;
  
      --********** VALOR MÍNIMO DA COBRANÇA **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoValorMinCob := 'I';
  
      --********** RCA BLOQUEADO **********
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoRcaBloqueado := 'I';
  
      --********** CLIENTE BLOQUEADO **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoClienteBloqueado := 'I';
   
      --********** CLIENTE SEM CREDITO **********--
      -- Ignorar Ação
      vrAcaoSobreCritica.vvAcaoClienteSemCredito := 'I';
   
