                               'vGeraPedBloq = '                   || vrIntegradora.vvGeraPedBloq                      || CHR(13) ||
                               'vUSAREGRANORMALIZADESC = '         || vrRegrasEspecificas.vUSAREGRANORMALIZADESC       || CHR(13) ||
                               'vREVALIDAPROMOCAOGRAVACAOPED = '   || vrRegrasEspecificas.vREVALIDAPROMOCAOGRAVACAOPED || CHR(13) ||
                               'vUSAREGRAPERMISSAO = '             || vrParametros.vUSAREGRAPERMISSAO                  || CHR(13) ||
                               'vMEDPERMITEDISTRIBDIFRCA = '       || vrParametros.vMEDPERMITEDISTRIBDIFRCA            || CHR(13) ||
                               'vUSALIMCREDSANZONALPEDIDO = '      || vrRegrasEspecificas.vUSALIMCREDSANZONALPEDIDO    || CHR(13) ||
                               'vUSAPARAMLIMITEITEMBNFTV1 = '      || vrRegrasEspecificas.vUSAPARAMLIMITEITEMBNFTV1    || CHR(13) ||
                               'nPERCLIMITEVLTV5 = '               || vrParametros.nPERCLIMITEVLTV5                    || CHR(13) ||
                               'vVALIDALVARAFUNCLIBERADOS = '      || vrParametros.vVALIDALVARAFUNCLIBERADOS           || CHR(13) ||
                               'vREJEITAPEDRCASEMSALDOFV = '       || vrParametros.vREJEITAPEDRCASEMSALDOFV            || CHR(13) ||
                               'vIGNORARVALIDACAOALVARASUS = '     || vrParametros.vIGNORARVALIDACAOALVARASUS          || CHR(13) ||
                               'vIGNORARVALIDACAOALVARACRF = '     || vrParametros.vIGNORARVALIDACAOALVARACRF          || CHR(13) ||
                               'vACEITARPEDALVARAVENCINTEGRAD = '  || vrParametros.vACEITARPEDALVARAVENCINTEGRAD       || CHR(13) ||
                               'vHABILITCANALAUTORIZPBMTELEV = '   || vrParametros.vHABILITCANALAUTORIZPBMTELEV                      -- CA PMB
                               );
                               
    IF (F_IGNORARACESSOCONTROLE2336(pi_nCodRotina)) THEN                               
      P_INSERE_LOG_PROCESSAMENTO('IGNORARACESSOCONTROLE2336 = S');
    END IF;
  
   /*************************************************************************************************
                                                F I M   
                            DEFINIÇÃO DA AÇÃO AO NÃO ATINGIR VALORES MÍNIMOS
    **************************************************************************************************/ 
  
  
  
  
    ---------------------------------------------------------
    --- DEFINE SE OS DADOS SERÃO LIBERADOS A CADA PROCESSO --
    ---------------------------------------------------------
    IF    (NVL(pi_nCodRotina,0) = 2513) THEN
    
      -- INTEGRADORA_MED -> Não tem Controle de Processo (NEM FARÁ COMMIT)
      vbCommitPorProcesso := FALSE;
    
    ELSIF (NVL(pi_nCodRotina,0) = 2312) THEN
  
      -- Não tem Controle de Processo (Faz tudo ou nada)
      vbCommitPorProcesso := FALSE;
  
    ELSIF (NVL(pi_nCodRotina,0) = 2641) THEN
  
      -- Não tem Controle de Processo (Faz tudo ou nada)
      vbCommitPorProcesso := FALSE;
    
    ELSIF (pi_vChamadaProcesso = 'GP') THEN
  
      vbCommitPorProcesso := TRUE;
            
    ELSE
    
      -- Não tem Controle de Processo (Faz tudo ou nada)
      vbCommitPorProcesso := FALSE;
      
    END IF;
  
  
    -- Limpa Tabela Temporária de Críticas
    DELETE FROM PCMED_VALIDACAO_ESTOQUE_RESERV; 
    -- Limpa Tabela Temporária de Itens Faltantes
    DELETE FROM PCMED_FALTAS_ESTOQUE_RESERV;
    -- Limpar Tabela de Validação Críticas de Saldo do Item
    DELETE FROM PCMED_VALIDACAO_SALDO_ITEM;
  
  
  
  
   /*************************************************************************************************
                                             I N I C I O
                                 CARGA DOS DADOS PARA PROCESSAMENTO
    **************************************************************************************************/             
  
  
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------
    --                        PREPARA WHERE DA PESQUISA DA PCPEDI E DA PCEST                       --
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------  
    
    -- Inicializa Flag que identifica que Filtrou os Itens do Pedido
    vbFiltrouItensPed := FALSE;
  
    -- Se Cancelamento de Itens (Somente implementado na 2336)
    IF (NVL(pi_vChamadaProcesso,' ') IN ('CI','CC')) THEN
     
     /* 
      *
      * DDMEDICA-4566 - Verificado que ao cancelar um produto na 2336 preciso processar todos os itens,
      *                 porque se mudar a posição do pedido não faz o estorno correto do saldo reservado para pendente.
      *                 Pelo conceito da própria rotina, os itens que não tiverem mudança de quantidade, preço e posição permanecerão ser alteração 
      *                 (A Proc. compara os valores anteriores em outra sessão Prgama com os atuais)
      *     
      -- Somente Processa Itens do Pedido marcados como Cancelados
      vvWhereConformeProcesso := ' AND (PCPEDI.POSICAO = ''C'') ';
      -- Atualiza Flag que identifica que Filtrou os Itens do Pedido
      vbFiltrouItensPed       := TRUE;
      */
      NULL;
      
    -- Se NÃO FOR Cancelamento de Itens
       
    END IF;
    
    -- Se Edição do Produto na 2336 (Inclusão/Alteração) - Somente processa o Produto do Pedido passado no Parâmetro 
    -- (Limitar Lock e Processamento somente ao Produto passado no Parâmetro)
   /* 
    *
    * DDMEDICA-3658 - Verificado que ao incluir um produto na 2336 preciso processar todos os itens,
    *                 porque se mudar a posição do pedido não faz o estorno correto do saldo reservado para pendente.
    *                 Pelo conceito da própria rotina, os itens que não tiverem mudança de quantidade, preço e posição permanecerão ser alteração 
    *                 (A Proc. compara os valores anteriores em outra sessão Prgama com os atuais)
    *
    IF (pi_vChamadaProcesso = 'EP') AND 
       (pi_nCodRotina = 2336)       THEN
       
      -- Somente Processa o Produto passado como Parâmetro
      vvWhereConformeProcesso := vvWhereConformeProcesso || 
                                ' AND (PCPEDI.CODPROD = ' || pi_nCodProdEdicao || ')';
      -- Atualiza Flag que identifica que Filtrou os Itens do Pedido
      vbFiltrouItensPed       := TRUE;
                                
    END IF;
    */
  
  
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------
    --                                       BLOQUEIA PEDIDO                                       --
    --                        CARREGA ARRAYS COM OS DADOS DOS ITENS DO PEDIDO                      --
    --                                          (Sempre)                                           --
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------  
  
    -- Controle Processo: Bloqueio Itens Pedido
    vvControleProcesso := 'BloqueioItens';
  
    -- CARGA DO ARRAY SOMENTE COM OS ITENS PARA PROCESSAMENTO ---------------------------------------
  
    -- Limpa Arrays de Processamento do Pedido
    vtPED_NUMPED.DELETE;
    vtPED_CODPROD.DELETE;
    vtPED_QT.DELETE;
    vtPED_PVENDA.DELETE;
    vtPED_PTABELA.DELETE;
    vtPED_PBASERCA.DELETE;
    vtPED_NUMSEQ.DELETE;
    vtPED_ITEMCANCELADO.DELETE;
    vtPED_BONIFIC.DELETE;
    vtPED_MOTIVOCANCELAMENTOMED.DELETE;
    vtPED_ST.DELETE;
    vtPED_STPBASERCA.DELETE; 
    vtPED_VLSALDORCA.DELETE; 
    vtPED_CODPROMOCAOMED.DELETE;
    -- Limpa Arrays de Validação do Valor Mínimo
    vtPEDVLMIN_NUMPED.DELETE;
    vtPEDVLMIN_CODPROD.DELETE;
    vtPEDVLMIN_CODFILIALRETIRA.DELETE;
    vtPEDVLMIN_QT.DELETE;
    vtPEDVLMIN_PVENDA.DELETE;
    vtPEDVLMIN_PVENDALIQUIDO.DELETE;
    vtPEDVLMIN_NUMSEQ.DELETE;
    vtPEDVLMIN_GRUPOFATURAMENTO.DELETE;
    vtPEDVLMIN_CODPLPAG.DELETE;
    vtPEDVLMIN_ITEMCANCELADO.DELETE;
    vtPEDVLMIN_CODPROMOCAOMED.DELETE;
    vtPEDVLMIN_ST.DELETE;
    vtPEDVLMIN_PBASERCA.DELETE;
    vtPEDVLMIN_STPBASERCA.DELETE;
    vtPEDVLMIN_BONIFIC.DELETE;
    vtPEDVLMIN_CODMOTIVOPOSICAOMED.DELETE;
    vtPEDVLMIN_MOTIVOPOSICAOMED.DELETE;
    vtPEDVLMIN_VLCUSTOFIN.DELETE;
         
    -- Prepara Sql
    vvSql := ' SELECT PCPEDI.NUMPED
                    , PCPEDI.CODPROD
                    , PCPEDI.CODFILIALRETIRA
                    , PCPEDI.QT
                    , PCPEDI.PVENDA
                    , PCPEDI.PTABELA
                    , PCPEDI.PBASERCA
                    , PCPEDI.NUMSEQ
                    , DECODE(PCPEDI.POSICAO,''C'',''S'',''N'')
                    , NVL(PCPEDI.BONIFIC,''N'')   
                    , PCPEDI.MOTIVOCANCELAMENTOMED     
                    , PCPEDI.ST
                    , PCPEDI.STPBASERCA         
                    , PCPEDI.VLSALDORCA
                    , PCPEDI.CODPROMOCAOMED
                    , PCPEDI.NUMPED                                                                       NUMPED_VLMIN
                    , PCPEDI.CODPROD                                                                      CODPROD_VLMIN
                    , PCPEDI.CODFILIALRETIRA                                                              CODFILIALRETIRA_VLMIN
                    , PCPEDI.QT                                                                           QT_VLMIN
                    , PCPEDI.PVENDA                                                                       PVENDA_VLMIN
                    , (PCPEDI.PVENDA - (NVL(ST,0) + NVL(VLOUTROS,0) + NVL(VLREPASSE,0) + NVL(VLOUTRASDESP,0) + NVL(VLIPI,0) + NVL(VLISS,0))) PVENDA_VLMIN_LIQ
                    , PCPEDI.NUMSEQ                                                                       NUMSEQ_VLMIN
                    , PCPEDI.GRUPOFATURAMENTO                                                             GRUPOFATURAMENTO_VLMIN
                    , PCPEDI.CODPLPAG                                                                     CODPLPAG_VLMIN
                    , DECODE(PCPEDI.POSICAO,''C'',''S'',''N'')                                            ITEMCANCELADO_VLMIN
                    , PCPEDI.CODPROMOCAOMED                                                               CODPROMOCAOMED_VLMIN 
                    , PCPEDI.ST                                                                           ST_VLMIN
                    , PCPEDI.PBASERCA                                                                     PBASERCA_VLMIN
                    , PCPEDI.STPBASERCA                                                                   STPBASERCA_VLMIN
                    , NVL(PCPEDI.BONIFIC,''N'')                                                           BONIFIC_VLMIN
                    , PCPEDI.CODMOTIVOPOSICAOMED                                                          CODMOTIVOPOSICAOMED
                    , PCPEDI.MOTIVOPOSICAOMED                                                             MOTIVOPOSICAOMED
                    , PCPEDI.VLCUSTOFIN                                                                   VLCUSTOFIN
                 FROM PCPEDI
                WHERE (NUMPED = ' || pi_nNumPed || ') ' || vvWhereConformeProcesso ||
              ' ORDER BY NUMSEQ ';
  
    -- Insere Dados em Arrays
    EXECUTE IMMEDIATE vvSql
       BULK COLLECT INTO vtPED_NUMPED
                       , vtPED_CODPROD
                       , vtPED_CODFILIALRETIRA
                       , vtPED_QT        
                       , vtPED_PVENDA
                       , vtPED_PTABELA
                       , vtPED_PBASERCA
                       , vtPED_NUMSEQ
                       , vtPED_ITEMCANCELADO
                       , vtPED_BONIFIC
                       , vtPED_MOTIVOCANCELAMENTOMED
                       , vtPED_ST
                       , vtPED_STPBASERCA
                       , vtPED_VLSALDORCA
                       , vtPED_CODPROMOCAOMED
                       , vtPEDVLMIN_NUMPED
                       , vtPEDVLMIN_CODPROD
                       , vtPEDVLMIN_CODFILIALRETIRA
                       , vtPEDVLMIN_QT
                       , vtPEDVLMIN_PVENDA
                       , vtPEDVLMIN_PVENDALIQUIDO
                       , vtPEDVLMIN_NUMSEQ
                       , vtPEDVLMIN_GRUPOFATURAMENTO
                       , vtPEDVLMIN_CODPLPAG
                       , vtPEDVLMIN_ITEMCANCELADO
                       , vtPEDVLMIN_CODPROMOCAOMED
                       , vtPEDVLMIN_ST
                       , vtPEDVLMIN_PBASERCA
                       , vtPEDVLMIN_STPBASERCA
                       , vtPEDVLMIN_BONIFIC
                       , vtPEDVLMIN_CODMOTIVOPOSICAOMED
                       , vtPEDVLMIN_MOTIVOPOSICAOMED
                       , vtPEDVLMIN_VLCUSTOFIN;
               
    -- Se não Achou os Itens do Pedido
    IF (NVL(vtPED_NUMPED.COUNT,0) = 0) THEN
      RAISE e_AbortaBloqueioItens;
    END IF;
  
    -- Fim do Controle Processo: Bloqueio Itens Pedido
    vvControleProcesso := NULL;
  
    -- SE FILTROU A PCPEDI POR ITENS CANCELADOS E/OU PRODUTO ESPECÍFICO NO SELECT ANTERIOR, 
    -- PRECISO RE-CONSULTAR O PEDIDO INTEIRO PARA PODER VALIDAR O VALOR MÍNIMO COM TODOS OS ITENS DO PEDIDO
    IF (vbFiltrouItensPed) THEN
      
      -- Limpa Arrays
      vtPEDVLMIN_NUMPED.DELETE;
      vtPEDVLMIN_CODPROD.DELETE;
      vtPEDVLMIN_CODFILIALRETIRA.DELETE;
      vtPEDVLMIN_QT.DELETE;
      vtPEDVLMIN_PVENDA.DELETE;
      vtPEDVLMIN_PVENDALIQUIDO.DELETE;
      vtPEDVLMIN_NUMSEQ.DELETE;
      vtPEDVLMIN_GRUPOFATURAMENTO.DELETE;
      vtPEDVLMIN_CODPLPAG.DELETE;
      vtPEDVLMIN_ITEMCANCELADO.DELETE;
      vtPEDVLMIN_CODPROMOCAOMED.DELETE;
      vtPEDVLMIN_ST.DELETE;
      vtPEDVLMIN_PBASERCA.DELETE;
      vtPEDVLMIN_STPBASERCA.DELETE;
      vtPEDVLMIN_CODMOTIVOPOSICAOMED.DELETE;
      vtPEDVLMIN_MOTIVOPOSICAOMED.DELETE;
      vtPEDVLMIN_VLCUSTOFIN.DELETE;

      -- Prepara Sql
      vvSql := ' SELECT PCPEDI.NUMPED
                      , PCPEDI.CODPROD
                      , PCPEDI.CODFILIALRETIRA
                      , PCPEDI.QT
                      , PCPEDI.PVENDA
                      , (PCPEDI.PVENDA - (NVL(ST,0) + NVL(VLOUTROS,0) + NVL(VLREPASSE,0) + NVL(VLOUTRASDESP,0) + NVL(VLIPI,0) + NVL(VLISS,0))) PVENDA_VLMIN_LIQ
                      , PCPEDI.NUMSEQ
                      , PCPEDI.GRUPOFATURAMENTO
                      , PCPEDI.CODPLPAG
                      , DECODE(PCPEDI.POSICAO,''C'',''S'',''N'')
                      , PCPEDI.CODPROMOCAOMED
                      , PCPEDI.ST
                      , PCPEDI.PBASERCA
                      , PCPEDI.STPBASERCA
                      , NVL(PCPEDI.BONIFIC,''N'')
                      , PCPEDI.CODMOTIVOPOSICAOMED
                      , PCPEDI.MOTIVOPOSICAOMED
                      , PCPEDI.VLCUSTOFIN
                   FROM PCPEDI
                  WHERE (NUMPED = ' || pi_nNumPed || ') ' ||
                ' ORDER BY NUMSEQ ';
    
      -- Insere Dados em Arrays
      EXECUTE IMMEDIATE vvSql
         BULK COLLECT INTO vtPEDVLMIN_NUMPED
                         , vtPEDVLMIN_CODPROD
                         , vtPEDVLMIN_CODFILIALRETIRA
                         , vtPEDVLMIN_QT        
                         , vtPEDVLMIN_PVENDA
                         , vtPEDVLMIN_PVENDALIQUIDO
                         , vtPEDVLMIN_NUMSEQ
                         , vtPEDVLMIN_GRUPOFATURAMENTO
                         , vtPEDVLMIN_CODPLPAG
                         , vtPEDVLMIN_ITEMCANCELADO
                         , vtPEDVLMIN_CODPROMOCAOMED
                         , vtPEDVLMIN_ST
                         , vtPEDVLMIN_PBASERCA
                         , vtPEDVLMIN_STPBASERCA
                         , vtPEDVLMIN_BONIFIC
                         , vtPEDVLMIN_CODMOTIVOPOSICAOMED
                         , vtPEDVLMIN_MOTIVOPOSICAOMED
                         , vtPEDVLMIN_VLCUSTOFIN;
                 
      -- Se não Achou os Itens do Pedido
      IF (NVL(vtPEDVLMIN_NUMPED.COUNT,0) = 0) THEN
        RAISE e_AbortaItensVlMin;
      END IF;
      
    END IF; -- FIM CONDIÇÃO: SE FILTROU A PCPEDI NO SELECT ANTERIOR
    
    ---------------------------------------------------------------------------
    -- MED-1964 - SE NÃO PRECISAR VALIDAR VALOR MÍNIMO (Implementado pela 2312)
    ---------------------------------------------------------------------------
    IF (NOT vbValidarValorMinimo) THEN
    
      -- Limpa Arrays
      vtPEDVLMIN_NUMPED.DELETE;
      vtPEDVLMIN_CODPROD.DELETE;
      vtPEDVLMIN_CODFILIALRETIRA.DELETE;
      vtPEDVLMIN_QT.DELETE;
      vtPEDVLMIN_PVENDA.DELETE;
      vtPEDVLMIN_PVENDALIQUIDO.DELETE;
      vtPEDVLMIN_NUMSEQ.DELETE;
      vtPEDVLMIN_GRUPOFATURAMENTO.DELETE;
      vtPEDVLMIN_CODPLPAG.DELETE;
      vtPEDVLMIN_ITEMCANCELADO.DELETE;
      vtPEDVLMIN_CODPROMOCAOMED.DELETE;
      vtPEDVLMIN_ST.DELETE;
      vtPEDVLMIN_PBASERCA.DELETE;
      vtPEDVLMIN_STPBASERCA.DELETE;
      vtPEDVLMIN_CODMOTIVOPOSICAOMED.DELETE;
      vtPEDVLMIN_MOTIVOPOSICAOMED.DELETE;
      vtPEDVLMIN_VLCUSTOFIN.DELETE;
    
    END IF;
    
            
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------
    --                                       CARREGA ESTOQUE                                       --
    -------------------------------------------------------------------------------------------------
    ------------------------------------------------------------------------------------------------- 
    
    -- CARGA DO ARRAY PARA VALIDAÇÃO DO VALOR MÍNIMO ----------------------------------------------
  
    -- Limpa Arrays de Validação do Valor Mínimo
    vtEST_ROWNUM.DELETE;
    vtEST_CODPROD.DELETE;
    vtEST_CODFILIAL.DELETE;
    vtEST_QTRESERV_PEDIDO.DELETE;
    vtEST_QTDISPONIVEL.DELETE;
    
    -- Nome da Função a ser chamada
    IF    (NVL(vrPedido.vvPedidoAvaria,'N') = 'S')     THEN -- DDMEDICA-619
      vvNomeFCT_MED_OBTER_ESTOQUE := 'PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_AVARIA(CODPROD,CODFILIAL) QTDISPONIVEL';
    ELSIF (NVL(vrPedido.vnNumTransEntCrossDock,0) > 0) THEN -- DDMEDICA-619
      vvNomeFCT_MED_OBTER_ESTOQUE := 'PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_BLOQ(CODPROD,CODFILIAL) QTDISPONIVEL';
    ELSIF (NVL(pi_nCodRotina,0) = 2336)                THEN
      --DDMEDICA-1008
      IF (NVL(vrParametros.vVALIDARQTCONTGRAVACAOPED,'N') = 'S') OR (NVL(vrParametros.vCON_VERIFICAESTOQUECONT,'N') = 'S') THEN
        vvNomeFCT_MED_OBTER_ESTOQUE := 'LEAST(PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISPPEND(CODPROD,CODFILIAL,'||NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)||'),PKG_FUNCOESVENDAS_MED.F_OBTER_EST_CONTAB_DISP(CODPROD, CODFILIAL,''S'')) QTDISPONIVEL';
    ELSE
        vvNomeFCT_MED_OBTER_ESTOQUE := 'PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISPPEND(CODPROD,CODFILIAL,'||NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)||') QTDISPONIVEL';
      END IF;
    ELSIF (NVL(pi_nCodRotina,0) = 2641)                THEN
      -- DDMEDICA-1147
      vvNomeFCT_MED_OBTER_ESTOQUE := 'PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISPPEND(CODPROD,CODFILIAL) QTDISPONIVEL';
    ELSE
      --DDMEDICA-1008
      IF (NVL(vrParametros.vVALIDARQTCONTGRAVACAOPED,'N') = 'S') OR (NVL(vrParametros.vCON_VERIFICAESTOQUECONT,'N') = 'S') THEN
        vvNomeFCT_MED_OBTER_ESTOQUE := 'LEAST(PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISP(CODPROD,CODFILIAL,'||NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)||'),PKG_FUNCOESVENDAS_MED.F_OBTER_EST_CONTAB_DISP(CODPROD, CODFILIAL)) QTDISPONIVEL';
      ELSE
        vvNomeFCT_MED_OBTER_ESTOQUE := 'PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISP(CODPROD,CODFILIAL,'||NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)||') QTDISPONIVEL';
      END IF;
    END IF;
    
    -- Prepara Sql (SEM LOCK) (TODOS OS ITENS DO PEDIDO)
    vvSql := ' SELECT ROWNUM
                    , CODPROD
                    , CODFILIAL
                    , 0 QTRESERV_PEDIDO ';
                    
    --DDMEDICA-1008
    vvSql := vvSql  || ', ' || vvNomeFCT_MED_OBTER_ESTOQUE;
    
      vvSql := vvSql  || '
                 FROM PCEST
                WHERE ((PCEST.CODPROD, PCEST.CODFILIAL) IN (SELECT PCPEDI.CODPROD
                                                                 , NVL(PCPEDI.CODFILIALRETIRA, ' || '''' || vrPedido.vvCodFilial || '''' || ') 
                                                              FROM PCPEDI
                                                             WHERE (PCPEDI.NUMPED = ' || pi_nNumPed || '))) ';
  
    -- Insere Dados em Arrays
    EXECUTE IMMEDIATE vvSql
         BULK COLLECT INTO vtEST_ROWNUM
                         , vtEST_CODPROD
                         , vtEST_CODFILIAL
                         , vtEST_QTRESERV_PEDIDO
                         , vtEST_QTDISPONIVEL;
    
    -- Se não Achou os Itens no Estoque
    IF (NVL(vtEST_CODPROD.COUNT,0) = 0) THEN
      RAISE e_AbortaItensEstoqueVlMin;
    END IF;          
        
   /*************************************************************************************************
                                 CARGA DOS DADOS PARA PROCESSAMENTO
                                               F I M           
    **************************************************************************************************/ 
  
  
  
      
    --------------------------------------------------------------------------------------------------
    --------------------------------------------------------------------------------------------------
    -- Canal Autorizador PBM - CA PBM
    --------------------------------------------------------------------------------------------------
    --------------------------------------------------------------------------------------------------
    IF (vrPedido.vvOrigemPed = 'T') AND
       (NVL(vrPedido.vnCodPromocaoMed,0) > 0) AND
       (NVL(vrParametros.vHABILITCANALAUTORIZPBMTELEV,'N') = 'S') THEN
       
      -- Se existir alguma Integradora com Canal Autorizador enviando o Pedido 
      IF (F_EXISTE_INTEGRADORA_CA_PBM = 'S') THEN
       
        -- Limpa Itens do Pedido de Operador Logístico 
        -- (Dependerá da Situação da Integração)
        P_LIMPAR_ITENS_PEDIDO_CA_PBM(pi_nNumPed); 
        
      END IF;
      
    END IF;
  

  
  
   /*************************************************************************************************
                                              I N I C I O
                         PREVISÃO DE ATENDIMENTO PARA CRÍTICA DE VALOR MÍNIMO
    **************************************************************************************************/ 
  
    -- ITENS DO PEDIDO PARA VALIDAÇÃO DO VALOR MÍNIMO ------------------------------------------------  
    IF (vtPEDVLMIN_NUMPED.COUNT > 0) THEN
  
  
      -- Limpa Tabela Temporária de Críticas
      DELETE FROM PCMED_VALIDACAO_ESTOQUE_RESERV; 
      -- Limpar Tabela de Validação Críticas de Saldo do Item
      DELETE FROM PCMED_VALIDACAO_SALDO_ITEM;
                
      ------------------------------------------------------------------------------------------------
      -- LAÇO DE ITENS PARA ESTORNO PROVISÓRIO DA QTDE CANCELADA
      ------------------------------------------------------------------------------------------------
      FOR viSeqItemPed IN vtPEDVLMIN_NUMPED.FIRST..vtPEDVLMIN_NUMPED.LAST LOOP
      
        -- Limpa Record
        vrItemPedValidarVlMinimo := vrLimpaItemPedValidarVlMinimo;
            
        -- Inicializa Dados do Item do Pedido
        vrItemPedValidarVlMinimo.vnCodProd               := vtPEDVLMIN_CODPROD(viSeqItemPed);
        vrItemPedValidarVlMinimo.vvCodFilialRetira       := vtPEDVLMIN_CODFILIALRETIRA(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnQtdePedido            := NVL(vtPEDVLMIN_QT(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnPVenda                := NVL(vtPEDVLMIN_PVENDA(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnPVendaLiquido         := NVL(vtPEDVLMIN_PVENDALIQUIDO(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnNumSeq                := NVL(vtPEDVLMIN_NUMSEQ(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vvGrupoFaturamento      := vtPEDVLMIN_GRUPOFATURAMENTO(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnCodPlPag              := vtPEDVLMIN_CODPLPAG(viSeqItemPed);
        vrItemPedValidarVlMinimo.vvItemCancelado         := vtPEDVLMIN_ITEMCANCELADO(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnCodPromocaoMed        := vtPEDVLMIN_CODPROMOCAOMED(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnSt                    := NVL(vtPEDVLMIN_ST(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnPbaseRca              := NVL(vtPEDVLMIN_PBASERCA(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnStPbaseRca            := NVL(vtPEDVLMIN_STPBASERCA(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vvBonific               := NVL(vtPEDVLMIN_BONIFIC(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnCodMotivoPosicaoMed   := NVL(vtPEDVLMIN_CODMOTIVOPOSICAOMED(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vvMotivoPosicaoMed      := NVL(vtPEDVLMIN_MOTIVOPOSICAOMED(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnVlCustoFin            := NVL(vtPEDVLMIN_VLCUSTOFIN(viSeqItemPed),0);
  
        -- Inicializa Filial para Baixa do Estoque
        vrItemPedValidarVlMinimo.vvCodFilialBaixaEstoque := NVL(vrItemPedValidarVlMinimo.vvCodFilialRetira, vrPedido.vvCodFilial);
  
        -- SE O ITEM DO PEDIDO ESTÁ CANCELADO
        IF (NVL(vrItemPedValidarVlMinimo.vvItemCancelado,'N') = 'S') THEN
          
          -- PESQUISA PRODUTO E FILIAL NO ARRAY DE ESTOQUE
          IF (vtEST_CODPROD.COUNT > 0) THEN
            FOR viLacoEst IN vtEST_CODPROD.FIRST..vtEST_CODPROD.LAST LOOP
              
              -- Se encontrou o Produto PCEST
              IF (vtEST_CODPROD(viLacoEst)   = vrItemPedValidarVlMinimo.vnCodProd) AND
                 (vtEST_CODFILIAL(viLacoEst) = vrItemPedValidarVlMinimo.vvCodFilialBaixaEstoque) THEN
                 
                -- Adiciona a Quantidade Cancelada ao Array de Estoque, Coluna Qtde. Disponível
                vtEST_QTDISPONIVEL(viLacoEst) := NVL(vtEST_QTDISPONIVEL(viLacoEst),0) + NVL(vrItemPedValidarVlMinimo.vnQtdePedido,0);
                                                
                -- Sai do Laço ao encontrar dados da PCEST
                EXIT;
                              
              END IF; -- Fim Condição Se encontrou o Produto PCEST
    
            END LOOP;
          END IF; -- Fim da Pesquisa no Array de Estoque do Produto 
        
        END IF; -- FIM CONDIÇÃO: SE O ITEM DO PEDIDO ESTÁ CANCELADO
          
      END LOOP; -- FIM: LAÇO DE ITENS PARA ESTORNO PROVISÓRIO DA QTDE CANCELADA
  
      ------------------------------------------------------------------------------------------------
      -- LAÇO DE ITENS PARA CALCULAR A QUANTIDADE ATENDIDA
      ------------------------------------------------------------------------------------------------
      FOR viSeqItemPed IN vtPEDVLMIN_NUMPED.FIRST..vtPEDVLMIN_NUMPED.LAST LOOP
      
        -------------------------
        -- CARREGA DADOS DO ARRAY
        -------------------------
      
        -- Limpa Record
        vrItemPedValidarVlMinimo := vrLimpaItemPedValidarVlMinimo;
          
        -- Inicializa Dados do Item do Pedido
        vrItemPedValidarVlMinimo.vnCodProd               := vtPEDVLMIN_CODPROD(viSeqItemPed);
        vrItemPedValidarVlMinimo.vvCodFilialRetira       := vtPEDVLMIN_CODFILIALRETIRA(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnQtdePedido            := NVL(vtPEDVLMIN_QT(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnPVenda                := NVL(vtPEDVLMIN_PVENDA(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnPVendaLiquido         := NVL(vtPEDVLMIN_PVENDALIQUIDO(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnNumSeq                := NVL(vtPEDVLMIN_NUMSEQ(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vvGrupoFaturamento      := vtPEDVLMIN_GRUPOFATURAMENTO(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnCodPlPag              := vtPEDVLMIN_CODPLPAG(viSeqItemPed);
        vrItemPedValidarVlMinimo.vvItemCancelado         := vtPEDVLMIN_ITEMCANCELADO(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnCodPromocaoMed        := vtPEDVLMIN_CODPROMOCAOMED(viSeqItemPed);
        vrItemPedValidarVlMinimo.vnSt                    := NVL(vtPEDVLMIN_ST(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnPbaseRca              := NVL(vtPEDVLMIN_PBASERCA(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnStPbaseRca            := NVL(vtPEDVLMIN_STPBASERCA(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vvBonific               := NVL(vtPEDVLMIN_BONIFIC(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnCodMotivoPosicaoMed   := NVL(vtPEDVLMIN_CODMOTIVOPOSICAOMED(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vvMotivoPosicaoMed      := NVL(vtPEDVLMIN_MOTIVOPOSICAOMED(viSeqItemPed),0);
        vrItemPedValidarVlMinimo.vnVlCustoFin            := NVL(vtPEDVLMIN_VLCUSTOFIN(viSeqItemPed),0);
  
        -- Inicializa Filial para Baixa do Estoque
        vrItemPedValidarVlMinimo.vvCodFilialBaixaEstoque := NVL(vrItemPedValidarVlMinimo.vvCodFilialRetira, vrPedido.vvCodFilial);
        
        -- Inicializa a Qtde. Atendida com a Qtde. do Pedido
        vrItemPedValidarVlMinimo.vnQtdeAtendida          := NVL(vtPEDVLMIN_QT(viSeqItemPed),0);
        
        -- Inicializa Plano de Pagamento do Item
        vrItemPedValidarVlMinimo.vnCodPlPagItem          := F_RETORNAR_PLPAG_ITEM(vrParametros.vTIPOPRAZOMEDICAMEN,
                                                                                  vrItemPedValidarVlMinimo.vnCodProd,
                                                                                  vrItemPedValidarVlMinimo.vnCodPlPag,
                                                                                  vrPedido.vnCodPlPag,
                                                                                  vrPedido.vnCodPlPagEtico,
                                                                                  vrPedido.vnCodPlPagGenerico,
                                                                                  vrItemPedValidarVlMinimo.vvGrupoFaturamento);      

        -- Inicializa Tipo de Prazo de Medicamento e a Linha de Prazo
        P_RETORNAR_TIPOPRAZOMEDICAM(vrParametros.vTIPOPRAZOMEDICAMEN,
                                    vrItemPedValidarVlMinimo.vnCodProd,
                                    vrItemPedValidarVlMinimo.vnCodPlPag,
                                    vrPedido.vnCodPlPag,
                                    vrPedido.vnCodPlPagEtico,
                                    vrPedido.vnCodPlPagGenerico,
                                    vrItemPedValidarVlMinimo.vvGrupoFaturamento,
                                    vrItemPedValidarVlMinimo.vvTipoPrazoMedicam,
                                    vrItemPedValidarVlMinimo.vnCodLinhaPrazo);      
              
        -- Pesquisa Valores Anteriores na PCPEDI para o Processo de Estorno de Estoque
        FUNCOES_MED.P_OBTER_VALORES_ANTERIOR(pi_nNumPed,
                                             vrItemPedValidarVlMinimo.vnCodProd,
                                             vrItemPedValidarVlMinimo.vnNumSeq,
                                             vrItemPedValidarVlMinimo.OLD_nQT,
                                             vrItemPedValidarVlMinimo.OLD_nVLSALDORCA,
                                             vrItemPedValidarVlMinimo.OLD_nQTSALDORCA,
                                             vrItemPedValidarVlMinimo.OLD_vPOSICAO);
                    
        -- SE ITEM DO PEDIDO NÃO ESTÁ CANCELADO
        IF (NVL(vrItemPedValidarVlMinimo.vvItemCancelado,'N') <> 'S') THEN
           
          ----------------------------------------
          -- PESQUISA O ESTOQUE DISPONIVEL
          ----------------------------------------
    
          -- Inicializa Flag para identificar se achou o Produto na PCEST
          vbEncontrouProdutoPCEST := FALSE;
          
          -- Inicializa Estoque Disponível
          vnEstoqueDisponivel     := 0;
          
          -- Inicializa Indice do Array da Posição encontrada
          viIdxArrayEstoque       := 0;
    
          -- Pesquisa Estoque do Produto no Array de Estoque
          IF (vtEST_CODPROD.COUNT > 0) THEN
            FOR viLacoEst IN vtEST_CODPROD.FIRST..vtEST_CODPROD.LAST LOOP
              
              -- Se encontrou o Produto PCEST
              IF (vtEST_CODPROD(viLacoEst)   = vrItemPedValidarVlMinimo.vnCodProd) AND
                 (vtEST_CODFILIAL(viLacoEst) = vrItemPedValidarVlMinimo.vvCodFilialBaixaEstoque) THEN
                  
                -- Guarda o ROWNUM para posterior atualização da quantidade provisionada no Array 
                -- (Requerido no cálculo quando o Produto existe mais de uma vez no Pedido)
                viIdxArrayEstoque   := viLacoEst;
                  
                -- Pega no Array a Quantidade Disponível
                vnEstoqueDisponivel := NVL(vtEST_QTDISPONIVEL(viLacoEst),0);
                
                -- Pega no Array o que já foi Reservado no Pedido quando o Produto existe mais de uma vez no Pedido
                vnQtReserv_Pedido   := NVL(vtEST_QTRESERV_PEDIDO(viLacoEst),0);
                
                -- Deduz do Estoque Disponível o que já foi provisionado no Pedido quando o Produto existe mais de uma vez no Pedido
                vnEstoqueDisponivel := NVL(vnEstoqueDisponivel,0) - NVL(vnQtReserv_Pedido,0);
            
                -- Não deixa Saldo Estoque Negativo
                IF (NVL(vnEstoqueDisponivel,0) < 0) THEN
                  vnEstoqueDisponivel := 0;
                END IF;
                                
                -- Se o Item estava Liberado, devolve ao Estoque Disponivel a Qtde. Anterior,
                -- para não dar corte quando estiver editando um Pedido Liberado onde alterou somente a quantidade
                IF (vrItemPedValidarVlMinimo.OLD_vPOSICAO IN ('L','M')) THEN
                  vnEstoqueDisponivel := NVL(vnEstoqueDisponivel,0) + NVL(vrItemPedValidarVlMinimo.OLD_nQT,0); 
                END IF;
                                
                -- Sai do Laço ao encontrar dados da PCEST
                EXIT;
                              
              END IF; -- Fim Condição Se encontrou o Produto PCEST
    
            END LOOP;
          END IF; -- Fim da Pesquisa no Array de Estoque do Produto 
          
          -- SE O PEDIDO PODE ATUALIZAR O ESTOQUE -----------------------------------------------------
          IF (vbPedidoPodeAtualizarEstoque) THEN
          
            --------------------------------
            -- CALCULA A QUANTIDADE ATENDIDA
            --------------------------------
                              
            -- Se não tem Quantidade suficiente para atender a Quantidade do Item do Pedido
            IF (NVL(vnEstoqueDisponivel,0) < NVL(vrItemPedValidarVlMinimo.vnQtdeAtendida,0)) THEN    

              -- A Quantidade Atendida será Restringida ao Estoque Disponivel
              vrItemPedValidarVlMinimo.vnQtdeAtendida := NVL(vnEstoqueDisponivel,0);                

              ------------------------------------------------------------------
              -- RECALCULO DA QUANTIDADE ATENDIDA quando Multiplo DDVENDAS-41227
              ------------------------------------------------------------------

              vnEstoqueMultiplo := F_OBTER_ESTOQUE_MULTIPLO(vrPedido.vnCodCli,
                                                            vrPedido.vnCondVenda,
                                                            vrItemPedValidarVlMinimo.vnCodProd,
                                                            vrItemPedValidarVlMinimo.vnQtdeAtendida,
                                                            vrPedido.vvCodFilial,
                                                            NVL(vnEstoqueDisponivel,0));

              -- Se não tem Quantidade Multipla suficiente para atender a Quantidade do Item do Pedido
              IF (NVL(vnEstoqueMultiplo,0) > 0) AND
                 (NVL(vnEstoqueMultiplo,0) < NVL(vrItemPedValidarVlMinimo.vnQtdeAtendida,0)) THEN              

                -- A Quantidade Atendida será Restringida ao Estoque Multiplo Disponivel
                vrItemPedValidarVlMinimo.vnQtdeAtendida := NVL(vnEstoqueMultiplo,0);

              END IF;

            END IF;               
            
            -- Guarda o Estoque Disponível
            vrItemPedValidarVlMinimo.vnEstoqueDisponivel := NVL(vnEstoqueDisponivel,0);
              
            -------------------------------------------------------------
            -- ATUALIZA ARRAY DE QTDE. DE ESTOQUE PROVISIONADA DO PRODUTO
            -------------------------------------------------------------
            IF (vtEST_QTRESERV_PEDIDO.EXISTS(viIdxArrayEstoque)) THEN
            
              -- Guarda a Qtde. Provisionada para o Produto no Pedido, o Produto pode existir mais de uma vez no Pedido
              vtEST_QTRESERV_PEDIDO(viIdxArrayEstoque) := NVL(vtEST_QTRESERV_PEDIDO(viIdxArrayEstoque),0) + NVL(vrItemPedValidarVlMinimo.vnQtdeAtendida,0);
              
            END IF;                   
                                
            
            -------------------------------------------
            -- VERIFICA SE VÃO OCORRER FALTAS NO PEDIDO
            -------------------------------------------
            
            -- Calcula a Quantidade de Faltas
            vnQtdeFalta := (NVL(vrItemPedValidarVlMinimo.vnQtdePedido,0) - NVL(vrItemPedValidarVlMinimo.vnQtdeAtendida,0));
              
            -- Retorno que indica se Existem Faltas
            IF (NVL(vnQtdeFalta,0) > 0) THEN
              po_vExistemFaltas := 'S';
            END IF;                  
            
            ---------------------------------------------
            -- GRAVA TABELA TEMPORÁRIA DE ITENS FALTANTES
            ---------------------------------------------
            IF (NVL(vnQtdeFalta,0) > 0) THEN
            
              -- Inicializa Record que receberá os dados da Promoção
              vrPromocao := vrLimpaPromocao;
            
              -- Verifica se Promoção COMBO
              BEGIN
                SELECT PCPROMOCAOMED.DESCRICAORESUMIDA
                     , CASE
                         WHEN (PCPROMOCAOMED.TIPOPROMOCAO = 'K') THEN
                           'S'
                         ELSE
                           'N'
                       END COMBO
                     , CASE
                         WHEN (PCPROMOCAOMED.TIPOPROMOCAO = 'K') THEN
                           CODPROMOCAOMED
                         ELSE
                           TO_NUMBER(NULL)
                       END COMBO
                  INTO vrPromocao.vvDescricaoResumida
                     , vrPromocao.vvCombo
                     , vrPromocao.vnCodPromocaoCombo
                  FROM PCPROMOCAOMED
                 WHERE (CODPROMOCAOMED = vrItemPedValidarVlMinimo.vnCodPromocaoMed);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vrPromocao.vvDescricaoResumida := NULL;
                  vrPromocao.vvCombo             := NULL;
                  vrPromocao.vnCodPromocaoCombo  := NULL;
              END;
              
              -- Verifica se Item com Promoção Combo Obrigatorio no Pedido
              IF (vrPromocao.vvCombo = 'S') THEN
                BEGIN
                  SELECT NVL(PROMOCAOMEDOBRIGATORIO,'N')
                    INTO vrPromocao.vvItemComboObrigatorio
                    FROM PCDESCONTO
                   WHERE (CODPROD        = vrItemPedValidarVlMinimo.vnCodProd)
                     AND (CODPROMOCAOMED = vrItemPedValidarVlMinimo.vnCodPromocaoMed)
                     AND (ROWNUM         = 1);
                EXCEPTION 
                  WHEN NO_DATA_FOUND THEN
                    vrPromocao.vvItemComboObrigatorio := 'N';
                END;
              END IF;
              
              -- Corte do Combo - ITEM OBRIGATÓRIO
              IF    (NVL(vrPromocao.vvCombo,'N')                = 'S') AND
                    (NVL(vrPromocao.vvItemComboObrigatorio,'N') = 'S') THEN
                vrPromocao.vvCorteCombo         := 'P'; -->> Principal pelo Corte
                vrPromocao.vvMensagemCorteCombo := SUBSTR('Produto com estoque insuficiente que gerou o Corte Total do Combo ' || vrItemPedValidarVlMinimo.vnCodPromocaoMed || ' - ' || vrPromocao.vvDescricaoResumida,1,250);
              ELSIF (NVL(vrPromocao.vvCombo,'N')                 = 'S') AND
                    (NVL(vrPromocao.vvItemComboObrigatorio,'N') <> 'S') THEN
                vrPromocao.vvCorteCombo         := 'S'; -->> Secundário pelo Corte
                vrPromocao.vvMensagemCorteCombo := SUBSTR('Produto com estoque insuficiente no Combo ' || vrItemPedValidarVlMinimo.vnCodPromocaoMed || ' - ' || vrPromocao.vvDescricaoResumida || ', mas não é obrigatório no Pedido',1,250);
              END IF;      
        
              -- Se 2316 e tiver permissão para gravar pedido de faltas, não utilizará o processo de corte de combo
              IF (pi_nCodRotina = 2316) AND
                 (F_VERIFICARACESSOCONTROLE(2316,93,pi_nMatricula)) THEN
                vrPromocao.vvCorteCombo         := NULL;
                vrPromocao.vvMensagemCorteCombo := NULL;
              END IF;
              -- Se 2336 e tiver permissão para gravar pedido de faltas, não utilizará o processo de corte de combo
              IF (pi_nCodRotina = 2336) AND
                 (F_VERIFICARACESSOCONTROLE(2336,76,pi_nMatricula)) THEN
                vrPromocao.vvCorteCombo         := NULL;
                vrPromocao.vvMensagemCorteCombo := NULL;
              END IF;
        
              -- MED-729 - Considerar no pedido o valor minimo pedido - imposto
              BEGIN             
                vvCONSIDVALORMINSEMIMPOSTO := 'N';
                
                SELECT NVL(PCPARAMINTEGRADORAMED.VALOR,'N')
                  INTO vvCONSIDVALORMINSEMIMPOSTO
                  FROM PCPARAMINTEGRADORAMED
                 WHERE (PCPARAMINTEGRADORAMED.NOME        = 'CONSIDERAVALORMINIMOSEMIMPOSTO')
                   AND (PCPARAMINTEGRADORAMED.INTEGRADORA = vrPedido.vnIntegradora);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vvCONSIDVALORMINSEMIMPOSTO := 'N';
              END;
              
              IF (vvCONSIDVALORMINSEMIMPOSTO = 'S') AND (vrItemPedValidarVlMinimo.vnPVendaLiquido < vrItemPedValidarVlMinimo.vnPVenda) THEN
                vrItemPedValidarVlMinimo.vnPVenda := vrItemPedValidarVlMinimo.vnPVendaLiquido;
              END IF;
              
              -- Grava Tabela Temporária de Itens Faltantes
              INSERT INTO PCMED_FALTAS_ESTOQUE_RESERV
                        ( NUMPED
                        , CODPROD
                        , NUMSEQ
                        , DESCRICAO
                        , QTDEORIGINAL
                        , VALORORIGINAL
                        , QTDEATENDIDA
                        , VALORATENDIDO
                        , QTDEFALTA
                        , VALORFALTA
                        , ESTOQUEDISPONIVEL
                        , COMBO
                        , CODPROMOCAOCOMBO
                        , DESCRICAOPROMOCAO
                        , DESCRICAOFALTA
                        , OBRIGATORIOPEDIDO
                        , CORTECOMBO )
                 VALUES ( pi_nNumPed
                        , vrItemPedValidarVlMinimo.vnCodProd
                        , vrItemPedValidarVlMinimo.vnNumSeq
                        , SUBSTR((SELECT DESCRICAO FROM PCPRODUT WHERE PCPRODUT.CODPROD = vrItemPedValidarVlMinimo.vnCodProd),1,200)
                        , vrItemPedValidarVlMinimo.vnQtdePedido
                        , ROUND((vrItemPedValidarVlMinimo.vnPVenda * vrItemPedValidarVlMinimo.vnQtdePedido),2)
                        , vrItemPedValidarVlMinimo.vnQtdeAtendida
                        , ROUND((vrItemPedValidarVlMinimo.vnPVenda * vrItemPedValidarVlMinimo.vnQtdeAtendida),2)
                        , vnQtdeFalta 
                        , ROUND((vrItemPedValidarVlMinimo.vnPVenda * vnQtdeFalta),2)
                        , vnEstoqueDisponivel
                        , vrPromocao.vvCombo
                        , vrPromocao.vnCodPromocaoCombo
                        , SUBSTR(vrPromocao.vvDescricaoResumida,1,40)
                        , SUBSTR(vrPromocao.vvMensagemCorteCombo,1,250)
                        , vrPromocao.vvItemComboObrigatorio
                        , vrPromocao.vvCorteCombo );
                        
            END IF; -- Fim Condição: Se Grava Tabela Temporária de Itens Faltantes          
  
          END IF; -- FIM CONDIÇÃO: SE O PEDIDO PODE OU NÃO PODE ATUALIAR O ESTOQUE
                     
          
          -- MED-729 - Considerar no pedido o valor minimo pedido - imposto
          BEGIN
            vvCONSIDVALORMINSEMIMPOSTO := 'N';          
             
            SELECT NVL(PCPARAMINTEGRADORAMED.VALOR,'N')
              INTO vvCONSIDVALORMINSEMIMPOSTO
              FROM PCPARAMINTEGRADORAMED
             WHERE (PCPARAMINTEGRADORAMED.NOME        = 'CONSIDERAVALORMINIMOSEMIMPOSTO')
               AND (PCPARAMINTEGRADORAMED.INTEGRADORA = vrPedido.vnIntegradora);        
            
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvCONSIDVALORMINSEMIMPOSTO := 'N';
          END;
          
          IF (vvCONSIDVALORMINSEMIMPOSTO = 'S') AND (vrItemPedValidarVlMinimo.vnPVendaLiquido < vrItemPedValidarVlMinimo.vnPVenda) THEN
            vrItemPedValidarVlMinimo.vnPVenda := vrItemPedValidarVlMinimo.vnPVendaLiquido;
          END IF;
            
          ---------------------------------------------------------
          -- ATUALIZA TABELA TEMPORÁRIA DE CRITICAS DE VALOR MÍNIMO
          ---------------------------------------------------------
          P_ATU_CRITICAS_VALOR_MINIMO(vrItemPedValidarVlMinimo.vnQtdePedido,
                                      vrItemPedValidarVlMinimo.vnQtdeAtendida,
                                      vrItemPedValidarVlMinimo.vnPVenda,
                                      vrItemPedValidarVlMinimo.vnCodPlPagItem,
                                      vrItemPedValidarVlMinimo.vnCodProd,
                                      vrItemPedValidarVlMinimo.vnNumSeq,
                                      vrItemPedValidarVlMinimo.vnSt,
                                      vrItemPedValidarVlMinimo.vnPBaseRca,
                                      vrItemPedValidarVlMinimo.vnStPBaseRca,
                                      vrItemPedValidarVlMinimo.vvBonific,
                                      vrItemPedValidarVlMinimo.vnCodMotivoPosicaoMed,
                                      vrItemPedValidarVlMinimo.vvMotivoPosicaoMed,
                                      vrItemPedValidarVlMinimo.vvGrupoFaturamento,
                                      vrItemPedValidarVlMinimo.vvTipoPrazoMedicam,
                                      vrItemPedValidarVlMinimo.vnCodLinhaPrazo,
                                      vrItemPedValidarVlMinimo.vnVlCustoFin,
                                      vrItemPedValidarVlMinimo.vnCodPromocaoMed);  
          
        END IF; -- FIM CONDIÇÃO: SE ITEM DO PEDIDO NÃO ESTÁ CANCELADO     
            
        -- Insere Dados do Item do Pedido em Lista (Para reuso se necessário)
        vtItensPedValidarVlMinimo(NVL(vtItensPedValidarVlMinimo.COUNT,0) + 1) := vrItemPedValidarVlMinimo;
            
      END LOOP; -- FIM: LAÇO DE ITENS PARA CALCULAR A QUANTIDADE ATENDIDA
    
      -----------------------------------------------------------------------
      -- MEDICA-477 - PROCESSAR TABELA TEMPORÁRIA DE CRITICAS DE VALOR MÍNIMO
      -----------------------------------------------------------------------
      
      -- BUSCA O SALDO DO RCA UMA ÚNICA VEZ SEM CONSIDERAR O PEDIDO ATUAL --
      ----------------------------------------------------------------------
      IF (pi_vMovimentarSaldoRca = 'S') THEN
      
        -- Saldo Atual do RCA
        vnSaldoRcaDisponivel := PC_PKG_CONTROLARSALDORCA_MED.CCRCA_CHECAR_DISPONIVEL_ATUAL(pi_nCodUsurContaCorrente);
           
        -- Se Movimenta o Saldo dos Pedidos no Faturamento, vai precisar estornar os valores deste pedido já gravados na PCPEDC e PCPEDI
        -- (Estornar o valor que foi atualizado no Saldo RCA para não criticar 2x o mesmo valor - MED-2537)
        IF (FUNCOES_MED.FUSA_REGRA_MEDICAMENTOS('99','MOVSALDORCAPORPEDIDOFAT') = 'S') THEN        
                  
          -- Busca Saldo RCA do Pedido
          vnSaldoRcaPedido := ObterSaldoRcaPedidoAtualNaoFat('OD', -- Preciso passar OD para usar a regra de outros pedidos diferente do atual, mesmo filtrando internamente pelo pedido atual
                                                             pi_nCodUsurContaCorrente,
                                                             pi_nNumPed);
    
          -- Log: Saldo Regra Específica
          P_INSERE_LOG_PROCESSAMENTO('MOVSALDORCAPORPEDIDOFAT = '  || 'S'                         || CHR(13) ||
                                     'pi_nCodUsurContaCorrente = ' || pi_nCodUsurContaCorrente    || CHR(13) ||
                                     'vnSaldoRcaDisponivel = '     || NVL(vnSaldoRcaDisponivel,0) || CHR(13) || 
                                     'vnSaldoRcaPedido = '         || NVL(vnSaldoRcaPedido,0));          
    
           -- Subtrai o Saldo RCA do Pedido
           vnSaldoRcaDisponivel := NVL(vnSaldoRcaDisponivel,0) - NVL(vnSaldoRcaPedido,0);
           
        ELSE
        
          -- Log: Saldo Padrão Pacote
          P_INSERE_LOG_PROCESSAMENTO('MOVSALDORCAPORPEDIDOFAT = '  || 'N'                         || CHR(13) ||
                                     'pi_nCodUsurContaCorrente = ' || pi_nCodUsurContaCorrente    || CHR(13) ||
                                     'vnSaldoRcaDisponivel = '     || NVL(vnSaldoRcaDisponivel,0));          
                                     
        END IF;
        
      END IF; -- (pi_vMovimentarSaldoRca = 'S')
      
      

      
      ----------------------------------------------------------------------    
      --              PROCESSA AS CRÍTICAS DE VALOR MÍNIMO                 -
      ----------------------------------------------------------------------    
      P_PROC_CRITICAS_VALOR_MINIMO(vnSaldoRcaDisponivel,
                                   vrParametros.vREJEITAPEDRCASEMSALDOFV); -- DDMEDICA-6363
      
      
      
      
      ------------------------------------------------------------------------
      -- Atualização Motivo passado no Parâmetro nas CRÍTICAS DE VALOR MÍNIMO 
      -- ao Validar o Valor Mínimo (Motivo ainda não mapeado no novo processo)
      ------------------------------------------------------------------------
      IF (pi_vChamadaProcesso = 'VM')  AND
         (pi_nCodRotina <> 2336)       AND
         (pi_vNovaPosicaoPedido = 'B') THEN
        -- Log: Motivo do Pedido
        P_INSERE_LOG_PROCESSAMENTO('pi_nCodMotivo = '         || pi_nCodMotivo || CHR(13) ||
                                   'pi_nCodMotivoBloqueio = ' || NVL(pi_nCodMotivoBloqueio,0));          
        -- 
        IF (F_INCLUIR_BLOQUEIO_PEDIDO(pi_nNumPed,
                                       pi_nCodMotivo,
                                       pi_nCodMotivoBloqueio) = 'S') THEN
          IF (pi_nCodRotina = 2316) THEN
            vvAcaoMotivoPedido := 'P';
          ELSE
            vvAcaoMotivoPedido := 'B';
          END IF;
          -- Verifica se o Código do Motivo já está tratado na gravação do pedido
          BEGIN
            SELECT 'S'
              INTO vvExisteCodMotivoPedido
              FROM PCMED_VALIDACAO_ESTOQUE_RESERV
             WHERE (NUMPED    = pi_nNumPed)
               AND (CODMOTIVO = pi_nCodMotivo)
               AND (ROWNUM    = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvExisteCodMotivoPedido := 'N';
          END;
          -- Se ainda não está tratado o motivo na gravação do pedido
          IF (vvExisteCodMotivoPedido = 'N') THEN
            P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                          , pi_nNumPed
                                          , 0
                                          , 9999
                                          , vvAcaoMotivoPedido -- pACAO
                                          , SUBSTR(pi_vMotivoPosicao,1,100)
                                          , NULL  -- nCODROTINA
                                          , NULL  -- pVALORVALIDACAO
                                          , NULL  -- pVALORATINGIDO
                                          , 'X'
                                          , NULL  -- pNUMEROPARAMETRO
                                          , pi_nCodMotivo
                                          , pi_nCodMotivoBloqueio
                                          , SUBSTR(pi_vMotivoPosicao,1,60)
                                          , NULL  -- pPERMISSAO
                                          , NULL  -- pSOLUCAOP4
                                          , 'P' );
          END IF;
        END IF;
      END IF;
      
      
      
      
      -----------------------------------------------------------------------
      -- Atualização Motivo passado no Parâmetro nas CRITICAS DE VALOR MÍNIMO
      -- ao Incluir o Pedido (Motivo ainda não mapeado no novo processo)
      -----------------------------------------------------------------------
      IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) AND
         (pi_nCodRotina <> 2336)                             AND
         (pi_vNovaPosicaoPedido = 'B')                       AND
         (NVL(pi_nCodMotivo,0) > 0)                          THEN
        -- Log: Motivo do Pedido
        P_INSERE_LOG_PROCESSAMENTO('pi_nCodMotivo = '         || pi_nCodMotivo || CHR(13) ||
                                   'pi_nCodMotivoBloqueio = ' || NVL(pi_nCodMotivoBloqueio,0));          
        -- 
        IF (F_INCLUIR_BLOQUEIO_PEDIDO(pi_nNumPed,
                                      pi_nCodMotivo,
                                      pi_nCodMotivoBloqueio) = 'S') THEN
          IF (pi_nCodRotina = 2316) THEN
            vvAcaoMotivoPedido := 'P';
          ELSE
            vvAcaoMotivoPedido := 'B';
          END IF;
          -- Verifica se o Código do Motivo já está tratado na gravação do pedido
          BEGIN
            SELECT 'S'
              INTO vvExisteCodMotivoPedido
              FROM PCMED_VALIDACAO_ESTOQUE_RESERV
             WHERE (NUMPED    = pi_nNumPed)
               AND (CODMOTIVO = pi_nCodMotivo)
               AND (ROWNUM    = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvExisteCodMotivoPedido := 'N';
          END;
          -- Se ainda não está tratado o motivo na gravação do pedido
          IF (vvExisteCodMotivoPedido = 'N') THEN
            P_ATU_VALIDACAO_ESTOQUE_RESERV( pi_vChamadaProcesso
                                          , pi_nNumPed
                                          , 0
                                          , 9999
                                          , vvAcaoMotivoPedido -- pACAO
                                          , SUBSTR(pi_vMotivoPosicao,1,100)
                                          , NULL  -- nCODROTINA
                                          , NULL  -- pVALORVALIDACAO
                                          , NULL  -- pVALORATINGIDO
                                          , 'X'
                                          , NULL  -- pNUMEROPARAMETRO
                                          , pi_nCodMotivo
                                          , pi_nCodMotivoBloqueio
                                          , SUBSTR(pi_vMotivoPosicao,1,60)
                                          , NULL  -- pPERMISSAO
                                          , NULL  -- pSOLUCAOP4
                                          , 'P' );
          END IF;
        END IF;
      END IF;
      
      
      
      
      ----------------------------------------------------------------------    
      --              VALIDAÇÃO DAS CRÍTICAS DE VALOR MÍNIMO               -
      ----------------------------------------------------------------------    
      vbATENDEU_VALOR_MINIMO := F_ATENDEU_VALOR_MINIMO;
      
      
  
    
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      --                              CORTE TOTAL DO COMBO VIRTUAL (KIT)                          --
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      IF (vrRegrasEspecificas.vREALIZARCORTETOTALKIT = 'S') THEN
      
        -- Laço de Combos com Faltas nos Itens Obrigatórios no Pedido
        FOR vc_ComboComFaltas IN (SELECT CODPROMOCAOCOMBO
                                       , DESCRICAOPROMOCAO  
                                       , COUNT(*) QT_ITENS
                                    FROM PCMED_FALTAS_ESTOQUE_RESERV
                                   WHERE (CORTECOMBO = 'P') -->> Principal pelo Corte
                                   GROUP BY CODPROMOCAOCOMBO
                                          , DESCRICAOPROMOCAO) LOOP
                                                                    
          -- Zera a Qtde. e Valor Atendido dos Itens que serão cortados automaticamente por haver falta no Combo
          -- A Qtde. e Valor da Falta não precisará demonstrar no Grid por ser corte automático
          UPDATE PCMED_FALTAS_ESTOQUE_RESERV
             SET QTDEATENDIDA   = 0
               , VALORATENDIDO  = 0 
               , QTDEFALTA      = NULL
               , VALORFALTA     = NULL
           WHERE (CODPROMOCAOCOMBO = vc_ComboComFaltas.CODPROMOCAOCOMBO)
             AND (CORTECOMBO       = 'S'); -->> Somente atualiza os itens que não tiveram falta (mantém falta original dos itens com falta)
  
          -- Laço de Itens para buscar todos os produtos do Combo
          IF (vtItensPedValidarVlMinimo.COUNT > 0) THEN
            FOR viSeqItemPed IN vtItensPedValidarVlMinimo.FIRST..vtItensPedValidarVlMinimo.LAST LOOP
            
              -- Inicializa Record de dados da Promoção
              vrPromocao := vrLimpaPromocao;
            
              -- Pega Record do Array
              vrItemPedValidarVlMinimo := vtItensPedValidarVlMinimo(viSeqItemPed);
              
              -------------------------------------------------
              -- SE O ITEM DO PEDIDO PERTENCER À MESMA PROMOÇÃO
              -------------------------------------------------
              IF (vrItemPedValidarVlMinimo.vnCodPromocaoMed = vc_ComboComFaltas.CODPROMOCAOCOMBO) THEN 
              
                -- Verifica se o Produto já está na Tabela Temporára de Itens Faltantes
                BEGIN
                  SELECT 'S'
                       , CORTECOMBO
                    INTO vvAchouDadosTabTemp
                       , vvCorteComboTabTemp
                    FROM PCMED_FALTAS_ESTOQUE_RESERV
                   WHERE (NUMPED  = pi_nNumPed)
                     AND (CODPROD = vrItemPedValidarVlMinimo.vnCodProd)
                     AND (NUMSEQ  = vrItemPedValidarVlMinimo.vnNumSeq)
                     AND (ROWNUM  = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvAchouDadosTabTemp := 'N';
                    vvCorteComboTabTemp := 'N';
                END;                         
                            
                -- Mensagem de Corte do Combo
                IF (NVL(vc_ComboComFaltas.QT_ITENS,0) = 1) THEN
                  vrPromocao.vvMensagemCorteCombo := SUBSTR('Produto que será cortado no Pedido por existir ' || NVL(vc_ComboComFaltas.QT_ITENS,0) || ' item com estoque insuficiente no Combo ' || vc_ComboComFaltas.CODPROMOCAOCOMBO || ' - ' || vc_ComboComFaltas.DESCRICAOPROMOCAO,1,250);
                ELSE
                  vrPromocao.vvMensagemCorteCombo := SUBSTR('Produto que será cortado no Pedido por existirem ' || NVL(vc_ComboComFaltas.QT_ITENS,0) || ' itens com estoque insuficiente no Combo ' || vc_ComboComFaltas.CODPROMOCAOCOMBO || ' - ' || vc_ComboComFaltas.DESCRICAOPROMOCAO,1,250);
                END IF;
                
                -- Se o Item ainda não está na Tabela Temporária
                IF (vvAchouDadosTabTemp = 'N') THEN
                             
                  -- Grava Tabela Temporária de Itens Faltantes
                  INSERT INTO PCMED_FALTAS_ESTOQUE_RESERV
                            ( NUMPED
                            , CODPROD
                            , NUMSEQ
                            , DESCRICAO
                            , QTDEORIGINAL
                            , VALORORIGINAL
                            , QTDEATENDIDA
                            , VALORATENDIDO
                            , QTDEFALTA
                            , VALORFALTA
                            , ESTOQUEDISPONIVEL
                            , COMBO
                            , CODPROMOCAOCOMBO
                            , DESCRICAOPROMOCAO
                            , DESCRICAOFALTA
                            , CORTECOMBO )
                     VALUES ( pi_nNumPed
                            , vrItemPedValidarVlMinimo.vnCodProd
                            , vrItemPedValidarVlMinimo.vnNumSeq
                            , SUBSTR((SELECT DESCRICAO FROM PCPRODUT WHERE PCPRODUT.CODPROD = vrItemPedValidarVlMinimo.vnCodProd),1,200)
                            , vrItemPedValidarVlMinimo.vnQtdePedido
                            , ROUND((vrItemPedValidarVlMinimo.vnPVenda * vrItemPedValidarVlMinimo.vnQtdePedido),2)
                            , 0      -- QTDEATENDIDA
                            , 0      -- VALORATENDIDO
                            , NULL   -- QTDEFALTA
                            , NULL   -- VALORFALTA
                            , vrItemPedValidarVlMinimo.vnEstoqueDisponivel
                            , 'S'    -- COMBO
                            , vc_ComboComFaltas.CODPROMOCAOCOMBO
                            , SUBSTR(vc_ComboComFaltas.DESCRICAOPROMOCAO,1,40) 
                            , vrPromocao.vvMensagemCorteCombo
                            , 'S' ); -- CORTECOMBO
                            
                -- Se o Item já existir na Tabela Temporária            
                ELSE
                
                  -- Se Secundário, padroniza as mensagens dos itens cortados automaticamente por ter ocorrido estoque insuficiente no combo
                  IF (vvCorteComboTabTemp = 'S') THEN
                  
                    UPDATE PCMED_FALTAS_ESTOQUE_RESERV
                       SET DESCRICAOFALTA = vrPromocao.vvMensagemCorteCombo
                     WHERE (NUMPED  = pi_nNumPed)
                       AND (CODPROD = vrItemPedValidarVlMinimo.vnCodProd)
                       AND (NUMSEQ  = vrItemPedValidarVlMinimo.vnNumSeq);
  
                  END IF;
                
                END IF; -- FIM: Grava Tabela Temporária de Itens Faltantes 
  
              END IF; -- FIM CONDIÇÃO: SE O ITEM DO PEDIDO PERTENCER À MESMA PROMOÇÃO
            
            END LOOP;
          END IF;
                                           
        END LOOP;                  
        
      END IF; -- Fim Condição: CORTE TOTAL DO COMBO VIRTUAL (KIT)
     
    
    
    
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      -- AO GRAVAR O PEDIDO COMO PENDENTE, E LIBERA AUTOMATICAMENTE O PEDIDO PENDENTE SE TODOS OS --
      -- FOREM ATENDIDOS, GRAVA O PEDIDO COMO LIBERADO (SE NÃO OCORREU PREVISÃO DE CORTE          --
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      ----------------------------------------------------------------------------------------------
      IF (pi_nCodRotina                      IN (2316,2513)) AND
         (vrParametros.vLIBERARPEDIDOPENDENTE = 'S')         AND
         (vrParametros.vACEITAVENDASEMEST     = 'S')         AND
         (po_vPosicaoFinalPedido              = 'P')         AND
         (NVL(po_vExistemFaltas,'N')          = 'N')         THEN
        po_vPosicaoFinalPedido := 'L';
        -- Motivo do Pedido ficar como Liberado
        P_GERAR_TEXTO_LOG_BLOQUEIO(0,
                                   '',
                                   'Parâmetro "Liberar pedido pendente automaticamente" igual = SIM, grava Pedido como Liberado',
                                   po_nCodMotivo,
                                   po_vMotivoPosicao,
                                   po_vObservacaoMotivo);
      END IF;
   
  
    
    
     /**************************************************************************************************  
      **************************************************************************************************  
      *                                                                                                *
      *                V A L I D A Ç Ã O    D O    M Í N I M O    D O    P E D I D O                   *
      *                                                                                                *
      **************************************************************************************************  
      **************************************************************************************************/
     
      --------------------------------------------------------------------------------------------------
      --------------------------------------------------------------------------------------------------
      --                        AO CHAMAR SOMENTE PARA VALIDAR VALOR MINIMO O PEDIDO                  --
      --------------------------------------------------------------------------------------------------
      --------------------------------------------------------------------------------------------------    
      IF (pi_vChamadaProcesso IN ('VM','LB')) THEN
    
        -- SE NÃO ATENDEU O VALOR MÍNIMO ---------------------------------------------------------------
        IF (NOT vbATENDEU_VALOR_MINIMO) THEN
       
          -------------------------------------------
          -- Laço de Retorno com os Motivo da Posição
          -------------------------------------------    
          FOR vc_Motivo IN (SELECT CASE 
                                     WHEN (NVL(PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO,0) = 0) THEN
                                       1
                                     ELSE
                                       2 + NVL((SELECT PCBLOQUEIO.CODMOTIVO
                                                  FROM PCBLOQUEIO 
                                                 WHERE PCBLOQUEIO.CODMOTBLOQUEIO = PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO
                                                   AND ROWNUM = 1),0) -- Pegar por último os bloqueios comerciais com vinculo com codmotivo
                                   END ORDENACAO_1   
                                 , CASE
                                     WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'P') THEN
                                       1
                                     WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'B') THEN
                                       2
                                     ELSE
                                       3
                                   END ORDENACAO_2                                  
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO
                              FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                             WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO IN ('P','B','A'))
                             ORDER BY 1, 1 -->> CLASSIFICAR A ORDENAÇÃO (Primeiro os Bloqueios Automáticos (DDMEDICA-4851) e depois os que abortam por último)
                             ) LOOP       
        
            -- Retorna Posição como Bloqueado, para a Rotina entender ocorreram validações que indicam Bloqueio do Pedido
            po_vPosicaoFinalPedido := 'B';
        
            -- Motivo do Pedido
            P_GERAR_TEXTO_LOG_BLOQUEIO(vc_Motivo.CODMOTIVO,
                                       vc_Motivo.MOTIVOPOSICAO,
                                       NVL(vc_Motivo.OBSERVACAO,vc_Motivo.MOTIVOPOSICAO),
                                       po_nCodMotivo,
                                       po_vMotivoPosicao,
                                       po_vObservacaoMotivo);
                                      
            -- Log
            P_INSERE_LOG_PROCESSAMENTO('po_vPosicaoFinalPedido: ' || po_vPosicaoFinalPedido || ' > ' || vc_Motivo.CODMOTIVO || ' - ' || vc_Motivo.MOTIVOPOSICAO || ' (NAO_ATENDEU_VALOR_MINIMO)');
                                    
          END LOOP; -- Fim: Laço de Retorno com os Motivo da Posição
    
        END IF; -- FIM CONDIÇÃO: SE NÃO ATENDEU O VALOR MÍNIMO      
              
      --------------------------------------------------------------------------------------------------
      --------------------------------------------------------------------------------------------------
      --                 AO CHAMAR NA GRAVAÇÃO DO PEDIDO PARA VALIDAR O MÍNIMO PÓS CORTE              --
      --------------------------------------------------------------------------------------------------
      --------------------------------------------------------------------------------------------------    
      ELSE
            
        -- SE GRAVAÇÃO DO PEDIDO E VAI GERAR O PEDIDO COMO LIBERADO/MONTADO E NÃO ATINGIU VALOR MÍNIMO - 
        IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI')) AND -- OBS: 'CC' - Call Center não tem crítica, é pra cancelar TUDO
           (po_vPosicaoFinalPedido IN ('L','M'))          AND
           (NOT vbATENDEU_VALOR_MINIMO)                   THEN
                
          -- Nem tenta mudar a Posição do Pedido para Liberado/Montado, 
          -- porque não tem Permissão para Gravar o Pedido como Liberado abaixo da Fatura Mínima 
          po_vPosicaoFinalPedido := 'B';
          
          -- Laço de Retorno com os Motivo da Posição,
          -- que não deixaram Liberar o Pedido
          FOR vc_Motivo IN (SELECT CASE 
                                     WHEN (NVL(PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO,0) = 0) THEN
                                       1
                                     ELSE
                                       2 + NVL((SELECT PCBLOQUEIO.CODMOTIVO
                                                  FROM PCBLOQUEIO 
                                                 WHERE PCBLOQUEIO.CODMOTBLOQUEIO = PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO
                                                   AND ROWNUM = 1),0) -- Pegar por último os bloqueios comerciais com vinculo com codmotivo
                                   END ORDENACAO_1   
                                 , CASE
                                     WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'P') THEN
                                       1
                                     WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'B') THEN
                                       2
                                     ELSE
                                       3
                                   END ORDENACAO_2
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO
                                 , PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO
                              FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                             WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO IN ('P','B','A'))
                             ORDER BY 1, 1 -->> CLASSIFICAR A ORDENAÇÃO (Primeiro os Bloqueios Automaticos (DDMEDICA-4851) e depois os que abortam por último)
                             ) LOOP       
      
            -- Motivo do Pedido ter sido Bloqueado após o Corte
            P_GERAR_TEXTO_LOG_BLOQUEIO(vc_Motivo.CODMOTIVO,
                                       vc_Motivo.MOTIVOPOSICAO,
                                       NVL(vc_Motivo.OBSERVACAO,vc_Motivo.MOTIVOPOSICAO),
                                       po_nCodMotivo,
                                       po_vMotivoPosicao,
                                       po_vObservacaoMotivo);
                                   
            -- Log: Motivos
            P_INSERE_LOG_PROCESSAMENTO('Motivos que não deixaram Liberar o Pedido: ' || CHR(13) ||
                                       vc_Motivo.CODREJEICAO || ' - ' || vc_Motivo.OBSERVACAO   || ' [' || vc_Motivo.ACAO || ']');
                         
            -- Log
            P_INSERE_LOG_PROCESSAMENTO('po_vPosicaoFinalPedido: ' || po_vPosicaoFinalPedido || ' >> ' || vc_Motivo.CODMOTIVO || ' - ' || vc_Motivo.MOTIVOPOSICAO || ' (NAO_ATENDEU_VALOR_MINIMO)');
                                                     
          END LOOP; -- Fim: Laço de Retorno com os Motivo da Posição        
                             
        END IF; -- FIM CONDIÇÃO: GRAVAR O PEDIDO COMO LIBERADO/MONTADO, SE NÃO VAI ATENDER O VALOR MÍNIMO APÓS O CORTE         
  
      
      END IF; -- FIM CONDIÇÃO: TIPO CHAMADA PARA VALIDAR O VALOR MÍNIMO
    
      
      -- Log
      P_INSERE_LOG_PROCESSAMENTO('po_vPosicaoFinalPedido: ' || po_vPosicaoFinalPedido || ' (NAO_ATENDEU_VALOR_MINIMO)');
      P_INSERE_LOG_PROCESSAMENTO('po_vMotivoPosicao: ' || po_vMotivoPosicao || ' (NAO_ATENDEU_VALOR_MINIMO)');
      P_INSERE_LOG_PROCESSAMENTO('po_vObservacaoMotivo: ' || po_vObservacaoMotivo || ' (NAO_ATENDEU_VALOR_MINIMO)');      
      
    
      
    END IF;
  
   /*************************************************************************************************
                            PREVISÃO DE ATENDIMENTO PARA CRÍTICA DE VALOR MÍNIMO
                                                F I M     
    **************************************************************************************************/ 
  
   
  
  
   /*************************************************************************************************
                                              I N I C I O
                                   CARGA DO ARRAY DE ITENS DO PEDIDO
    **************************************************************************************************/ 
   
    -- ITENS DO PEDIDO PARA PROCESSAMENTO ------------------------------------------------------------
    
    -- Se tem Itens para Processamento
    IF (vtPED_NUMPED.COUNT > 0) THEN
  
      -- LAÇO DE ITENS DO PEDIDO PARA PROCESSAMENTO
      FOR viSeqItemPed IN vtPED_NUMPED.FIRST..vtPED_NUMPED.LAST LOOP
      
        -- Limpa Record
        vrItemPedido := vrLimpaItemPedido;     
          
        -- Inicializa Dados do Item do Pedido
        vrItemPedido.vnCodProd               := vtPED_CODPROD(viSeqItemPed);
        vrItemPedido.vvCodFilialRetira       := vtPED_CODFILIALRETIRA(viSeqItemPed);
        vrItemPedido.vnQtdePedido            := NVL(vtPED_QT(viSeqItemPed),0);
        vrItemPedido.vnPVenda                := NVL(vtPED_PVENDA(viSeqItemPed),0);
        vrItemPedido.vnPTabela               := NVL(vtPED_PTABELA(viSeqItemPed),0);
        vrItemPedido.vnPBaseRca              := NVL(vtPED_PBASERCA(viSeqItemPed),0);
        vrItemPedido.vnNumSeq                := NVL(vtPED_NUMSEQ(viSeqItemPed),0);
        vrItemPedido.vvItemCancelado         := vtPED_ITEMCANCELADO(viSeqItemPed);
        vrItemPedido.vvBonific               := vtPED_BONIFIC(viSeqItemPed);
        vrItemPedido.vvMotivoCancelamentoMed := vtPED_MOTIVOCANCELAMENTOMED(viSeqItemPed);
        vrItemPedido.vnSt                    := NVL(vtPED_ST(viSeqItemPed),0);
        vrItemPedido.vnStPBaseRca            := NVL(vtPED_STPBASERCA(viSeqItemPed),0);
        vrItemPedido.vnVlSaldoRca            := NVL(vtPED_VLSALDORCA(viSeqItemPed),0);
        vrItemPedido.vnCodPromocaoMed        := NVL(vtPED_CODPROMOCAOMED(viSeqItemPed),0);
  
        -- Inicializa Filial para Baixa do Estoque
        vrItemPedido.vvCodFilialBaixaEstoque := NVL(vrItemPedido.vvCodFilialRetira, vrPedido.vvCodFilial);
        
        -- Inicializa a Qtde. Atendida com a Qtde. do Pedido
        vrItemPedido.vnQtdeAtendida          := NVL(vtPED_QT(viSeqItemPed),0);
             
        -- Pesquisa Valores Anteriores na PCPEDI para o Processo de Estorno de Estoque e C/C RCA
        FUNCOES_MED.P_OBTER_VALORES_ANTERIOR(pi_nNumPed,
                                             vrItemPedido.vnCodProd,
                                             vrItemPedido.vnNumSeq,
                                             vrItemPedido.OLD_nQT,
                                             vrItemPedido.OLD_nVLSALDORCA,
                                             vrItemPedido.OLD_nQTSALDORCA,
                                             vrItemPedido.OLD_vPOSICAO);
        
        --------------------------------------------------------------
        -- INSERE DADOS DO ITEM DO PEDIDO EM LISTA -------------------
        --------------------------------------------------------------
        vtItensPedido(NVL(vtItensPedido.COUNT,0) + 1) := vrItemPedido;
      
      END LOOP; -- FIM: LAÇO DE ITENS DO PEDIDO PARA PROCESSAMENTO
      
    END IF; -- Fim Condição: Se tem Itens para Processamento
  
   /*************************************************************************************************
                                   CARGA DO ARRAY DE ITENS DO PEDIDO
                                                F I M     
    **************************************************************************************************/ 
  
  
  
  
  
   /**************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
  
                                               I N I C I O
                                               
                                M O T I V O S   D E   B L O Q U E I O S
  
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************/ 

    IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) THEN

      --------------------------------------------------
      -- INCLUSAO DOS BLOQUEIOS (vbATENDEU_VALOR_MINIMO)
      --------------------------------------------------
      FOR vc_Bloqueios IN (SELECT PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO                                
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTBLOQUEIO
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.VALORVALIDACAO
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.VALORATINGIDO
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.CODPLPAG
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO
                                , PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO
                             FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                            WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.NUMPED         = pi_nNumPed) 
                              AND (PCMED_VALIDACAO_ESTOQUE_RESERV.VENDAPERMITIDA = 'N')
                              AND (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO           IN ('P','B','A'))) LOOP
        P_INSERIR_MOTIVO_BLOQ(pi_nNumPed,
                              vc_Bloqueios.CODMOTIVO,
                              vc_Bloqueios.MOTIVOPOSICAO,
                              vc_Bloqueios.CODMOTBLOQUEIO,
                              vc_Bloqueios.CODPLPAG,
                              vc_Bloqueios.CODREJEICAO,
                              vc_Bloqueios.DESCRICAOREJEICAO,
                              vc_Bloqueios.OBSERVACAO);
        -- Log
        IF (NVL(vc_Bloqueios.VALORVALIDACAO,0) > 0) THEN
          P_INSERE_LOG_PROCESSAMENTO('Inclusão de Bloqueio: ' || vc_Bloqueios.CODREJEICAO || ' - ' || vc_Bloqueios.DESCRICAOREJEICAO || ' [Valor Validação: ' || vc_Bloqueios.VALORVALIDACAO || '; Valor Atingido: ' || vc_Bloqueios.VALORATINGIDO || ']');
        ELSE
          P_INSERE_LOG_PROCESSAMENTO('Inclusão de Bloqueio: ' || vc_Bloqueios.CODREJEICAO || ' - ' || vc_Bloqueios.DESCRICAOREJEICAO);
        END IF;
      END LOOP;
      
      --------------------------
      -- LIBERAÇÃO DOS BLOQUEIOS
      --------------------------
      IF (NVL(pi_nCodRotina,0)   = 2336) AND
         (pi_vChamadaProcesso    = 'MP') THEN
        
        -- DDMEDICA-4851 - No processo de Libera o Pedido por Motivos de Bloqueio, 
        -- precisa executar a liberação dos Bloqueios da Matricula, 
        -- mesmo que o Pedido continue como bloqueado
        -- DDVENDAS-35974 - Liberação do Balcão Recebe chega com a Posição M
        IF ((NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'N') AND (po_vPosicaoFinalPedido IN ('L','M'))) OR
           ((NVL(vrParametros.vUSAREGRAPERMISSAO,'N') = 'S') AND (po_vPosicaoFinalPedido IN ('L','M','B'))) THEN
           
          -- Chama procedimento para Liberação dos Bloqueios
          P_LIBERAR_MOTIVO_BLOQ(pi_nNumPed,
                                pi_nMatricula,
                                vvBloqueioPendente,
                                vnCodMotivoBloqueioPendente,
                                vvMotivoBloqueioPendente,
                                vvObservacaoBloqueioPendente);
          
          -- Se ainda ficou algum bloqueio pendente
          IF (vvBloqueioPendente = 'S') THEN
            -- Volta a posição para Bloqueado
            po_vPosicaoFinalPedido := 'B';
            -- Motivo do Pedido
            P_GERAR_TEXTO_LOG_BLOQUEIO(vnCodMotivoBloqueioPendente,
                                       vvMotivoBloqueioPendente,
                                       NVL(vvObservacaoBloqueioPendente,vvMotivoBloqueioPendente),
                                       po_nCodMotivo,
                                       po_vMotivoPosicao,
                                       po_vObservacaoMotivo);
            -- Log
            P_INSERE_LOG_PROCESSAMENTO('Existem Bloqueios Pendentes de Liberação por outras Matrículas');        
          ELSE
            -- Log
            P_INSERE_LOG_PROCESSAMENTO('Sem Bloqueios Pendentes de Liberação');        
          END IF;                   
          
        ELSE

          -- Log
          P_INSERE_LOG_PROCESSAMENTO('Posição Final ao Mudar a Posição do Pedido: ' || po_vPosicaoFinalPedido);        
        
        END IF;
                                          
      END IF; -- FIM: LIBERAÇÃO DOS BLOQUEIOS
  
    END IF;
    
    IF (pi_vChamadaProcesso IN ('VM','LB')) THEN
    
      ------------------------
      -- INCLUSÃO DO HISTÓRICO
      ------------------------
      P_HISTORICO_MOTIVO_BLOQ(pi_vChamadaProcesso,
                              pi_nNumPed,
                              pi_nMatricula);

    END IF;
    
    
    -- Log
    P_INSERE_LOG_PROCESSAMENTO('po_vPosicaoFinalPedido: ' || po_vPosicaoFinalPedido || ' (SITUACAO_FINAL)');
    P_INSERE_LOG_PROCESSAMENTO('po_vMotivoPosicao: ' || po_vMotivoPosicao || ' (SITUACAO_FINAL)');
    P_INSERE_LOG_PROCESSAMENTO('po_vObservacaoMotivo: ' || po_vObservacaoMotivo || ' (SITUACAO_FINAL)');      
    
   
   /**************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
                                                 
                                M O T I V O S   D E   B L O Q U E I O S
  
                                                 F I M

    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************/ 
  


     
          
   /**************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
  
                                               I N I C I O
                                               
                      P R O C E S S O    D E    B A I X A    D E    E S T O Q U E     
  
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************/ 
    IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) THEN
    
    
      
      ------- ATUALIZA TOTAIS DO PEDIDO --------
      IF (pi_nCodRotina NOT IN (2336,2641)) THEN
        P_ATUALIZAR_TOTAIS_PEDIDO('S',
                                  pi_nNumPed);
      END IF;
      --
      IF (pi_nCodRotina = 2336) AND 
         (pi_vChamadaProcesso = 'EP') THEN
        -- DDMEDICA-5000 - Se chamado da 2336 ao aumentar por exemplo a quantidade do item, preciso recalcular também o VLTOTAL
        P_ATUALIZAR_TOTAIS_PEDIDO('S',
                                  pi_nNumPed);
      END IF;
  
      -- Verifica se pode realizar o Processo da Baixa do Estoque
      vbPodeProcessoBaixaEstoque := TRUE;
      IF (pi_vChamadaProcesso = 'GP') AND
         (NVL(vrPedido.vvStatusProcessamentoMed,'N') IN ('E','S','F')) THEN
        -- Se na Gravação do Pedido já realizou o Processo de Baixa de Estoque dos Itens do Pedido, não permitirá fazê-lo novamente        
        -- (Obs: Status S e F são etapas posteriores, ou seja, já passaram pela Baixa do Estoque)
        vbPodeProcessoBaixaEstoque := FALSE;
      END IF;
      
      
     /***********************************************************************************************
      SE PODE SER REALIZADO O PROCESSO DE BAIXA DE ESTOQUE
      ****************************************************/ 
      IF (vbPodeProcessoBaixaEstoque) THEN
      
    
        -----------------------------------------------------------------------------------
        --- SALVA POSIÇÃO DO ROLLBACK EM TODAS AS CHAMADAS ANTES DE ATUALIZAR O ESTOQUE ---
        -----------------------------------------------------------------------------------
        SAVEPOINT inicio_gravar_pedido;
        vbUsouSavePoint := TRUE;
         
        -- Atualiza Status do Pedido, indicando que vai realizar o Processo de Atualização do Estoque
        P_ATU_STATUS_PROCESSAMENTO(pi_vChamadaProcesso,
                                   'E',
                                   vrPedido.vvStatusProcessamentoMed);
  
  
       /***********************************************************************************************
        SE O PEDIDO PODE BAIXAR O ESTOQUE
        *********************************/ 
        IF (vbPedidoPodeAtualizarEstoque) THEN
     
    
         /*************************************************************************************************
                                                   I N I C I O
                                          ESTORNO DA MUDANÇA DE POSIÇÃO
          **************************************************************************************************/ 
          IF (vtItensPedido.COUNT > 0) THEN -- Se tem Itens no Pedido
        
            -- LAÇO DE ITENS DO PEDIDO PARA ESTORNAR A QUANTIDADE CANCELADA
            FOR viSeqItemPed IN vtItensPedido.FIRST..vtItensPedido.LAST LOOP
        
              -- Pega Dados Do Item do Pedido em Lista
              vrItemPedido := vtItensPedido(viSeqItemPed);
              
              -- DDVENDAS-31376 - Se houve modificação de posição ou quantidade
              IF (NVL(vrItemPedido.vvItemCancelado,'N') = 'S')                           OR
                 (NVL(vrItemPedido.OLD_nQT,0) <> NVL(vrItemPedido.vnQtdePedido,0))                OR
                 (NVL(vrItemPedido.OLD_vPOSICAO,' ') <> NVL(po_vPosicaoFinalPedido,' ')) THEN
                -- Verifica se o WMS puxou o Pedido que está sendo Editado na 2316
                IF (F_MED_VALIDA_ENVIO_WMS(pi_nNumPed,
                                           pi_nCodRotina,
                                           pi_vChamadaProcesso) = 'S') THEN
                  RAISE e_EstoqueReservUsoWms;
                END IF;
              END IF;                                     
              
              -- Se o item existia no banco de dados (QT > 0)
              IF (NVL(vrItemPedido.OLD_nQT,0) > 0) THEN
                
                -- Se o item foi cancelado ou se vai ocorrer Mudança de Posição
                IF (NVL(vrItemPedido.vvItemCancelado,'N') = 'S') OR
                   (NVL(vrItemPedido.OLD_vPOSICAO,' ') <> NVL(po_vPosicaoFinalPedido,' ')) THEN
              
                  --------------------------------------------
                  -- ESTORNO DA QUANTIDADE NA POSIÇÃO ANTERIOR
                  --------------------------------------------
        
                  -- Origem Chamada
                  IF    (pi_nCodRotina = 2316) THEN -->> CHAMADO DA ROTINA 2316
                    vnOrigemChamadaReservaEst := 2;
                  ELSIF (pi_nCodRotina = 2336) THEN -->> CHAMADO DA ROTINA 2336
                    vnOrigemChamadaReservaEst := 3;
                  ELSIF (pi_nCodRotina = 2513) THEN -->> CHAMADO DA INTEGRADORA_MED
                    vnOrigemChamadaReservaEst := 4;
                  ELSIF (pi_nCodRotina = 2312) THEN -->> CHAMADO DA ROTINA 2312
                    vnOrigemChamadaReservaEst := 7;
                  ELSIF (pi_nCodRotina = 2641) THEN -->> CHAMADO DA ROTINA 2641
                    vnOrigemChamadaReservaEst := 8;
                  END IF;
        
                  -- Se a Posição anterior do Item estiver como Montado/Liberado
                  IF    (NVL(vrItemPedido.OLD_vPOSICAO,' ') IN ('L','M')) THEN
                    vvOperacaoReservaEst   := 'BR'; -- 'BR' - Baixar Reserva
                  -- Se a Posição anterior do Item estiver como Bloqueado/Pendente
                  ELSIF (NVL(vrItemPedido.OLD_vPOSICAO,' ') IN ('B','P')) THEN
                    vvOperacaoReservaEst   := 'BP'; -- 'BP' - Baixar Pendente
                  ELSE
                    -- Aqui como é Estorno, pode ser que não tinha Posição Anterior (Item novo).
                    -- Por isso aqui não tem exceção no ELSE
                    vvOperacaoReservaEst   := NULL; 
                  END IF;        
                          
                  -- Se vai Atualizar o Estoque (Se achou Posição Anterior)
                  IF (vvOperacaoReservaEst IS NOT NULL) THEN 
        
                    -- Chama Procedimento para Reservar o Estoque
                    P_ESTOQUE_RESERV_ITEM_01(vnOrigemChamadaReservaEst,
                                             vvOperacaoReservaEst,
                                             vrItemPedido.vvCodFilialBaixaEstoque, -->> FILIAL PARA BAIXAR O ESTOQUE
                                             pi_nNumPed,
                                             vrItemPedido.vnCodProd,
                                             vrItemPedido.vnNumSeq,
                                             NVL(vrItemPedido.OLD_nQT,0), -->> QTDE DO PEDIDO ESTÁ SENDO ESTORNADA
                                             'S', -- pi_vPedidoExiste,
                                             vvOcorreramErrosEstoqueReserv,
                                             vvMsgErrosEstoqueReserv);
                    IF (vvOcorreramErrosEstoqueReserv = 'S') THEN
                      -- DDMEDICA-6582 - Adicionar à mensagem do erro a posição do pedido
                      P_INC_MENSAGEM_ERRO_RESERVADO(pi_nNumPed,
                                                    vrItemPedido.vnCodProd,
                                                    vrItemPedido.vnNumSeq,
                                                    vvOperacaoReservaEst,
                                                    vvMsgErrosEstoqueReserv);                    
                      RAISE e_EstoqueReservEstorno;
                    END IF;
                  
                    -- Log: Cancelamento do Item
                    P_INSERE_LOG_PROCESSAMENTO('Estorno Estoque Posição Seq. Item Pedido = ' || vrItemPedido.vnNumSeq                || CHR(13) ||
                                               'vvCodFilialBaixaEstoque = '                  || vrItemPedido.vvCodFilialBaixaEstoque || CHR(13) ||
                                               'OLD_nQT = '                                  || vrItemPedido.OLD_nQT            || CHR(13) ||
                                               'vvOperacaoReservaEst = '                     || vvOperacaoReservaEst                 || CHR(13) ||
                                               'vvItemCancelado = '                          || vrItemPedido.vvItemCancelado,
                                               vrItemPedido.vnCodProd);                                                                                        
                  
                  END IF; -- FIM CONDIÇÃO: Se vai Atualizar o Estoque (Se achou Posição Anterior)
                
                END IF; -- FIM CONDIÇÃO: Se o item foi cancelado ou se vai ocorrer Mudança de Posição
             
              END IF; -- FIM CONDIÇÃO: Se o item existia no banco de dados (QT > 0)
        
            END LOOP; -- FIM: LAÇO DE ITENS DO PEDIDO PARA ESTORNAR A QUANTIDADE CANCELADA
            
          END IF; -- FIM: Se tem Itens no Pedido
         /*************************************************************************************************
                                           ESTORNO DA MUDANÇA DE POSIÇÃO
                                                      F I M     
          **************************************************************************************************/ 
    
     
            
         /*************************************************************************************************
                                                   I N I C I O
                                                RESERVA DO ESTOQUE
          **************************************************************************************************/ 
          
          -- Se tem Itens no Pedido
          IF (vtItensPedido.COUNT > 0) THEN
          
            -- DDMEDICA-6582 - A partir da versão 30.3 é requerido que o Pedido já esteja na Posição Final
            UPDATE PCPEDC
               SET POSICAO = po_vPosicaoFinalPedido
             WHERE (NUMPED = pi_nNumPed);          
                
            -- LAÇO DE ITENS DO PEDIDO PARA RESERVA DO ESTOQUE -------------------------------------------
            FOR viSeqItemPed IN vtItensPedido.FIRST..vtItensPedido.LAST LOOP
          
              -- Pega Dados Do Item do Pedido em Lista
              vrItemPedido := vtItensPedido(viSeqItemPed);
              
              -- Se o Item NÃO ESTÁ Cancelado ------------------------------------------------------------
              IF (NVL(vrItemPedido.vvItemCancelado,'N') <> 'S') THEN                                   
              
    
                -- SE MUDOU A QUANTIDADE OU VAI MUDAR A POSIÇÃO DO ITEM DO PEDIDO ------------------------
                -- (Se a Quantidade e Posição Anterior do item no Banco de Dados for a mesma,
                -- indica que já passou por este processo mas ocorreu algum problema na 
                -- finalização do Pedido, então não precisa gastar tempo de processamento 
                -- porque não haverá nada a atualizar)
                IF (NVL(vrItemPedido.OLD_nQT,0)        <> NVL(vrItemPedido.vnQtdePedido,0)) OR
                   (NVL(vrItemPedido.OLD_vPOSICAO,' ') <> NVL(po_vPosicaoFinalPedido,' '))  THEN  
    
        
                  ------------------------------------------------------------------------------------------
                  ------------------------------------------------------------------------------------------
                  --                                   I N I C I O                                        --
                  --                SE ESTIVER GRAVANDO O PEDIDO COMO LIBERADO OU MONTADO,                --
                  --            CALCULA A QUANTIDADE A QUANTIDADE ATENDIDA ABATENDO AS FALTAS             --
                  ------------------------------------------------------------------------------------------
                  ------------------------------------------------------------------------------------------
                  IF (po_vPosicaoFinalPedido IN ('L','M')) OR
                     (NVL(vvCortarItemSemEstPedBloq,'N') = 'S') THEN -- MED-2625

                    vnEstoqueMultiplo := 0; -- DDVENDAS-41227
                
                    -------------------------------------------
                    -- Pesquisa Informações de Estoque da PCEST 
                    -- (Informações atualizadas com o Estorno)
                    -------------------------------------------
                    
                    -- Chama Função da Logística para Obter o Estoque Disponível
                    IF     (NVL(vrPedido.vvPedidoAvaria,'N') = 'S')     THEN -- DDMEDICA-619
                      BEGIN
                        SELECT PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_AVARIA(CODPROD,
                                                                            CODFILIAL) QTDISPONIVEL
                          INTO vnEstoqueDisponivel
                          FROM PCEST
                         WHERE (CODPROD   = vrItemPedido.vnCodProd)
                           AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vnEstoqueDisponivel := 0;
                      END;
                    ELSIF (NVL(vrPedido.vnNumTransEntCrossDock,0) > 0) THEN -- DDMEDICA-619
                      BEGIN
                        SELECT PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_BLOQ(CODPROD,
                                                                          CODFILIAL) QTDISPONIVEL
                          INTO vnEstoqueDisponivel
                          FROM PCEST
                         WHERE (CODPROD   = vrItemPedido.vnCodProd)
                           AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vnEstoqueDisponivel := 0;
                      END;
                    ELSIF (NVL(pi_nCodRotina,0) = 2336) THEN
                      --DDMEDICA-1008
                      IF (NVL(vrParametros.vVALIDARQTCONTGRAVACAOPED,'N') = 'S') OR (NVL(vrParametros.vCON_VERIFICAESTOQUECONT,'N') = 'S') THEN
                        BEGIN
                          SELECT LEAST(PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISPPEND(CODPROD,CODFILIAL,NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)),PKG_FUNCOESVENDAS_MED.F_OBTER_EST_CONTAB_DISP(CODPROD, CODFILIAL,'S')) QTDISPONIVEL
                            INTO vnEstoqueDisponivel
                            FROM PCEST
                           WHERE (CODPROD   = vrItemPedido.vnCodProd)
                             AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                        EXCEPTION
                          WHEN NO_DATA_FOUND THEN
                            vnEstoqueDisponivel := 0;
                        END;
                      ELSE
                      BEGIN
                        SELECT PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISPPEND(CODPROD,
                                                                              CODFILIAL,
                                                                              NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)) QTDISPONIVEL
                          INTO vnEstoqueDisponivel
                          FROM PCEST
                         WHERE (CODPROD   = vrItemPedido.vnCodProd)
                           AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vnEstoqueDisponivel := 0;
                      END;
                      END IF;               
                    ELSIF (NVL(pi_nCodRotina,0) = 2641) THEN
                      -- DDMEDICA-1147
                      BEGIN
                        SELECT PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISPPEND(CODPROD,
                                                                              CODFILIAL) QTDISPONIVEL
                          INTO vnEstoqueDisponivel
                          FROM PCEST
                         WHERE (CODPROD   = vrItemPedido.vnCodProd)
                           AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vnEstoqueDisponivel := 0;
                      END;
                    ELSE
                      
                      --DDMEDICA-1008
                      IF (NVL(vrParametros.vVALIDARQTCONTGRAVACAOPED,'N') = 'S') OR (NVL(vrParametros.vCON_VERIFICAESTOQUECONT,'N') = 'S') THEN
                        BEGIN
                          SELECT LEAST(PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISP(CODPROD,CODFILIAL,NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)),PKG_FUNCOESVENDAS_MED.F_OBTER_EST_CONTAB_DISP(CODPROD, CODFILIAL)) QTDISPONIVEL
                            INTO vnEstoqueDisponivel
                            FROM PCEST
                           WHERE (CODPROD   = vrItemPedido.vnCodProd)
                             AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                        EXCEPTION
                          WHEN NO_DATA_FOUND THEN
                            vnEstoqueDisponivel := 0;
                        END;   
                      ELSE
                        BEGIN
                          SELECT PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISP(CODPROD,
                                                                            CODFILIAL,
                                                                            NVL(vrPedido.vnOpcaoLimitarVendaEstMin,0)) QTDISPONIVEL
                            INTO vnEstoqueDisponivel
                            FROM PCEST
                           WHERE (CODPROD   = vrItemPedido.vnCodProd)
                             AND (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque);
                        EXCEPTION
                          WHEN NO_DATA_FOUND THEN
                            vnEstoqueDisponivel := 0;
                        END;
                      END IF;
                    END IF;
                    
                    -- Não deixa Saldo Estoque Negativo
                    IF (NVL(vnEstoqueDisponivel,0) < 0) THEN
                      vnEstoqueDisponivel := 0;
                    END IF;
                    
                    -- Se o Item estava Liberado, devolve ao Estoque Disponivel a Qtde. Anterior,
                    -- para não dar corte quando estiver editando um Pedido Liberado onde alterou somente a quantidade
                    IF (vrItemPedido.OLD_vPOSICAO IN ('L','M')) THEN
                      vnEstoqueDisponivel := NVL(vnEstoqueDisponivel,0) + NVL(vrItemPedido.OLD_nQT,0); 
                    END IF;

                    ------------------------------------------------------------
                    -- RECALCULO DA QUANTIDADE ATENDIDA com o Estoque Atualizado
                    ------------------------------------------------------------
                        
                    -- Se não tem Quantidade suficiente para atender a Quantidade do Item do Pedido
                    IF (NVL(vnEstoqueDisponivel,0) < NVL(vrItemPedido.vnQtdeAtendida,0)) THEN              

                      -- A Quantidade Atendida será Restringida ao Estoque Disponivel
                      vrItemPedido.vnQtdeAtendida := NVL(vnEstoqueDisponivel,0);

                      ------------------------------------------------------------------
                      -- RECALCULO DA QUANTIDADE ATENDIDA quando Multiplo DDVENDAS-41227
                      ------------------------------------------------------------------

                      vnEstoqueMultiplo := F_OBTER_ESTOQUE_MULTIPLO(vrPedido.vnCodCli,
                                                                    vrPedido.vnCondVenda,
                                                                    vrItemPedido.vnCodProd,
                                                                    vrItemPedido.vnQtdeAtendida,
                                                                    vrPedido.vvCodFilial,
                                                                    NVL(vnEstoqueDisponivel,0));

                      -- Se não tem Quantidade Multipla suficiente para atender a Quantidade do Item do Pedido
                      IF (NVL(vnEstoqueMultiplo,0) > 0) AND
                         (NVL(vnEstoqueMultiplo,0) < NVL(vrItemPedido.vnQtdeAtendida,0)) THEN              

                        -- A Quantidade Atendida será Restringida ao Estoque Multiplo Disponivel
                        vrItemPedido.vnQtdeAtendida := NVL(vnEstoqueMultiplo,0);

                      END IF;

                    END IF;               

                    ----------------------------------
                    -- CALCULO DA QUANTIDADE DE FALTAS
                    ----------------------------------
                    
                    -- Calcula a Quantidade de Faltas
                    vnQtdeFalta := (NVL(vrItemPedido.vnQtdePedido,0) - NVL(vrItemPedido.vnQtdeAtendida,0));
                      
                    -- Calcula a Quantidade de Faltas que serão guardadas
                    IF (NVL(pi_vGuardaFalta,'N') = 'S') THEN
                      vnQtdeGuardaFalta := NVL(vnQtdeFalta,0);
                    ELSE
                      vnQtdeGuardaFalta := 0;
                    END IF;  
                                    
                    --------------------------------------
                    -- ATUALIZAÇÃO DAS FALTAS NA PCPEDI --
                    --------------------------------------
    
                    IF (NVL(vnQtdeFalta,0) > 0) THEN
                    
                      -- OBS: Por causa do Conta-Corrente, não pode excluir o item neste momento, se não tiver quantidade atendida,
                      --      é imprescindível gravar 0 (zero) para não dar NO_DATA_FOUND
                      UPDATE PCPEDI
                         SET QT      = NVL(vrItemPedido.vnQtdeAtendida,0)
                           , QTFALTA = NVL(vnQtdeFalta,0)
                       WHERE (NUMPED  = pi_nNumPed)
                         AND (CODPROD = vrItemPedido.vnCodProd)
                         AND (NUMSEQ  = vrItemPedido.vnNumSeq);
                              
                      -- Retorno que indica se Existem Faltas
                      po_vExistemFaltas        := 'S';
                      
                      -- IMPORTANTE: Para saber que houve corte no Estorno do Saldo do Conta Corrente do RCA
                      vrItemPedido.vvCorte     := 'S';                
                      vrItemPedido.vnQtdeCorte := NVL(vnQtdeFalta,0);
                      
                    END IF;
                    
                    
                    ---------------------------------------------------
                    -- ATUALIZAÇÃO DA INFORMAÇÃO DA FALTA POR ALVARÁ --
                    ---------------------------------------------------
                    
                    -- Se está chamando do Corte por Alvará e Registrou Motivo da Alterção por Qtde.
                    IF (NVL(pi_vGuardaFalta,'N') = 'A')                   AND
                       (vrItemPedido.vvMotivoCancelamentoMed IS NOT NULL) THEN                  
                    
                      -- Log: Cancelamento do Item
                      P_INSERE_LOG_PROCESSAMENTO('Corte Alvara Seq Item Pedido = ' || vrItemPedido.vnNumSeq || CHR(13) ||
                                                 'OLD_nQT = '                      || vrItemPedido.OLD_nQT  || CHR(13) ||
                                                 'vnQtdePedido = '                 || vrItemPedido.vnQtdeAtendida,
                                                 vrItemPedido.vnCodProd);                                                                                        
                     
                      -- Pega Motivo do Cancelamento do Item
                      vvMotivoCancelamentoResumido  := SUBSTR(vrItemPedido.vvMotivoCancelamentoMed, 1,  100);
                      vvMotivoCancelamentoDetalhado := SUBSTR(vrItemPedido.vvMotivoCancelamentoMed, 1, 2000);
                
                      -- Não deixa o Motivo do Cancelamento ficar Nulo
                      IF (vvMotivoCancelamentoResumido IS NULL) THEN
                        vvMotivoCancelamentoResumido  := 'CANCELAMENTO ITEM PEDIDO';
                      END IF;
                      IF (vvMotivoCancelamentoDetalhado IS NULL) THEN
                         vvMotivoCancelamentoDetalhado := 'CANCELAMENTO ITEM PEDIDO';
                      END IF;
                                                       
                      -- Insere no Log de Itens Excluídos
                      INSERT INTO PCNFCANITEM
                                ( NUMPED
                                , CODROTINA
                                , MOTIVO
                                , CODCLI
                                , CODPROD
                                , PVENDA
                                , PTABELA
                                , NUMSEQ
                                , DATACANC
                                , CODFUNCCANC
                                , DATAEMISSAO 
                                , CODFUNCEMITE
                                , DESCRICAO
                                , CODUSUR
                                , NUMCAR
                                , QT
                                , HORACANC
                                , PBASERCA )
                         VALUES ( pi_nNumPed
                                , pi_nCodRotina -->> Código da Rotina
                                , SUBSTR(vvMotivoCancelamentoResumido, 1, 60)
                                , vrPedido.vnCodCli
                                , vrItemPedido.vnCodProd
                                , vrItemPedido.vnPVenda
                                , vrItemPedido.vnPTabela
                                , vrItemPedido.vnNumSeq
                                , TRUNC(SYSDATE)
                                , pi_nMatricula
                                , TRUNC(SYSDATE)
                                , pi_nMatricula
                                , vvDescricaoExclusaoPedido
                                , vrPedido.vnCodUsur
                                , 0
                                , (NVL(vrItemPedido.OLD_nQT,0) - vrItemPedido.vnQtdeAtendida) -->> Qtde Cortada
                                , SYSDATE
                                , vrItemPedido.vnPBaseRca );
                 
                      -- Log de Alteração de Dados
                      P_INSERE_LOG_ALTERACAO_DADOS('N',
                                                   pi_nNumPed,
                                                   vrItemPedido.vnCodProd,
                                                   vrItemPedido.vnNumSeq,
                                                   'PCPEDI',
                                                   'QT',
                                                   NULL,
                                                   NULL,
                                                   0,
                                                   (NVL(vrItemPedido.OLD_nQT,0) - vrItemPedido.vnQtdeAtendida),
                                                   SUBSTR(vvMotivoCancelamentoResumido, 1, 60),
                                                   'EXCLUSÃO DO ITEM NA PCPEDI QUANDO HOUVER CANCELAMENTO DO ITEM - PROCEDIMENTO PRC_MED_ESTOQUE_RESERVADO_01 - ' || vvMotivoCancelamentoDetalhado);              
  
                    END IF; -- FIM: ATUALIZAÇÃO DA INFORMAÇÃO DA FALTA POR ALVARÁ
                    
                    --------------------------------------------------------------
                    --           FALTAS PARA GERAR LOG DA 2312                  --
                    -- (Como 2312 não valida valor mínimo, tem que gravar aqui) --
                    -- (Idem 2641 não valida valor mínimo, tem que gravar aqui) --
                    --------------------------------------------------------------
                    IF (pi_nCodRotina IN (2312,2641)) AND
                       (NOT vbValidarValorMinimo)     THEN
                    
                      -- Grava Tabela Temporária de Itens Faltantes
                      INSERT INTO PCMED_FALTAS_ESTOQUE_RESERV
                                ( NUMPED
                                , CODPROD
                                , NUMSEQ
                                , DESCRICAO
                                , QTDEORIGINAL
                                , VALORORIGINAL
                                , QTDEATENDIDA
                                , VALORATENDIDO
                                , QTDEFALTA
                                , VALORFALTA
                                , ESTOQUEDISPONIVEL )
                         VALUES ( pi_nNumPed
                                , vrItemPedido.vnCodProd
                                , vrItemPedido.vnNumSeq
                                , SUBSTR((SELECT DESCRICAO FROM PCPRODUT WHERE PCPRODUT.CODPROD = vrItemPedido.vnCodProd),1,200)
                                , vrItemPedido.vnQtdePedido
                                , ROUND((vrItemPedido.vnPVenda * vrItemPedido.vnQtdePedido),2)
                                , vrItemPedido.vnQtdeAtendida
                                , ROUND((vrItemPedido.vnPVenda * vrItemPedido.vnQtdeAtendida),2)
                                , vnQtdeFalta 
                                , ROUND((vrItemPedido.vnPVenda * vnQtdeFalta),2)
                                , vnEstoqueDisponivel );
                                
                    END IF; -- Fim Condição: FALTAS PARA GERAR LOG DA 2312/2641
                                      
                    ----------------------------------
                    -- CORTE DO COMBO VIRTUAL (KIT) --
                    ----------------------------------
                    
                    -- Inicializa Variável de Corte por Combo
                    vrItemPedido.vvCorteCombo := 'N';
                    
                    -- Verifica se houve Corte do Combo
                    BEGIN
                      SELECT CORTECOMBO
                        INTO vrItemPedido.vvCorteCombo
                        FROM PCMED_FALTAS_ESTOQUE_RESERV
                       WHERE (NUMPED  = pi_nNumPed)
                         AND (CODPROD = vrItemPedido.vnCodProd)
                         AND (NUMSEQ  = vrItemPedido.vnNumSeq)
                         AND (ROWNUM  = 1);
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vrItemPedido.vvCorteCombo := NULL;
                    END;                         
                                      
                    
                   /*****************************************************************************************
                    **********************************************
                    *         GRAVAÇÃO DO CORTE DO COMBO         *
                    **********************************************
                    **********************************************/
                    IF (NVL(vrItemPedido.vvCorteCombo,'X') IN ('P','S')) THEN
                      
                      --------------------------------------------------------------
                      --        INCLUSAO DO LOG DAS FALTAS SE GUARDA FALTAS       --
                      -- (Somente os Itens do Combo que realmente tiveram Faltas) --
                      --------------------------------------------------------------
                      IF (NVL(vrItemPedido.vvCorteCombo,'X') = 'P') AND -->> Principal
                         (NVL(vnQtdeGuardaFalta,0) > 0)             THEN
                      
                        -- Insere Falta no Log
                        BEGIN
                          INSERT INTO PCFALTA
                                    ( NUMPED
                                    , DATA
                                    , CODPROD
                                    , CODUSUR
                                    , CODCLI
                                    , QT
                                    , PVENDA
                                    , CODFILIAL
                                    , NUMSEQ )
                             VALUES ( pi_nNumPed
                                    , TRUNC(SYSDATE)
                                    , vrItemPedido.vnCodProd
                                    , vrPedido.vnCodUsur
                                    , vrPedido.vnCodCli
                                    , NVL(vnQtdeGuardaFalta,0) -- Quantidade de Faltas que serão guardadas
                                    , vrItemPedido.vnPVenda
                                    , vrPedido.vvCodFilial 
                                    , vrItemPedido.vnNumSeq );
                        EXCEPTION
                          WHEN OTHERS THEN 
                            NULL;
                        END;                        
                                                                     
                      END IF; -- FIM CONDIÇÃO: INCLUSAO DO LOG DAS FALTAS SE GUARDA FALTAS          
                      
                      
                      ----------------------------------------------
                      -- SEM QUANTIDADE ATENDIDA PELO CORTE DO COMBO
                      ----------------------------------------------
                      
                      -- Atualiza Record
                      vrItemPedido.vnQtdeAtendida := 0;
                      
                      -- Atualiza PCPEDI                                   
                      UPDATE PCPEDI
                         SET QT      = 0
                       WHERE (NUMPED  = pi_nNumPed)
                         AND (CODPROD = vrItemPedido.vnCodProd)
                         AND (NUMSEQ  = vrItemPedido.vnNumSeq);
                                
                      -- Retorno que indica se Existem Faltas
                      po_vExistemFaltas        := 'S';
                        
                      -- IMPORTANTE: Para saber que houve corte no Estorno do Saldo do Conta Corrente do RCA
                      vrItemPedido.vvCorte     := 'S';                
                      vrItemPedido.vnQtdeCorte := NVL(vrItemPedido.vnQtdePedido,0);
                                                            
                      -- Insere no Log de Itens Excluídos
                      INSERT INTO PCNFCANITEM
                                ( NUMPED
                                , CODROTINA
                                , MOTIVO
                                , CODCLI
                                , CODPROD
                                , PVENDA
                                , PTABELA
                                , NUMSEQ
                                , DATACANC
                                , CODFUNCCANC
                                , DATAEMISSAO 
                                , CODFUNCEMITE
                                , DESCRICAO
                                , CODUSUR
                                , NUMCAR
                                , QT
                                , HORACANC
                                , PBASERCA )
                         VALUES ( pi_nNumPed
                                , pi_nCodRotina -->> Código da Rotina
                                , SUBSTR('CORTE TOTAL COMBO VIRTUAL (KIT) ' || '(' || vrItemPedido.vvCorteCombo || ')', 1, 60)
                                , vrPedido.vnCodCli
                                , vrItemPedido.vnCodProd
                                , vrItemPedido.vnPVenda
                                , vrItemPedido.vnPTabela
                                , vrItemPedido.vnNumSeq
                                , TRUNC(SYSDATE)
                                , pi_nMatricula
                                , TRUNC(SYSDATE)
                                , pi_nMatricula
                                , vvDescricaoExclusaoPedido
                                , vrPedido.vnCodUsur
                                , 0
                                , NVL(vrItemPedido.vnQtdePedido,0) -->> Qtde Cortada
                                , SYSDATE
                                , vrItemPedido.vnPBaseRca );
                                      
                      -- Log de Alteração de Dados
                      P_INSERE_LOG_ALTERACAO_DADOS('N',
                                                   pi_nNumPed,
                                                   vrItemPedido.vnCodProd,
                                                   vrItemPedido.vnNumSeq,
                                                   'PCPEDI',
                                                   'QT',
                                                   NULL,
                                                   NULL,
                                                   0,
                                                   NVL(vrItemPedido.vnQtdePedido,0),
                                                   SUBSTR('CORTE TOTAL DO COMBO VIRTUAL (KIT) ' || '(' || vrItemPedido.vvCorteCombo || ')', 1, 60),
                                                   'EXCLUSÃO DO ITEM NA PCPEDI QUANDO HOUVER CORTE TOTAL DO COMBO VIRTUAL (KIT) - PROCEDIMENTO PRC_MED_ESTOQUE_RESERVADO_01 - ' || vvMotivoCancelamentoDetalhado);              
                                                
                                                                                                         
                    
                   /*****************************************************************************************
                    **********************************************
                    *   GRAVAÇÃO DO PEDIDO DE ITENS FALTANTES    *
                    **********************************************
                    **********************************************/
                    ELSIF (NVL(vnQtdeFalta,0) > 0)              AND
                          (vvGravarPedidoItensFalta = 'S')      AND
                          (po_vPosicaoFinalPedido IN ('L','M')) THEN
                    
                      -------------------------------------------------------
                      -- GERAÇÃO DO CABEÇALHO DO PEDIDO DE ITENS FALTANTES --
                      -------------------------------------------------------
                      IF (NOT vbGerouCabPedItensFaltantes) THEN
                        
                        -- Gera Cabeçallho do Pedido
                        FUNCOES_MED.P_DUPLICAR_PCPEDC(pi_nNumPed,
                                                      vnNumPedItensFaltantes,
                                                      vvOcorreramErrosCabPedFalta,
                                                      vvMsgErrosCabPedFalta);
                        IF (vvOcorreramErrosCabPedFalta = 'S') THEN
                          RAISE e_CabPedFalta;
                        END IF;
                        
                        -- Muda a Posição do Pedido com Itens Faltantes
                        -- OBS: O campo OBS deve ser mantido conforme implementado, uso esse texto para apresentar o Pedido de Itens Faltantes
                        --      no Resumo do Pedido >> AND (SUBSTR(UPPER(OBS),1,20) = UPPER('Ped. Itens Faltantes'))
                        UPDATE PCPEDC 
                           SET POSICAO     = 'P'
                             , OBS         = 'Ped. Itens Faltantes'
                             , LOG         = LOG || CHR(13) || TO_CHAR(SYSDATE,'DD/MM/YYYY HH24:MI:SS') || ' - ' || 'Pedido de Itens Faltantes referente ao Pedido ' || pi_nNumPed                   
                             , CODEMITENTE = NVL(CODEMITENTE,pi_nMatricula) -- DDMEDICA-3717
                         WHERE (NUMPED = vnNumPedItensFaltantes);
                         
                         -- Guarda a Referência do Pedido Faltante no Pedido Original
                         UPDATE PCPEDC
                            SET NUMPEDITENSFALTA = vnNumPedItensFaltantes 
                          WHERE (NUMPED = pi_nNumPed);
                         
                        -- Gerou Cabeçalho de Pedido de Itens Faltantes
                        vbGerouCabPedItensFaltantes := TRUE; 
                         
                        -- LOG: Cabeçalho do Pedido Faltante
                        P_INSERE_LOG_PROCESSAMENTO('Geração Pedido Faltante = ' || vnNumPedItensFaltantes);
                                       
                      END IF; -- Fim Condição: Gerar o Cabeçalho do Pedido de Itens Faltantes
            
                      ------------------------------------------------------------------------
                      -- INCLUSÃO DOS ITENS FALNTES NO NOVO PEDIDO "vnNumPedItensFaltantes" --
                      ------------------------------------------------------------------------
                      FUNCOES_MED.P_DUPLICAR_PCPEDI(pi_nNumPed,
                                                    vnNumPedItensFaltantes,
                                                    vrItemPedido.vnCodProd,
                                                    vrItemPedido.vnNumSeq,
                                                    vrItemPedido.vnNumSeq,
                                                    vvOcorreramErrosItePedFalta,
                                                    vvMsgErrosItePedFalta);
                      IF (vvOcorreramErrosItePedFalta = 'S') THEN
                        RAISE e_ItePedFalta;
                      END IF;
                      
                      -- Muda a Posição do Item Fantante do Pedido, com aplica a Qtde. Faltante
                      UPDATE PCPEDI
                         SET POSICAO = 'P'
                           , QT      = NVL(vnQtdeFalta,0)
                           , QTFALTA = 0
                       WHERE (NUMPED  = vnNumPedItensFaltantes)
                         AND (CODPROD = vrItemPedido.vnCodProd)
                         AND (NUMSEQ  = vrItemPedido.vnNumSeq);
                      
                      -- Se houve Falta TOTAL
                      IF (NVL(vnQtdeFalta,0) >= NVL(vrItemPedido.vnQtdePedido,0)) THEN
                         
                        -- Muda a Origem de Preço para o Novo Pedido 
                        UPDATE PCORIGEMPRECO
                           SET NUMPED = vnNumPedItensFaltantes
                         WHERE (NUMPED  = pi_nNumPed)
                           AND (CODPROD = vrItemPedido.vnCodProd)
                           AND (NUMSEQ  = vrItemPedido.vnNumSeq);
                           
                        -- Muda o Item Pedido Cesta para o Novo Pedido
                        UPDATE PCPEDICESTA
                           SET NUMPED = vnNumPedItensFaltantes
                         WHERE (NUMPED  = pi_nNumPed)
                           AND (CODPROD = vrItemPedido.vnCodProd)
                           AND (NUMSEQ  = vrItemPedido.vnNumSeq);
                                         
                      END IF;               
                                  
                      -- LOG: Itens do Pedido Faltante
                      P_INSERE_LOG_PROCESSAMENTO('Seq. Item Faltante = ' || vrItemPedido.vnNumSeq || CHR(13) ||
                                                 'vnQtdeFalta = '        || vnQtdeFalta,
                                                 vrItemPedido.vnCodProd);
                              
                      ---------------------------------------------
                      -- ATUALIZAÇÃO DO ESTOQUE DO ITEM FALTANTE --
                      ---------------------------------------------
                      
                      -- Origem Chamada
                      IF    (pi_nCodRotina = 2316) THEN -->> CHAMADO DA ROTINA 2316
                        vnOrigemChamadaReservaEst := 2;
                      ELSIF (pi_nCodRotina = 2336) THEN -->> CHAMADO DA ROTINA 2336
                        vnOrigemChamadaReservaEst := 3;
                      ELSIF (pi_nCodRotina = 2513) THEN -->> CHAMADO DA INTEGRADORA_MED
                        vnOrigemChamadaReservaEst := 4;
                      ELSIF (pi_nCodRotina = 2312) THEN -->> CHAMADO DA ROTINA 2312
                        vnOrigemChamadaReservaEst := 7;
                      ELSIF (pi_nCodRotina = 2641) THEN -->> CHAMADO DA ROTINA 2641
                        vnOrigemChamadaReservaEst := 8;
                      END IF;
            
                      -- Sempre Grava o Item Faltante como Pendente
                      vvOperacaoReservaEst := 'IP'; -- 'IP' - Incluir Pendente
                       
                      -- Chama Procedimento para Reservar o Estoque
                      P_ESTOQUE_RESERV_ITEM_01(vnOrigemChamadaReservaEst,
                                               vvOperacaoReservaEst,
                                               vrItemPedido.vvCodFilialBaixaEstoque, -->> FILIAL PARA BAIXAR O ESTOQUE
                                               vnNumPedItensFaltantes,
                                               vrItemPedido.vnCodProd,
                                               vrItemPedido.vnNumSeq,
                                               vnQtdeFalta, -->> QTDE FALTA
                                               'S', -- pi_vPedidoExiste,
                                               vvOcorreramErrosEstoqueReserv,
                                               vvMsgErrosEstoqueReserv);
                      IF (vvOcorreramErrosEstoqueReserv = 'S') THEN
                        -- DDMEDICA-6582 - Adicionar à mensagem do erro a posição do pedido
                        P_INC_MENSAGEM_ERRO_RESERVADO(vnNumPedItensFaltantes,
                                                      vrItemPedido.vnCodProd,
                                                      vrItemPedido.vnNumSeq,
                                                      vvOperacaoReservaEst,
                                                      vvMsgErrosEstoqueReserv);                                          
                        RAISE e_EstoqueReservFalta;
                      END IF;
                      
                      -- Log: Reserva Estoque Item Faltante
                      P_INSERE_LOG_PROCESSAMENTO('Atu. Estoque Pendente Seq. Item Faltante = ' || vrItemPedido.vnNumSeq                || CHR(13) ||
                                                 'vvCodFilialBaixaEstoque = '                  || vrItemPedido.vvCodFilialBaixaEstoque || CHR(13) ||
                                                 'vnNumPedItensFaltantes = '                   || vnNumPedItensFaltantes               || CHR(13) || 
                                                 'vnQtdeFalta = '                              || vnQtdeFalta                          || CHR(13) ||
                                                 'vvOperacaoReservaEst = '                     || vvOperacaoReservaEst,
                                                 vrItemPedido.vnCodProd);                                                                                        
                                                                   
                      ---------------------------------------
                      -- INCLUSÃO C/C RCA DO ITEM FALTANTE --
                      ---------------------------------------
                      IF (pi_vMovimentarSaldoRca = 'S') THEN
            
                        -- Lançamento na Conta Corrente do RCA            
                        vbLancSaldoRca := PC_PKG_CONTROLARSALDORCA_MED.CCRCA_INCLUIR_ITEM_PEDIDO(pi_nMatricula, 
                                                                                             pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                                             pi_nCodUsurContaCorrente, 
                                                                                             vnNumPedItensFaltantes, 
                                                                                             vrItemPedido.vnCodProd, 
                                                                                             vrItemPedido.vnNumSeq);     
            
                        -- Log: Incluir Conta Corrente Item Faltante
                        P_INSERE_LOG_PROCESSAMENTO('Incluir CCRCA Seq. Item Faltante = ' || vrItemPedido.vnNumSeq    || CHR(13) ||
                                                   'vnNumPedItensFaltantes = '           || vnNumPedItensFaltantes   || CHR(13) ||
                                                   'vnQtdeFalta = '                      || vnQtdeFalta              || CHR(13) ||
                                                   'vnPVenda = '                         || vrItemPedido.vnPVenda    || CHR(13) ||
                                                   'vnPBaseRca = '                       || vrItemPedido.vnPBaseRca  || CHR(13) ||
                                                   'pi_nCodUsurContaCorrente = '         || pi_nCodUsurContaCorrente,
                                                   vrItemPedido.vnCodProd);                                                                                        
                                                   
                      END IF; -- FIM CONDIÇÃO: INCLUSÃO C/C RCA DO ITEM FALTANTE          
                                                                                   
                   /*****************************************************************************************
                    **********************************************
                    *   GRAVAÇÃO DAS FALTAS NO ITEM DO PEDIDO    *
                    **********************************************
                    **********************************************/
                    ELSIF (NVL(vnQtdeFalta,0) > 0) THEN
                                                
                      -------------------------------------------------
                      -- INCLUSAO DO LOG DAS FALTAS SE GUARDA FALTAS --
                      -------------------------------------------------
                      IF (NVL(vnQtdeGuardaFalta,0) > 0) THEN
                      
                        -- Insere Falta no Log
                        BEGIN
                          INSERT INTO PCFALTA
                                    ( NUMPED
                                    , DATA
                                    , CODPROD
                                    , CODUSUR
                                    , CODCLI
                                    , QT
                                    , PVENDA
                                    , CODFILIAL
                                    , NUMSEQ )
                             VALUES ( pi_nNumPed
                                    , TRUNC(SYSDATE)
                                    , vrItemPedido.vnCodProd
                                    , vrPedido.vnCodUsur
                                    , vrPedido.vnCodCli
                                    , NVL(vnQtdeGuardaFalta,0) -- Quantidade de Faltas que serão guardadas
                                    , vrItemPedido.vnPVenda
                                    , vrPedido.vvCodFilial 
                                    , vrItemPedido.vnNumSeq );
                        EXCEPTION
                          WHEN OTHERS THEN 
                            NULL;
                        END;                        
                                                                     
                      END IF; -- FIM CONDIÇÃO: INCLUSAO DO LOG DAS FALTAS SE GUARDA FALTAS          
                      
                      -------------------------------
                      -- ATUALIZAÇÃO DA VENDA PERDIDA
                      -------------------------------
                      UPDATE PCEST
                         SET QTVENDAPERDIDA = NVL(QTVENDAPERDIDA,0) + NVL(vnQtdeFalta,0)
                       WHERE (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque) -->> Código da Filial para Atualização da PCEST
                         AND (CODPROD   = vrItemPedido.vnCodProd);
                                                                                     
                    END IF; -- FIM CONDIÇÃO: SE GERA PEDIDO DE ITENS FALTANTES OU SE GUARDA FALTA (NUNCA AMBOS)
          
                  
                  END IF;
                  ------------------------------------------------------------------------------------------
                  ------------------------------------------------------------------------------------------
                  --                                     F  I  M                                          --
                  --                SE ESTIVER GRAVANDO O PEDIDO COMO LIBERADO OU MONTADO,                --
                  --            CALCULA A QUANTIDADE A QUANTIDADE ATENDIDA ABATENDO AS FALTAS             --
                  ------------------------------------------------------------------------------------------
                  ------------------------------------------------------------------------------------------
                  
                    
                   
                  --------------------------------------------------------------
                  -- RESERVA DO ESTOQUE DA QUANTIDADE ATENDIDA DO ITEM DO PEDIDO
                  --------------------------------------------------------------
                  IF (NVL(vrItemPedido.vnQtdeAtendida,0) > 0) THEN              
      
                    -----------------------------------------------------------
                    -- Atualiza Posição do Item do Pedido para Liberado/Montado
                    -----------------------------------------------------------
                                    
                    -- Atualiza Item do Pedido
                    UPDATE PCPEDI 
                       SET POSICAO = po_vPosicaoFinalPedido -->> Nova Posição do Pedido Liberado/Montado
                     WHERE (NUMPED  = pi_nNumPed)
                       AND (CODPROD = vrItemPedido.vnCodProd)
                       AND (NUMSEQ  = vrItemPedido.vnNumSeq);
      
                    --------------------------------------
                    -- Reserva o Estoque do Item do Pedido
                    --------------------------------------
                          
                    -- Origem Chamada
                    IF    (pi_nCodRotina = 2316) THEN -->> CHAMADO DA ROTINA 2316
                      vnOrigemChamadaReservaEst := 2;
                    ELSIF (pi_nCodRotina = 2336) THEN -->> CHAMADO DA ROTINA 2336
                      vnOrigemChamadaReservaEst := 3;
                    ELSIF (pi_nCodRotina = 2513) THEN -->> CHAMADO DA INTEGRADORA_MED
                      vnOrigemChamadaReservaEst := 4;
                    ELSIF (pi_nCodRotina = 2312) THEN -->> CHAMADO DA ROTINA 2312
                      vnOrigemChamadaReservaEst := 7;
                    ELSIF (pi_nCodRotina = 2641) THEN -->> CHAMADO DA ROTINA 2641
                      vnOrigemChamadaReservaEst := 8;
                    END IF;           
                    
                    -- Inicializa Operação do Estoque
                    vvOperacaoReservaEst := NULL;          
                                                          
                    -- SE A NOVA POSIÇÃO DO PEDIDO ESTÁ DIFERENTE DA POSIÇÃO ANTERIOR DO ITEM
                    -- (Entendemos como Inclusão do Estoque na Nova Posição)
                    IF    (NVL(vrItemPedido.OLD_vPOSICAO,' ') <> NVL(po_vPosicaoFinalPedido,' ')) THEN
                    
                      -- Se a Nova Posição for Montado/Liberado
                      IF    (NVL(po_vPosicaoFinalPedido,' ') IN ('L','M')) THEN
                        vvOperacaoReservaEst   := 'IR'; -- 'IR' - Incluir Reserva
                      -- Se a Nova Posição for Bloqueado/Pendente
                      ELSIF (NVL(po_vPosicaoFinalPedido,' ') IN ('B','P')) THEN
                        vvOperacaoReservaEst   := 'IP'; -- 'IP' - Incluir Pendente
                      ELSE
                        vvMsgErroPosicaoItemInvalida := 'Produto: ' || vrItemPedido.vnCodProd || '; ' || vrItemPedido.vnNumSeq || '; ' || po_vPosicaoFinalPedido;
                        RAISE e_PosicaoAnteriorItemInvalida;
                      END IF;        
                    
                    -- SE A NOVA POSIÇÃO DO PEDIDO ESTÁ IGUAL DA POSIÇÃO ANTERIOR DO ITEM 
                    ELSE
                    
                      -- Entendemos como Alteração do Estoque SOMENTE se a Quantidade mudou
                      IF  (NVL(vrItemPedido.OLD_nQT,0) <> NVL(vrItemPedido.vnQtdeAtendida,0)) THEN
                      
                        -- Se a Nova Posição for Montado/Liberado
                        IF    (NVL(po_vPosicaoFinalPedido,' ') IN ('L','M')) THEN
                          vvOperacaoReservaEst   := 'AR'; -- AIR' - Alterar Reserva
                        -- Se a Nova Posição for Bloqueado/Pendente
                        ELSIF (NVL(po_vPosicaoFinalPedido,' ') IN ('B','P')) THEN
                          vvOperacaoReservaEst   := 'AP'; -- 'AP' - Alterar Pendente
                        ELSE
                          vvMsgErroPosicaoItemInvalida := 'Produto: ' || vrItemPedido.vnCodProd || '; ' || vrItemPedido.vnNumSeq || '; ' || po_vPosicaoFinalPedido;
                          RAISE e_PosicaoAnteriorItemInvalida;
                        END IF;        
                      
                      END IF;                
                    
                    END IF; -- FIM CONDIÇÃO: TIPO DE OPERAÇÃO DO ESTOQUE
                                        
                    -- Se precisa Atualizar o Estoque
                    IF (vvOperacaoReservaEst IS NOT NULL) THEN
                    
                      -- Chama Procedimento para Reservar o Estoque
                      P_ESTOQUE_RESERV_ITEM_01(vnOrigemChamadaReservaEst,
                                               vvOperacaoReservaEst,
                                               vrItemPedido.vvCodFilialBaixaEstoque, -->> FILIAL PARA BAIXAR O ESTOQUE
                                               pi_nNumPed,
                                               vrItemPedido.vnCodProd,
                                               vrItemPedido.vnNumSeq,
                                               vrItemPedido.vnQtdeAtendida, -->> QTDE ATENDIDA
                                               'S', -- pi_vPedidoExiste,
                                               vvOcorreramErrosEstoqueReserv,
                                               vvMsgErrosEstoqueReserv);
                      IF (vvOcorreramErrosEstoqueReserv = 'S') THEN
                        -- DDMEDICA-6582 - Adicionar à mensagem do erro a posição do pedido
                        P_INC_MENSAGEM_ERRO_RESERVADO(pi_nNumPed,
                                                      vrItemPedido.vnCodProd,
                                                      vrItemPedido.vnNumSeq,
                                                      vvOperacaoReservaEst,
                                                      vvMsgErrosEstoqueReserv);                                          
                        RAISE e_EstoqueReserv;
                      END IF;
                      
                      -- Log: Reserva Estoque Item Pedido
                      P_INSERE_LOG_PROCESSAMENTO('Reserva Estoque Seq. Item Pedido = ' || vrItemPedido.vnNumSeq         || CHR(13) ||
                                                 'vnCodPromocaoMed = '                 || vrItemPedido.vnCodPromocaoMed || CHR(13) ||
                                                 'vnEstoqueDisponivel = '              || vnEstoqueDisponivel           || CHR(13) ||
                                                 'vnQtdePedido = '                     || vrItemPedido.vnQtdePedido     || CHR(13) ||
                                                 'vnQtdeAtendida = '                   || vrItemPedido.vnQtdeAtendida   || CHR(13) ||
                                                 'OLD_nQT = '                          || vrItemPedido.OLD_nQT          || CHR(13) ||
                                                 'vvOperacaoReservaEst = '             || vvOperacaoReservaEst          || CHR(13) ||
                                                 'vnEstoqueMultiplo = '                || vnEstoqueMultiplo,            -- DDVENDAS-41227',
                                                 vrItemPedido.vnCodProd);                                                                                        
                    
                    END IF; -- Fim Condição: Se precisa Atualizar o Estoque  
      
                    ----------------------------------
                    -- Atualiza a Data da Última Saída
                    ----------------------------------
                    UPDATE PCEST
                       SET DTULTSAIDA     = TRUNC(SYSDATE) -- Se atendeu ao menos uma unidade Atualiza DTULTSAIDA
                     WHERE (CODFILIAL = vrItemPedido.vvCodFilialBaixaEstoque) -->> Código da Filial para Atualização da PCEST
                       AND (CODPROD   = vrItemPedido.vnCodProd);
      
                  END IF; -- FIM CONDIÇÃO: RESERVA DO ESTOQUE DA QUANTIDADE ATENDIDA DO ITEM DO PEDIDO
              
                            
                END IF; -- FIM CONDIÇÃO: SE MUDOU A QUANTIDADE OU VAI MUDAR A POSIÇÃO DO ITEM DO PEDIDO --
      
              
              END IF; -- FIM CONDIÇÃO: Se o Item NÃO ESTÁ Cancelado --------------------------------------
                      
              -- Atualiza Posição do Array, por causa os valores atualizados de Qtde. Atendida e Corte
              vtItensPedido(viSeqItemPed) := vrItemPedido;
              
            END LOOP; -- FIM: LAÇO DE ITENS DO PEDIDO PARA RESERVA DO ESTOQUE ----------------------------
            
            -- Se Gerou Cabeçalho de Pedido de Itens Faltantes
            IF (vbGerouCabPedItensFaltantes) THEN
              -- Atualizar Totais Pedido de Itens Faltantes  
              P_ATUALIZAR_TOTAIS_PEDIDO('S',
                                        vnNumPedItensFaltantes);
            END IF;
            
          END IF; -- FIM: Se tem Itens no Pedido
                            
         /*************************************************************************************************
                                                RESERVA DO ESTOQUE
                                                      F I M     
          **************************************************************************************************/ 
      
        
          ------------------------------------------------------------------------
          --- EFETIVA TRANSAÇÕES A CADA PROCESSO SOMENTE NA GRAVAÇÃO DO PEDIDO ---
          ------------------------------------------------------------------------
          IF (vbCommitPorProcesso) THEN   
            -- Atualizar DTWMS nas Transferências entre Filiais com Estoque Compartilhado no WMS
            IF (vrPedido.vnCondVenda = 10) THEN
              P_ATU_DTWMS(pi_nNumPed,
                          vrPedido.vvCodFilial,
                          vrPedido.vnCodCli,
                          vvMensagemDtWms);         
              -- Log:
              P_INSERE_LOG_PROCESSAMENTO('Alertas Serviço DTWS: ' || vvMensagemDtWms);
            END IF;
            -- Efetiva Transações, LIBERANDO O ESTOQUE
            COMMIT;
            vbUsouSavePoint := FALSE;        
          END IF;  
                         
    
        END IF; -- FIM CONDIÇÃO: SE O PEDIDO PODE BAIXAR O ESTOQUE
      
  
      END IF; -- FIM CONDIÇÃO: SE PODE SER REALIZADO O PROCESSO DE BAIXA DE ESTOQUE
  
      
    END IF;
   /**************************************************************************************************
    **************************************************************************************************
                      P R O C E S S O    D E    B A I X A    D E    E S T O Q U E     
                                                 F I M                                                  
    **************************************************************************************************
    **************************************************************************************************/ 
  
  
  
   /**************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
  
                                               I N I C I O                                            
  
                 P R O C E S S O    D E    M O V I M E N T A R    S A L D O    R C A
                                                  E  
                   F I N A L I Z A R    A    G R A V A C A O    D O    P E D I D O
  
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************
    **************************************************************************************************/ 
    IF (pi_vChamadaProcesso IN ('GP','EP','MP','CI','CC')) THEN
  
      
      -- Verifica se pode realizar o Processo de Movimentação do Saldo RCA
      vbPodeProcessoSaldoRca := TRUE;
      IF (pi_vChamadaProcesso = 'GP') AND
         (NVL(vrPedido.vvStatusProcessamentoMed,'N') IN ('S','F')) THEN
        -- Se na Gravação do Pedido já realizou o processo de movimentação do Saldo RCA, não permitirá fazê-lo novamente        
        -- (Obs: Status F é uma etapa posterior, ou seja, já passou pela Movimentação do Saldo RCA)
        vbPodeProcessoSaldoRca := FALSE;
      END IF;
  
  
     /***********************************************************************************************
      SE PODE SER REALIZADO O PROCESSO DE MOVIMENTAÇÃO DO SALDO RCA
      *************************************************************/ 
      IF (vbPodeProcessoSaldoRca) THEN
  
  
        -------------------------------------------------------------------------------
        --- SALVA POSIÇÃO DO ROLLBACK A CADA PROCESSO SOMENTE NA GRAVAÇÃO DO PEDIDO ---
        -------------------------------------------------------------------------------
        IF (vbCommitPorProcesso) THEN   
          -- Marca posição para Rollback
          SAVEPOINT inicio_gravar_pedido;
          vbUsouSavePoint := TRUE;      
        END IF;
      
        -- Atualiza Status do Pedido, indicando que vai realizar o Processo de Atualização do Saldo RCA
        P_ATU_STATUS_PROCESSAMENTO(pi_vChamadaProcesso,
                                   'S', -- MED-1669
                                   vrPedido.vvStatusProcessamentoMed);
                                
               
       /************************************************************************************************       
        ************************************************************************************************       
        SE MOVIMENTA O SALDO DA CONTA CORRENTE DO RCA 
        *********************************************
        *********************************************/
        IF (pi_vMovimentarSaldoRca = 'S') THEN
       
          
          ---------------
          -- BLOQUEIA RCA
          ---------------
        
          -- Controle Processo: Bloqueio RCA
          vvControleProcesso := 'BloqueioRca';
        
          -- Bloqueia o RCA
          BEGIN
            SELECT 'S'
              INTO vvBloqueou
              FROM PCUSUARI
            WHERE (PCUSUARI.CODUSUR = pi_nCodUsurContaCorrente)
               FOR UPDATE NOWAIT;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvBloqueou := 'N';
          END;
          
          -- Se não Achou o RCA
          IF (vvBloqueou = 'N') THEN
            RAISE e_AbortaBloqueioRca;
          END IF;
            
          -- Fim do Controle Processo: Bloqueio RCA
          vvControleProcesso := NULL;
        
              
        
         /*************************************************************************************************
                                                   I N I C I O
                                          ESTORNO DO VALOR CANCELADO
          **************************************************************************************************/ 
          IF (vtItensPedido.COUNT > 0) THEN -- Se tem Itens no Pedido
        
            -- LAÇO DE ITENS DO PEDIDO PARA ESTORNAR O VALOR CANCELADO
            FOR viSeqItemPed IN vtItensPedido.FIRST..vtItensPedido.LAST LOOP
        
              -- Pega Dados Do Item do Pedido em Lista
              vrItemPedido := vtItensPedido(viSeqItemPed);
              
              -- Se o Item foi Cancelado
              IF (NVL(vrItemPedido.vvItemCancelado,'N') = 'S') THEN
              
                -- Estorno na Conta Corrente do RCA          
                vbLancSaldoRca := PC_PKG_CONTROLARSALDORCA_MED.CCRCA_EXCLUIR_ITEM_PEDIDO(pi_nMatricula, 
                                                                                     pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                                     pi_nCodUsurContaCorrente, 
                                                                                     pi_nNumPed, 
                                                                                     vrItemPedido.vnCodProd, 
                                                                                     vrItemPedido.vnNumSeq, 
                                                                                     NVL(vrItemPedido.vnQtdePedido,0)); -->> QTDE DO PEDIDO QUE ESTÁ SENDO ESTORNADA
                                                                                                                                                          
                -- Log: Estorno Conta Corrente Item Pedido
                P_INSERE_LOG_PROCESSAMENTO('Estorno RCA Cancelamento Seq. Item Pedido = ' || vrItemPedido.vnNumSeq            || CHR(13) ||
                                           'vnQt = '                                      || NVL(vrItemPedido.vnQtdePedido,0) || CHR(13) || 
                                           'vnVlSaldoRca = '                              || NVL(vrItemPedido.vnVlSaldoRca,0) || CHR(13) ||
                                           'pi_nCodUsurContaCorrente = '                  || pi_nCodUsurContaCorrente,
                                           vrItemPedido.vnCodProd);          
      
              END IF; -- FIM CONDIÇÃO: Se o Item foi Cancelado
        
            END LOOP; -- FIM: LAÇO DE ITENS DO PEDIDO PARA ESTORNAR ESTORNAR O VALOR CANCELADO
            
          END IF; -- FIM: Se tem Itens no Pedido
         /*************************************************************************************************
                                           ESTORNO DO VALOR CANCELADO
                                                      F I M     
          **************************************************************************************************/ 
      
      
          
         /*************************************************************************************************
                                                    I N I C I O
                                         LANÇAMENTO DE NOVO VALOR SALDO RCA
                                         ESTORNO DO VALOR SALDO RCA ALTERADO
          **************************************************************************************************/ 
          IF (vtItensPedido.COUNT > 0) THEN -- Se tem Itens no Pedido
        
            -- LAÇO DE ITENS DO PEDIDO PARA ESTORNAR O VALOR CANCELADO
            FOR viSeqItemPed IN vtItensPedido.FIRST..vtItensPedido.LAST LOOP
        
              -- Pega Dados Do Item do Pedido em Lista
              vrItemPedido := vtItensPedido(viSeqItemPed);
              
              -- Se o Item NÃO ESTÁ Cancelado
              IF (NVL(vrItemPedido.vvItemCancelado,'N') <> 'S') THEN
              
                -- SE PODE OCORRER INCLUSÃO DO SALDO RCA (Não teve movimentação e passou a movimentar) ---------
                IF ((NVL(vrItemPedido.OLD_nQTSALDORCA,0) = 0) AND (NVL(vrItemPedido.vnQtdeAtendida,0) > 0)) THEN
                
                  -- Lançamento na Conta Corrente do RCA            
                  vbLancSaldoRca := PC_PKG_CONTROLARSALDORCA_MED.CCRCA_INCLUIR_ITEM_PEDIDO(pi_nMatricula, 
                                                                                       pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                                       pi_nCodUsurContaCorrente, 
                                                                                       pi_nNumPed,
                                                                                       vrItemPedido.vnCodProd,
                                                                                       vrItemPedido.vnNumSeq);        
                  -- Atualiza campos da PCPEDI: QTSALDORCA e VLSALDORCA 
                  vbLancSaldoRca := F_CCRCA_ATUALIZAR_VLSALDORCA(pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                 pi_nCodUsurContaCorrente,
                                                                 pi_nNumPed,
                                                                 vrItemPedido.vnCodProd,
                                                                 vrItemPedido.vnNumSeq);
        
                  -- Log: Incluir Conta Corrente Item Pedido
                  P_INSERE_LOG_PROCESSAMENTO('Incluir CCRCA Seq. Item Pedido = ' || vrItemPedido.vnNumSeq       || CHR(13) ||
                                             'vnQtdeAtendida = '                 || vrItemPedido.vnQtdeAtendida || CHR(13) || 
                                             'vnPVenda = '                       || vrItemPedido.vnPVenda       || CHR(13) ||
                                             'vnPBaseRca = '                     || vrItemPedido.vnPBaseRca     || CHR(13) ||
                                             'vnSt = '                           || vrItemPedido.vnSt           || CHR(13) ||
                                             'vnStPBASERCA = '                   || vrItemPedido.vnStPbaseRca   || CHR(13) ||
                                             'vvBonific = '                      || vrItemPedido.vvBonific      || CHR(13) ||
                                             'pi_nCodUsurContaCorrente = '       || pi_nCodUsurContaCorrente,
                                             vrItemPedido.vnCodProd);                 
                
                -- SE NÃO PODE OCORRER INCLUSÃO DO SALDO RCA -----------------------------------------------------
                ELSE
                
                  -- Calcula o novo Valor Total de Saldo RCA que será movimentado na Conta-Corrente do RCA para o Item do Pedido
                  vnNovoVlTotalSaldoRcaItemPed := F_CCRCA_OBTER_VALOR_LANC_ATUAL(pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                                 pi_nCodUsurContaCorrente,
                                                                                 pi_nNumPed,
                                                                                 vrItemPedido.vnCodProd,
                                                                                 vrItemPedido.vnNumSeq);
                  
                  -- SE PODE OCORRER ALTERAÇÃO DO SALDO RCA -----------------------------------------------------
                  -- (Para evitar estorno por arredondamento, limita a diferença a 0.10) ------------------------
                  IF (ABS((ROUND(NVL(vrItemPedido.OLD_nQTSALDORCA,0) * NVL(vrItemPedido.OLD_nVLSALDORCA,0),2) -
                             ROUND(vnNovoVlTotalSaldoRcaItemPed,2))) >= 0.10) THEN
                                
                    -------------------------------------------------------------------------------------------------------------
                    -- Estorno do CORTE na Conta Corrente do RCA (Valor Total Movimentado anteriormente)
                    -- Na Função CCRCA_ALTERAR_VLSALDORCA após o estorno é realizada a inclusão dos
                    -- novos valores se a quantidade na PCPEDI estiver maior que zero (Insere o que ficou na PCPEDI após o Corte)
                    -------------------------------------------------------------------------------------------------------------
                    
                    -- Chama Função para Alterar o Saldo do RCA
                    vbLancSaldoRca := F_CCRCA_ALTERAR_VLSALDORCA(pi_nMatricula,
                                                                 pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                 pi_nCodUsurContaCorrente, 
                                                                 pi_nNumPed, 
                                                                 vrItemPedido.vnCodProd, 
                                                                 vrItemPedido.vnNumSeq, 
                                                                 NVL(vrItemPedido.OLD_nQTSALDORCA,0),
                                                                 NVL(vrItemPedido.OLD_nVLSALDORCA,0));
    
                    -- Atualiza campos da PCPEDI: QTSALDORCA e VLSALDORCA 
                    vbLancSaldoRca := F_CCRCA_ATUALIZAR_VLSALDORCA(pi_nCodRotina, -->> Código da Rotina conforme Origem da Chamada
                                                                   pi_nCodUsurContaCorrente,
                                                                   pi_nNumPed,
                                                                   vrItemPedido.vnCodProd,
                                                                   vrItemPedido.vnNumSeq);
                                                                    
                    -- Log: Estorno Conta Corrente Item Pedido
                    P_INSERE_LOG_PROCESSAMENTO('Estorno Corte CCRCA Seq. Item Pedido = ' || vrItemPedido.vnNumSeq               || CHR(13) ||
                                               'OLD_nQTSALDORCA = '                      || NVL(vrItemPedido.OLD_nQTSALDORCA,0) || CHR(13) || 
                                               'OLD_nVLSALDORCA = '                      || vrItemPedido.OLD_nVLSALDORCA        || CHR(13) ||
                                               'vnQtdeAtendida = '                       || vrItemPedido.vnQtdeAtendida         || CHR(13) || 
                                               'vnPVenda = '                             || vrItemPedido.vnPVenda               || CHR(13) ||
                                               'vnPBaseRca = '                           || vrItemPedido.vnPBaseRca             || CHR(13) ||
                                               'vnSt = '                                 || vrItemPedido.vnSt                   || CHR(13) ||
                                               'vnStPBASERCA = '                         || vrItemPedido.vnStPbaseRca           || CHR(13) ||
                                               'vvBonific = '                            || vrItemPedido.vvBonific              || CHR(13) ||
                                               'pi_nCodUsurContaCorrente = '             || pi_nCodUsurContaCorrente,
                                               vrItemPedido.vnCodProd);               
                                                   
                  END IF; -- FIM CONDIÇÃO: SE PODE OCORRER ALTERAÇÃO DO SALDO RCA
                
                END IF; -- FIM CONDIÇÃO: SE PODE OCORRER INCLUSÃO DO SALDO RCA
                
              END IF; -- FIM CONDIÇÃO: Se o Item NÃO ESTÁ Cancelado
        
            END LOOP; -- FIM: LAÇO DE ITENS DO PEDIDO PARA ESTORNAR ESTORNAR O VALOR CANCELADO
            
          END IF; -- FIM: Se tem Itens no Pedido
         /*************************************************************************************************
                                         LANÇAMENTO DE NOVO VALOR SALDO RCA
                                         ESTORNO DO VALOR SALDO RCA ALTERADO
                                                      F I M     
          **************************************************************************************************/ 
      
      
        END IF; -- FIM CONDIÇÃO: SE MOVIMENTAR OU NÃO MOTIVAMENTA O SALDO DA CONTA CORRENTE DO RCA
    
  
      END IF; -- FIM CONDIÇÃO: SE PODE SER REALIZADO O PROCESSO DE MOVIMENTAÇÃO DO SALDO RCA
  
  
     /*************************************************************************************************
                                                I N I C I O
                                        EXCLUSAO DOS ITENS DO PEDIDO
                               ATUALIZAÇÕES ADICIONAIS NOS ITENS DO PEDIDO
      **************************************************************************************************/ 
      
      -- Laço de Itens do Pedido
      FOR vc_ItensPed IN (SELECT NUMSEQ
                               , CODPROD
                               , QT
                               , MOTIVOCANCELAMENTOMED
                               , PVENDA
                               , PTABELA
                               , POSICAO
                               , PBASERCA
                               , CODST
                            FROM PCPEDI
                           WHERE (NUMPED = pi_nNumPed)) LOOP                                                          
             
        ---------------------------
        -- Item do Pedido Cancelado                    
        ---------------------------
        IF    (NVL(vc_ItensPed.POSICAO,'L') = 'C') THEN
         
          -- Se Cancelamento Pedido Call-Center
          IF (pi_vChamadaProcesso = 'CC') THEN
            -- Somente zera a Qtde, o Pedido ficará no Sistema como Cancelado
             UPDATE PCPEDI
                SET QT     = 0
                  , NUMCAR = 0
              WHERE (NUMPED  = pi_nNumPed)
                AND (CODPROD = vc_ItensPed.CODPROD)
                AND (NUMSEQ  = vc_ItensPed.NUMSEQ);
          -- Se NÃO for Cancelamento Pedido Call-Center
          ELSE       
            -- Exclui Item do Pedido porque Foi Cancelado
            DELETE FROM PCPEDI
                  WHERE (NUMPED  = pi_nNumPed)
                    AND (CODPROD = vc_ItensPed.CODPROD)
                    AND (NUMSEQ  = vc_ItensPed.NUMSEQ);
          END IF;
         
          -- Log: Cancelamento do Item
          P_INSERE_LOG_PROCESSAMENTO('Exclusão Seq Item Pedido = ' || vc_ItensPed.NUMSEQ || CHR(13) ||
                                     'vnQtdePedido = '             || vc_ItensPed.QT,
                                     vc_ItensPed.CODPROD);                                                                                        
         
          -- Pega Motivo do Cancelamento do Item
          vvMotivoCancelamentoResumido  := SUBSTR(vc_ItensPed.MOTIVOCANCELAMENTOMED, 1,  100);
          vvMotivoCancelamentoDetalhado := SUBSTR(vc_ItensPed.MOTIVOCANCELAMENTOMED, 1, 2000);
    
          -- Não deixa o Motivo do Cancelamento ficar Nulo
          IF (vvMotivoCancelamentoResumido IS NULL) THEN
            vvMotivoCancelamentoResumido  := 'CANCELAMENTO ITEM PEDIDO';
          END IF;
          IF (vvMotivoCancelamentoDetalhado IS NULL) THEN
             vvMotivoCancelamentoDetalhado := 'CANCELAMENTO ITEM PEDIDO';
          END IF;
                                           
          -- Insere no Log de Itens Excluídos
          INSERT INTO PCNFCANITEM
                    ( NUMPED
                    , CODROTINA
                    , MOTIVO
                    , CODCLI
                    , CODPROD
                    , PVENDA
                    , PTABELA
                    , NUMSEQ
                    , DATACANC
                    , CODFUNCCANC
                    , DATAEMISSAO 
                    , CODFUNCEMITE
                    , DESCRICAO
                    , CODUSUR
                    , NUMCAR
                    , QT
                    , HORACANC
                    , PBASERCA )
             VALUES ( pi_nNumPed
                    , pi_nCodRotina -->> Código da Rotina
                    , SUBSTR(vvMotivoCancelamentoResumido, 1, 60)
                    , vrPedido.vnCodCli
                    , vc_ItensPed.CODPROD
                    , vc_ItensPed.PVENDA
                    , vc_ItensPed.PTABELA
                    , vc_ItensPed.NUMSEQ
                    , TRUNC(SYSDATE)
                    , pi_nMatricula
                    , TRUNC(SYSDATE)
                    , pi_nMatricula
                    , vvDescricaoExclusaoPedido
                    , vrPedido.vnCodUsur
                    , 0
                    , NVL(vc_ItensPed.QT,0)
                    , SYSDATE
                    , vc_ItensPed.PBASERCA );
     
          -- Log de Alteração de Dados
          P_INSERE_LOG_ALTERACAO_DADOS('N',
                                       pi_nNumPed,
                                       vc_ItensPed.CODPROD,
                                       vc_ItensPed.NUMSEQ,
                                       'PCPEDI',
                                       'QT',
                                       NULL,
                                       NULL,
                                       0,
                                       NVL(vc_ItensPed.QT,0),
                                       SUBSTR(vvMotivoCancelamentoResumido, 1, 60),
                                       'EXCLUSÃO DO ITEM NA PCPEDI QUANDO HOUVER CANCELAMENTO DO ITEM - PROCEDIMENTO PRC_MED_ESTOQUE_RESERVADO_01 - ' || vvMotivoCancelamentoDetalhado);              
        
        ------------------------------
        -- Item do Pedido NÃO ATENDIDO
        ------------------------------
        ELSIF (NVL(vc_ItensPed.QT,0) <= 0) THEN
         
          -- Exclui Item do Pedido porque não existe quantidade atendida
          DELETE FROM PCPEDI
                WHERE (NUMPED  = pi_nNumPed)
                  AND (CODPROD = vc_ItensPed.CODPROD)
                  AND (NUMSEQ  = vc_ItensPed.NUMSEQ);
  
  
          -- INICIO: DDMEDICA-198 - Log do Corte
          
          -- Log: Cancelamento do Item
          P_INSERE_LOG_PROCESSAMENTO('Exclusão Seq Item Pedido = ' || vc_ItensPed.NUMSEQ || CHR(13) ||
                                     'vnQtdePedido = '             || vc_ItensPed.QT,
                                     vc_ItensPed.CODPROD);                                                                                        
         
          -- Motivo do Cancelamento do Item
          vvMotivoCancelamentoResumido  := SUBSTR('CANCELAMENTO DO ITEM POR FALTA DE ESTOQUE', 1,  100);
          vvMotivoCancelamentoDetalhado := SUBSTR('CANCELAMENTO DO ITEM POR FALTA DE ESTOQUE', 1, 2000);
                                           
          -- Insere no Log de Itens Excluídos
          INSERT INTO PCNFCANITEM
                    ( NUMPED
                    , CODROTINA
                    , MOTIVO
                    , CODCLI
                    , CODPROD
                    , PVENDA
                    , PTABELA
                    , NUMSEQ
                    , DATACANC
                    , CODFUNCCANC
                    , DATAEMISSAO 
                    , CODFUNCEMITE
                    , DESCRICAO
                    , CODUSUR
                    , NUMCAR
                    , QT
                    , HORACANC
                    , PBASERCA )
             VALUES ( pi_nNumPed
                    , pi_nCodRotina -->> Código da Rotina
                    , SUBSTR(vvMotivoCancelamentoResumido, 1, 60)
                    , vrPedido.vnCodCli
                    , vc_ItensPed.CODPROD
                    , vc_ItensPed.PVENDA
                    , vc_ItensPed.PTABELA
                    , vc_ItensPed.NUMSEQ
                    , TRUNC(SYSDATE)
                    , pi_nMatricula
                    , TRUNC(SYSDATE)
                    , pi_nMatricula
                    , vvDescricaoExclusaoPedido
                    , vrPedido.vnCodUsur
                    , 0
                    , NVL(vc_ItensPed.QT,0)
                    , SYSDATE
                    , vc_ItensPed.PBASERCA );
     
          -- Log de Alteração de Dados
          P_INSERE_LOG_ALTERACAO_DADOS('N',
                                       pi_nNumPed,
                                       vc_ItensPed.CODPROD,
                                       vc_ItensPed.NUMSEQ,
                                       'PCPEDI',
                                       'QT',
                                       NULL,
                                       NULL,
                                       0,
                                       NVL(vc_ItensPed.QT,0),
                                       SUBSTR(vvMotivoCancelamentoResumido, 1, 60),
                                       'EXCLUSÃO DO ITEM NA PCPEDI QUANDO HOUVER FALA DE ESTOQUE - PROCEDIMENTO PRC_MED_ESTOQUE_RESERVADO_01 - ' || vvMotivoCancelamentoDetalhado);

        END IF;

      END LOOP; -- Fim Laço de Itens do Pedido                          
  
     /*************************************************************************************************
                                        EXCLUSAO DOS ITENS DO PEDIDO
                               ATUALIZAÇÕES ADICIONAIS NOS ITENS DO PEDIDO
                                                  F I M      
      **************************************************************************************************/ 
       
  
  
     /*************************************************************************************************
                                                I N I C I O
                                           ATUALIZAÇÃO DO PEDIDO
      **************************************************************************************************/ 
    
      --- ATUALIZA TOTAIS DO PEDIDO ---
      P_ATUALIZAR_TOTAIS_PEDIDO('N',
                                pi_nNumPed);
      --                          
      IF (pi_nCodRotina = 2336) AND 
         (pi_vChamadaProcesso = 'CI') THEN
        -- DDMEDICA-5000 - Se chamado da 2336 ao aumentar por exemplo a quantidade do item, preciso recalcular também o VLTOTAL
        P_ATUALIZAR_TOTAIS_PEDIDO('S',
                                  pi_nNumPed);
      END IF;
      
      -- Verifica se existem Itens no Pedido
      SELECT COUNT(*) 
       INTO viQtdeItens
        FROM PCPEDI
       WHERE (NUMPED = pi_nNumPed);
      -- Se não tiver Itens retornará posição Cancelado
      IF (NVL(viQtdeItens,0) = 0) THEN
        -- Retornará que o Pedido deverá ser excluído   
        po_vPosicaoFinalPedido := 'C';
        -- Log: Cancelamento do Item
        P_INSERE_LOG_PROCESSAMENTO('Pedido sem Itens. Posição alterada para C-Cancelado.');
      END IF;
  
      ----------------------------------------
      -- EXCLUSÃO DO PEDIDO SE NÃO TIVER ITENS
      ----------------------------------------
      IF (NVL(viQtdeItens,0) = 0) THEN
      
        -- Libera Autorização
        UPDATE PCAUTORI
           SET DATA_UTILIZACAO = NULL
             , CODFUNCUTILIZ = NULL
             , STATUSUTILIZ = 'N'
             , NUMPED = NULL
             , PVENDIDO = NULL
         WHERE (NUMPED = pi_nNumPed);
        
        -- Deleta Itens do Rolo 
        DELETE FROM PCITEMROLO
         WHERE (NUMPED = pi_nNumPed);
  
        -- Deleta Itens da Cesta
        DELETE FROM PCPEDICESTA
         WHERE (NUMPED = pi_nNumPed);
         
        -- Deleta Origem do Preço
        DELETE FROM PCORIGEMPRECO
         WHERE (NUMPED = pi_nNumPed);
         
        -- Gera Log na PCNFCAN
        INSERT INTO PCNFCAN
             (NUMPED, CODROTINA, MOTIVO, CODCLI, VLTOTAL,
              DATACANC, CODFUNCCANC, DATAEMISSAO, CODFUNCEMITE, DESCRICAO, CODUSUR, NUMCAR,
              CODPLPAG, CODCOB, CODFILIAL, ORIGEMPED, TOTPESO, TOTVOLUME, CONDVENDA, NUMPEDRCA, HORACANC, CODSUPERVISOR)
        SELECT NUMPED
             , pi_nCodRotina
             , SUBSTR('CORTE TOTAL DO PEDIDO',1,60)
             , CODCLI
             , VLTOTAL
             , TRUNC(SYSDATE) -- DATACANC
             , pi_nMatricula
             , NULL           -- DATAEMISSAO
             , pi_nMatricula
             , SUBSTR(vvDescricaoExclusaoPedido,1,120)
             , CODUSUR
             , NUMCAR
             , CODPLPAG
             , CODCOB
             , CODFILIAL
             , ORIGEMPED
             , TOTPESO
             , TOTVOLUME
             , CONDVENDA
             , NUMPEDRCA
             , SYSDATE -- HORACANC
             , CODSUPERVISOR
          FROM PCPEDC
         WHERE (NUMPED = pi_nNumPed);
  
        -- Deleta Pedido
        DELETE FROM PCPEDC
         WHERE (NUMPED = pi_nNumPed);
  
        -- Log: Cancelamento do Item
        P_INSERE_LOG_PROCESSAMENTO('Pedido sem Itens. Pedido Excluído.');
  
      ---------------------------------------
      -- ATUALIZAÇÃO DO PEDIDO SE TIVER ITENS
      ---------------------------------------
      ELSE
      
        -- (Na 2316 quem Grava a Posição é a própria Rotina)
        -- (Na INTEGRADORA_MED quem Grava a Posição é a própria Rotina)
        IF (NVL(pi_nCodRotina,0) NOT IN (2316,2513)) THEN
      
          UPDATE PCPEDC
             SET POSICAO = po_vPosicaoFinalPedido -->> Nova Posição do Pedido
          WHERE (NUMPED  = pi_nNumPed);
          
          -- DDMEDICA-683 - Se chamado da 2336 e continuar bloqueado, incrementar log da posição
          IF (pi_nCodRotina = 2336) AND
             (po_vPosicaoFinalPedido = 'B') THEN
            -- DDMEDICA-7731 - Limitar tamanho do texto 
            UPDATE PCPEDC
               SET LOG = SUBSTR(LOG,1,3000) || CHR(13) || po_vObservacaoMotivo
            WHERE (NUMPED  = pi_nNumPed);
          END IF;
          
          -- Log: Cancelamento do Item
          P_INSERE_LOG_PROCESSAMENTO('Pedido com Itens. Pedido Atualizado.');
          
        END IF;
      
      END IF; -- FIM: EXCLUSÃO DO PEDIDO SE NÃO TIVER ITENS
          
      --- GRAVA O LOG DA ROTINA ---
      P_GRAVA_LOG_PROCESSAMENTO;
  
      --- EFETIVA TRANSAÇÕES ---
      -- (Na INTEGRADORA_MED quem Realiza Commit é a INTEGRADORA_MED)
      -- (Na 2312 quem Realiza Commit é a Procedure de Gravação Reposição da 2312 - MED-1964)
      -- (Na 2641 quem Realiza Commit é a Package de Integração do WMS - DDMEDICA-1147)
      IF (NVL(pi_nCodRotina,0) NOT IN (2513,2312,2641)) THEN
        -- Atualizar DTWMS nas Transferências entre Filiais com Estoque Compartilhado no WMS
        IF (vrPedido.vnCondVenda = 10) THEN
          P_ATU_DTWMS(pi_nNumPed,
                      vrPedido.vvCodFilial,
                      vrPedido.vnCodCli,
                      vvMensagemDtWms);         
          -- Log:
          P_INSERE_LOG_PROCESSAMENTO('Alertas Serviço DTWS: ' || vvMensagemDtWms);
        END IF;
        -- Efetiva Transações
        COMMIT;        
        vbUsouSavePoint := FALSE;        
      END IF;
  
  
     /*************************************************************************************************
                                           ATUALIZAÇÃO DO PEDIDO
                                                  F I M      
      **************************************************************************************************/ 
  
  
    END IF; -- FIM CONDIÇÃO: SE AINDA NÃO PASSOU PELO PROCESSO DE ATUALIZAÇÃO DO SALDO DO SALDO RCA
   /**************************************************************************************************
    **************************************************************************************************
                 P R O C E S S O    D E    M O V I M E N T A R    S A L D O    R C A
                                                  E  
                   F I N A L I Z A R    A    G R A V A C A O    D O    P E D I D O
                                                 F I M                                                  
    **************************************************************************************************
    **************************************************************************************************/ 
          
  EXCEPTION
    WHEN e_NumPedFaltasNaoInformado  THEN
      -- Inicio do Processo não tem SavePoint
      po_vRetorno  := 'NumPedidoFaltante';
      po_vMsgErros := 'Numero do Pedido de Itens Faltantes não foi informado';
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_PkgFuncoesMed             THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ObjetoInvalido';
      po_vMsgErros := 'Package FUNCOES_MED está inválida ou inexistente.' || 'Favor executar a rotina "2300 - Atualizar Banco de Dados"';
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_PkgEstoque                THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ObjetoInvalido';
      po_vMsgErros := 'Package PKG_ESTOQUE está inválida ou inexistente.' || 'Favor executar a rotina "500 - Atualizar Procedure"';
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_PkgControlarSaldoRca      THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ObjetoInvalido';
      po_vMsgErros := 'Package PC_PKG_CONTROLARSALDORCA_MED está inválida ou inexistente.' || 'Favor executar a rotina "300 - Atualizar Funções de Venda"';
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_AbortaBloqueioRca         THEN -- Não conseguiu bloquear RCA
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'BloqueioRca';
      po_vMsgErros := 'Não conseguiu bloquear o RCA: ' || NVL(pi_nCodUsurContaCorrente,0);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_AbortaItensVlMin          THEN -- Não conseguiu encontrar Itens para Validação do Valor Mínimo
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vMsgErros := SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000); -- Temp.      
      po_vRetorno  := 'NaoAchouItensVlMin';
      po_vMsgErros := 'Não conseguiu encontrar os Itens do Pedido:  ' || NVL(pi_nNumPed,0);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_AbortaItensEstoqueVlMin   THEN -- Não conseguiu encontrar Estoque dos Itens para Validação do Valor Mínimo
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vMsgErros := SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000); -- Temp.      
      po_vRetorno  := 'NaoAchouEstoqueItensVlMin';
      po_vMsgErros := 'Não conseguiu encontrar o Estoque dos Itens do Pedido:  ' || NVL(pi_nNumPed,0);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_AbortaBloqueioItens       THEN -- Não conseguiu bloquear os Itens do Pedido
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vMsgErros := SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000); -- Temp.      
      po_vRetorno  := 'BloqueioItens';
      po_vMsgErros := 'Não conseguiu bloquear os Itens do Pedido:  ' || NVL(pi_nNumPed,0);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_PosicaoAnteriorItemInvalida THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'PosicaoAnteriorItemInvalida';
      po_vMsgErros := SUBSTR('Posição anterior do Item Inválida > ' || vvMsgErroPosicaoItemInvalida,1,250);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_CabPedFalta                 THEN -- Não conseguiu Gerar o Cabeçalho do Pedido de Itens Faltantes
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'GerarPedItensFaltantes';
      po_vMsgErros := SUBSTR('Erro ao Gerar Pedido de Itens Faltantes: ' || vvMsgErrosCabPedFalta,1,250);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_ItePedFalta               THEN -- Não conseguiu Gerar o Item do Pedido Faltante
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'GerarPedItensFaltantes';
      po_vMsgErros := SUBSTR('Erro ao Gerar Item Faltante: ' || vvMsgErrosItePedFalta,1,250);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_NovaPosicaoPedidoInvalida THEN -- Posição Atual do Pedido Inválida
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'PosicaoInvalida';
      po_vMsgErros := 'Posição Inválida do Pedido: ' || vrPedido.vvPosicaoAtual;
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_EstoqueReservEstorno      THEN -- Não conseguiu reservar o Estoque
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ReservarEstoque';
      po_vMsgErros := SUBSTR('Erro ao Estornar Estoque: ' || vvMsgErrosEstoqueReserv,1,2000);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_EstoqueReservFalta        THEN -- Não conseguiu reservar o Estoque
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ReservarEstoque';
      po_vMsgErros := SUBSTR('Erro ao Reservar Estoque Item Faltante: ' || vvMsgErrosEstoqueReserv,1,2000);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_EstoqueReserv             THEN -- Não conseguiu reservar o Estoque
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ReservarEstoque';
      po_vMsgErros := SUBSTR('Erro ao Reservar Estoque: ' || vvMsgErrosEstoqueReserv,1,2000);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_EstornoSaldoRca            THEN    
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'EstornoSaldoRca';
      po_vMsgErros := SUBSTR('Erro ao pesquisar dados para Estorno do Conta Corrente do RCA',1,250);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_DadosEstornoSaldoRcaNotFound THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'DadosEstornoSaldoRca';
      po_vMsgErros := SUBSTR('Dados para Estorno do Conta Corrente do RCA não encontrados',1,250);
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_ItensCancelarNotFound        THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'ItensCancelar';
      po_vMsgErros := SUBSTR('Não foram encontrados itens para Cancelamento',1,250);    
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    WHEN e_EstoqueReservUsoWms          THEN -- DDVENDAS-31376 
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'EstoqueReservUsoWms';
      po_vMsgErros := SUBSTR('O Pedido já está em uso pelo WMS e não pode mais ter alteração de quantidade reservada',1,250);    
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
    /*  
    WHEN e_RegraPermissaoBloqueio       THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vRetorno  := 'RegraPermissaoBloqueio';
      po_vMsgErros := SUBSTR('O Pedido não pode ser liberado porque existem motivos pendentes de aprovação',1,250);    
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log      
    */
    WHEN OTHERS THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN  
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      -- Erro em Processo Controlado
      IF (vvControleProcesso IS NOT NULL) THEN
        -- Tipo de Retorno
        po_vRetorno  := vvControleProcesso;
        po_vMsgErros := vvControleProcesso;
        -- Mensagem de Retorno
        IF    (vvControleProcesso = 'BloqueioRca')   THEN
          po_vMsgErros := 'Não conseguiu bloquear o RCA: ' || NVL(pi_nCodUsurContaCorrente,0);
        ELSIF (vvControleProcesso = 'BloqueioItens') THEN
          po_vMsgErros := 'Não conseguiu bloquear os Itens do Pedido: ' || NVL(pi_nNumPed,0);
        END IF;
      -- Erro Sem Processo Controlado
      ELSE
        po_vRetorno  := '-1'; -- Erro no Processamento
        po_vMsgErros := SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,2000);      
      END IF;
      P_GRAVA_LOG_PROCESSAMENTO(po_vRetorno,po_vMsgErros); -- Log
  END P_GRAVACAO_PEDIDO_01;

 /*******************************************************************************
  Nome         : P_FINALIZACAO_PEDIDO_01
  Descricão    : Processo de Finalização do Pedido
  Parâmetros   : Entrada:
                 pi_nCodRotina              = Código da Rotina
                 pi_nNumPed                 = Número do Pedido
                 pi_nNumRegiao              = Número da Região
                 pi_nMatricula              = Matrícula
                 pi_vPosicaoPedido          = Posição do Pedido
                 pi_nProxNumCar             = Próximo Número de Carregamento
                 Saida:
                 po_vOcorreramErros         = Se ocorreram Erros (S-Sim/N-Não)
                 po_vMsgErros               = Mensagem de Erros
  Alteração    : Anderson Silva - 08/11/2017
                 Tarefa: HIS.04281.2017 Criação da Procedure *
  Alteração    : Anderson Silva    = 20/06/2018 - MED-1090 - FCP
  Alteração    : 02/09/2018  Anderson Silva Taxa Frete.
  Alteração    : 11/09/2018 Anderson Silva - MED-1663 - Controle ProxNumPed
  Alteração    : 13/09/2018 - MED-1669 - Taxa de Frete se não tiver Quebras
  Alteração    : 13/09/2018 - MED-1769 - Carregamento Balcão
  Alteração    : 18/12/2018 - MED-1999 - Plano Bonificação
  Alteração    : 18/03/2018 - 4415.029804.2019 - Alteração Estorno Conta Corrente
                              com Item de Campanha (novo processo de estoque precisa estornar)
  Alteração    : 17/04/2019 - MED-2478 - Tratamento para TV7/TV8
  Alteração    : 02/07/2019 - DDMEDICA-174 - OL/PE não ter quebra de pedidos na liberação da 2336.
  Alteração    : 09/08/2019 - DDMEDICA-486 - Mensagem indevida de quebra de item bonificado
  Alteração    : 23/10/2019 - DDMEDICA-1112 - Marcos Levi - Quebra por Rca Linha de produto
  Alteração    : 28/11/2019 - DDMEDICA-1451 - Limitar valor recebido no campo totvolume da pccarreg
  Alteração    : 24/12/2019 - DDMEDICA-1666 - Quebra Pedidos Especial para Crossdocking
  Alteração    : 09/01/2020 - DDMEDICA-1761 - Quebra Pedido Por Restrição de transporte 
  Alteração    : 10/01/2019 - DDMEDICA-1769 - Rastreabilidade Crossdocking na Quebra do Pedido
  *******************************************************************************/
  PROCEDURE P_FINALIZACAO_PEDIDO_01(pi_nCodRotina      IN  NUMBER,
                                    pi_nNumPed         IN  NUMBER,
                                    pi_nMatricula      IN  NUMBER,
                                    pi_vPosicaoPedido  IN  VARCHAR2,
                                    pi_nProxNumCar     IN  NUMBER,
                                    po_vOcorreramErros OUT VARCHAR2,
                                    po_vMsgErros       OUT VARCHAR2)
  IS
  
    -- Versão da Procedure
    vvVersaoProcedure                  VARCHAR2(20) := '28.6.0.1';
  
    -- Versão
    vvVersao                            VARCHAR2(250);
    vnVersao                            NUMBER;
  
    -- Controle do Processo
    vvControleProcesso                  VARCHAR2(50);
  
    -- Flag de Controle de uso do SavePoint
    vbUsouSavePoint                     BOOLEAN;
  
    -- Dados do Pedido
    TYPE TRecPedido                     IS RECORD(
         vnCodCli                       PCPEDC.CODCLI%TYPE,
         vnCondVenda                    PCPEDC.CONDVENDA%TYPE,
         vnCodPlPag                     PCPEDC.CODPLPAG%TYPE,
         vnCodPlPagEtico                PCPEDC.CODPLPAGETICO%TYPE,
         vnCodPlPagGenerico             PCPEDC.CODPLPAGGENERICO%TYPE,
         vvCodCob                       PCPEDC.CODCOB%TYPE,
         vdData                         PCPEDC.DATA%TYPE,
         vdDtEntrega                    PCPEDC.DTENTREGA%TYPE,
         vvOrigemPed                    PCPEDC.ORIGEMPED%TYPE,
         vvPosicaoAtual                 PCPEDC.POSICAO%TYPE,
         vnCodUsur                      PCPEDC.CODUSUR%TYPE,
         vvCodFilial                    PCPEDC.CODFILIAL%TYPE,
         vvPedidoAvaria                 PCPEDC.PEDIDOAVARIA%TYPE,
         vnTotPeso                      PCPEDC.TOTPESO%TYPE,
         vnTotVolume                    PCPEDC.TOTVOLUME%TYPE,
         vnVlTabela                     PCPEDC.VLTABELA%TYPE,
         vnVlAtend                      PCPEDC.VLATEND%TYPE,
         vnNumRegiao                    PCPEDC.NUMREGIAO%TYPE,
         vnCodPromocaoMed               PCPEDC.CODPROMOCAOMED%TYPE,
         vvPosicao                      PCPEDC.POSICAO%TYPE,
         vvCodFilialNf                  PCPEDC.CODFILIALNF%TYPE,
         vnNumCar                       PCPEDC.NUMCAR%TYPE,
         vvStatusProcessamentoMed       PCPEDC.STATUSPROCESSAMENTOMED%TYPE,
         vvTipoFv                       PCPEDC.TIPOFV%TYPE,
         vnVlFreteOutrasDesp            PCPEDC.VLFRETEOUTRASDESP%TYPE);
    vrPedido                            TRecPedido;
  
    -- Parâmetros
    TYPE TRecParametros                 IS RECORD(
         vUSANUMCARVENDABALCAO          PCCONSUM.USANUMCARVENDABALCAO%TYPE,
         vFECHACARREGAUTVENDABALCAO     PCCONSUM.FECHACARREGAUTVENDABALCAO%TYPE,
         vGERARBRINDEPEDBONIFIC         PCCONSUM.GERARBRINDEPEDBONIFIC%TYPE,
         vRESERVARESTOQUETV7            PCPARAMFILIAL.VALOR%TYPE,
         vGRAVARPEDVENBLOQMED           PCPARAMFILIAL.VALOR%TYPE
         );
    vrParametros                        TRecParametros;
  
    -- Valor Total Carregamento
    vnVlTotaCarregamento                NUMBER;
  
    -- Variável para verificar se existem Brindes
    vvAchouBrindes                      VARCHAR2(1);
  
    -- Variáveis de Retorno da Procedure que Valida Promoção
    vvRetPodeGravarPedidoPromo          VARCHAR2(1);
    vvRetMotivoNaoPodeGravarPromo       VARCHAR2(2000);
  
    -- Variáveis de Retorno da Procedure de Quebra de Pedidos
    vvRetQuebrarPedido                  VARCHAR2(1);
    vvMsgErrosQuebrarPedido             VARCHAR2(2000);
  
    -- Controle de Finalização do Pedido
    vbPodeFinalizarPedido               BOOLEAN;
  
    -- Variáveis de Retorno da Procedure de Quebra Pedido TV8
    vvRetMsgTV8                         VARCHAR2(2000);
    vnRetNumPedGeradoTV8                NUMBER;
    vvRetPosicaoGeratTV8                VARCHAR2(2000);
    vvRetMotivoTV8                      VARCHAR2(2000);
    vvAchouTv8                          VARCHAR2(1);
  
    -- Dados dos Totalizadores
    TYPE TRecTotalizador                IS RECORD(
         vnTotQTITENS                   NUMBER,
         vnTotUNIDADES                  NUMBER,
         vnTotLIQUIDO                   NUMBER,
         vnTotSTREPASSE                 NUMBER,
         vnTotTOTAL                     NUMBER,
         vnTotFCP                       NUMBER);
    vrTotalizador                       TRecTotalizador;
  
    -- Taxa Frete
    TYPE TRecRetTaxaFrete               IS RECORD(
         vvAchouFrete                   VARCHAR2(1),
         vnValorTaxa                    NUMBER,
         vnValorMinimo                  NUMBER);
    vrRetTaxaFrete                      TRecRetTaxaFrete;
    -- Variável para Cálculo da Taxa de Frete
    vnTotalPedidoValidaTaxafrete        NUMBER;
  
    -- Controle de Carregamento
    vvExisteCarreg                      VARCHAR2(1);
  
    -- Log
    vvMsgLog                            VARCHAR2(32000);
    -- Observação TEMP
    vvObservacaoTemp                    PCMED_RESUMO_PEDIDOS.OBSERVACAO%TYPE;
  
    -- Exceções
    e_PedidoNaoEncontrado               EXCEPTION;
    e_NumCarregamento                   EXCEPTION;
    e_ValidacaoPromo                    EXCEPTION;
    e_QuebrarPedido                     EXCEPTION;
  
    -- Array de Log de Processamento
    TYPE TRecLogProcessamento           IS RECORD(
         vnNumPed                       PCPEDC.NUMPED%TYPE,
         vvMensagem                     VARCHAR2(32000));
    TYPE TTLogProcessamento             IS TABLE OF TRecLogProcessamento INDEX BY BINARY_INTEGER;
    vtLogProcessamento                  TTLogProcessamento;
  
   /********************************************************************
    PROCEDURE: P_INSERE_LOG_PROCESSAMENTO
    DESCRIÇÃO: Insere Log de Processamento
    ********************************************************************/
    PROCEDURE P_INSERE_LOG_PROCESSAMENTO(pi_vMensagem IN VARCHAR2,
                                         pi_nCodProd  IN NUMBER DEFAULT NULL) IS
      viIdxLog INTEGER;
    BEGIN
      -- Log somente se Gravar Pedido
      viIdxLog := NVL(vtLogProcessamento.COUNT,0) + 1;
      vtLogProcessamento(viIdxLog).vnNumPed     := pi_nNumPed;
      IF (NVL(pi_nCodProd,0) > 0) THEN
        vtLogProcessamento(viIdxLog).vvMensagem := '[' || pi_nCodProd || '] ' ||  pi_vMensagem;
      ELSE
        vtLogProcessamento(viIdxLog).vvMensagem := pi_vMensagem;
      END IF;
    END P_INSERE_LOG_PROCESSAMENTO;
  
   /********************************************************************
    PROCEDURE: P_GRAVA_LOG_PROCESSAMENTO
    DESCRIÇÃO: Gravar Log de Processamento
    ********************************************************************/
    PROCEDURE P_GRAVA_LOG_PROCESSAMENTO
    IS PRAGMA AUTONOMOUS_TRANSACTION;
      vcMsgLog CLOB;
    BEGIN
      BEGIN
        IF (vtLogProcessamento.COUNT > 0) THEN
          -- Inicializa Msg
          vcMsgLog := 'INICIO LOG: ' || CHR(13);
          -- Laço Processamento para Concatenar Logs
          FOR viIdxLog IN vtLogProcessamento.FIRST..vtLogProcessamento.LAST LOOP
            vcMsgLog := vcMsgLog || vtLogProcessamento(viIdxLog).vvMensagem || CHR(13);
          END LOOP;
          -- Grava Log do Pedido
          vcMsgLog := vcMsgLog || 'FIM LOG';
          INSERT INTO PCLOGPROCFATURMED
                    ( DTLOG,
                      NUMPED,
                      NUMCAR,
                      OBSERVACAO)
             VALUES ( SYSDATE
                    , pi_nNumPed
                    , -11
                    , vcMsgLog);
          -- Efetiva Transações
          COMMIT;
          -- Limpa Array para re-uso
          vtLogProcessamento.DELETE;
        END IF;
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    END P_GRAVA_LOG_PROCESSAMENTO;
  
   /************************************************************************
    PROCEDIMENTO PARA RETORNAR A TAXA DE FRETE
    ************************************************************************/
    PROCEDURE OBTER_TAXA_FRETE(pi_vCodFilial   IN  VARCHAR2,
                               pi_vOrigemPed   IN  VARCHAR2,
                               pi_vTipoFv      IN  VARCHAR2,
                               po_vAchouTaxa   OUT VARCHAR2,
                               po_nValorTaxa   OUT NUMBER,
                               po_nValorMinimo OUT NUMBER)
    IS
      vvOrigem VARCHAR2(200);
    BEGIN
      -- Inicializa Retornos
      po_vAchouTaxa := 'N';
      po_nValorTaxa := 0;
  
      -- Define Origem
      IF    (pi_vOrigemPed = 'F') AND (NVL(pi_vTipoFv,'FV') = 'OL') THEN
        vvOrigem := 'L';
      ELSIF (pi_vOrigemPed = 'F') AND (NVL(pi_vTipoFv,'FV') = 'PE') THEN
        vvOrigem := 'E';
      ELSE
        vvOrigem := pi_vOrigemPed;
      END IF;
  
      -- Pesquisa Valores por Filial (verifica se existe algum valor cadastradp para a Filial passada no parâmetro)
      BEGIN
        SELECT 'S'
          INTO po_vAchouTaxa
          FROM PCLIMITESFILIALORIGEMMED
         WHERE (TIPOLIMITE = 'TF')
           AND (CODFILIAL  = pi_vCodFilial)
           AND (ROWNUM     = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vAchouTaxa := 'N';
      END;
  
      -- Se achou Valores por Filial
      IF (po_vAchouTaxa = 'S') THEN
  
        -- Pesquisa Valores da Filial passada no Parâmetro
        BEGIN
          SELECT 'S'
               , VALORDESPESA
               , VALORLIMITE
            INTO po_vAchouTaxa
               , po_nValorTaxa
               , po_nValorMinimo
            FROM PCLIMITESFILIALORIGEMMED
           WHERE (TIPOLIMITE = 'TF')
             AND (CODFILIAL  = pi_vCodFilial)
             AND (ORIGEM     = vvOrigem);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            po_vAchouTaxa := 'N';
        END;
  
      -- Se NÃO achou Valores por Filial
      ELSE
  
        -- Pesquisa Valor para Todas as Filiais
        BEGIN
          SELECT 'S'
               , VALORDESPESA
               , VALORLIMITE
            INTO po_vAchouTaxa
               , po_nValorTaxa
               , po_nValorMinimo
            FROM PCLIMITESFILIALORIGEMMED
           WHERE (TIPOLIMITE = 'TF')
             AND (CODFILIAL  = '99') -->> Todas as Filiais "99"
             AND (ORIGEM     = vvOrigem);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            po_vAchouTaxa := 'N';
        END;
  
      END IF;
  
    END OBTER_TAXA_FRETE;
    
    /*************************************************************************
       Nome        : P_ATU_DISTRIB_PEDIDO_INICIAL
       Objetivo    : Garantir no Pedido Inicial a Distribuição dos Produtos 
                     que ficaram nele - DDMEDICA-6036
       Parametros  : pi_nNumPed : Filtro Número do Pedido Inicial
     ************************************************************************/
    PROCEDURE P_ATU_DISTRIB_PEDIDO_INICIAL(pi_nNumPedInicial IN NUMBER) IS
      vMEDPERMITEDISTRIBDIFRCA PCPARAMFILIAL.VALOR%TYPE;
      vvCodDistrib             PCPRODUT.CODDISTRIB%TYPE;
    BEGIN
    
      -- Parâmetro para Permitir incluir no pedido itens de distribuição diferente do RCA
      POBTEM_PARAMFILIAL_STRING('99',
                                'MEDPERMITEDISTRIBDIFRCA',
                                'N',
                                vMEDPERMITEDISTRIBDIFRCA);

      IF (NVL(vMEDPERMITEDISTRIBDIFRCA,'N') = 'S') THEN
    
        -- Pesquisa o Código da Distribuição de um dos Produtos do Pedido Inicial
        BEGIN
          SELECT PCPRODUT.CODDISTRIB
            INTO vvCodDistrib
            FROM PCPEDI
               , PCPRODUT
           WHERE (PCPEDI.CODPROD = PCPRODUT.CODPROD)
             AND (PCPEDI.NUMPED  = pi_nNumPedInicial)
             AND (PCPRODUT.CODDISTRIB IS NOT NULL)
             AND (ROWNUM         = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvCodDistrib := NULL;
        END;
    
        -- Atualizar a Distribuição do Pedido
        IF (vvCodDistrib IS NOT NULL) THEN
          UPDATE PCPEDC
             SET CODDISTRIB = vvCodDistrib
           WHERE (NUMPED = pi_nNumPedInicial);
        END IF;
  
      END IF;
     
    END P_ATU_DISTRIB_PEDIDO_INICIAL;    
  
