      -- Parâmetros
      TYPE TRecParametros           IS RECORD (
           vvGerarBrindePedBonific  PCCONSUM.GERARBRINDEPEDBONIFIC%TYPE,
           vvSepararProdComSt       PCPARAMFILIAL.VALOR%TYPE);
      vrParametros                  TRecParametros;
      -- Outras Variáveis
      vnNovoNumPed                      NUMBER;
      vQUEBRARPEDIDOREGIMESP            PCPARAMFILIAL.VALOR%TYPE;
      vQUEBRARPEDIDOTIPOMEDICAM         PCPARAMFILIAL.VALOR%TYPE;
