      -- Array para Guardar os Próximos Números de Pedido - MED-1663
      TYPE TT_NOVO_NUMPED_PCPEDC    IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
      vtNOVO_NUMPED_PCPEDC          TT_NOVO_NUMPED_PCPEDC;
  
      -- Código da Bonificação Padrão do Brinde
      vnCodBnfPadraoBrinde          PCTIPOBONIFIC.CODBNF%TYPE;
      -- Código do Plano de Pagamento do Brinde
      vnCodPlPagBrinde              PCPLPAG.CODPLPAG%TYPE;
      
      -- Regra para Quebra de Controlados em Pedidos de Crossdocking
      vQUEBRACONTROLADOSCROSSDOCK   PCREGRASEXCECAOMED.VALOR%TYPE;
      
      -- Array de Log de Processamento
      TYPE TRecLogProcessamento     IS RECORD(
           vnNumPed                 PCPEDC.NUMPED%TYPE,
           vvMensagem               VARCHAR2(32000));
      TYPE TTLogProcessamento       IS TABLE OF TRecLogProcessamento INDEX BY BINARY_INTEGER;
      vtLogProcessamento            TTLogProcessamento;
      vvMsgLog                      VARCHAR2(32000);
  
      -- Taxa Frete
      TYPE TRecRetTaxaFrete         IS RECORD(
           vvAchouFrete             VARCHAR2(1),
           vnValorTaxa              NUMBER,
           vnValorMinimo            NUMBER);
      vrRetTaxaFrete                TRecRetTaxaFrete;
  
      -- Erro Tratado
      vvMsgErroTratado              VARCHAR2(400);
      e_Tratado                     EXCEPTION;
      e_Break                       EXCEPTION;
  
     /********************************************************************
      PROCEDURE: P_INSERE_LOG_PROCESSAMENTO
      DESCRIÇÃO: Insere Log de Processamento
      ********************************************************************/
      PROCEDURE P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed   IN NUMBER,
                                           pi_vMensagem IN VARCHAR2) IS
        viIdxLog INTEGER;
      BEGIN
        viIdxLog := NVL(vtLogProcessamento.COUNT,0) + 1;
        vtLogProcessamento(viIdxLog).vnNumPed   := pi_nNumPed;
        vtLogProcessamento(viIdxLog).vvMensagem := pi_vMensagem;
      END P_INSERE_LOG_PROCESSAMENTO;
  
     /********************************************************************
      PROCEDURE: P_GRAVA_LOG_PROCESSAMENTO
      DESCRIÇÃO: Gravar Log de Processamento
      ********************************************************************/
      PROCEDURE P_GRAVA_LOG_PROCESSAMENTO(pi_nNumPed IN NUMBER) IS
        vdDtLog   DATE;
        vcMsgLog  CLOB;
        vvMsgErro VARCHAR(250);
      BEGIN
        vdDtLog  := SYSDATE;
        vcMsgLog := 'INICIO PROCESSAMENTO' || CHR(13);
        BEGIN
          IF (vtLogProcessamento.COUNT > 0) THEN
            -- Laço Processamento
            FOR viIdxLog IN vtLogProcessamento.FIRST..vtLogProcessamento.LAST LOOP
              vcMsgLog := vcMsgLog || vtLogProcessamento(viIdxLog).vvMensagem || CHR(13);
            END LOOP;
            -- Grava Log do Pedido
            vcMsgLog := vcMsgLog || 'FIM PROCESSAMENTO';
            INSERT INTO PCLOGPROCFATURMED
                      ( DTLOG,
                        NUMPED,
                        NUMCAR,
                        OBSERVACAO)
               VALUES ( vdDtLog
                      , pi_nNumPed
                      , -6
                      , vcMsgLog);
          END IF;
        EXCEPTION
          WHEN OTHERS THEN
            BEGIN
              vvMsgErro := 'Erro: ' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
              INSERT INTO PCLOGPROCFATURMED(DTLOG,NUMPED,NUMCAR,OBSERVACAO) VALUES (vdDtLog, pi_nNumPed, -6, vvMsgErro);
            EXCEPTION
              WHEN OTHERS THEN
                NULL;
            END;
        END;
      END P_GRAVA_LOG_PROCESSAMENTO;
  
     /********************************************************************
      PROCEDIMENTO: P_OBTER_PRAZO_PEDIDO
      ********************************************************************/
      PROCEDURE P_OBTER_PRAZO_PEDIDO(pi_nNumPedParcelas IN  NUMBER,
                                     pi_nCodPlPag       IN  NUMBER,
                                     po_rPrazos         OUT TRecPrazos) IS
  
        -- Array de Parcelas que será carregada nesta função
        po_aArrayParcelas TTArrayParcelas;
  
        -- Array para Armazenar os Dados do Plano de Pagamento
        TYPE TRecDadosPlPag IS RECORD(
             vnCodPlPag PCPLPAG.CODPLPAG%TYPE,
             vnPrazo1   PCPLPAG.PRAZO1%TYPE,
             vnPrazo2   PCPLPAG.PRAZO2%TYPE,
             vnPrazo3   PCPLPAG.PRAZO3%TYPE,
             vnPrazo4   PCPLPAG.PRAZO4%TYPE,
             vnPrazo5   PCPLPAG.PRAZO5%TYPE,
             vnPrazo6   PCPLPAG.PRAZO6%TYPE,
             vnPrazo7   PCPLPAG.PRAZO7%TYPE,
             vnPrazo8   PCPLPAG.PRAZO8%TYPE,
             vnPrazo9   PCPLPAG.PRAZO9%TYPE,
             vnPrazo10  PCPLPAG.PRAZO10%TYPE,
             vnPrazo11  PCPLPAG.PRAZO11%TYPE,
             vnPrazo12  PCPLPAG.PRAZO12%TYPE,
             vdDtVenc1  PCPLPAG.DTVENC1%TYPE,
             vdDtVenc2  PCPLPAG.DTVENC2%TYPE,
             vdDtVenc3  PCPLPAG.DTVENC3%TYPE,
             vvFormaParcelamento PCPLPAG.FORMAPARCELAMENTO%TYPE
             );
        vrDadosPlPag    TRecDadosPlPag;
  
        -- Plano de Pagamento para Pesquisa dos dados do Plano de Pagamento
        vnCodPlPagPesqDadosPlPag PCPREST.CODCOB%TYPE;
  
        -- Dados do Pedido que serão lidos nesta função
        pi_vCodCob               PCPEDC.CODCOB%TYPE;
        pi_dDtEntrega            PCPEDC.DTENTREGA%TYPE;
  
        -- Record para Inicializar os Prazos
        vrLimpaPrazos            TRecPrazos;
  
        -- Somatório dos Prazos
        vnSomatorioPrazos        NUMBER;
  
       /********************************************************************
        PROCEDURE: atualizar_prazos_datavenc_fixa
        DESCRIÇÃO: Atualizar os Prazos a partir das datas de vencimento fixa
        ********************************************************************/
        PROCEDURE atualizar_prazos_datavenc_fixa(pi_dDtEntrega IN PCNFSAID.DTENTREGA%TYPE,
                                                 pi_dDtVenc1   IN PCPLPAG.DTVENC1%TYPE,
                                                 pi_dDtVenc2   IN PCPLPAG.DTVENC2%TYPE,
                                                 pi_dDtVenc3   IN PCPLPAG.DTVENC3%TYPE,
                                                 pio_nPrazo1   IN OUT PCPLPAG.PRAZO1%TYPE,
                                                 pio_nPrazo2   IN OUT PCPLPAG.PRAZO2%TYPE,
                                                 pio_nPrazo3   IN OUT PCPLPAG.PRAZO3%TYPE) IS
        BEGIN
  
          IF (pi_dDtVenc1 IS NOT NULL) THEN
  
            -- Prazo 1
            pio_nPrazo1 := (pi_dDtVenc1 - pi_dDtEntrega);
            IF (pio_nPrazo1 < 0) THEN
              pio_nPrazo1 := 0;
            END IF;
  
            IF (pi_dDtVenc2 IS NOT NULL) THEN
  
              -- Prazo 2
              pio_nPrazo2 := (pi_dDtVenc2 - pi_dDtEntrega);
              IF (pio_nPrazo2 < 0) THEN
                pio_nPrazo2 := 0;
              END IF;
  
              IF (pi_dDtVenc3 IS NOT NULL) THEN
  
                -- Prazo 3
                pio_nPrazo3 := (pi_dDtVenc3 - pi_dDtEntrega);
                IF (pio_nPrazo3 < 0) THEN
                  pio_nPrazo3 := 0;
                END IF;
  
              END IF;
  
            END IF;
  
          END IF;
        END atualizar_prazos_datavenc_fixa;
  
      BEGIN
  
          -- Pesquisa Cobrança e Data de Entrega
          BEGIN
           SELECT CODCOB
                , NVL(DTENTREGA,TRUNC(SYSDATE))
             INTO pi_vCodCob
                , pi_dDtEntrega
             FROM PCPEDC
            WHERE (NUMPED = pi_nNumPedParcelas);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              pi_vCodCob    := NULL;
              pi_dDtEntrega := TRUNC(SYSDATE);
          END;
  
          -- Inicializa Record de Retorno de Prazos
          po_rPrazos := vrLimpaPrazos;
  
          -- Inicializa Retorno de Prazo Médio
          po_rPrazos.vnPrazoMedio := 0;
  
          -- Inicializa Array de Parcelas
          po_aArrayParcelas.DELETE;
  
          -- Se Cobrança BNF
          IF (NVL(pi_vCodCob,' ') = 'BNF') THEN
  
            -- Pesquisará pelo Plano 99
            vnCodPlPagPesqDadosPlPag := 99;
  
          ELSE
  
            -- Pesquisará pelo Plano enviado no Parâmetro
            vnCodPlPagPesqDadosPlPag := pi_nCodPlPag;
  
          END IF;
  
          -- Pesquisa informações do Plano de Pagamento
          BEGIN
            SELECT PCPLPAG.PRAZO1
                 , PCPLPAG.PRAZO2
                 , PCPLPAG.PRAZO3
                 , PCPLPAG.PRAZO4
                 , PCPLPAG.PRAZO5
                 , PCPLPAG.PRAZO6
                 , PCPLPAG.PRAZO7
                 , PCPLPAG.PRAZO8
                 , PCPLPAG.PRAZO9
                 , PCPLPAG.PRAZO10
                 , PCPLPAG.PRAZO11
                 , PCPLPAG.PRAZO12
                 , PCPLPAG.DTVENC1
                 , PCPLPAG.DTVENC2
                 , PCPLPAG.DTVENC3
                 , PCPLPAG.FORMAPARCELAMENTO
              INTO vrDadosPlPag.vnPrazo1
                 , vrDadosPlPag.vnPrazo2
                 , vrDadosPlPag.vnPrazo3
                 , vrDadosPlPag.vnPrazo4
                 , vrDadosPlPag.vnPrazo5
                 , vrDadosPlPag.vnPrazo6
                 , vrDadosPlPag.vnPrazo7
                 , vrDadosPlPag.vnPrazo8
                 , vrDadosPlPag.vnPrazo9
                 , vrDadosPlPag.vnPrazo10
                 , vrDadosPlPag.vnPrazo11
                 , vrDadosPlPag.vnPrazo12
                 , vrDadosPlPag.vdDtVenc1
                 , vrDadosPlPag.vdDtVenc2
                 , vrDadosPlPag.vdDtVenc3
                 , vrDadosPlPag.vvFormaParcelamento
              FROM PCPLPAG
             WHERE (PCPLPAG.CODPLPAG = vnCodPlPagPesqDadosPlPag); -->> Plano 99 ou Plano passado no Parâmetro
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vrDadosPlPag.vnPrazo1  := NULL;
              vrDadosPlPag.vnPrazo2  := NULL;
              vrDadosPlPag.vnPrazo3  := NULL;
              vrDadosPlPag.vnPrazo4  := NULL;
              vrDadosPlPag.vnPrazo5  := NULL;
              vrDadosPlPag.vnPrazo6  := NULL;
              vrDadosPlPag.vnPrazo7  := NULL;
              vrDadosPlPag.vnPrazo8  := NULL;
              vrDadosPlPag.vnPrazo9  := NULL;
              vrDadosPlPag.vnPrazo10 := NULL;
              vrDadosPlPag.vnPrazo11 := NULL;
              vrDadosPlPag.vnPrazo12 := NULL;
              vrDadosPlPag.vdDtVenc1 := NULL;
              vrDadosPlPag.vdDtVenc2 := NULL;
              vrDadosPlPag.vdDtVenc3 := NULL;
              vrDadosPlPag.vvFormaParcelamento := NULL;
          END;
  
          -- Se preencheu a Data Vencimento Fixa
          IF (vrDadosPlPag.vdDtVenc1 IS NOT NULL) THEN
  
            atualizar_prazos_datavenc_fixa(pi_dDtEntrega,
                                           vrDadosPlPag.vdDtVenc1,
                                           vrDadosPlPag.vdDtVenc2,
                                           vrDadosPlPag.vdDtVenc3,
                                           vrDadosPlPag.vnPrazo1,
                                           vrDadosPlPag.vnPrazo2,
                                           vrDadosPlPag.vnPrazo3);
  
            po_aArrayParcelas(1).vnPrazo := NVL(vrDadosPlPag.vnPrazo1,0);
            IF (vrDadosPlPag.vdDtVenc2 IS NOT NULL) THEN
              po_aArrayParcelas(2).vnPrazo := NVL(vrDadosPlPag.vnPrazo2,0);
              IF (vrDadosPlPag.vdDtVenc3 IS NOT NULL) THEN
                po_aArrayParcelas(3).vnPrazo := NVL(vrDadosPlPag.vnPrazo3,0);
              END IF;
            END IF;
  
          -- Se NÃO preencheu a Data Vencimento Fixa
          ELSE
  
            -- Laço de Prazos
            FOR viIdxPrazo IN 1..12 LOOP
  
              -- Pega Prazo
              IF    ((viIdxPrazo = 1)) THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo1;
              ELSIF ((viIdxPrazo = 2) AND (NVL(vrDadosPlPag.vnPrazo2,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo2;
              ELSIF ((viIdxPrazo = 3) AND (NVL(vrDadosPlPag.vnPrazo3,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo3;
              ELSIF ((viIdxPrazo = 4) AND (NVL(vrDadosPlPag.vnPrazo4,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo4;
              ELSIF ((viIdxPrazo = 5) AND (NVL(vrDadosPlPag.vnPrazo5,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo5;
              ELSIF ((viIdxPrazo = 6) AND (NVL(vrDadosPlPag.vnPrazo6,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo6;
              ELSIF ((viIdxPrazo = 7) AND (NVL(vrDadosPlPag.vnPrazo7,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo7;
              ELSIF ((viIdxPrazo = 8) AND (NVL(vrDadosPlPag.vnPrazo8,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo8;
              ELSIF ((viIdxPrazo = 9) AND (NVL(vrDadosPlPag.vnPrazo9,0) > 0))   THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo9;
              ELSIF ((viIdxPrazo = 10) AND (NVL(vrDadosPlPag.vnPrazo10,0) > 0)) THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo10;
              ELSIF ((viIdxPrazo = 11) AND (NVL(vrDadosPlPag.vnPrazo11,0) > 0)) THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo11;
              ELSIF ((viIdxPrazo = 12) AND (NVL(vrDadosPlPag.vnPrazo12,0) > 0)) THEN
                po_aArrayParcelas(viIdxPrazo).vnPrazo := vrDadosPlPag.vnPrazo12;
              END IF;
  
            END LOOP; -- Fim Laço de Prazos
  
          END IF; -- Fim Condição Se preencheu a Data Vencimento Fixa
  
          -- Calcula Prazo Médio
          IF (po_aArrayParcelas.COUNT > 0) THEN
  
            vnSomatorioPrazos := 0;
            FOR viIdxPrazo IN po_aArrayParcelas.FIRST..po_aArrayParcelas.LAST LOOP
  
              -- Atualiza Prazo
              IF (NVL(po_aArrayParcelas(viIdxPrazo).vnPrazo,0) > 0) THEN
                IF    (viIdxPrazo = 1)  THEN
                  po_rPrazos.vnPrazo1 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 2)  THEN
                  po_rPrazos.vnPrazo2 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 3)  THEN
                  po_rPrazos.vnPrazo3 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 4)  THEN
                  po_rPrazos.vnPrazo4 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 5)  THEN
                  po_rPrazos.vnPrazo5 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 6)  THEN
                  po_rPrazos.vnPrazo6 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 7)  THEN
                  po_rPrazos.vnPrazo7 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 8)  THEN
                  po_rPrazos.vnPrazo8 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 9)  THEN
                  po_rPrazos.vnPrazo9 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 10) THEN
                  po_rPrazos.vnPrazo10 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 11) THEN
                  po_rPrazos.vnPrazo11 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                ELSIF (viIdxPrazo = 12) THEN
                  po_rPrazos.vnPrazo12 := po_aArrayParcelas(viIdxPrazo).vnPrazo;
                END IF;
              END IF;
  
              -- Incrementa Somatório de Prazos
              vnSomatorioPrazos := vnSomatorioPrazos + NVL(po_aArrayParcelas(viIdxPrazo).vnPrazo,0);
  
            END LOOP;
  
            po_rPrazos.vnPrazoMedio := TRUNC((vnSomatorioPrazos / po_aArrayParcelas.COUNT));
  
          END IF;
  
      END P_OBTER_PRAZO_PEDIDO;
  
      ----------------------------------
      -- PROCEDIMENTO: P_ATUALIZA_QUEBRA
      ----------------------------------
      PROCEDURE P_ATUALIZA_QUEBRA(pi_nNumPed          IN NUMBER,
                                  pi_nCodProd         IN NUMBER,
                                  pi_nNumSeq          IN NUMBER,
                                  pi_vTipoQuebra      IN VARCHAR2,
                                  pi_vCodPrincQuebra  IN VARCHAR2,
                                  pi_vCodSecQuebra    IN VARCHAR2,
                                  pi_vDescricaoQuebra IN VARCHAR2,
                                  pio_nColunaQuebra   IN INTEGER)
      IS
      BEGIN
  
        -- Quebra 1
        IF    (pio_nColunaQuebra = 1) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA1      = pi_vTipoQuebra
               , CODPRINCQUEBRA1 = pi_vCodPrincQuebra
               , CODSECQUEBRA1   = pi_vCodSecQuebra
               , DESQUEBRA1      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 2
        ELSIF (pio_nColunaQuebra = 2) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA2      = pi_vTipoQuebra
               , CODPRINCQUEBRA2 = pi_vCodPrincQuebra
               , CODSECQUEBRA2   = pi_vCodSecQuebra
               , DESQUEBRA2      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 3
        ELSIF (pio_nColunaQuebra = 3) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA3      = pi_vTipoQuebra
               , CODPRINCQUEBRA3 = pi_vCodPrincQuebra
               , CODSECQUEBRA3   = pi_vCodSecQuebra
               , DESQUEBRA3      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 4
        ELSIF (pio_nColunaQuebra = 4) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA4      = pi_vTipoQuebra
               , CODPRINCQUEBRA4 = pi_vCodPrincQuebra
               , CODSECQUEBRA4   = pi_vCodSecQuebra
               , DESQUEBRA4      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 5
        ELSIF (pio_nColunaQuebra = 5) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA5      = pi_vTipoQuebra
               , CODPRINCQUEBRA5 = pi_vCodPrincQuebra
               , CODSECQUEBRA5   = pi_vCodSecQuebra
               , DESQUEBRA5      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 6
        ELSIF (pio_nColunaQuebra = 6) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA6      = pi_vTipoQuebra
               , CODPRINCQUEBRA6 = pi_vCodPrincQuebra
               , CODSECQUEBRA6   = pi_vCodSecQuebra
               , DESQUEBRA6      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 7
        ELSIF (pio_nColunaQuebra = 7) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA7      = pi_vTipoQuebra
               , CODPRINCQUEBRA7 = pi_vCodPrincQuebra
               , CODSECQUEBRA7   = pi_vCodSecQuebra
               , DESQUEBRA7      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 8
        ELSIF (pio_nColunaQuebra = 8) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA8      = pi_vTipoQuebra
               , CODPRINCQUEBRA8 = pi_vCodPrincQuebra
               , CODSECQUEBRA8   = pi_vCodSecQuebra
               , DESQUEBRA8      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        -- Quebra 9
        ELSIF (pio_nColunaQuebra = 9) THEN
          UPDATE PCMED_GERAR_QUEBRA_PEDIDO
             SET TIPQUEBRA9      = pi_vTipoQuebra
               , CODPRINCQUEBRA9 = pi_vCodPrincQuebra
               , CODSECQUEBRA9   = pi_vCodSecQuebra
               , DESQUEBRA9      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);
        ELSIF (pio_nColunaQuebra = 10) THEN
         UPDATE PCMED_GERAR_QUEBRA_PEDIDO P
             SET TIPQUEBRA10      = pi_vTipoQuebra
               , CODPRINCQUEBRA10 = pi_vCodPrincQuebra
               , CODSECQUEBRA10   = pi_vCodSecQuebra
               , DESQUEBRA10      = SUBSTR(pi_vDescricaoQuebra,1,40)
           WHERE (NUMPED  = pi_nNumPed)
             AND (CODPROD = pi_nCodProd)
             AND (NUMSEQ  = pi_nNumSeq);           
        END IF;
  
      END P_ATUALIZA_QUEBRA;
  
      -----------------------------------
      -- PROCEDIMENTO: SALVAR_NOVO_PEDIDO
      -----------------------------------
      PROCEDURE SALVAR_NOVO_PEDIDO(pi_nNumPedOriginal    IN NUMBER,
                                   pi_nNovoNumPed        IN NUMBER,
                                   pi_vCtlAtuItemBonific IN VARCHAR2,
                                   pi_nCodBnf            IN NUMBER,
                                   pio_bGerouPedBnf      IN OUT BOOLEAN,
                                   pio_nNumPedBnf        IN OUT NUMBER,
                                   pi_nVlFreteOutrasDesp IN NUMBER) IS
        -- Parâmetro de Bonificação
        vBONIFICALTDEBCREDRCA PCCONSUM.BONIFICALTDEBCREDRCA%TYPE;
        vMOVCONTACORRBRINDEX  PCBRINDEEX.MOVCCRCA%TYPE;
        -- Registro para quebra do pedido - DDVENDAS-38786
        registroPedido        PCPEDC%ROWTYPE;
      BEGIN
  
        SELECT PCPEDC.* 
          INTO registroPedido
          FROM PCPEDC
         WHERE NUMPED = pi_nNumPedOriginal;
  
        registroPedido.NUMPED            := pi_nNovoNumPed;
        registroPedido.NUMPEDORIGEM      := pi_nNumPedOriginal;
        registroPedido.VLFRETEOUTRASDESP := pi_nVlFreteOutrasDesp;
        
        -- Insere novo Pedido
        INSERT INTO PCPEDC VALUES registroPedido;
  
        --------------------------------------------------------------------------------------
        -- ATUALIZAÇÃO DIFERENCIADA DE ITENS BONIFICADOS
        -- (Aqui deve ser alterado Tipo de Venda por causa do Estorno do Conta-Corrente do RCA
        --------------------------------------------------------------------------------------
        IF (NVL(pi_vCtlAtuItemBonific,'N') = 'S') THEN
  
          -- Pesquisa Parâmetro de Bonfiicação
          BEGIN
            SELECT NVL(PCCONSUM.BONIFICALTDEBCREDRCA,'N')
              INTO vBONIFICALTDEBCREDRCA
              FROM PCCONSUM;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vBONIFICALTDEBCREDRCA := 'N';
          END;
  
          -- Pesquisa Campo de movimentação de conta corrente do cadastro de brinde vinculado ao pedido
          BEGIN
            SELECT NVL(PCBRINDEEX.MOVCCRCA,'N')
              INTO vMOVCONTACORRBRINDEX
              FROM PCBRINDEEX
             WHERE PCBRINDEEX.codbrex IN (SELECT PCPEDI.CODIGOBRINDE
                                            FROM PCPEDI
                                           WHERE PCPEDI.CODIGOBRINDE > 0
                                             AND PCPEDI.NUMPED = pi_nNumPedOriginal)
               AND ROWNUM = 1;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vMOVCONTACORRBRINDEX := 'N';
          END;
  
          -- Atualiza Cabeçalho do Pedido
          UPDATE PCPEDC
             SET CONDVENDA            = 5
               , CODCOB               = 'BNF' -->> Se muda para TV5, deve mudar também a Cobrança
               , CODBNF               = pi_nCodBnf
               , BONIFICALTDEBCREDRCA = NVL(vMOVCONTACORRBRINDEX,
                                             NVL((SELECT PCTIPOBONIFIC.MOVIMENTACCRCA
                                               FROM PCTIPOBONIFIC
                                                   WHERE (PCTIPOBONIFIC.CODBNF = pi_nCodBnf)),vBONIFICALTDEBCREDRCA)) -->> NVL com Parâmetro da PCCONSUM
               , NUMPEDTV1            = pi_nNumPedOriginal
           WHERE (NUMPED  = pi_nNovoNumPed);
  
          -- Gerou Pedido Bonificado
          pio_bGerouPedBnf := TRUE;
          pio_nNumPedBnf   := pi_nNovoNumPed;
          -- LOG
          vvMsgLog := 'Inclusão de Pedido BNF:'   || pi_nNovoNumPed || CHR(13);
          P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                     vvMsgLog);
  
        --------------------------------------------------------------------------------------
        -- SEM ATUALIZAÇÃO DIFERENCIADA
        --------------------------------------------------------------------------------------
        ELSE
  
          -- LOG
          vvMsgLog := 'Inclusão de Pedido Venda:' || pi_nNovoNumPed || CHR(13);
          P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                     vvMsgLog);
  
        END IF; -- FIM:  ATUALIZAÇÃO DIFERENCIADA DE ITENS BONIFICADOS
  
      END SALVAR_NOVO_PEDIDO;
  
      --------------------------------------------
      -- PROCEDIMENTO: ATUALIZAR_ITENS_NOVO_PEDIDO
      --------------------------------------------
      PROCEDURE ATUALIZAR_ITENS_NOVO_PEDIDO(pi_nNumPedOriginal  IN NUMBER,
                                            pi_nNovoNumPed      IN NUMBER,
                                            pi_nCodProd         IN NUMBER,
                                            pi_nNumSeq          IN NUMBER,
                                            pi_nQt              IN NUMBER,
                                            pi_nCodEmitente     IN NUMBER,
                                            pi_nCodUsur         IN NUMBER,
                                            pi_nCodPromocaoMed  IN NUMBER) IS
        vbSaldoRca     BOOLEAN;
        vvTipoPromocao PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
        iQtAtu         INTEGER;
      BEGIN
  
        -- Pesquisa o Tipo de Promoção do Item do Pedido
        BEGIN
          SELECT TIPOPROMOCAO
            INTO vvTipoPromocao
            FROM PCPROMOCAOMED
           WHERE (CODPROMOCAOMED = pi_nCodPromocaoMed);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvTipoPromocao := NULL;
        END;
  
        -- Estorna Conta-Corrente do Pedido Antigo
        -- (SE O PEDIDO ANTIGO ESTAVA COM PROMOÇÃO DE CAMPANHA, NÃO ESTORNA PORQUE NÃO INSERIU NA 2316)
        -- 4415.029804.2019 - Alteração Estorno Conta Corrente com Item de Campanha (novo processo de estoque precisa estornar)
        --IF (NVL(vvTipoPromocao,'C') <> 'N') THEN
          vbSaldoRca := PC_PKG_CONTROLARSALDORCA_MED.ccrca_excluir_item_pedido(pi_nCodEmitente
                                                                          ,2316
                                                                          ,pi_nCodUsur
                                                                          ,pi_nNumPedOriginal
                                                                          ,pi_nCodProd
                                                                          ,pi_nNumSeq
                                                                          ,pi_nQt
                                                                          );
        --END IF;
  
        -- Atualização PADRÃO itens do pedido
        UPDATE PCPEDI
           SET NUMPED = pi_nNovoNumPed
         WHERE NUMPED  = pi_nNumPedOriginal
           AND CODPROD = pi_nCodProd
           AND NUMSEQ  = pi_nNumSeq;
        iQtAtu := NVL(SQL%ROWCOUNT,0);
        -- Atualizar itens da cesta
        UPDATE PCPEDICESTA
           SET NUMPED = pi_nNovoNumPed
         WHERE NUMPED  = pi_nNumPedOriginal
           AND CODPROD = pi_nCodProd
           AND NUMSEQ  = pi_nNumSeq;
        -- Atualizar origem preço
        UPDATE PCORIGEMPRECO
           SET NUMPED = pi_nNovoNumPed
         WHERE NUMPED  = pi_nNumPedOriginal
           AND CODPROD = pi_nCodProd
           AND NUMSEQ  = pi_nNumSeq;
  
        -- Insere Conta-Corrente do Pedido Novo
        vbSaldoRca := PC_PKG_CONTROLARSALDORCA_MED.ccrca_incluir_item_pedido(pi_nCodEmitente
                                                                        ,2316
                                                                        ,pi_nCodUsur
                                                                        ,pi_nNovoNumPed
                                                                        ,pi_nCodProd
                                                                        ,pi_nNumSeq
                                                                        );
      END ATUALIZAR_ITENS_NOVO_PEDIDO;
  
      -----------------------------------
      -- PROCEDIMENTO: CALC_TOTALIZADORES
      -----------------------------------
      PROCEDURE CALC_TOTALIZADORES(pi_nNumPedTotalizar      IN NUMBER,
                                   pi_vOrigemPed            IN VARCHAR2,
                                   pi_vObservacao           IN VARCHAR2,
                                   pi_vCtlAtuItemBonific    IN VARCHAR2,
                                   pi_vCtlAtuDistribuicao   IN VARCHAR2,
                                   pi_vCtlAtuPlanoPagamento IN VARCHAR2,
                                   pi_CtlAtuRcaLinhaProduto IN VARCHAR2,
                                   pi_CtlAtuRestricaoTransp IN VARCHAR2,
                                   pi_nVlFreteOutrasDesp    IN NUMBER) IS
        -- Variáveis do método TOTALIZADORES
        vnTotQTITENS          NUMBER;
        vnTotVLCUSTOFIN       NUMBER;
        vnTotVLCUSTOREAL      NUMBER;
        vnTotVLCUSTOCONT      NUMBER;
        vnTotVLCUSTOREP       NUMBER;
        vnTotVLTABELA         NUMBER;
        vnTotVLATEND          NUMBER;
        vnTotTOTPESO          NUMBER;
        vnTotTOTVOLUME        NUMBER;
        vnTotVLTOTAL          NUMBER;
        -- Variáveis Adicionais TOTALIZADORES
        vnCONDVENDA           PCPEDC.CONDVENDA%TYPE;
        vnVLOUTRASDESP        PCPEDC.VLOUTRASDESP%TYPE;
        vnVLDESCONTO          PCPEDC.VLDESCONTO%TYPE;
        vnVLFRETE             PCPEDC.VLFRETE%TYPE;
        vnVLBONIFIC           PCPEDC.VLBONIFIC%TYPE;
        vnVLATEND             PCPEDC.VLATEND%TYPE;
        vnVLTABELA            PCPEDC.VLTABELA%TYPE;
        vnVLTOTAL             PCPEDC.VLTOTAL%TYPE;
        vnTotUNIDADES         NUMBER;
        vnTotLIQUIDO          NUMBER;
        vnTotSTREPASSE        NUMBER;
        vnTotTOTAL            NUMBER;
        vnPERDESC             PCPEDC.PERDESC%TYPE;
        vnTotFCP              NUMBER;
        -- Código da Distribuição
        vvCodDistrib          PCPEDC.CODDISTRIB%TYPE;
        -- Plano de Pagamento
        vnCodPlPag            PCPEDC.CODPLPAG%TYPE;
        -- Codigo usuario rca por linha de produto
        vvCodUsurRca          PCPEDI.CODUSUR%TYPE;
        -- Carregamento
        vnNumCar              PCPEDC.NUMCAR%TYPE;
        -- MED-1999 - Plano Bonificação
        vnCodPlPagBNF         PCPEDC.CODPLPAG%TYPE;
         -- restrição transporte
        vnTipoRestricao       PCPEDC.RESTRICAOTRANSP%TYPE;      
      BEGIN
  
        -------------------------------------------
        -- ATUALIZAÇÃO DIFERENCIADA DE DISTRIBUIÇÃO
        -------------------------------------------
        IF (pi_vCtlAtuDistribuicao = 'S') THEN
  
          -- Pesquisa o Código da Distribuição de um dos Produtos
          BEGIN
            SELECT PCPRODUT.CODDISTRIB
              INTO vvCodDistrib
              FROM PCPEDI
                 , PCPRODUT
             WHERE (PCPEDI.CODPROD = PCPRODUT.CODPROD)
               AND (PCPEDI.NUMPED  = pi_nNumPedTotalizar)
               AND (ROWNUM         = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvCodDistrib := NULL;
          END;
  
          -- Atualizar a Distribuição do Pedido
          UPDATE PCPEDC
             SET CODDISTRIB = vvCodDistrib
           WHERE (NUMPED  = pi_nNumPedTotalizar);
  
        END IF;
  
       -------------------------------------------
       -- ATUALIZAÇÃO DIFERENCIADA RCA POR LINHA DE PRODUTO
       -------------------------------------------
       IF (pi_CtlAtuRcaLinhaProduto = 'S') THEN
         BEGIN
             SELECT DECODE(NVL(PCPEDI.CODUSUR,0),0,PCPEDC.CODUSUR,PCPEDI.CODUSUR) CODQUEBRA_RCALINHA_PRODUTO
             INTO vvCodUsurRca
             FROM PCPEDI,
                  PCPEDC
             WHERE PCPEDI.NUMPED   = pi_nNumPedTotalizar
             AND   PCPEDC.NUMPED   = PCPEDI.NUMPED
             AND   (ROWNUM         = 1);
         EXCEPTION
             WHEN NO_DATA_FOUND THEN
                vvCodUsurRca := NULL;
         END;
  
          UPDATE PCPEDC SET CODUSUR  = vvCodUsurRca
          WHERE PCPEDC.NUMPED = pi_nNumPedTotalizar;
       END IF;
  
        -------------------------------------------------
        -- ATUALIZAÇÃO DIFERENCIADA DE PLANO DE PAGAMENTO
        ------------------------------------------------
        IF (pi_vCtlAtuPlanoPagamento = 'S') THEN
  
          -- Pesquisa um Código de Plano de Pagamento de um dos Produtos
          BEGIN
            SELECT PCPEDI.CODPLPAG
              INTO vnCodPlPag
              FROM PCPEDI
             WHERE (PCPEDI.NUMPED  = pi_nNumPedTotalizar)
               AND (ROWNUM         = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vnCodPlPag := NULL;
          END;
  
          -- Atualizar Plano de Pagamento do Pedido
          IF (NVL(vnCodPlPag,0) > 0) THEN
  
            -- Pesquisa Prazo Médio
            P_OBTER_PRAZO_PEDIDO(pi_nNumPedTotalizar,
                                 vnCodPlPag,
                                 vrPrazos);
  
            -- Atualiza Plano de Pagamento e Prazos do Pedido
            UPDATE PCPEDC
               SET CODPLPAG   = vnCodPlPag
                 , PRAZO1     = vrPrazos.vnPrazo1
                 , PRAZO2     = vrPrazos.vnPrazo2
                 , PRAZO3     = vrPrazos.vnPrazo3
                 , PRAZO4     = vrPrazos.vnPrazo4
                 , PRAZO5     = vrPrazos.vnPrazo5
                 , PRAZO6     = vrPrazos.vnPrazo6
                 , PRAZO7     = vrPrazos.vnPrazo7
                 , PRAZO8     = vrPrazos.vnPrazo8
                 , PRAZO9     = vrPrazos.vnPrazo9
                 , PRAZO10    = vrPrazos.vnPrazo10
                 , PRAZO11    = vrPrazos.vnPrazo11
                 , PRAZO12    = vrPrazos.vnPrazo12
                 , PRAZOMEDIO = vrPrazos.vnPrazoMedio
             WHERE (NUMPED  = pi_nNumPedTotalizar);
  
          END IF;
  
        END IF;
  
        ------------------------------------------------
        -- ATUALIZAÇÃO DIFERENCIADA DE ITENS BONIFICADOS
        ------------------------------------------------
        IF (pi_vCtlAtuItemBonific = 'S') THEN
  
          -- Se utiliza Plano de Pagamento por Linha de Prazo
          IF (NVL(vTIPOPRAZOMEDICAMEN,'1') = '4') THEN
            -- Limpar o Campo BONIFIC porque deixará se ser Item Bonificado em TV1 para passar a ser TV5
            -- E
            -- Alterar o Plano de Pagamento para 99 porque deixará se ser Item Bonificado em TV1 para passar a ser TV5 com Plano 99 (com Plano de Pagamento por Linha)
            UPDATE PCPEDI
               SET BONIFIC = NULL
                 , CODPLPAG = 99
             WHERE (NUMPED  = pi_nNumPedTotalizar);
            -- Colocar o Pedido com Plano 99 e Cobrança BNF (O CONDVENDA = 5 é colocado na geração da PCPEDC)
            UPDATE PCPEDC
               SET CODPLPAG         = 99
                 , CODCOB           = 'BNF'
                 , CODPLPAGETICO    = NULL
                 , CODPLPAGGENERICO = NULL
                 , PERDESC          = 100
             WHERE (NUMPED  = pi_nNumPedTotalizar);
            -- Pesquisa Prazo Médio
            P_OBTER_PRAZO_PEDIDO(pi_nNumPedTotalizar,
                                 99, -->> Plano 99
                                 vrPrazos);
          -- Se não usar Linhas de Prazo no Plano de Pagamento
          ELSE
            -- MED-1999 - Plano Bonificação
            BEGIN
              SELECT CODPLPAG
                INTO vnCodPlPagBNF
                FROM PCPLPAG
               WHERE (TIPOPRAZO = 'B')
                 AND (ROWNUM    = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                BEGIN
                  SELECT CODPLPAG
                   INTO vnCodPlPagBNF
                   FROM PCPEDC
                  WHERE (NUMPED = pi_nNumPed);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnCodPlPagBNF := 99;
                END;
            END;
            -- Limpar o Campo BONIFIC porque deixará se ser Item Bonificado em TV1 para passar a ser TV5
            UPDATE PCPEDI
               SET BONIFIC  = NULL
             WHERE (NUMPED  = pi_nNumPedTotalizar);
            -- Colocar o Pedido Plano 99 e Cobrança BNF (O CONDVENDA = 5 é colocado na geração da PCPEDC)
            UPDATE PCPEDC
               SET CODPLPAG         = vnCodPlPagBNF -->> MED-1999 - Plano Bonificação
                 , CODCOB           = 'BNF'
                 , CODPLPAGETICO    = NULL
                 , CODPLPAGGENERICO = NULL
                 , PERDESC          = 100
             WHERE (NUMPED  = pi_nNumPedTotalizar);
            -- Pesquisa Prazo Médio -->> MED-1999 - Plano Bonificação
            P_OBTER_PRAZO_PEDIDO(pi_nNumPedTotalizar,
                                 vnCodPlPagBNF , -->> Plano BNF
                                 vrPrazos);
          END IF;
  
          -- Atualiza Prazos do Pedido (Depende antes da Atualização da Cobrança)
          UPDATE PCPEDC
             SET PRAZO1     = vrPrazos.vnPrazo1
               , PRAZO2     = vrPrazos.vnPrazo2
               , PRAZO3     = vrPrazos.vnPrazo3
               , PRAZO4     = vrPrazos.vnPrazo4
               , PRAZO5     = vrPrazos.vnPrazo5
               , PRAZO6     = vrPrazos.vnPrazo6
               , PRAZO7     = vrPrazos.vnPrazo7
               , PRAZO8     = vrPrazos.vnPrazo8
               , PRAZO9     = vrPrazos.vnPrazo9
               , PRAZO10    = vrPrazos.vnPrazo10
               , PRAZO11    = vrPrazos.vnPrazo11
               , PRAZO12    = vrPrazos.vnPrazo12
               , PRAZOMEDIO = vrPrazos.vnPrazoMedio
           WHERE (NUMPED  = pi_nNumPedTotalizar);
  
          -- SE BALCÃO RESERVA (Regra que tinha na procedure de pacote de gerar pedido de brindes)
          IF (pi_vOrigemPed = 'R') THEN
  
            -- Próximo Numero Carregamento
            vnNumCar := FUNCOES_MED.FOBTEM_PROX_NUMCAR_PRAGMA;
  
            -- Se conseguiu gerar Numero Carregamento
            IF (NVL(vnNumCar,0) > 0) THEN
  
              -- Insere Carregamento
              INSERT INTO PCCARREG
                (NUMCAR, DTSAIDA)
              VALUES
                (vnNumCar, TRUNC(SYSDATE));
  
              -- Atualiza Pedido
              UPDATE PCPEDC
                 SET NUMCAR = vnNumCar
               WHERE (NUMPED = pi_nNumPedTotalizar);
  
              -- Atualiza Itens do pedido
              UPDATE PCPEDI
                 SET NUMCAR = vnNumCar
               WHERE (NUMPED = pi_nNumPedTotalizar);
  
            END IF;
  
          END IF; -- Fim Condição: SE BALCÃO RESERVA
  
        END IF; -- FIM:  ATUALIZAÇÃO DIFERENCIADA DE ITENS BONIFICADOS
        
        IF (pi_CtlAtuRestricaoTransp = 'S') THEN
            BEGIN
             SELECT p.restricaotransp
             INTO vnTipoRestricao
             FROM PCPEDI I,
                  PCPRODUT P
             WHERE (I.CODPROD = P.CODPROD)
               AND (I.NUMPED  = pi_nNumPedTotalizar)
               AND (ROWNUM    = 1);
            EXCEPTION
             WHEN NO_DATA_FOUND THEN
                vnTipoRestricao := NULL;
         END;
  
          UPDATE PCPEDC P SET P.RESTRICAOTRANSP  = vnTipoRestricao
          WHERE P.NUMPED = pi_nNumPedTotalizar;
        END IF;
  
        ------------------------
        -- TOTALIZAÇÃO DO PEDIDO
        ------------------------
  
        -- Pesquisa o Tipo de Pedido - HIS.01889.2017
        BEGIN
          SELECT CONDVENDA
               , VLOUTRASDESP
               , VLDESCONTO
               , VLFRETE
               , VLTOTAL
            INTO vnCONDVENDA
               , vnVLOUTRASDESP
               , vnVLDESCONTO
               , vnVLFRETE
               , vnVLTOTAL
            FROM PCPEDC
           WHERE (NUMPED = pi_nNumPedTotalizar);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnCONDVENDA    := NULL;
            vnVLOUTRASDESP := 0;
            vnVLDESCONTO   := 0;
            vnVLFRETE      := 0;
            vnVLTOTAL      := 0;
        END;
  
        -- Calcula o novo Total do Pedido
        -- DDMEDICA-7697 - Aplicação do ST Recolhido Anteriormente
        SELECT COUNT(*) ITENS,
               SUM(QT) UNIDADES,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOFIN, 0)) VLCUSTOFIN,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOREAL, 0)) VLCUSTOREAL,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOCONT, 0)) VLCUSTOCONT,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLCUSTOREP, 0)) VLCUSTOREP,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PTABELA, 0)) VLTABELA,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0)) VLATEND,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPRODUT.PESOBRUTO, 0)) TOTPESOBRUTO,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPRODUT.VOLUME, 0)) TOTVOLUME,
               SUM((NVL(PCPEDI.QT, 0) + NVL(PCPEDI.QTFALTA, 0)) * PCPEDI.PVENDA) VLTOTAL,
               SUM(NVL(PCPEDI.QT, 0) * (NVL(PCPEDI.PVENDA, 0) - NVL(PCPEDI.ST, 0) - NVL(PCPEDI.VLICMSSTRETANTERIOR, 0) - NVL(PCPEDI.VLREPASSE, 0)- NVL(PCPEDI.VLFECP,0))) LIQUIDO, -- DDMEDICA-7697
               SUM(NVL(PCPEDI.QT, 0) * (NVL(PCPEDI.ST, 0) + NVL(PCPEDI.VLICMSSTRETANTERIOR, 0) + NVL(PCPEDI.VLREPASSE, 0))) STREPASSE, -- DDMEDICA-7697
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0)) TOTAL,
               SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLFECP,0)) TOTFCP
          INTO vnTotQTITENS,
               vnTotUNIDADES,
               vnTotVLCUSTOFIN,
               vnTotVLCUSTOREAL,
               vnTotVLCUSTOCONT,
               vnTotVLCUSTOREP,
               vnTotVLTABELA,
               vnTotVLATEND,
               vnTotTOTPESO,
               vnTotTOTVOLUME,
               vnTotVLTOTAL,
               vnTotLIQUIDO,
               vnTotSTREPASSE,
               vnTotTOTAL,
               vnTotFCP
          FROM PCPEDI
             , PCPRODUT
         WHERE (PCPEDI.CODPROD = PCPRODUT.CODPROD)
           AND (PCPEDI.NUMPED = pi_nNumPedTotalizar);
  
        -- HIS.01889.2017 - Calcula antes por causa do TV5
        vnVLATEND := (NVL(vnTotVLATEND, 0) -
                      NVL(vnVLDESCONTO, 0) +   -- Desconto já gravado no Pedido
                      NVL(vnVLOUTRASDESP, 0) + -- Outras Despesas já gravado no Pedido
                      NVL(vnVLFRETE, 0));      -- Frete já gravado no Pedido
  
        -- HIS.01889.2017 - Calcula Valor Tabela
        vnVLTABELA := (NVL(vnTotVLTABELA, 0) +
                       NVL(vnVLOUTRASDESP, 0) + -- Outras Despesas já gravado no Pedido
                       NVL(vnVLFRETE, 0));      -- Frete já gravado no Pedido
  
        -- HIS.01889.2017 - Calcula Valor Total
        vnVLTOTAL  := (NVL(vnTotVLTOTAL, 0) -
                       NVL(vnVLDESCONTO, 0) +   -- Desconto já gravado no Pedido
                       NVL(vnVLOUTRASDESP, 0) + -- Outras Despesas já gravado no Pedido
                       NVL(vnVLFRETE, 0));      -- Frete já gravado no Pedido
  
        -- Bonificação TV5 - HIS.01889.2017
        IF (NVL(vnCONDVENDA,0) = 5) THEN
  
          vnVLBONIFIC := vnVLATEND;
          vnVLATEND   := 0; -- TV5 não manda VLATEND
  
        -- Venda
        ELSE
  
          -- Totais BNF em TV1 -- HIS.01889.2017
          SELECT SUM(PBONIFIC * QT)
            INTO vnVLBONIFIC
            FROM PCPEDI
           WHERE NUMPED  = pi_nNumPedTotalizar
             AND BONIFIC = 'F';
  
          -- Abate do Valor Atendido o que está em Itens Bonificados em TV1 -- HIS.01889.2017
          vnVLATEND  := ROUND(vnVLATEND - NVL(vnVLBONIFIC,0), 2);
  
        END IF;
  
        -- Perdesc do Pedido
        IF (NVL(vnCONDVENDA,0) = 5) THEN
          vnPERDESC := 100;
        ELSE
          IF (vnTotVLTABELA <> 0) THEN
            vnPERDESC := ((NVL(vnTotVLTABELA,0) - NVL(vnVLATEND,0)) / NVL(vnTotVLTABELA,0)) * 100;
          ELSE
            vnPERDESC := 0;
          END IF;
        END IF;
  
        ------------------------
        -- ATUALIZAÇÃO DO PEDIDO
        ------------------------
  
        -- Atualiza Posição e Totais do Pedido
        UPDATE PCPEDC
           SET VLATEND     = vnVLATEND,   -- HIS.01889.2017
               VLBONIFIC   = vnVLBONIFIC, -- HIS.01889.2017
               NUMITENS    = vnTotQTITENS,
               VLCUSTOFIN  = vnTotVLCUSTOFIN,
               VLCUSTOREAL = vnTotVLCUSTOREAL,
               TOTPESO     = vnTotTOTPESO,
               TOTVOLUME   = vnTotTOTVOLUME,
               VLCUSTOCONT = vnTotVLCUSTOCONT,
               VLCUSTOREP  = vnTotVLCUSTOREP,
               VLTABELA    = vnVLTABELA,
               VLTOTAL     = vnVLTOTAL,
               VLFRETEOUTRASDESP = pi_nVlFreteOutrasDesp -- Taxa Frete
         WHERE (NUMPED = pi_nNumPedTotalizar);
  
        -- Insere na Tabela Temporária
        INSERT INTO PCMED_RESUMO_PEDIDOS
                  ( NUMPEDORIGINAL
                  , NUMPED
                  , ITENS
                  , QT
                  , TOTLIQUIDO
                  , TOTSTREPASSE
                  , TOTPVENDA
                  , OBSERVACAO
                  , TOTFCP )
           VALUES ( pi_nNumPed
                  , pi_nNumPedTotalizar
                  , vnTotQTITENS
                  , vnTotUNIDADES
                  , vnTotLIQUIDO
                  , vnTotSTREPASSE
                  , vnTotTOTAL
                  , SUBSTR(pi_vObservacao,1,250)
                  , vnTotFCP );
  
      END CALC_TOTALIZADORES;
  
      -----------------------------------------
      -- FUNÇÃO: OBTER_NOVO_NUMPED_PCPEDC
      -----------------------------------------
      FUNCTION OBTER_NOVO_NUMPED_PCPEDC(pi_nCodUsur IN NUMBER)
      RETURN NUMBER IS
        vnRetNovoNumPed PCPEDC.NUMPED%TYPE;
      BEGIN
        -- Obtém Próximo Número do Pedido
        vnRetNovoNumPed := FUNCOES_MED.FOBTEM_PROX_NUMPED_PRAGMA(pi_nCodUsur);
        -- Retorno
        RETURN vnRetNovoNumPed;
      END OBTER_NOVO_NUMPED_PCPEDC;
  
    /*********************************
     INICIO DO PROCESSAMENTO PRINCIPAL
     *********************************/
    BEGIN
  
      -- INICIALIZA RETORNO
      po_vRetorno   := '1';
  
      -- Inicializa Controle de Geração de Pedido Bonificado
      vbGerouPedBnf := FALSE;
  
      -------------------------------
      -- Inicializa Tabela Temporária
      -------------------------------
  
      -- Limpa Tabela Temporária
      DELETE FROM PCMED_RESUMO_PEDIDOS;
      DELETE FROM PCMED_GERAR_QUEBRA_PEDIDO;
  
      -- Insere na Tabela Temporária os Itens do Pedido
      INSERT INTO PCMED_GERAR_QUEBRA_PEDIDO
                ( NUMPED
                , CODPROD
                , NUMSEQ
                , QT
                , CODPROMOCAOMED
                , TIPQUEBRA1
                , TIPQUEBRA2
                , TIPQUEBRA3
                , TIPQUEBRA4
                , TIPQUEBRA5
                , TIPQUEBRA6
                , TIPQUEBRA7
                , TIPQUEBRA8
                , TIPQUEBRA9
                --
                , CODPRINCQUEBRA1
                , CODPRINCQUEBRA2
                , CODPRINCQUEBRA3
                , CODPRINCQUEBRA4
                , CODPRINCQUEBRA5
                , CODPRINCQUEBRA6
                , CODPRINCQUEBRA7
                , CODPRINCQUEBRA8
                , CODPRINCQUEBRA9
                --
                , CODSECQUEBRA1
                , CODSECQUEBRA2
                , CODSECQUEBRA3
                , CODSECQUEBRA4
                , CODSECQUEBRA5
                , CODSECQUEBRA6
                , CODSECQUEBRA7
                , CODSECQUEBRA8
                , CODSECQUEBRA9
                --
                , DESQUEBRA1
                , DESQUEBRA2
                , DESQUEBRA3
                , DESQUEBRA4
                , DESQUEBRA5
                , DESQUEBRA6
                , DESQUEBRA7
                , DESQUEBRA8
                , DESQUEBRA9
                --
                , OBSERVACAO
                , PRODST )
           SELECT NUMPED
                , CODPROD
                , NUMSEQ
                , QT
                , CODPROMOCAOMED
                , 'SQ' TIPQUEBRA1
                , 'SQ' TIPQUEBRA2
                , 'SQ' TIPQUEBRA3
                , 'SQ' TIPQUEBRA4
                , 'SQ' TIPQUEBRA5
                , 'SQ' TIPQUEBRA6
                , 'SQ' TIPQUEBRA7
                , 'SQ' TIPQUEBRA8
                , 'SQ' TIPQUEBRA9
                --
                , '0'  CODPRINCQUEBRA1
                , '0'  CODPRINCQUEBRA2
                , '0'  CODPRINCQUEBRA3
                , '0'  CODPRINCQUEBRA4
                , '0'  CODPRINCQUEBRA5
                , '0'  CODPRINCQUEBRA6
                , '0'  CODPRINCQUEBRA7
                , '0'  CODPRINCQUEBRA8
                , '0'  CODPRINCQUEBRA9
                --
                , '0'  CODSECQUEBRA1
                , '0'  CODSECQUEBRA2
                , '0'  CODSECQUEBRA3
                , '0'  CODSECQUEBRA4
                , '0'  CODSECQUEBRA5
                , '0'  CODSECQUEBRA6
                , '0'  CODSECQUEBRA7
                , '0'  CODSECQUEBRA8
                , '0'  CODSECQUEBRA9
                --
                , NULL DESQUEBRA1
                , NULL DESQUEBRA2
                , NULL DESQUEBRA3
                , NULL DESQUEBRA4
                , NULL DESQUEBRA5
                , NULL DESQUEBRA6
                , NULL DESQUEBRA7
                , NULL DESQUEBRA8
                , NULL DESQUEBRA9
                --
                , NULL OBSERVACAO
                , NULL PRODST
             FROM PCPEDI
            WHERE (NUMPED = pi_nNumPed);
  
      ---------------------------
      -- Pesquisa Dados do Pedido
      ---------------------------
      BEGIN
        SELECT CODEMITENTE
             , CODUSUR
             , POSICAO
             , CONDVENDA -- HIS.01889.2017
             , ORIGEMPED
             , CODPLPAG
             , ORIGEMPED -- Taxa Frete
             , TIPOFV    -- Taxa Frete
             , NUMTRANSENTCROSSDOCK
          INTO vrDadosPedidoOriginal.vnCodEmitente
             , vrDadosPedidoOriginal.vnCodUsur
             , vrDadosPedidoOriginal.vvPosicao
             , vrDadosPedidoOriginal.vnCondVenda -- HIS.01889.2017
             , vrDadosPedidoOriginal.vvOrigemPed
             , vrDadosPedidoOriginal.vnCodPlPag
             , vrDadosPedidoOriginal.vvOrigemPed -- Taxa Frete
             , vrDadosPedidoOriginal.vvTipoFv    -- Taxa Frete
             , vrDadosPedidoOriginal.vnNumTransEntCrossDock
          FROM PCPEDC
         WHERE NUMPED = pi_nNumPed;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrDadosPedidoOriginal.vnCodEmitente          := NULL;
          vrDadosPedidoOriginal.vnCodUsur              := NULL;
          vrDadosPedidoOriginal.vvPosicao              := NULL;
          vrDadosPedidoOriginal.vnCondVenda            := NULL; -- HIS.01889.2017
          vrDadosPedidoOriginal.vvOrigemPed            := NULL;
          vrDadosPedidoOriginal.vnCodPlPag             := NULL;
          vrDadosPedidoOriginal.vvOrigemPed            := NULL; -- Taxa Frete
          vrDadosPedidoOriginal.vvTipoFv               := NULL; -- Taxa Frete
          vrDadosPedidoOriginal.vnNumTransEntCrossDock := NULL;
      END;
  
      -------------------------
      -- Pesquisa Taxa de Frete
      -------------------------
      vnVlFreteOutrasDesp := 0;
      OBTER_TAXA_FRETE(pi_vCodFilial,
                       vrDadosPedidoOriginal.vvOrigemPed,
                       vrDadosPedidoOriginal.vvTipoFv,
                       vrRetTaxaFrete.vvAchouFrete,
                       vrRetTaxaFrete.vnValorTaxa,
                       vrRetTaxaFrete.vnValorMinimo);
      IF (vrRetTaxaFrete.vvAchouFrete = 'S') THEN
        -- Calcula Total do Pedido
        SELECT SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0)) VLATEND
          INTO vnTotalPedidoValidaTaxafrete
          FROM PCPEDI
         WHERE (PCPEDI.NUMPED = pi_nNumPed);
        -- Se Total do Pedido ficar abaixo do Mínimo (acima ou igual ao mínimo não aplica a taxa de frete)
        IF (NVL(vnTotalPedidoValidaTaxafrete,0) < NVL(vrRetTaxaFrete.vnValorMinimo,0)) THEN
          vnVlFreteOutrasDesp := NVL(vrRetTaxaFrete.vnValorTaxa,0);
        END IF;
      END IF;
  
      ---------------------------
      -- Pesquisa Parâmetros
      ---------------------------
      BEGIN
        SELECT VALOR
          INTO vQUEBRARPEDIDOREGIMESP
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = pi_vCodFilial
           AND NOME      = 'QUEBRARPEDIDOREGIMESP';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vQUEBRARPEDIDOREGIMESP := 'N';
      END;
  
      BEGIN
        SELECT VALOR
          INTO vQUEBRARPEDIDOTIPOMEDICAM
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = pi_vCodFilial
           AND NOME = 'QUEBRARPEDIDOTIPOMEDICAM';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vQUEBRARPEDIDOTIPOMEDICAM := 'N';
      END;
  
      BEGIN
        SELECT VALOR
          INTO vQUEBRARPEDIDODISTRIBMED
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = '99'
           AND NOME = 'QUEBRARPEDIDODISTRIBMED';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vQUEBRARPEDIDODISTRIBMED := 'N';
      END;
  
      BEGIN
        SELECT VALOR
          INTO vGRAVARPEDVENBLOQMED
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = '99'
           AND NOME = 'GRAVARPEDVENBLOQMED';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vGRAVARPEDVENBLOQMED := 'N';
      END;
  
      BEGIN
        SELECT VALOR
          INTO vMEDQUEBRARPEDPLPAGLINHAPRAZO
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = pi_vCodFilial
           AND NOME = 'MEDQUEBRARPEDPLPAGLINHAPRAZO';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vMEDQUEBRARPEDPLPAGLINHAPRAZO := 'N';
      END;
      -- 4415.029804.2019 - Se Pedido do Força de Vendas e OL/PE, já vem Quebrado por Plano de Pagamento
      IF (NVL(pi_nCodRotina,0) <> 2336) THEN -- DDMEDICA-7182 - Se 2336 pode quebrar o pedido pela alteração dos planos de pagamento
        IF (vrDadosPedidoOriginal.vvOrigemPed = 'F') THEN
          vMEDQUEBRARPEDPLPAGLINHAPRAZO := 'N';
        END IF;
      END IF;
  
      BEGIN
        SELECT VALOR
          INTO vTIPOPRAZOMEDICAMEN
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = '99'
           AND NOME = 'TIPOPRAZOMEDICAMEN';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vTIPOPRAZOMEDICAMEN := '1';
      END;
  
      BEGIN
        SELECT NVL(VALOR,'N')
          INTO vrParametros.vvSepararProdComSt
          FROM PCPARAMFILIAL
         WHERE CODFILIAL = pi_vCodFilial
           AND NOME = 'SEPARARPRODCOMST';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParametros.vvSepararProdComSt := 'N';
      END;
  
      -- Parâmetros da PCCONSUM
      BEGIN
        SELECT NVL(PCCONSUM.GERARBRINDEPEDBONIFIC,'N')
          INTO vrParametros.vvGerarBrindePedBonific
          FROM PCCONSUM;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParametros.vvGerarBrindePedBonific := 'N';
      END;
  
      BEGIN
          SELECT VALOR
          INTO vQUEBRARPEDIDORCALINHA
          FROM PCPARAMFILIAL
          WHERE CODFILIAL = '99'
          AND NOME = 'QUEBRARPEDIDORCALINHA';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
             vQUEBRARPEDIDORCALINHA := 'N';
      END;
  
      -------------------------------------------------------
      -- QUEBRA DE BONIFICAÇÃO - HIS.01889.2017
      -- (Verifica se terá Quebra de Bonificação de Campanha)
      -------------------------------------------------------
      vvExisteCampanha := 'N';
      IF (vrDadosPedidoOriginal.vnCondVenda = 1) THEN -->> IMPORTANTE: Somente Venda
        BEGIN
          SELECT 'S'
            INTO vvExisteCampanha
            FROM PCPEDI
               , PCPROMOCAOMED
           WHERE (PCPEDI.CODPROMOCAOMED      = PCPROMOCAOMED.CODPROMOCAOMED)
             AND (PCPEDI.NUMPED              = pi_nNumped) /* Filtro Número do Pedido */
             AND (PCPROMOCAOMED.TIPOPROMOCAO = 'N')
             AND (ROWNUM                     = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvExisteCampanha := 'N';
        END;
      END IF;
  
      -------------------------------------------------------
      -- QUEBRA DE BRINDES
      -------------------------------------------------------
      vvExisteBrinde := 'N';
      IF (vrDadosPedidoOriginal.vnCondVenda IN (1,10)) AND
         (vrParametros.vvGerarBrindePedBonific = 'S')  THEN
        BEGIN
          SELECT 'S'
            INTO vvExisteBrinde
            FROM PCPEDI
           WHERE (PCPEDI.NUMPED = pi_nNumped) /* Filtro Número do Pedido */
             AND (PCPEDI.BRINDE = 'S')
             AND (ROWNUM        = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvExisteBrinde := 'N';
        END;
        -- Código da Bonificação Padrão do Brinde
        BEGIN
          SELECT PCTIPOBONIFIC.CODBNF
            INTO vnCodBnfPadraoBrinde
            FROM PCTIPOBONIFIC
           WHERE (PCTIPOBONIFIC.BONIFPADRAO = 'S')
             AND (ROWNUM = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnCodBnfPadraoBrinde := NULL;
        END;
        -- Código do Plano de Pagamento do Brinde
        BEGIN
          SELECT PCPLPAG.CODPLPAG
            INTO vnCodPlPagBrinde
            FROM PCPLPAG
           WHERE (PCPLPAG.TIPOPRAZO = 'B')
             AND (ROWNUM = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            -- Se não achou Plano de Pagamento de Bonificação, usa o Plano do Pedido
            vnCodPlPagBrinde := vrDadosPedidoOriginal.vnCodPlPag;
        END;
      END IF; -- Fim Condição: (vrParametros.vvGerarBrindePedBonific = 'S')
  
      -------------------------------------------------------
      -- QUEBRA DE PRODUTOS COM ST
      -------------------------------------------------------
      vvExisteProdSt := 'N';
      IF (vrParametros.vvSepararProdComSt = 'S') THEN
  
         -- Itens com ST maior que zero
         SELECT COUNT(*)
           INTO viContadorSimProdSt
           FROM (
         SELECT CODPROD,
                NUMSEQ,
                ferramentas.VERIFICAR_ISENTOST(pcpedi.CODCLI,pcpedi.CODPROD,pcpedi.CODST) ISENTOST,
                pcpedi.st,
                PCPEDI.BASEICST
           FROM pcpedi
          WHERE pcpedi.numped = pi_nNumPed )
          WHERE ((ST > 0)
             OR (ST = 0 AND ISENTOST = 'N'))
            AND (BASEICST > 0);
  
         -- Itens com ST igual a zero
         SELECT COUNT(*)
          INTO viContadorNaoProdSt
          FROM (
        SELECT CODPROD,
               NUMSEQ,
               ferramentas.VERIFICAR_ISENTOST(pcpedi.CODCLI,pcpedi.CODPROD,pcpedi.CODST) ISENTOST,
               pcpedi.st,
               PCPEDI.BASEICST
          FROM pcpedi
         WHERE pcpedi.numped = pi_nNumPed )
         WHERE (ST = 0)
           AND ((ISENTOST = 'S')
            OR (BASEICST = 0 ));
  
        -- Se vai gerar Quebra
        IF (viContadorSimProdSt > 0) AND
           (viContadorNaoProdSt > 0) THEN
  
           -- Laço somente dos Produtos com ST
           FOR vc_ProdSt IN ( SELECT CODPROD
                                   , NUMSEQ
                                   , ISENTOST
                                   , ST
                                   , BASEICST
                                FROM (
                              SELECT CODPROD,
                                     NUMSEQ,
                                     ferramentas.VERIFICAR_ISENTOST(pcpedi.CODCLI,pcpedi.CODPROD,pcpedi.CODST) ISENTOST,
                                     pcpedi.st,
                                     PCPEDI.BASEICST
                                FROM pcpedi
                               WHERE pcpedi.numped = pi_nNumPed )
                               WHERE ((ST > 0)
                                  OR (ST = 0 AND ISENTOST = 'N'))
                                 AND (BASEICST > 0) ) LOOP
  
             -- Marca na Tabela Temporária os Produtos com ST
             UPDATE PCMED_GERAR_QUEBRA_PEDIDO
                SET PRODST = 'S'
              WHERE (NUMPED  = pi_nNumPed)
                AND (CODPROD = vc_ProdSt.CODPROD)
                AND (NUMSEQ  = vc_ProdSt.NUMSEQ);
  
           END LOOP;
  
          -- VAI EXISTIR QUEBRA DE PRODUTOS COM ST
          vvExisteProdSt := 'N';
  
        END IF; -- Fim Condição: -- Se vai gerar Quebra
  
      END IF; -- (vrParametros.vvSepararProdComSt = 'S')
  
      -- Regra para Quebra de Controlados em Pedidos de Crossdocking
      vQUEBRACONTROLADOSCROSSDOCK := 'N';
      IF (NVL(vrDadosPedidoOriginal.vnNumTransEntCrossDock,0) > 0) THEN
        BEGIN
          SELECT VALOR
            INTO vQUEBRACONTROLADOSCROSSDOCK
            FROM PCREGRASEXCECAOMED
           WHERE (CODFILIAL = '99')
             AND (NOME      = 'QUEBRACONTROLADOSCROSSDOCK');
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vQUEBRACONTROLADOSCROSSDOCK := 'N';
        END;
      END IF;
      
       -- QUEBRA DE PEDIDO POR RESTRIÇÃO DE TRANSPORTE.
      BEGIN
          SELECT VALOR
          INTO vQUEBRARPEDIDORESTRICAOTRANSP
          FROM PCPARAMFILIAL
          WHERE CODFILIAL = '99'
          AND NOME = 'CON_SEPARARPRODCOMRESTRICAOTRANSP';
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
             vQUEBRARPEDIDORESTRICAOTRANSP := 'N';           
      END;
      
  
     /***********************************************************************************************
      Controle para não quebrar Pedidos que são gravados como Bloqueados com base em parâmetro da 132
      ***********************************************************************************************/
      IF ((NVL(vGRAVARPEDVENBLOQMED,'N') = 'N') OR
          ((NVL(vGRAVARPEDVENBLOQMED,'S') = 'S') AND (NVL(vrDadosPedidoOriginal.vvPosicao,' ') = 'L'))) THEN
  
        -------------------------------------------------
        -- Validações para verificar se pode Gerar Quebra
        -------------------------------------------------
  
        -- Quebra por Distribuição
        IF (NVL(vMEDQUEBRARPEDPLPAGLINHAPRAZO,'N') = 'S') THEN
          SELECT COUNT(*)
            INTO viQtRegistrosEncontrados
            FROM PCPEDI
           WHERE (NVL(PCPEDI.CODPLPAG,0) = 0)
             AND (PCPEDI.NUMPED  = pi_nNumped);
          IF (NVL(viQtRegistrosEncontrados,0) > 0) THEN
            vvMsgErroTratado := 'Foram encontrados ' || viQtRegistrosEncontrados || ' Itens sem plano de Pagamento.' || CHR(13) || 'Quebra de Pedido não permitida!';
            RAISE e_Tratado;
          END IF;
        END IF;
  
  
        ------------------------------
        -- Laço de Geração das Quebras
        ------------------------------
        FOR vcProduto IN (SELECT PCPEDI.NUMPED
                               , PCPEDI.CODPROD
                               , PCPEDI.NUMSEQ
                               , NVL(PCPEDI.BONIFIC,'N') BONIFIC
                               ------------------------------------------------
                               -- QUEBRA POR BONIFICAÇÃO
                               ------------------------------------------------
                               , CASE WHEN (NVL(PCPEDI.BONIFIC,'N') = 'F') THEN
                                   'F'
                                 ELSE
                                   'N'
                                 END CODQUEBRA_BONIFICACAO
                               , CASE WHEN (NVL(PCPEDI.BONIFIC,'N') = 'F') THEN
                                   TO_CHAR(NVL(PCPROMOCAOMED.CODBNF,0))
                                 ELSE
                                   '0'
                                 END CODQUEBRA_CODBNF
                               , CASE WHEN (NVL(PCPEDI.BONIFIC,'N') = 'F') THEN
                                   CASE WHEN (NVL(PCPROMOCAOMED.CODBNF,0) = 0) THEN
                                     'Pedido Bonificado'
                                   ELSE
                                     'Pedido Bonificado: ' || NVL(PCPROMOCAOMED.CODBNF,0) || ' - ' || (SELECT PCTIPOBONIFIC.DESCRICAO
                                                                                                         FROM PCTIPOBONIFIC
                                                                                                        WHERE PCTIPOBONIFIC.CODBNF = PCPROMOCAOMED.CODBNF)
                                   END
                                 ELSE
                                   'Pedido de Venda'
                                 END DESQUEBRA_BONIFICACAO
                               ------------------------------------------------
                               -- QUEBRA POR PLANO DE PAGAMENTO
                               ------------------------------------------------
                               , CASE WHEN (NVL(PCPEDI.BONIFIC,'N') = 'F') THEN
                                   -- Quando tem Quebra por Plano de Pagamento, o Item Bonificado deve entrar como Plano 99
                                   '99'
                                 ELSE
                                   TO_CHAR(NVL(PCPEDI.CODPLPAG,0))
                                 END CODQUEBRA_PLANOPAGAMENTO
                               , CASE WHEN (NVL(PCPEDI.BONIFIC,'N') = 'F') THEN
                                   -- Quando tem Quebra por Plano de Pagamento, o Item Bonificado deve entrar como Plano 99
                                   'Plano Pagamento: ' || '99' || ' - ' || (SELECT PCPLPAG.DESCRICAO
                                                                              FROM PCPLPAG
                                                                             WHERE PCPLPAG.CODPLPAG = 99)
                                 ELSE
                                   'Plano Pagamento: ' || NVL(PCPEDI.CODPLPAG,0) || ' - ' || (SELECT PCPLPAG.DESCRICAO
                                                                                                FROM PCPLPAG
                                                                                               WHERE PCPLPAG.CODPLPAG = PCPEDI.CODPLPAG)
                                 END DESQUEBRA_PLANOPAGAMENTO
                               ------------------------------------------------
                               -- QUEBRA POR DISTRIBUIÇÃO
                               ------------------------------------------------
                               , NVL(PCPRODUT.CODDISTRIB,'0') CODQUEBRA_DISTRIBUICAO
                               , CASE WHEN (NVL(PCPRODUT.CODDISTRIB,'0') = '0') THEN
                                   'Sem Distribuição'
                                 ELSE
                                   'Distribuição: ' || NVL(PCPRODUT.CODDISTRIB,'0') || ' - ' || (SELECT PCDISTRIB.DESCRICAO
                                                                                                   FROM PCDISTRIB
                                                                                                  WHERE PCDISTRIB.CODDISTRIB = PCPRODUT.CODDISTRIB)
                                 END DESQUEBRA_DISTRIBUICAO
                               ------------------------------------------------
                               -- QUEBRA POR REGIME ESPECIAL
                               ------------------------------------------------
                               , CASE WHEN (NVL((SELECT PCPRODFILIAL.REGIMEESPECIAL FROM PCPRODFILIAL WHERE PCPRODFILIAL.CODPROD = PCPEDI.CODPROD AND PCPRODFILIAL.CODFILIAL = PCPEDC.CODFILIAL),'N') IN ('S')) THEN
                                   'RE' -- Regime Especial
                                 ELSE
                                   'RN' -- Regime Normal
                                 END CODQUEBRA_REGIMESPECIAL
                               , CASE WHEN (NVL((SELECT PCPRODFILIAL.REGIMEESPECIAL FROM PCPRODFILIAL WHERE PCPRODFILIAL.CODPROD = PCPEDI.CODPROD AND PCPRODFILIAL.CODFILIAL = PCPEDC.CODFILIAL),'N') IN ('S')) THEN
                                   'Produtos com Regime Especial'
                                 ELSE
                                   'Produtos sem Regime Especial'
                                 END DESQUEBRA_REGIMESPECIAL
                               ------------------------------------------------
                               -- QUEBRA POR TIPO MEDICAMENTO
                               ------------------------------------------------
                               , CASE WHEN (NVL(PCPRODUT.TIPOMEDICAMENTO,' ') IN ('S', 'G')) THEN
                                   'G'
                                 ELSE
                                   'O'
                                 END CODQUEBRA_TIPOMEDICAMENTO
                               , CASE WHEN (NVL(PCPRODUT.TIPOMEDICAMENTO,' ') IN ('S', 'G')) THEN
                                   'Produtos Genéricos e Similares'
                                 ELSE
                                   'Outros Produtos'
                                 END DESQUEBRA_TIPOMEDICAMENTO
                               ------------------------------------------------
                               -- QUEBRA POR BRINDE
                               ------------------------------------------------
                               , NVL(PCPEDI.BRINDE,'N') CODQUEBRA_BRINDE
                               , CASE WHEN (NVL(PCPEDI.BRINDE,'N') = 'S') THEN
                                   'Brinde'
                                 ELSE
                                   'Outros Produtos não Brindes'
                                 END DESQUEBRA_BRINDE
                               ------------------------------------------------
                               -- QUEBRA POR ST
                               ------------------------------------------------
                               , NVL(( SELECT NVL(TMP.PRODST,'N') FROM PCMED_GERAR_QUEBRA_PEDIDO TMP WHERE TMP.NUMPED = pi_nNumPed AND TMP.CODPROD = PCPEDI.CODPROD AND TMP.NUMSEQ = PCPEDI.NUMSEQ AND ROWNUM = 1 ),'N') CODQUEBRA_PRODST
                               , CASE WHEN (NVL(( SELECT NVL(TMP.PRODST,'N') FROM PCMED_GERAR_QUEBRA_PEDIDO TMP WHERE TMP.NUMPED = pi_nNumPed AND TMP.CODPROD = PCPEDI.CODPROD AND TMP.NUMSEQ = PCPEDI.NUMSEQ AND ROWNUM = 1 ),'N') = 'S') THEN
                                   'Prod. com ST'
                                 ELSE
                                   'Prod. sem ST'
                                 END DESQUEBRA_PRODST
                                ------------------------------------------------
                                -- QUEBRA POR RCA NA LINHA DE PRODUTO
                                ------------------------------------------------
                               , DECODE(NVL(PCPEDI.CODUSUR,0),0,PCPEDC.CODUSUR,PCPEDI.CODUSUR) CODQUEBRA_RCALINHA_PRODUTO
                               , CASE WHEN (DECODE(NVL(PCPEDI.CODUSUR,0),0,PCPEDC.CODUSUR,PCPEDI.CODUSUR) = 0) THEN
                                   'Sem Rca linha'
                                 ELSE
                                   'Rca da linha: ' || DECODE(NVL(PCPEDI.CODUSUR,0),0,PCPEDC.CODUSUR,PCPEDI.CODUSUR) ||
                                                              ' - ' || (SELECT PCUSUARI.NOME
                                                                        FROM PCUSUARI
                                                                        WHERE PCUSUARI.CODUSUR =
                                                                        DECODE(NVL(PCPEDI.CODUSUR,0),0,PCPEDC.CODUSUR,PCPEDI.CODUSUR))
                                 END DESQUEBRA_RCALINHA_PRODUTO
                                ------------------------------------------------
                                -- QUEBRA POR CONTROLADOS EM CROSSDOKING
                                ------------------------------------------------
                               , CASE WHEN (NVL(PCPRODUT.PSICOTROPICO,'N') = 'S') THEN
                                   'C'
                                      WHEN (NVL(PCPRODUT.RETINOICO,'N') = 'S') THEN
                                   'C'
                                 ELSE
                                   'L'
                                 END CODQUEBRA_CONTROLADOS_CROSS
                               , CASE WHEN (NVL(PCPRODUT.PSICOTROPICO,'N') = 'S') THEN
                                   'Controlados - Crossdocking'
                                      WHEN (NVL(PCPRODUT.RETINOICO,'N') = 'S') THEN
                                   'Controlados - Crossdocking'
                                 ELSE
                                   'Liberados - Crossdocking'
                                 END DESQUEBRA_CONTROLADOS_CROSS ,
                                 ------------------------------------------------
                                 -- QUEBRA DE PEDIDO POR RESTRIÇÃO DE TRANSPORTE
                                 ------------------------------------------------
                                 NVL(PCPRODUT.RESTRICAOTRANSP,'N') TIPORESTRICAO,
                                 CASE 
                                 WHEN  PCPRODUT.RESTRICAOTRANSP = 'S' THEN 'PRODUTO '|| pcprodut.codprod  || ' INFLAMÁVEL'
                                 WHEN  PCPRODUT.RESTRICAOTRANSP = 'R' THEN 'PRODUTO' || pcprodut.codprod  || 'REFRIGERADO' 
                                 ELSE 'NORMAL' END DESCRICAO_RESTRICAO
                                 FROM PCPEDC
                               , PCPEDI
                               , PCPRODUT
                               , PCPROMOCAOMED
                           WHERE (PCPEDI.NUMPED         = PCPEDC.NUMPED)
                             AND (PCPEDI.CODPROD        = PCPRODUT.CODPROD(+))
                             AND (PCPEDI.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED(+))
                             AND (PCPEDI.NUMPED         = pi_nNumPed)
                           ORDER BY CODQUEBRA_BONIFICACAO DESC       -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                  , CODQUEBRA_BRINDE                 -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                  , CODQUEBRA_PRODST                 -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                  , CODQUEBRA_CONTROLADOS_CROSS DESC -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                             ) LOOP
  
          -----------------------------------------------------------
          -- Atualiza Quebra por Bonificação (SEMPRE PRIMEIRA QUEBRA)
          -----------------------------------------------------------
          IF (NVL(vvExisteCampanha,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'B', -->> Quebra de Bonificação
                              vcProduto.CODQUEBRA_BONIFICACAO,
                              vcProduto.CODQUEBRA_CODBNF,
                              vcProduto.DESQUEBRA_BONIFICACAO,
                              1); -->> PRIMEIRA QUEBRA
          END IF;
  
          ---------------------------------------------------------
          -- Atualiza Quebra por Distribuição OU Plano de Pagamento
          ---------------------------------------------------------
          -- Atualiza Quebra por Distribuição (SEMPRE SEGUNDA QUEBRA)
          IF    (NVL(vQUEBRARPEDIDODISTRIBMED,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'D', -->> Quebra de Distribuição
                              vcProduto.CODQUEBRA_DISTRIBUICAO,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_DISTRIBUICAO,
                              2);  -->> SEGUNDA QUEBRA
          -- Atualiza Quebra por Plano de Pagamento (SEMPRE TERCEIRA QUEBRA)
          ELSIF (NVL(vMEDQUEBRARPEDPLPAGLINHAPRAZO,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'P', -->> Quebra de Plano de Pagamento
                              vcProduto.CODQUEBRA_PLANOPAGAMENTO,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_PLANOPAGAMENTO,
                              3);  -->> TERCEIRA QUEBRA
          END IF;
  
          -------------------------------------------------------------
          -- Atualiza Quebra por Regime Especial OU Tipo de Medicamento
          -------------------------------------------------------------
          -- Atualiza Quebra por Regime Especial (SEMPRE QUARTA QUEBRA)
          IF    (NVL(vQUEBRARPEDIDOREGIMESP,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'R', -->> Quebra de Regime Especial
                              vcProduto.CODQUEBRA_REGIMESPECIAL,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_REGIMESPECIAL,
                              4);  -->> QUARTA QUEBRA
          -- Atualiza Quebra por Tipo de Medicamento  (SEMPRE QUINTA QUEBRA)
          ELSIF (NVL(vQUEBRARPEDIDOTIPOMEDICAM,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'M', -->> Quebra de Tipo de Medicamento
                              vcProduto.CODQUEBRA_TIPOMEDICAMENTO,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_TIPOMEDICAMENTO,
                              5);  -->> QUINTA QUEBRA
          END IF;
  
          ---------------------------------------------------
          -- Atualiza Quebra por Brinde (SEMPRE SEXTA QUEBRA)
          ---------------------------------------------------
          IF (NVL(vvExisteBrinde,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'I', -->> Quebra de Brindes
                              vcProduto.CODQUEBRA_BRINDE,
                              vnCodBnfPadraoBrinde, -->> Código da Bonificação Padrão do Brinde
                              vcProduto.DESQUEBRA_BRINDE,
                              6); -->> SEXTA QUEBRA
          END IF;
  
          ------------------------------------------------
          -- Atualiza Quebra por ST (SEMPRE SETIMA QUEBRA)
          ------------------------------------------------
          IF (NVL(vvExisteProdSt,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'S', -->> Quebra de ST
                              vcProduto.CODQUEBRA_PRODST,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_PRODST,
                              7); -->> SETIMA QUEBRA
          END IF;
          ------------------------------------------------
          -- Atualiza Quebra por Rca de linha produto
          ------------------------------------------------
          IF (NVL(vQUEBRARPEDIDORCALINHA,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'L', -->> Quebra de RCA por linha de produto
                              vcProduto.CODQUEBRA_RCALINHA_PRODUTO,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_RCALINHA_PRODUTO,
                              8); -->> OITAVA QUEBRA
          END IF;
          ------------------------------------------------
          -- Atualiza Quebra por Controlados em Crossdock
          ------------------------------------------------
          IF (NVL(vQUEBRACONTROLADOSCROSSDOCK,'N') = 'S') THEN
            P_ATUALIZA_QUEBRA(vcProduto.NUMPED,
                              vcProduto.CODPROD,
                              vcProduto.NUMSEQ,
                              'C', -->> Quebra de RCA por Controlados em Crossdocking
                              vcProduto.CODQUEBRA_CONTROLADOS_CROSS,
                              '0', -- Sem Quebra Secundária
                              vcProduto.DESQUEBRA_CONTROLADOS_CROSS,
                              9); -->> NONA QUEBRA
          END IF;
          
          ------------------------------------------------
          -- Atualiza Quebra por retrição de transporte apenas S OU R. 
          -- RESTRIÇÃO: N - NORMAL, S - INFLAMAVEL , R - REGRIGERADOS
          ------------------------------------------------        
          IF ((vcProduto.TIPORESTRICAO <> 'N') AND (NVL(vQUEBRARPEDIDORESTRICAOTRANSP,'N') = 'S')) THEN
            P_ATUALIZA_QUEBRA(vcProduto.Numped,
                              vcProduto.Codprod,
                              vcProduto.Numseq,
                              'T', -->> Quebra de pedido por restrição de transporte
                              vcProduto.TIPORESTRICAO,
                              '0',
                              vcProduto.Descricao_Restricao,
                              10                            
                              );        
          END IF;
          
          -- LOG
          vvMsgLog := 'Produto: '   || vcProduto.CODPROD || CHR(13)          ||
                      'NumSeq: '    || vcProduto.NUMSEQ  || CHR(13)          ||
                      'BNF: ['      || vcProduto.CODQUEBRA_BONIFICACAO       || '] - [' || vcProduto.CODQUEBRA_CODBNF            || '] - [' || vcProduto.DESQUEBRA_BONIFICACAO || ']' || CHR(13) ||
                      'DIST: ['     || vcProduto.CODQUEBRA_DISTRIBUICAO      || '] - [' || vcProduto.DESQUEBRA_DISTRIBUICAO      || ']' || CHR(13) ||
                      'PLPAG: ['    || vcProduto.CODQUEBRA_PLANOPAGAMENTO    || '] - [' || vcProduto.DESQUEBRA_PLANOPAGAMENTO    || ']' || CHR(13) ||
                      'R.ESP: ['    || vcProduto.CODQUEBRA_REGIMESPECIAL     || '] - [' || vcProduto.DESQUEBRA_REGIMESPECIAL     || ']' || CHR(13) ||
                      'TP.MED: ['   || vcProduto.CODQUEBRA_TIPOMEDICAMENTO   || '] - [' || vcProduto.DESQUEBRA_TIPOMEDICAMENTO   || ']' || CHR(13) ||
                      'BRINDE: ['   || vcProduto.CODQUEBRA_BRINDE            || '] - [' || vcProduto.DESQUEBRA_BRINDE            || ']' || CHR(13) ||
                      'PROD ST: ['  || vcProduto.CODQUEBRA_PRODST            || '] - [' || vcProduto.DESQUEBRA_PRODST            || ']' || CHR(13) ||
                      'RCA LINHA:[' || vcProduto.CODQUEBRA_RCALINHA_PRODUTO  || '] - [' || vcProduto.DESQUEBRA_RCALINHA_PRODUTO  || ']' || CHR(13) ||
                      'CROSSDOCK:[' || vcProduto.CODQUEBRA_CONTROLADOS_CROSS || '] - [' || vcProduto.DESQUEBRA_CONTROLADOS_CROSS || ']' || CHR(13) ||
                      'RESTRIÇÃO TRANSP: ' || vcProduto.Tiporestricao        || '] - [' || vcProduto.Descricao_Restricao         || ']' || CHR(13);
          P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                     vvMsgLog);
  
        END LOOP; -- Fim Laço de Geração das Quebras
  
        ------------------------------
        -- Gravação das Quebras
        ------------------------------
  
        -- Primeiro verifica a Qtde. de Quebras
        viContadorPedidos := 0;
        FOR vcQuebra IN (SELECT DISTINCT
                                TIPQUEBRA1
                              , TIPQUEBRA2
                              , TIPQUEBRA3
                              , TIPQUEBRA4
                              , TIPQUEBRA5
                              , TIPQUEBRA6
                              , TIPQUEBRA7
                              , TIPQUEBRA8
                              , TIPQUEBRA9
                              , TIPQUEBRA10
                              --
                              , CODPRINCQUEBRA1
                              , CODPRINCQUEBRA2
                              , CODPRINCQUEBRA3
                              , CODPRINCQUEBRA4
                              , CODPRINCQUEBRA5
                              , CODPRINCQUEBRA6
                              , CODPRINCQUEBRA7
                              , CODPRINCQUEBRA8
                              , CODPRINCQUEBRA9
                              , CODPRINCQUEBRA10
                              --
                              , CODSECQUEBRA1
                              , CODSECQUEBRA2
                              , CODSECQUEBRA3
                              , CODSECQUEBRA4
                              , CODSECQUEBRA5
                              , CODSECQUEBRA6
                              , CODSECQUEBRA7
                              , CODSECQUEBRA8
                              , CODSECQUEBRA9
                              , CODSECQUEBRA10
                              --
                              , DESQUEBRA1
                              , DESQUEBRA2
                              , DESQUEBRA3
                              , DESQUEBRA4
                              , DESQUEBRA5
                              , DESQUEBRA6
                              , DESQUEBRA7
                              , DESQUEBRA8
                              , DESQUEBRA9
                              , DESQUEBRA10 
                           FROM PCMED_GERAR_QUEBRA_PEDIDO P
                          ORDER BY CODPRINCQUEBRA1 DESC -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                 , CODPRINCQUEBRA6      -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                 , CODPRINCQUEBRA7      -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                 , CODPRINCQUEBRA9 DESC -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                           ) LOOP
          viContadorPedidos := NVL(viContadorPedidos,0) + 1;
  
          -- MED-1663 - Reserva novo Sequencial de Pedido (PRAGMA), para não concorrer com a PCUSUARI atualizada pela Package do Conta-Corrente
          IF (NVL(viContadorPedidos,0) >= 2) THEN -->> A partir da segunda quebra
            vtNOVO_NUMPED_PCPEDC(viContadorPedidos) := OBTER_NOVO_NUMPED_PCPEDC(vrDadosPedidoOriginal.vnCodUsur);
          END IF;
  
        END LOOP;
  
  
        ------------------------------------------------------------------------------
        -- DDMEDICA-486 - Alterada posição da mensagem de quebra com itens bonificados
        ------------------------------------------------------------------------------
        -- Realiza busca por itens de pedido bonificado (BONIFIC = 'F')      0.061546.2015 | 13/08/2015 | Vinícius Melo
        -- HIS.01889.2017 - Quando Quebra de Bonificação por Campanha, será necessário separar do Pedidos os Itens Bonificados
        IF (NVL(vvExisteCampanha,'N') = 'N') THEN
          SELECT COUNT(*)
            INTO viQtRegistrosEncontrados
            FROM PCPEDI
           WHERE (PCPEDI.BONIFIC IS NOT NULL)
             AND (PCPEDI.BONIFIC = 'F')
             AND (PCPEDI.NUMPED  = pi_nNumped)
           ORDER BY PCPEDI.BONIFIC;
          IF (NVL(viQtRegistrosEncontrados,0) > 0) THEN
            -- DDMEDICA-486 - Verifica se vão ter quebras
            IF (viContadorPedidos > 1) THEN
              vvMsgErroTratado := 'O desdobramento em vários pedidos conforme regra de quebra de pedidos definida nos parâmetros da presidência' || CHR(13) ||
                                  'não será aplicada neste pedido porque contém itens bonificados.' || CHR(13) ||
                                  'A posição do pedido será alterada mas será mantido um único pedido.';
              RAISE e_Tratado;
            END IF;
          END IF;
        END IF;
  
  
        -------------------------------------
        -- Divide Taxa de Frete pelos Pedidos
        -------------------------------------
        -- LOG
        vvMsgLog := 'VlFreteOutrasDesp:' || vnVlFreteOutrasDesp || CHR(13) ||
                    'ContadorPedidos:'   || viContadorPedidos   || CHR(13);
        P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                   vvMsgLog);
        IF (viContadorPedidos > 1) THEN
          vnVlFreteOutrasDesp := ROUND((vnVlFreteOutrasDesp / viContadorPedidos),2);
        END IF;
  
        -- Se houver mais de uma Quebra
        IF (NVL(viContadorPedidos,0) > 1) THEN
  
          -- Por fim grava as Quebras
          viContadorPedidos := 0;
          FOR vcQuebra IN (SELECT DISTINCT
                                  TIPQUEBRA1
                                , TIPQUEBRA2
                                , TIPQUEBRA3
                                , TIPQUEBRA4
                                , TIPQUEBRA5
                                , TIPQUEBRA6
                                , TIPQUEBRA7
                                , TIPQUEBRA8
                                , TIPQUEBRA9 
                                , TIPQUEBRA10                              
                                 --
                                , CODPRINCQUEBRA1
                                , CODPRINCQUEBRA2
                                , CODPRINCQUEBRA3
                                , CODPRINCQUEBRA4
                                , CODPRINCQUEBRA5
                                , CODPRINCQUEBRA6
                                , CODPRINCQUEBRA7
                                , CODPRINCQUEBRA8
                                , CODPRINCQUEBRA9
                                , CODPRINCQUEBRA10 
                                --
                                , CODSECQUEBRA1
                                , CODSECQUEBRA2
                                , CODSECQUEBRA3
                                , CODSECQUEBRA4
                                , CODSECQUEBRA5
                                , CODSECQUEBRA6
                                , CODSECQUEBRA7
                                , CODSECQUEBRA8
                                , CODSECQUEBRA9
                                , CODSECQUEBRA10
                                --
                                , DESQUEBRA1
                                , DESQUEBRA2
                                , DESQUEBRA3
                                , DESQUEBRA4
                                , DESQUEBRA5
                                , DESQUEBRA6
                                , DESQUEBRA7
                                , DESQUEBRA8
                                , DESQUEBRA9
                                , DESQUEBRA10
                             FROM PCMED_GERAR_QUEBRA_PEDIDO
                            ORDER BY CODPRINCQUEBRA1 DESC -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                   , CODPRINCQUEBRA6      -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                   , CODPRINCQUEBRA7      -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                                   , CODPRINCQUEBRA9 DESC -->> IMPORTANTÍSSO: A ordenação garante que o Pedido Original ficará SEMPRE os Itens Normais. Isto garante o estorno correto do C/C RCA
                             ) LOOP
  
            -- Contador de Pedidos
            viContadorPedidos := NVL(viContadorPedidos,0) + 1;
  
            -- Dados do Where da Quebra
            vrDadosWhereQuebra.vvCodPrinc1 := vcQuebra.CODPRINCQUEBRA1;
            vrDadosWhereQuebra.vvCodPrinc2 := vcQuebra.CODPRINCQUEBRA2;
            vrDadosWhereQuebra.vvCodPrinc3 := vcQuebra.CODPRINCQUEBRA3;
            vrDadosWhereQuebra.vvCodPrinc4 := vcQuebra.CODPRINCQUEBRA4;
            vrDadosWhereQuebra.vvCodPrinc5 := vcQuebra.CODPRINCQUEBRA5;
            vrDadosWhereQuebra.vvCodPrinc6 := vcQuebra.CODPRINCQUEBRA6;
            vrDadosWhereQuebra.vvCodPrinc7 := vcQuebra.CODPRINCQUEBRA7;
            vrDadosWhereQuebra.vvCodPrinc8 := vcQuebra.CODPRINCQUEBRA8;
            vrDadosWhereQuebra.vvCodPrinc9 := vcQuebra.CODPRINCQUEBRA9;
            vrDadosWhereQuebra.vvCodPrinc10:= vcQuebra.CODPRINCQUEBRA10;
        
            --
            vrDadosWhereQuebra.vvCodSec1   := vcQuebra.CODSECQUEBRA1;
            vrDadosWhereQuebra.vvCodSec2   := vcQuebra.CODSECQUEBRA2;
            vrDadosWhereQuebra.vvCodSec3   := vcQuebra.CODSECQUEBRA3;
            vrDadosWhereQuebra.vvCodSec4   := vcQuebra.CODSECQUEBRA4;
            vrDadosWhereQuebra.vvCodSec5   := vcQuebra.CODSECQUEBRA5;
            vrDadosWhereQuebra.vvCodSec6   := vcQuebra.CODSECQUEBRA6;
            vrDadosWhereQuebra.vvCodSec7   := vcQuebra.CODSECQUEBRA7;
            vrDadosWhereQuebra.vvCodSec8   := vcQuebra.CODSECQUEBRA8;
            vrDadosWhereQuebra.vvCodSec9   := vcQuebra.CODSECQUEBRA9;
            vrDadosWhereQuebra.vvCodSec10  := vcQuebra.CODSECQUEBRA10;
  
            ----------------------------------------------
            -- Controles de Atualização de Item Bonificado
            ---------------------------------------------
  
            -- Item Bonificado
            vvCtlAtuItemBonific    := 'N';
            vnCtlAtuCodBnf         := NULL;
            -- Distribuição
            vvCtlAtuDistribuicao   := 'N';
            -- Plano Pagamento
            vvCtlAtuPlanoPagamento := NULL;
  
            --------------------------------------
            -- Observação da Descrição das Quebras
            --------------------------------------
  
            -- Inicializa Observação Geral
            vvObservacaoGeral := NULL;
  
            -- Laço para Pegar Informação Dados das Colunas
            FOR viIdx IN 1..viQtQuebrasImplementadas LOOP
  
              IF    (viIdx = 1) AND (vcQuebra.TIPQUEBRA1 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA1;
              ELSIF (viIdx = 2) AND (vcQuebra.TIPQUEBRA2 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA2;
              ELSIF (viIdx = 3) AND (vcQuebra.TIPQUEBRA3 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA3;
              ELSIF (viIdx = 4) AND (vcQuebra.TIPQUEBRA4 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA4;
              ELSIF (viIdx = 5) AND (vcQuebra.TIPQUEBRA5 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA5;
              ELSIF (viIdx = 6) AND (vcQuebra.TIPQUEBRA6 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA6;
              ELSIF (viIdx = 7) AND (vcQuebra.TIPQUEBRA7 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA7;
              ELSIF (viIdx = 8) AND (vcQuebra.TIPQUEBRA8 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA8;
              ELSIF (viIdx = 9) AND (vcQuebra.TIPQUEBRA9 <> 'SQ') THEN
                -- Pega Dados da Coluna
                IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA9;
              ELSIF (viIdx = 10) and (vcQuebra.Tipquebra10 <> 'SQ') THEN 
               IF (vvObservacaoGeral IS NOT NULL) THEN
                  vvObservacaoGeral := vvObservacaoGeral || ' e ' ;
                END IF;
                vvObservacaoGeral := vvObservacaoGeral || vcQuebra.DESQUEBRA10;
              END IF;
  
            END LOOP; -- FIM Laço para monta Observação com a Descriçao das Quebras
  
            -----------------------------------------------------
            -- Regras de Atualização das Colunas conforme Quebras
            -----------------------------------------------------
            -- Atualiza Quebra por Bonificação PRIMEIRA QUEBRA --
            IF (vcQuebra.TIPQUEBRA1 = 'B') AND
               (vcQuebra.CODPRINCQUEBRA1 = 'F') THEN
              -- Se Quebra de Item Bonificado
              -- Vai ter Atualização diferenciada para Itens Bonificados
              vvCtlAtuItemBonific := 'S';
              -- O Código da BNF estará no Código Segundário
              BEGIN
                vnCtlAtuCodBnf := TO_NUMBER(TRIM(vcQuebra.CODSECQUEBRA1));
                IF (NVL(vnCtlAtuCodBnf,0) = 0) THEN
                  vnCtlAtuCodBnf := NULL;
                END IF;
              EXCEPTION
                WHEN OTHERS THEN
                  vnCtlAtuCodBnf := NULL;
              END;
            END IF;
            -- Atualiza Quebra por Distribuição SEGUNDA QUEBRA --
            IF (vcQuebra.TIPQUEBRA2 = 'D') THEN
              -- Se Quebra de Distribuição
              -- Vai ter Atualização diferenciada para Distribuição
              vvCtlAtuDistribuicao := 'S';
            END IF;
            -- Atualiza Quebra por Plano de Pagamento TERCEIRA QUEBRA
            -- Se Quebra de Plano de Pagamento
            IF (vcQuebra.TIPQUEBRA3 = 'P') THEN
              -- Vai ter Atualização diferenciada para Distribuição
              vvCtlAtuPlanoPagamento := 'S';
            END IF;
            -- Atualiza Quebra por Brinde SEXTA QUEBRA --
            IF (vcQuebra.TIPQUEBRA6 = 'I') AND
               (vcQuebra.CODPRINCQUEBRA6 = 'S') THEN
              -- Se Quebra de Item Brinde
              -- Vai ter Atualização diferenciada para Brindes que são também Itens Bonificados
              vvCtlAtuItemBonific := 'S';
              -- Se Quebra de Brinde
              -- O Código da BNF estará no Código Segundário
              BEGIN
                vnCtlAtuCodBnf := TO_NUMBER(TRIM(vcQuebra.CODSECQUEBRA6));
                IF (NVL(vnCtlAtuCodBnf,0) = 0) THEN
                  vnCtlAtuCodBnf := NULL;
                END IF;
              EXCEPTION
                WHEN OTHERS THEN
                  vnCtlAtuCodBnf := NULL;
              END;
            END IF;
            -- Atualiza Quebra por Rca linha de produto Sexta QUEBRA --
            IF (vcQuebra.TIPQUEBRA8 = 'L') THEN
               -- Se Quebra por Rca linha de produto
              -- Vai ter Atualização diferenciada para Rca por linha de produto
              vvCtlAtuRcaLinhaProduto := 'S';
            END IF;
            
            IF (VCQUEBRA.TIPQUEBRA10 = 'T') THEN
              vvCtlAtuRestricaoTransp := 'S';
            END IF;
  
            -- LOG
            vvMsgLog := 'Quebra:' || viContadorPedidos   || CHR(13) ||
                        'Q1: ['   || vcQuebra.TIPQUEBRA1 || '] - [' || vcQuebra.CODPRINCQUEBRA1 || '] - [' || vcQuebra.CODSECQUEBRA1 || ']' || CHR(13) ||
                        'Q2: ['   || vcQuebra.TIPQUEBRA2 || '] - [' || vcQuebra.CODPRINCQUEBRA2 || '] - [' || vcQuebra.CODSECQUEBRA2 || ']' || CHR(13) ||
                        'Q3: ['   || vcQuebra.TIPQUEBRA3 || '] - [' || vcQuebra.CODPRINCQUEBRA3 || '] - [' || vcQuebra.CODSECQUEBRA3 || ']' || CHR(13) ||
                        'Q4: ['   || vcQuebra.TIPQUEBRA4 || '] - [' || vcQuebra.CODPRINCQUEBRA4 || '] - [' || vcQuebra.CODSECQUEBRA4 || ']' || CHR(13) ||
                        'Q5: ['   || vcQuebra.TIPQUEBRA5 || '] - [' || vcQuebra.CODPRINCQUEBRA5 || '] - [' || vcQuebra.CODSECQUEBRA5 || ']' || CHR(13) ||
                        'Q6: ['   || vcQuebra.TIPQUEBRA6 || '] - [' || vcQuebra.CODPRINCQUEBRA6 || '] - [' || vcQuebra.CODSECQUEBRA6 || ']' || CHR(13) ||
                        'Q7: ['   || vcQuebra.TIPQUEBRA7 || '] - [' || vcQuebra.CODPRINCQUEBRA7 || '] - [' || vcQuebra.CODSECQUEBRA7 || ']' || CHR(13) ||
                        'Q8: ['   || vcQuebra.TIPQUEBRA8 || '] - [' || vcQuebra.CODPRINCQUEBRA8 || '] - [' || vcQuebra.CODSECQUEBRA8 || ']' || CHR(13) ||
                        'Q9: ['   || vcQuebra.TIPQUEBRA9 || '] - [' || vcQuebra.CODPRINCQUEBRA9 || '] - [' || vcQuebra.CODSECQUEBRA9 || ']' || CHR(13) ||
                        'AtuItemBonific: ['    || vvCtlAtuItemBonific     || '] - [' || vnCtlAtuCodBnf || ']' || CHR(13) ||
                        'AtuDistribuicao: ['   || vvCtlAtuDistribuicao    || ']'     || CHR(13) ||
                        'AtuPlanoPagamento: [' || vvCtlAtuPlanoPagamento  || ']'     || CHR(13) ||
                        'AtuRcaLinhaProduto: ['|| vvCtlAtuRcaLinhaProduto || ']'     || CHR(13) ||
                        'AtuRcaRestriçãoTransporte: [' || vvCtlAtuRestricaoTransp || ']';
            P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                       vvMsgLog);
  
            --------------------------------------------------------------------------------------------------------------------
            -- Guarda Informações de Quebra do Primeiro Pedido - Pedido do Parâmetro
            -------------------------------------------------------------------------------------------------------------------
            IF (NVL(viContadorPedidos,0) = 1) THEN
  
              -- Precisa guardar os Valores do Primeiro Pedido
              -- por causa da Atualização dos Totais do Primeiro Pedido considerar atributos da Primeira Quebra
              vvCtlAtuItemBonificQuebra1    := vvCtlAtuItemBonific;
              vnCtlAtuCodBnfQuebra1         := vnCtlAtuCodBnf;
              vvCtlAtuDistribuicaoQuebra1   := vvCtlAtuDistribuicao;
              vvCtlAtuPlanoPagamentoQuebra1 := vvCtlAtuPlanoPagamento;
              vvObservacaoGeralQuebra1      := vvObservacaoGeral;
              vvCtlAtuRcaLinhaProdutoQuebra1:= vvCtlAtuRcaLinhaProduto;
              vvCtlAtuRestricaoTranspQuebra1:= vvCtlAtuRestricaoTransp;
            --------------------------------------------------------------------------------------------------------------------
            -- A partir da segunda Quebra separa os Produtos (a primeira quebra será com o Pedido original passado no parâmetro)
            -------------------------------------------------------------------------------------------------------------------
            ELSE
  
              -- Gerar novo Sequencial de Pedido
              --vnNovoNumPed := OBTER_NOVO_NUMPED_PCPEDC(vrDadosPedidoOriginal.vnCodUsur);
              vnNovoNumPed := vtNOVO_NUMPED_PCPEDC(viContadorPedidos); -- MED-1663 - Pega do Array Número já Pré-Reservado
  
              -- LOG
              vvMsgLog := 'Quebra:' || viContadorPedidos || CHR(13) ||
                          'Pedido:' || vnNovoNumPed      || CHR(13);
              P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                         vvMsgLog);
  
              -- Criar Cabeçalho novo Pedido
              SALVAR_NOVO_PEDIDO(pi_nNumPed,   -->> Referência para o Pedido Original
                                 vnNovoNumPed, -->> Novo Número do Pedido
                                 vvCtlAtuItemBonific,
                                 vnCtlAtuCodBnf,
                                 vbGerouPedBnf,
                                 vnNumPedBnf,
                                 vnVlFreteOutrasDesp); -- Taxa Frete
  
              -----------------------------------------------------------
              -- Laço de Produtos da Quebra - PARA SEPARAÇÃO DOS PRODUTOS
              -----------------------------------------------------------
              FOR vcProdQuebra IN (SELECT CODPROD
                                        , NUMSEQ
                                        , QT
                                        , CODPROMOCAOMED
                                     FROM PCMED_GERAR_QUEBRA_PEDIDO p
                                    WHERE (NVL(CODPRINCQUEBRA1,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc1,' '))
                                      AND (NVL(CODPRINCQUEBRA2,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc2,' '))
                                      AND (NVL(CODPRINCQUEBRA3,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc3,' '))
                                      AND (NVL(CODPRINCQUEBRA4,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc4,' '))
                                      AND (NVL(CODPRINCQUEBRA5,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc5,' '))
                                      AND (NVL(CODPRINCQUEBRA6,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc6,' '))
                                      AND (NVL(CODPRINCQUEBRA7,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc7,' '))
                                      AND (NVL(CODPRINCQUEBRA8,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc8,' '))
                                      AND (NVL(CODPRINCQUEBRA9,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc9,' '))
                                      AND (NVL(CODPRINCQUEBRA10,' ') = NVL(vrDadosWhereQuebra.vvCodPrinc10,' '))
                                      --
                                      AND (NVL(CODSECQUEBRA1, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec1, '  '))
                                      AND (NVL(CODSECQUEBRA2, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec2, '  '))
                                      AND (NVL(CODSECQUEBRA3, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec3, '  '))
                                      AND (NVL(CODSECQUEBRA4, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec4, '  '))
                                      AND (NVL(CODSECQUEBRA5, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec5, '  '))
                                      AND (NVL(CODSECQUEBRA6, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec6, '  '))
                                      AND (NVL(CODSECQUEBRA7, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec7, '  '))
                                      AND (NVL(CODSECQUEBRA8, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec8, '  '))
                                      AND (NVL(CODSECQUEBRA9, '  ')  = NVL(vrDadosWhereQuebra.vvCodSec9, '  '))
                                      AND (NVL(CODSECQUEBRA10,'  ')  = NVL(vrDadosWhereQuebra.vvCodSec10,'  ')) ) LOOP
  
                -- Mudar o Número do Pedido dos Itens para o Novo Pedido
                ATUALIZAR_ITENS_NOVO_PEDIDO(pi_nNumPed,   -->> Referência para o Pedido Original
                                            vnNovoNumPed, -->> Novo Número do Pedido
                                            vcProdQuebra.CODPROD,
                                            vcProdQuebra.NUMSEQ,
                                            vcProdQuebra.QT,
                                            vrDadosPedidoOriginal.vnCodEmitente,
                                            vrDadosPedidoOriginal.vnCodUsur,
                                            vcProdQuebra.CODPROMOCAOMED);
  
              END LOOP; -- Fim Laço de Produtos da Quebra - PARA SEPARAÇÃO DOS PRODUTOS
  
              -- Recalcular Totais Novo Pedido
              CALC_TOTALIZADORES(vnNovoNumPed,
                                 vrDadosPedidoOriginal.vvOrigemPed,
                                 vvObservacaoGeral,
                                 vvCtlAtuItemBonific,
                                 vvCtlAtuDistribuicao,
                                 vvCtlAtuPlanoPagamento,
                                 vvCtlAtuRcaLinhaProduto,
                                 vvCtlAtuRestricaoTransp,
                                 vnVlFreteOutrasDesp); -- Taxa Frete
  
            END IF; -- Fim Condição: A partir da segunda quebra
  
          END LOOP; -- Fim Laço para Gravar as Quebras
  
          -- Recalcular Totais Pedido Original (com os Produtos que ficaram)
          -- Passa como Parâmetro os Atributos da Primeira Quebra
          CALC_TOTALIZADORES(pi_nNumPed,
                             vrDadosPedidoOriginal.vvOrigemPed,
                             vvObservacaoGeralQuebra1,
                             vvCtlAtuItemBonificQuebra1,
                             vvCtlAtuDistribuicaoQuebra1,
                             vvCtlAtuPlanoPagamentoQuebra1,
                             vvCtlAtuRcaLinhaProdutoQuebra1,
                             vvCtlAtuRestricaoTranspQuebra1,
                             vnVlFreteOutrasDesp); -- Taxa Frete
  
          -- Se Gerou Pedido Bonificado, referencia ele ao Pedido Normal Original passado no Parâmetro
          IF (vbGerouPedBnf) THEN
            UPDATE PCPEDC
               SET NUMPEDBNF = vnNumPedBnf
             WHERE (NUMPED = pi_nNumPed);
          END IF;
  
         /**********************************
          Validação de Novos Pedidos Gerados
          **********************************/
          FOR vcPedidoGer IN (SELECT NUMPED
                                FROM PCMED_RESUMO_PEDIDOS) LOOP
  
            -- Cabeçalho
            SELECT COUNT(*)
              INTO viQtRegistrosGerados
              FROM PCPEDC
             WHERE (NUMPED = vcPedidoGer.NUMPED);
            IF (NVL(viQtRegistrosGerados,0) = 0) THEN
              vvMsgErroTratado := 'Pedido ' || NVL(vcPedidoGer.NUMPED,0) || ' não foi encontrado!';
              RAISE e_Tratado;
            END IF;
  
            -- Itens
            SELECT COUNT(*)
              INTO viQtRegistrosGerados
              FROM PCPEDI
             WHERE (NUMPED = vcPedidoGer.NUMPED);
            IF (NVL(viQtRegistrosGerados,0) = 0) THEN
              vvMsgErroTratado := 'Itens do Pedido ' || NVL(vcPedidoGer.NUMPED,0) || ' não foram encontrados!';
              RAISE e_Tratado;
            END IF;
  
          END LOOP; -- Fim: Validação de Novos Pedidos Gerados
  
          -- LOG
          P_GRAVA_LOG_PROCESSAMENTO(pi_nNumPed);
  
          -- ATUALIZA RETORNO - QUEBROU PEDIDOS
          po_vRetorno := '2';
  
        -- Se houver somente uma Quebra
        ELSE
  
          -----------------------------------------------------------------------------------------
          -- Se Usa Quebra por Plano de Pagamento e tiver somente um Plano de Pagamento,
          -- precisa forçar a atualizar do Plano de Pagamento do Pedido a partir do Plano dos Itens
          -- Sem esta tratativa, o Pedido passado no parâmetro fica com o Plano 99
          -----------------------------------------------------------------------------------------
          IF (NVL(vTIPOPRAZOMEDICAMEN,'1') = '4') AND
             (NVL(vMEDQUEBRARPEDPLPAGLINHAPRAZO,'N') = 'S') THEN
  
            -- Pesquisa um Código de Plano de Pagamento de um dos Produtos
            BEGIN
              SELECT PCPEDI.CODPLPAG
                INTO vnCodPlPagPedido
                FROM PCPEDI
               WHERE (PCPEDI.NUMPED  = pi_nNumPed)
                 AND (ROWNUM         = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnCodPlPagPedido := NULL;
            END;
  
            -- LOG
            vvMsgLog := 'Quebra:' || 'Unica'           || CHR(13) ||
                        'Q3: ['   || vnCodPlPagPedido  || '] '    || CHR(13) ||
                        'Pedido:' || pi_nNumPed        || CHR(13);
            P_INSERE_LOG_PROCESSAMENTO(pi_nNumPed,
                                       vvMsgLog);
  
            -- Atualizar Plano de Pagamento do Pedido
            IF (NVL(vnCodPlPagPedido,0) > 0) THEN
  
              -- Pesquisa Prazo Médio
              P_OBTER_PRAZO_PEDIDO(pi_nNumPed,
                                   vnCodPlPagPedido,
                                   vrPrazos);
  
              -- Atualiza Pedido Plano de Pagamento e Prazos do Pedido
              UPDATE PCPEDC
                 SET CODPLPAG   = vnCodPlPagPedido
                   , PRAZO1     = vrPrazos.vnPrazo1
                   , PRAZO2     = vrPrazos.vnPrazo2
                   , PRAZO3     = vrPrazos.vnPrazo3
                   , PRAZO4     = vrPrazos.vnPrazo4
                   , PRAZO5     = vrPrazos.vnPrazo5
                   , PRAZO6     = vrPrazos.vnPrazo6
                   , PRAZO7     = vrPrazos.vnPrazo7
                   , PRAZO8     = vrPrazos.vnPrazo8
                   , PRAZO9     = vrPrazos.vnPrazo9
                   , PRAZO10    = vrPrazos.vnPrazo10
                   , PRAZO11    = vrPrazos.vnPrazo11
                   , PRAZO12    = vrPrazos.vnPrazo12
                   , PRAZOMEDIO = vrPrazos.vnPrazoMedio
                   , VLFRETEOUTRASDESP = vnVlFreteOutrasDesp -- Taxa Frete
               WHERE (NUMPED  = pi_nNumPed);
  
              -- LOG
              P_GRAVA_LOG_PROCESSAMENTO(pi_nNumPed);
  
            END IF;
  
          END IF;
  
        END IF; -- Fim Condição Se houver mais de uma Quebra
  
  
      END IF; -- Fim Condição pode Quebrar Pedidos
  
    EXCEPTION
      WHEN e_Break THEN
  
        po_vRetorno  := '1';
  
      WHEN e_Tratado THEN
  
        -- Ocorreram Erros
        po_vRetorno  := '3';
        po_vMsgErros := vvMsgErroTratado;
  
      WHEN OTHERS THEN
  
        -- Ocorreram Erros
        po_vRetorno  := '3';
        po_vMsgErros := DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM;
  
    END P_QUEBRAR_PEDIDO;
  
   /********************************************************************
    PROCEDURE: P_QUEBRA_PEDIDO_TV8
    DESCRIÇÃO: Chama a Procedure PRC_GERARPEDTV8
    ********************************************************************/
    PROCEDURE P_QUEBRA_PEDIDO_TV8(pi_nNumPed              IN  NUMBER,
                                  po_vRetMsgTV8           OUT VARCHAR2,
                                  po_nRetNumPedGeradoTV8  OUT  NUMBER,
                                  po_vRetPosicaoGeratTV8  OUT VARCHAR2,
                                  po_vRetMotivoTV8        OUT VARCHAR2,
                                  po_vAchouTv8            OUT VARCHAR2)
    IS
      -- String para executar Bloco de Procedure
      vvBlocoExecucaoProcedure VARCHAR2(32000);
    BEGIN
  
      -- Verifica se foi gerado o Pedido TV8
      BEGIN
        SELECT 'S'
          INTO po_vAchouTv8
          FROM PCPEDC
         WHERE (numpedentfut = pi_nNumPed)
           AND (ROWNUM       = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vAchouTv8 := 'N';
      END;
  
      -- Se ainda não gerou o TV8
      IF (po_vAchouTv8 = 'N') THEN
      
          -- String para executar Bloco de Cálculo de ST Fonte
          vvBlocoExecucaoProcedure := 'BEGIN PRC_GERARPEDTV8(:pi_nNumPed,:po_vRetMsgTV8,:po_nRetNumPedGeradoTV8,:po_vRetPosicaoGeratTV8,:po_vRetMotivoTV8); END;';
  
          -- Executa Bloco
          EXECUTE IMMEDIATE vvBlocoExecucaoProcedure
            USING in pi_nNumPed
                , out po_vRetMsgTV8
                , out po_nRetNumPedGeradoTV8
                , out po_vRetPosicaoGeratTV8
                , out po_vRetMotivoTV8;        
        
      END IF;
  
    END P_QUEBRA_PEDIDO_TV8;
  
  /*********************************************************************
    PROCEDIMENTO : P_ATU_STATUS_PROCESSAMENTO
    DESCRIÇÃO    : Procedimento para Atualizar o Status de Processamento
    *********************************************************************/
    PROCEDURE P_ATU_STATUS_PROCESSAMENTO(pi_vNovoStatus      IN VARCHAR2,
                                         pio_vStatusAtual    IN OUT VARCHAR2)
    IS
    BEGIN
  
      -- Atualiza Status de Gravação do Pedido
      UPDATE PCPEDC
         SET STATUSPROCESSAMENTOMED = pi_vNovoStatus
       WHERE (NUMPED = pi_nNumPed);
  
      -- Atualiza Retorno com o novo Status
      pio_vStatusAtual := pi_vNovoStatus;
  
    END P_ATU_STATUS_PROCESSAMENTO;
  
   /**********************
    INICIO DO PROCEDIMENTO
    **********************/
  BEGIN
  
  
   /*************************************************************************************************
                                             I N I C I O
                                       INICIALIZAÇÃO DE VARIÁVEIS
    **************************************************************************************************/
  
    -- Flag de Controle de uso do SavePoint
    vbUsouSavePoint := FALSE;
  
    -- Pesquisa Dados do Pedido - 4493.120105.2016
    BEGIN
      SELECT CODCLI
           , CONDVENDA
           , CODPLPAG
           , CODPLPAGETICO
           , CODPLPAGGENERICO
           , CODCOB
           , DATA
           , NVL(DTENTREGA,DATA)
           , ORIGEMPED
           , POSICAO
           , CODUSUR
           , CODFILIAL
           , NVL(PEDIDOAVARIA,'N')
           , TOTPESO
           , TOTVOLUME
           , VLTABELA
           , VLATEND
           , NUMREGIAO
           , CODPROMOCAOMED
           , POSICAO
           , CODFILIALNF
           , NUMCAR
           , STATUSPROCESSAMENTOMED
           , TIPOFV
           , VLFRETEOUTRASDESP
        INTO vrPedido.vnCodCli
           , vrPedido.vnCondVenda
           , vrPedido.vnCodPlPag
           , vrPedido.vnCodPlPagEtico
           , vrPedido.vnCodPlPagGenerico
           , vrPedido.vvCodCob
           , vrPedido.vdData
           , vrPedido.vdDtEntrega
           , vrPedido.vvOrigemPed
           , vrPedido.vvPosicaoAtual
           , vrPedido.vnCodUsur
           , vrPedido.vvCodFilial
           , vrPedido.vvPedidoAvaria
           , vrPedido.vnTotPeso
           , vrPedido.vnTotVolume
           , vrPedido.vnVlTabela
           , vrPedido.vnVlAtend
           , vrPedido.vnNumRegiao
           , vrPedido.vnCodPromocaoMed
           , vrPedido.vvPosicao
           , vrPedido.vvCodFilialNf
           , vrPedido.vnNumCar
           , vrPedido.vvStatusProcessamentoMed
           , vrPedido.vvTipoFv
           , vrPedido.vnVlFreteOutrasDesp
        FROM PCPEDC
       WHERE (NUMPED = pi_nNumPed);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        RAISE e_PedidoNaoEncontrado;
    END;
    
    -- Não ultrapassar o tamanho do campo do carregamento
    IF (vrPedido.vnTotVolume > 99999999) THEN
      vrPedido.vnTotVolume := 99999999;
    END IF;
  
    -- Parâmetros PCCONSUM
    BEGIN
      SELECT NVL(USANUMCARVENDABALCAO,'N')
           , NVL(FECHACARREGAUTVENDABALCAO,'N')
           , NVL(GERARBRINDEPEDBONIFIC,'N')
        INTO vrParametros.vUSANUMCARVENDABALCAO
           , vrParametros.vFECHACARREGAUTVENDABALCAO
           , vrParametros.vGERARBRINDEPEDBONIFIC
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vUSANUMCARVENDABALCAO      := 'N';
        vrParametros.vFECHACARREGAUTVENDABALCAO := 'N';
        vrParametros.vGERARBRINDEPEDBONIFIC     := 'N';
    END;
  
    -- Parâmetros PCPARAMFILIAL
    BEGIN
      SELECT NVL(VALOR,'N')
       INTO vrParametros.vRESERVARESTOQUETV7
       FROM PCPARAMFILIAL
      WHERE (CODFILIAL = vrPedido.vvCodFilial)
        AND (NOME      = 'RESERVARESTOQUETV7');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vRESERVARESTOQUETV7 := 'N';
    END;
    --
    BEGIN
      SELECT NVL(VALOR,'N')
       INTO vrParametros.vGRAVARPEDVENBLOQMED
       FROM PCPARAMFILIAL
      WHERE (CODFILIAL = '99')
        AND (NOME      = 'GRAVARPEDVENBLOQMED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vrParametros.vGRAVARPEDVENBLOQMED := 'N';
    END;
  
    -- LOG: Parâmetros
    P_INSERE_LOG_PROCESSAMENTO('pi_nCodRotina = '              || pi_nCodRotina                           || CHR(13) ||
                               'pi_nNumPed = '                 || pi_nNumPed                              || CHR(13) ||
                               'pi_nMatricula = '              || pi_nMatricula                           || CHR(13) ||
                               'pi_nProxNumCar = '             || pi_nProxNumCar                          || CHR(13) ||
                               'pi_vPosicaoPedido = '          || pi_vPosicaoPedido                       || CHR(13) ||
                               'vvOrigemPed = '                || vrPedido.vvOrigemPed                    || CHR(13) ||
                               'vnCondVenda = '                || vrPedido.vnCondVenda                    || CHR(13) ||
                               'vUSANUMCARVENDABALCAO = '      || vrParametros.vUSANUMCARVENDABALCAO      || CHR(13) ||
                               'vFECHACARREGAUTVENDABALCAO = ' || vrParametros.vFECHACARREGAUTVENDABALCAO || CHR(13) ||
                               'vGERARBRINDEPEDBONIFIC = '     || vrParametros.vGERARBRINDEPEDBONIFIC     || CHR(13) ||
                               'vRESERVARESTOQUETV7 = '        || vrParametros.vRESERVARESTOQUETV7        || CHR(13) ||
                               'vGRAVARPEDVENBLOQMED = '       || vrParametros.vGRAVARPEDVENBLOQMED
                               );
  
   /*************************************************************************************************
                                       INICIALIZAÇÃO DE VARIÁVEIS
                                                F I M
    **************************************************************************************************/
  
  
  
   /*************************************************************************************************
                                             I N I C I O
                                         FINALIZAÇÃO DO PEDIDO
    **************************************************************************************************/
    IF (NVL(vrPedido.vvStatusProcessamentoMed,' ') <> 'F') THEN
  
      -- Inicializa Controle de Finalização do Pedido
      vbPodeFinalizarPedido := FALSE;
  
      -- 2336 sempre pode Finalizar o Pedido
      IF (pi_nCodRotina = 2336) THEN
  
        vbPodeFinalizarPedido := TRUE;
  
      -- Demais Rotinas
      ELSE
  
        -- Se 2316 ou Integração
        IF  (pi_nCodRotina IN (2316,2513)) THEN
  
          -- Se Balcão/Balcão Reserva, depende da Posição
          IF (vrPedido.vvOrigemPed IN ('B','R')) THEN
  
            -- Se Posição Faturado ou Montado pode Finalizar o Pedido
            IF (pi_vPosicaoPedido IN ('L','M')) THEN
  
              vbPodeFinalizarPedido := TRUE;
  
            -- Se precisar de Liberação não pode finalizar o Pedido (a Finalização será na 2336 ao Liberar)
            -- O motivo é não gerar o carregamento enquanto não for liberado
            ELSE
  
              vbPodeFinalizarPedido := FALSE;
  
            END IF;
  
          -- Demais Origens depende do Parâmetro x Posição
          ELSE
  
            -- Se NÃO Gravar Pedidos de Venda como Bloqueados, pode Finalizar o Pedido
            IF    (NVL(vrParametros.vGRAVARPEDVENBLOQMED,'N') = 'N') THEN
  
              vbPodeFinalizarPedido := TRUE;
  
            -- Se Gravar Pedidos de Venda como Bloqueados, pode Finalizar o Pedido SOMENTE se Liberado
            ELSIF ((NVL(vrParametros.vGRAVARPEDVENBLOQMED,'S') = 'S') AND (NVL(vrPedido.vvPosicao,' ') = 'L')) THEN
  
              vbPodeFinalizarPedido := TRUE;
  
            END IF;
  
          END IF;
  
        END IF;
  
      END IF; -- Fim Condição: Avalia se pode finalizar o Pedido
  
  
     /**************************
      SE PODE FINALIZAR O PEDIDO
      **************************/
      IF (vbPodeFinalizarPedido) THEN
  
  
        -- Marca posição para Rollback
        SAVEPOINT inicio_gravar_pedido;
        vbUsouSavePoint := TRUE;
  
        -- Atualiza Status do Pedido, indicando que vai realizar o Processo de Finalização do Pedido
        P_ATU_STATUS_PROCESSAMENTO('F',
                                   vrPedido.vvStatusProcessamentoMed);
  
  
        --------------------------------------------------------------------------------------------------
        --                                          I N I C I O                                         --
        --                                   CARREGAMENTO BALCÃO RESERVA                                --
        --------------------------------------------------------------------------------------------------
        IF (vrPedido.vvOrigemPed IN ('B','R')) THEN
  
          IF (pi_nCodRotina IN (2316, 2336, 2513)) THEN
  
            -- Se não passou o Próximo Número Carregamento
            IF (NVL(pi_nProxNumCar,0) = 0) THEN
              RAISE e_NumCarregamento;
            END IF;
  
            -- Valor Total Carregamento
            IF (NVL(vrPedido.vnCondVenda,0) IN (5,11)) THEN
              vnVlTotaCarregamento := vrPedido.vnVlTabela;
            ELSE
              vnVlTotaCarregamento := vrPedido.vnVlAtend;
            END IF;
  
            -- Verifica se inseriu o carregamento - MED-1769
            BEGIN
              SELECT 'S'
                INTO vvExisteCarreg
                FROM PCCARREG
               WHERE (NUMCAR = pi_nProxNumCar);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vvExisteCarreg := 'N';
            END;
  
            -- Montar Carregamento
            IF (vvExisteCarreg = 'N') THEN
  
              INSERT INTO PCCARREG
                        ( NUMCAR
                        , DTSAIDA
                        , TOTPESO
                        , TOTVOLUME
                        , VLTOTAL
                        , DESTINO
                        , DATAMON
                        , CODVEICULO
                        , CODFUNCMON
                        , HORAMON
                        , MINUTOMON
                        , SEGUNDOMON )
                 VALUES ( pi_nProxNumCar
                        , vrPedido.vdData
                        , NVL(vrPedido.vnTotPeso,0)
                        , NVL(vrPedido.vnTotVolume,0)
                        , NVL(vnVlTotaCarregamento,0) -- VLTOTAL
                        , 'VENDA BALCAO'
                        , vrPedido.vdData
                        , 0 -- CODVEICULO
                        , pi_nMatricula
                        , TO_NUMBER(TO_CHAR(SYSDATE,'MI'))
                        , TO_NUMBER(TO_CHAR(SYSDATE,'SS'))
                        , TO_NUMBER(TO_CHAR(SYSDATE,'SS')) );
  
              -- Fechamento Automatico
              IF (NOT ((NVL(vrPedido.vnCondVenda,0) = 13) AND (NVL(vrParametros.vUSANUMCARVENDABALCAO,'N') = 'S'))) AND
                 (NVL(vrParametros.vFECHACARREGAUTVENDABALCAO,'N') = 'S') THEN
                UPDATE PCCARREG
                   SET DTFECHA = vrPedido.vdData
                WHERE (NUMCAR = pi_nProxNumCar);
              END IF;
  
            END IF; -- Fim Condição: Ainda não montou o Carregamento
  
            -- Atualiza Carregamento no Item do Pedido
            UPDATE PCPEDI
               SET NUMCAR  = pi_nProxNumCar
                 , POSICAO = 'M'
             WHERE (NUMPED = pi_nNumPed);
  
            -- Atualiza Carregamento no Cabeçalho do Pedido
            UPDATE PCPEDC
               SET NUMCAR  = pi_nProxNumCar
                 , POSICAO = 'M'
             WHERE (NUMPED = pi_nNumPed);
  
            -- LOG: Carregamento
            P_INSERE_LOG_PROCESSAMENTO('Carregamento = ' || pi_nProxNumCar);
  
          END IF;
  
        END IF; -- FIM: Se Balcão/Balcão Reserva
        --------------------------------------------------------------------------------------------------
        --                                            F I M                                             --
        --                                   CARREGAMENTO BALCÃO RESERVA                                --
        --------------------------------------------------------------------------------------------------
  
  
  
  
  
        --------------------------------------------------------------------------------------------------
        --                                          I N I C I O                                         --
        --                                       QUEBRA DE PEDIDOS                                      --
        --------------------------------------------------------------------------------------------------
        IF (pi_nCodRotina IN (2316, 2336, 2513)) THEN
  
          ---------------------------------------------
          -- PEDIDOS DE OL/PE NÃO TÊM QUEBRA DE PEDIDOS
          ---------------------------------------------
          IF (NVL(vrPedido.vvOrigemPed,'X') = 'F') AND
             (NVL(vrPedido.vvTipoFv,'FV') IN ('OL','PE')) THEN
  
            -- Sem Quebra de Pedido
            vvRetQuebrarPedido := '1';
  
            -- LOG: Carregamento
            P_INSERE_LOG_PROCESSAMENTO('Pedidos OL/PE sem quebra de pedido');
  
          ELSE
  
            --------------------------------------------
            -- EXECUTA PROCEDIMENTO DE QUEBRA DE PEDIDOS
            --------------------------------------------
            P_QUEBRAR_PEDIDO(pi_nNumPed,
                             vrPedido.vvCodFilial,
                             vvRetQuebrarPedido,
                             vvMsgErrosQuebrarPedido);
            IF (vvRetQuebrarPedido = '3') THEN
              RAISE e_QuebrarPedido;
            END IF;
  
            -- LOG: Carregamento
            P_INSERE_LOG_PROCESSAMENTO('Resultado da Quebra do Pedido: ' || vvRetQuebrarPedido || ' - ' || vvMsgErrosQuebrarPedido);
  
          END IF; -- FIM CONDIÇÃO: SEM QUEBRA OL/PE
  
          -- Se não houve Quebra de Pedidos e ainda não gravou a Taxa de Frete
          IF (vvRetQuebrarPedido = '1') AND
             (NVL(vrPedido.vnVlFreteOutrasDesp,0) = 0) THEN
  
            -------------------------
            -- Pesquisa Taxa de Frete
            -------------------------
            vrPedido.vnVlFreteOutrasDesp := 0;
            OBTER_TAXA_FRETE(vrPedido.vvCodFilial,
                             vrPedido.vvOrigemPed,
                             vrPedido.vvTipoFv,
                             vrRetTaxaFrete.vvAchouFrete,
                             vrRetTaxaFrete.vnValorTaxa,
                             vrRetTaxaFrete.vnValorMinimo);
            IF (vrRetTaxaFrete.vvAchouFrete = 'S') THEN
              -- Calcula Total do Pedido
              SELECT SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0)) VLATEND
                INTO vnTotalPedidoValidaTaxafrete
                FROM PCPEDI
               WHERE (PCPEDI.NUMPED = pi_nNumPed);
              -- LOG: Parâmetros Taxa Frete
              P_INSERE_LOG_PROCESSAMENTO('Parâmetros Taxa de Frete > Valor Pedido: ' || vnTotalPedidoValidaTaxafrete || ' ; Valor Mínimo: ' || vrRetTaxaFrete.vnValorMinimo);
              -- Se Total do Pedido ficar abaixo do Mínimo (acima ou igual ao mínimo não aplica a taxa de frete)
              IF (NVL(vnTotalPedidoValidaTaxafrete,0) < NVL(vrRetTaxaFrete.vnValorMinimo,0)) THEN
                -- Recebe Taxa de Frete
                vrPedido.vnVlFreteOutrasDesp := NVL(vrRetTaxaFrete.vnValorTaxa,0);
                -- Atualiza Taxa de Frete no Pedido
                UPDATE PCPEDC
                   SET VLFRETEOUTRASDESP = vrPedido.vnVlFreteOutrasDesp
                 WHERE (NUMPED = pi_nNumPed);
                -- LOG: Taxa de Frete
                P_INSERE_LOG_PROCESSAMENTO('Taxa de Frete: ' || vrPedido.vnVlFreteOutrasDesp);
              END IF;
            END IF;
  
          END IF;
  
        END IF; -- FIM CONDIÇÃO: SE PODE Quebrar de Pedido
        
        -- Garantir o CODDISTRIB do Produto que ficou no Pedido Inicial inclusive se não teve quebra de pedidos
        P_ATU_DISTRIB_PEDIDO_INICIAL(pi_nNumPed);
        --------------------------------------------------------------------------------------------------
        --                                            F I M                                             --
        --                                       QUEBRA DE PEDIDOS                                      --
        --------------------------------------------------------------------------------------------------
  
  
  
  
        ------------------------------------------------------
        -- EFETIVA TRANSAÇÕES (Preciso do COMMIT antes do TV8)
        ------------------------------------------------------
        COMMIT;
  
  
  
  
        --------------------------------------------------------------------------------------------------
        --                                         I N I C I O                                          --
        --                                    GERACAO DOS PEDIDOS TV8                                   --
        --------------------------------------------------------------------------------------------------
        IF (pi_nCodRotina IN (2316, 2336, 2513))    AND
           (vrParametros.vRESERVARESTOQUETV7 = 'S') AND
           (vrPedido.vnCondVenda             = 7)   THEN -->> Se o Pedido Original era TV7
  
          -- Laço de Pedidos Vinculados ao Pedido Original -----------------------------------------------
          FOR vc_Pedido IN (SELECT PCPEDC.NUMPED
                              FROM PCPEDC
                             WHERE (PCPEDC.DATA = vrPedido.vdData)
                               AND (PCPEDC.CONDVENDA = 7)
                               AND ((PCPEDC.NUMPED = pi_nNumPed) OR
                                    (PCPEDC.NUMPEDORIGEM = pi_nNumPed))) LOOP
  
            -- Chama procedimento que irá chamar a PRC_GERARPEDTV8
            P_QUEBRA_PEDIDO_TV8(vc_Pedido.NUMPED, -->> Número do Pedido do Laço
                                vvRetMsgTV8,
                                vnRetNumPedGeradoTV8,
                                vvRetPosicaoGeratTV8,
                                vvRetMotivoTV8,
                                vvAchouTv8);
            -- LOG
            vvMsgLog := 'Resultado Pedido TV8: [' || vnRetNumPedGeradoTV8  || ']' || CHR(13) ||
                        'PedidoOrigem: ['         || pi_nNumPed            || ']' || CHR(13) ||
                        'PedidoTV7: ['            || vc_Pedido.NUMPED      || ']' || CHR(13) ||
                        'RetMsgTV8: ['            || vvRetMsgTV8           || ']' || CHR(13) ||
                        'RetPosicaoGeratTV8: ['   || vvRetPosicaoGeratTV8  || ']' || CHR(13) ||
                        'RetMotivoTV8: ['         || vvRetMotivoTV8        || ']' || CHR(13) ||
                        'AchouTv8: ['             || vvAchouTv8            || ']' || CHR(13);
            P_INSERE_LOG_PROCESSAMENTO(vvMsgLog);
  
            -- Se gerou Pedido TV8
            IF (NVL(vnRetNumPedGeradoTV8,0) > 0) THEN
  
              -- Pesquisa Observacao Original
              BEGIN
                SELECT OBSERVACAO
                  INTO vvObservacaoTemp
                  FROM PCMED_RESUMO_PEDIDOS
                 WHERE (NUMPED = vc_Pedido.NUMPED)
                   AND (ROWNUM = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vvObservacaoTemp := NULL;
              END;
              -- Calcula o Total do Pedido TV8
              -- DDMEDICA-7697 - Aplicação do ST Recolhido Anteriormente
              SELECT COUNT(*) ITENS,
                     SUM(QT) UNIDADES,
                     SUM(NVL(PCPEDI.QT, 0) * (NVL(PCPEDI.PVENDA, 0) - NVL(PCPEDI.ST, 0) - NVL(PCPEDI.VLICMSSTRETANTERIOR, 0) - NVL(PCPEDI.VLREPASSE, 0) - NVL(PCPEDI.VLFECP, 0))) LIQUIDO, -- DDMEDICA-7697
                     SUM(NVL(PCPEDI.QT, 0) * (NVL(PCPEDI.ST, 0) + NVL(PCPEDI.VLICMSSTRETANTERIOR, 0) + NVL(PCPEDI.VLREPASSE, 0))) STREPASSE, -- DDMEDICA-7697
                     SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0)) TOTAL,
                     SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLFECP, 0)) TOTFECP
                INTO vrTotalizador.vnTotQTITENS,
                     vrTotalizador.vnTotUNIDADES,
                     vrTotalizador.vnTotLIQUIDO,
                     vrTotalizador.vnTotSTREPASSE,
                     vrTotalizador.vnTotTOTAL,
                     vrTotalizador.vnTotFCP
                FROM PCPEDI
                   , PCPRODUT
               WHERE (PCPEDI.CODPROD = PCPRODUT.CODPROD)
                 AND (PCPEDI.NUMPED = vnRetNumPedGeradoTV8);
              -- Insere na Tabela Temporária o Pedido TV8
              INSERT INTO PCMED_RESUMO_PEDIDOS
                        ( NUMPEDORIGINAL
                        , NUMPED
                        , ITENS
                        , QT
                        , TOTLIQUIDO
                        , TOTSTREPASSE
                        , TOTPVENDA
                        , OBSERVACAO
                        , TOTFCP )
                 VALUES ( pi_nNumPed           -->> REFERENCIA O PEDIDO ORIGINAL E NÃO O TV7
                        , vnRetNumPedGeradoTV8 -->> PEDIDO TV8
                        , vrTotalizador.vnTotQTITENS
                        , vrTotalizador.vnTotUNIDADES
                        , vrTotalizador.vnTotLIQUIDO
                        , vrTotalizador.vnTotSTREPASSE
                        , vrTotalizador.vnTotTOTAL
                        , SUBSTR('PEDIDO TV8' || ' ' || NVL(vvObservacaoTemp,' '),1,250)
                        , vrTotalizador.vnTotFCP );
  
              -- Atualiza Pedido TV7
              UPDATE PCMED_RESUMO_PEDIDOS
                 SET OBSERVACAO = SUBSTR('PEDIDO TV7'||' '||NVL(vvObservacaoTemp,' '),1,250)
               WHERE (NUMPED = vc_Pedido.NUMPED);
  
              -- Efetiva Transações
              COMMIT;
  
            END IF; -- Fim Condição: Se gerou Pedido TV8
  
          END LOOP; -- FIM: Laço de Pedidos Vinculados ao Pedido Original --------------------------------
  
          --
          -- Preciso inserir na Tabela Temporária o Pedido Original, senão somente aparecem as quebras e os TV8
          --
  
          -- Pesquisa Observacao Original
          BEGIN
            SELECT OBSERVACAO
              INTO vvObservacaoTemp
              FROM PCMED_RESUMO_PEDIDOS
             WHERE (NUMPED = pi_nNumped)
               AND (ROWNUM = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvObservacaoTemp := NULL;
          END;
          -- Deleta da Temporária o Pedido Original
          DELETE FROM PCMED_RESUMO_PEDIDOS
                WHERE (NUMPED = pi_nNumped);
          -- Calcula o Total do Pedido Original
          -- DDMEDICA-7697 - Aplicação do ST Recolhido Anteriormente
          SELECT COUNT(*) ITENS,
                 SUM(QT) UNIDADES,
                 SUM(NVL(PCPEDI.QT, 0) * (NVL(PCPEDI.PVENDA, 0) - NVL(PCPEDI.ST, 0) - NVL(PCPEDI.VLICMSSTRETANTERIOR, 0) - NVL(PCPEDI.VLREPASSE, 0) - NVL(PCPEDI.VLFECP, 0))) LIQUIDO, -- DDMEDICA-7697
                 SUM(NVL(PCPEDI.QT, 0) * (NVL(PCPEDI.ST, 0) + NVL(PCPEDI.VLICMSSTRETANTERIOR, 0) + NVL(PCPEDI.VLREPASSE, 0))) STREPASSE, -- DDMEDICA-7697
                 SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0)) TOTAL,
                 SUM(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.VLFECP, 0)) TOTFECP
            INTO vrTotalizador.vnTotQTITENS,
                 vrTotalizador.vnTotUNIDADES,
                 vrTotalizador.vnTotLIQUIDO,
                 vrTotalizador.vnTotSTREPASSE,
                 vrTotalizador.vnTotTOTAL,
                 vrTotalizador.vnTotFCP
            FROM PCPEDI
               , PCPRODUT
           WHERE (PCPEDI.CODPROD = PCPRODUT.CODPROD)
             AND (PCPEDI.NUMPED = pi_nNumped);
          -- Insere na Tabela Temporária o Pedido Original
          INSERT INTO PCMED_RESUMO_PEDIDOS
                    ( NUMPEDORIGINAL
                    , NUMPED
                    , ITENS
                    , QT
                    , TOTLIQUIDO
                    , TOTSTREPASSE
                    , TOTPVENDA
                    , OBSERVACAO
                    , TOTFCP )
             VALUES ( NULL       -->> Não Grava o Pedido Original nele mesmo
                    , pi_nNumped -->> PEDIDO TV7
                    , vrTotalizador.vnTotQTITENS
                    , vrTotalizador.vnTotUNIDADES
                    , vrTotalizador.vnTotLIQUIDO
                    , vrTotalizador.vnTotSTREPASSE
                    , vrTotalizador.vnTotTOTAL
                    , NVL(vvObservacaoTemp,'PEDIDO TV7') -- SUBSTR('PEDIDO TV7'||' '||NVL(vvObservacaoTemp,' '),1,250)
                    , vrTotalizador.vnTotFCP );
  
          -- Efetiva Transações
          COMMIT;
  
        END IF; -- Fim Condição Quebra Pedido TV8
        --------------------------------------------------------------------------------------------------
        --                                            F I M                                             --
        --                                    GERACAO DOS PEDIDOS TV8                                   --
        --------------------------------------------------------------------------------------------------
  
  
        ------------
        -- GRAVA LOG
        ------------
        P_GRAVA_LOG_PROCESSAMENTO;
  
        -------------------------------
        -- EFETIVA TRANSAÇÕES PENDENTES
        -------------------------------
        COMMIT;
  
  
      END IF; -- FIM CONDIÇÃO: SE PODE FINALIZAR O PEDIDO
  
    END IF; -- FIM CONDIÇÃO: (NVL(vrPedido.vvStatusProcessamentoMed,' ') <> 'F')
  
  EXCEPTION
    WHEN e_PedidoNaoEncontrado THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vOcorreramErros := 'S';
      po_vMsgErros       := 'Pedido ' || NVL(pi_nNumPed,0) || ' não encontrado.';
      P_GRAVA_LOG_PROCESSAMENTO; -- Log
    WHEN e_NumCarregamento     THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vOcorreramErros := 'S';
      po_vMsgErros       := 'Número de Carregamento inválido.';
      P_GRAVA_LOG_PROCESSAMENTO; -- Log
    WHEN e_ValidacaoPromo      THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vOcorreramErros := 'S';
      po_vMsgErros       := vvRetMotivoNaoPodeGravarPromo;
      P_GRAVA_LOG_PROCESSAMENTO; -- Log
    WHEN e_QuebrarPedido       THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vOcorreramErros := 'S';
      po_vMsgErros       := vvMsgErrosQuebrarPedido;
      P_GRAVA_LOG_PROCESSAMENTO; -- Log
    WHEN OTHERS THEN
      --- ROLLBACK se usar SAVEPOINT
      IF (vbUsouSavePoint) THEN
        ROLLBACK TO SAVEPOINT inicio_gravar_pedido;
      END IF;
      po_vOcorreramErros := 'S';
      po_vMsgErros       := DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM;
      P_GRAVA_LOG_PROCESSAMENTO; -- Log
  END P_FINALIZACAO_PEDIDO_01;

 /*******************************************************************************
  Nome         : P_REVALIDA_PROMOCAO
  Descricão    : Procedimento para Revalidar a Promoção ao gravar o Pedido  
  ********************************************************************************/   
  PROCEDURE P_REVALIDA_PROMOCAO(pi_vOrigemChamada       IN VARCHAR2,
                                pi_nMatricula           IN NUMBER,
                                pi_nNumPed              IN NUMBER,
                                pi_nCodCli              IN NUMBER,
                                pi_nCodUsur             IN NUMBER,
                                pi_nCodPlPag            IN NUMBER,
                                pi_nCodPlPagEtico       IN NUMBER,
                                pi_nCodPlPagGenerico    IN NUMBER,
                                pi_vCodCob              IN VARCHAR2,
                                pi_nCodPromocaoMed      IN NUMBER,
                                pi_nNumRegiao           IN NUMBER,
                                pi_vCodFilial           IN VARCHAR2,
                                pi_vCodFilialNf         IN VARCHAR2,
                                pi_vOrigemPed           IN VARCHAR2,
                                pi_vTipoFv              IN VARCHAR2,
                                pi_nCodCondicaoVenda    IN NUMBER,
                                po_vOcorreramAlertas    OUT VARCHAR2,
                                po_vOcorreramRejeicoes  OUT VARCHAR2) IS

    -- Dados Itens Pedido
    TYPE TRecDadosItens       IS RECORD (
         CODPROD              PCPEDI.CODPROD%TYPE,
         NUMSEQ               PCPEDI.NUMSEQ%TYPE,
         QT                   PCPEDI.QT%TYPE,
         CODPROMOCAOMED       PCPEDI.CODPROMOCAOMED%TYPE,
         CODDESCONTO          PCPEDI.CODDESCONTO%TYPE,
         CODFILIALRETIRA      PCPEDI.CODFILIALRETIRA%TYPE,
         PRECOMAXCONSUM       PCPEDI.PRECOMAXCONSUM%TYPE,
         NUMLOTE              PCPEDI.NUMLOTE%TYPE,
         NUMLOTEPROMOCAOMED   PCPEDI.NUMLOTEPROMOCAOMED%TYPE,
         CODPLPAG             PCPEDI.CODPLPAG%TYPE,
         --
         OLD_QT               PCPEDI.QT%TYPE,
         OLD_VLSALDORCA       NUMBER,
         OLD_QTSALDORCA       NUMBER,
         OLD_POSICAO          PCPEDI.POSICAO%TYPE,
         --
         NEW_PTABELA          PCPEDI.PTABELA%TYPE,
         NEW_PERDESC          PCPEDI.PERDESC%TYPE,
         NEW_PVENDA           PCPEDI.PVENDA%TYPE,
         NEW_ST               PCPEDI.ST%TYPE,
         NEW_VLFECP           PCPEDI.VLFECP%TYPE,
         NEW_VLREPASSE        PCPEDI.VLREPASSE%TYPE,
         --
         CRITICA_TRIBUTACAO   VARCHAR2(1),
         DESCRICAO_TRIBUTACAO VARCHAR2(2000),
         ROTINA_TRIBUTACAO    NUMBER,
         CRITICA_PRECIFIC     VARCHAR2(1),
         DESCRICAO_PRECIFIC   VARCHAR(2000),
         -- DDMEDICA-5009
         NUMVERBACAMPANHA     PCPEDI.NUMVERBACAMPANHA%TYPE,
         VLDESCCMVPROMOCAOMED PCPEDI.VLDESCCMVPROMOCAOMED%TYPE);
    vrDadosItens              TRecDadosItens;
    TYPE TTvDadosItens        IS TABLE OF TRecDadosItens INDEX BY BINARY_INTEGER;
    vtDadosItens              TTvDadosItens;
    viIdx                     INTEGER;
    -- DDMEDICA-5009
    vtDadosItensVerba         TTvDadosItens;
    viIdxVerba                INTEGER;
    
    -- Outras Variáveis
    vTIPOPRAZOMEDICAMEN       PCPARAMFILIAL.VALOR%TYPE;    
    vDESCRICAO                PCPRODUT.DESCRICAO%TYPE;
    vGRUPOFATURAMENTO         PCPRODUT.GRUPOFATURAMENTO%TYPE;
    vnCodPlPagProduto         PCPEDC.CODPLPAG%TYPE;
    vvPodeComprarPromocao     VARCHAR2(2000);
    vDESCRICAORESUMIDA        PCPROMOCAOMED.DESCRICAORESUMIDA%TYPE;
    vvTipoCriticaProd         VARCHAR2(1);
    vREVALIDASEMPROMOGRAVACAO PCREGRASEXCECAOMED.VALOR%TYPE;

    -- DDMEDICA-5009
    bPossuiVerbaPromocao      BOOLEAN; 
    vPERMITEVERBAPROMOCAO     VARCHAR2(255);
    vvJaInseriuProduto        VARCHAR2(1); 
    nCODMOTIVOVERBAPROMOCAO   NUMBER; -- DDMEDICA-5401        
    vDESCMOTIVOVERBAPROMOCAO  VARCHAR2(255); -- DDMEDICA-5401        

  BEGIN

   /**********
    Parâmetros
    **********/
    POBTEM_PARAMFILIAL_STRING('9',
                              'TIPOPRAZOMEDICAMEN',
                              '2',
                              vTIPOPRAZOMEDICAMEN);
    vREVALIDASEMPROMOGRAVACAO := F_REGRA_MEDICAMENTOS('99','REVALIDASEMPROMOGRAVACAOPED2316');
    
    -- Controle de Verba da Promoção - DDMEDICA-5009
    bPossuiVerbaPromocao := FALSE;

   /***********************
    Carrega Itens do Pedido
    ***********************/
    FOR vc_Itens IN (SELECT PCPEDI.CODPROD,
                            PCPEDI.NUMSEQ,
                            PCPEDI.QT,
                            PCPEDI.CODPROMOCAOMED,
                            PCPEDI.CODDESCONTO,
                            PCPEDI.CODFILIALRETIRA,
                            PCPEDI.PRECOMAXCONSUM,
                            PCPEDI.NUMLOTE,
                            PCPEDI.NUMLOTEPROMOCAOMED,
                            PCPEDI.CODPLPAG,
                            (NVL(PCPEDI.PTABELA,0)  - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLREPASSE,0) - NVL(PCPEDI.VLFECP,0)) PTABELA,
                            PCPEDI.PERDESC,
                            (NVL(PCPEDI.PVENDA,0)  - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLREPASSE,0) -  NVL(PCPEDI.VLFECP,0)) PVENDA,
                            PCPEDI.ST,
                            PCPEDI.VLFECP,
                            PCPEDI.VLREPASSE,
                            PCPEDI.NUMVERBACAMPANHA, -- DDMEDICA-5009
                            PCPEDI.VLDESCCMVPROMOCAOMED, -- DDMEDICA-5009
                            PCPEDI.POSICAO -- DDMEDICA-5009
                       FROM PCPEDI
                      WHERE (PCPEDI.NUMPED = pi_nNumPed)
                      ORDER BY PCPEDI.CODPROD,
                               PCPEDI.NUMSEQ) LOOP
      
      -- Pesquisa Valores Anteriores na PCPEDI para não afetar produtos já gravados anteriomente
      FUNCOES_MED.P_OBTER_VALORES_ANTERIOR(pi_nNumPed,
                                           vc_Itens.CODPROD,
                                           vc_Itens.NUMSEQ,
                                           vrDadosItens.OLD_QT,
                                           vrDadosItens.OLD_VLSALDORCA,
                                           vrDadosItens.OLD_QTSALDORCA,
                                           vrDadosItens.OLD_POSICAO);
      
      -- Somente se o Produto não existia no Produto (Negociação já fechada não pode travar)
      IF (NVL(vrDadosItens.OLD_QT,0) = 0) THEN
        vrDadosItens.CODPROD            := vc_Itens.CODPROD;
        vrDadosItens.NUMSEQ             := vc_Itens.NUMSEQ;
        vrDadosItens.QT                 := vc_Itens.QT;
        vrDadosItens.CODPROMOCAOMED     := vc_Itens.CODPROMOCAOMED;
        vrDadosItens.CODDESCONTO        := vc_Itens.CODDESCONTO;
        vrDadosItens.CODFILIALRETIRA    := vc_Itens.CODFILIALRETIRA;
        vrDadosItens.PRECOMAXCONSUM     := vc_Itens.PRECOMAXCONSUM;     
        vrDadosItens.NUMLOTE            := vc_Itens.NUMLOTE;     
        vrDadosItens.NUMLOTEPROMOCAOMED := vc_Itens.NUMLOTEPROMOCAOMED;     
        vrDadosItens.CODPLPAG           := vc_Itens.CODPLPAG;     
        vrDadosItens.NEW_PTABELA        := vc_Itens.PTABELA;
        vrDadosItens.NEW_PERDESC        := vc_Itens.PERDESC;
        vrDadosItens.NEW_PVENDA         := vc_Itens.PVENDA;
        vrDadosItens.NEW_ST             := vc_Itens.ST;
        vrDadosItens.NEW_VLFECP         := vc_Itens.VLFECP;
        vrDadosItens.NEW_VLREPASSE      := vc_Itens.VLREPASSE;
      END IF;

      viIdx := NVL(viIdx,0) + 1;
            
      vtDadosItens(viIdx) := vrDadosItens;
      
      -- Controle de Verba da Promoção - DDMEDICA-5009
      IF (NVL(vc_Itens.CODPROMOCAOMED,0) > 0)   AND
         (NVL(vc_Itens.NUMVERBACAMPANHA,0) > 0) AND
         (NVL(vc_Itens.POSICAO,'L') <> 'C')     THEN
         
        bPossuiVerbaPromocao              := TRUE;
        
        vrDadosItens.CODPROD              := vc_Itens.CODPROD;
        vrDadosItens.NUMSEQ               := vc_Itens.NUMSEQ;
        vrDadosItens.QT                   := vc_Itens.QT;
        vrDadosItens.CODPROMOCAOMED       := vc_Itens.CODPROMOCAOMED;
        vrDadosItens.CODDESCONTO          := vc_Itens.CODDESCONTO;
        vrDadosItens.CODFILIALRETIRA      := vc_Itens.CODFILIALRETIRA;
        vrDadosItens.PRECOMAXCONSUM       := vc_Itens.PRECOMAXCONSUM;     
        vrDadosItens.NUMLOTE              := vc_Itens.NUMLOTE;     
        vrDadosItens.NUMLOTEPROMOCAOMED   := vc_Itens.NUMLOTEPROMOCAOMED;     
        vrDadosItens.CODPLPAG             := vc_Itens.CODPLPAG;     
        vrDadosItens.NEW_PTABELA          := vc_Itens.PTABELA;
        vrDadosItens.NEW_PERDESC          := vc_Itens.PERDESC;
        vrDadosItens.NEW_PVENDA           := vc_Itens.PVENDA;
        vrDadosItens.NEW_ST               := vc_Itens.ST;
        vrDadosItens.NEW_VLFECP           := vc_Itens.VLFECP;
        vrDadosItens.NEW_VLREPASSE        := vc_Itens.VLREPASSE;
        vrDadosItens.NUMVERBACAMPANHA     := vc_Itens.NUMVERBACAMPANHA;
        vrDadosItens.VLDESCCMVPROMOCAOMED := vc_Itens.VLDESCCMVPROMOCAOMED;
        
        viIdxVerba := NVL(viIdxVerba,0) + 1;
              
        vtDadosItensVerba(viIdxVerba) := vrDadosItens;
        
      END IF;
            
    END LOOP;                               

   /*************************
    Limpa Tabelas Temporárias
    *************************/
    DELETE FROM PCMED_VALIDACAO_PRECO_TROCA;
    DELETE FROM PCMED_VALIDACAO_GERAL_TROCA;
                
   /********************
    Validações dos Itens
    ********************/
    -- Se não for Força de Vendas
    IF (NVL(pi_vOrigemChamada,'9999') NOT IN ('2513')) THEN
      IF (vtDadosItens.COUNT > 0) THEN
        FOR viIdx IN vtDadosItens.FIRST..vtDadosItens.LAST LOOP
        
          vrDadosItens := vtDadosItens(viIdx);
          
          -- Pesquisa Dados do Produto
          BEGIN
            SELECT PCPRODUT.DESCRICAO
                 , PCPRODUT.GRUPOFATURAMENTO
              INTO vDESCRICAO
                 , vGRUPOFATURAMENTO
              FROM PCPRODUT
             WHERE (PCPRODUT.CODPROD = vrDadosItens.CODPROD);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vDESCRICAO        := NULL;
              vGRUPOFATURAMENTO := NULL;
          END;
        
          --------------------------------
          -- Plano de Pagamento do Produto
          --------------------------------
          vnCodPlPagProduto := F_RETORNAR_PLPAG_ITEM(vTIPOPRAZOMEDICAMEN,
                                                     vrDadosItens.CODPROD,
                                                     vrDadosItens.CODPLPAG,
                                                     pi_nCodPlPag,
                                                     pi_nCodPlPagEtico,
                                                     pi_nCodPlPagGenerico,
                                                     vGRUPOFATURAMENTO);      
        
          -----------------------------------------------------------------------------
          -- Validação da Promoção do Item do Pedido com relação ao Cabeçalho do Pedido
          -----------------------------------------------------------------------------
          IF (NVL(vrDadosItens.CODPROMOCAOMED,0) > 0) THEN
            vvPodeComprarPromocao := PKG_FUNCOESVENDAS_MED.F_PODECOMPRARPROMOCAO(vrDadosItens.CODPROMOCAOMED,
                                                                                 pi_vCodFilial,
                                                                                 pi_nCodCli,
                                                                                 pi_nNumRegiao,
                                                                                 pi_nCodUsur,
                                                                                 vnCodPlPagProduto, -->> Plano de Pagamento do Produto
                                                                                 pi_nCodCondicaoVenda, 
                                                                                 pi_vOrigemPed, 
                                                                                 pi_vTipoFv,
                                                                                 TRUNC(SYSDATE)); -->> Data Hoje
            IF (NVL(vvPodeComprarPromocao,'N') <> 'S') THEN
              P_INSERE_TABTEMP(pi_nNumPed,
                               vrDadosItens.CODPROD,
                               vrDadosItens.NUMSEQ,
                               vDESCRICAO,
                               NULL,
                               NULL,
                               NULL,
                               'Promoção',
                               2323,
                               'Promoção não permitida: ' || SUBSTR(vvPodeComprarPromocao,5,LENGTH(vvPodeComprarPromocao)),
                               'R',
                               po_vOcorreramAlertas,
                               po_vOcorreramRejeicoes);      
            END IF;                                                     
          END IF;
  
          -----------------------------------------------------------------
          -- Validação da Promoção do Item do Pedido com relação ao Produto
          -----------------------------------------------------------------
          IF (NVL(vrDadosItens.CODPROMOCAOMED,0) > 0) THEN
            vvPodeComprarPromocao := F_MED_MIX_PROMOCAO(vrDadosItens.CODPROMOCAOMED,
                                                        vrDadosItens.CODPROD,
                                                        pi_nCodCli,
                                                        pi_nCodUsur);
            IF (NVL(vvPodeComprarPromocao,'N') <> 'S') THEN
              P_INSERE_TABTEMP(pi_nNumPed,
                               vrDadosItens.CODPROD,
                               vrDadosItens.NUMSEQ,
                               vDESCRICAO,
                               NULL,
                               NULL,
                               NULL,
                               'Promoção',
                               2323,
                               'Promoção não permitida: Produto não faz parte do Mix da Promoção',
                               'R',
                               po_vOcorreramAlertas,
                               po_vOcorreramRejeicoes);      
            END IF;                                                     
          END IF;        
          
          -------------------------------------------
          -- Validação do Item do Pedido sem Promoção
          -------------------------------------------
          IF (vREVALIDASEMPROMOGRAVACAO = 'S') AND
             (NVL(vrDadosItens.CODPROMOCAOMED,0) = 0) THEN
            P_INSERE_TABTEMP(pi_nNumPed,
                             vrDadosItens.CODPROD,
                             vrDadosItens.NUMSEQ,
                             vDESCRICAO,
                             NULL,
                             NULL,
                             NULL,
                             'Promoção',
                             2323,
                             'Item do Pedido sem Promoção',
                             'R',
                             po_vOcorreramAlertas,
                             po_vOcorreramRejeicoes);      
          END IF;                                             
          
          -------------------------------
          -- Gravação da Tabela dos Itens
          -------------------------------
          
          -- Pesquisa a Descrição da Promoção
          BEGIN
            SELECT PCPROMOCAOMED.DESCRICAORESUMIDA
              INTO vDESCRICAORESUMIDA
              FROM PCPROMOCAOMED
             WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vrDadosItens.CODPROMOCAOMED);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vDESCRICAORESUMIDA := NULL;
          END;
          
          -- Define o Tipo de Crítica do Produto
          BEGIN
            SELECT ALERTACRITICA
              INTO vvTipoCriticaProd
              FROM PCMED_VALIDACAO_GERAL_TROCA
             WHERE (NUMPED        = pi_nNumPed)
               AND (CODPROD       = vrDadosItens.CODPROD)
               AND (NUMSEQ        = vrDadosItens.NUMSEQ)
               AND (ALERTACRITICA = 'R')
               AND (ROWNUM        = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
               vvTipoCriticaProd := NULL;
          END;
          
          -- Insere na Tabela Temporária se houver Crítica de Rejeição
          IF (vvTipoCriticaProd = 'R') THEN
            INSERT INTO PCMED_VALIDACAO_PRECO_TROCA
                      ( NUMPED            
                      , CODPROD           
                      , NUMSEQ            
                      , DESCRICAOPROD     
                      , CODPROMOCAOMED    
                      , DESCRICAOPROMO    
                      , NEW_PTABELA       
                      , NEW_PERDESC       
                      , NEW_PVENDA        
                      , NEW_ST            
                      , NEW_VLFECP        
                      , NEW_VLREPASSE     
                      , ALERTACRITICA )          
               VALUES ( pi_nNumPed
                      , vrDadosItens.CODPROD           
                      , vrDadosItens.NUMSEQ            
                      , SUBSTR(vDESCRICAO,1,80)
                      , vrDadosItens.CODPROMOCAOMED    
                      , SUBSTR(vDESCRICAORESUMIDA,1,40)
                      , vrDadosItens.NEW_PTABELA       
                      , vrDadosItens.NEW_PERDESC       
                      , vrDadosItens.NEW_PVENDA        
                      , vrDadosItens.NEW_ST            
                      , vrDadosItens.NEW_VLFECP        
                      , vrDadosItens.NEW_VLREPASSE     
                      , vvTipoCriticaProd );       
          END IF;
  
        END LOOP;
      END IF;
    END IF; -- Fim: Se não for Força de Vendas

    --------------------------------------------------------------------------------------------
    -- Validação da Promoção do Item do Pedido com relação à Verba do Fornecedor - DDMEDICA-5009
    --------------------------------------------------------------------------------------------
    IF (bPossuiVerbaPromocao) THEN
      
      FOR vc_VerbaPromocao IN (SELECT DISTINCT 
                                      PCPEDI.CODPROMOCAOMED
                                    , PCPEDI.NUMVERBACAMPANHA
                                    , PCPEDI.POSICAO
                                 FROM PCPEDI 
                                WHERE (PCPEDI.NUMPED = pi_nNumPed)) LOOP
                                  
        IF (NVL(vc_VerbaPromocao.CODPROMOCAOMED,0) > 0)   AND
           (NVL(vc_VerbaPromocao.NUMVERBACAMPANHA,0) > 0) AND
           (NVL(vc_VerbaPromocao.POSICAO,'L') <> 'C')     THEN
           
          vPERMITEVERBAPROMOCAO := F_MED_VERBA_PROMOCAO(pi_nNumPed,
                                                        vc_VerbaPromocao.CODPROMOCAOMED,
                                                        vc_VerbaPromocao.NUMVERBACAMPANHA,
                                                        nCODMOTIVOVERBAPROMOCAO,
                                                        vDESCMOTIVOVERBAPROMOCAO);
          IF (NVL(vPERMITEVERBAPROMOCAO,'N') <> 'S') THEN
          
           /********************
            Validações dos Itens
            ********************/
            IF (vtDadosItensVerba.COUNT > 0) THEN
              FOR viIdx IN vtDadosItensVerba.FIRST..vtDadosItensVerba.LAST LOOP
          
                vrDadosItens := vtDadosItensVerba(viIdx);
                
                -- Pesquisa Dados do Produto - DDVENDAS-39352
                BEGIN
                  SELECT PCPRODUT.DESCRICAO
                    INTO vDESCRICAO
                    FROM PCPRODUT
                   WHERE (PCPRODUT.CODPROD = vrDadosItens.CODPROD);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vDESCRICAO        := NULL;
                END;				
                                
                -- Se Produto de mesma Promoção + Verba do Laço
                IF (vrDadosItens.CODPROMOCAOMED   = vc_VerbaPromocao.CODPROMOCAOMED) AND
                   (vrDadosItens.NUMVERBACAMPANHA = vc_VerbaPromocao.NUMVERBACAMPANHA) THEN
          
                  P_INSERE_TABTEMP_2(pi_nNumPed,
                                     vrDadosItens.CODPROD,
                                     vrDadosItens.NUMSEQ,
                                     NULL,
                                     nCODMOTIVOVERBAPROMOCAO, -->> Código da Rejeição para Gravar como Bloqueado
                                     NULL,
                                     NULL,
                                     vDESCMOTIVOVERBAPROMOCAO, -->> Descrição da Rejeição para Gravar como Bloqueado
                                     2323,
                                     SUBSTR(vPERMITEVERBAPROMOCAO,3,255) ||
                                       ' O valor utilizado neste item foi ' || F_FORMATAR_NUMERO_PARA_TEXTO(NVL(vrDadosItens.QT,0) * NVL(vrDadosItens.VLDESCCMVPROMOCAOMED,0),2) || '.',
                                     SUBSTR(vPERMITEVERBAPROMOCAO,1,1), -- A ou R
                                     vrDadosItens.CODPROMOCAOMED,
                                     vrDadosItens.NUMVERBACAMPANHA,
                                     po_vOcorreramAlertas,
                                     po_vOcorreramRejeicoes);      
                               
                  -- Define o Tipo de Crítica do Produto
                  BEGIN
                    SELECT 'S'
                      INTO vvJaInseriuProduto
                      FROM PCMED_VALIDACAO_PRECO_TROCA
                     WHERE (NUMPED        = pi_nNumPed)
                       AND (CODPROD       = vrDadosItens.CODPROD)
                       AND (NUMSEQ        = vrDadosItens.NUMSEQ)
                       AND (ROWNUM        = 1);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                       vvJaInseriuProduto := 'N';
                  END;
                  
                  -- Insere na Tabela Temporária se ainda não inseriu o Produto
                  IF (vvJaInseriuProduto = 'N') THEN
                    INSERT INTO PCMED_VALIDACAO_PRECO_TROCA
                              ( NUMPED            
                              , CODPROD           
                              , NUMSEQ            
                              , DESCRICAOPROD     
                              , CODPROMOCAOMED    
                              , DESCRICAOPROMO    
                              , NEW_PTABELA       
                              , NEW_PERDESC       
                              , NEW_PVENDA        
                              , NEW_ST            
                              , NEW_VLFECP        
                              , NEW_VLREPASSE     
                              , ALERTACRITICA )          
                       VALUES ( pi_nNumPed
                              , vrDadosItens.CODPROD           
                              , vrDadosItens.NUMSEQ            
                              , SUBSTR(vDESCRICAO,1,80)
                              , vrDadosItens.CODPROMOCAOMED    
                              , SUBSTR(vDESCRICAORESUMIDA,1,40)
                              , vrDadosItens.NEW_PTABELA       
                              , vrDadosItens.NEW_PERDESC       
                              , vrDadosItens.NEW_PVENDA        
                              , vrDadosItens.NEW_ST            
                              , vrDadosItens.NEW_VLFECP        
                              , vrDadosItens.NEW_VLREPASSE     
                              , SUBSTR(vPERMITEVERBAPROMOCAO,1,1) ); -- A ou R      
                  END IF;
                                   
                END IF; -- Fim: Se Produto de mesma Promoção + Verba do Laço
                
              END LOOP;
            END IF;
          END IF;                                                     
        END IF;        
        
      END LOOP;
      
    END IF; -- FIM: (bPossuiVerbaPromocao)
  
  END P_REVALIDA_PROMOCAO; 
                                 
END PKG_GRAVACAO_PEDIDO_MED;
